const CallPattern = struct {
    captures: []const CallPatternCapture = &.{},
    args: []const DemandedKnownValue,
};

const CallPatternCapture = union(enum) {
    unused,
    residual,
    split: DemandedKnownValue,
};

const ValueDemand = union(enum) {
    none,
    materialize,
    loop_param: usize,
    fn_param: FunctionDemandSlotId,
    record: []const FieldDemand,
    tuple: []const ItemDemand,
    tag: TagDemand,
    nominal: *const ValueDemand,
    callable: CallableDemand,
};

const FunctionDemandRole = enum {
    arg,
    capture,
};

const FunctionDemandSlotId = struct {
    node: usize,
};

const FunctionDemandNode = struct {
    frame_id: usize,
    fn_id: Ast.FnId,
    role: FunctionDemandRole,
    index: usize,
    slot: *ValueDemand,
    parent: ?usize = null,
};

const DemandSlotOwner = enum {
    loop_param,
    fn_param,
};

const DemandSlotEndpoint = struct {
    kind: DemandSlotOwner,
    id: usize,
};

const DemandSlotEdge = struct {
    lhs: ?DemandSlotEndpoint,
    rhs: ?DemandSlotEndpoint,
};

const FieldDemand = struct {
    name: names.RecordFieldNameId,
    demand: *const ValueDemand,
};

const ItemDemand = struct {
    index: u32,
    demand: *const ValueDemand,
};

const TagAlternativeDemand = struct {
    name: names.TagNameId,
    payloads: []const ItemDemand,
};

const TagDemand = struct {
    alternatives: []const TagAlternativeDemand,
};

const CallableDemand = struct {
    captures: []const ValueDemand,
    result: ?*const ValueDemand = null,
};

const Spec = struct {
    pattern: CallPattern,
    result_demand: ValueDemand,
    compact_result: ?CompactResult,
    fn_id: ?Ast.FnId = null,
    written: bool = false,
};

const FnPlan = struct {
    used_args: []bool,
    arg_demands: []ValueDemand,
    used_captures: []bool,
    capture_demands: []ValueDemand,
    specs: std.ArrayList(Spec),

    fn deinit(self: *FnPlan, allocator: Allocator) void {
        allocator.free(self.capture_demands);
        allocator.free(self.used_captures);
        allocator.free(self.arg_demands);
        allocator.free(self.used_args);
        self.specs.deinit(allocator);
    }
};

