const OptimizedContext = struct {
    allocator: Allocator,
    arena: std.heap.ArenaAllocator,
    program: *Ast.Program,
    solved: ?*const Solved.Program,
    inline_plan: SolvedInline.Plan,
    plans: []FnPlan,
    original_bodies: []const ?Ast.ExprId,
    worker_worklist: std.ArrayList(WorkerJob),
    callable_specializations: std.ArrayList(CallableSpecialization),
    symbols: Common.SymbolGen,

    fn init(
        allocator: Allocator,
        program: *Ast.Program,
        solved: ?*const Solved.Program,
        inline_plan: SolvedInline.Plan,
    ) Allocator.Error!OptimizedContext {
        var arena = std.heap.ArenaAllocator.init(allocator);
        errdefer arena.deinit();

        const plans = try allocator.alloc(FnPlan, program.fns.items.len);
        errdefer allocator.free(plans);

        for (plans, 0..) |*plan, index| {
            const fn_ = program.fns.items[index];
            const args = program.typedLocalSpan(fn_.args);
            const used_args = try allocator.alloc(bool, args.len);
            errdefer allocator.free(used_args);
            @memset(used_args, false);
            const arg_demands = try allocator.alloc(ValueDemand, args.len);
            errdefer allocator.free(arg_demands);
            @memset(arg_demands, .none);

            const captures = program.typedLocalSpan(fn_.captures);
            const used_captures = try allocator.alloc(bool, captures.len);
            errdefer allocator.free(used_captures);
            @memset(used_captures, false);
            const capture_demands = try allocator.alloc(ValueDemand, captures.len);
            errdefer allocator.free(capture_demands);
            @memset(capture_demands, .none);

            plan.* = .{
                .used_args = used_args,
                .arg_demands = arg_demands,
                .used_captures = used_captures,
                .capture_demands = capture_demands,
                .specs = .empty,
            };
        }

        return .{
            .allocator = allocator,
            .arena = arena,
            .program = program,
            .solved = solved,
            .inline_plan = inline_plan,
            .plans = plans,
            .original_bodies = &.{},
            .worker_worklist = .empty,
            .callable_specializations = .empty,
            .symbols = .{ .next = program.next_symbol },
        };
    }

    fn deinit(self: *OptimizedContext) void {
        self.callable_specializations.deinit(self.allocator);
        self.worker_worklist.deinit(self.allocator);
        for (self.plans) |*plan| plan.deinit(self.allocator);
        self.allocator.free(self.plans);
        self.arena.deinit();
    }

    fn solvedSingleCallableMember(self: *const OptimizedContext, expr_id: Ast.ExprId) ?SolvedType.FnMember {
        const solved = self.solved orelse return null;
        const raw = @intFromEnum(expr_id);
        if (raw >= solved.expr_tys.items.len) return null;
        return self.solvedSingleCallableMemberFromType(solved.expr_tys.items[raw]);
    }

    fn solvedSingleCallableMemberFromType(self: *const OptimizedContext, ty: SolvedType.TypeVarId) ?SolvedType.FnMember {
        const solved = self.solved orelse return null;
        const callable_ty = switch (solved.types.rootContent(ty)) {
            .func => |func| func.callable,
            .lambda_set => ty,
            else => return null,
        };
        const members = switch (solved.types.rootContent(callable_ty)) {
            .lambda_set => |members| members,
            else => return null,
        };
        const member_items = solved.types.memberSpan(members);
        if (member_items.len == 0) return null;
        if (member_items.len != 1 and !self.solvedCallableMembersAreEquivalent(member_items)) return null;
        return member_items[0];
    }

    fn solvedCallableMembersAreEquivalent(self: *const OptimizedContext, members: []const SolvedType.FnMember) bool {
        if (members.len <= 1) return true;

        const first_fn_id = self.fnWithSymbol(members[0].lambda) orelse return false;
        const solved = self.solved orelse return false;
        const first_captures = solved.types.captureSpan(members[0].captures);

        for (members[1..]) |member| {
            const fn_id = self.fnWithSymbol(member.lambda) orelse return false;
            if (!callableTargetMatches(self.program, first_fn_id, fn_id)) return false;

            const captures = solved.types.captureSpan(member.captures);
            if (captures.len != first_captures.len) return false;
            for (first_captures, captures) |first_capture, capture| {
                if (first_capture.local != capture.local) return false;
            }
        }

        return true;
    }

    fn fnWithSymbol(self: *const OptimizedContext, symbol: Common.Symbol) ?Ast.FnId {
        for (self.program.fns.items, 0..) |fn_, index| {
            if (fn_.symbol == symbol) return @enumFromInt(@as(u32, @intCast(index)));
        }
        return null;
    }

    fn primitiveType(self: *OptimizedContext, primitive: Type.Primitive) Allocator.Error!Type.TypeId {
        return try self.program.types.add(.{ .primitive = primitive });
    }

    fn unitType(self: *OptimizedContext) Allocator.Error!Type.TypeId {
        return try self.program.types.add(.{ .record = .empty() });
    }

    fn compactSlotTupleType(self: *OptimizedContext, slot_tys: []const Type.TypeId) Allocator.Error!Type.TypeId {
        return switch (slot_tys.len) {
            0 => try self.unitType(),
            1 => slot_tys[0],
            else => try self.program.types.add(.{
                .tuple = try self.program.types.addSpan(slot_tys),
            }),
        };
    }

    fn compactFiniteTagsType(self: *OptimizedContext, finite_tags: DemandedKnownTags) Allocator.Error!Type.TypeId {
        if (finite_tags.alternatives.len == 1) {
            var slot_tys = std.ArrayList(Type.TypeId).empty;
            defer slot_tys.deinit(self.allocator);
            try self.appendCompactIndexedValueTypes(finite_tags.alternatives[0].payloads, &slot_tys);
            return try self.compactSlotTupleType(slot_tys.items);
        }

        const compact_tags = try self.allocator.alloc(Type.Tag, finite_tags.alternatives.len);
        defer self.allocator.free(compact_tags);

        for (finite_tags.alternatives, compact_tags) |alternative, *out| {
            var payload_tys = std.ArrayList(Type.TypeId).empty;
            defer payload_tys.deinit(self.allocator);
            try self.appendCompactIndexedValueTypes(alternative.payloads, &payload_tys);
            out.* = .{
                .name = alternative.name,
                .checked_name = checkedTagNameForDemandedTag(self.program, finite_tags.ty, alternative.name),
                .payloads = try self.program.types.addSpan(payload_tys.items),
            };
        }

        return try self.program.types.add(.{
            .tag_union = try self.program.types.addTags(compact_tags),
        });
    }

    fn compactFiniteCallablesType(self: *OptimizedContext, finite_callables: DemandedKnownCallables) Allocator.Error!Type.TypeId {
        if (finite_callables.alternatives.len == 1) {
            var slot_tys = std.ArrayList(Type.TypeId).empty;
            defer slot_tys.deinit(self.allocator);
            try self.appendCompactIndexedValueTypes(finite_callables.alternatives[0].captures, &slot_tys);
            return try self.compactSlotTupleType(slot_tys.items);
        }

        const compact_tags = try self.allocator.alloc(Type.Tag, finite_callables.alternatives.len);
        defer self.allocator.free(compact_tags);

        for (finite_callables.alternatives, compact_tags, 0..) |alternative, *out, index| {
            var payload_tys = std.ArrayList(Type.TypeId).empty;
            defer payload_tys.deinit(self.allocator);
            try self.appendCompactIndexedValueTypes(alternative.captures, &payload_tys);
            const tag_name = try self.compactCallableAlternativeTagName(index);
            out.* = .{
                .name = tag_name,
                .checked_name = tag_name,
                .payloads = try self.program.types.addSpan(payload_tys.items),
            };
        }

        return try self.program.types.add(.{
            .tag_union = try self.program.types.addTags(compact_tags),
        });
    }

    fn compactCallableAlternativeTagName(self: *OptimizedContext, index: usize) Allocator.Error!names.TagNameId {
        var buffer: [64]u8 = undefined;
        const text = std.fmt.bufPrint(&buffer, "SpecConstrCallable{d}", .{index}) catch
            Common.invariant("compact callable tag name buffer was too small");
        return try self.program.names.internTagLabel(text);
    }

    fn appendCompactIndexedValueTypes(
        self: *OptimizedContext,
        values: []const DemandedKnownIndexedValue,
        out: *std.ArrayList(Type.TypeId),
    ) Allocator.Error!void {
        for (values) |value| try self.appendCompactValueTypes(value.known_value, out);
    }

    fn appendCompactValueTypes(
        self: *OptimizedContext,
        known_value: DemandedKnownValue,
        out: *std.ArrayList(Type.TypeId),
    ) Allocator.Error!void {
        switch (known_value) {
            .any,
            .leaf,
            => |ty| try out.append(self.allocator, ty),
            .tag => |tag| try self.appendCompactIndexedValueTypes(tag.payloads, out),
            .record => |record| {
                for (record.fields) |field| try self.appendCompactValueTypes(field.known_value, out);
            },
            .tuple => |tuple| try self.appendCompactIndexedValueTypes(tuple.items, out),
            .nominal => |nominal| {
                if (nominal.backing) |backing| try self.appendCompactValueTypes(backing.*, out);
            },
            .callable => |callable| try self.appendCompactIndexedValueTypes(callable.captures, out),
            .finite_tags,
            .compact_finite_tags,
            => |finite_tags| try out.append(self.allocator, try self.compactFiniteTagsType(finite_tags)),
            .finite_callables,
            .compact_finite_callables,
            => |finite_callables| try out.append(self.allocator, try self.compactFiniteCallablesType(finite_callables)),
        }
    }

    fn run(self: *OptimizedContext) LowerError!void {
        const original_fn_count = self.plans.len;
        const original_bodies = try self.captureOriginalBodies(original_fn_count);
        defer self.allocator.free(original_bodies);
        self.original_bodies = original_bodies;

        try self.collectArgUses(original_fn_count);
        try self.rewriteBaseBodies(original_bodies);
        try self.createSpecializations(original_bodies);

        self.original_bodies = &.{};
        self.program.next_symbol = self.symbols.next;
    }

    fn originalBody(self: *const OptimizedContext, fn_id: Ast.FnId) ?Ast.ExprId {
        const index = @intFromEnum(fn_id);
        if (index >= self.original_bodies.len) return null;
        return self.original_bodies[index];
    }

    fn inlineBody(self: *const OptimizedContext, fn_id: Ast.FnId) ?Ast.ExprId {
        const index = @intFromEnum(fn_id);
        if (self.inline_plan.inline_bodies.len == 0 or index >= self.inline_plan.inline_bodies.len) return null;
        return self.inline_plan.inline_bodies[index];
    }

    fn materializeInlineBody(self: *const OptimizedContext, fn_id: Ast.FnId) ?Ast.ExprId {
        const index = @intFromEnum(fn_id);
        if (self.inline_plan.materialize_bodies.len == 0 or index >= self.inline_plan.materialize_bodies.len) return null;
        return self.inline_plan.materialize_bodies[index];
    }

    fn copyProcDebugName(self: *OptimizedContext, source_symbol: Common.Symbol, target_symbol: Common.Symbol) Allocator.Error!void {
        if (self.program.procDebugName(source_symbol)) |name| {
            try self.program.setProcDebugName(target_symbol, name);
        }
    }

    fn captureOriginalBodies(self: *OptimizedContext, original_fn_count: usize) Allocator.Error![]?Ast.ExprId {
        const original_bodies = try self.allocator.alloc(?Ast.ExprId, original_fn_count);
        for (self.program.fns.items[0..original_fn_count], original_bodies) |fn_, *body_slot| {
            body_slot.* = switch (fn_.body) {
                .roc => |body| body,
                .hosted => null,
            };
        }
        return original_bodies;
    }

    fn collectArgUses(self: *OptimizedContext, original_fn_count: usize) LowerError!void {
        var changed = true;
        var iterations: usize = 0;
        while (changed) {
            iterations += 1;
            if (iterations > 1000) Common.invariant("argument-use demand propagation did not converge");
            changed = false;
            for (self.program.fns.items[0..original_fn_count], 0..) |fn_, index| {
                const body = switch (fn_.body) {
                    .roc => |body| body,
                    .hosted => continue,
                };
                const fn_id: Ast.FnId = @enumFromInt(@as(u32, @intCast(index)));
                try self.markArgUsesInExpr(fn_id, body, &changed);
            }
        }
    }

    fn rewriteBaseBodies(self: *OptimizedContext, original_bodies: []const ?Ast.ExprId) LowerError!void {
        for (original_bodies, 0..) |maybe_body, index| {
            const body_expr = maybe_body orelse continue;
            const fn_id: Ast.FnId = @enumFromInt(@as(u32, @intCast(index)));

            var cloner = Cloner.initForBaseBody(self, fn_id);
            defer cloner.deinit();

            try cloner.inline_stack.append(self.allocator, .{ .fn_id = fn_id });
            defer {
                const popped = cloner.inline_stack.pop() orelse Common.invariant("base body inline stack underflow");
                if (popped.fn_id != fn_id) Common.invariant("base body inline stack was corrupted");
            }

            const cloned_body = try cloner.cloneExpr(body_expr);
            self.program.fns.items[index].body = .{ .roc = cloned_body };
        }
    }

    fn createSpecializations(self: *OptimizedContext, original_bodies: []const ?Ast.ExprId) LowerError!void {
        while (self.worker_worklist.pop()) |job| {
            const source_index = @intFromEnum(job.source_fn);
            const source_body = original_bodies[source_index] orelse
                Common.invariant("hosted function had a call-pattern specialization");
            if (self.plans[source_index].specs.items[job.spec_index].written) continue;

            self.plans[source_index].specs.items[job.spec_index].written = true;
            try self.writeSpecialization(job.source_fn, job.spec_index, source_body);
        }
    }

    fn markArgUsesInExpr(self: *OptimizedContext, fn_id: Ast.FnId, expr_id: Ast.ExprId, changed: *bool) LowerError!void {
        const expr = self.program.exprs.items[@intFromEnum(expr_id)];
        switch (expr.data) {
            .local => try self.markArgUseIfLocal(fn_id, expr_id, changed),
            .unit,
            .int_lit,
            .frac_f32_lit,
            .frac_f64_lit,
            .dec_lit,
            .str_lit,
            .static_data,
            .crash,
            .comptime_exhaustiveness_failed,
            .uninitialized,
            .uninitialized_payload,
            => {},
            .fn_ref => |target| {
                const target_fn = self.program.fns.items[@intFromEnum(target)];
                const target_captures = self.program.typedLocalSpan(target_fn.captures);
                const target_raw = @intFromEnum(target);
                const target_plan = if (target_raw < self.plans.len and target_fn.body == .roc)
                    self.plans[target_raw]
                else
                    null;
                for (target_captures, 0..) |capture, index| {
                    const capture_demand = if (target_plan) |plan|
                        if (index < plan.used_captures.len and plan.used_captures[index])
                            plan.capture_demands[index]
                        else
                            .none
                    else
                        .materialize;
                    try self.markArgDemandForLocal(fn_id, capture.local, capture_demand, changed);
                }
            },
            .fn_ref_captures => |fn_ref| {
                const target_fn = self.program.fns.items[@intFromEnum(fn_ref.target)];
                const target_captures = self.program.typedLocalSpan(target_fn.captures);
                const capture_exprs = self.program.exprSpan(fn_ref.captures);
                if (target_captures.len != capture_exprs.len) {
                    Common.invariant("explicit function reference capture count differed from target function captures");
                }
                const target_raw = @intFromEnum(fn_ref.target);
                const target_plan = if (target_raw < self.plans.len and target_fn.body == .roc)
                    self.plans[target_raw]
                else
                    null;
                for (capture_exprs, 0..) |capture_expr, index| {
                    const capture_demand = if (target_plan) |plan|
                        if (index < plan.used_captures.len and plan.used_captures[index])
                            plan.capture_demands[index]
                        else
                            .none
                    else
                        .materialize;
                    try self.markArgDemandInExpr(fn_id, capture_expr, capture_demand, changed);
                }
            },
            .static_data_candidate => |candidate| try self.markArgUsesInExpr(fn_id, candidate.restored_expr, changed),
            .list,
            .tuple,
            => |items| for (self.program.exprSpan(items)) |child| try self.markArgUsesInExpr(fn_id, child, changed),
            .record => |fields| for (self.program.fieldExprSpan(fields)) |field| try self.markArgUsesInExpr(fn_id, field.value, changed),
            .tag => |tag| for (self.program.exprSpan(tag.payloads)) |payload| try self.markArgUsesInExpr(fn_id, payload, changed),
            .nominal,
            .return_,
            .dbg,
            .expect,
            => |child| try self.markArgUsesInExpr(fn_id, child, changed),
            .expect_err => |expect_err| try self.markArgUsesInExpr(fn_id, expect_err.msg, changed),
            .comptime_branch_taken => |taken| try self.markArgUsesInExpr(fn_id, taken.body, changed),
            .let_ => |let_| {
                try self.markArgUsesInExpr(fn_id, let_.value, changed);
                try self.markArgUsesInExpr(fn_id, let_.rest, changed);
            },
            .lambda,
            .def_ref,
            .fn_def,
            => Common.invariant("pre-lift function expression reached call-pattern specialization"),
            .call_value => |call| {
                try self.markArgDemandInExpr(fn_id, call.callee, .{ .callable = .{
                    .captures = &.{},
                    .result = try self.storedDemand(.materialize),
                } }, changed);
                for (self.program.exprSpan(call.args)) |arg| try self.markArgUsesInExpr(fn_id, arg, changed);
            },
            .call_proc => |call| {
                const args = self.program.exprSpan(call.args);
                for (args) |arg| try self.markArgUsesInExpr(fn_id, arg, changed);
                const callee = Ast.callProcCallee(call);
                const callee_raw = @intFromEnum(callee);
                if (callee_raw < self.plans.len) {
                    const callee_uses = self.plans[callee_raw].used_args;
                    if (args.len != callee_uses.len) Common.invariant("direct call arity differed from lifted function arity while propagating argument uses");
                    const callee_demands = self.plans[callee_raw].arg_demands;
                    for (args, callee_uses, callee_demands) |arg, callee_uses_arg, callee_demand| {
                        if (callee_uses_arg) try self.markArgDemandIfLocal(fn_id, arg, callee_demand, changed);
                    }
                }
            },
            .low_level => |call| {
                for (self.program.exprSpan(call.args)) |arg| try self.markArgUsesInExpr(fn_id, arg, changed);
            },
            .field_access => |field| {
                try self.markArgDemandInExpr(
                    fn_id,
                    field.receiver,
                    try self.demandRecordField(field.field, .materialize),
                    changed,
                );
            },
            .tuple_access => |access| {
                try self.markArgDemandInExpr(
                    fn_id,
                    access.tuple,
                    try self.demandTupleItem(access.elem_index, .materialize),
                    changed,
                );
            },
            .structural_eq => |eq| {
                try self.markArgUsesInExpr(fn_id, eq.lhs, changed);
                try self.markArgUsesInExpr(fn_id, eq.rhs, changed);
            },
            .structural_hash => |h| {
                try self.markArgUsesInExpr(fn_id, h.value, changed);
                try self.markArgUsesInExpr(fn_id, h.hasher, changed);
            },
            .match_ => |match| {
                try self.markArgUseIfLocal(fn_id, match.scrutinee, changed);
                try self.markArgUsesInExpr(fn_id, match.scrutinee, changed);
                for (self.program.branchSpan(match.branches)) |branch| {
                    if (branch.guard) |guard| try self.markArgUsesInExpr(fn_id, guard, changed);
                    try self.markArgUsesInExpr(fn_id, branch.body, changed);
                }
            },
            .if_ => |if_| {
                for (self.program.ifBranchSpan(if_.branches)) |branch| {
                    try self.markArgUsesInExpr(fn_id, branch.cond, changed);
                    try self.markArgUsesInExpr(fn_id, branch.body, changed);
                }
                try self.markArgUsesInExpr(fn_id, if_.final_else, changed);
            },
            .block => |block| {
                for (self.program.stmtSpan(block.statements)) |stmt| try self.markArgUsesInStmt(fn_id, stmt, changed);
                try self.markArgUsesInExpr(fn_id, block.final_expr, changed);
            },
            .loop_ => |loop| {
                for (self.program.exprSpan(loop.initial_values)) |initial| try self.markArgUsesInExpr(fn_id, initial, changed);
                try self.markArgUsesInExpr(fn_id, loop.body, changed);
            },
            .state_loop => |state_loop| {
                for (self.program.exprSpan(state_loop.entry_values)) |initial| try self.markArgUsesInExpr(fn_id, initial, changed);
                for (self.program.stateLoopStateSpan(state_loop.states)) |state| {
                    try self.markArgUsesInExpr(fn_id, state.body, changed);
                }
            },
            .break_ => |maybe| if (maybe) |value| try self.markArgUsesInExpr(fn_id, value, changed),
            .continue_ => |continue_| for (self.program.exprSpan(continue_.values)) |value| try self.markArgUsesInExpr(fn_id, value, changed),
            .state_continue => |continue_| for (self.program.exprSpan(continue_.values)) |value| try self.markArgUsesInExpr(fn_id, value, changed),
            .if_initialized_payload => |payload_switch| {
                try self.markArgUsesInExpr(fn_id, payload_switch.cond, changed);
                try self.markArgUsesInExpr(fn_id, payload_switch.initialized, changed);
                try self.markArgUsesInExpr(fn_id, payload_switch.uninitialized, changed);
            },
            .try_sequence => |sequence| {
                try self.markArgUsesInExpr(fn_id, sequence.try_expr, changed);
                try self.markArgUsesInExpr(fn_id, sequence.ok_body, changed);
            },
            .try_record_sequence => |sequence| {
                try self.markArgUsesInExpr(fn_id, sequence.try_expr, changed);
                try self.markArgUsesInExpr(fn_id, sequence.ok_body, changed);
            },
        }
    }

    fn markArgUsesInStmt(self: *OptimizedContext, fn_id: Ast.FnId, stmt_id: Ast.StmtId, changed: *bool) LowerError!void {
        switch (self.program.stmts.items[@intFromEnum(stmt_id)]) {
            .let_ => |let_| try self.markArgUsesInExpr(fn_id, let_.value, changed),
            .expr,
            .expect,
            .dbg,
            .return_,
            => |expr| try self.markArgUsesInExpr(fn_id, expr, changed),
            .uninitialized, .crash => {},
        }
    }

    fn markArgUseIfLocal(self: *OptimizedContext, fn_id: Ast.FnId, expr_id: Ast.ExprId, changed: *bool) LowerError!void {
        try self.markArgDemandIfLocal(fn_id, expr_id, .materialize, changed);
    }

    fn markArgDemandInExpr(
        self: *OptimizedContext,
        fn_id: Ast.FnId,
        expr_id: Ast.ExprId,
        demand: ValueDemand,
        changed: *bool,
    ) LowerError!void {
        if (demand == .none) return;
        const expr = self.program.exprs.items[@intFromEnum(expr_id)];
        switch (expr.data) {
            .local => try self.markArgDemandIfLocal(fn_id, expr_id, demand, changed),
            .field_access => |field| try self.markArgDemandInExpr(
                fn_id,
                field.receiver,
                try self.demandRecordField(field.field, demand),
                changed,
            ),
            .tuple_access => |access| try self.markArgDemandInExpr(
                fn_id,
                access.tuple,
                try self.demandTupleItem(access.elem_index, demand),
                changed,
            ),
            .comptime_branch_taken => |taken| try self.markArgDemandInExpr(fn_id, taken.body, demand, changed),
            else => try self.markArgUsesInExpr(fn_id, expr_id, changed),
        }
    }

    fn markArgDemandIfLocal(
        self: *OptimizedContext,
        fn_id: Ast.FnId,
        expr_id: Ast.ExprId,
        demand: ValueDemand,
        changed: *bool,
    ) LowerError!void {
        if (demand == .none) return;
        const local = localExpr(self.program, expr_id) orelse return;
        try self.markArgDemandForLocal(fn_id, local, demand, changed);
    }

    fn markArgDemandForLocal(
        self: *OptimizedContext,
        fn_id: Ast.FnId,
        local: Ast.LocalId,
        demand: ValueDemand,
        changed: *bool,
    ) LowerError!void {
        if (demand == .none) return;
        const args = self.program.typedLocalSpan(self.program.fns.items[@intFromEnum(fn_id)].args);
        for (args, 0..) |arg, index| {
            if (arg.local == local) {
                const used = &self.plans[@intFromEnum(fn_id)].used_args[index];
                if (!used.*) {
                    used.* = true;
                    changed.* = true;
                }
                const merged = try self.mergeValueDemand(self.plans[@intFromEnum(fn_id)].arg_demands[index], demand);
                if (!valueDemandEql(self.program, self.plans[@intFromEnum(fn_id)].arg_demands[index], merged)) {
                    self.plans[@intFromEnum(fn_id)].arg_demands[index] = merged;
                    changed.* = true;
                }
                return;
            }
        }

        const captures = self.program.typedLocalSpan(self.program.fns.items[@intFromEnum(fn_id)].captures);
        for (captures, 0..) |capture, index| {
            if (capture.local == local) {
                const used = &self.plans[@intFromEnum(fn_id)].used_captures[index];
                if (!used.*) {
                    used.* = true;
                    changed.* = true;
                }
                const merged = try self.mergeValueDemand(self.plans[@intFromEnum(fn_id)].capture_demands[index], demand);
                if (!valueDemandEql(self.program, self.plans[@intFromEnum(fn_id)].capture_demands[index], merged)) {
                    self.plans[@intFromEnum(fn_id)].capture_demands[index] = merged;
                    changed.* = true;
                }
                return;
            }
        }
    }

    fn storedDemand(self: *OptimizedContext, demand: ValueDemand) Allocator.Error!*const ValueDemand {
        const stored = try self.arena.allocator().create(ValueDemand);
        stored.* = demand;
        return stored;
    }

    fn demandRecordField(self: *OptimizedContext, field: names.RecordFieldNameId, demand: ValueDemand) Allocator.Error!ValueDemand {
        const fields = try self.arena.allocator().alloc(FieldDemand, 1);
        fields[0] = .{
            .name = field,
            .demand = try self.storedDemand(demand),
        };
        return .{ .record = fields };
    }

    fn demandTupleItem(self: *OptimizedContext, index: u32, demand: ValueDemand) Allocator.Error!ValueDemand {
        const items = try self.arena.allocator().alloc(ItemDemand, 1);
        items[0] = .{
            .index = index,
            .demand = try self.storedDemand(demand),
        };
        return .{ .tuple = items };
    }

    fn mergeValueDemand(self: *OptimizedContext, existing: ValueDemand, incoming: ValueDemand) LowerError!ValueDemand {
        if (existing == .materialize or incoming == .materialize) return .materialize;
        if (existing == .none) return incoming;
        if (incoming == .none) return existing;
        if (std.meta.activeTag(existing) != std.meta.activeTag(incoming)) return .materialize;

        return switch (existing) {
            .none, .materialize => unreachable,
            .loop_param => |existing_index| if (existing_index == incoming.loop_param) existing else .materialize,
            .fn_param => if (functionDemandSlotIdEql(existing.fn_param, incoming.fn_param)) existing else .materialize,
            .record => try self.mergeRecordDemand(existing.record, incoming.record),
            .tuple => try self.mergeTupleDemand(existing.tuple, incoming.tuple),
            .tag => blk: {
                const alternatives = try self.mergeTagDemand(existing.tag.alternatives, incoming.tag.alternatives);
                break :blk ValueDemand{ .tag = .{ .alternatives = alternatives } };
            },
            .nominal => blk: {
                const merged = try self.mergeValueDemand(existing.nominal.*, incoming.nominal.*);
                break :blk ValueDemand{ .nominal = try self.storedDemand(merged) };
            },
            .callable => |existing_callable| blk: {
                const incoming_callable = incoming.callable;
                const captures_len = @max(existing_callable.captures.len, incoming_callable.captures.len);
                const captures = try self.arena.allocator().alloc(ValueDemand, captures_len);
                for (captures, 0..) |*out, index| {
                    const existing_capture = if (index < existing_callable.captures.len) existing_callable.captures[index] else .none;
                    const incoming_capture = if (index < incoming_callable.captures.len) incoming_callable.captures[index] else .none;
                    out.* = try self.mergeValueDemand(existing_capture, incoming_capture);
                }
                const result = if (existing_callable.result) |existing_result| result: {
                    if (incoming_callable.result) |incoming_result| {
                        const merged = try self.mergeValueDemand(existing_result.*, incoming_result.*);
                        break :result try self.storedDemand(merged);
                    }
                    break :result existing_result;
                } else incoming_callable.result;
                break :blk ValueDemand{ .callable = .{ .captures = captures, .result = result } };
            },
        };
    }

    fn mergeRecordDemand(
        self: *OptimizedContext,
        existing: []const FieldDemand,
        incoming: []const FieldDemand,
    ) LowerError!ValueDemand {
        var fields = std.ArrayList(FieldDemand).empty;
        defer fields.deinit(self.allocator);
        try fields.appendSlice(self.allocator, existing);

        for (incoming) |incoming_field| {
            for (fields.items) |*field| {
                if (!self.program.names.recordFieldLabelTextEql(field.name, incoming_field.name)) continue;
                const merged = try self.mergeValueDemand(field.demand.*, incoming_field.demand.*);
                field.demand = try self.storedDemand(merged);
                break;
            } else {
                try fields.append(self.allocator, incoming_field);
            }
        }

        return .{ .record = try self.arena.allocator().dupe(FieldDemand, fields.items) };
    }

    fn mergeTupleDemand(
        self: *OptimizedContext,
        existing: []const ItemDemand,
        incoming: []const ItemDemand,
    ) LowerError!ValueDemand {
        var items = std.ArrayList(ItemDemand).empty;
        defer items.deinit(self.allocator);
        try items.appendSlice(self.allocator, existing);

        for (incoming) |incoming_item| {
            for (items.items) |*item| {
                if (item.index != incoming_item.index) continue;
                const merged = try self.mergeValueDemand(item.demand.*, incoming_item.demand.*);
                item.demand = try self.storedDemand(merged);
                break;
            } else {
                try items.append(self.allocator, incoming_item);
            }
        }

        return .{ .tuple = try self.arena.allocator().dupe(ItemDemand, items.items) };
    }

    fn mergeTagDemand(
        self: *OptimizedContext,
        existing: []const TagAlternativeDemand,
        incoming: []const TagAlternativeDemand,
    ) LowerError![]const TagAlternativeDemand {
        var alternatives = std.ArrayList(TagAlternativeDemand).empty;
        defer alternatives.deinit(self.allocator);
        try alternatives.appendSlice(self.allocator, existing);

        for (incoming) |incoming_alternative| {
            for (alternatives.items) |*alternative| {
                if (!self.program.names.tagLabelTextEql(alternative.name, incoming_alternative.name)) continue;
                const merged = try self.mergeTupleDemand(alternative.payloads, incoming_alternative.payloads);
                alternative.payloads = merged.tuple;
                break;
            } else {
                try alternatives.append(self.allocator, incoming_alternative);
            }
        }

        return try self.arena.allocator().dupe(TagAlternativeDemand, alternatives.items);
    }

    fn valueDemandFromDemandedKnownValue(self: *OptimizedContext, known_value: DemandedKnownValue) LowerError!ValueDemand {
        return switch (known_value) {
            .any,
            .leaf,
            => .materialize,
            .record => |record| blk: {
                const fields = try self.arena.allocator().alloc(FieldDemand, record.fields.len);
                for (record.fields, fields) |field, *out| {
                    out.* = .{
                        .name = field.name,
                        .demand = try self.storedDemand(try self.valueDemandFromDemandedKnownValue(field.known_value)),
                    };
                }
                break :blk ValueDemand{ .record = fields };
            },
            .tuple => |tuple| blk: {
                const items = try self.valueDemandItemsFromDemandedKnownIndexedValues(tuple.items);
                break :blk ValueDemand{ .tuple = items };
            },
            .tag => |tag| blk: {
                const payloads = try self.valueDemandItemsFromDemandedKnownIndexedValues(tag.payloads);
                const alternatives = try self.arena.allocator().alloc(TagAlternativeDemand, 1);
                alternatives[0] = .{
                    .name = tag.name,
                    .payloads = payloads,
                };
                break :blk ValueDemand{ .tag = .{ .alternatives = alternatives } };
            },
            .nominal => |nominal| blk: {
                const backing = nominal.backing orelse break :blk .materialize;
                break :blk ValueDemand{ .nominal = try self.storedDemand(try self.valueDemandFromDemandedKnownValue(backing.*)) };
            },
            .callable => |callable| try self.valueDemandFromDemandedKnownCallable(callable),
            .finite_tags,
            .compact_finite_tags,
            => |finite_tags| blk: {
                var demand: ValueDemand = .none;
                for (finite_tags.alternatives) |alternative| {
                    demand = try self.mergeValueDemand(demand, try self.valueDemandFromDemandedKnownValue(.{ .tag = alternative }));
                }
                break :blk demand;
            },
            .finite_callables,
            .compact_finite_callables,
            => |finite_callables| blk: {
                var demand: ValueDemand = .none;
                for (finite_callables.alternatives) |alternative| {
                    demand = try self.mergeValueDemand(demand, try self.valueDemandFromDemandedKnownValue(.{ .callable = alternative }));
                }
                break :blk demand;
            },
        };
    }

    fn valueDemandItemsFromDemandedKnownIndexedValues(
        self: *OptimizedContext,
        indexed: []const DemandedKnownIndexedValue,
    ) LowerError![]const ItemDemand {
        const items = try self.arena.allocator().alloc(ItemDemand, indexed.len);
        for (indexed, items) |item, *out| {
            out.* = .{
                .index = item.index,
                .demand = try self.storedDemand(try self.valueDemandFromDemandedKnownValue(item.known_value)),
            };
        }
        return items;
    }

    fn valueDemandFromDemandedKnownCallable(self: *OptimizedContext, callable: DemandedKnownCallable) LowerError!ValueDemand {
        var captures_len: usize = 0;
        for (callable.captures) |capture| {
            captures_len = @max(captures_len, @as(usize, capture.index) + 1);
        }

        const captures = try self.arena.allocator().alloc(ValueDemand, captures_len);
        @memset(captures, .none);
        for (callable.captures) |capture| {
            captures[capture.index] = try self.valueDemandFromDemandedKnownValue(capture.known_value);
        }
        return .{ .callable = .{ .captures = captures } };
    }

    fn ensureCallPatternForValues(self: *OptimizedContext, fn_id: Ast.FnId, values: []const Value) LowerError!void {
        const raw = @intFromEnum(fn_id);
        if (raw >= self.plans.len) return;

        const fn_args = self.program.typedLocalSpan(self.program.fns.items[raw].args);
        if (values.len != fn_args.len) Common.invariant("direct call arity differed from lifted function arity");
        const fn_captures = self.program.typedLocalSpan(self.program.fns.items[raw].captures);
        const captures = try self.arena.allocator().alloc(CallPatternCapture, fn_captures.len);
        @memset(captures, .unused);

        const known_values = try self.arena.allocator().alloc(DemandedKnownValue, values.len);
        var has_constructor = false;
        for (values, 0..) |value, index| {
            if (self.plans[raw].used_args[index]) {
                if (try self.knownValueFromValue(value)) |known_value| {
                    if (try demandedKnownValueFromDemand(
                        null,
                        self.program,
                        self.arena.allocator(),
                        known_value,
                        self.plans[raw].arg_demands[index],
                    )) |demanded| {
                        known_values[index] = demanded;
                        has_constructor = has_constructor or demandedKnownValueHasStructure(demanded);
                        continue;
                    }
                }
            }
            known_values[index] = .{ .any = valueType(self.program, value) };
        }
        if (!has_constructor) return;

        const pattern: CallPattern = .{
            .captures = captures,
            .args = known_values,
        };
        for (self.plans[raw].specs.items) |spec| {
            if (specEql(self.program, spec, pattern, .materialize)) return;
        }

        const spec_index = self.plans[raw].specs.items.len;
        try self.plans[raw].specs.append(self.allocator, .{
            .pattern = pattern,
            .result_demand = .materialize,
            .compact_result = null,
        });
        try self.reserveWorker(@enumFromInt(@as(u32, @intCast(raw))), spec_index);
    }

    fn reserveWorker(self: *OptimizedContext, source_fn_id: Ast.FnId, spec_index: usize) Allocator.Error!void {
        const source_index = @intFromEnum(source_fn_id);
        const spec = &self.plans[source_index].specs.items[spec_index];
        if (spec.fn_id != null) Common.invariant("call-pattern specialization id was assigned twice");

        try self.program.fns.ensureUnusedCapacity(self.allocator, 1);
        try self.worker_worklist.ensureUnusedCapacity(self.allocator, 1);

        const source_fn = self.program.fns.items[source_index];
        const fn_id_reserved: Ast.FnId = @enumFromInt(@as(u32, @intCast(self.program.fns.items.len)));
        const symbol = self.symbols.fresh();
        const args = try self.callPatternArgSpan(spec.pattern);
        const captures = try self.callPatternCaptureSpan(source_fn_id, spec.pattern);
        spec.fn_id = fn_id_reserved;
        self.program.fns.appendAssumeCapacity(.{
            .symbol = symbol,
            .source = source_fn.source,
            .args = args,
            .captures = captures,
            .body = .hosted,
            .ret = source_fn.ret,
        });
        self.worker_worklist.appendAssumeCapacity(.{
            .source_fn = source_fn_id,
            .spec_index = spec_index,
        });
        try self.copyProcDebugName(source_fn.symbol, symbol);
    }

    fn callPatternArgSpan(self: *OptimizedContext, pattern: CallPattern) Allocator.Error!Ast.Span(Ast.TypedLocal) {
        var args = std.ArrayList(Ast.TypedLocal).empty;
        defer args.deinit(self.allocator);

        for (pattern.captures) |capture| {
            if (capture == .split) try self.appendDemandedKnownValueArgs(capture.split, &args);
        }
        for (pattern.args) |arg| try self.appendDemandedKnownValueArgs(arg, &args);

        return try self.program.addTypedLocalSpan(args.items);
    }

    fn callPatternCaptureSpan(self: *OptimizedContext, source_fn_id: Ast.FnId, pattern: CallPattern) Allocator.Error!Ast.Span(Ast.TypedLocal) {
        const source_fn = self.program.fns.items[@intFromEnum(source_fn_id)];
        const source_captures = self.program.typedLocalSpan(source_fn.captures);
        if (source_captures.len != pattern.captures.len) Common.invariant("call-pattern capture count differed from source function capture arity");

        var captures = std.ArrayList(Ast.TypedLocal).empty;
        defer captures.deinit(self.allocator);
        for (source_captures, pattern.captures) |capture, pattern_capture| {
            if (pattern_capture == .residual) try captures.append(self.allocator, capture);
        }

        return try self.program.addTypedLocalSpan(captures.items);
    }

    fn appendDemandedKnownValueArgs(
        self: *OptimizedContext,
        known_value: DemandedKnownValue,
        args: *std.ArrayList(Ast.TypedLocal),
    ) Allocator.Error!void {
        switch (known_value) {
            .any,
            .leaf,
            => |ty| {
                const local = try self.program.addLocal(self.symbols.fresh(), ty);
                try args.append(self.allocator, .{ .local = local, .ty = ty });
            },
            .tag => |tag| try self.appendDemandedKnownIndexedValueArgs(tag.payloads, args),
            .record => |record| {
                for (record.fields) |field| try self.appendDemandedKnownValueArgs(field.known_value, args);
            },
            .tuple => |tuple| try self.appendDemandedKnownIndexedValueArgs(tuple.items, args),
            .nominal => |nominal| if (nominal.backing) |backing| try self.appendDemandedKnownValueArgs(backing.*, args),
            .callable => |callable| try self.appendDemandedKnownIndexedValueArgs(callable.captures, args),
            .finite_tags => |finite_tags| {
                const selector_ty = try self.primitiveType(.u64);
                const selector = try self.program.addLocal(self.symbols.fresh(), selector_ty);
                try args.append(self.allocator, .{ .local = selector, .ty = selector_ty });
                for (finite_tags.alternatives) |alternative| {
                    try self.appendDemandedKnownIndexedValueArgs(alternative.payloads, args);
                }
            },
            .compact_finite_tags => |finite_tags| {
                const compact_ty = try self.compactFiniteTagsType(finite_tags);
                const local = try self.program.addLocal(self.symbols.fresh(), compact_ty);
                try args.append(self.allocator, .{ .local = local, .ty = compact_ty });
            },
            .finite_callables => |finite_callables| {
                const selector_ty = try self.primitiveType(.u64);
                const selector = try self.program.addLocal(self.symbols.fresh(), selector_ty);
                try args.append(self.allocator, .{ .local = selector, .ty = selector_ty });
                for (finite_callables.alternatives) |alternative| {
                    try self.appendDemandedKnownIndexedValueArgs(alternative.captures, args);
                }
            },
            .compact_finite_callables => |finite_callables| {
                const compact_ty = try self.compactFiniteCallablesType(finite_callables);
                const local = try self.program.addLocal(self.symbols.fresh(), compact_ty);
                try args.append(self.allocator, .{ .local = local, .ty = compact_ty });
            },
        }
    }

    fn appendDemandedKnownIndexedValueArgs(
        self: *OptimizedContext,
        known_values: []const DemandedKnownIndexedValue,
        args: *std.ArrayList(Ast.TypedLocal),
    ) Allocator.Error!void {
        for (known_values) |known_value| try self.appendDemandedKnownValueArgs(known_value.known_value, args);
    }

    fn writeSpecialization(self: *OptimizedContext, source_fn_id: Ast.FnId, spec_index: usize, source_body: Ast.ExprId) LowerError!void {
        const source_fn = self.program.fns.items[@intFromEnum(source_fn_id)];
        const spec = &self.plans[@intFromEnum(source_fn_id)].specs.items[spec_index];

        const spec_fn_id = spec.fn_id orelse Common.invariant("call-pattern specialization id was not assigned before cloning");
        const symbol = self.program.fns.items[@intFromEnum(spec_fn_id)].symbol;
        const captures = self.program.fns.items[@intFromEnum(spec_fn_id)].captures;

        var cloner = Cloner.init(self, source_fn_id, spec_fn_id, spec.pattern);
        defer cloner.deinit();

        const args = self.program.fns.items[@intFromEnum(spec_fn_id)].args;
        try cloner.bindCallPatternArgs(args);

        const active_args = if (spec.compact_result != null) active_args: {
            const source_args = self.program.typedLocalSpan(source_fn.args);
            const values = try self.allocator.alloc(Value, source_args.len);
            defer self.allocator.free(values);
            for (source_args, values) |source_arg, *value| {
                value.* = cloner.subst.get(source_arg.local) orelse
                    Common.invariant("specialized worker source arg was not bound by its call pattern");
            }
            break :active_args try cloner.directCallActiveArgsFromValues(values);
        } else null;

        try cloner.inline_stack.append(self.allocator, .{
            .fn_id = source_fn_id,
            .args = active_args,
        });
        defer {
            const popped = cloner.inline_stack.pop() orelse Common.invariant("call-pattern inline stack underflow while writing specialization");
            if (popped.fn_id != source_fn_id) Common.invariant("call-pattern inline stack was corrupted while writing specialization");
        }

        const body_expr = if (spec.compact_result) |result| body: {
            const value = try cloner.cloneExprValueWithDemand(source_body, spec.result_demand);
            break :body try cloner.compactResultExpr(result, value);
        } else try cloner.cloneExpr(source_body);
        const body: Ast.FnBody = .{ .roc = body_expr };

        self.program.fns.items[@intFromEnum(spec_fn_id)] = .{
            .symbol = symbol,
            .source = source_fn.source,
            .args = args,
            .captures = captures,
            .body = body,
            .ret = if (spec.compact_result) |result| result.ty else source_fn.ret,
        };
        try self.copyProcDebugName(source_fn.symbol, symbol);
    }

    fn constructorKnownValue(self: *OptimizedContext, expr_id: Ast.ExprId) Allocator.Error!?KnownValue {
        const expr = self.program.exprs.items[@intFromEnum(expr_id)];
        return switch (expr.data) {
            .unit,
            .int_lit,
            .frac_f32_lit,
            .frac_f64_lit,
            .dec_lit,
            .str_lit,
            .static_data,
            .list,
            => KnownValue{ .leaf = expr.ty },
            .tag => |tag| blk: {
                const payloads = self.program.exprSpan(tag.payloads);
                const known_values = try self.arena.allocator().alloc(KnownValue, payloads.len);
                for (payloads, 0..) |payload, index| {
                    known_values[index] = (try self.constructorKnownValue(payload)) orelse
                        .{ .any = self.program.exprs.items[@intFromEnum(payload)].ty };
                }
                break :blk KnownValue{ .tag = .{
                    .ty = expr.ty,
                    .name = tag.name,
                    .payloads = known_values,
                } };
            },
            .record => |fields_span| blk: {
                const fields = self.program.fieldExprSpan(fields_span);
                const known_values = try self.arena.allocator().alloc(KnownField, fields.len);
                for (fields, 0..) |field, index| {
                    known_values[index] = .{
                        .name = field.name,
                        .known_value = (try self.constructorKnownValue(field.value)) orelse
                            .{ .any = self.program.exprs.items[@intFromEnum(field.value)].ty },
                    };
                }
                break :blk KnownValue{ .record = .{
                    .ty = expr.ty,
                    .fields = known_values,
                } };
            },
            .tuple => |items_span| blk: {
                const items = self.program.exprSpan(items_span);
                const known_values = try self.arena.allocator().alloc(KnownValue, items.len);
                for (items, 0..) |item, index| {
                    known_values[index] = (try self.constructorKnownValue(item)) orelse
                        .{ .any = self.program.exprs.items[@intFromEnum(item)].ty };
                }
                break :blk KnownValue{ .tuple = .{
                    .ty = expr.ty,
                    .items = known_values,
                } };
            },
            .nominal => |backing| blk: {
                const backing_known_value = (try self.constructorKnownValue(backing)) orelse break :blk null;
                const stored = try self.arena.allocator().create(KnownValue);
                stored.* = backing_known_value;
                break :blk KnownValue{ .nominal = .{
                    .ty = expr.ty,
                    .backing = stored,
                } };
            },
            .fn_ref => |fn_id| blk: {
                const fn_ = self.program.fns.items[@intFromEnum(fn_id)];
                const captures = self.program.typedLocalSpan(fn_.captures);
                const capture_known_values = try self.arena.allocator().alloc(KnownValue, captures.len);
                for (captures, 0..) |capture, index| {
                    capture_known_values[index] = .{ .any = capture.ty };
                }
                break :blk KnownValue{ .callable = .{
                    .ty = expr.ty,
                    .fn_id = fn_id,
                    .captures = capture_known_values,
                } };
            },
            .fn_ref_captures => |fn_ref| blk: {
                const fn_ = self.program.fns.items[@intFromEnum(fn_ref.target)];
                const target_captures = self.program.typedLocalSpan(fn_.captures);
                const capture_exprs = self.program.exprSpan(fn_ref.captures);
                if (target_captures.len != capture_exprs.len) {
                    Common.invariant("explicit function reference capture count differed from target function captures");
                }
                const capture_known_values = try self.arena.allocator().alloc(KnownValue, capture_exprs.len);
                for (capture_exprs, 0..) |capture_expr, index| {
                    capture_known_values[index] = (try self.constructorKnownValue(capture_expr)) orelse
                        .{ .any = self.program.exprs.items[@intFromEnum(capture_expr)].ty };
                }
                break :blk KnownValue{ .callable = .{
                    .ty = expr.ty,
                    .fn_id = fn_ref.target,
                    .captures = capture_known_values,
                } };
            },
            else => null,
        };
    }

    fn knownValueFromValue(self: *OptimizedContext, value: Value) Allocator.Error!?KnownValue {
        return switch (value) {
            .expr => |expr| try self.constructorKnownValue(expr),
            .expr_with_known_value => |known_value_expr| known_value_expr.known_value,
            .let_ => |let_value| try self.knownValueFromValue(let_value.body.*),
            .if_ => |if_value| blk: {
                var joined: ?KnownValue = null;
                for (if_value.branches) |branch| {
                    const branch_known_value = (try self.knownValueFromValue(branch.body)) orelse break :blk null;
                    joined = if (joined) |existing|
                        (try joinKnownValuesInArena(self.program, self.arena.allocator(), existing, branch_known_value)) orelse break :blk null
                    else
                        branch_known_value;
                }
                const final_known_value = (try self.knownValueFromValue(if_value.final_else.*)) orelse break :blk null;
                break :blk if (joined) |existing|
                    (try joinKnownValuesInArena(self.program, self.arena.allocator(), existing, final_known_value)) orelse null
                else
                    final_known_value;
            },
            .match_ => |match_value| blk: {
                var joined: ?KnownValue = null;
                for (match_value.branches) |branch| {
                    const branch_known_value = (try self.knownValueFromValue(branch.body)) orelse break :blk null;
                    joined = if (joined) |existing|
                        (try joinKnownValuesInArena(self.program, self.arena.allocator(), existing, branch_known_value)) orelse break :blk null
                    else
                        branch_known_value;
                }
                break :blk joined;
            },
            .tag => |tag| blk: {
                const payloads = try self.arena.allocator().alloc(KnownValue, tag.payloads.len);
                for (tag.payloads, 0..) |payload, index| {
                    payloads[index] = (try self.knownValueFromValue(payload)) orelse
                        .{ .any = valueType(self.program, payload) };
                }
                break :blk KnownValue{ .tag = .{
                    .ty = tag.ty,
                    .name = tag.name,
                    .payloads = payloads,
                } };
            },
            .record => |record| blk: {
                const fields = try self.arena.allocator().alloc(KnownField, record.fields.len);
                for (record.fields, 0..) |field, index| {
                    fields[index] = .{
                        .name = field.name,
                        .known_value = (try self.knownValueFromValue(field.value)) orelse
                            .{ .any = valueType(self.program, field.value) },
                    };
                }
                break :blk KnownValue{ .record = .{
                    .ty = record.ty,
                    .fields = fields,
                } };
            },
            .tuple => |tuple| blk: {
                const items = try self.arena.allocator().alloc(KnownValue, tuple.items.len);
                for (tuple.items, 0..) |item, index| {
                    items[index] = (try self.knownValueFromValue(item)) orelse
                        .{ .any = valueType(self.program, item) };
                }
                break :blk KnownValue{ .tuple = .{
                    .ty = tuple.ty,
                    .items = items,
                } };
            },
            .nominal => |nominal| blk: {
                const backing_known_value = (try self.knownValueFromValue(nominal.backing.*)) orelse break :blk null;
                const stored = try self.arena.allocator().create(KnownValue);
                stored.* = backing_known_value;
                break :blk KnownValue{ .nominal = .{
                    .ty = nominal.ty,
                    .backing = stored,
                } };
            },
            .callable => |callable| blk: {
                const captures = try self.arena.allocator().alloc(KnownValue, callable.captures.len);
                for (callable.captures, 0..) |capture, index| {
                    captures[index] = (try self.knownValueFromValue(capture)) orelse
                        (try leafKnownValueFromValue(self.program, capture)) orelse
                        .{ .any = valueType(self.program, capture) };
                }
                break :blk KnownValue{ .callable = .{
                    .ty = callable.ty,
                    .fn_id = callable.fn_id,
                    .captures = captures,
                } };
            },
            .finite_tags => |finite_tags| blk: {
                const alternatives = try self.arena.allocator().alloc(KnownTag, finite_tags.alternatives.len);
                for (finite_tags.alternatives, alternatives) |alternative, *out| {
                    const payloads = try self.arena.allocator().alloc(KnownValue, alternative.payloads.len);
                    for (alternative.payloads, payloads) |payload, *payload_out| {
                        payload_out.* = (try self.knownValueFromValue(payload)) orelse
                            .{ .any = valueType(self.program, payload) };
                    }
                    out.* = .{
                        .ty = alternative.ty,
                        .name = alternative.name,
                        .payloads = payloads,
                    };
                }
                break :blk KnownValue{ .finite_tags = .{
                    .ty = finite_tags.ty,
                    .alternatives = alternatives,
                } };
            },
            .finite_callables => |finite_callables| blk: {
                const alternatives = try self.arena.allocator().alloc(KnownCallable, finite_callables.alternatives.len);
                for (finite_callables.alternatives, alternatives) |alternative, *out| {
                    const captures = try self.arena.allocator().alloc(KnownValue, alternative.captures.len);
                    for (alternative.captures, captures) |capture, *capture_out| {
                        capture_out.* = (try self.knownValueFromValue(capture)) orelse
                            (try leafKnownValueFromValue(self.program, capture)) orelse
                            .{ .any = valueType(self.program, capture) };
                    }
                    out.* = .{
                        .ty = alternative.ty,
                        .fn_id = alternative.fn_id,
                        .captures = captures,
                    };
                }
                break :blk KnownValue{ .finite_callables = .{
                    .ty = finite_callables.ty,
                    .alternatives = alternatives,
                } };
            },
            .private_state => |private_state| try knownValueFromPrivateState(self.program, self.arena.allocator(), private_state),
        };
    }
};

const Cloner = struct {
    pass: *OptimizedContext,
    source_fn: Ast.FnId,
    output_fn: Ast.FnId,
    pattern: CallPattern,
    subst: std.AutoHashMap(Ast.LocalId, Value),
    state_loop_state_map: std.AutoHashMap(Ast.StateLoopStateId, Ast.StateLoopStateId),
    changes: std.ArrayList(BindingChange),
    inline_stack: std.ArrayList(ActiveInline),
    demand_stack: std.ArrayList(ActiveDemand),
    function_demand_nodes: std.ArrayList(FunctionDemandNode),
    function_demand_merge_stack: std.ArrayList(FunctionDemandMergeFrame),
    loop_demand_merge_stack: std.ArrayList(LoopDemandMergeFrame),
    demand_slot_edge_scratch: std.ArrayList(DemandSlotEdge),
    local_demand_stack: std.ArrayList(LocalDemandFrame),
    local_demand_cache: std.ArrayList(LocalDemandCacheEntry),
    function_demand_cache: std.ArrayList(FunctionDemandCacheEntry),
    local_demand_cache_index: std.AutoHashMap(LocalDemandCacheId, std.ArrayList(usize)),
    function_demand_cache_index: std.AutoHashMap(FunctionDemandCacheId, std.ArrayList(usize)),
    loop_stack: std.ArrayList(LoopPattern),
    state_loop_stack: std.ArrayList(SparseStateLoopPattern),
    state_param_stack: std.ArrayList([]const Ast.TypedLocal),
    scoped_locals: std.ArrayList(Ast.LocalId),
    active_pending_lets: std.ArrayList(PendingLet),
    inline_direct_calls: bool,
    inline_direct_requires_known_arg: bool,
    record_call_patterns: bool,
    source_arg_locals_in_scope: bool,
    current_loc: SourceLoc,
    current_region: Region,
    demand_cache_epoch: usize,
    active_demand_resolves: usize,
    inline_safe_binding_check: bool,
    subst_scope_id: usize,
    next_subst_scope_id: usize,
    next_demand_frame_id: usize,
    merge_value_demand_depth: usize,
    demanded_known_depth: usize,

    fn init(pass: *OptimizedContext, source_fn: Ast.FnId, output_fn: Ast.FnId, pattern: CallPattern) Cloner {
        return .{
            .pass = pass,
            .source_fn = source_fn,
            .output_fn = output_fn,
            .pattern = pattern,
            .subst = std.AutoHashMap(Ast.LocalId, Value).init(pass.allocator),
            .state_loop_state_map = std.AutoHashMap(Ast.StateLoopStateId, Ast.StateLoopStateId).init(pass.allocator),
            .changes = .empty,
            .inline_stack = .empty,
            .demand_stack = .empty,
            .function_demand_nodes = .empty,
            .function_demand_merge_stack = .empty,
            .loop_demand_merge_stack = .empty,
            .demand_slot_edge_scratch = .empty,
            .local_demand_stack = .empty,
            .local_demand_cache = .empty,
            .function_demand_cache = .empty,
            .local_demand_cache_index = std.AutoHashMap(LocalDemandCacheId, std.ArrayList(usize)).init(pass.allocator),
            .function_demand_cache_index = std.AutoHashMap(FunctionDemandCacheId, std.ArrayList(usize)).init(pass.allocator),
            .loop_stack = .empty,
            .state_loop_stack = .empty,
            .state_param_stack = .empty,
            .scoped_locals = .empty,
            .active_pending_lets = .empty,
            .inline_direct_calls = true,
            .inline_direct_requires_known_arg = true,
            .record_call_patterns = true,
            .source_arg_locals_in_scope = false,
            .current_loc = SourceLoc.none,
            .current_region = Region.zero(),
            .demand_cache_epoch = 0,
            .active_demand_resolves = 0,
            .inline_safe_binding_check = false,
            .subst_scope_id = 0,
            .next_subst_scope_id = 1,
            .next_demand_frame_id = 1,
            .merge_value_demand_depth = 0,
            .demanded_known_depth = 0,
        };
    }

    fn initForBaseClone(pass: *OptimizedContext) Cloner {
        return .{
            .pass = pass,
            .source_fn = undefined, // Set by initForBaseBody before any source-function state is read.
            .output_fn = undefined, // Set by initForBaseBody before any output-function locals are read.
            .pattern = .{ .args = &.{} },
            .subst = std.AutoHashMap(Ast.LocalId, Value).init(pass.allocator),
            .state_loop_state_map = std.AutoHashMap(Ast.StateLoopStateId, Ast.StateLoopStateId).init(pass.allocator),
            .changes = .empty,
            .inline_stack = .empty,
            .demand_stack = .empty,
            .function_demand_nodes = .empty,
            .function_demand_merge_stack = .empty,
            .loop_demand_merge_stack = .empty,
            .demand_slot_edge_scratch = .empty,
            .local_demand_stack = .empty,
            .local_demand_cache = .empty,
            .function_demand_cache = .empty,
            .local_demand_cache_index = std.AutoHashMap(LocalDemandCacheId, std.ArrayList(usize)).init(pass.allocator),
            .function_demand_cache_index = std.AutoHashMap(FunctionDemandCacheId, std.ArrayList(usize)).init(pass.allocator),
            .loop_stack = .empty,
            .state_loop_stack = .empty,
            .state_param_stack = .empty,
            .scoped_locals = .empty,
            .active_pending_lets = .empty,
            .inline_direct_calls = true,
            .inline_direct_requires_known_arg = false,
            .record_call_patterns = true,
            .source_arg_locals_in_scope = false,
            .current_loc = SourceLoc.none,
            .current_region = Region.zero(),
            .demand_cache_epoch = 0,
            .active_demand_resolves = 0,
            .inline_safe_binding_check = false,
            .subst_scope_id = 0,
            .next_subst_scope_id = 1,
            .next_demand_frame_id = 1,
            .merge_value_demand_depth = 0,
            .demanded_known_depth = 0,
        };
    }

    fn initForBaseBody(pass: *OptimizedContext, source_fn: Ast.FnId) Cloner {
        var cloner = Cloner.initForBaseClone(pass);
        cloner.source_fn = source_fn;
        cloner.output_fn = source_fn;
        cloner.inline_direct_requires_known_arg = true;
        cloner.source_arg_locals_in_scope = true;
        return cloner;
    }

    fn deinit(self: *Cloner) void {
        self.active_pending_lets.deinit(self.pass.allocator);
        self.scoped_locals.deinit(self.pass.allocator);
        self.state_param_stack.deinit(self.pass.allocator);
        self.state_loop_stack.deinit(self.pass.allocator);
        self.deinitDemandCacheIndexes();
        self.function_demand_cache.deinit(self.pass.allocator);
        self.local_demand_cache.deinit(self.pass.allocator);
        self.local_demand_stack.deinit(self.pass.allocator);
        self.demand_slot_edge_scratch.deinit(self.pass.allocator);
        for (self.function_demand_merge_stack.items) |*frame| {
            frame.extras.deinit(self.pass.allocator);
        }
        self.function_demand_merge_stack.deinit(self.pass.allocator);
        for (self.loop_demand_merge_stack.items) |*frame| {
            frame.extras.deinit(self.pass.allocator);
        }
        self.loop_demand_merge_stack.deinit(self.pass.allocator);
        self.function_demand_nodes.deinit(self.pass.allocator);
        self.demand_stack.deinit(self.pass.allocator);
        self.inline_stack.deinit(self.pass.allocator);
        self.loop_stack.deinit(self.pass.allocator);
        self.changes.deinit(self.pass.allocator);
        self.state_loop_state_map.deinit();
        self.subst.deinit();
    }

    fn deinitDemandCacheIndexes(self: *Cloner) void {
        var local_values = self.local_demand_cache_index.valueIterator();
        while (local_values.next()) |indices| {
            indices.deinit(self.pass.allocator);
        }
        self.local_demand_cache_index.deinit();

        var function_values = self.function_demand_cache_index.valueIterator();
        while (function_values.next()) |indices| {
            indices.deinit(self.pass.allocator);
        }
        self.function_demand_cache_index.deinit();
    }

    fn functionDemandNodesForSlots(
        self: *Cloner,
        frame_id: usize,
        fn_id: Ast.FnId,
        role: FunctionDemandRole,
        slots: []ValueDemand,
    ) Allocator.Error![]const usize {
        const node_ids = try self.pass.arena.allocator().alloc(usize, slots.len);
        for (slots, node_ids, 0..) |*slot, *node_id, index| {
            node_id.* = self.function_demand_nodes.items.len;
            try self.function_demand_nodes.append(self.pass.allocator, .{
                .frame_id = frame_id,
                .fn_id = fn_id,
                .role = role,
                .index = index,
                .slot = slot,
            });
        }
        return node_ids;
    }

    fn bindCallPatternArgs(self: *Cloner, args_span: Ast.Span(Ast.TypedLocal)) LowerError!void {
        const source_fn = self.pass.program.fns.items[@intFromEnum(self.source_fn)];
        const source_captures = try self.pass.allocator.dupe(Ast.TypedLocal, self.pass.program.typedLocalSpan(source_fn.captures));
        defer self.pass.allocator.free(source_captures);
        const source_args = try self.pass.allocator.dupe(Ast.TypedLocal, self.pass.program.typedLocalSpan(source_fn.args));
        defer self.pass.allocator.free(source_args);
        if (source_captures.len != self.pattern.captures.len) Common.invariant("call-pattern capture count differed from source function capture arity");
        if (source_args.len != self.pattern.args.len) Common.invariant("call-pattern argument count differed from source function arity");
        const args = self.pass.program.typedLocalSpan(args_span);
        const saved_loc = self.current_loc;
        defer self.current_loc = saved_loc;
        const saved_region = self.current_region;
        defer self.current_region = saved_region;
        self.current_loc = switch (source_fn.body) {
            .roc => |body| self.pass.program.exprLoc(body),
            .hosted => SourceLoc.none,
        };
        self.current_region = switch (source_fn.body) {
            .roc => |body| self.pass.program.exprRegion(body),
            .hosted => Region.zero(),
        };

        var arg_index: usize = 0;
        for (source_captures, self.pattern.captures) |source_capture, pattern_capture| {
            switch (pattern_capture) {
                .unused,
                .residual,
                => {},
                .split => |known_value| {
                    const value = try self.valueFromCallPatternArg(known_value, args, &arg_index);
                    try self.putSubst(source_capture.local, value);
                },
            }
        }
        for (source_args, self.pattern.args) |source_arg, known_value| {
            const value = try self.valueFromCallPatternArg(known_value, args, &arg_index);
            try self.putSubst(source_arg.local, value);
        }
        if (arg_index != args.len) Common.invariant("reserved worker arg count exceeded call pattern leaf count");
    }

    fn valueFromCallPatternArg(
        self: *Cloner,
        known_value: DemandedKnownValue,
        args: []const Ast.TypedLocal,
        index: *usize,
    ) LowerError!Value {
        return switch (known_value) {
            .any,
            .leaf,
            => |ty| {
                if (index.* >= args.len) Common.invariant("call pattern leaf count exceeded reserved worker arg count");
                const arg = args[index.*];
                index.* += 1;
                if (!sameType(self.pass.program, arg.ty, ty)) Common.invariant("reserved worker arg type differed from call pattern leaf type");
                return .{ .expr = try self.addExpr(.{
                    .ty = arg.ty,
                    .data = .{ .local = arg.local },
                }) };
            },
            .tag => |tag| blk: {
                const payload_tys = tagTypePayloads(self.pass.program, tag.ty, tag.name) orelse
                    Common.invariant("demanded tag referenced a tag absent from its type");
                const payloads = try self.pass.arena.allocator().alloc(Value, payload_tys.len);
                for (payload_tys, payloads) |payload_ty, *payload| {
                    payload.* = try self.uninitializedValue(payload_ty);
                }
                for (tag.payloads) |payload| {
                    if (payload.index >= payloads.len) Common.invariant("demanded tag payload index exceeded tag payload count");
                    payloads[payload.index] = try self.valueFromCallPatternArg(payload.known_value, args, index);
                }
                break :blk Value{ .tag = .{
                    .ty = tag.ty,
                    .name = tag.name,
                    .payloads = payloads,
                } };
            },
            .record => |record| blk: {
                const fields = try self.pass.arena.allocator().alloc(FieldValue, record.fields.len);
                for (record.fields, fields) |field, *out| {
                    out.* = .{
                        .name = field.name,
                        .value = try self.valueFromCallPatternArg(field.known_value, args, index),
                    };
                }
                break :blk Value{ .record = .{
                    .ty = record.ty,
                    .fields = fields,
                } };
            },
            .tuple => |tuple| blk: {
                const item_tys = tupleTypeItems(self.pass.program, tuple.ty);
                const items = try self.pass.arena.allocator().alloc(Value, item_tys.len);
                for (item_tys, items) |item_ty, *item| {
                    item.* = try self.uninitializedValue(item_ty);
                }
                for (tuple.items) |item| {
                    if (item.index >= items.len) Common.invariant("demanded tuple item index exceeded tuple item count");
                    items[item.index] = try self.valueFromCallPatternArg(item.known_value, args, index);
                }
                break :blk Value{ .tuple = .{
                    .ty = tuple.ty,
                    .items = items,
                } };
            },
            .nominal => |nominal| blk: {
                const backing = nominal.backing orelse {
                    break :blk Value{ .private_state = .{ .nominal = .{
                        .ty = nominal.ty,
                        .backing = null,
                    } } };
                };
                const stored = try self.pass.arena.allocator().create(Value);
                stored.* = try self.valueFromCallPatternArg(backing.*, args, index);
                break :blk Value{ .nominal = .{
                    .ty = nominal.ty,
                    .backing = stored,
                } };
            },
            .callable => |callable| blk: {
                const source_fn = self.pass.program.fns.items[@intFromEnum(callable.fn_id)];
                const source_captures = self.pass.program.typedLocalSpan(source_fn.captures);
                const captures = try self.pass.arena.allocator().alloc(Value, source_captures.len);
                for (source_captures, captures) |source_capture, *capture| {
                    capture.* = try self.uninitializedValue(source_capture.ty);
                }
                for (callable.captures) |capture| {
                    if (capture.index >= captures.len) Common.invariant("demanded callable capture index exceeded callable capture count");
                    captures[capture.index] = try self.valueFromCallPatternArg(capture.known_value, args, index);
                }
                break :blk Value{ .callable = .{
                    .ty = callable.ty,
                    .fn_id = callable.fn_id,
                    .captures = captures,
                } };
            },
            .finite_tags => |finite_tags| try self.finiteTagsValueFromDemandedKnownTagsReservedArgs(finite_tags, args, index),
            .finite_callables => |finite_callables| try self.finiteCallablesValueFromDemandedKnownCallablesReservedArgs(finite_callables, args, index),
            .compact_finite_tags,
            .compact_finite_callables,
            => .{ .private_state = try self.privateStateValueFromDemandedKnownValueReservedArgs(known_value, args, index) },
        };
    }

    fn finiteTagsValueFromDemandedKnownTagsReservedArgs(
        self: *Cloner,
        finite_tags: DemandedKnownTags,
        args: []const Ast.TypedLocal,
        index: *usize,
    ) LowerError!Value {
        if (index.* >= args.len) Common.invariant("finite tag value had no reserved selector arg");
        const selector_arg = args[index.*];
        index.* += 1;
        const selector_ty = try self.pass.primitiveType(.u64);
        if (!sameType(self.pass.program, selector_arg.ty, selector_ty)) Common.invariant("reserved finite tag selector arg type differed from selector type");
        const selector = try self.addExpr(.{
            .ty = selector_arg.ty,
            .data = .{ .local = selector_arg.local },
        });

        const alternatives = try self.pass.arena.allocator().alloc(TagValue, finite_tags.alternatives.len);
        for (finite_tags.alternatives, alternatives) |alternative, *out| {
            const payload_tys = tagTypePayloads(self.pass.program, alternative.ty, alternative.name) orelse
                Common.invariant("demanded finite tag referenced a tag absent from its type");
            const payloads = try self.pass.arena.allocator().alloc(Value, payload_tys.len);
            for (payload_tys, payloads) |payload_ty, *payload| {
                payload.* = try self.uninitializedValue(payload_ty);
            }
            for (alternative.payloads) |payload| {
                if (payload.index >= payloads.len) Common.invariant("demanded finite tag payload index exceeded tag payload count");
                payloads[payload.index] = try self.valueFromCallPatternArg(payload.known_value, args, index);
            }
            out.* = .{
                .ty = alternative.ty,
                .name = alternative.name,
                .payloads = payloads,
            };
        }

        return .{ .finite_tags = .{
            .ty = finite_tags.ty,
            .selector = selector,
            .alternatives = alternatives,
        } };
    }

    fn finiteCallablesValueFromDemandedKnownCallablesReservedArgs(
        self: *Cloner,
        finite_callables: DemandedKnownCallables,
        args: []const Ast.TypedLocal,
        index: *usize,
    ) LowerError!Value {
        if (index.* >= args.len) Common.invariant("finite callable value had no reserved selector arg");
        const selector_arg = args[index.*];
        index.* += 1;
        const selector_ty = try self.pass.primitiveType(.u64);
        if (!sameType(self.pass.program, selector_arg.ty, selector_ty)) Common.invariant("reserved finite callable selector arg type differed from selector type");
        const selector = try self.addExpr(.{
            .ty = selector_arg.ty,
            .data = .{ .local = selector_arg.local },
        });

        const alternatives = try self.pass.arena.allocator().alloc(CallableValue, finite_callables.alternatives.len);
        for (finite_callables.alternatives, alternatives) |alternative, *out| {
            const source_fn = self.pass.program.fns.items[@intFromEnum(alternative.fn_id)];
            const source_captures = self.pass.program.typedLocalSpan(source_fn.captures);
            const captures = try self.pass.arena.allocator().alloc(Value, source_captures.len);
            for (source_captures, captures) |source_capture, *capture| {
                capture.* = try self.uninitializedValue(source_capture.ty);
            }
            for (alternative.captures) |capture| {
                if (capture.index >= captures.len) Common.invariant("demanded finite callable capture index exceeded callable capture count");
                captures[capture.index] = try self.valueFromCallPatternArg(capture.known_value, args, index);
            }
            out.* = .{
                .ty = alternative.ty,
                .fn_id = alternative.fn_id,
                .captures = captures,
            };
        }

        return .{ .finite_callables = .{
            .ty = finite_callables.ty,
            .selector = selector,
            .alternatives = alternatives,
        } };
    }

    fn valueFromKnownValueArgs(self: *Cloner, known_value: KnownValue, args: *std.ArrayList(Ast.TypedLocal)) Allocator.Error!Value {
        switch (known_value) {
            .any => |ty| {
                const local = try self.pass.program.addLocal(self.pass.symbols.fresh(), ty);
                try args.append(self.pass.allocator, .{ .local = local, .ty = ty });
                return .{ .expr = try self.addExpr(.{
                    .ty = ty,
                    .data = .{ .local = local },
                }) };
            },
            .leaf => |ty| {
                const local = try self.pass.program.addLocal(self.pass.symbols.fresh(), ty);
                try args.append(self.pass.allocator, .{ .local = local, .ty = ty });
                return .{ .expr = try self.addExpr(.{
                    .ty = ty,
                    .data = .{ .local = local },
                }) };
            },
            .tag => |tag| {
                const payloads = try self.pass.arena.allocator().alloc(Value, tag.payloads.len);
                for (tag.payloads, 0..) |payload, index| {
                    payloads[index] = try self.valueFromKnownValueArgs(payload, args);
                }
                return .{ .tag = .{
                    .ty = tag.ty,
                    .name = tag.name,
                    .payloads = payloads,
                } };
            },
            .record => |record| {
                const fields = try self.pass.arena.allocator().alloc(FieldValue, record.fields.len);
                for (record.fields, 0..) |field, index| {
                    fields[index] = .{
                        .name = field.name,
                        .value = try self.valueFromKnownValueArgs(field.known_value, args),
                    };
                }
                return .{ .record = .{
                    .ty = record.ty,
                    .fields = fields,
                } };
            },
            .tuple => |tuple| {
                const items = try self.pass.arena.allocator().alloc(Value, tuple.items.len);
                for (tuple.items, 0..) |item, index| {
                    items[index] = try self.valueFromKnownValueArgs(item, args);
                }
                return .{ .tuple = .{
                    .ty = tuple.ty,
                    .items = items,
                } };
            },
            .nominal => |nominal| {
                const backing = try self.pass.arena.allocator().create(Value);
                backing.* = try self.valueFromKnownValueArgs(nominal.backing.*, args);
                return .{ .nominal = .{
                    .ty = nominal.ty,
                    .backing = backing,
                } };
            },
            .callable => |callable| {
                const captures = try self.pass.arena.allocator().alloc(Value, callable.captures.len);
                for (callable.captures, 0..) |capture, index| {
                    captures[index] = try self.valueFromKnownValueArgs(capture, args);
                }
                return .{ .callable = .{
                    .ty = callable.ty,
                    .fn_id = callable.fn_id,
                    .captures = captures,
                } };
            },
            .finite_tags => |finite_tags| {
                const selector_ty = try self.pass.primitiveType(.u64);
                const selector_local = try self.pass.program.addLocal(self.pass.symbols.fresh(), selector_ty);
                try args.append(self.pass.allocator, .{ .local = selector_local, .ty = selector_ty });
                const selector = try self.addExpr(.{
                    .ty = selector_ty,
                    .data = .{ .local = selector_local },
                });

                const alternatives = try self.pass.arena.allocator().alloc(TagValue, finite_tags.alternatives.len);
                for (finite_tags.alternatives, alternatives) |alternative, *out| {
                    const payloads = try self.pass.arena.allocator().alloc(Value, alternative.payloads.len);
                    for (alternative.payloads, payloads) |payload_known_value, *payload_out| {
                        payload_out.* = try self.valueFromKnownValueArgs(payload_known_value, args);
                    }
                    out.* = .{
                        .ty = alternative.ty,
                        .name = alternative.name,
                        .payloads = payloads,
                    };
                }

                return .{ .finite_tags = .{
                    .ty = finite_tags.ty,
                    .selector = selector,
                    .alternatives = alternatives,
                } };
            },
            .finite_callables => |finite_callables| {
                const selector_ty = try self.pass.primitiveType(.u64);
                const selector_local = try self.pass.program.addLocal(self.pass.symbols.fresh(), selector_ty);
                try args.append(self.pass.allocator, .{ .local = selector_local, .ty = selector_ty });
                const selector = try self.addExpr(.{
                    .ty = selector_ty,
                    .data = .{ .local = selector_local },
                });

                const alternatives = try self.pass.arena.allocator().alloc(CallableValue, finite_callables.alternatives.len);
                for (finite_callables.alternatives, alternatives) |alternative, *out| {
                    const captures = try self.pass.arena.allocator().alloc(Value, alternative.captures.len);
                    for (alternative.captures, captures) |capture_known_value, *capture_out| {
                        capture_out.* = try self.valueFromKnownValueArgs(capture_known_value, args);
                    }
                    out.* = .{
                        .ty = alternative.ty,
                        .fn_id = alternative.fn_id,
                        .captures = captures,
                    };
                }

                return .{ .finite_callables = .{
                    .ty = finite_callables.ty,
                    .selector = selector,
                    .alternatives = alternatives,
                } };
            },
        }
    }

    fn appendLoopSplitLocal(
        self: *Cloner,
        provenance: *std.ArrayList(LoopLocalProvenance),
        local: Ast.LocalId,
        source_local: Ast.LocalId,
        path: []const DemandPathStep,
    ) Allocator.Error!void {
        try provenance.append(self.pass.allocator, .{
            .local = local,
            .source_local = source_local,
            .path = try self.pass.arena.allocator().dupe(DemandPathStep, path),
        });
    }

    fn valueFromKnownValueLoopParamArgs(
        self: *Cloner,
        known_value: KnownValue,
        args: *std.ArrayList(Ast.TypedLocal),
        source_local: Ast.LocalId,
        path: *std.ArrayList(DemandPathStep),
        provenance: *std.ArrayList(LoopLocalProvenance),
    ) Allocator.Error!Value {
        switch (known_value) {
            .any => |ty| {
                const local = try self.pass.program.addLocal(self.pass.symbols.fresh(), ty);
                try args.append(self.pass.allocator, .{ .local = local, .ty = ty });
                try self.appendLoopSplitLocal(provenance, local, source_local, path.items);
                return .{ .expr = try self.addExpr(.{
                    .ty = ty,
                    .data = .{ .local = local },
                }) };
            },
            .leaf => |ty| {
                const local = try self.pass.program.addLocal(self.pass.symbols.fresh(), ty);
                try args.append(self.pass.allocator, .{ .local = local, .ty = ty });
                try self.appendLoopSplitLocal(provenance, local, source_local, path.items);
                return .{ .expr = try self.addExpr(.{
                    .ty = ty,
                    .data = .{ .local = local },
                }) };
            },
            .tag => |tag| {
                const payloads = try self.pass.arena.allocator().alloc(Value, tag.payloads.len);
                for (tag.payloads, 0..) |payload, index| {
                    try path.append(self.pass.allocator, .{ .tag_payload = .{
                        .name = tag.name,
                        .index = @intCast(index),
                    } });
                    defer _ = path.pop();
                    payloads[index] = try self.valueFromKnownValueLoopParamArgs(payload, args, source_local, path, provenance);
                }
                return .{ .tag = .{
                    .ty = tag.ty,
                    .name = tag.name,
                    .payloads = payloads,
                } };
            },
            .record => |record| {
                const fields = try self.pass.arena.allocator().alloc(FieldValue, record.fields.len);
                for (record.fields, 0..) |field, index| {
                    try path.append(self.pass.allocator, .{ .record_field = field.name });
                    defer _ = path.pop();
                    fields[index] = .{
                        .name = field.name,
                        .value = try self.valueFromKnownValueLoopParamArgs(field.known_value, args, source_local, path, provenance),
                    };
                }
                return .{ .record = .{
                    .ty = record.ty,
                    .fields = fields,
                } };
            },
            .tuple => |tuple| {
                const items = try self.pass.arena.allocator().alloc(Value, tuple.items.len);
                for (tuple.items, 0..) |item, index| {
                    try path.append(self.pass.allocator, .{ .tuple_item = @intCast(index) });
                    defer _ = path.pop();
                    items[index] = try self.valueFromKnownValueLoopParamArgs(item, args, source_local, path, provenance);
                }
                return .{ .tuple = .{
                    .ty = tuple.ty,
                    .items = items,
                } };
            },
            .nominal => |nominal| {
                try path.append(self.pass.allocator, .nominal_backing);
                defer _ = path.pop();
                const backing = try self.pass.arena.allocator().create(Value);
                backing.* = try self.valueFromKnownValueLoopParamArgs(nominal.backing.*, args, source_local, path, provenance);
                return .{ .nominal = .{
                    .ty = nominal.ty,
                    .backing = backing,
                } };
            },
            .callable => |callable| {
                const captures = try self.pass.arena.allocator().alloc(Value, callable.captures.len);
                for (callable.captures, 0..) |capture, index| {
                    try path.append(self.pass.allocator, .{ .callable_capture = @intCast(index) });
                    defer _ = path.pop();
                    captures[index] = try self.valueFromKnownValueLoopParamArgs(capture, args, source_local, path, provenance);
                }
                return .{ .callable = .{
                    .ty = callable.ty,
                    .fn_id = callable.fn_id,
                    .captures = captures,
                } };
            },
            .finite_tags => |finite_tags| {
                const selector_ty = try self.pass.primitiveType(.u64);
                const selector_local = try self.pass.program.addLocal(self.pass.symbols.fresh(), selector_ty);
                try args.append(self.pass.allocator, .{ .local = selector_local, .ty = selector_ty });
                try self.appendLoopSplitLocal(provenance, selector_local, source_local, path.items);
                const selector = try self.addExpr(.{
                    .ty = selector_ty,
                    .data = .{ .local = selector_local },
                });

                const alternatives = try self.pass.arena.allocator().alloc(TagValue, finite_tags.alternatives.len);
                for (finite_tags.alternatives, alternatives) |alternative, *out| {
                    const payloads = try self.pass.arena.allocator().alloc(Value, alternative.payloads.len);
                    for (alternative.payloads, payloads) |payload_known_value, *payload_out| {
                        payload_out.* = try self.valueFromKnownValueLoopParamArgs(payload_known_value, args, source_local, path, provenance);
                    }
                    out.* = .{
                        .ty = alternative.ty,
                        .name = alternative.name,
                        .payloads = payloads,
                    };
                }

                return .{ .finite_tags = .{
                    .ty = finite_tags.ty,
                    .selector = selector,
                    .alternatives = alternatives,
                } };
            },
            .finite_callables => |finite_callables| {
                const selector_ty = try self.pass.primitiveType(.u64);
                const selector_local = try self.pass.program.addLocal(self.pass.symbols.fresh(), selector_ty);
                try args.append(self.pass.allocator, .{ .local = selector_local, .ty = selector_ty });
                try self.appendLoopSplitLocal(provenance, selector_local, source_local, path.items);
                const selector = try self.addExpr(.{
                    .ty = selector_ty,
                    .data = .{ .local = selector_local },
                });

                const alternatives = try self.pass.arena.allocator().alloc(CallableValue, finite_callables.alternatives.len);
                for (finite_callables.alternatives, alternatives) |alternative, *out| {
                    const captures = try self.pass.arena.allocator().alloc(Value, alternative.captures.len);
                    for (alternative.captures, captures) |capture_known_value, *capture_out| {
                        capture_out.* = try self.valueFromKnownValueLoopParamArgs(capture_known_value, args, source_local, path, provenance);
                    }
                    out.* = .{
                        .ty = alternative.ty,
                        .fn_id = alternative.fn_id,
                        .captures = captures,
                    };
                }

                return .{ .finite_callables = .{
                    .ty = finite_callables.ty,
                    .selector = selector,
                    .alternatives = alternatives,
                } };
            },
        }
    }

    fn privateStateValueFromDemandedKnownValueArgs(
        self: *Cloner,
        known_value: DemandedKnownValue,
        args: *std.ArrayList(Ast.TypedLocal),
    ) Allocator.Error!PrivateStateValue {
        return switch (known_value) {
            .any,
            .leaf,
            => |ty| blk: {
                const local = try self.pass.program.addLocal(self.pass.symbols.fresh(), ty);
                try args.append(self.pass.allocator, .{ .local = local, .ty = ty });
                break :blk PrivateStateValue{ .leaf = .{
                    .ty = ty,
                    .expr = try self.addExpr(.{
                        .ty = ty,
                        .data = .{ .local = local },
                    }),
                } };
            },
            .tag => |tag| .{ .tag = .{
                .ty = tag.ty,
                .name = tag.name,
                .payloads = try self.privateStateIndexedValuesFromDemandedKnownValues(tag.payloads, args),
            } },
            .record => |record| blk: {
                const fields = try self.pass.arena.allocator().alloc(PrivateStateField, record.fields.len);
                for (record.fields, fields) |field, *out| {
                    out.* = .{
                        .name = field.name,
                        .value = try self.privateStateValueFromDemandedKnownValueArgs(field.known_value, args),
                    };
                }
                break :blk PrivateStateValue{ .record = .{
                    .ty = record.ty,
                    .fields = fields,
                } };
            },
            .tuple => |tuple| .{ .tuple = .{
                .ty = tuple.ty,
                .items = try self.privateStateIndexedValuesFromDemandedKnownValues(tuple.items, args),
            } },
            .nominal => |nominal| blk: {
                const backing = if (nominal.backing) |backing_known_value| backing: {
                    const stored = try self.pass.arena.allocator().create(PrivateStateValue);
                    stored.* = try self.privateStateValueFromDemandedKnownValueArgs(backing_known_value.*, args);
                    break :backing stored;
                } else null;
                break :blk PrivateStateValue{ .nominal = .{
                    .ty = nominal.ty,
                    .backing = backing,
                } };
            },
            .callable => |callable| .{ .callable = .{
                .ty = callable.ty,
                .fn_id = callable.fn_id,
                .captures = try self.privateStateIndexedValuesFromDemandedKnownValues(callable.captures, args),
            } },
            .compact_finite_tags => |finite_tags| blk: {
                const compact_ty = try self.pass.compactFiniteTagsType(finite_tags);
                const local = try self.pass.program.addLocal(self.pass.symbols.fresh(), compact_ty);
                try args.append(self.pass.allocator, .{ .local = local, .ty = compact_ty });
                break :blk PrivateStateValue{ .compact_finite_tags = .{
                    .source = finite_tags,
                    .compact_expr = try self.addExpr(.{
                        .ty = compact_ty,
                        .data = .{ .local = local },
                    }),
                } };
            },
            .compact_finite_callables => |finite_callables| blk: {
                const compact_ty = try self.pass.compactFiniteCallablesType(finite_callables);
                const local = try self.pass.program.addLocal(self.pass.symbols.fresh(), compact_ty);
                try args.append(self.pass.allocator, .{ .local = local, .ty = compact_ty });
                break :blk PrivateStateValue{ .compact_finite_callables = .{
                    .source = finite_callables,
                    .compact_expr = try self.addExpr(.{
                        .ty = compact_ty,
                        .data = .{ .local = local },
                    }),
                } };
            },
            .finite_tags,
            .finite_callables,
            => Common.invariant("finite demanded state reached private-state argument construction before expansion"),
        };
    }

    fn privateStateValueFromDemandedKnownValueReservedArgs(
        self: *Cloner,
        known_value: DemandedKnownValue,
        args: []const Ast.TypedLocal,
        index: *usize,
    ) Allocator.Error!PrivateStateValue {
        return switch (known_value) {
            .any,
            .leaf,
            => |ty| blk: {
                if (index.* >= args.len) Common.invariant("call pattern private leaf count exceeded reserved worker arg count");
                const arg = args[index.*];
                index.* += 1;
                if (!sameType(self.pass.program, arg.ty, ty)) Common.invariant("reserved private worker arg type differed from call pattern leaf type");
                break :blk PrivateStateValue{ .leaf = .{
                    .ty = arg.ty,
                    .expr = try self.addExpr(.{
                        .ty = arg.ty,
                        .data = .{ .local = arg.local },
                    }),
                } };
            },
            .tag => |tag| .{ .tag = .{
                .ty = tag.ty,
                .name = tag.name,
                .payloads = try self.privateStateIndexedValuesFromDemandedKnownValuesReservedArgs(tag.payloads, args, index),
            } },
            .record => |record| blk: {
                const fields = try self.pass.arena.allocator().alloc(PrivateStateField, record.fields.len);
                for (record.fields, fields) |field, *out| {
                    out.* = .{
                        .name = field.name,
                        .value = try self.privateStateValueFromDemandedKnownValueReservedArgs(field.known_value, args, index),
                    };
                }
                break :blk PrivateStateValue{ .record = .{
                    .ty = record.ty,
                    .fields = fields,
                } };
            },
            .tuple => |tuple| .{ .tuple = .{
                .ty = tuple.ty,
                .items = try self.privateStateIndexedValuesFromDemandedKnownValuesReservedArgs(tuple.items, args, index),
            } },
            .nominal => |nominal| blk: {
                const backing = if (nominal.backing) |backing_known_value| backing: {
                    const stored = try self.pass.arena.allocator().create(PrivateStateValue);
                    stored.* = try self.privateStateValueFromDemandedKnownValueReservedArgs(backing_known_value.*, args, index);
                    break :backing stored;
                } else null;
                break :blk PrivateStateValue{ .nominal = .{
                    .ty = nominal.ty,
                    .backing = backing,
                } };
            },
            .callable => |callable| .{ .callable = .{
                .ty = callable.ty,
                .fn_id = callable.fn_id,
                .captures = try self.privateStateIndexedValuesFromDemandedKnownValuesReservedArgs(callable.captures, args, index),
            } },
            .compact_finite_tags => |finite_tags| blk: {
                if (index.* >= args.len) Common.invariant("finite tag state had no reserved compact arg");
                const compact_arg = args[index.*];
                index.* += 1;
                const compact_ty = try self.pass.compactFiniteTagsType(finite_tags);
                if (!sameType(self.pass.program, compact_arg.ty, compact_ty)) Common.invariant("reserved finite tag compact arg type differed from call pattern compact type");
                break :blk PrivateStateValue{ .compact_finite_tags = .{
                    .source = finite_tags,
                    .compact_expr = try self.addExpr(.{
                        .ty = compact_arg.ty,
                        .data = .{ .local = compact_arg.local },
                    }),
                } };
            },
            .compact_finite_callables => |finite_callables| blk: {
                if (index.* >= args.len) Common.invariant("finite callable state had no reserved compact arg");
                const compact_arg = args[index.*];
                index.* += 1;
                const compact_ty = try self.pass.compactFiniteCallablesType(finite_callables);
                if (!sameType(self.pass.program, compact_arg.ty, compact_ty)) Common.invariant("reserved finite callable compact arg type differed from call pattern compact type");
                break :blk PrivateStateValue{ .compact_finite_callables = .{
                    .source = finite_callables,
                    .compact_expr = try self.addExpr(.{
                        .ty = compact_arg.ty,
                        .data = .{ .local = compact_arg.local },
                    }),
                } };
            },
            .finite_tags,
            .finite_callables,
            => Common.invariant("finite demanded state reached reserved private-state argument binding before expansion"),
        };
    }

    fn privateStateIndexedValuesFromDemandedKnownValuesReservedArgs(
        self: *Cloner,
        known_values: []const DemandedKnownIndexedValue,
        args: []const Ast.TypedLocal,
        index: *usize,
    ) Allocator.Error![]const PrivateStateIndexedValue {
        const values = try self.pass.arena.allocator().alloc(PrivateStateIndexedValue, known_values.len);
        for (known_values, values) |known_value, *out| {
            out.* = .{
                .index = known_value.index,
                .value = try self.privateStateValueFromDemandedKnownValueReservedArgs(known_value.known_value, args, index),
            };
        }
        return values;
    }

    fn privateStateIndexedValuesFromDemandedKnownValues(
        self: *Cloner,
        known_values: []const DemandedKnownIndexedValue,
        args: *std.ArrayList(Ast.TypedLocal),
    ) Allocator.Error![]const PrivateStateIndexedValue {
        const values = try self.pass.arena.allocator().alloc(PrivateStateIndexedValue, known_values.len);
        for (known_values, values) |known_value, *out| {
            out.* = .{
                .index = known_value.index,
                .value = try self.privateStateValueFromDemandedKnownValueArgs(known_value.known_value, args),
            };
        }
        return values;
    }

    fn privateStateValueFromDemandedKnownValueLoopParamArgs(
        self: *Cloner,
        known_value: DemandedKnownValue,
        args: *std.ArrayList(Ast.TypedLocal),
        source_local: Ast.LocalId,
        path: *std.ArrayList(DemandPathStep),
        provenance: *std.ArrayList(LoopLocalProvenance),
    ) Allocator.Error!PrivateStateValue {
        return switch (known_value) {
            .any,
            .leaf,
            => |ty| blk: {
                const local = try self.pass.program.addLocal(self.pass.symbols.fresh(), ty);
                try args.append(self.pass.allocator, .{ .local = local, .ty = ty });
                try self.appendLoopSplitLocal(provenance, local, source_local, path.items);
                break :blk PrivateStateValue{ .leaf = .{
                    .ty = ty,
                    .expr = try self.addExpr(.{
                        .ty = ty,
                        .data = .{ .local = local },
                    }),
                } };
            },
            .tag => |tag| blk: {
                const payloads = try self.pass.arena.allocator().alloc(PrivateStateIndexedValue, tag.payloads.len);
                for (tag.payloads, payloads) |payload, *out| {
                    try path.append(self.pass.allocator, .{ .tag_payload = .{
                        .name = tag.name,
                        .index = payload.index,
                    } });
                    defer _ = path.pop();
                    out.* = .{
                        .index = payload.index,
                        .value = try self.privateStateValueFromDemandedKnownValueLoopParamArgs(
                            payload.known_value,
                            args,
                            source_local,
                            path,
                            provenance,
                        ),
                    };
                }
                break :blk PrivateStateValue{ .tag = .{
                    .ty = tag.ty,
                    .name = tag.name,
                    .payloads = payloads,
                } };
            },
            .record => |record| blk: {
                const fields = try self.pass.arena.allocator().alloc(PrivateStateField, record.fields.len);
                for (record.fields, fields) |field, *out| {
                    try path.append(self.pass.allocator, .{ .record_field = field.name });
                    defer _ = path.pop();
                    out.* = .{
                        .name = field.name,
                        .value = try self.privateStateValueFromDemandedKnownValueLoopParamArgs(
                            field.known_value,
                            args,
                            source_local,
                            path,
                            provenance,
                        ),
                    };
                }
                break :blk PrivateStateValue{ .record = .{
                    .ty = record.ty,
                    .fields = fields,
                } };
            },
            .tuple => |tuple| blk: {
                const items = try self.pass.arena.allocator().alloc(PrivateStateIndexedValue, tuple.items.len);
                for (tuple.items, items) |item, *out| {
                    try path.append(self.pass.allocator, .{ .tuple_item = item.index });
                    defer _ = path.pop();
                    out.* = .{
                        .index = item.index,
                        .value = try self.privateStateValueFromDemandedKnownValueLoopParamArgs(
                            item.known_value,
                            args,
                            source_local,
                            path,
                            provenance,
                        ),
                    };
                }
                break :blk PrivateStateValue{ .tuple = .{
                    .ty = tuple.ty,
                    .items = items,
                } };
            },
            .nominal => |nominal| blk: {
                const backing = if (nominal.backing) |backing_known_value| backing: {
                    try path.append(self.pass.allocator, .nominal_backing);
                    defer _ = path.pop();
                    const stored = try self.pass.arena.allocator().create(PrivateStateValue);
                    stored.* = try self.privateStateValueFromDemandedKnownValueLoopParamArgs(
                        backing_known_value.*,
                        args,
                        source_local,
                        path,
                        provenance,
                    );
                    break :backing stored;
                } else null;
                break :blk PrivateStateValue{ .nominal = .{
                    .ty = nominal.ty,
                    .backing = backing,
                } };
            },
            .callable => |callable| blk: {
                const captures = try self.pass.arena.allocator().alloc(PrivateStateIndexedValue, callable.captures.len);
                for (callable.captures, captures) |capture, *out| {
                    try path.append(self.pass.allocator, .{ .callable_capture = capture.index });
                    defer _ = path.pop();
                    out.* = .{
                        .index = capture.index,
                        .value = try self.privateStateValueFromDemandedKnownValueLoopParamArgs(
                            capture.known_value,
                            args,
                            source_local,
                            path,
                            provenance,
                        ),
                    };
                }
                break :blk PrivateStateValue{ .callable = .{
                    .ty = callable.ty,
                    .fn_id = callable.fn_id,
                    .captures = captures,
                    .loop_origin = .{
                        .source_local = source_local,
                        .path = try self.pass.arena.allocator().dupe(DemandPathStep, path.items),
                    },
                } };
            },
            .compact_finite_tags => |finite_tags| blk: {
                const compact_ty = try self.pass.compactFiniteTagsType(finite_tags);
                const local = try self.pass.program.addLocal(self.pass.symbols.fresh(), compact_ty);
                try args.append(self.pass.allocator, .{ .local = local, .ty = compact_ty });
                try self.appendLoopSplitLocal(provenance, local, source_local, path.items);
                break :blk PrivateStateValue{ .compact_finite_tags = .{
                    .source = finite_tags,
                    .compact_expr = try self.addExpr(.{
                        .ty = compact_ty,
                        .data = .{ .local = local },
                    }),
                } };
            },
            .compact_finite_callables => |finite_callables| blk: {
                const compact_ty = try self.pass.compactFiniteCallablesType(finite_callables);
                const local = try self.pass.program.addLocal(self.pass.symbols.fresh(), compact_ty);
                try args.append(self.pass.allocator, .{ .local = local, .ty = compact_ty });
                try self.appendLoopSplitLocal(provenance, local, source_local, path.items);
                break :blk PrivateStateValue{ .compact_finite_callables = .{
                    .source = finite_callables,
                    .compact_expr = try self.addExpr(.{
                        .ty = compact_ty,
                        .data = .{ .local = local },
                    }),
                } };
            },
            .finite_tags,
            .finite_callables,
            => Common.invariant("finite demanded state reached private loop-param construction before expansion"),
        };
    }

    fn cloneExpr(self: *Cloner, expr_id: Ast.ExprId) LowerError!Ast.ExprId {
        const saved_loc = self.current_loc;
        defer self.current_loc = saved_loc;
        const saved_region = self.current_region;
        defer self.current_region = saved_region;
        self.current_loc = self.pass.program.exprLoc(expr_id);
        self.current_region = self.pass.program.exprRegion(expr_id);
        if (exprContainsEscapingControlTransfer(self.pass.program, expr_id)) return try self.cloneExprPlain(expr_id);
        return try self.materialize(try self.cloneExprValueWithDemand(expr_id, .materialize));
    }

    fn cloneExprValue(self: *Cloner, expr_id: Ast.ExprId) LowerError!Value {
        const saved_loc = self.current_loc;
        defer self.current_loc = saved_loc;
        const saved_region = self.current_region;
        defer self.current_region = saved_region;
        self.current_loc = self.pass.program.exprLoc(expr_id);
        self.current_region = self.pass.program.exprRegion(expr_id);

        const expr = self.pass.program.exprs.items[@intFromEnum(expr_id)];
        switch (expr.data) {
            .local => |local| {
                if (self.subst.get(local)) |value| return value;
                if (try self.solvedSingleCallable(expr_id)) |callable| return callable;
                return .{ .expr = try self.addExpr(.{ .ty = expr.ty, .data = .{ .local = local } }) };
            },
            .fn_ref => |fn_id| return try self.callableValue(expr.ty, fn_id),
            .fn_ref_captures => |fn_ref| return try self.callableValueWithCaptureExprs(
                expr.ty,
                fn_ref.target,
                self.pass.program.exprSpan(fn_ref.captures),
            ),
            .tag => |tag| {
                const payload_exprs = try self.pass.allocator.dupe(Ast.ExprId, self.pass.program.exprSpan(tag.payloads));
                defer self.pass.allocator.free(payload_exprs);
                const payloads = try self.pass.arena.allocator().alloc(Value, payload_exprs.len);
                for (payload_exprs, 0..) |payload, index| {
                    payloads[index] = try self.cloneExprValueDemandingKnownValue(payload);
                }
                return .{ .tag = .{
                    .ty = expr.ty,
                    .name = tag.name,
                    .payloads = payloads,
                } };
            },
            .record => |fields_span| {
                const source_fields = try self.pass.allocator.dupe(Ast.FieldExpr, self.pass.program.fieldExprSpan(fields_span));
                defer self.pass.allocator.free(source_fields);
                const fields = try self.pass.arena.allocator().alloc(FieldValue, source_fields.len);
                for (source_fields, 0..) |field, index| {
                    fields[index] = .{
                        .name = field.name,
                        .value = try self.cloneExprValueDemandingKnownValue(field.value),
                    };
                }
                return .{ .record = .{
                    .ty = expr.ty,
                    .fields = fields,
                } };
            },
            .tuple => |items_span| {
                const source_items = try self.pass.allocator.dupe(Ast.ExprId, self.pass.program.exprSpan(items_span));
                defer self.pass.allocator.free(source_items);
                const items = try self.pass.arena.allocator().alloc(Value, source_items.len);
                for (source_items, 0..) |item, index| {
                    items[index] = try self.cloneExprValueDemandingKnownValue(item);
                }
                return .{ .tuple = .{
                    .ty = expr.ty,
                    .items = items,
                } };
            },
            .nominal => |backing| {
                const backing_value = try self.cloneExprValueDemandingKnownValue(backing);
                return .{ .nominal = .{
                    .ty = expr.ty,
                    .backing = try self.copyValue(backing_value),
                } };
            },
            .let_ => |let_| return try self.cloneLetValue(let_),
            .field_access => |field| {
                try self.noteLoopDemandIfLocalExpr(
                    field.receiver,
                    try self.pass.demandRecordField(field.field, .materialize),
                );
                const receiver = try self.cloneExprValueDemandingKnownValue(field.receiver);
                if (try self.fieldFromKnownValue(receiver, field.field)) |value| return value;
                if (try self.solvedSingleCallable(expr_id)) |callable| return callable;
                const receiver_expr = if (self.valueCanMaterializePublic(receiver))
                    try self.materialize(receiver)
                else
                    try self.cloneExprPlain(field.receiver);
                return .{ .expr = try self.addExpr(.{ .ty = expr.ty, .data = .{ .field_access = .{
                    .receiver = receiver_expr,
                    .field = field.field,
                } } }) };
            },
            .tuple_access => |access| {
                try self.noteLoopDemandIfLocalExpr(
                    access.tuple,
                    try self.pass.demandTupleItem(access.elem_index, .materialize),
                );
                const receiver = try self.cloneExprValueDemandingKnownValue(access.tuple);
                if (try self.itemFromKnownValue(receiver, access.elem_index)) |value| return value;
                if (try self.solvedSingleCallable(expr_id)) |callable| return callable;
                const receiver_expr = if (self.valueCanMaterializePublic(receiver))
                    try self.materialize(receiver)
                else
                    try self.cloneExprPlain(access.tuple);
                return .{ .expr = try self.addExpr(.{ .ty = expr.ty, .data = .{ .tuple_access = .{
                    .tuple = receiver_expr,
                    .elem_index = access.elem_index,
                } } }) };
            },
            .match_ => |match| {
                const scrutinee = try self.cloneMatchScrutineeValue(match, .materialize);
                if (try self.simplifyKnownMatchValue(expr.ty, scrutinee, match.branches)) |value| return value;
                if (try self.cloneMatchStructuredScrutineeValue(expr.ty, scrutinee, match)) |value| return value;
                const public_scrutinee = try self.publicScrutineeForRuntimeMatch(match.scrutinee, scrutinee);
                const scrutinee_expr = try self.materialize(public_scrutinee);
                if (try self.cloneCaseOfCaseValue(expr.ty, scrutinee_expr, match.branches)) |value| return value;
                const scrutinee_known_value = try self.pass.knownValueFromValue(public_scrutinee);
                return try self.cloneMatchJoinedValue(expr.ty, scrutinee_expr, match, scrutinee_known_value, public_scrutinee);
            },
            .if_ => |if_| return try self.cloneIfValue(expr.ty, if_),
            .block => |block| return try self.cloneBlockValue(expr.ty, block),
            .call_value => |call| {
                const callee_demand = try self.callableDemandForCalleeExpr(call.callee);
                try self.noteLoopDemandIfLocalExpr(call.callee, callee_demand);
                if (self.activeStateLoopDemandChanged()) return try self.uninitializedValue(expr.ty);
                const callee = try self.cloneExprValueWithDemand(call.callee, callee_demand);
                return try self.callKnownValue(expr.ty, callee, call.args, false);
            },
            .call_proc => |call| {
                if (call.is_cold) return .{ .expr = try self.cloneExprPlain(expr_id) };
                if (!self.inline_direct_calls) return .{ .expr = try self.cloneExprPlain(expr_id) };
                const callee = Ast.callProcCallee(call);
                if (!try self.directCallMayInlineForMaterialization(callee, call.args)) {
                    return .{ .expr = try self.cloneExprPlain(expr_id) };
                }
                return try self.inlineDirectCallValue(
                    callee,
                    call.args,
                    expr_id,
                    false,
                );
            },
            else => return .{ .expr = try self.cloneExprPlain(expr_id) },
        }
    }

    fn cloneExprValueDemandingKnownValue(self: *Cloner, expr_id: Ast.ExprId) LowerError!Value {
        const expr = self.pass.program.exprs.items[@intFromEnum(expr_id)];
        const value = blk: switch (expr.data) {
            .call_value => |call| {
                const callee_demand = try self.callableDemandForCalleeExprWithResultDemand(call.callee, .materialize);
                try self.noteLoopDemandIfLocalExpr(call.callee, callee_demand);
                if (self.activeStateLoopDemandChanged()) break :blk try self.uninitializedValue(expr.ty);
                const callee = try self.cloneExprValueWithDemand(call.callee, callee_demand);
                break :blk try self.callKnownValue(expr.ty, callee, call.args, true);
            },
            .call_proc => |call| {
                if (call.is_cold) break :blk try self.cloneExprValue(expr_id);
                if (!self.inline_direct_calls) break :blk try self.cloneExprValue(expr_id);
                const callee = Ast.callProcCallee(call);
                if (!try self.directCallMayInlineForMaterialization(callee, call.args)) {
                    break :blk try self.materializeDirectCallBoundaryForDemand(expr_id, .materialize);
                }
                break :blk try self.inlineDirectCallValueWithDemand(
                    callee,
                    call.args,
                    expr_id,
                    .materialize,
                );
            },
            .block => |block| break :blk try self.cloneBlockValueDemandingKnownValue(expr.ty, block),
            .comptime_branch_taken => |taken| break :blk try self.cloneExprValueDemandingKnownValue(taken.body),
            else => break :blk try self.cloneExprValue(expr_id),
        };
        return try self.ensureDemandedKnownValue(value);
    }

    fn activeBreakResultDemand(self: *Cloner, default_demand: ValueDemand) ValueDemand {
        if (self.loop_stack.getLastOrNull()) |loop| return loop.result_demand;
        if (self.state_loop_stack.getLastOrNull()) |state_loop| return state_loop.result_demand;
        return default_demand;
    }

    fn activeStateLoopDemandChanged(self: *Cloner) bool {
        if (self.loop_stack.items.len != 0) return false;
        const state_loop = self.state_loop_stack.getLastOrNull() orelse return false;
        return state_loop.changed.*;
    }

    fn uninitializedValue(self: *Cloner, ty: Type.TypeId) LowerError!Value {
        return .{ .expr = try self.addExpr(.{
            .ty = ty,
            .data = .uninitialized,
        }) };
    }

    fn activeCompactBreakResult(self: *Cloner) ?CompactResult {
        if (self.loop_stack.items.len != 0) return null;
        const state_loop = self.state_loop_stack.getLastOrNull() orelse return null;
        return state_loop.compact_result;
    }

    fn activeCompactBreakForType(self: *Cloner, break_ty: Type.TypeId) ?ActiveCompactBreak {
        if (self.loop_stack.items.len != 0) return null;
        const state_loop = self.state_loop_stack.getLastOrNull() orelse return null;
        const result = state_loop.compact_result orelse return null;
        if (sameType(self.pass.program, break_ty, demandedKnownValueType(result.known_value))) return .{ .source = result };
        if (sameType(self.pass.program, break_ty, result.ty)) return .{ .compact = result };
        Common.invariant("break type did not match active compact state-loop result");
    }

    fn cloneBreakExpr(
        self: *Cloner,
        break_ty: Type.TypeId,
        maybe_value: ?Ast.ExprId,
        default_demand: ValueDemand,
    ) LowerError!Ast.ExprId {
        const active_compact = self.activeCompactBreakForType(break_ty);
        const output_ty = if (active_compact) |active| switch (active) {
            .source => |result| result.ty,
            .compact => |result| result.ty,
        } else break_ty;

        return try self.addExpr(.{ .ty = output_ty, .data = .{
            .break_ = if (maybe_value) |value| try self.cloneBreakPayloadExpr(active_compact, value, default_demand) else null,
        } });
    }

    fn cloneBreakPayloadExpr(
        self: *Cloner,
        active_compact: ?ActiveCompactBreak,
        value: Ast.ExprId,
        default_demand: ValueDemand,
    ) LowerError!Ast.ExprId {
        if (active_compact) |active| {
            return switch (active) {
                .source => |result| blk: {
                    const payload = try self.cloneExprValueWithDemand(value, self.activeBreakResultDemand(default_demand));
                    break :blk try self.compactResultExpr(result, payload);
                },
                .compact => try self.materialize(try self.cloneExprValueWithDemand(value, .materialize)),
            };
        }

        return try self.materialize(try self.cloneExprValueWithDemand(value, self.activeBreakResultDemand(default_demand)));
    }

    fn cloneExprValueWithDemand(self: *Cloner, expr_id: Ast.ExprId, demand: ValueDemand) LowerError!Value {
        const resolved_demand = self.resolveLoopDemandRef(demand);
        return switch (resolved_demand) {
            .none => try self.cloneExprValue(expr_id),
            .materialize => try self.cloneExprValueDemandingKnownValue(expr_id),
            .loop_param => Common.invariant("loop demand reference did not resolve before expression cloning"),
            else => blk: {
                const expr = self.pass.program.exprs.items[@intFromEnum(expr_id)];
                switch (expr.data) {
                    .local => |local| {
                        if (self.subst.get(local)) |value| break :blk try self.applyValueDemand(value, resolved_demand);
                        break :blk try self.cloneExprValueDemandingKnownValue(expr_id);
                    },
                    .call_proc => |call| {
                        if (call.is_cold) break :blk try self.cloneExprValueDemandingKnownValue(expr_id);
                        if (!self.inline_direct_calls) break :blk try self.cloneExprValueDemandingKnownValue(expr_id);
                        const callee = Ast.callProcCallee(call);
                        if (!try self.directCallMayInline(callee, call.args)) {
                            break :blk try self.materializeDirectCallBoundaryForDemand(expr_id, resolved_demand);
                        }
                        break :blk try self.inlineDirectCallValueWithDemand(
                            callee,
                            call.args,
                            expr_id,
                            resolved_demand,
                        );
                    },
                    .call_value => |call| {
                        const callee_demand = try self.callableDemandForCalleeExprWithResultDemand(call.callee, resolved_demand);
                        try self.noteLoopDemandIfLocalExpr(call.callee, callee_demand);
                        if (self.activeStateLoopDemandChanged()) break :blk try self.uninitializedValue(expr.ty);
                        const callee = try self.cloneExprValueWithDemand(call.callee, callee_demand);
                        break :blk try self.callKnownValueWithDemand(expr.ty, callee, call.args, resolved_demand);
                    },
                    .field_access => |field| break :blk try self.cloneFieldAccessValueWithDemand(expr.ty, field, resolved_demand),
                    .tuple_access => |access| break :blk try self.cloneTupleAccessValueWithDemand(expr.ty, access, resolved_demand),
                    .tag => |tag| break :blk try self.cloneTagValueWithDemand(expr.ty, tag, resolved_demand),
                    .record => |fields_span| break :blk try self.cloneRecordValueWithDemand(expr.ty, fields_span, resolved_demand),
                    .let_ => |let_| break :blk try self.cloneLetValueWithDemand(let_, resolved_demand),
                    .block => |block| break :blk try self.cloneBlockValueWithDemand(expr.ty, block, resolved_demand),
                    .if_ => |if_| break :blk try self.cloneIfValueWithDemand(expr.ty, if_, resolved_demand),
                    .match_ => |match| break :blk try self.cloneMatchValueWithDemand(expr.ty, match, resolved_demand),
                    .loop_ => |loop| break :blk try self.cloneLoopValueWithDemand(expr.ty, loop, resolved_demand),
                    .break_ => |maybe_value| break :blk .{ .expr = try self.cloneBreakExpr(expr.ty, maybe_value, resolved_demand) },
                    .return_ => |value| break :blk .{ .expr = try self.addExpr(.{ .ty = expr.ty, .data = .{
                        .return_ = try self.materialize(try self.cloneExprValueWithDemand(value, resolved_demand)),
                    } }) },
                    .comptime_branch_taken => |taken| break :blk try self.cloneExprValueWithDemand(taken.body, resolved_demand),
                    else => break :blk try self.cloneExprValueDemandingKnownValue(expr_id),
                }
            },
        };
    }

    fn callableDemandForCalleeExpr(self: *Cloner, expr_id: Ast.ExprId) LowerError!ValueDemand {
        if (try self.exprSubstitutedValueNoInline(expr_id)) |value| {
            if (try self.callableDemandForValue(value)) |demand| return demand;
        }

        const known_value = (try self.exprKnownValueNoInline(expr_id)) orelse
            return .{ .callable = .{ .captures = &.{} } };
        return try self.callableDemandForKnownValue(known_value);
    }

    fn callableDemandForCalleeExprWithResultDemand(
        self: *Cloner,
        expr_id: Ast.ExprId,
        result_demand: ValueDemand,
    ) LowerError!ValueDemand {
        if (try self.exprSubstitutedValueNoInline(expr_id)) |value| {
            if (try self.callableDemandForValueWithResultDemand(value, result_demand)) |demand| return demand;
        }

        const known_value = (try self.exprKnownValueNoInline(expr_id)) orelse
            return try self.callableDemandWithResult(&.{}, result_demand);
        return try self.callableDemandForKnownValueWithResultDemand(known_value, result_demand);
    }

    fn callableDemandForValue(self: *Cloner, value: Value) LowerError!?ValueDemand {
        return switch (value) {
            .callable => |callable| try self.callableDemandForFn(callable.fn_id, callable.captures.len),
            .finite_callables => |finite_callables| blk: {
                var demand: ValueDemand = .{ .callable = .{ .captures = &.{} } };
                for (finite_callables.alternatives) |alternative| {
                    demand = try self.mergeValueDemand(
                        demand,
                        try self.callableDemandForFn(alternative.fn_id, alternative.captures.len),
                    );
                }
                break :blk demand;
            },
            .private_state => |private_state| try self.callableDemandForPrivateStateValue(private_state),
            else => null,
        };
    }

    fn callableDemandForValueWithResultDemand(
        self: *Cloner,
        value: Value,
        result_demand: ValueDemand,
    ) LowerError!?ValueDemand {
        return switch (value) {
            .callable => |callable| try self.callableDemandForCallableValueWithResultDemand(callable, result_demand),
            .finite_callables => |finite_callables| blk: {
                var demand: ValueDemand = .{ .callable = .{ .captures = &.{} } };
                for (finite_callables.alternatives) |alternative| {
                    demand = try self.mergeValueDemand(
                        demand,
                        try self.callableDemandForCallableValueWithResultDemand(alternative, result_demand),
                    );
                }
                break :blk demand;
            },
            .private_state => |private_state| try self.callableDemandForPrivateStateValueWithResultDemand(private_state, result_demand),
            else => null,
        };
    }

    fn callableDemandForPrivateStateValue(self: *Cloner, value: PrivateStateValue) LowerError!?ValueDemand {
        return switch (value) {
            .callable => |callable| blk: {
                const source_fn = self.pass.program.fns.items[@intFromEnum(callable.fn_id)];
                break :blk try self.callableDemandForFn(callable.fn_id, self.pass.program.typedLocalSpan(source_fn.captures).len);
            },
            .compact_finite_callables => |finite_callables| try self.callableDemandForDemandedKnownCallables(finite_callables.source),
            .nominal => |nominal| if (nominal.backing) |backing| try self.callableDemandForPrivateStateValue(backing.*) else null,
            else => null,
        };
    }

    fn callableDemandForPrivateStateValueWithResultDemand(
        self: *Cloner,
        value: PrivateStateValue,
        result_demand: ValueDemand,
    ) LowerError!?ValueDemand {
        return switch (value) {
            .callable => |callable| try self.callableDemandForPrivateStateCallableWithResultDemand(callable, result_demand),
            .compact_finite_callables => |finite_callables| try self.callableDemandForDemandedKnownCallablesWithResultDemand(finite_callables.source, result_demand),
            .nominal => |nominal| if (nominal.backing) |backing| try self.callableDemandForPrivateStateValueWithResultDemand(backing.*, result_demand) else null,
            else => null,
        };
    }

    fn callableDemandWithResult(
        self: *Cloner,
        captures: []const ValueDemand,
        result_demand: ValueDemand,
    ) Allocator.Error!ValueDemand {
        const result = if (result_demand == .none) null else try self.pass.storedDemand(result_demand);
        return .{ .callable = .{ .captures = captures, .result = result } };
    }

    fn callableCaptureDemandForPreservedValue(callable_demand: CallableDemand, index: usize) ValueDemand {
        if (index < callable_demand.captures.len and callable_demand.captures[index] != .none) {
            return callable_demand.captures[index];
        }
        return if (callable_demand.result == null) .materialize else .none;
    }

    fn callableDemandForCallableValueWithResultDemand(
        self: *Cloner,
        callable: CallableValue,
        result_demand: ValueDemand,
    ) LowerError!ValueDemand {
        const source_fn = self.pass.program.fns.items[@intFromEnum(callable.fn_id)];
        const source_captures = self.pass.program.typedLocalSpan(source_fn.captures);
        if (source_captures.len != callable.captures.len) {
            Common.invariant("callable value capture count differed from lifted function capture count while computing callable demand");
        }
        if (source_captures.len == 0) return try self.callableDemandWithResult(&.{}, result_demand);

        if (try self.activeCallableDemand(callable.fn_id, result_demand)) |active_demand| return active_demand;
        if (self.demandStackContains(callable.fn_id)) {
            return try self.callableDemandForFnWithResultDemand(callable.fn_id, source_captures.len, result_demand);
        }

        const body = self.demandBody(callable.fn_id) orelse
            return try self.callableDemandForFnWithResultDemand(callable.fn_id, source_captures.len, result_demand);

        const captures = try self.pass.arena.allocator().alloc(ValueDemand, source_captures.len);
        @memset(captures, .none);
        const demand_frame_id = self.next_demand_frame_id;
        self.next_demand_frame_id += 1;
        const capture_nodes = try self.functionDemandNodesForSlots(demand_frame_id, callable.fn_id, .capture, captures);
        const active_index = self.demand_stack.items.len;
        try self.demand_stack.append(self.pass.allocator, .{
            .id = demand_frame_id,
            .fn_id = callable.fn_id,
            .result = result_demand,
            .captures = captures,
            .capture_nodes = capture_nodes,
        });
        defer _ = self.demand_stack.pop();

        while (true) {
            self.demand_stack.items[active_index].changed = false;
            const change_start = self.changes.items.len;
            defer self.restore(change_start);

            for (source_captures, callable.captures) |source_capture, capture| {
                try self.putSubst(source_capture.local, capture);
            }

            var changed = false;
            for (source_captures, captures) |source_capture, *capture_demand| {
                const observed = try self.localDemandInExpr(source_capture.local, body, result_demand);
                const merged = try self.mergeValueDemand(capture_demand.*, observed);
                if (!try self.valueDemandEqlInActiveContext(capture_demand.*, merged)) {
                    capture_demand.* = merged;
                    changed = true;
                    self.demand_cache_epoch += 1;
                }
            }

            if (!changed and !self.demand_stack.items[active_index].changed) break;
        }

        for (captures) |*capture_demand| {
            capture_demand.* = try self.closeFunctionDemandFrameRefs(capture_demand.*, demand_frame_id);
        }

        var has_capture_demand = false;
        for (captures) |capture_demand| {
            if (capture_demand != .none) {
                has_capture_demand = true;
                break;
            }
        }
        if (!has_capture_demand) return try self.callableDemandWithResult(&.{}, result_demand);
        return try self.callableDemandWithResult(captures, result_demand);
    }

    fn callableDemandForPrivateStateCallableWithResultDemand(
        self: *Cloner,
        callable: PrivateStateCallable,
        result_demand: ValueDemand,
    ) LowerError!ValueDemand {
        const source_fn = self.pass.program.fns.items[@intFromEnum(callable.fn_id)];
        const source_captures = self.pass.program.typedLocalSpan(source_fn.captures);
        if (source_captures.len == 0) return try self.callableDemandWithResult(&.{}, result_demand);

        if (try self.activeCallableDemand(callable.fn_id, result_demand)) |active_demand| return active_demand;
        if (self.demandStackContains(callable.fn_id)) {
            return try self.callableDemandForFnWithResultDemand(callable.fn_id, source_captures.len, result_demand);
        }

        const body = self.demandBody(callable.fn_id) orelse
            return try self.callableDemandForFnWithResultDemand(callable.fn_id, source_captures.len, result_demand);

        const captures = try self.pass.arena.allocator().alloc(ValueDemand, source_captures.len);
        @memset(captures, .none);
        const demand_frame_id = self.next_demand_frame_id;
        self.next_demand_frame_id += 1;
        const capture_nodes = try self.functionDemandNodesForSlots(demand_frame_id, callable.fn_id, .capture, captures);
        const active_index = self.demand_stack.items.len;
        try self.demand_stack.append(self.pass.allocator, .{
            .id = demand_frame_id,
            .fn_id = callable.fn_id,
            .result = result_demand,
            .captures = captures,
            .capture_nodes = capture_nodes,
        });
        defer _ = self.demand_stack.pop();

        while (true) {
            self.demand_stack.items[active_index].changed = false;
            const change_start = self.changes.items.len;
            defer self.restore(change_start);

            for (callable.captures) |capture| {
                if (capture.index >= source_captures.len) Common.invariant("private callable capture index exceeded lifted function capture count");
                try self.putSubst(source_captures[capture.index].local, .{ .private_state = capture.value });
            }

            var changed = false;
            for (source_captures, captures) |source_capture, *capture_demand| {
                const observed = try self.localDemandInExpr(source_capture.local, body, result_demand);
                const merged = try self.mergeValueDemand(capture_demand.*, observed);
                if (!try self.valueDemandEqlInActiveContext(capture_demand.*, merged)) {
                    capture_demand.* = merged;
                    changed = true;
                    self.demand_cache_epoch += 1;
                }
            }

            if (!changed and !self.demand_stack.items[active_index].changed) break;
        }

        for (captures) |*capture_demand| {
            capture_demand.* = try self.closeFunctionDemandFrameRefs(capture_demand.*, demand_frame_id);
        }

        var has_capture_demand = false;
        for (captures) |capture_demand| {
            if (capture_demand != .none) {
                has_capture_demand = true;
                break;
            }
        }
        if (!has_capture_demand) return try self.callableDemandWithResult(&.{}, result_demand);
        return try self.callableDemandWithResult(captures, result_demand);
    }

    fn callableDemandForKnownValue(self: *Cloner, known_value: KnownValue) LowerError!ValueDemand {
        return switch (known_value) {
            .callable => |callable| try self.callableDemandForFn(callable.fn_id, callable.captures.len),
            .finite_callables => |finite_callables| blk: {
                var demand: ValueDemand = .{ .callable = .{ .captures = &.{} } };
                for (finite_callables.alternatives) |alternative| {
                    demand = try self.mergeValueDemand(
                        demand,
                        try self.callableDemandForFn(alternative.fn_id, alternative.captures.len),
                    );
                }
                break :blk demand;
            },
            else => .materialize,
        };
    }

    fn callableDemandForKnownValueWithResultDemand(
        self: *Cloner,
        known_value: KnownValue,
        result_demand: ValueDemand,
    ) LowerError!ValueDemand {
        return switch (known_value) {
            .callable => |callable| try self.callableDemandForFnWithResultDemand(
                callable.fn_id,
                callable.captures.len,
                result_demand,
            ),
            .finite_callables => |finite_callables| blk: {
                var demand: ValueDemand = .{ .callable = .{ .captures = &.{} } };
                for (finite_callables.alternatives) |alternative| {
                    demand = try self.mergeValueDemand(
                        demand,
                        try self.callableDemandForFnWithResultDemand(
                            alternative.fn_id,
                            alternative.captures.len,
                            result_demand,
                        ),
                    );
                }
                break :blk demand;
            },
            else => try self.callableDemandWithResult(&.{}, result_demand),
        };
    }

    fn callableDemandForDemandedKnownCallables(
        self: *Cloner,
        finite_callables: DemandedKnownCallables,
    ) LowerError!ValueDemand {
        var demand: ValueDemand = .{ .callable = .{ .captures = &.{} } };
        for (finite_callables.alternatives) |alternative| {
            const source_fn = self.pass.program.fns.items[@intFromEnum(alternative.fn_id)];
            const source_captures = self.pass.program.typedLocalSpan(source_fn.captures);
            demand = try self.mergeValueDemand(
                demand,
                try self.callableDemandForFn(alternative.fn_id, source_captures.len),
            );
        }
        return demand;
    }

    fn callableDemandForDemandedKnownCallablesWithResultDemand(
        self: *Cloner,
        finite_callables: DemandedKnownCallables,
        result_demand: ValueDemand,
    ) LowerError!ValueDemand {
        var demand: ValueDemand = .{ .callable = .{ .captures = &.{} } };
        for (finite_callables.alternatives) |alternative| {
            const source_fn = self.pass.program.fns.items[@intFromEnum(alternative.fn_id)];
            const source_captures = self.pass.program.typedLocalSpan(source_fn.captures);
            demand = try self.mergeValueDemand(
                demand,
                try self.callableDemandForFnWithResultDemand(
                    alternative.fn_id,
                    source_captures.len,
                    result_demand,
                ),
            );
        }
        return demand;
    }

    fn callableDemandForFnWithResultDemand(
        self: *Cloner,
        fn_id: Ast.FnId,
        capture_count: usize,
        result_demand: ValueDemand,
    ) LowerError!ValueDemand {
        const source_fn = self.pass.program.fns.items[@intFromEnum(fn_id)];
        const source_captures = self.pass.program.typedLocalSpan(source_fn.captures);
        const captures = try self.pass.arena.allocator().alloc(ValueDemand, capture_count);
        var has_capture_demand = false;
        for (captures, 0..) |*out, index| {
            if (index < source_captures.len) {
                out.* = try self.functionLocalDemand(fn_id, source_captures[index].local, result_demand);
            } else {
                out.* = .none;
            }
            if (out.* != .none) has_capture_demand = true;
        }
        if (!has_capture_demand) return try self.callableDemandWithResult(&.{}, result_demand);
        return try self.callableDemandWithResult(captures, result_demand);
    }

    fn functionLocalDemand(
        self: *Cloner,
        fn_id: Ast.FnId,
        local: Ast.LocalId,
        result_demand: ValueDemand,
    ) LowerError!ValueDemand {
        const effective_result_demand = self.decompositionDemand(result_demand);
        var active_stack_index = self.demand_stack.items.len;
        while (active_stack_index > 0) {
            active_stack_index -= 1;
            const active = &self.demand_stack.items[active_stack_index];
            if (active.fn_id != fn_id) continue;
            if (active.result != null) {
                if (try self.mergeActiveFunctionResultDemand(active_stack_index, result_demand)) |_| {
                    const known_active_demand = self.activeFunctionLocalDemand(fn_id, local, active.args, active.captures) orelse .none;
                    const active_demand = if (self.activeFunctionLocalDemandRef(fn_id, local, active.args, active.arg_nodes, active.captures, active.capture_nodes)) |demand_ref|
                        ValueDemand{ .fn_param = demand_ref }
                    else
                        known_active_demand;
                    return active_demand;
                }
                continue;
            }
            if (active.captures) |captures| {
                if (active.result != null) {
                    if (try self.mergeActiveFunctionResultDemand(active_stack_index, result_demand)) |_| {
                        const active_demand = self.activeCaptureDemand(fn_id, local, captures) orelse .none;
                        return active_demand;
                    }
                }
            }
        }

        if (effective_result_demand == .none) return .none;

        const demand_resolves_before = self.active_demand_resolves;
        const function_cache_key: FunctionDemandCacheId = .{
            .fn_id = @intFromEnum(fn_id),
            .local = @intFromEnum(local),
        };
        if (self.function_demand_cache_index.get(function_cache_key)) |indices| {
            var cache_index = indices.items.len;
            while (cache_index > 0) {
                cache_index -= 1;
                const entry = self.function_demand_cache.items[indices.items[cache_index]];
                if (entry.depends_on_active_demands and entry.demand_epoch != self.demand_cache_epoch) continue;
                if (entry.subst_scope_id != self.subst_scope_id) continue;
                if (!try self.valueDemandRefsAreActive(entry.result_demand)) continue;
                if (!try self.valueDemandRefsAreActive(entry.demand)) continue;
                if (!try self.valueDemandEqlInActiveContext(entry.result_demand, effective_result_demand)) continue;
                return entry.demand;
            }
        }

        const body = self.demandBody(fn_id) orelse return .materialize;
        const source_fn = self.pass.program.fns.items[@intFromEnum(fn_id)];
        const source_args = self.pass.program.typedLocalSpan(source_fn.args);
        const source_captures = self.pass.program.typedLocalSpan(source_fn.captures);

        const arg_demands = try self.pass.arena.allocator().alloc(ValueDemand, source_args.len);
        @memset(arg_demands, .none);
        const capture_demands = try self.pass.arena.allocator().alloc(ValueDemand, source_captures.len);
        @memset(capture_demands, .none);

        const active_index = self.demand_stack.items.len;
        const demand_frame_id = self.next_demand_frame_id;
        self.next_demand_frame_id += 1;
        const arg_nodes = try self.functionDemandNodesForSlots(demand_frame_id, fn_id, .arg, arg_demands);
        const capture_nodes = try self.functionDemandNodesForSlots(demand_frame_id, fn_id, .capture, capture_demands);
        try self.demand_stack.append(self.pass.allocator, .{
            .id = demand_frame_id,
            .fn_id = fn_id,
            .result = effective_result_demand,
            .args = arg_demands,
            .arg_nodes = arg_nodes,
            .captures = capture_demands,
            .capture_nodes = capture_nodes,
        });
        defer _ = self.demand_stack.pop();

        var function_local_demand_iterations: usize = 0;
        while (true) {
            function_local_demand_iterations += 1;
            if (function_local_demand_iterations > 1000) Common.invariant("function local demand loop did not converge");
            self.demand_stack.items[active_index].changed = false;
            var changed = false;
            const active_result = self.demand_stack.items[active_index].result orelse
                Common.invariant("function demand frame lost result demand");
            for (source_args, arg_demands) |source_arg, *arg_demand| {
                const observed = try self.localDemandInExpr(source_arg.local, body, active_result);
                const merged = try self.mergeValueDemand(arg_demand.*, observed);
                if (!try self.valueDemandEqlInActiveContext(arg_demand.*, merged)) {
                    arg_demand.* = merged;
                    changed = true;
                    self.demand_cache_epoch += 1;
                }
            }
            for (source_captures, capture_demands) |source_capture, *capture_demand| {
                const observed = try self.localDemandInExpr(source_capture.local, body, active_result);
                const merged = try self.mergeValueDemand(capture_demand.*, observed);
                if (!try self.valueDemandEqlInActiveContext(capture_demand.*, merged)) {
                    capture_demand.* = merged;
                    changed = true;
                    self.demand_cache_epoch += 1;
                }
            }
            if (!changed and !self.demand_stack.items[active_index].changed) break;
        }

        const observed = try self.closeFunctionDemandFrameRefs(
            self.activeFunctionLocalDemand(fn_id, local, arg_demands, capture_demands) orelse .none,
            demand_frame_id,
        );
        const function_cache_entry_index = self.function_demand_cache.items.len;
        try self.function_demand_cache.append(self.pass.allocator, .{
            .demand_epoch = self.demand_cache_epoch,
            .subst_scope_id = self.subst_scope_id,
            .depends_on_active_demands = valueDemandContainsActiveRef(effective_result_demand) or
                self.active_demand_resolves != demand_resolves_before,
            .fn_id = fn_id,
            .local = local,
            .result_demand = effective_result_demand,
            .demand = observed,
        });
        const function_index_entry = try self.function_demand_cache_index.getOrPut(function_cache_key);
        if (!function_index_entry.found_existing) function_index_entry.value_ptr.* = .empty;
        try function_index_entry.value_ptr.append(self.pass.allocator, function_cache_entry_index);
        return observed;
    }

    fn activeFunctionLocalDemand(
        self: *Cloner,
        fn_id: Ast.FnId,
        local: Ast.LocalId,
        args: ?[]const ValueDemand,
        captures: ?[]const ValueDemand,
    ) ?ValueDemand {
        const source_fn = self.pass.program.fns.items[@intFromEnum(fn_id)];
        if (args) |arg_demands| {
            for (self.pass.program.typedLocalSpan(source_fn.args), 0..) |arg, index| {
                if (arg.local != local) continue;
                return if (index < arg_demands.len) arg_demands[index] else .none;
            }
        }
        if (captures) |capture_demands| {
            for (self.pass.program.typedLocalSpan(source_fn.captures), 0..) |capture, index| {
                if (capture.local != local) continue;
                return if (index < capture_demands.len) capture_demands[index] else .none;
            }
        }
        return null;
    }

    fn closeFunctionDemandFrameRefs(
        self: *Cloner,
        demand: ValueDemand,
        frame_id: usize,
    ) Allocator.Error!ValueDemand {
        var seen = std.ArrayList(usize).empty;
        defer seen.deinit(self.pass.allocator);
        return try self.closeFunctionDemandFrameRefsSeen(demand, frame_id, &seen);
    }

    fn closeFunctionDemandFrameRefsSeen(
        self: *Cloner,
        demand: ValueDemand,
        frame_id: usize,
        seen: *std.ArrayList(usize),
    ) Allocator.Error!ValueDemand {
        return switch (demand) {
            .none,
            .materialize,
            .loop_param,
            => demand,
            .fn_param => |demand_ref| blk: {
                const root_ref = self.canonicalFunctionDemandSlotId(demand_ref);
                if (root_ref.node >= self.function_demand_nodes.items.len) {
                    Common.invariant("function demand reference node exceeded demand graph");
                }
                const node = self.function_demand_nodes.items[root_ref.node];
                if (node.frame_id != frame_id) {
                    if (!self.demandFrameIsActive(node.frame_id)) {
                        Common.invariant("function demand reference escaped inactive frame");
                    }
                    break :blk ValueDemand{ .fn_param = root_ref };
                }

                for (seen.items) |seen_node| {
                    if (seen_node == root_ref.node) break :blk .none;
                }

                try seen.append(self.pass.allocator, root_ref.node);
                defer _ = seen.pop();

                const slot = self.activeFunctionDemandSlot(root_ref);
                const concrete = if (slot.* == .fn_param and functionDemandSlotIdEql(slot.fn_param, root_ref))
                    ValueDemand.none
                else
                    slot.*;
                break :blk try self.closeFunctionDemandFrameRefsSeen(concrete, frame_id, seen);
            },
            .record => |fields| blk: {
                const closed_fields = try self.pass.arena.allocator().alloc(FieldDemand, fields.len);
                for (fields, closed_fields) |field, *closed| {
                    closed.* = .{
                        .name = field.name,
                        .demand = try self.pass.storedDemand(try self.closeFunctionDemandFrameRefsSeen(field.demand.*, frame_id, seen)),
                    };
                }
                break :blk ValueDemand{ .record = closed_fields };
            },
            .tuple => |items| blk: {
                const closed_items = try self.pass.arena.allocator().alloc(ItemDemand, items.len);
                for (items, closed_items) |item, *closed| {
                    closed.* = .{
                        .index = item.index,
                        .demand = try self.pass.storedDemand(try self.closeFunctionDemandFrameRefsSeen(item.demand.*, frame_id, seen)),
                    };
                }
                break :blk ValueDemand{ .tuple = closed_items };
            },
            .tag => |tag| blk: {
                const alternatives = try self.pass.arena.allocator().alloc(TagAlternativeDemand, tag.alternatives.len);
                for (tag.alternatives, alternatives) |alternative, *closed_alternative| {
                    const payloads = try self.pass.arena.allocator().alloc(ItemDemand, alternative.payloads.len);
                    for (alternative.payloads, payloads) |payload, *closed_payload| {
                        closed_payload.* = .{
                            .index = payload.index,
                            .demand = try self.pass.storedDemand(try self.closeFunctionDemandFrameRefsSeen(payload.demand.*, frame_id, seen)),
                        };
                    }
                    closed_alternative.* = .{
                        .name = alternative.name,
                        .payloads = payloads,
                    };
                }
                break :blk ValueDemand{ .tag = .{ .alternatives = alternatives } };
            },
            .nominal => |backing| blk: {
                const closed_backing = try self.closeFunctionDemandFrameRefsSeen(backing.*, frame_id, seen);
                break :blk ValueDemand{ .nominal = try self.pass.storedDemand(closed_backing) };
            },
            .callable => |callable| blk: {
                const captures = try self.pass.arena.allocator().alloc(ValueDemand, callable.captures.len);
                for (callable.captures, captures) |capture, *closed_capture| {
                    closed_capture.* = try self.closeFunctionDemandFrameRefsSeen(capture, frame_id, seen);
                }
                const result = if (callable.result) |result_demand|
                    try self.pass.storedDemand(try self.closeFunctionDemandFrameRefsSeen(result_demand.*, frame_id, seen))
                else
                    null;
                break :blk ValueDemand{ .callable = .{
                    .captures = captures,
                    .result = result,
                } };
            },
        };
    }

    fn mergeActiveFunctionResultDemand(
        self: *Cloner,
        frame_index: usize,
        requested: ValueDemand,
    ) LowerError!?ValueDemand {
        if (requested == .none) return null;
        const frame = &self.demand_stack.items[frame_index];
        const active_result = frame.result orelse return null;

        switch (requested) {
            .loop_param,
            .fn_param,
            => {
                _ = try self.mergeValueDemand(requested, active_result);
                const resolved = self.decompositionDemand(requested);
                return if (resolved == .none) active_result else resolved;
            },
            else => {
                const merged = try self.mergeValueDemand(active_result, requested);
                if (!try self.valueDemandEqlInActiveContext(active_result, merged)) {
                    frame.result = merged;
                    frame.changed = true;
                    self.demand_cache_epoch += 1;
                }
                return frame.result.?;
            },
        }
    }

    fn activeFunctionLocalDemandRef(
        self: *Cloner,
        fn_id: Ast.FnId,
        local: Ast.LocalId,
        args: ?[]const ValueDemand,
        arg_nodes: ?[]const usize,
        captures: ?[]const ValueDemand,
        capture_nodes: ?[]const usize,
    ) ?FunctionDemandSlotId {
        const source_fn = self.pass.program.fns.items[@intFromEnum(fn_id)];
        if (args) |arg_demands| {
            const nodes = arg_nodes orelse Common.invariant("active function args had no demand nodes");
            for (self.pass.program.typedLocalSpan(source_fn.args), 0..) |arg, index| {
                if (arg.local != local) continue;
                if (index >= arg_demands.len) return null;
                if (index >= nodes.len) Common.invariant("active function arg demand nodes differed from arg demand count");
                return .{ .node = nodes[index] };
            }
        }
        if (captures) |capture_demands| {
            const nodes = capture_nodes orelse Common.invariant("active function captures had no demand nodes");
            for (self.pass.program.typedLocalSpan(source_fn.captures), 0..) |capture, index| {
                if (capture.local != local) continue;
                if (index >= capture_demands.len) return null;
                if (index >= nodes.len) Common.invariant("active function capture demand nodes differed from capture demand count");
                return .{ .node = nodes[index] };
            }
        }
        return null;
    }

    fn activeCallableDemand(
        self: *Cloner,
        fn_id: Ast.FnId,
        result_demand: ValueDemand,
    ) LowerError!?ValueDemand {
        var active_stack_index = self.demand_stack.items.len;
        while (active_stack_index > 0) {
            active_stack_index -= 1;
            const active = &self.demand_stack.items[active_stack_index];
            if (active.fn_id != fn_id) continue;
            const captures = active.captures orelse continue;
            _ = (try self.mergeActiveFunctionResultDemand(active_stack_index, result_demand)) orelse continue;
            const capture_nodes = active.capture_nodes orelse Common.invariant("active callable demand frame had captures without demand nodes");
            if (capture_nodes.len != captures.len) Common.invariant("active callable demand node count differed from capture demand count");
            const capture_refs = try self.pass.arena.allocator().alloc(ValueDemand, captures.len);
            for (capture_refs, capture_nodes) |*capture_ref, node| {
                capture_ref.* = .{ .fn_param = .{ .node = node } };
            }
            return try self.callableDemandWithResult(capture_refs, result_demand);
        }
        return null;
    }

    fn activeCaptureDemand(
        self: *Cloner,
        fn_id: Ast.FnId,
        local: Ast.LocalId,
        captures: []const ValueDemand,
    ) ?ValueDemand {
        const source_fn = self.pass.program.fns.items[@intFromEnum(fn_id)];
        for (self.pass.program.typedLocalSpan(source_fn.captures), 0..) |capture, index| {
            if (capture.local != local) continue;
            return if (index < captures.len) captures[index] else .none;
        }
        return null;
    }

    fn plannedLocalDemand(self: *Cloner, fn_id: Ast.FnId, local: Ast.LocalId) ValueDemand {
        const raw = @intFromEnum(fn_id);
        if (raw >= self.pass.plans.len) return .materialize;

        const plan = self.pass.plans[raw];
        const fn_ = self.pass.program.fns.items[raw];

        for (self.pass.program.typedLocalSpan(fn_.args), 0..) |arg, index| {
            if (arg.local != local) continue;
            if (index < plan.used_args.len and plan.used_args[index]) return plan.arg_demands[index];
            return .none;
        }

        for (self.pass.program.typedLocalSpan(fn_.captures), 0..) |capture, index| {
            if (capture.local != local) continue;
            if (index < plan.used_captures.len and plan.used_captures[index]) return plan.capture_demands[index];
            return .none;
        }

        return .none;
    }

    fn demandBody(self: *Cloner, fn_id: Ast.FnId) ?Ast.ExprId {
        const source_fn = self.pass.program.fns.items[@intFromEnum(fn_id)];
        const body = self.pass.originalBody(fn_id) orelse switch (source_fn.body) {
            .roc => |body| body,
            .hosted => return null,
        };
        if (exprContainsReturn(self.pass.program, body)) return null;
        return body;
    }

    fn callableDemandForFn(self: *Cloner, fn_id: Ast.FnId, capture_count: usize) Allocator.Error!ValueDemand {
        const raw = @intFromEnum(fn_id);
        if (raw >= self.pass.plans.len) return .{ .callable = .{ .captures = &.{} } };

        const plan = self.pass.plans[raw];
        var has_capture_demand = false;
        const captures = try self.pass.arena.allocator().alloc(ValueDemand, capture_count);
        for (captures, 0..) |*out, index| {
            if (index < plan.used_captures.len and plan.used_captures[index]) {
                out.* = plan.capture_demands[index];
                has_capture_demand = true;
            } else {
                out.* = .none;
            }
        }

        if (!has_capture_demand) return .{ .callable = .{ .captures = &.{} } };
        return .{ .callable = .{ .captures = captures } };
    }

    fn applyValueDemand(self: *Cloner, value: Value, demand: ValueDemand) LowerError!Value {
        const resolved_demand = self.resolveLoopDemandRef(demand);
        return switch (resolved_demand) {
            .none => value,
            .materialize => try self.ensureDemandedKnownValue(value),
            .loop_param => Common.invariant("loop demand reference did not resolve before value demand application"),
            .fn_param => Common.invariant("function demand reference did not resolve before value demand application"),
            .record,
            .tuple,
            .tag,
            .nominal,
            .callable,
            => blk: {
                switch (value) {
                    .if_ => |if_value| {
                        const branches = try self.pass.arena.allocator().alloc(IfValueBranch, if_value.branches.len);
                        for (if_value.branches, branches) |branch, *out| {
                            out.* = .{
                                .cond = branch.cond,
                                .body = if (branch.source_body) |source|
                                    try self.cloneExprValueSourceWithDemand(source, demand)
                                else
                                    try self.applyValueDemand(branch.body, demand),
                                .source_body = branch.source_body,
                            };
                        }
                        const final_else = try self.pass.arena.allocator().create(Value);
                        final_else.* = if (if_value.final_else_source) |source|
                            try self.cloneExprValueSourceWithDemand(source, demand)
                        else
                            try self.applyValueDemand(if_value.final_else.*, demand);
                        break :blk Value{ .if_ = .{
                            .ty = if_value.ty,
                            .branches = branches,
                            .final_else = final_else,
                            .final_else_source = if_value.final_else_source,
                        } };
                    },
                    .match_ => |match_value| {
                        const branches = try self.pass.arena.allocator().alloc(MatchValueBranch, match_value.branches.len);
                        for (match_value.branches, branches) |branch, *out| {
                            out.* = .{
                                .pat = branch.pat,
                                .guard = branch.guard,
                                .body = try self.cloneMatchValueBranchBodyWithDemand(branch, demand),
                                .source = branch.source,
                            };
                        }
                        break :blk Value{ .match_ = .{
                            .ty = match_value.ty,
                            .scrutinee = match_value.scrutinee,
                            .branches = branches,
                            .comptime_site = match_value.comptime_site,
                        } };
                    },
                    else => {},
                }
                var pending_lets = std.ArrayList(PendingLet).empty;
                defer pending_lets.deinit(self.pass.allocator);
                const private_state = (try self.privateStateValueFromValueDemandCollectingLets(value, resolved_demand, &pending_lets)) orelse
                    return try self.ensureDemandedKnownValue(value);
                break :blk try self.wrapPendingLets(.{ .private_state = private_state }, pending_lets.items, true);
            },
        };
    }

    fn cloneMatchValueBranchBodyWithDemand(
        self: *Cloner,
        branch: MatchValueBranch,
        demand: ValueDemand,
    ) LowerError!Value {
        const source = branch.source orelse return try self.applyValueDemand(branch.body, demand);

        const change_start = self.changes.items.len;
        defer self.restore(change_start);
        const missing_source_pending_lets = try self.missingActivePendingLets(source.pending_lets);
        defer self.pass.allocator.free(missing_source_pending_lets);
        const source_pending_start = self.activePendingLetsLen();
        const source_pending_scope_start = try self.pushPendingLetScope(missing_source_pending_lets);
        defer self.popPendingLetScope(source_pending_scope_start, source_pending_start);

        const scoped_start = self.scopedLocalsLen();
        defer self.restoreScopedLocals(scoped_start);
        try self.appendPatternScopedLocals(source.pat);

        for (source.bindings) |binding| {
            try self.putSubst(binding.local, binding.value);
        }

        var pending_lets = std.ArrayList(PendingLet).empty;
        defer pending_lets.deinit(self.pass.allocator);

        const demand_context: ValueDemand = if (demand == .none) .materialize else demand;
        const source_body_demand = try self.matchSourceBodyDemand(source, demand_context);
        var scrutinee_demand = try self.patternDemandInExpr(source.pat, source.body, source_body_demand);
        if (source.guard) |guard| {
            scrutinee_demand = try self.mergeValueDemand(scrutinee_demand, try self.patternDemandInExpr(source.pat, guard, .materialize));
        }
        const demanded_scrutinee = try self.cloneExprValueWithDemand(source.scrutinee, scrutinee_demand);
        const binding_scrutinee = if (source.scrutinee_value) |value|
            try self.applyValueDemand(value.*, scrutinee_demand)
        else
            demanded_scrutinee;
        const unsafe_count = self.unsafeLeafCount(binding_scrutinee);
        const binding_known_value = (try self.pass.knownValueFromValue(binding_scrutinee)) orelse
            (try self.pass.knownValueFromValue(demanded_scrutinee)) orelse
            source.scrutinee_known_value;
        switch (try self.bindPatToMatchValue(source.pat, binding_scrutinee, source.body, source_body_demand, unsafe_count, &pending_lets)) {
            .matched => {
                if (binding_known_value) |known_value| {
                    try self.upgradePatternBindingsWithKnownValue(source.pat, known_value);
                }
            },
            .no_match,
            .unsupported,
            => {
                const known_value = binding_known_value orelse
                    return try self.applyValueDemand(branch.body, demand);
                const binding_value = switch (demanded_scrutinee) {
                    .expr => if (source.scrutinee_value) |value| value.* else demanded_scrutinee,
                    .expr_with_known_value => |known| if (known.value == null)
                        if (source.scrutinee_value) |value| value.* else demanded_scrutinee
                    else
                        demanded_scrutinee,
                    else => demanded_scrutinee,
                };
                _ = try self.bindPatToExprWithKnownValueAndValue(source.pat, known_value, binding_value);
            },
        }

        const result = try self.cloneMatchSourceBodyReadWithDemand(source, demand);
        const body_with_branch_pending = try self.wrapPendingLets(result, pending_lets.items, demand != .none);
        return try self.wrapPendingLets(body_with_branch_pending, missing_source_pending_lets, demand != .none);
    }

    fn matchSourceBodyDemand(
        self: *Cloner,
        source: MatchValueBranchSource,
        demand: ValueDemand,
    ) Allocator.Error!ValueDemand {
        return switch (source.read) {
            .none => demand,
            .callable_capture => |capture_read| try self.callableCaptureDemand(capture_read.capture_index, demand),
        };
    }

    fn cloneMatchSourceBodyReadWithDemand(
        self: *Cloner,
        source: MatchValueBranchSource,
        demand: ValueDemand,
    ) LowerError!Value {
        return switch (source.read) {
            .none => try self.cloneExprValueWithDemand(source.body, demand),
            .callable_capture => |capture_read| blk: {
                const capture_demand: ValueDemand = if (demand == .none) .materialize else demand;
                const callable_demand = try self.callableCaptureDemand(capture_read.capture_index, capture_demand);
                const body_value = try self.cloneExprValueWithDemand(source.body, callable_demand);
                break :blk (try self.callableCaptureFromValue(body_value, capture_read.callable, capture_read.capture_index)) orelse
                    Common.invariant("callable capture source read did not produce requested capture");
            },
        };
    }

    fn privateStateValueFromValueDemand(
        self: *Cloner,
        value: Value,
        demand: ValueDemand,
    ) LowerError!?PrivateStateValue {
        return try self.privateStateValueFromValueDemandCollectingLets(value, demand, null);
    }

    fn privateStateValueFromValueDemandCollectingLets(
        self: *Cloner,
        value: Value,
        demand: ValueDemand,
        pending_lets: ?*std.ArrayList(PendingLet),
    ) LowerError!?PrivateStateValue {
        const resolved_demand = self.resolveLoopDemandRef(demand);
        if (resolved_demand == .fn_param) {
            return null;
        }
        if (value == .let_) {
            const let_value = value.let_;
            const body_private_state = if (pending_lets) |lets| body: {
                try self.appendPendingLetsUnique(lets, let_value.lets);
                const change_start = self.changes.items.len;
                defer self.restore(change_start);
                const pending_start = self.activePendingLetsLen();
                const scoped_start = try self.pushPendingLetScope(let_value.lets);
                defer self.popPendingLetScope(scoped_start, pending_start);
                break :body (try self.privateStateValueFromValueDemandCollectingLets(let_value.body.*, resolved_demand, lets)) orelse return null;
            } else body: {
                const change_start = self.changes.items.len;
                defer self.restore(change_start);
                const pending_start = self.activePendingLetsLen();
                const scoped_start = try self.pushPendingLetScope(let_value.lets);
                defer self.popPendingLetScope(scoped_start, pending_start);
                break :body (try self.privateStateValueFromValueDemandCollectingLets(let_value.body.*, resolved_demand, null)) orelse return null;
            };
            if (pending_lets != null) return body_private_state;
            return try self.wrapPendingLetsInPrivateState(body_private_state, let_value.lets);
        }
        if (value == .if_) {
            if (try self.privateStateValueFromIfDemand(value.if_, resolved_demand, pending_lets)) |private_state| return private_state;
        }
        if (value == .match_) {
            if (try self.privateStateValueFromMatchDemand(value.match_, resolved_demand, pending_lets)) |private_state| return private_state;
        }
        if (value == .expr) {
            switch (resolved_demand) {
                .record,
                .tuple,
                .tag,
                .nominal,
                .callable,
                => {
                    switch (self.pass.program.exprs.items[@intFromEnum(value.expr)].data) {
                        .local => |local| {
                            if (self.subst.get(local)) |subst| {
                                const refined = try self.applyValueDemand(subst, resolved_demand);
                                if (!valueIsExpr(refined, value.expr)) {
                                    if (refined == .expr) return try self.privateStateLeafFromValue(refined);
                                    return try self.privateStateValueFromValueDemandCollectingLets(refined, resolved_demand, pending_lets);
                                }
                            }
                        },
                        .call_proc,
                        .call_value,
                        => {
                            const refined = try self.cloneExprValueWithDemand(value.expr, resolved_demand);
                            if (!valueIsExpr(refined, value.expr)) {
                                if (refined == .expr) return try self.privateStateLeafFromValue(refined);
                                return try self.privateStateValueFromValueDemandCollectingLets(refined, resolved_demand, pending_lets);
                            }
                        },
                        else => {},
                    }
                },
                .none,
                .materialize,
                .loop_param,
                .fn_param,
                => {},
            }
        }

        return switch (resolved_demand) {
            .none => null,
            .materialize => if (value == .private_state)
                value.private_state
            else
                try self.privateStateLeafFromValue(value),
            .loop_param => Common.invariant("loop demand reference did not resolve before private-state construction"),
            .fn_param => Common.invariant("function demand reference did not resolve before private-state construction"),
            .record => |field_demands| blk: {
                var fields = std.ArrayList(PrivateStateField).empty;
                defer fields.deinit(self.pass.allocator);
                for (field_demands) |field_demand| {
                    if (field_demand.demand.* == .none) continue;
                    const field_ty = recordFieldType(self.pass.program, valueType(self.pass.program, value), field_demand.name) orelse
                        break :blk try self.privateStateLeafFromValue(value);
                    const field_value = (try self.fieldFromKnownValue(value, field_demand.name)) orelse
                        fieldFromValue(self.pass.program, value, field_demand.name) orelse
                        (try self.fieldFromPatternValue(value, field_demand.name, field_ty)) orelse
                        break :blk try self.privateStateLeafFromValue(value);
                    const field_private_state = (try self.privateStateValueFromValueDemandOrLeafCollectingLets(field_value, field_demand.demand.*, pending_lets)) orelse
                        break :blk try self.privateStateLeafFromValue(value);
                    try fields.append(self.pass.allocator, .{
                        .name = field_demand.name,
                        .value = field_private_state,
                    });
                }
                break :blk PrivateStateValue{ .record = .{
                    .ty = valueType(self.pass.program, value),
                    .fields = try self.pass.arena.allocator().dupe(PrivateStateField, fields.items),
                } };
            },
            .tuple => |item_demands| blk: {
                var items = std.ArrayList(PrivateStateIndexedValue).empty;
                defer items.deinit(self.pass.allocator);
                for (item_demands) |item_demand| {
                    if (item_demand.demand.* == .none) continue;
                    const item_ty = tupleItemType(self.pass.program, valueType(self.pass.program, value), item_demand.index) orelse
                        break :blk try self.privateStateLeafFromValue(value);
                    const item_value = (try self.itemFromKnownValue(value, item_demand.index)) orelse
                        itemFromValue(value, item_demand.index) orelse
                        (try self.itemFromPatternValue(value, item_demand.index, item_ty)) orelse
                        break :blk try self.privateStateLeafFromValue(value);
                    const item_private_state = (try self.privateStateValueFromValueDemandOrLeafCollectingLets(item_value, item_demand.demand.*, pending_lets)) orelse
                        break :blk try self.privateStateLeafFromValue(value);
                    try items.append(self.pass.allocator, .{
                        .index = item_demand.index,
                        .value = item_private_state,
                    });
                }
                break :blk PrivateStateValue{ .tuple = .{
                    .ty = valueType(self.pass.program, value),
                    .items = try self.pass.arena.allocator().dupe(PrivateStateIndexedValue, items.items),
                } };
            },
            .tag => |tag_demand| blk: {
                if (value == .private_state) {
                    if (value.private_state == .compact_finite_tags) {
                        const source_known = try knownValueFromDemandedKnownValue(
                            self.pass.program,
                            self.pass.arena.allocator(),
                            .{ .finite_tags = value.private_state.compact_finite_tags.source },
                        );
                        _ = (try demandedKnownValueFromDemand(
                            self,
                            self.pass.program,
                            self.pass.arena.allocator(),
                            source_known,
                            .{ .tag = tag_demand },
                        )) orelse break :blk null;
                        break :blk value.private_state;
                    }

                    if (privateStateTag(value.private_state)) |private_tag| {
                        var payloads = std.ArrayList(PrivateStateIndexedValue).empty;
                        defer payloads.deinit(self.pass.allocator);
                        if (tagAlternativeDemandByName(self.pass.program, tag_demand.alternatives, private_tag.name)) |alternative_demand| {
                            for (alternative_demand.payloads) |payload_demand| {
                                if (payload_demand.demand.* == .none) continue;
                                const payload = privateStateIndexedValueByIndex(private_tag.payloads, payload_demand.index) orelse break :blk null;
                                const payload_private_state = (try self.privateStateValueFromValueDemandOrLeafCollectingLets(.{ .private_state = payload }, payload_demand.demand.*, pending_lets)) orelse break :blk null;
                                try payloads.append(self.pass.allocator, .{
                                    .index = payload_demand.index,
                                    .value = payload_private_state,
                                });
                            }
                        }
                        break :blk PrivateStateValue{ .tag = .{
                            .ty = private_tag.ty,
                            .name = private_tag.name,
                            .payloads = try self.pass.arena.allocator().dupe(PrivateStateIndexedValue, payloads.items),
                        } };
                    }
                }

                if (value == .finite_tags) {
                    const known = (try self.pass.knownValueFromValue(value)) orelse break :blk null;
                    const demanded = (try demandedKnownValueFromDemand(
                        self,
                        self.pass.program,
                        self.pass.arena.allocator(),
                        known,
                        .{ .tag = tag_demand },
                    )) orelse break :blk null;
                    if (demanded != .finite_tags) break :blk null;

                    var local_pending_lets = std.ArrayList(PendingLet).empty;
                    defer local_pending_lets.deinit(self.pass.allocator);
                    const compact_pending_lets = pending_lets orelse &local_pending_lets;
                    var compact_expr = (try self.compactFiniteTagsExpr(demanded.finite_tags, value, compact_pending_lets)) orelse break :blk null;
                    if (pending_lets == null) {
                        compact_expr = try self.wrapPendingLetsAroundExpr(
                            try self.pass.compactFiniteTagsType(demanded.finite_tags),
                            compact_expr,
                            local_pending_lets.items,
                        );
                    }
                    break :blk PrivateStateValue{ .compact_finite_tags = .{
                        .source = demanded.finite_tags,
                        .compact_expr = compact_expr,
                    } };
                }

                const tag = tagFromValue(value) orelse break :blk null;
                var payloads = std.ArrayList(PrivateStateIndexedValue).empty;
                defer payloads.deinit(self.pass.allocator);
                if (tagAlternativeDemandByName(self.pass.program, tag_demand.alternatives, tag.name)) |alternative_demand| {
                    for (alternative_demand.payloads) |payload_demand| {
                        if (payload_demand.demand.* == .none) continue;
                        if (payload_demand.index >= tag.payloads.len) break :blk null;
                        const payload_private_state = (try self.privateStateValueFromValueDemandOrLeafCollectingLets(tag.payloads[payload_demand.index], payload_demand.demand.*, pending_lets)) orelse break :blk null;
                        try payloads.append(self.pass.allocator, .{
                            .index = payload_demand.index,
                            .value = payload_private_state,
                        });
                    }
                }
                break :blk PrivateStateValue{ .tag = .{
                    .ty = tag.ty,
                    .name = tag.name,
                    .payloads = try self.pass.arena.allocator().dupe(PrivateStateIndexedValue, payloads.items),
                } };
            },
            .nominal => |backing_demand| blk: {
                const nominal_ty = switch (value) {
                    .nominal => |nominal| nominal.ty,
                    .private_state => |private_state| switch (private_state) {
                        .nominal => |nominal| nominal.ty,
                        else => break :blk null,
                    },
                    else => break :blk null,
                };
                const backing_value = switch (value) {
                    .nominal => |value_nominal| value_nominal.backing.*,
                    .private_state => switch (value.private_state) {
                        .nominal => |private_nominal| if (private_nominal.backing) |backing| Value{ .private_state = backing.* } else break :blk null,
                        else => break :blk null,
                    },
                    else => break :blk null,
                };
                const backing_private_state = (try self.privateStateValueFromValueDemandOrLeafCollectingLets(backing_value, backing_demand.*, pending_lets)) orelse break :blk null;
                const backing = try self.pass.arena.allocator().create(PrivateStateValue);
                backing.* = backing_private_state;
                break :blk PrivateStateValue{ .nominal = .{
                    .ty = nominal_ty,
                    .backing = backing,
                } };
            },
            .callable => |callable_demand| blk: {
                var effective_callable_demand = callable_demand;
                if (callable_demand.result) |result_demand| {
                    const concrete_demand = switch (value) {
                        .callable => |callable| try self.callableDemandForCallableValueWithResultDemand(callable, result_demand.*),
                        .finite_callables => |finite_callables| concrete: {
                            var alternative_demand: ValueDemand = .{ .callable = .{ .captures = &.{} } };
                            for (finite_callables.alternatives) |alternative| {
                                alternative_demand = try self.mergeValueDemand(
                                    alternative_demand,
                                    try self.callableDemandForCallableValueWithResultDemand(alternative, result_demand.*),
                                );
                            }
                            break :concrete alternative_demand;
                        },
                        .private_state => |private_state| try self.callableDemandForPrivateStateValueWithResultDemand(
                            private_state,
                            result_demand.*,
                        ) orelse null,
                        else => null,
                    };
                    if (concrete_demand) |concrete| {
                        const merged = try self.mergeValueDemand(.{ .callable = callable_demand }, concrete);
                        if (merged == .callable) effective_callable_demand = merged.callable;
                    }
                    if (value == .private_state) {
                        if (privateStateCallable(value.private_state)) |private_callable| {
                            if (private_callable.captures.len > 0) {
                                const finite_identity_demand = try self.finiteStateIdentityDemandFromPrivateCallable(private_callable);
                                if (finite_identity_demand == .callable) {
                                    const merged = try self.mergeValueDemand(.{ .callable = effective_callable_demand }, finite_identity_demand);
                                    if (merged == .callable) effective_callable_demand = merged.callable;
                                }
                            }
                        }
                    }
                    if (value == .callable) {
                        if (value.callable.captures.len > 0) {
                            const finite_identity_demand = try self.finiteStateIdentityDemandFromCallableValue(value.callable);
                            if (finite_identity_demand == .callable) {
                                const merged = try self.mergeValueDemand(.{ .callable = effective_callable_demand }, finite_identity_demand);
                                if (merged == .callable) effective_callable_demand = merged.callable;
                            }
                        }
                    }
                    if (value == .finite_callables) {
                        const alternative_demand = try self.finiteStateIdentityDemandFromValue(value);
                        if (alternative_demand == .callable) {
                            const merged = try self.mergeValueDemand(.{ .callable = effective_callable_demand }, alternative_demand);
                            if (merged == .callable) effective_callable_demand = merged.callable;
                        }
                    }
                    if (value == .private_state and value.private_state == .compact_finite_callables) {
                        const alternative_demand = try self.finiteStateIdentityDemandFromPrivateState(value.private_state);
                        if (alternative_demand == .callable) {
                            const merged = try self.mergeValueDemand(.{ .callable = effective_callable_demand }, alternative_demand);
                            if (merged == .callable) effective_callable_demand = merged.callable;
                        }
                    }
                }
                if (value == .private_state) {
                    if (privateStateLeafExpr(value.private_state) != null) break :blk value.private_state;
                    if (value.private_state == .compact_finite_callables) {
                        const source_known = try knownValueFromDemandedKnownValue(
                            self.pass.program,
                            self.pass.arena.allocator(),
                            .{ .finite_callables = value.private_state.compact_finite_callables.source },
                        );
                        _ = (try demandedKnownValueFromDemand(
                            self,
                            self.pass.program,
                            self.pass.arena.allocator(),
                            source_known,
                            .{ .callable = effective_callable_demand },
                        )) orelse break :blk null;
                        break :blk value.private_state;
                    }
                }

                if (value == .finite_callables) {
                    const known = (try self.pass.knownValueFromValue(value)) orelse break :blk null;
                    const demanded = (try demandedKnownValueFromDemand(
                        self,
                        self.pass.program,
                        self.pass.arena.allocator(),
                        known,
                        .{ .callable = effective_callable_demand },
                    )) orelse break :blk null;
                    if (demanded != .finite_callables) break :blk null;

                    var local_pending_lets = std.ArrayList(PendingLet).empty;
                    defer local_pending_lets.deinit(self.pass.allocator);
                    const compact_pending_lets = pending_lets orelse &local_pending_lets;
                    var compact_expr = (try self.compactFiniteCallablesExpr(demanded.finite_callables, value, compact_pending_lets)) orelse break :blk null;
                    if (pending_lets == null) {
                        compact_expr = try self.wrapPendingLetsAroundExpr(
                            try self.pass.compactFiniteCallablesType(demanded.finite_callables),
                            compact_expr,
                            local_pending_lets.items,
                        );
                    }
                    break :blk PrivateStateValue{ .compact_finite_callables = .{
                        .source = demanded.finite_callables,
                        .compact_expr = compact_expr,
                    } };
                }

                const callable_ty = switch (value) {
                    .callable => |callable| callable.ty,
                    .private_state => |private_state| (privateStateCallable(private_state) orelse break :blk null).ty,
                    else => break :blk null,
                };
                const callable_fn_id = switch (value) {
                    .callable => |callable| callable.fn_id,
                    .private_state => |private_state| (privateStateCallable(private_state) orelse break :blk null).fn_id,
                    else => break :blk null,
                };
                const callable_loop_origin: ?PrivateStateLoopOrigin = switch (value) {
                    .private_state => |private_state| (privateStateCallable(private_state) orelse break :blk null).loop_origin,
                    else => null,
                };
                var captures = std.ArrayList(PrivateStateIndexedValue).empty;
                defer captures.deinit(self.pass.allocator);
                const capture_count = switch (value) {
                    .callable => |callable_value| callable_value.captures.len,
                    .private_state => |private_state| if (privateStateCallable(private_state)) |private_callable| self.pass.program.typedLocalSpan(self.pass.program.fns.items[@intFromEnum(private_callable.fn_id)].captures).len else 0,
                    else => 0,
                };
                var index: usize = 0;
                while (index < capture_count) : (index += 1) {
                    const maybe_capture_demand = if (index < effective_callable_demand.captures.len)
                        effective_callable_demand.captures[index]
                    else
                        .none;
                    const capture_demand = maybe_capture_demand;
                    if (capture_demand == .none) continue;
                    const capture_value = switch (value) {
                        .callable => |callable_value| callable_value.captures[index],
                        .private_state => |private_state| blk_capture: {
                            const private_callable = privateStateCallable(private_state) orelse break :blk null;
                            break :blk_capture (try self.privateStateCallableCaptureValue(private_callable, index)) orelse {
                                break :blk null;
                            };
                        },
                        else => break :blk null,
                    };
                    const capture_private_state = (try self.privateStateValueFromValueDemandOrLeafCollectingLets(capture_value, capture_demand, pending_lets)) orelse break :blk null;
                    try captures.append(self.pass.allocator, .{
                        .index = @intCast(index),
                        .value = capture_private_state,
                    });
                }
                const private_captures = try self.pass.arena.allocator().dupe(PrivateStateIndexedValue, captures.items);
                break :blk PrivateStateValue{ .callable = .{
                    .ty = callable_ty,
                    .fn_id = callable_fn_id,
                    .captures = private_captures,
                    .loop_origin = callable_loop_origin,
                } };
            },
        };
    }

    fn finiteStateIdentityDemandFromCallableValue(
        self: *Cloner,
        callable: CallableValue,
    ) LowerError!ValueDemand {
        const captures = try self.pass.arena.allocator().alloc(ValueDemand, callable.captures.len);
        @memset(captures, .none);
        var has_capture_demand = false;
        for (callable.captures, captures) |capture, *out| {
            out.* = try self.finiteStateIdentityDemandFromValue(capture);
            has_capture_demand = has_capture_demand or out.* != .none;
        }
        if (!has_capture_demand) return .none;
        return .{ .callable = .{ .captures = captures } };
    }

    fn finiteStateIdentityDemandFromPrivateCallable(
        self: *Cloner,
        callable: PrivateStateCallable,
    ) LowerError!ValueDemand {
        var captures_len: usize = 0;
        for (callable.captures) |capture| {
            captures_len = @max(captures_len, @as(usize, capture.index) + 1);
        }

        const captures = try self.pass.arena.allocator().alloc(ValueDemand, captures_len);
        @memset(captures, .none);
        var has_capture_demand = false;
        for (callable.captures) |capture| {
            captures[capture.index] = try self.finiteStateIdentityDemandFromPrivateState(capture.value);
            has_capture_demand = has_capture_demand or captures[capture.index] != .none;
        }
        if (!has_capture_demand) return .none;
        return .{ .callable = .{ .captures = captures } };
    }

    fn finiteStateIdentityDemandFromValue(
        self: *Cloner,
        value: Value,
    ) LowerError!ValueDemand {
        return switch (value) {
            .let_ => |let_value| try self.finiteStateIdentityDemandFromValue(let_value.body.*),
            .if_ => |if_value| blk: {
                var demand: ValueDemand = .none;
                for (if_value.branches) |branch| {
                    demand = try self.mergeValueDemand(demand, try self.finiteStateIdentityDemandFromValue(branch.body));
                }
                demand = try self.mergeValueDemand(demand, try self.finiteStateIdentityDemandFromValue(if_value.final_else.*));
                break :blk demand;
            },
            .match_ => |match_value| blk: {
                var demand: ValueDemand = .none;
                for (match_value.branches) |branch| {
                    demand = try self.mergeValueDemand(demand, try self.finiteStateIdentityDemandFromValue(branch.body));
                }
                break :blk demand;
            },
            .record => |record| blk: {
                var fields = std.ArrayList(FieldDemand).empty;
                defer fields.deinit(self.pass.allocator);
                for (record.fields) |field| {
                    const field_demand = try self.finiteStateIdentityDemandFromValue(field.value);
                    if (field_demand == .none) continue;
                    try fields.append(self.pass.allocator, .{
                        .name = field.name,
                        .demand = try self.pass.storedDemand(field_demand),
                    });
                }
                if (fields.items.len == 0) break :blk .none;
                break :blk ValueDemand{ .record = try self.pass.arena.allocator().dupe(FieldDemand, fields.items) };
            },
            .tuple => |tuple| blk: {
                var items = std.ArrayList(ItemDemand).empty;
                defer items.deinit(self.pass.allocator);
                for (tuple.items, 0..) |item, index| {
                    const item_demand = try self.finiteStateIdentityDemandFromValue(item);
                    if (item_demand == .none) continue;
                    try items.append(self.pass.allocator, .{
                        .index = @intCast(index),
                        .demand = try self.pass.storedDemand(item_demand),
                    });
                }
                if (items.items.len == 0) break :blk .none;
                break :blk ValueDemand{ .tuple = try self.pass.arena.allocator().dupe(ItemDemand, items.items) };
            },
            .tag => |tag| blk: {
                var payloads = std.ArrayList(ItemDemand).empty;
                defer payloads.deinit(self.pass.allocator);
                for (tag.payloads, 0..) |payload, index| {
                    const payload_demand = try self.finiteStateIdentityDemandFromValue(payload);
                    if (payload_demand == .none) continue;
                    try payloads.append(self.pass.allocator, .{
                        .index = @intCast(index),
                        .demand = try self.pass.storedDemand(payload_demand),
                    });
                }
                if (payloads.items.len == 0) break :blk .none;
                const alternatives = try self.pass.arena.allocator().alloc(TagAlternativeDemand, 1);
                alternatives[0] = .{
                    .name = tag.name,
                    .payloads = try self.pass.arena.allocator().dupe(ItemDemand, payloads.items),
                };
                break :blk ValueDemand{ .tag = .{ .alternatives = alternatives } };
            },
            .nominal => |nominal| blk: {
                const backing_demand = try self.finiteStateIdentityDemandFromValue(nominal.backing.*);
                if (backing_demand == .none) break :blk .none;
                break :blk ValueDemand{ .nominal = try self.pass.storedDemand(backing_demand) };
            },
            .callable => |callable| try self.finiteStateIdentityDemandFromCallableValue(callable),
            .finite_tags,
            .finite_callables,
            => try self.finiteStateIdentityDemandFromKnownValue((try self.pass.knownValueFromValue(value)) orelse
                KnownValue{ .any = valueType(self.pass.program, value) }),
            .private_state => |private_state| try self.finiteStateIdentityDemandFromPrivateState(private_state),
            .expr_with_known_value => |known| if (known.value) |structured|
                try self.finiteStateIdentityDemandFromValue(structured.*)
            else
                try self.finiteStateIdentityDemandFromKnownValue(known.known_value),
            .expr => .none,
        };
    }

    fn finiteStateIdentityDemandFromPrivateState(
        self: *Cloner,
        value: PrivateStateValue,
    ) LowerError!ValueDemand {
        return switch (value) {
            .leaf => .none,
            .record => |record| blk: {
                var fields = std.ArrayList(FieldDemand).empty;
                defer fields.deinit(self.pass.allocator);
                for (record.fields) |field| {
                    const field_demand = try self.finiteStateIdentityDemandFromPrivateState(field.value);
                    if (field_demand == .none) continue;
                    try fields.append(self.pass.allocator, .{
                        .name = field.name,
                        .demand = try self.pass.storedDemand(field_demand),
                    });
                }
                if (fields.items.len == 0) break :blk .none;
                break :blk ValueDemand{ .record = try self.pass.arena.allocator().dupe(FieldDemand, fields.items) };
            },
            .tuple => |tuple| blk: {
                var items = std.ArrayList(ItemDemand).empty;
                defer items.deinit(self.pass.allocator);
                for (tuple.items) |item| {
                    const item_demand = try self.finiteStateIdentityDemandFromPrivateState(item.value);
                    if (item_demand == .none) continue;
                    try items.append(self.pass.allocator, .{
                        .index = item.index,
                        .demand = try self.pass.storedDemand(item_demand),
                    });
                }
                if (items.items.len == 0) break :blk .none;
                break :blk ValueDemand{ .tuple = try self.pass.arena.allocator().dupe(ItemDemand, items.items) };
            },
            .tag => |tag| blk: {
                var payloads = std.ArrayList(ItemDemand).empty;
                defer payloads.deinit(self.pass.allocator);
                for (tag.payloads) |payload| {
                    const payload_demand = try self.finiteStateIdentityDemandFromPrivateState(payload.value);
                    if (payload_demand == .none) continue;
                    try payloads.append(self.pass.allocator, .{
                        .index = payload.index,
                        .demand = try self.pass.storedDemand(payload_demand),
                    });
                }
                if (payloads.items.len == 0) break :blk .none;
                const alternatives = try self.pass.arena.allocator().alloc(TagAlternativeDemand, 1);
                alternatives[0] = .{
                    .name = tag.name,
                    .payloads = try self.pass.arena.allocator().dupe(ItemDemand, payloads.items),
                };
                break :blk ValueDemand{ .tag = .{ .alternatives = alternatives } };
            },
            .nominal => |nominal| blk: {
                const backing = nominal.backing orelse break :blk .none;
                const backing_demand = try self.finiteStateIdentityDemandFromPrivateState(backing.*);
                if (backing_demand == .none) break :blk .none;
                break :blk ValueDemand{ .nominal = try self.pass.storedDemand(backing_demand) };
            },
            .callable => |callable| try self.finiteStateIdentityDemandFromPrivateCallable(callable),
            .compact_finite_tags => |finite_tags| try self.finiteStateIdentityDemandFromDemandedKnownValue(.{ .finite_tags = finite_tags.source }),
            .compact_finite_callables => |finite_callables| try self.finiteStateIdentityDemandFromDemandedKnownValue(.{ .finite_callables = finite_callables.source }),
        };
    }

    fn finiteStateIdentityDemandFromKnownValue(
        self: *Cloner,
        known_value: KnownValue,
    ) LowerError!ValueDemand {
        const demanded = try materializedDemandedKnownValue(self.pass.arena.allocator(), known_value);
        return try self.finiteStateIdentityDemandFromDemandedKnownValue(demanded);
    }

    fn finiteStateIdentityDemandFromDemandedKnownValue(
        self: *Cloner,
        known_value: DemandedKnownValue,
    ) LowerError!ValueDemand {
        return switch (known_value) {
            .any,
            .leaf,
            => .none,
            .record => |record| blk: {
                var fields = std.ArrayList(FieldDemand).empty;
                defer fields.deinit(self.pass.allocator);
                for (record.fields) |field| {
                    const field_demand = try self.finiteStateIdentityDemandFromDemandedKnownValue(field.known_value);
                    if (field_demand == .none) continue;
                    try fields.append(self.pass.allocator, .{
                        .name = field.name,
                        .demand = try self.pass.storedDemand(field_demand),
                    });
                }
                if (fields.items.len == 0) break :blk .none;
                break :blk ValueDemand{ .record = try self.pass.arena.allocator().dupe(FieldDemand, fields.items) };
            },
            .tuple => |tuple| blk: {
                var items = std.ArrayList(ItemDemand).empty;
                defer items.deinit(self.pass.allocator);
                for (tuple.items) |item| {
                    const item_demand = try self.finiteStateIdentityDemandFromDemandedKnownValue(item.known_value);
                    if (item_demand == .none) continue;
                    try items.append(self.pass.allocator, .{
                        .index = item.index,
                        .demand = try self.pass.storedDemand(item_demand),
                    });
                }
                if (items.items.len == 0) break :blk .none;
                break :blk ValueDemand{ .tuple = try self.pass.arena.allocator().dupe(ItemDemand, items.items) };
            },
            .tag => |tag| blk: {
                var payloads = std.ArrayList(ItemDemand).empty;
                defer payloads.deinit(self.pass.allocator);
                for (tag.payloads) |payload| {
                    const payload_demand = try self.finiteStateIdentityDemandFromDemandedKnownValue(payload.known_value);
                    if (payload_demand == .none) continue;
                    try payloads.append(self.pass.allocator, .{
                        .index = payload.index,
                        .demand = try self.pass.storedDemand(payload_demand),
                    });
                }
                if (payloads.items.len == 0) break :blk .none;
                const alternatives = try self.pass.arena.allocator().alloc(TagAlternativeDemand, 1);
                alternatives[0] = .{
                    .name = tag.name,
                    .payloads = try self.pass.arena.allocator().dupe(ItemDemand, payloads.items),
                };
                break :blk ValueDemand{ .tag = .{ .alternatives = alternatives } };
            },
            .nominal => |nominal| blk: {
                const backing = nominal.backing orelse break :blk .none;
                const backing_demand = try self.finiteStateIdentityDemandFromDemandedKnownValue(backing.*);
                if (backing_demand == .none) break :blk .none;
                break :blk ValueDemand{ .nominal = try self.pass.storedDemand(backing_demand) };
            },
            .callable => |callable| blk: {
                var captures_len: usize = 0;
                for (callable.captures) |capture| {
                    captures_len = @max(captures_len, @as(usize, capture.index) + 1);
                }
                const captures = try self.pass.arena.allocator().alloc(ValueDemand, captures_len);
                @memset(captures, .none);
                var has_capture_demand = false;
                for (callable.captures) |capture| {
                    captures[capture.index] = try self.finiteStateIdentityDemandFromDemandedKnownValue(capture.known_value);
                    has_capture_demand = has_capture_demand or captures[capture.index] != .none;
                }
                if (!has_capture_demand) break :blk .none;
                break :blk ValueDemand{ .callable = .{ .captures = captures } };
            },
            .finite_tags,
            .compact_finite_tags,
            => |finite_tags| blk: {
                var alternatives = std.ArrayList(TagAlternativeDemand).empty;
                defer alternatives.deinit(self.pass.allocator);
                for (finite_tags.alternatives) |alternative| {
                    var payloads = std.ArrayList(ItemDemand).empty;
                    defer payloads.deinit(self.pass.allocator);
                    for (alternative.payloads) |payload| {
                        const payload_demand = try self.finiteStateIdentityDemandFromDemandedKnownValue(payload.known_value);
                        if (payload_demand == .none) continue;
                        try payloads.append(self.pass.allocator, .{
                            .index = payload.index,
                            .demand = try self.pass.storedDemand(payload_demand),
                        });
                    }
                    try alternatives.append(self.pass.allocator, .{
                        .name = alternative.name,
                        .payloads = try self.pass.arena.allocator().dupe(ItemDemand, payloads.items),
                    });
                }
                break :blk ValueDemand{ .tag = .{ .alternatives = try self.pass.arena.allocator().dupe(TagAlternativeDemand, alternatives.items) } };
            },
            .finite_callables,
            .compact_finite_callables,
            => |finite_callables| blk: {
                var demand: ValueDemand = .{ .callable = .{ .captures = &.{} } };
                for (finite_callables.alternatives) |alternative| {
                    const alternative_demand = try self.finiteStateIdentityDemandFromDemandedKnownValue(.{ .callable = alternative });
                    demand = try self.mergeValueDemand(demand, alternative_demand);
                }
                break :blk demand;
            },
        };
    }

    fn privateStateValueFromValueDemandOrLeafCollectingLets(
        self: *Cloner,
        value: Value,
        demand: ValueDemand,
        pending_lets: ?*std.ArrayList(PendingLet),
    ) LowerError!?PrivateStateValue {
        if (try self.privateStateValueFromValueDemandCollectingLets(value, demand, pending_lets)) |private_state| return private_state;
        return try self.privateStateLeafFromValue(value);
    }

    fn privateStateCallableCaptureValue(
        self: *Cloner,
        callable: PrivateStateCallable,
        index: usize,
    ) LowerError!?Value {
        if (privateStateIndexedValueByIndex(callable.captures, @intCast(index))) |capture| {
            return Value{ .private_state = capture };
        }

        const source_fn = self.pass.program.fns.items[@intFromEnum(callable.fn_id)];
        const source_captures = self.pass.program.typedLocalSpan(source_fn.captures);
        if (index >= source_captures.len) {
            Common.invariant("private callable capture index exceeded lifted function capture count");
        }

        if (self.subst.get(source_captures[index].local)) |value| return value;
        return try self.scopedLocalValue(source_captures[index]);
    }

    fn wrapPendingLetsInPrivateState(
        self: *Cloner,
        value: PrivateStateValue,
        pending_lets: []const PendingLet,
    ) LowerError!PrivateStateValue {
        if (pending_lets.len == 0) return value;

        return switch (value) {
            .leaf => |leaf| .{ .leaf = .{
                .ty = leaf.ty,
                .expr = try self.wrapPendingLetsAroundExpr(leaf.ty, leaf.expr, pending_lets),
            } },
            .tag => |tag| blk: {
                const payloads = try self.pass.arena.allocator().alloc(PrivateStateIndexedValue, tag.payloads.len);
                for (tag.payloads, payloads) |payload, *out| {
                    out.* = .{
                        .index = payload.index,
                        .value = try self.wrapPendingLetsInPrivateState(payload.value, pending_lets),
                    };
                }
                break :blk PrivateStateValue{ .tag = .{
                    .ty = tag.ty,
                    .name = tag.name,
                    .payloads = payloads,
                } };
            },
            .record => |record| blk: {
                const fields = try self.pass.arena.allocator().alloc(PrivateStateField, record.fields.len);
                for (record.fields, fields) |field, *out| {
                    out.* = .{
                        .name = field.name,
                        .value = try self.wrapPendingLetsInPrivateState(field.value, pending_lets),
                    };
                }
                break :blk PrivateStateValue{ .record = .{
                    .ty = record.ty,
                    .fields = fields,
                } };
            },
            .tuple => |tuple| blk: {
                const items = try self.pass.arena.allocator().alloc(PrivateStateIndexedValue, tuple.items.len);
                for (tuple.items, items) |item, *out| {
                    out.* = .{
                        .index = item.index,
                        .value = try self.wrapPendingLetsInPrivateState(item.value, pending_lets),
                    };
                }
                break :blk PrivateStateValue{ .tuple = .{
                    .ty = tuple.ty,
                    .items = items,
                } };
            },
            .nominal => |nominal| blk: {
                const backing = if (nominal.backing) |backing_value| backing: {
                    const stored = try self.pass.arena.allocator().create(PrivateStateValue);
                    stored.* = try self.wrapPendingLetsInPrivateState(backing_value.*, pending_lets);
                    break :backing stored;
                } else null;
                break :blk PrivateStateValue{ .nominal = .{
                    .ty = nominal.ty,
                    .backing = backing,
                } };
            },
            .callable => |callable| blk: {
                const captures = try self.pass.arena.allocator().alloc(PrivateStateIndexedValue, callable.captures.len);
                for (callable.captures, captures) |capture, *out| {
                    out.* = .{
                        .index = capture.index,
                        .value = try self.wrapPendingLetsInPrivateState(capture.value, pending_lets),
                    };
                }
                break :blk PrivateStateValue{ .callable = .{
                    .ty = callable.ty,
                    .fn_id = callable.fn_id,
                    .captures = captures,
                    .loop_origin = callable.loop_origin,
                } };
            },
            .compact_finite_tags => |finite_tags| .{ .compact_finite_tags = .{
                .source = finite_tags.source,
                .compact_expr = try self.wrapPendingLetsAroundExpr(
                    self.pass.program.exprs.items[@intFromEnum(finite_tags.compact_expr)].ty,
                    finite_tags.compact_expr,
                    pending_lets,
                ),
            } },
            .compact_finite_callables => |finite_callables| .{ .compact_finite_callables = .{
                .source = finite_callables.source,
                .compact_expr = try self.wrapPendingLetsAroundExpr(
                    self.pass.program.exprs.items[@intFromEnum(finite_callables.compact_expr)].ty,
                    finite_callables.compact_expr,
                    pending_lets,
                ),
            } },
        };
    }

    fn privateStateLeafFromValue(self: *Cloner, value: Value) LowerError!?PrivateStateValue {
        if (value == .private_state) {
            const expr = privateStateLeafExpr(value.private_state) orelse return null;
            if (try self.substitutedPrivateLeafValue(value.private_state)) |substituted| {
                if (!(substituted == .private_state and privateStateEql(self.pass.program, substituted.private_state, value.private_state))) {
                    return try self.privateStateLeafFromValue(substituted);
                }
            }
            return .{ .leaf = .{
                .ty = privateStateValueType(value.private_state),
                .expr = expr,
            } };
        }
        switch (value) {
            .let_,
            .if_,
            .match_,
            => return null,
            else => {},
        }

        const ty = valueType(self.pass.program, value);
        return .{ .leaf = .{
            .ty = ty,
            .expr = (try self.outputExprFromValue(value)) orelse return null,
        } };
    }

    fn cloneFieldAccessValueWithDemand(self: *Cloner, ty: Type.TypeId, field: anytype, demand: ValueDemand) LowerError!Value {
        const receiver_demand = try self.pass.demandRecordField(field.field, demand);
        const receiver = try self.cloneExprValueWithDemand(field.receiver, receiver_demand);
        if (try self.fieldFromKnownValue(receiver, field.field)) |value| return try self.applyValueDemand(value, demand);
        if (try self.fieldFromPatternValueDemanded(receiver, field.field, ty, demand)) |value| return value;
        const receiver_expr = if (self.valueCanMaterializePublic(receiver))
            try self.materialize(receiver)
        else
            try self.cloneExprPlain(field.receiver);
        return try self.cloneExprValueDemandingKnownValue(try self.addExpr(.{ .ty = ty, .data = .{ .field_access = .{
            .receiver = receiver_expr,
            .field = field.field,
        } } }));
    }

    fn cloneTupleAccessValueWithDemand(self: *Cloner, ty: Type.TypeId, access: anytype, demand: ValueDemand) LowerError!Value {
        const receiver_demand = try self.pass.demandTupleItem(access.elem_index, demand);
        const receiver = try self.cloneExprValueWithDemand(access.tuple, receiver_demand);
        if (try self.itemFromKnownValue(receiver, access.elem_index)) |value| return try self.applyValueDemand(value, demand);
        if (try self.itemFromPatternValueDemanded(receiver, access.elem_index, ty, demand)) |value| return value;
        const receiver_expr = if (self.valueCanMaterializePublic(receiver))
            try self.materialize(receiver)
        else
            try self.cloneExprPlain(access.tuple);
        return try self.cloneExprValueDemandingKnownValue(try self.addExpr(.{ .ty = ty, .data = .{ .tuple_access = .{
            .tuple = receiver_expr,
            .elem_index = access.elem_index,
        } } }));
    }

    fn cloneTagValueWithDemand(
        self: *Cloner,
        ty: Type.TypeId,
        tag: anytype,
        demand: ValueDemand,
    ) LowerError!Value {
        const tag_demand = switch (demand) {
            .tag => |tag_demand| tag_demand,
            else => return try self.cloneExprValueDemandingKnownValue(try self.addExpr(.{ .ty = ty, .data = .{
                .tag = tag,
            } })),
        };

        const source_payloads = try self.pass.allocator.dupe(Ast.ExprId, self.pass.program.exprSpan(tag.payloads));
        defer self.pass.allocator.free(source_payloads);
        const alternative_demand = tagAlternativeDemandByName(self.pass.program, tag_demand.alternatives, tag.name);

        for (source_payloads, 0..) |payload, index| {
            if (alternative_demand != null and itemDemandByIndex(alternative_demand.?.payloads, @intCast(index)) != null) {
                const payload_demand = itemDemandByIndex(alternative_demand.?.payloads, @intCast(index)).?;
                if (payload_demand.demand.* != .none) continue;
            }
            if (!try discardedExprIsEffectFree(self.pass.program, self.pass.allocator, payload)) {
                return try self.cloneExprValueDemandingKnownValue(try self.addExpr(.{ .ty = ty, .data = .{
                    .tag = tag,
                } }));
            }
        }

        var pending_lets = std.ArrayList(PendingLet).empty;
        defer pending_lets.deinit(self.pass.allocator);

        var payloads = std.ArrayList(PrivateStateIndexedValue).empty;
        defer payloads.deinit(self.pass.allocator);
        for (source_payloads, 0..) |payload, index| {
            const explicit_demand = if (alternative_demand != null and itemDemandByIndex(alternative_demand.?.payloads, @intCast(index)) != null)
                itemDemandByIndex(alternative_demand.?.payloads, @intCast(index)).?.demand.*
            else
                ValueDemand.none;
            const payload_value = if (explicit_demand == .none)
                try self.cloneExprValueDemandingKnownValue(payload)
            else
                try self.cloneExprValueWithDemand(payload, explicit_demand);
            const payload_demand = try self.mergeValueDemand(explicit_demand, try self.finiteStateIdentityDemandFromValue(payload_value));
            if (payload_demand == .none) continue;
            const payload_private_state = (try self.privateStateValueFromValueDemandOrLeafCollectingLets(payload_value, payload_demand, &pending_lets)) orelse
                return try self.cloneExprValueDemandingKnownValue(try self.addExpr(.{ .ty = ty, .data = .{
                    .tag = tag,
                } }));
            try payloads.append(self.pass.allocator, .{
                .index = @intCast(index),
                .value = payload_private_state,
            });
        }

        return try self.wrapPendingLets(.{ .private_state = .{ .tag = .{
            .ty = ty,
            .name = tag.name,
            .payloads = try self.pass.arena.allocator().dupe(PrivateStateIndexedValue, payloads.items),
        } } }, pending_lets.items, true);
    }

    fn cloneRecordValueWithDemand(
        self: *Cloner,
        ty: Type.TypeId,
        fields_span: Ast.Span(Ast.FieldExpr),
        demand: ValueDemand,
    ) LowerError!Value {
        const field_demands = switch (demand) {
            .record => |field_demands| field_demands,
            else => return try self.cloneExprValueDemandingKnownValue(try self.addExpr(.{ .ty = ty, .data = .{
                .record = fields_span,
            } })),
        };

        const source_fields = try self.pass.allocator.dupe(Ast.FieldExpr, self.pass.program.fieldExprSpan(fields_span));
        defer self.pass.allocator.free(source_fields);

        for (source_fields) |field| {
            if (fieldDemandByName(self.pass.program, field_demands, field.name) != null) continue;
            if (!try discardedExprIsEffectFree(self.pass.program, self.pass.allocator, field.value)) {
                return try self.cloneExprValueDemandingKnownValue(try self.addExpr(.{ .ty = ty, .data = .{
                    .record = fields_span,
                } }));
            }
        }

        var pending_lets = std.ArrayList(PendingLet).empty;
        defer pending_lets.deinit(self.pass.allocator);

        var fields = std.ArrayList(PrivateStateField).empty;
        defer fields.deinit(self.pass.allocator);
        for (source_fields) |field| {
            const field_demand = fieldDemandByName(self.pass.program, field_demands, field.name) orelse continue;
            if (field_demand.demand.* == .none) continue;
            const field_value = try self.cloneExprValueWithDemand(field.value, field_demand.demand.*);
            const field_private_state = (try self.privateStateValueFromValueDemandOrLeafCollectingLets(field_value, field_demand.demand.*, &pending_lets)) orelse {
                return try self.cloneExprValueDemandingKnownValue(try self.addExpr(.{ .ty = ty, .data = .{
                    .record = fields_span,
                } }));
            };
            try fields.append(self.pass.allocator, .{
                .name = field.name,
                .value = field_private_state,
            });
        }

        return try self.wrapPendingLets(.{ .private_state = .{ .record = .{
            .ty = ty,
            .fields = try self.pass.arena.allocator().dupe(PrivateStateField, fields.items),
        } } }, pending_lets.items, true);
    }

    fn cloneLetValueWithDemand(self: *Cloner, let_: anytype, demand: ValueDemand) LowerError!Value {
        var value_demand = try self.patternDemandInExpr(let_.bind, let_.rest, demand);
        const raw_value = try self.cloneBindingValueWithExpandedDemand(let_.value, &value_demand);
        var pending_lets = std.ArrayList(PendingLet).empty;
        defer pending_lets.deinit(self.pass.allocator);

        const pending_change_start = self.changes.items.len;
        var value = raw_value;
        while (value == .let_) {
            try pending_lets.appendSlice(self.pass.allocator, value.let_.lets);
            value = value.let_.body.*;
        }

        {
            const base_pending_start = self.activePendingLetsLen();
            const base_scoped_start = try self.pushPendingLetScope(pending_lets.items);
            defer self.popPendingLetScope(base_scoped_start, base_pending_start);

            const reusable_pending_start = pending_lets.items.len;
            if (try self.tryMakeReusableForMatch(value, &pending_lets)) |reusable| {
                const reusable_active_start = self.activePendingLetsLen();
                const reusable_scoped_start = try self.pushPendingLetScope(pending_lets.items[reusable_pending_start..]);
                defer self.popPendingLetScope(reusable_scoped_start, reusable_active_start);

                const bind_change_start = self.changes.items.len;
                if (try self.bindPatToReusableValue(let_.bind, reusable)) {
                    const rest = try self.cloneExprValueWithDemand(let_.rest, demand);
                    self.restore(pending_change_start);
                    return try self.wrapPendingLets(rest, pending_lets.items, demand != .none);
                }
                self.restore(bind_change_start);
                pending_lets.shrinkRetainingCapacity(reusable_pending_start);
            }

            const bind_change_start = self.changes.items.len;
            if (try self.bindPatToSingleUseRestValue(let_.bind, value, let_.rest)) {
                const rest = try self.cloneExprValueWithDemand(let_.rest, demand);
                self.restore(pending_change_start);
                return try self.wrapPendingLets(rest, pending_lets.items, demand != .none);
            }
            self.restore(bind_change_start);

            const demanded_change_start = self.changes.items.len;
            if (try self.bindPatToDemandedValue(let_.bind, value, value_demand)) {
                const rest = try self.cloneExprValueWithDemand(let_.rest, demand);
                self.restore(pending_change_start);
                return try self.wrapPendingLets(rest, pending_lets.items, demand != .none);
            }
            self.restore(demanded_change_start);
        }
        self.restore(pending_change_start);

        const value_expr = try self.materialize(raw_value);
        // The emitted let expression binds these locals for the rest being
        // cloned; the scope is restored once the rest is built.
        const let_scoped_start = self.scopedLocalsLen();
        defer self.restoreScopedLocals(let_scoped_start);
        try self.appendPatternScopedLocals(let_.bind);
        const change_start = self.changes.items.len;
        if (try self.bindPatToMaterializedKnownValue(let_.bind, raw_value)) {
            const rest_value = try self.cloneExprValueWithDemand(let_.rest, demand);
            const rest = try self.materialize(rest_value);
            self.restore(change_start);
            return .{ .expr = try self.addExpr(.{ .ty = self.pass.program.exprs.items[@intFromEnum(let_.rest)].ty, .data = .{ .let_ = .{
                .bind = try self.clonePat(let_.bind),
                .value = value_expr,
                .rest = rest,
                .comptime_site = let_.comptime_site,
            } } }) };
        }
        self.restore(change_start);
        return .{ .expr = try self.addExpr(.{ .ty = self.pass.program.exprs.items[@intFromEnum(let_.rest)].ty, .data = .{ .let_ = .{
            .bind = try self.clonePat(let_.bind),
            .value = value_expr,
            .rest = try self.cloneExpr(let_.rest),
            .comptime_site = let_.comptime_site,
        } } }) };
    }

    fn cloneBlockValueWithDemand(self: *Cloner, ty: Type.TypeId, block: anytype, demand: ValueDemand) LowerError!Value {
        const change_start = self.changes.items.len;
        defer self.restore(change_start);
        const scoped_start = self.scopedLocalsLen();
        defer self.restoreScopedLocals(scoped_start);
        const provenance_start = self.loopProvenanceLen();
        defer self.restoreLoopProvenance(provenance_start);

        const source = try self.pass.allocator.dupe(Ast.StmtId, self.pass.program.stmtSpan(block.statements));
        defer self.pass.allocator.free(source);

        var statements = std.ArrayList(Ast.StmtId).empty;
        defer statements.deinit(self.pass.allocator);
        for (source, 0..) |stmt, index| {
            try self.cloneStmtInto(stmt, &statements, .{
                .statements = source[index + 1 ..],
                .final_expr = block.final_expr,
            }, demand);
        }

        const final_value = try self.cloneExprValueWithDemand(block.final_expr, demand);
        if (statements.items.len == 0) return final_value;

        var pending_lets = std.ArrayList(PendingLet).empty;
        defer pending_lets.deinit(self.pass.allocator);
        if (try self.appendPendingLetsFromStatements(statements.items, &pending_lets)) {
            return try self.wrapPendingLets(final_value, pending_lets.items, demand != .none);
        }

        const final_expr = try self.materialize(final_value);
        return .{ .expr = try self.addExpr(.{ .ty = ty, .data = .{ .block = .{
            .statements = try self.pass.program.addStmtSpan(statements.items),
            .final_expr = final_expr,
        } } }) };
    }

    fn cloneIfValueWithDemand(self: *Cloner, ty: Type.TypeId, if_: anytype, demand: ValueDemand) LowerError!Value {
        const source_branches = try self.pass.allocator.dupe(Ast.IfBranch, self.pass.program.ifBranchSpan(if_.branches));
        defer self.pass.allocator.free(source_branches);

        return try self.cloneIfValueWithDemandFromBranches(ty, source_branches, 0, if_.final_else, demand);
    }

    fn cloneIfValueWithDemandFromBranches(
        self: *Cloner,
        ty: Type.TypeId,
        source_branches: []const Ast.IfBranch,
        index: usize,
        final_else_expr: Ast.ExprId,
        demand: ValueDemand,
    ) LowerError!Value {
        if (index == source_branches.len) {
            return try self.cloneExprValueWithDemand(final_else_expr, demand);
        }

        const branch = source_branches[index];
        const cond_value = try self.cloneExprValueDemandingKnownValue(branch.cond);
        if (knownIfConditionBoolTag(self.pass.program, cond_value)) |cond| {
            if (cond) return try self.cloneScopedExprValueWithDemand(branch.body, demand);
            return try self.cloneIfValueWithDemandFromBranches(ty, source_branches, index + 1, final_else_expr, demand);
        }
        if (finiteBoolTagsValue(self.pass.program, cond_value)) |finite_bool| {
            const true_value = try self.cloneScopedExprValueWithDemand(branch.body, demand);
            const false_value = try self.cloneIfValueWithDemandFromBranches(ty, source_branches, index + 1, final_else_expr, demand);
            return try self.selectFiniteBoolValue(ty, finite_bool, true_value, false_value);
        }

        const branches = try self.pass.arena.allocator().alloc(IfValueBranch, 1);
        const branch_body_value = try self.cloneScopedExprValueWithDemand(branch.body, demand);
        const active_pending_lets = try self.snapshotActivePendingLets();
        const active_scoped_locals = try self.snapshotScopedLocals();
        const active_bindings = try self.snapshotSubstBindings();
        branches[0] = .{
            .cond = try self.materialize(cond_value),
            .body = branch_body_value,
            .source_body = .{
                .expr = branch.body,
                .pending_lets = active_pending_lets,
                .scoped_locals = active_scoped_locals,
                .bindings = active_bindings,
            },
        };
        const final_else = try self.pass.arena.allocator().create(Value);
        final_else.* = try self.cloneIfValueWithDemandFromBranches(ty, source_branches, index + 1, final_else_expr, demand);
        return .{ .if_ = .{
            .ty = ty,
            .branches = branches,
            .final_else = final_else,
            .final_else_source = if (index + 1 == source_branches.len) .{
                .expr = final_else_expr,
                .pending_lets = active_pending_lets,
                .scoped_locals = active_scoped_locals,
                .bindings = active_bindings,
            } else null,
        } };
    }

    fn cloneScopedExprValueWithDemand(self: *Cloner, expr_id: Ast.ExprId, demand: ValueDemand) LowerError!Value {
        const change_start = self.changes.items.len;
        const value = try self.cloneExprValueWithDemand(expr_id, demand);
        self.restore(change_start);
        return value;
    }

    fn ensureDemandedKnownValue(self: *Cloner, value: Value) LowerError!Value {
        if ((try self.pass.knownValueFromValue(value)) != null) return value;
        return switch (value) {
            .expr => |expr| blk: {
                const ty = self.pass.program.exprs.items[@intFromEnum(expr)].ty;
                if (try typeMayContainRefcounted(self.pass.program, ty)) break :blk value;
                break :blk Value{ .expr_with_known_value = .{
                    .expr = expr,
                    .known_value = .{ .leaf = ty },
                } };
            },
            .let_ => |let_value| blk: {
                const body = try self.ensureDemandedKnownValue(let_value.body.*);
                break :blk Value{ .let_ = .{
                    .lets = let_value.lets,
                    .body = try self.copyValue(body),
                } };
            },
            else => value,
        };
    }

    fn directCallHasKnownValueArg(self: *Cloner, args_span: Ast.Span(Ast.ExprId)) Allocator.Error!bool {
        for (self.pass.program.exprSpan(args_span)) |arg| {
            if (try self.exprHasKnownValue(arg)) return true;
        }
        return false;
    }

    fn directCallMayInline(self: *Cloner, callee: Ast.FnId, args_span: Ast.Span(Ast.ExprId)) Allocator.Error!bool {
        if (!self.inline_direct_requires_known_arg) return true;
        if (self.pass.inlineBody(callee) != null) return true;
        return try self.directCallHasKnownValueArg(args_span);
    }

    fn directCallMayInlineForMaterialization(self: *Cloner, callee: Ast.FnId, args_span: Ast.Span(Ast.ExprId)) Allocator.Error!bool {
        if (!self.inline_direct_requires_known_arg) return true;
        if (self.pass.materializeInlineBody(callee) != null) return true;
        return try self.directCallHasKnownValueArg(args_span);
    }

    fn directCallActiveArgs(self: *Cloner, args_span: Ast.Span(Ast.ExprId)) Allocator.Error![]const ActiveInlineArg {
        const args = self.pass.program.exprSpan(args_span);
        const active_args = try self.pass.arena.allocator().alloc(ActiveInlineArg, args.len);
        for (args, 0..) |arg, index| {
            active_args[index] = try self.directCallActiveArg(arg);
        }
        return active_args;
    }

    fn directCallActiveArg(self: *Cloner, arg: Ast.ExprId) Allocator.Error!ActiveInlineArg {
        if (try self.exprSubstitutedValueNoInline(arg)) |value| {
            if (value == .private_state) {
                return .{ .private_state = value.private_state };
            }
            if (try self.pass.knownValueFromValue(value)) |known_value| {
                return .{ .known = known_value };
            }
        }

        return .{ .known = (try self.exprKnownValueNoInline(arg)) orelse .{
            .any = self.pass.program.exprs.items[@intFromEnum(arg)].ty,
        } };
    }

    fn directCallActiveArgsFromValues(self: *Cloner, values: []const Value) LowerError![]const ActiveInlineArg {
        const active_args = try self.pass.arena.allocator().alloc(ActiveInlineArg, values.len);
        for (values, 0..) |value, index| {
            active_args[index] = try self.directCallActiveArgFromValue(value);
        }
        return active_args;
    }

    fn directCallActiveAliasesFromValues(
        self: *Cloner,
        source_args: []const Ast.TypedLocal,
        arg_exprs: []const Ast.ExprId,
        values: []const Value,
    ) LowerError![]const ActiveInlineAlias {
        if (source_args.len != values.len) Common.invariant("active alias arity differed from direct call arity");
        if (arg_exprs.len != values.len) Common.invariant("active alias expression arity differed from direct call arity");

        var aliases = std.ArrayList(ActiveInlineAlias).empty;
        defer aliases.deinit(self.pass.allocator);
        for (source_args, arg_exprs, values) |source_arg, arg_expr, value| {
            const active_arg = try self.directCallActiveArgFromValue(value);
            try aliases.append(self.pass.allocator, .{
                .local = source_arg.local,
                .value = active_arg,
            });
            if (localExpr(self.pass.program, arg_expr)) |arg_local| {
                if (arg_local != source_arg.local) {
                    try aliases.append(self.pass.allocator, .{
                        .local = arg_local,
                        .value = active_arg,
                    });
                }
            }
        }
        return try self.pass.arena.allocator().dupe(ActiveInlineAlias, aliases.items);
    }

    fn directCallActiveArgFromValue(self: *Cloner, value: Value) LowerError!ActiveInlineArg {
        if (value == .expr) {
            var seen = std.ArrayList(Ast.ExprId).empty;
            defer seen.deinit(self.pass.allocator);
            if (try self.substitutedExprValueAvoidingCycles(value.expr, &seen)) |substituted| {
                if (!valueIsExpr(substituted, value.expr)) return try self.directCallActiveArgFromValue(substituted);
            }
        }
        if (value == .expr_with_known_value) {
            if (value.expr_with_known_value.value) |structured| {
                return try self.directCallActiveArgFromValue(structured.*);
            }
            if (try self.substitutedKnownExprValue(value.expr_with_known_value)) |substituted| {
                return try self.directCallActiveArgFromValue(substituted);
            }
        }
        return switch (value) {
            .let_ => |let_value| try self.directCallActiveArgFromValue(let_value.body.*),
            .private_state => |private_state| .{ .private_state = try self.normalizedPrivateStateValue(private_state) },
            else => if (try self.pass.knownValueFromValue(value)) |known_value|
                .{ .known = known_value }
            else
                .{ .known = .{ .any = valueType(self.pass.program, value) } },
        };
    }

    fn exprKnownValueNoInline(self: *Cloner, expr_id: Ast.ExprId) Allocator.Error!?KnownValue {
        if (try self.exprSubstitutedValueNoInline(expr_id)) |value| {
            if (try self.pass.knownValueFromValue(value)) |known_value| return known_value;
        }

        const expr = self.pass.program.exprs.items[@intFromEnum(expr_id)];
        return switch (expr.data) {
            .local => null,
            .fn_ref => |fn_id| try self.knownCallable(expr.ty, fn_id),
            .fn_ref_captures => |fn_ref| try self.knownCallableWithCaptureExprs(
                expr.ty,
                fn_ref.target,
                self.pass.program.exprSpan(fn_ref.captures),
            ),
            .tag,
            .record,
            .tuple,
            .nominal,
            .unit,
            .int_lit,
            .frac_f32_lit,
            .frac_f64_lit,
            .dec_lit,
            .str_lit,
            .static_data,
            .list,
            => try self.pass.constructorKnownValue(expr_id),
            .comptime_branch_taken => |taken| try self.exprKnownValueNoInline(taken.body),
            else => null,
        };
    }

    fn exprSubstitutedValueNoInline(self: *Cloner, expr_id: Ast.ExprId) Allocator.Error!?Value {
        const expr = self.pass.program.exprs.items[@intFromEnum(expr_id)];
        return switch (expr.data) {
            .local => |local| self.subst.get(local),
            .field_access => |field| blk: {
                const receiver = (try self.exprSubstitutedValueNoInline(field.receiver)) orelse break :blk null;
                break :blk fieldFromValue(self.pass.program, receiver, field.field);
            },
            .tuple_access => |access| blk: {
                const tuple = (try self.exprSubstitutedValueNoInline(access.tuple)) orelse break :blk null;
                break :blk itemFromValue(tuple, access.elem_index);
            },
            .comptime_branch_taken => |taken| try self.exprSubstitutedValueNoInline(taken.body),
            else => null,
        };
    }

    fn exprValueForDemandNoInline(self: *Cloner, expr_id: Ast.ExprId) Allocator.Error!Value {
        if (try self.exprSubstitutedValueNoInline(expr_id)) |value| return value;
        if (try self.exprKnownValueNoInline(expr_id)) |known_value| {
            return .{ .expr_with_known_value = .{
                .expr = expr_id,
                .known_value = known_value,
            } };
        }
        return .{ .expr = expr_id };
    }

    fn exprValueForDirectCallBoundaryArg(self: *Cloner, expr_id: Ast.ExprId) LowerError!Value {
        const expr = self.pass.program.exprs.items[@intFromEnum(expr_id)];
        switch (expr.data) {
            .call_proc => |call| {
                if (!call.is_cold and self.inline_direct_calls) {
                    const callee = Ast.callProcCallee(call);
                    if (self.pass.materializeInlineBody(callee) != null) {
                        return try self.inlineDirectCallValueWithDemand(callee, call.args, expr_id, .materialize);
                    }
                }
            },
            .comptime_branch_taken => |taken| return try self.exprValueForDirectCallBoundaryArg(taken.body),
            else => {},
        }
        return try self.exprValueForDemandNoInline(expr_id);
    }

    fn exprValueForDemandNoInlineProtectingLocal(
        self: *Cloner,
        expr_id: Ast.ExprId,
        protected_local: Ast.LocalId,
    ) Allocator.Error!Value {
        if (localUseCountInExpr(self.pass.program, protected_local, expr_id) != 0) {
            return .{ .expr = expr_id };
        }
        return try self.exprValueForDemandNoInline(expr_id);
    }

    fn demandStackContains(self: *Cloner, fn_id: Ast.FnId) bool {
        for (self.demand_stack.items) |active| {
            if (active.fn_id == fn_id) return true;
        }
        return false;
    }

    fn exprHasKnownValue(self: *Cloner, expr_id: Ast.ExprId) Allocator.Error!bool {
        const expr = self.pass.program.exprs.items[@intFromEnum(expr_id)];
        return switch (expr.data) {
            .local => |local| if (self.subst.get(local)) |value|
                (try self.knownValueFromValueAllowingSparsePrivateState(value)) != null
            else
                false,
            .fn_ref => true,
            .fn_ref_captures => true,
            .tag,
            .record,
            .tuple,
            .nominal,
            .unit,
            .int_lit,
            .frac_f32_lit,
            .frac_f64_lit,
            .dec_lit,
            .str_lit,
            .static_data,
            .list,
            => (try self.pass.constructorKnownValue(expr_id)) != null,
            .static_data_candidate => true,
            .field_access => |field| blk: {
                const receiver_local = localExpr(self.pass.program, field.receiver) orelse break :blk false;
                const receiver = self.subst.get(receiver_local) orelse break :blk false;
                const value = fieldFromValue(self.pass.program, receiver, field.field) orelse break :blk false;
                break :blk (try self.pass.knownValueFromValue(value)) != null;
            },
            .tuple_access => |access| blk: {
                const tuple_local = localExpr(self.pass.program, access.tuple) orelse break :blk false;
                const tuple = self.subst.get(tuple_local) orelse break :blk false;
                const value = itemFromValue(tuple, access.elem_index) orelse break :blk false;
                break :blk (try self.pass.knownValueFromValue(value)) != null;
            },
            .comptime_branch_taken => |taken| try self.exprHasKnownValue(taken.body),
            .comptime_exhaustiveness_failed => false,
            else => false,
        };
    }

    fn valueCanSubstitute(self: *Cloner, value: Value) bool {
        return switch (value) {
            .expr => |expr| self.exprCanSubstitute(expr),
            .let_ => false,
            .if_ => |if_value| blk: {
                for (if_value.branches) |branch| {
                    if (!self.exprCanSubstitute(branch.cond) or !self.valueCanSubstitute(branch.body)) break :blk false;
                }
                break :blk self.valueCanSubstitute(if_value.final_else.*);
            },
            .match_ => |match_value| blk: {
                if (!self.exprCanSubstitute(match_value.scrutinee)) break :blk false;
                for (match_value.branches) |branch| {
                    if (branch.guard) |guard| {
                        if (!self.exprCanSubstitute(guard)) break :blk false;
                    }
                    if (!self.valueCanSubstitute(branch.body)) break :blk false;
                }
                break :blk true;
            },
            .tag => |tag| blk: {
                for (tag.payloads) |payload| {
                    if (!self.valueCanSubstitute(payload)) break :blk false;
                }
                break :blk true;
            },
            .record => |record| blk: {
                for (record.fields) |field| {
                    if (!self.valueCanSubstitute(field.value)) break :blk false;
                }
                break :blk true;
            },
            .tuple => |tuple| blk: {
                for (tuple.items) |item| {
                    if (!self.valueCanSubstitute(item)) break :blk false;
                }
                break :blk true;
            },
            .nominal => |nominal| self.valueCanSubstitute(nominal.backing.*),
            .callable => |callable| blk: {
                for (callable.captures) |capture| {
                    if (!self.valueCanSubstitute(capture)) break :blk false;
                }
                break :blk true;
            },
            .finite_tags => |finite_tags| blk: {
                if (!self.exprCanSubstitute(finite_tags.selector)) break :blk false;
                for (finite_tags.alternatives) |alternative| {
                    for (alternative.payloads) |payload| {
                        if (!self.valueCanSubstitute(payload)) break :blk false;
                    }
                }
                break :blk true;
            },
            .finite_callables => |finite_callables| blk: {
                if (!self.exprCanSubstitute(finite_callables.selector)) break :blk false;
                for (finite_callables.alternatives) |alternative| {
                    for (alternative.captures) |capture| {
                        if (!self.valueCanSubstitute(capture)) break :blk false;
                    }
                }
                break :blk true;
            },
            .expr_with_known_value => |known_value_expr| self.exprCanSubstitute(known_value_expr.expr),
            .private_state => |private_state| self.privateStateCanSubstitute(private_state),
        };
    }

    fn privateStateCanSubstitute(self: *Cloner, value: PrivateStateValue) bool {
        return switch (value) {
            .leaf => |leaf| self.exprCanSubstitute(leaf.expr),
            .tag => |tag| blk: {
                for (tag.payloads) |payload| {
                    if (!self.privateStateCanSubstitute(payload.value)) break :blk false;
                }
                break :blk true;
            },
            .record => |record| blk: {
                for (record.fields) |field| {
                    if (!self.privateStateCanSubstitute(field.value)) break :blk false;
                }
                break :blk true;
            },
            .tuple => |tuple| blk: {
                for (tuple.items) |item| {
                    if (!self.privateStateCanSubstitute(item.value)) break :blk false;
                }
                break :blk true;
            },
            .nominal => |nominal| if (nominal.backing) |backing| self.privateStateCanSubstitute(backing.*) else true,
            .callable => |callable| blk: {
                for (callable.captures) |capture| {
                    if (!self.privateStateCanSubstitute(capture.value)) break :blk false;
                }
                break :blk true;
            },
            .compact_finite_tags => |finite_tags| self.exprCanSubstitute(finite_tags.compact_expr),
            .compact_finite_callables => |finite_callables| self.exprCanSubstitute(finite_callables.compact_expr),
        };
    }

    fn valueCanBeMadeReusableForMatch(self: *Cloner, value: Value) bool {
        if (self.valueCanSubstitute(value)) return true;
        return switch (value) {
            .expr => |expr| self.exprCanBeMadeReusableForMatch(expr),
            .expr_with_known_value => |known| self.exprCanBeMadeReusableForMatch(known.expr),
            .let_ => |let_value| blk: {
                for (let_value.lets) |pending| {
                    if (!self.pendingLetCanBeMadeReusableForMatch(pending)) break :blk false;
                }
                break :blk self.valueCanBeMadeReusableForMatch(let_value.body.*);
            },
            .if_ => |if_value| blk: {
                for (if_value.branches) |branch| {
                    if (!self.exprCanBeMadeReusableForMatch(branch.cond)) break :blk false;
                    if (!self.valueCanBeMadeReusableForMatch(branch.body)) break :blk false;
                }
                break :blk self.valueCanBeMadeReusableForMatch(if_value.final_else.*);
            },
            .match_ => |match_value| blk: {
                if (!self.exprCanBeMadeReusableForMatch(match_value.scrutinee)) break :blk false;
                for (match_value.branches) |branch| {
                    if (branch.guard) |guard| {
                        if (!self.exprCanBeMadeReusableForMatch(guard)) break :blk false;
                    }
                    if (!self.valueCanBeMadeReusableForMatch(branch.body)) break :blk false;
                }
                break :blk true;
            },
            .tag => |tag| blk: {
                for (tag.payloads) |payload| {
                    if (!self.valueCanBeMadeReusableForMatch(payload)) break :blk false;
                }
                break :blk true;
            },
            .record => |record| blk: {
                for (record.fields) |field| {
                    if (!self.valueCanBeMadeReusableForMatch(field.value)) break :blk false;
                }
                break :blk true;
            },
            .tuple => |tuple| blk: {
                for (tuple.items) |item| {
                    if (!self.valueCanBeMadeReusableForMatch(item)) break :blk false;
                }
                break :blk true;
            },
            .nominal => |nominal| self.valueCanBeMadeReusableForMatch(nominal.backing.*),
            .callable => |callable| blk: {
                for (callable.captures) |capture| {
                    if (!self.valueCanBeMadeReusableForMatch(capture)) break :blk false;
                }
                break :blk true;
            },
            .finite_tags => |finite_tags| blk: {
                if (!self.exprCanBeMadeReusableForMatch(finite_tags.selector)) break :blk false;
                for (finite_tags.alternatives) |alternative| {
                    for (alternative.payloads) |payload| {
                        if (!self.valueCanBeMadeReusableForMatch(payload)) break :blk false;
                    }
                }
                break :blk true;
            },
            .finite_callables => |finite_callables| blk: {
                if (!self.exprCanBeMadeReusableForMatch(finite_callables.selector)) break :blk false;
                for (finite_callables.alternatives) |alternative| {
                    for (alternative.captures) |capture| {
                        if (!self.valueCanBeMadeReusableForMatch(capture)) break :blk false;
                    }
                }
                break :blk true;
            },
            .private_state => |private_state| self.privateStateCanBeMadeReusableForMatch(private_state),
        };
    }

    fn exprCanBeMadeReusableForMatch(self: *Cloner, expr: Ast.ExprId) bool {
        if (self.exprCanSubstitute(expr)) return true;
        if (self.exprReferencesAvailableBindings(expr)) return true;
        return switch (self.pass.program.exprs.items[@intFromEnum(expr)].data) {
            .local => |local| if (self.subst.get(local)) |value|
                self.valueCanBeMadeReusableForMatch(value)
            else
                false,
            .field_access => |field| self.exprCanBeMadeReusableForMatch(field.receiver),
            .tuple_access => |access| self.exprCanBeMadeReusableForMatch(access.tuple),
            .comptime_branch_taken => |taken| self.exprCanBeMadeReusableForMatch(taken.body),
            else => false,
        };
    }

    fn privateStateCanBeMadeReusableForMatch(self: *Cloner, value: PrivateStateValue) bool {
        return switch (value) {
            .leaf => |leaf| self.exprCanBeMadeReusableForMatch(leaf.expr),
            .tag => |tag| blk: {
                for (tag.payloads) |payload| {
                    if (!self.privateStateCanBeMadeReusableForMatch(payload.value)) break :blk false;
                }
                break :blk true;
            },
            .record => |record| blk: {
                for (record.fields) |field| {
                    if (!self.privateStateCanBeMadeReusableForMatch(field.value)) break :blk false;
                }
                break :blk true;
            },
            .tuple => |tuple| blk: {
                for (tuple.items) |item| {
                    if (!self.privateStateCanBeMadeReusableForMatch(item.value)) break :blk false;
                }
                break :blk true;
            },
            .nominal => |nominal| if (nominal.backing) |backing|
                self.privateStateCanBeMadeReusableForMatch(backing.*)
            else
                true,
            .callable => |callable| blk: {
                for (callable.captures) |capture| {
                    if (!self.privateStateCanBeMadeReusableForMatch(capture.value)) break :blk false;
                }
                break :blk true;
            },
            .compact_finite_tags => |finite_tags| self.exprCanBeMadeReusableForMatch(finite_tags.compact_expr),
            .compact_finite_callables => |finite_callables| self.exprCanBeMadeReusableForMatch(finite_callables.compact_expr),
        };
    }

    fn pendingLetCanBeMadeReusableForMatch(self: *Cloner, pending: PendingLet) bool {
        return switch (pending.value) {
            .source => |expr| self.exprCanBeMadeReusableForMatch(expr),
            .cloned => |expr| self.exprCanBeMadeReusableForMatch(expr),
        };
    }

    fn valueContainsEscapingControlTransfer(self: *Cloner, value: Value) bool {
        return switch (value) {
            .expr => |expr| exprContainsEscapingControlTransfer(self.pass.program, expr),
            .expr_with_known_value => |known_value_expr| exprContainsEscapingControlTransfer(self.pass.program, known_value_expr.expr),
            .let_ => |let_value| blk: {
                for (let_value.lets) |pending| {
                    if (pendingLetValueContainsEscapingControlTransfer(self.pass.program, pending.value)) break :blk true;
                }
                break :blk self.valueContainsEscapingControlTransfer(let_value.body.*);
            },
            .if_ => |if_value| blk: {
                for (if_value.branches) |branch| {
                    if (exprContainsEscapingControlTransfer(self.pass.program, branch.cond) or
                        self.valueContainsEscapingControlTransfer(branch.body))
                    {
                        break :blk true;
                    }
                }
                break :blk self.valueContainsEscapingControlTransfer(if_value.final_else.*);
            },
            .match_ => |match_value| blk: {
                if (exprContainsEscapingControlTransfer(self.pass.program, match_value.scrutinee)) break :blk true;
                for (match_value.branches) |branch| {
                    if (branch.guard) |guard| {
                        if (exprContainsEscapingControlTransfer(self.pass.program, guard)) break :blk true;
                    }
                    if (self.valueContainsEscapingControlTransfer(branch.body)) break :blk true;
                }
                break :blk false;
            },
            .tag => |tag| blk: {
                for (tag.payloads) |payload| {
                    if (self.valueContainsEscapingControlTransfer(payload)) break :blk true;
                }
                break :blk false;
            },
            .record => |record| blk: {
                for (record.fields) |field| {
                    if (self.valueContainsEscapingControlTransfer(field.value)) break :blk true;
                }
                break :blk false;
            },
            .tuple => |tuple| blk: {
                for (tuple.items) |item| {
                    if (self.valueContainsEscapingControlTransfer(item)) break :blk true;
                }
                break :blk false;
            },
            .nominal => |nominal| self.valueContainsEscapingControlTransfer(nominal.backing.*),
            .callable => |callable| blk: {
                for (callable.captures) |capture| {
                    if (self.valueContainsEscapingControlTransfer(capture)) break :blk true;
                }
                break :blk false;
            },
            .finite_tags => |finite_tags| blk: {
                if (exprContainsEscapingControlTransfer(self.pass.program, finite_tags.selector)) break :blk true;
                for (finite_tags.alternatives) |alternative| {
                    for (alternative.payloads) |payload| {
                        if (self.valueContainsEscapingControlTransfer(payload)) break :blk true;
                    }
                }
                break :blk false;
            },
            .finite_callables => |finite_callables| blk: {
                if (exprContainsEscapingControlTransfer(self.pass.program, finite_callables.selector)) break :blk true;
                for (finite_callables.alternatives) |alternative| {
                    for (alternative.captures) |capture| {
                        if (self.valueContainsEscapingControlTransfer(capture)) break :blk true;
                    }
                }
                break :blk false;
            },
            .private_state => false,
        };
    }

    fn exprCanSubstitute(self: *Cloner, expr_id: Ast.ExprId) bool {
        return switch (self.pass.program.exprs.items[@intFromEnum(expr_id)].data) {
            .local => |local| self.localCanBeReferencedDirectly(local),
            .unit,
            .int_lit,
            .frac_f32_lit,
            .frac_f64_lit,
            .dec_lit,
            .str_lit,
            .static_data,
            .fn_ref,
            => true,
            .fn_ref_captures => |fn_ref| blk: {
                for (self.pass.program.exprSpan(fn_ref.captures)) |capture| {
                    if (!self.exprCanSubstitute(capture)) break :blk false;
                }
                break :blk true;
            },
            .field_access => |field| self.exprCanSubstitute(field.receiver),
            .tuple_access => |access| self.exprCanSubstitute(access.tuple),
            else => false,
        };
    }

    fn exprReferencesAvailableBindings(self: *Cloner, expr_id: Ast.ExprId) bool {
        return self.exprReferencesAvailableBindingsInScope(expr_id, null);
    }

    fn exprReferencesAvailableBindingsInScope(self: *Cloner, expr_id: Ast.ExprId, scope: ?*const AvailableBindingScope) bool {
        return switch (self.pass.program.exprs.items[@intFromEnum(expr_id)].data) {
            .local => |local| self.localBindingAvailableInScope(local, expr_id, scope),
            .unit,
            .int_lit,
            .frac_f32_lit,
            .frac_f64_lit,
            .dec_lit,
            .str_lit,
            .static_data,
            .fn_ref,
            .uninitialized,
            .uninitialized_payload,
            .comptime_exhaustiveness_failed,
            .crash,
            => true,
            .fn_ref_captures => |fn_ref| self.exprSpanReferencesAvailableBindingsInScope(fn_ref.captures, scope),
            .static_data_candidate => |candidate| self.exprReferencesAvailableBindingsInScope(candidate.restored_expr, scope),
            .field_access => |field| self.exprReferencesAvailableBindingsInScope(field.receiver, scope),
            .tuple_access => |access| self.exprReferencesAvailableBindingsInScope(access.tuple, scope),
            .list,
            .tuple,
            => |items| blk: {
                for (self.pass.program.exprSpan(items)) |item| {
                    if (!self.exprReferencesAvailableBindingsInScope(item, scope)) break :blk false;
                }
                break :blk true;
            },
            .record => |fields| blk: {
                for (self.pass.program.fieldExprSpan(fields)) |field| {
                    if (!self.exprReferencesAvailableBindingsInScope(field.value, scope)) break :blk false;
                }
                break :blk true;
            },
            .tag => |tag| blk: {
                for (self.pass.program.exprSpan(tag.payloads)) |payload| {
                    if (!self.exprReferencesAvailableBindingsInScope(payload, scope)) break :blk false;
                }
                break :blk true;
            },
            .nominal => |backing| self.exprReferencesAvailableBindingsInScope(backing, scope),
            .call_value => |call| blk: {
                if (!self.exprReferencesAvailableBindingsInScope(call.callee, scope)) break :blk false;
                for (self.pass.program.exprSpan(call.args)) |arg| {
                    if (!self.exprReferencesAvailableBindingsInScope(arg, scope)) break :blk false;
                }
                break :blk true;
            },
            .call_proc => |call| blk: {
                for (self.pass.program.exprSpan(call.args)) |arg| {
                    if (!self.exprReferencesAvailableBindingsInScope(arg, scope)) break :blk false;
                }
                break :blk true;
            },
            .low_level => |call| blk: {
                for (self.pass.program.exprSpan(call.args)) |arg| {
                    if (!self.exprReferencesAvailableBindingsInScope(arg, scope)) break :blk false;
                }
                break :blk true;
            },
            .structural_eq => |eq| self.exprReferencesAvailableBindingsInScope(eq.lhs, scope) and self.exprReferencesAvailableBindingsInScope(eq.rhs, scope),
            .structural_hash => |hash| self.exprReferencesAvailableBindingsInScope(hash.value, scope) and self.exprReferencesAvailableBindingsInScope(hash.hasher, scope),
            .comptime_branch_taken => |taken| self.exprReferencesAvailableBindingsInScope(taken.body, scope),
            .dbg,
            .expect,
            .return_,
            => |child| self.exprReferencesAvailableBindingsInScope(child, scope),
            .expect_err => |expect_err| self.exprReferencesAvailableBindingsInScope(expect_err.msg, scope),
            .break_ => |maybe| if (maybe) |value| self.exprReferencesAvailableBindingsInScope(value, scope) else true,
            .continue_ => |continue_| self.exprSpanReferencesAvailableBindingsInScope(continue_.values, scope),
            .state_continue => |continue_| self.exprSpanReferencesAvailableBindingsInScope(continue_.values, scope),
            .let_ => |let_| blk: {
                const rest_scope = AvailableBindingScope{
                    .binding = .{ .pat = let_.bind },
                    .parent = scope,
                };
                if (!self.exprReferencesAvailableBindingsInScope(let_.value, scope)) break :blk false;
                break :blk self.exprReferencesAvailableBindingsInScope(let_.rest, &rest_scope);
            },
            .block => |block| self.blockReferencesAvailableBindingsInScope(block, scope),
            .match_ => |match| blk: {
                if (!self.exprReferencesAvailableBindingsInScope(match.scrutinee, scope)) break :blk false;
                for (self.pass.program.branchSpan(match.branches)) |branch| {
                    const branch_scope = AvailableBindingScope{
                        .binding = .{ .pat = branch.pat },
                        .parent = scope,
                    };
                    if (branch.guard) |guard| {
                        if (!self.exprReferencesAvailableBindingsInScope(guard, &branch_scope)) break :blk false;
                    }
                    if (!self.exprReferencesAvailableBindingsInScope(branch.body, &branch_scope)) break :blk false;
                }
                break :blk true;
            },
            .if_ => |if_| blk: {
                for (self.pass.program.ifBranchSpan(if_.branches)) |branch| {
                    if (!self.exprReferencesAvailableBindingsInScope(branch.cond, scope)) break :blk false;
                    if (!self.exprReferencesAvailableBindingsInScope(branch.body, scope)) break :blk false;
                }
                break :blk self.exprReferencesAvailableBindingsInScope(if_.final_else, scope);
            },
            .loop_ => |loop| blk: {
                if (!self.exprSpanReferencesAvailableBindingsInScope(loop.initial_values, scope)) break :blk false;
                const body_scope = AvailableBindingScope{
                    .binding = .{ .typed_locals = self.pass.program.typedLocalSpan(loop.params) },
                    .parent = scope,
                };
                break :blk self.exprReferencesAvailableBindingsInScope(loop.body, &body_scope);
            },
            .state_loop => |state_loop| blk: {
                if (!self.exprSpanReferencesAvailableBindingsInScope(state_loop.entry_values, scope)) break :blk false;
                for (self.pass.program.stateLoopStateSpan(state_loop.states)) |state| {
                    const state_scope = AvailableBindingScope{
                        .binding = .{ .typed_locals = self.pass.program.typedLocalSpan(state.params) },
                        .parent = scope,
                    };
                    if (!self.exprReferencesAvailableBindingsInScope(state.body, &state_scope)) break :blk false;
                }
                break :blk true;
            },
            .if_initialized_payload => |payload_switch| blk: {
                if (!self.exprReferencesAvailableBindingsInScope(payload_switch.cond, scope)) break :blk false;
                const initialized_scope = AvailableBindingScope{
                    .binding = .{ .local = payload_switch.payload },
                    .parent = scope,
                };
                if (!self.exprReferencesAvailableBindingsInScope(payload_switch.initialized, &initialized_scope)) break :blk false;
                break :blk self.exprReferencesAvailableBindingsInScope(payload_switch.uninitialized, scope);
            },
            .try_sequence => |sequence| blk: {
                if (!self.exprReferencesAvailableBindingsInScope(sequence.try_expr, scope)) break :blk false;
                const ok_scope = AvailableBindingScope{
                    .binding = .{ .local = sequence.ok_local },
                    .parent = scope,
                };
                break :blk self.exprReferencesAvailableBindingsInScope(sequence.ok_body, &ok_scope);
            },
            .try_record_sequence => |sequence| blk: {
                if (!self.exprReferencesAvailableBindingsInScope(sequence.try_expr, scope)) break :blk false;
                const value_scope = AvailableBindingScope{
                    .binding = .{ .local = sequence.value_local },
                    .parent = scope,
                };
                const rest_scope = AvailableBindingScope{
                    .binding = .{ .local = sequence.rest_local },
                    .parent = &value_scope,
                };
                break :blk self.exprReferencesAvailableBindingsInScope(sequence.ok_body, &rest_scope);
            },
            .lambda,
            .def_ref,
            .fn_def,
            => false,
        };
    }

    fn exprSpanReferencesAvailableBindingsInScope(self: *Cloner, span: Ast.Span(Ast.ExprId), scope: ?*const AvailableBindingScope) bool {
        for (self.pass.program.exprSpan(span)) |expr| {
            if (!self.exprReferencesAvailableBindingsInScope(expr, scope)) return false;
        }
        return true;
    }

    fn blockReferencesAvailableBindingsInScope(self: *Cloner, block: anytype, scope: ?*const AvailableBindingScope) bool {
        const statements = self.pass.program.stmtSpan(block.statements);
        return self.blockTailReferencesAvailableBindingsInScope(statements, 0, block.final_expr, scope);
    }

    fn blockTailReferencesAvailableBindingsInScope(
        self: *Cloner,
        statements: []const Ast.StmtId,
        index: usize,
        final_expr: Ast.ExprId,
        scope: ?*const AvailableBindingScope,
    ) bool {
        if (index >= statements.len) return self.exprReferencesAvailableBindingsInScope(final_expr, scope);
        const stmt = self.pass.program.stmts.items[@intFromEnum(statements[index])];
        switch (stmt) {
            .uninitialized => |pat| {
                const next_scope = AvailableBindingScope{
                    .binding = .{ .pat = pat },
                    .parent = scope,
                };
                return self.blockTailReferencesAvailableBindingsInScope(statements, index + 1, final_expr, &next_scope);
            },
            .let_ => |let_| {
                const next_scope = AvailableBindingScope{
                    .binding = .{ .pat = let_.pat },
                    .parent = scope,
                };
                const value_scope = if (let_.recursive) &next_scope else scope;
                if (!self.exprReferencesAvailableBindingsInScope(let_.value, value_scope)) return false;
                return self.blockTailReferencesAvailableBindingsInScope(statements, index + 1, final_expr, &next_scope);
            },
            .expr,
            .expect,
            .dbg,
            .return_,
            => |expr| {
                if (!self.exprReferencesAvailableBindingsInScope(expr, scope)) return false;
                return self.blockTailReferencesAvailableBindingsInScope(statements, index + 1, final_expr, scope);
            },
            .crash => return self.blockTailReferencesAvailableBindingsInScope(statements, index + 1, final_expr, scope),
        }
    }

    fn localBindingAvailableInScope(self: *Cloner, local: Ast.LocalId, expr_id: Ast.ExprId, scope: ?*const AvailableBindingScope) bool {
        if (self.localBindingAvailableInLexicalScope(local, scope)) return true;
        if (self.subst.get(local)) |value| {
            if (valueIsExpr(value, expr_id)) return self.localCanBeReferencedDirectly(local);
            if (localAliasFromValue(self.pass.program, value)) |alias| {
                if (alias == local) return self.localCanBeReferencedDirectly(local);
            }
            return false;
        }
        return self.localCanBeReferencedDirectly(local);
    }

    fn localBindingAvailableInLexicalScope(self: *Cloner, local: Ast.LocalId, scope: ?*const AvailableBindingScope) bool {
        if (self.inline_safe_binding_check) {
            // An inline argument may be re-materialized wherever the inlined
            // body reaches a public boundary, so bindings that lapse with the
            // current region are not enough: only pending lets (re-emitted at
            // any consumer) qualify from the dynamic scope list.
            if (self.pendingLetIsActive(local)) return true;
        } else {
            for (self.scoped_locals.items) |scoped_local| {
                if (scoped_local == local) return true;
            }
        }
        for (self.loop_stack.items) |loop| {
            if (localInTypedLocalSpan(loop.params, local)) return true;
        }
        for (self.state_param_stack.items) |params| {
            if (localInTypedLocalSpan(params, local)) return true;
        }
        var cursor = scope;
        while (cursor) |binding_scope| {
            switch (binding_scope.binding) {
                .local => |scoped_local| if (scoped_local == local) return true,
                .pat => |pat| if (self.patternBindsLocal(pat, local)) return true,
                .typed_locals => |typed_locals| if (localInTypedLocalSpan(typed_locals, local)) return true,
            }
            cursor = binding_scope.parent;
        }
        return false;
    }

    fn patternBindsLocal(self: *Cloner, pat_id: Ast.PatId, local: Ast.LocalId) bool {
        const pat = self.pass.program.pats.items[@intFromEnum(pat_id)];
        return switch (pat.data) {
            .bind => |bound| bound == local,
            .wildcard,
            .int_lit,
            .dec_lit,
            .frac_f32_lit,
            .frac_f64_lit,
            .str_lit,
            => false,
            .as => |as| as.local == local or self.patternBindsLocal(as.pattern, local),
            .record => |fields| blk: {
                for (self.pass.program.recordDestructSpan(fields)) |field| {
                    if (self.patternBindsLocal(field.pattern, local)) break :blk true;
                }
                break :blk false;
            },
            .tuple => |items| blk: {
                for (self.pass.program.patSpan(items)) |item| {
                    if (self.patternBindsLocal(item, local)) break :blk true;
                }
                break :blk false;
            },
            .list => |list| blk: {
                for (self.pass.program.patSpan(list.patterns)) |item| {
                    if (self.patternBindsLocal(item, local)) break :blk true;
                }
                if (list.rest) |rest| {
                    if (rest.pattern) |rest_pattern| {
                        if (self.patternBindsLocal(rest_pattern, local)) break :blk true;
                    }
                }
                break :blk false;
            },
            .tag => |tag| blk: {
                for (self.pass.program.patSpan(tag.payloads)) |payload| {
                    if (self.patternBindsLocal(payload, local)) break :blk true;
                }
                break :blk false;
            },
            .nominal => |backing| self.patternBindsLocal(backing, local),
            .str_pattern => |str| blk: {
                for (self.pass.program.strPatternStepSpan(str.steps)) |step| {
                    if (step.capture) |capture| {
                        if (self.patternBindsLocal(capture, local)) break :blk true;
                    }
                }
                break :blk false;
            },
        };
    }

    fn callableValue(self: *Cloner, ty: Type.TypeId, fn_id: Ast.FnId) LowerError!Value {
        const fn_ = self.pass.program.fns.items[@intFromEnum(fn_id)];
        const source_captures = self.pass.program.typedLocalSpan(fn_.captures);
        const captures = try self.pass.arena.allocator().alloc(Value, source_captures.len);
        for (source_captures, 0..) |capture, index| {
            if (self.subst.get(capture.local)) |value| {
                captures[index] = value;
            } else if (try self.scopedLocalValue(capture)) |value| {
                captures[index] = value;
            } else {
                return .{ .expr = try self.addExpr(.{ .ty = ty, .data = .{ .fn_ref = fn_id } }) };
            }
        }
        return .{ .callable = .{
            .ty = ty,
            .fn_id = fn_id,
            .captures = captures,
        } };
    }

    fn callableValueWithCaptureExprs(
        self: *Cloner,
        ty: Type.TypeId,
        fn_id: Ast.FnId,
        capture_exprs: []const Ast.ExprId,
    ) LowerError!Value {
        const fn_ = self.pass.program.fns.items[@intFromEnum(fn_id)];
        const source_captures = self.pass.program.typedLocalSpan(fn_.captures);
        if (source_captures.len != capture_exprs.len) {
            Common.invariant("explicit function reference capture count differed from target function captures");
        }
        const captures = try self.pass.arena.allocator().alloc(Value, capture_exprs.len);
        for (capture_exprs, 0..) |capture_expr, index| {
            const capture_ty = self.pass.program.exprs.items[@intFromEnum(capture_expr)].ty;
            if (!sameType(self.pass.program, source_captures[index].ty, capture_ty)) {
                Common.invariant("explicit function reference capture type differed from target function capture type");
            }
            captures[index] = try self.cloneExprValueDemandingKnownValue(capture_expr);
        }
        return .{ .callable = .{
            .ty = ty,
            .fn_id = fn_id,
            .captures = captures,
        } };
    }

    fn knownCallable(self: *Cloner, ty: Type.TypeId, fn_id: Ast.FnId) Allocator.Error!KnownValue {
        const fn_ = self.pass.program.fns.items[@intFromEnum(fn_id)];
        const source_captures = self.pass.program.typedLocalSpan(fn_.captures);
        const captures = try self.pass.arena.allocator().alloc(KnownValue, source_captures.len);
        for (source_captures, 0..) |capture, index| {
            captures[index] = if (self.subst.get(capture.local)) |value|
                (try self.pass.knownValueFromValue(value)) orelse .{ .any = valueType(self.pass.program, value) }
            else
                .{ .any = capture.ty };
        }
        return .{ .callable = .{
            .ty = ty,
            .fn_id = fn_id,
            .captures = captures,
        } };
    }

    fn knownCallableWithCaptureExprs(
        self: *Cloner,
        ty: Type.TypeId,
        fn_id: Ast.FnId,
        capture_exprs: []const Ast.ExprId,
    ) Allocator.Error!KnownValue {
        const fn_ = self.pass.program.fns.items[@intFromEnum(fn_id)];
        const source_captures = self.pass.program.typedLocalSpan(fn_.captures);
        if (source_captures.len != capture_exprs.len) {
            Common.invariant("explicit function reference capture count differed from target function captures");
        }
        const captures = try self.pass.arena.allocator().alloc(KnownValue, capture_exprs.len);
        for (capture_exprs, 0..) |capture_expr, index| {
            const capture_ty = self.pass.program.exprs.items[@intFromEnum(capture_expr)].ty;
            if (!sameType(self.pass.program, source_captures[index].ty, capture_ty)) {
                Common.invariant("explicit function reference capture type differed from target function capture type");
            }
            captures[index] = (try self.exprKnownValueNoInline(capture_expr)) orelse
                .{ .any = capture_ty };
        }
        return .{ .callable = .{
            .ty = ty,
            .fn_id = fn_id,
            .captures = captures,
        } };
    }

    fn solvedSingleCallable(self: *Cloner, expr_id: Ast.ExprId) LowerError!?Value {
        const solved = self.pass.solved orelse return null;
        const member = self.pass.solvedSingleCallableMember(expr_id) orelse return null;
        const fn_id = self.pass.fnWithSymbol(member.lambda) orelse return null;
        const expr = self.pass.program.exprs.items[@intFromEnum(expr_id)];
        const solved_captures = solved.types.captureSpan(member.captures);
        const source_fn = self.pass.program.fns.items[@intFromEnum(fn_id)];
        const source_captures = self.pass.program.typedLocalSpan(source_fn.captures);
        if (solved_captures.len != source_captures.len) {
            Common.invariant("Lambda Solved callable member capture count differed from lifted function captures");
        }

        const captures = try self.pass.arena.allocator().alloc(Value, solved_captures.len);
        for (solved_captures, 0..) |capture, index| {
            if (capture.local != source_captures[index].local) {
                Common.invariant("Lambda Solved callable member captures differed from lifted function capture order");
            }
            captures[index] = if (self.subst.get(capture.local)) |value|
                value
            else if (try self.scopedLocalValue(source_captures[index])) |value|
                value
            else
                return null;
        }
        return .{ .callable = .{
            .ty = expr.ty,
            .fn_id = fn_id,
            .captures = captures,
        } };
    }

    fn cloneExprPlain(self: *Cloner, expr_id: Ast.ExprId) LowerError!Ast.ExprId {
        const saved_loc = self.current_loc;
        defer self.current_loc = saved_loc;
        const saved_region = self.current_region;
        defer self.current_region = saved_region;
        self.current_loc = self.pass.program.exprLoc(expr_id);
        self.current_region = self.pass.program.exprRegion(expr_id);

        const expr = self.pass.program.exprs.items[@intFromEnum(expr_id)];
        const data: Ast.ExprData = switch (expr.data) {
            .local => |local| blk: {
                break :blk .{ .local = local };
            },
            .unit => .unit,
            .uninitialized => .uninitialized,
            .uninitialized_payload => |payload| .{ .uninitialized_payload = payload },
            .int_lit => |value| .{ .int_lit = value },
            .frac_f32_lit => |value| .{ .frac_f32_lit = value },
            .frac_f64_lit => |value| .{ .frac_f64_lit = value },
            .dec_lit => |value| .{ .dec_lit = value },
            .str_lit => |value| .{ .str_lit = value },
            .static_data => |value| .{ .static_data = value },
            .static_data_candidate => |candidate| .{ .static_data_candidate = .{
                .static_data = candidate.static_data,
                .restored_expr = try self.cloneExpr(candidate.restored_expr),
            } },
            .list => |items| .{ .list = try self.cloneExprSpan(items) },
            .tuple => |items| .{ .tuple = try self.cloneExprSpan(items) },
            .record => |fields| .{ .record = try self.cloneFieldExprSpan(fields) },
            .tag => |tag| .{ .tag = .{
                .name = tag.name,
                .payloads = try self.cloneExprSpan(tag.payloads),
            } },
            .nominal => |backing| .{ .nominal = try self.cloneExpr(backing) },
            .let_ => |let_| try self.cloneLet(let_),
            .lambda,
            .def_ref,
            .fn_def,
            => Common.invariant("pre-lift function expression reached call-pattern specialization"),
            .fn_ref => |target| .{ .fn_ref = target },
            .fn_ref_captures => |fn_ref| .{ .fn_ref_captures = .{
                .target = fn_ref.target,
                .captures = try self.cloneExprSpan(fn_ref.captures),
            } },
            .call_value => |call| .{ .call_value = .{
                .callee = try self.cloneExpr(call.callee),
                .args = try self.cloneExprSpan(call.args),
            } },
            .call_proc => |call| return try self.cloneCallProcExpr(expr.ty, call),
            .low_level => |call| .{ .low_level = .{
                .op = call.op,
                .args = try self.cloneExprSpan(call.args),
            } },
            .field_access => |field| return try self.cloneFieldAccess(expr.ty, field),
            .tuple_access => |access| return try self.cloneTupleAccess(expr.ty, access),
            .structural_eq => |eq| .{ .structural_eq = .{
                .lhs = try self.cloneExpr(eq.lhs),
                .rhs = try self.cloneExpr(eq.rhs),
                .negated = eq.negated,
            } },
            .structural_hash => |h| .{ .structural_hash = .{
                .value = try self.cloneExpr(h.value),
                .hasher = try self.cloneExpr(h.hasher),
            } },
            .match_ => |match| return try self.cloneMatch(expr.ty, match),
            .if_ => |if_| .{ .if_ = .{
                .branches = try self.cloneIfBranchSpan(if_.branches),
                .final_else = try self.cloneExpr(if_.final_else),
            } },
            .block => |block| return try self.cloneBlock(expr.ty, block),
            .loop_ => |loop| return try self.cloneLoop(expr.ty, loop),
            .state_loop => |state_loop| try self.cloneStateLoopExprData(state_loop),
            .break_ => |maybe| return try self.cloneBreakExpr(expr.ty, maybe, .materialize),
            .continue_ => |continue_| try self.cloneContinue(expr.ty, continue_),
            .state_continue => |continue_| try self.cloneStateContinueExprData(continue_),
            .if_initialized_payload => |payload_switch| .{ .if_initialized_payload = .{
                .cond = try self.cloneExpr(payload_switch.cond),
                .cond_mask = payload_switch.cond_mask,
                .payload = payload_switch.payload,
                .uninitialized_is_cold = payload_switch.uninitialized_is_cold,
                .initialized = try self.cloneExpr(payload_switch.initialized),
                .uninitialized = try self.cloneExpr(payload_switch.uninitialized),
            } },
            .try_sequence => |sequence| .{ .try_sequence = .{
                .try_expr = try self.cloneExpr(sequence.try_expr),
                .ok_local = sequence.ok_local,
                .err_is_cold = sequence.err_is_cold,
                .ok_body = try self.cloneExpr(sequence.ok_body),
            } },
            .try_record_sequence => |sequence| .{ .try_record_sequence = .{
                .try_expr = try self.cloneExpr(sequence.try_expr),
                .value_local = sequence.value_local,
                .value_field = sequence.value_field,
                .rest_local = sequence.rest_local,
                .rest_field = sequence.rest_field,
                .err_is_cold = sequence.err_is_cold,
                .ok_body = try self.cloneExpr(sequence.ok_body),
            } },
            .return_ => |value| .{ .return_ = try self.cloneExpr(value) },
            .crash => |msg| .{ .crash = msg },
            .comptime_branch_taken => |taken| .{ .comptime_branch_taken = .{
                .site = taken.site,
                .branch_index = taken.branch_index,
                .body = try self.cloneExpr(taken.body),
            } },
            .comptime_exhaustiveness_failed => |site| .{ .comptime_exhaustiveness_failed = site },
            .dbg => |child| .{ .dbg = try self.cloneExpr(child) },
            .expect_err => |expect_err| .{ .expect_err = .{
                .msg = try self.cloneExpr(expect_err.msg),
                .region = expect_err.region,
            } },
            .expect => |child| .{ .expect = try self.cloneExpr(child) },
        };
        return try self.addExpr(.{ .ty = expr.ty, .data = data });
    }

    fn cloneLetValue(self: *Cloner, let_: anytype) LowerError!Value {
        const raw_value = try self.cloneExprValueDemandingKnownValue(let_.value);
        var pending_lets = std.ArrayList(PendingLet).empty;
        defer pending_lets.deinit(self.pass.allocator);

        const pending_change_start = self.changes.items.len;
        var value = raw_value;
        while (value == .let_) {
            try pending_lets.appendSlice(self.pass.allocator, value.let_.lets);
            value = value.let_.body.*;
        }

        {
            const base_pending_start = self.activePendingLetsLen();
            const base_scoped_start = try self.pushPendingLetScope(pending_lets.items);
            defer self.popPendingLetScope(base_scoped_start, base_pending_start);

            const reusable_pending_start = pending_lets.items.len;
            if (try self.tryMakeReusableForMatch(value, &pending_lets)) |reusable| {
                const reusable_active_start = self.activePendingLetsLen();
                const reusable_scoped_start = try self.pushPendingLetScope(pending_lets.items[reusable_pending_start..]);
                defer self.popPendingLetScope(reusable_scoped_start, reusable_active_start);

                const bind_change_start = self.changes.items.len;
                if (try self.bindPatToReusableValue(let_.bind, reusable)) {
                    if (exprContainsEscapingControlTransfer(self.pass.program, let_.rest)) {
                        const rest = try self.cloneExpr(let_.rest);
                        self.restore(pending_change_start);
                        return .{ .expr = try self.wrapPendingLetsAroundExpr(self.pass.program.exprs.items[@intFromEnum(let_.rest)].ty, rest, pending_lets.items) };
                    }
                    const rest = try self.cloneExprValue(let_.rest);
                    self.restore(pending_change_start);
                    return try self.wrapPendingLets(rest, pending_lets.items, true);
                }
                self.restore(bind_change_start);
                pending_lets.shrinkRetainingCapacity(reusable_pending_start);
            }

            const bind_change_start = self.changes.items.len;
            if (try self.bindPatToSingleUseRestValue(let_.bind, value, let_.rest)) {
                if (exprContainsEscapingControlTransfer(self.pass.program, let_.rest)) {
                    const rest = try self.cloneExpr(let_.rest);
                    self.restore(pending_change_start);
                    return .{ .expr = try self.wrapPendingLetsAroundExpr(self.pass.program.exprs.items[@intFromEnum(let_.rest)].ty, rest, pending_lets.items) };
                }
                const rest = try self.cloneExprValue(let_.rest);
                self.restore(pending_change_start);
                return try self.wrapPendingLets(rest, pending_lets.items, true);
            }
            self.restore(bind_change_start);
        }
        self.restore(pending_change_start);

        const value_expr = try self.materialize(raw_value);
        const change_start = self.changes.items.len;
        if (try self.bindPatToMaterializedKnownValue(let_.bind, raw_value)) {
            const scoped_start = self.scopedLocalsLen();
            defer self.restoreScopedLocals(scoped_start);
            try self.appendPatternScopedLocals(let_.bind);
            const rest = if (exprContainsEscapingControlTransfer(self.pass.program, let_.rest))
                try self.cloneExpr(let_.rest)
            else
                try self.materialize(try self.cloneExprValue(let_.rest));
            self.restore(change_start);
            return .{ .expr = try self.addExpr(.{ .ty = self.pass.program.exprs.items[@intFromEnum(let_.rest)].ty, .data = .{ .let_ = .{
                .bind = try self.clonePat(let_.bind),
                .value = value_expr,
                .rest = rest,
                .comptime_site = let_.comptime_site,
            } } }) };
        }
        self.restore(change_start);
        const scoped_start = self.scopedLocalsLen();
        defer self.restoreScopedLocals(scoped_start);
        try self.appendPatternScopedLocals(let_.bind);
        return .{ .expr = try self.addExpr(.{ .ty = self.pass.program.exprs.items[@intFromEnum(let_.rest)].ty, .data = .{ .let_ = .{
            .bind = try self.clonePat(let_.bind),
            .value = value_expr,
            .rest = try self.cloneExpr(let_.rest),
            .comptime_site = let_.comptime_site,
        } } }) };
    }

    fn cloneLet(self: *Cloner, let_: anytype) LowerError!Ast.ExprData {
        const value = try self.cloneExprValue(let_.value);
        const value_expr = try self.materialize(value);
        const change_start = self.changes.items.len;
        const bound = try self.bindPatToReusableValue(let_.bind, value);
        const rest = if (bound) blk: {
            const cloned = try self.cloneExpr(let_.rest);
            self.restore(change_start);
            break :blk cloned;
        } else if (try self.bindPatToSingleUseRestValue(let_.bind, value, let_.rest)) blk: {
            const cloned = try self.cloneExpr(let_.rest);
            self.restore(change_start);
            break :blk cloned;
        } else blk: {
            if (try self.bindPatToMaterializedKnownValue(let_.bind, value)) {
                const cloned = try self.cloneExpr(let_.rest);
                self.restore(change_start);
                break :blk cloned;
            }
            self.restore(change_start);
            if (try self.cloneLetOfCase(let_, value_expr)) |data| return data;
            const scoped_start = self.scopedLocalsLen();
            defer self.restoreScopedLocals(scoped_start);
            try self.appendPatternScopedLocals(let_.bind);
            break :blk try self.cloneExpr(let_.rest);
        };
        return .{ .let_ = .{
            .bind = try self.clonePat(let_.bind),
            .value = value_expr,
            .rest = rest,
            .comptime_site = let_.comptime_site,
        } };
    }

    fn cloneLetOfCase(self: *Cloner, let_: anytype, value_expr: Ast.ExprId) LowerError!?Ast.ExprData {
        const value_data = self.pass.program.exprs.items[@intFromEnum(value_expr)].data;
        const match = switch (value_data) {
            .match_ => |match| match,
            else => return null,
        };

        const branches = try self.pass.allocator.dupe(Ast.Branch, self.pass.program.branchSpan(match.branches));
        defer self.pass.allocator.free(branches);

        var rewritten = try self.pass.allocator.alloc(Ast.Branch, branches.len);
        defer self.pass.allocator.free(rewritten);

        for (branches, 0..) |branch, index| {
            const scoped_start = self.scopedLocalsLen();
            defer self.restoreScopedLocals(scoped_start);
            try self.appendPatternScopedLocals(branch.pat);
            const body = (try self.cloneLetCaseBranchBody(let_, branch.body)) orelse return null;
            rewritten[index] = .{
                .pat = branch.pat,
                .guard = branch.guard,
                .body = body,
            };
        }

        return .{ .match_ = .{
            .scrutinee = match.scrutinee,
            .branches = try self.pass.program.addBranchSpan(rewritten),
            .comptime_site = match.comptime_site,
        } };
    }

    fn cloneLetCaseBranchBody(self: *Cloner, let_: anytype, branch_body: Ast.ExprId) LowerError!?Ast.ExprId {
        const branch_expr = self.pass.program.exprs.items[@intFromEnum(branch_body)];
        switch (branch_expr.data) {
            .block => |block| {
                const change_start = self.changes.items.len;

                const source = try self.pass.allocator.dupe(Ast.StmtId, self.pass.program.stmtSpan(block.statements));
                defer self.pass.allocator.free(source);

                var statements = std.ArrayList(Ast.StmtId).empty;
                defer statements.deinit(self.pass.allocator);
                for (source, 0..) |stmt, stmt_index| {
                    try self.cloneStmtInto(stmt, &statements, .{
                        .statements = source[stmt_index + 1 ..],
                        .final_expr = block.final_expr,
                    }, .materialize);
                }

                const final_value = try self.cloneExprValue(block.final_expr);
                const rest_ty = self.pass.program.exprs.items[@intFromEnum(let_.rest)].ty;
                if (!try self.bindPatToReusableValue(let_.bind, final_value)) {
                    if (try self.cloneDivergentAtType(block.final_expr, rest_ty)) |divergent| {
                        self.restore(change_start);
                        return try self.addExpr(.{ .ty = rest_ty, .data = .{ .block = .{
                            .statements = try self.pass.program.addStmtSpan(statements.items),
                            .final_expr = divergent,
                        } } });
                    }
                    self.restore(change_start);
                    return null;
                }

                const rest = try self.cloneExpr(let_.rest);
                self.restore(change_start);

                return try self.addExpr(.{ .ty = rest_ty, .data = .{ .block = .{
                    .statements = try self.pass.program.addStmtSpan(statements.items),
                    .final_expr = rest,
                } } });
            },
            else => {
                const branch_value = try self.cloneExprValue(branch_body);
                const change_start = self.changes.items.len;
                if (!try self.bindPatToReusableValue(let_.bind, branch_value)) {
                    self.restore(change_start);
                    return null;
                }
                const rest = try self.cloneExpr(let_.rest);
                self.restore(change_start);
                return rest;
            },
        }
    }

    fn cloneDivergentAtType(self: *Cloner, expr_id: Ast.ExprId, ty: Type.TypeId) LowerError!?Ast.ExprId {
        const expr = self.pass.program.exprs.items[@intFromEnum(expr_id)];
        return switch (expr.data) {
            .crash => |msg| try self.addExpr(.{ .ty = ty, .data = .{ .crash = msg } }),
            .comptime_exhaustiveness_failed => |site| try self.addExpr(.{ .ty = ty, .data = .{ .comptime_exhaustiveness_failed = site } }),
            .return_ => |value| try self.addExpr(.{ .ty = ty, .data = .{ .return_ = try self.cloneExpr(value) } }),
            else => null,
        };
    }

    fn scopedLocalValue(self: *Cloner, local: Ast.TypedLocal) LowerError!?Value {
        if (!self.localCanBeReferencedDirectly(local.local)) return null;
        return .{ .expr = try self.addExpr(.{
            .ty = local.ty,
            .data = .{ .local = local.local },
        }) };
    }

    fn localCanBeReferencedDirectly(self: *Cloner, local: Ast.LocalId) bool {
        const output_fn = self.pass.program.fns.items[@intFromEnum(self.output_fn)];
        if (localInTypedLocalSpan(self.pass.program.typedLocalSpan(output_fn.captures), local)) return true;
        if (localInTypedLocalSpan(self.pass.program.typedLocalSpan(output_fn.args), local)) return true;

        for (self.inline_stack.items) |active| {
            if (active.fn_id == self.output_fn) continue;
            const active_fn = self.pass.program.fns.items[@intFromEnum(active.fn_id)];
            if (localInTypedLocalSpan(self.pass.program.typedLocalSpan(active_fn.args), local)) return false;
            if (localInTypedLocalSpan(self.pass.program.typedLocalSpan(active_fn.captures), local)) return false;
        }

        return false;
    }

    fn scopedLocalsLen(self: *Cloner) usize {
        return self.scoped_locals.items.len;
    }

    fn snapshotScopedLocals(self: *Cloner) Allocator.Error![]const Ast.LocalId {
        return try self.pass.arena.allocator().dupe(Ast.LocalId, self.scoped_locals.items);
    }

    fn snapshotSubstBindings(self: *Cloner) Allocator.Error![]const SavedBinding {
        var bindings = std.ArrayList(SavedBinding).empty;
        defer bindings.deinit(self.pass.allocator);

        var iterator = self.subst.iterator();
        while (iterator.next()) |entry| {
            try bindings.append(self.pass.allocator, .{
                .local = entry.key_ptr.*,
                .value = entry.value_ptr.*,
            });
        }

        return try self.pass.arena.allocator().dupe(SavedBinding, bindings.items);
    }

    fn restoreScopedLocals(self: *Cloner, mark: usize) void {
        self.scoped_locals.shrinkRetainingCapacity(mark);
    }

    fn activePendingLetsLen(self: *Cloner) usize {
        return self.active_pending_lets.items.len;
    }

    fn restoreActivePendingLets(self: *Cloner, mark: usize) void {
        self.active_pending_lets.shrinkRetainingCapacity(mark);
    }

    fn appendPatternScopedLocals(self: *Cloner, pat_id: Ast.PatId) Allocator.Error!void {
        const pat = self.pass.program.pats.items[@intFromEnum(pat_id)];
        switch (pat.data) {
            .bind => |local| try self.scoped_locals.append(self.pass.allocator, local),
            .wildcard,
            .int_lit,
            .dec_lit,
            .frac_f32_lit,
            .frac_f64_lit,
            .str_lit,
            => {},
            .as => |as| {
                try self.appendPatternScopedLocals(as.pattern);
                try self.scoped_locals.append(self.pass.allocator, as.local);
            },
            .record => |fields| {
                for (self.pass.program.recordDestructSpan(fields)) |field| {
                    try self.appendPatternScopedLocals(field.pattern);
                }
            },
            .tuple => |items| {
                for (self.pass.program.patSpan(items)) |item| {
                    try self.appendPatternScopedLocals(item);
                }
            },
            .list => |list| {
                for (self.pass.program.patSpan(list.patterns)) |item| {
                    try self.appendPatternScopedLocals(item);
                }
                if (list.rest) |rest| {
                    if (rest.pattern) |rest_pattern| try self.appendPatternScopedLocals(rest_pattern);
                }
            },
            .tag => |tag| {
                for (self.pass.program.patSpan(tag.payloads)) |payload| {
                    try self.appendPatternScopedLocals(payload);
                }
            },
            .nominal => |backing| try self.appendPatternScopedLocals(backing),
            .str_pattern => |str| {
                for (self.pass.program.strPatternStepSpan(str.steps)) |step| {
                    if (step.capture) |capture| try self.appendPatternScopedLocals(capture);
                }
            },
        }
    }

    fn appendPendingLetScopedLocals(self: *Cloner, pending_lets: []const PendingLet) Allocator.Error!void {
        for (pending_lets) |pending| {
            try self.scoped_locals.append(self.pass.allocator, pending.local);
        }
    }

    fn pushPendingLetScope(self: *Cloner, pending_lets: []const PendingLet) LowerError!usize {
        const scoped_start = self.scopedLocalsLen();
        try self.appendPendingLetScopedLocals(pending_lets);
        try self.bindPendingLetKnownValues(pending_lets);
        try self.active_pending_lets.appendSlice(self.pass.allocator, pending_lets);
        return scoped_start;
    }

    fn popPendingLetScope(self: *Cloner, scoped_start: usize, pending_start: usize) void {
        self.restoreActivePendingLets(pending_start);
        self.restoreScopedLocals(scoped_start);
    }

    fn snapshotActivePendingLets(self: *Cloner) Allocator.Error![]const PendingLet {
        return try self.pass.arena.allocator().dupe(PendingLet, self.active_pending_lets.items);
    }

    fn pendingLetIsActive(self: *Cloner, local: Ast.LocalId) bool {
        for (self.active_pending_lets.items) |pending| {
            if (pending.local == local) return true;
        }
        return false;
    }

    fn missingActivePendingLets(
        self: *Cloner,
        pending_lets: []const PendingLet,
    ) Allocator.Error![]const PendingLet {
        var missing = std.ArrayList(PendingLet).empty;
        defer missing.deinit(self.pass.allocator);
        for (pending_lets) |pending| {
            if (self.pendingLetIsActive(pending.local)) continue;
            try missing.append(self.pass.allocator, pending);
        }
        return try self.pass.allocator.dupe(PendingLet, missing.items);
    }

    fn appendActivePendingLetDependenciesForExpr(
        self: *Cloner,
        expr: Ast.ExprId,
        out: *std.ArrayList(PendingLet),
    ) Allocator.Error!void {
        if (self.active_pending_lets.items.len == 0) return;

        const selected = try self.pass.allocator.alloc(bool, self.active_pending_lets.items.len);
        defer self.pass.allocator.free(selected);
        @memset(selected, false);

        var changed = false;
        for (self.active_pending_lets.items, 0..) |pending, index| {
            if (localUseCountInExpr(self.pass.program, pending.local, expr) == 0) continue;
            selected[index] = true;
            changed = true;
        }

        while (changed) {
            changed = false;
            for (self.active_pending_lets.items, 0..) |pending, index| {
                if (!selected[index]) continue;
                for (self.active_pending_lets.items[0..index], 0..) |dependency, dependency_index| {
                    if (selected[dependency_index]) continue;
                    if (!pendingLetValueUsesLocal(self.pass.program, pending.value, dependency.local)) continue;
                    selected[dependency_index] = true;
                    changed = true;
                }
            }
        }

        for (self.active_pending_lets.items, selected) |pending, include| {
            if (include) try out.append(self.pass.allocator, pending);
        }
    }

    fn localBindingAvailable(self: *Cloner, local: Ast.LocalId) bool {
        if (self.localCanBeReferencedDirectly(local)) return true;
        for (self.scoped_locals.items) |scoped_local| {
            if (scoped_local == local) return true;
        }
        for (self.loop_stack.items) |loop| {
            if (localInTypedLocalSpan(loop.params, local)) return true;
        }
        for (self.state_param_stack.items) |params| {
            if (localInTypedLocalSpan(params, local)) return true;
        }
        return false;
    }

    fn cloneLoop(self: *Cloner, ty: Type.TypeId, loop: anytype) LowerError!Ast.ExprId {
        return try self.cloneLoopWithDemand(ty, loop, .materialize);
    }

    fn cloneLoopWithDemand(self: *Cloner, ty: Type.TypeId, loop: anytype, result_demand: ValueDemand) LowerError!Ast.ExprId {
        return try self.materialize(try self.cloneLoopValueWithDemand(ty, loop, result_demand));
    }

    fn cloneLoopValueWithDemand(self: *Cloner, ty: Type.TypeId, loop: anytype, result_demand: ValueDemand) LowerError!Value {
        const params = try self.pass.allocator.dupe(Ast.TypedLocal, self.pass.program.typedLocalSpan(loop.params));
        defer self.pass.allocator.free(params);
        const initial_values = try self.pass.allocator.dupe(Ast.ExprId, self.pass.program.exprSpan(loop.initial_values));
        defer self.pass.allocator.free(initial_values);
        if (params.len != initial_values.len) Common.invariant("loop parameter count differed from initial value count");

        const initial_demands = try self.loopParamDemands(loop, result_demand);
        defer self.pass.allocator.free(initial_demands);

        const source_initials = try self.pass.allocator.alloc(?ExprValueSource, initial_values.len);
        defer self.pass.allocator.free(source_initials);
        const active_pending_lets = try self.snapshotActivePendingLets();
        const active_scoped_locals = try self.snapshotScopedLocals();
        const active_bindings = try self.snapshotSubstBindings();
        for (initial_values, source_initials) |initial, *source| {
            source.* = .{
                .expr = initial,
                .pending_lets = active_pending_lets,
                .scoped_locals = active_scoped_locals,
                .bindings = active_bindings,
            };
        }

        var demand_iterations: usize = 0;
        while (true) {
            demand_iterations += 1;
            if (demand_iterations > 1000) Common.invariant("loop initial demand refinement did not converge");

            const change_start = self.changes.items.len;
            const scoped_start = self.scopedLocalsLen();

            const values = try self.pass.allocator.alloc(Value, initial_values.len);
            defer self.pass.allocator.free(values);
            for (initial_values, 0..) |initial, index| {
                values[index] = try self.cloneExprValueWithDemand(initial, initial_demands[index]);
            }

            if (try self.refineLoopDemandsFromConcreteInitialValues(loop, params, values, initial_demands, result_demand)) {
                self.restoreScopedLocals(scoped_start);
                self.restore(change_start);
                continue;
            }

            return try self.cloneLoopFromInitialValues(ty, loop, params, values, source_initials, initial_demands, result_demand);
        }
    }

    fn refineLoopDemandsFromConcreteInitialValues(
        self: *Cloner,
        loop: anytype,
        params: []const Ast.TypedLocal,
        values: []const Value,
        demands: []ValueDemand,
        result_demand: ValueDemand,
    ) LowerError!bool {
        if (!valueDemandsRequirePrivateState(demands)) return false;

        const demanded_known_values = try self.pass.allocator.alloc(DemandedKnownValue, values.len);
        defer self.pass.allocator.free(demanded_known_values);

        try self.refreshDemandedKnownValuesFromValueDemands(values, demands, demanded_known_values);
        return try self.stabilizeLoopDemandsFromDemandedStateBodies(loop, params, values, demanded_known_values, demands, result_demand);
    }

    fn refreshedLoopInitialValues(
        self: *Cloner,
        values: []const Value,
        source_initials: []const ?ExprValueSource,
        demands: []const ValueDemand,
    ) LowerError![]Value {
        if (values.len != source_initials.len or values.len != demands.len) {
            Common.invariant("loop initial source/value/demand arity differed while refreshing values");
        }

        const refreshed = try self.pass.allocator.alloc(Value, values.len);
        for (values, source_initials, demands, refreshed) |value, source, demand, *out| {
            out.* = if (source) |expr_source|
                try self.cloneExprValueSourceWithDemand(expr_source, demand)
            else
                try self.applyValueDemand(value, demand);
        }
        return refreshed;
    }

    fn cloneExprValueSourceWithDemand(
        self: *Cloner,
        source: ExprValueSource,
        demand: ValueDemand,
    ) LowerError!Value {
        const change_start = self.changes.items.len;
        defer self.restore(change_start);

        const missing_source_pending_lets = try self.missingActivePendingLets(source.pending_lets);
        defer self.pass.allocator.free(missing_source_pending_lets);

        const source_pending_start = self.activePendingLetsLen();
        const source_pending_scope_start = try self.pushPendingLetScope(missing_source_pending_lets);
        defer self.popPendingLetScope(source_pending_scope_start, source_pending_start);

        const scoped_start = self.scopedLocalsLen();
        defer self.restoreScopedLocals(scoped_start);
        try self.scoped_locals.appendSlice(self.pass.allocator, source.scoped_locals);

        for (source.bindings) |binding| {
            try self.putSubst(binding.local, binding.value);
        }

        const value = try self.cloneScopedExprValueWithDemand(source.expr, demand);
        return try self.wrapPendingLets(value, missing_source_pending_lets, demand != .none);
    }

    fn cloneLoopFromInitialValues(
        self: *Cloner,
        ty: Type.TypeId,
        loop: anytype,
        params: []const Ast.TypedLocal,
        values: []const Value,
        source_initials: ?[]const ?ExprValueSource,
        initial_demands: []const ValueDemand,
        result_demand: ValueDemand,
    ) LowerError!Value {
        if (try self.cloneLoopUnwrappedLet(ty, loop, params, values, source_initials, initial_demands, result_demand)) |unwrapped| return .{ .expr = unwrapped };
        if (try self.cloneLoopDistributedIf(ty, loop, params, values, source_initials, initial_demands, result_demand)) |distributed| return .{ .expr = distributed };

        const known_values = try self.pass.arena.allocator().alloc(KnownValue, values.len);
        var has_constructor = false;
        for (values, 0..) |value, index| {
            const initial_value_ty = valueType(self.pass.program, value);
            if (try self.pass.knownValueFromValue(value)) |known_value| {
                if (try self.projectableLoopKnownValueForValue(known_value, value)) |loop_known_value| {
                    known_values[index] = loop_known_value;
                    has_constructor = true;
                } else {
                    known_values[index] = .{ .any = initial_value_ty };
                }
            } else {
                known_values[index] = .{ .any = initial_value_ty };
            }
        }
        if (!has_constructor) {
            var needs_private_state = false;
            for (values) |value| {
                if (!self.valueCanMaterializePublic(value)) {
                    needs_private_state = true;
                    break;
                }
            }

            if (!needs_private_state) {
                const maybe_initial_span = try self.valuesToOutputExprSpan(values);
                if (maybe_initial_span) |initial_span| {
                    const refinements = try self.pass.allocator.alloc(?KnownValue, known_values.len);
                    defer self.pass.allocator.free(refinements);
                    @memset(refinements, null);

                    const demands = try self.pass.allocator.alloc(ValueDemand, known_values.len);
                    defer self.pass.allocator.free(demands);
                    @memset(demands, .none);

                    var provenance = std.ArrayList(LoopLocalProvenance).empty;
                    defer provenance.deinit(self.pass.allocator);

                    try self.loop_stack.append(self.pass.allocator, .{
                        .params = params,
                        .values = known_values,
                        .refinements = refinements,
                        .demands = demands,
                        .result_demand = result_demand,
                        .provenance = &provenance,
                    });
                    defer _ = self.loop_stack.pop();

                    const body = try self.cloneExpr(loop.body);
                    const loop_expr = try self.addExpr(.{ .ty = ty, .data = .{ .loop_ = .{
                        .params = loop.params,
                        .initial_values = initial_span,
                        .body = body,
                    } } });
                    return .{ .expr = loop_expr };
                }
            }

            const demands = try self.pass.arena.allocator().alloc(ValueDemand, values.len);
            const demanded_known_values = try self.pass.arena.allocator().alloc(DemandedKnownValue, values.len);
            for (values, demands, demanded_known_values, 0..) |value, *demand_out, *known_out, index| {
                const inferred_demand = try self.loopSlotDemand(initial_demands[index]);
                demand_out.* = inferred_demand;
                const demanded_known = try self.demandedKnownValueFromLoopStateValueDemand(value, inferred_demand);
                known_out.* = demanded_known orelse DemandedKnownValue{ .any = valueType(self.pass.program, value) };
            }

            if (try self.stabilizeLoopDemandsFromDemandedStateBodies(loop, params, values, demanded_known_values, demands, result_demand)) {
                if (source_initials) |sources| {
                    const refreshed_values = try self.refreshedLoopInitialValues(values, sources, demands);
                    defer self.pass.allocator.free(refreshed_values);
                    return try self.cloneLoopFromInitialValues(ty, loop, params, refreshed_values, source_initials, demands, result_demand);
                }
            }
            return try self.cloneStateLoopFromDemandedKnownValues(ty, loop, params, values, demanded_known_values, demands, result_demand);
        }

        var debug_loop_known_iterations: usize = 0;
        while (true) {
            debug_loop_known_iterations += 1;
            if (debug_loop_known_iterations > 1000) Common.invariant("debug loop known demand loop did not converge");
            const change_start = self.changes.items.len;
            defer self.restore(change_start);

            var new_params = std.ArrayList(Ast.TypedLocal).empty;
            defer new_params.deinit(self.pass.allocator);

            var provenance = std.ArrayList(LoopLocalProvenance).empty;
            defer provenance.deinit(self.pass.allocator);

            for (params, known_values) |param, known_value| {
                var path = std.ArrayList(DemandPathStep).empty;
                defer path.deinit(self.pass.allocator);
                const param_value = try self.valueFromKnownValueLoopParamArgs(known_value, &new_params, param.local, &path, &provenance);
                try self.putSubst(param.local, param_value);
            }
            const refinements = try self.pass.allocator.alloc(?KnownValue, known_values.len);
            defer self.pass.allocator.free(refinements);
            @memset(refinements, null);

            const demands = try self.pass.allocator.alloc(ValueDemand, known_values.len);
            defer self.pass.allocator.free(demands);
            @memset(demands, .none);

            try self.loop_stack.append(self.pass.allocator, .{
                .params = params,
                .values = known_values,
                .refinements = refinements,
                .demands = demands,
                .result_demand = result_demand,
                .provenance = &provenance,
            });
            var debug_loop_inner_iterations: usize = 0;
            while (true) {
                debug_loop_inner_iterations += 1;
                if (debug_loop_inner_iterations > 1000) Common.invariant("debug loop inner demand loop did not converge");
                var demand_changed = false;
                for (params, 0..) |param, index| {
                    const observed = try self.localDemandInExpr(param.local, loop.body, result_demand);
                    const merged = try self.mergeLoopParamDemand(known_values[index], demands[index], observed);
                    if (!try self.valueDemandEqlInActiveContext(demands[index], merged)) {
                        demands[index] = merged;
                        demand_changed = true;
                        self.demand_cache_epoch += 1;
                    }
                }
                if (!demand_changed) break;
            }
            if (valueDemandsRequirePrivateState(demands)) {
                try self.stabilizeLoopDemandsFromStateBodies(loop, params, known_values, demands, result_demand);
                _ = self.loop_stack.pop();
                const demanded_known_values = try self.pass.arena.allocator().alloc(DemandedKnownValue, known_values.len);
                for (known_values, values, demands, demanded_known_values) |known_value, value, *demand, *out| {
                    demand.* = try self.loopSlotDemand(try self.expandLoopCallableCaptureDemands(value, demand.*));
                    out.* = try self.demandedKnownValueFromLoopEntryDemand(value, known_value, demand.*);
                }
                self.restore(change_start);
                return try self.cloneStateLoopFromDemandedKnownValues(ty, loop, params, values, demanded_known_values, demands, result_demand);
            }
            const body_scoped_start = self.scopedLocalsLen();
            for (new_params.items) |new_param| {
                try self.scoped_locals.append(self.pass.allocator, new_param.local);
            }
            const body = try self.cloneExpr(loop.body);
            self.restoreScopedLocals(body_scoped_start);
            _ = self.loop_stack.pop();

            if (valueDemandsRequirePrivateState(demands)) {
                const demanded_known_values = try self.pass.arena.allocator().alloc(DemandedKnownValue, known_values.len);
                for (known_values, values, demands, demanded_known_values) |known_value, value, *demand, *out| {
                    demand.* = try self.loopSlotDemand(try self.expandLoopCallableCaptureDemands(value, demand.*));
                    out.* = try self.demandedKnownValueFromLoopEntryDemand(value, known_value, demand.*);
                }
                self.restore(change_start);
                return try self.cloneStateLoopFromDemandedKnownValues(ty, loop, params, values, demanded_known_values, demands, result_demand);
            }

            var refined = false;
            for (known_values, refinements, 0..) |*known_value, maybe_refinement, index| {
                const refinement = maybe_refinement orelse continue;
                if (known_valueEql(self.pass.program, known_value.*, refinement)) continue;
                known_values[index] = refinement;
                refined = true;
            }
            if (refined) continue;

            if (knownValuesContainFiniteState(known_values) or valueDemandsRequirePrivateState(demands)) {
                try self.stabilizeLoopDemandsFromStateBodies(loop, params, known_values, demands, result_demand);
                const demanded_known_values = try self.pass.arena.allocator().alloc(DemandedKnownValue, known_values.len);
                for (known_values, values, demands, demanded_known_values) |known_value, value, *demand, *out| {
                    demand.* = try self.loopSlotDemand(try self.expandLoopCallableCaptureDemands(value, demand.*));
                    out.* = try self.demandedKnownValueFromLoopEntryDemand(value, known_value, demand.*);
                }
                if (demandedKnownValuesContainFiniteState(demanded_known_values) or valueDemandsRequirePrivateState(demands)) {
                    self.restore(change_start);
                    return try self.cloneStateLoopFromDemandedKnownValues(ty, loop, params, values, demanded_known_values, demands, result_demand);
                }
            }

            var new_initials = std.ArrayList(Ast.ExprId).empty;
            defer new_initials.deinit(self.pass.allocator);

            var pending_lets = std.ArrayList(PendingLet).empty;
            defer pending_lets.deinit(self.pass.allocator);

            var initial_split_failed = false;
            for (known_values, values, 0..) |*known_value, value, index| {
                if (!try self.appendFieldReadExprsFromValueCollectingLets(known_value.*, value, &new_initials, &pending_lets)) {
                    const downgrade_ty = known_valueType(known_value.*);
                    if (known_value.* == .any and sameType(self.pass.program, known_value.any, downgrade_ty)) {
                        Common.invariant("loop initial split failed without progress");
                    }
                    known_values[index] = .{ .any = downgrade_ty };
                    initial_split_failed = true;
                    break;
                }
            }
            if (initial_split_failed) continue;

            const loop_expr = try self.addExpr(.{ .ty = ty, .data = .{ .loop_ = .{
                .params = try self.pass.program.addTypedLocalSpan(new_params.items),
                .initial_values = try self.pass.program.addExprSpan(new_initials.items),
                .body = body,
            } } });
            return .{ .expr = try self.wrapPendingLetsAroundExpr(ty, loop_expr, pending_lets.items) };
        }
    }

    fn demandedKnownValueFromLoopEntryDemand(
        self: *Cloner,
        value: Value,
        known_value: KnownValue,
        demand: ValueDemand,
    ) LowerError!DemandedKnownValue {
        const demanded_value = try self.applyValueDemand(value, demand);
        if (demanded_value == .private_state) {
            return try self.demandedKnownValueFromPrivateStateLoopStateShape(demanded_value.private_state);
        }

        if (try self.demandedKnownValueFromValueDemand(demanded_value, demand)) |demanded| {
            return demanded;
        }

        if (try self.demandedKnownValueFromValueDemand(value, demand)) |demanded| {
            return demanded;
        }

        return (try demandedKnownValueFromDemand(self, self.pass.program, self.pass.arena.allocator(), known_value, demand)) orelse
            DemandedKnownValue{ .any = known_valueType(known_value) };
    }

    fn stabilizeLoopDemandsFromStateBodies(
        self: *Cloner,
        loop: anytype,
        params: []const Ast.TypedLocal,
        known_values: []const KnownValue,
        demands: []ValueDemand,
        result_demand: ValueDemand,
    ) LowerError!void {
        var state_body_iterations: usize = 0;
        while (true) {
            state_body_iterations += 1;
            if (state_body_iterations > 1000) Common.invariant("state body demand loop did not converge");
            var changed = false;

            const demanded_known_values = try self.pass.allocator.alloc(DemandedKnownValue, known_values.len);
            defer self.pass.allocator.free(demanded_known_values);
            for (known_values, demands, demanded_known_values) |known_value, demand, *out| {
                out.* = (try demandedKnownValueFromDemand(self, self.pass.program, self.pass.arena.allocator(), known_value, demand)) orelse
                    DemandedKnownValue{ .any = known_valueType(known_value) };
            }

            const state_keys = try demandedKnownValueProducts(self.pass.allocator, self.pass.arena.allocator(), demanded_known_values);
            for (state_keys) |state_values| {
                if (state_values.len != params.len) Common.invariant("state demand key arity differed from loop params");

                const change_start = self.changes.items.len;

                var state_params = std.ArrayList(Ast.TypedLocal).empty;
                defer {
                    self.restore(change_start);
                    state_params.deinit(self.pass.allocator);
                }

                for (params, state_values) |param, state_value| {
                    const private_state = try self.privateStateValueFromDemandedKnownValueArgs(state_value, &state_params);
                    try self.putSubst(param.local, .{ .private_state = private_state });
                }

                for (params, 0..) |param, index| {
                    const observed = try self.localDemandInExpr(param.local, loop.body, result_demand);
                    const merged = try self.mergeLoopParamDemand(known_values[index], demands[index], observed);
                    if (!try self.valueDemandEqlInActiveContext(demands[index], merged)) {
                        demands[index] = merged;
                        changed = true;
                        self.demand_cache_epoch += 1;
                    }
                }
            }

            if (!changed) return;
        }
    }

    fn stabilizeLoopDemandsFromDemandedStateBodies(
        self: *Cloner,
        loop: anytype,
        params: []const Ast.TypedLocal,
        values: []const Value,
        demanded_known_values: []DemandedKnownValue,
        demands: []ValueDemand,
        result_demand: ValueDemand,
    ) LowerError!bool {
        const loop_known_values = try self.pass.allocator.alloc(KnownValue, values.len);
        defer self.pass.allocator.free(loop_known_values);
        for (values, loop_known_values) |value, *known_value| {
            known_value.* = .{ .any = valueType(self.pass.program, value) };
        }

        const refinements = try self.pass.allocator.alloc(?KnownValue, values.len);
        defer self.pass.allocator.free(refinements);
        @memset(refinements, null);

        var provenance = std.ArrayList(LoopLocalProvenance).empty;
        defer provenance.deinit(self.pass.allocator);

        try self.loop_stack.append(self.pass.allocator, .{
            .params = params,
            .values = loop_known_values,
            .source_values = values,
            .refinements = refinements,
            .demands = demands,
            .result_demand = result_demand,
            .provenance = &provenance,
        });
        defer _ = self.loop_stack.pop();

        var demanded_state_body_iterations: usize = 0;
        var changed_any = false;
        while (true) {
            demanded_state_body_iterations += 1;
            if (demanded_state_body_iterations > 1000) Common.invariant("demanded state body demand loop did not converge");
            var changed = false;
            const state_keys = try demandedKnownValueProducts(self.pass.allocator, self.pass.arena.allocator(), demanded_known_values);

            for (state_keys) |state_values| {
                if (state_values.len != params.len) Common.invariant("state demand key arity differed from loop params");

                const change_start = self.changes.items.len;
                const provenance_start = self.loopProvenanceLen();

                var state_params = std.ArrayList(Ast.TypedLocal).empty;
                defer {
                    self.restoreLoopProvenance(provenance_start);
                    self.restore(change_start);
                    state_params.deinit(self.pass.allocator);
                }

                for (params, state_values) |param, state_value| {
                    var path = std.ArrayList(DemandPathStep).empty;
                    defer path.deinit(self.pass.allocator);
                    const private_state = try self.privateStateValueFromDemandedKnownValueLoopParamArgs(
                        state_value,
                        &state_params,
                        param.local,
                        &path,
                        &provenance,
                    );
                    try self.putSubst(param.local, .{ .private_state = private_state });
                }

                for (params, values, 0..) |param, value, index| {
                    const observed = try self.localDemandInExpr(param.local, loop.body, result_demand);
                    const merged = try self.mergeLoopValueParamDemand(value, demands[index], observed);
                    if (!try self.valueDemandEqlInActiveContext(demands[index], merged)) {
                        demands[index] = merged;
                        changed = true;
                        changed_any = true;
                        self.demand_cache_epoch += 1;
                    }
                }
            }

            if (!changed) return changed_any;
            try self.refreshDemandedKnownValuesFromValueDemands(values, demands, demanded_known_values);
        }
    }

    fn cloneCompactLoopBodyExpr(
        self: *Cloner,
        expr_id: Ast.ExprId,
        result: CompactResult,
        demand: ValueDemand,
    ) LowerError!Ast.ExprId {
        const expr = self.pass.program.exprs.items[@intFromEnum(expr_id)];
        if (try self.cloneDivergentAtType(expr_id, result.ty)) |divergent| return divergent;

        return switch (expr.data) {
            .break_ => |maybe_value| try self.addExpr(.{ .ty = result.ty, .data = .{ .break_ = if (maybe_value) |value| blk: {
                const payload = try self.cloneExprValueWithDemand(value, demand);
                break :blk try self.compactResultExpr(result, payload);
            } else blk: {
                if (result.slot_tys.len != 0) Common.invariant("non-unit compact loop result had empty break");
                break :blk null;
            } } }),
            .continue_ => |continue_| try self.addExpr(.{
                .ty = result.ty,
                .data = try self.cloneContinue(result.ty, continue_),
            }),
            .state_continue => |continue_| try self.addExpr(.{
                .ty = result.ty,
                .data = try self.cloneStateContinueExprData(continue_),
            }),
            .return_ => |value| try self.addExpr(.{ .ty = result.ty, .data = .{ .return_ = try self.cloneExpr(value) } }),
            .comptime_branch_taken => |taken| try self.cloneCompactLoopBodyExpr(taken.body, result, demand),
            .block => |block| try self.cloneCompactLoopBlockExpr(block, result, demand),
            .if_ => |if_| try self.cloneCompactLoopIfExpr(if_, result, demand),
            .match_ => |match| try self.cloneCompactLoopMatchExpr(match, result, demand),
            .let_ => |let_| try self.cloneCompactLoopLetExpr(let_, result, demand),
            else => try self.compactResultExpr(result, try self.cloneExprValueWithDemand(expr_id, demand)),
        };
    }

    fn cloneCompactLoopBlockExpr(
        self: *Cloner,
        block: anytype,
        result: CompactResult,
        demand: ValueDemand,
    ) LowerError!Ast.ExprId {
        const change_start = self.changes.items.len;
        defer self.restore(change_start);
        const provenance_start = self.loopProvenanceLen();
        defer self.restoreLoopProvenance(provenance_start);

        const source = try self.pass.allocator.dupe(Ast.StmtId, self.pass.program.stmtSpan(block.statements));
        defer self.pass.allocator.free(source);

        var statements = std.ArrayList(Ast.StmtId).empty;
        defer statements.deinit(self.pass.allocator);
        for (source, 0..) |stmt, index| {
            if (stmtAlwaysEscapesControlTransfer(self.pass.program, stmt)) {
                const final_expr = try self.cloneCompactLoopStmtAsFinalExpr(stmt, result, demand);
                if (statements.items.len == 0) return final_expr;

                return try self.addExpr(.{ .ty = result.ty, .data = .{ .block = .{
                    .statements = try self.pass.program.addStmtSpan(statements.items),
                    .final_expr = final_expr,
                } } });
            }

            try self.cloneCompactLoopStmtInto(stmt, &statements, .{
                .statements = source[index + 1 ..],
                .final_expr = block.final_expr,
            }, result, demand);
        }

        const final_expr = try self.cloneCompactLoopBodyExpr(block.final_expr, result, demand);
        if (statements.items.len == 0) return final_expr;

        return try self.addExpr(.{ .ty = result.ty, .data = .{ .block = .{
            .statements = try self.pass.program.addStmtSpan(statements.items),
            .final_expr = final_expr,
        } } });
    }

    fn cloneCompactLoopStmtAsFinalExpr(
        self: *Cloner,
        stmt_id: Ast.StmtId,
        result: CompactResult,
        demand: ValueDemand,
    ) LowerError!Ast.ExprId {
        const stmt = self.pass.program.stmts.items[@intFromEnum(stmt_id)];
        return switch (stmt) {
            .expr => |expr| try self.cloneCompactLoopBodyExpr(expr, result, demand),
            .let_ => |let_| try self.cloneCompactLoopBodyExpr(let_.value, result, demand),
            .return_ => |expr| try self.addExpr(.{ .ty = result.ty, .data = .{ .return_ = try self.cloneExpr(expr) } }),
            .dbg => |expr| try self.addExpr(.{ .ty = result.ty, .data = .{ .dbg = try self.cloneCompactLoopBodyExpr(expr, result, demand) } }),
            .expect => |expr| try self.addExpr(.{ .ty = result.ty, .data = .{ .expect = try self.cloneCompactLoopBodyExpr(expr, result, demand) } }),
            .crash => |msg| try self.addExpr(.{ .ty = result.ty, .data = .{ .crash = msg } }),
            .uninitialized => Common.invariant("uninitialized statement was classified as definitely escaping"),
        };
    }

    fn cloneCompactLoopStmtInto(
        self: *Cloner,
        stmt_id: Ast.StmtId,
        out: *std.ArrayList(Ast.StmtId),
        tail: BlockTail,
        result: CompactResult,
        demand: ValueDemand,
    ) LowerError!void {
        const stmt = self.pass.program.stmts.items[@intFromEnum(stmt_id)];
        switch (stmt) {
            .expr => try self.cloneStmtInto(stmt_id, out, tail, demand),
            .let_ => |let_| {
                if (exprAlwaysEscapesControlTransferDepth(self.pass.program, let_.value, 0, 0)) {
                    try out.append(self.pass.allocator, try self.addStmt(.{ .let_ = .{
                        .pat = try self.clonePat(let_.pat),
                        .value = try self.cloneCompactLoopBodyExpr(let_.value, result, demand),
                        .recursive = let_.recursive,
                        .comptime_site = let_.comptime_site,
                    } }));
                } else {
                    try self.cloneStmtInto(stmt_id, out, tail, demand);
                }
            },
            .return_ => |expr| try out.append(self.pass.allocator, try self.addStmt(.{
                .return_ = try self.cloneExpr(expr),
            })),
            else => try self.cloneStmtInto(stmt_id, out, tail, demand),
        }
    }

    fn cloneCompactLoopIfExpr(
        self: *Cloner,
        if_: anytype,
        result: CompactResult,
        demand: ValueDemand,
    ) LowerError!Ast.ExprId {
        const source_branches = try self.pass.allocator.dupe(Ast.IfBranch, self.pass.program.ifBranchSpan(if_.branches));
        defer self.pass.allocator.free(source_branches);

        const branches = try self.pass.allocator.alloc(Ast.IfBranch, source_branches.len);
        defer self.pass.allocator.free(branches);
        for (source_branches, branches) |branch, *out| {
            out.* = .{
                .cond = try self.cloneExpr(branch.cond),
                .body = try self.cloneCompactLoopBodyExpr(branch.body, result, demand),
            };
        }

        return try self.addExpr(.{ .ty = result.ty, .data = .{ .if_ = .{
            .branches = try self.pass.program.addIfBranchSpan(branches),
            .final_else = try self.cloneCompactLoopBodyExpr(if_.final_else, result, demand),
        } } });
    }

    fn cloneCompactLoopMatchExpr(
        self: *Cloner,
        match: anytype,
        result: CompactResult,
        demand: ValueDemand,
    ) LowerError!Ast.ExprId {
        const scrutinee_demand = try self.matchScrutineeDemand(match.branches, demand);
        const scrutinee = try self.materialize(try self.cloneExprValueWithDemand(match.scrutinee, scrutinee_demand));

        const source_branches = try self.pass.allocator.dupe(Ast.Branch, self.pass.program.branchSpan(match.branches));
        defer self.pass.allocator.free(source_branches);
        const branches = try self.pass.allocator.alloc(Ast.Branch, source_branches.len);
        defer self.pass.allocator.free(branches);
        for (source_branches, branches) |branch, *out| {
            const scoped_start = self.scopedLocalsLen();
            defer self.restoreScopedLocals(scoped_start);
            try self.appendPatternScopedLocals(branch.pat);
            out.* = .{
                .pat = try self.clonePat(branch.pat),
                .guard = if (branch.guard) |guard| try self.cloneExpr(guard) else null,
                .body = try self.cloneCompactLoopBodyExpr(branch.body, result, demand),
            };
        }

        return try self.addExpr(.{ .ty = result.ty, .data = .{ .match_ = .{
            .scrutinee = scrutinee,
            .branches = try self.pass.program.addBranchSpan(branches),
            .comptime_site = match.comptime_site,
        } } });
    }

    fn cloneCompactLoopLetExpr(
        self: *Cloner,
        let_: anytype,
        result: CompactResult,
        demand: ValueDemand,
    ) LowerError!Ast.ExprId {
        if (exprAlwaysEscapesControlTransferDepth(self.pass.program, let_.value, 0, 0)) {
            return try self.cloneCompactLoopBodyExpr(let_.value, result, demand);
        }
        if (exprContainsEscapingControlTransfer(self.pass.program, let_.value)) {
            return try self.addExpr(.{ .ty = result.ty, .data = .{ .let_ = .{
                .bind = try self.clonePat(let_.bind),
                .value = try self.cloneExpr(let_.value),
                .rest = try self.cloneCompactLoopBodyExpr(let_.rest, result, demand),
                .comptime_site = let_.comptime_site,
            } } });
        }

        const let_value = try self.cloneLetValueWithDemand(let_, demand);
        return try self.compactResultExpr(result, let_value);
    }

    fn compactResultForDemand(
        self: *Cloner,
        ty: Type.TypeId,
        demand: ValueDemand,
    ) LowerError!?CompactResult {
        return switch (demand) {
            .none,
            .materialize,
            => null,
            .loop_param => Common.invariant("loop result demand reference did not resolve before compact loop result construction"),
            else => {
                const demanded = (try demandedKnownValueFromDemand(
                    self,
                    self.pass.program,
                    self.pass.arena.allocator(),
                    .{ .any = ty },
                    demand,
                )) orelse return null;

                const compact_demanded = try self.compactDemandedKnownValue(demanded);

                var slot_tys = std.ArrayList(Type.TypeId).empty;
                defer slot_tys.deinit(self.pass.allocator);
                try self.appendCompactResultLeafTypes(compact_demanded, &slot_tys);

                const stored_slot_tys = try self.pass.arena.allocator().dupe(Type.TypeId, slot_tys.items);
                return try self.compactResultFromDemandedKnownValueWithSlots(compact_demanded, stored_slot_tys);
            },
        };
    }

    fn compactResultFromDemandedKnownValue(
        self: *Cloner,
        demanded: DemandedKnownValue,
    ) LowerError!CompactResult {
        const compact_demanded = try self.compactDemandedKnownValue(demanded);
        var slot_tys = std.ArrayList(Type.TypeId).empty;
        defer slot_tys.deinit(self.pass.allocator);
        try self.appendCompactResultLeafTypes(compact_demanded, &slot_tys);
        const stored_slot_tys = try self.pass.arena.allocator().dupe(Type.TypeId, slot_tys.items);
        return try self.compactResultFromDemandedKnownValueWithSlots(compact_demanded, stored_slot_tys);
    }

    fn compactDemandedKnownValue(self: *Cloner, known_value: DemandedKnownValue) Allocator.Error!DemandedKnownValue {
        return switch (known_value) {
            .any,
            .leaf,
            => known_value,
            .tag => |tag| .{ .tag = .{
                .ty = tag.ty,
                .name = tag.name,
                .payloads = try self.compactDemandedKnownIndexedValues(tag.payloads),
            } },
            .record => |record| blk: {
                const fields = try self.pass.arena.allocator().alloc(DemandedKnownField, record.fields.len);
                for (record.fields, fields) |field, *out| {
                    out.* = .{
                        .name = field.name,
                        .known_value = try self.compactDemandedKnownValue(field.known_value),
                    };
                }
                break :blk DemandedKnownValue{ .record = .{
                    .ty = record.ty,
                    .fields = fields,
                } };
            },
            .tuple => |tuple| .{ .tuple = .{
                .ty = tuple.ty,
                .items = try self.compactDemandedKnownIndexedValues(tuple.items),
            } },
            .nominal => |nominal| blk: {
                const backing = if (nominal.backing) |source| backing: {
                    const stored = try self.pass.arena.allocator().create(DemandedKnownValue);
                    stored.* = try self.compactDemandedKnownValue(source.*);
                    break :backing stored;
                } else null;
                break :blk DemandedKnownValue{ .nominal = .{
                    .ty = nominal.ty,
                    .backing = backing,
                } };
            },
            .callable => |callable| .{ .callable = .{
                .ty = callable.ty,
                .fn_id = callable.fn_id,
                .captures = try self.compactDemandedKnownIndexedValues(callable.captures),
            } },
            .finite_tags => |finite_tags| .{ .compact_finite_tags = try self.compactDemandedKnownTags(finite_tags) },
            .finite_callables => |finite_callables| .{ .compact_finite_callables = try self.compactDemandedKnownCallables(finite_callables) },
            .compact_finite_tags => |finite_tags| .{ .compact_finite_tags = try self.compactDemandedKnownTags(finite_tags) },
            .compact_finite_callables => |finite_callables| .{ .compact_finite_callables = try self.compactDemandedKnownCallables(finite_callables) },
        };
    }

    fn compactDemandedKnownIndexedValues(
        self: *Cloner,
        values: []const DemandedKnownIndexedValue,
    ) Allocator.Error![]const DemandedKnownIndexedValue {
        const copied = try self.pass.arena.allocator().alloc(DemandedKnownIndexedValue, values.len);
        for (values, copied) |value, *out| {
            out.* = .{
                .index = value.index,
                .known_value = try self.compactDemandedKnownValue(value.known_value),
            };
        }
        return copied;
    }

    fn compactDemandedKnownTags(self: *Cloner, finite_tags: DemandedKnownTags) Allocator.Error!DemandedKnownTags {
        const alternatives = try self.pass.arena.allocator().alloc(DemandedKnownTag, finite_tags.alternatives.len);
        for (finite_tags.alternatives, alternatives) |alternative, *out| {
            out.* = .{
                .ty = alternative.ty,
                .name = alternative.name,
                .payloads = try self.compactDemandedKnownIndexedValues(alternative.payloads),
            };
        }
        return .{
            .ty = finite_tags.ty,
            .alternatives = alternatives,
        };
    }

    fn compactDemandedKnownCallables(self: *Cloner, finite_callables: DemandedKnownCallables) Allocator.Error!DemandedKnownCallables {
        const alternatives = try self.pass.arena.allocator().alloc(DemandedKnownCallable, finite_callables.alternatives.len);
        for (finite_callables.alternatives, alternatives) |alternative, *out| {
            out.* = .{
                .ty = alternative.ty,
                .fn_id = alternative.fn_id,
                .captures = try self.compactDemandedKnownIndexedValues(alternative.captures),
            };
        }
        return .{
            .ty = finite_callables.ty,
            .alternatives = alternatives,
        };
    }

    fn compactResultFromDemandedKnownValueWithSlots(
        self: *Cloner,
        demanded: DemandedKnownValue,
        slot_tys: []const Type.TypeId,
    ) LowerError!CompactResult {
        return CompactResult{
            .known_value = demanded,
            .ty = try self.compactSlotTupleType(slot_tys),
            .slot_tys = slot_tys,
        };
    }

    fn appendCompactResultLeafTypes(
        self: *Cloner,
        known_value: DemandedKnownValue,
        out: *std.ArrayList(Type.TypeId),
    ) Allocator.Error!void {
        try self.pass.appendCompactValueTypes(known_value, out);
    }

    fn compactSlotTupleType(self: *Cloner, slot_tys: []const Type.TypeId) Allocator.Error!Type.TypeId {
        return switch (slot_tys.len) {
            0 => try self.unitType(),
            1 => slot_tys[0],
            else => try self.pass.program.types.add(.{
                .tuple = try self.pass.program.types.addSpan(slot_tys),
            }),
        };
    }

    fn unitType(self: *Cloner) Allocator.Error!Type.TypeId {
        return try self.pass.program.types.add(.{ .record = .empty() });
    }

    fn compactResultExpr(
        self: *Cloner,
        result: CompactResult,
        value: Value,
    ) LowerError!Ast.ExprId {
        switch (value) {
            .let_ => |let_value| {
                const scoped_start = self.scopedLocalsLen();
                defer self.restoreScopedLocals(scoped_start);
                try self.appendPendingLetScopedLocals(let_value.lets);

                const change_start = self.changes.items.len;
                defer self.restore(change_start);
                try self.bindPendingLetKnownValues(let_value.lets);

                const body = try self.compactResultExpr(result, let_value.body.*);
                return try self.wrapPendingLetsAroundExpr(result.ty, body, let_value.lets);
            },
            .if_ => |if_value| {
                const branches = try self.pass.allocator.alloc(Ast.IfBranch, if_value.branches.len);
                defer self.pass.allocator.free(branches);
                for (if_value.branches, branches) |branch, *out| {
                    out.* = .{
                        .cond = branch.cond,
                        .body = try self.compactResultExpr(result, branch.body),
                    };
                }
                return try self.addExpr(.{ .ty = result.ty, .data = .{ .if_ = .{
                    .branches = try self.pass.program.addIfBranchSpan(branches),
                    .final_else = try self.compactResultExpr(result, if_value.final_else.*),
                } } });
            },
            .match_ => |match_value| {
                const branches = try self.pass.allocator.alloc(Ast.Branch, match_value.branches.len);
                defer self.pass.allocator.free(branches);
                for (match_value.branches, branches) |branch, *out| {
                    const scoped_start = self.scopedLocalsLen();
                    defer self.restoreScopedLocals(scoped_start);
                    try self.appendPatternScopedLocals(branch.pat);
                    out.* = .{
                        .pat = branch.pat,
                        .guard = branch.guard,
                        .body = try self.compactResultExpr(result, branch.body),
                    };
                }
                return try self.addExpr(.{ .ty = result.ty, .data = .{ .match_ = .{
                    .scrutinee = match_value.scrutinee,
                    .branches = try self.pass.program.addBranchSpan(branches),
                    .comptime_site = match_value.comptime_site,
                } } });
            },
            else => {},
        }

        if (value == .expr and sameType(self.pass.program, self.pass.program.exprs.items[@intFromEnum(value.expr)].ty, result.ty)) {
            return value.expr;
        }
        if (value == .expr_with_known_value and sameType(self.pass.program, self.pass.program.exprs.items[@intFromEnum(value.expr_with_known_value.expr)].ty, result.ty)) {
            return value.expr_with_known_value.expr;
        }

        var leaf_exprs = std.ArrayList(Ast.ExprId).empty;
        defer leaf_exprs.deinit(self.pass.allocator);
        if (!try self.appendExprsFromCompactResult(result.known_value, value, &leaf_exprs)) {
            Common.invariant("optimized loop result could not be split into compact result leaves");
        }
        if (leaf_exprs.items.len != result.slot_tys.len) {
            Common.invariant("optimized loop result split produced the wrong leaf count");
        }
        return try self.compactLeafTupleExpr(result.ty, leaf_exprs.items);
    }

    fn appendExprsFromCompactResult(
        self: *Cloner,
        compact_known_value: DemandedKnownValue,
        value: Value,
        out: *std.ArrayList(Ast.ExprId),
    ) LowerError!bool {
        return try self.appendExprsFromDemandedKnownValue(compact_known_value, value, out);
    }

    fn compactLeafTupleExpr(
        self: *Cloner,
        ty: Type.TypeId,
        leaf_exprs: []const Ast.ExprId,
    ) LowerError!Ast.ExprId {
        return switch (leaf_exprs.len) {
            0 => try self.addExpr(.{ .ty = ty, .data = .unit }),
            1 => leaf_exprs[0],
            else => try self.addExpr(.{ .ty = ty, .data = .{
                .tuple = try self.pass.program.addExprSpan(leaf_exprs),
            } }),
        };
    }

    fn appendCompactSlotExprs(
        self: *Cloner,
        compact_expr: Ast.ExprId,
        slot_tys: []const Type.TypeId,
        out: *std.ArrayList(Ast.ExprId),
    ) LowerError!void {
        switch (slot_tys.len) {
            0 => {},
            1 => try out.append(self.pass.allocator, compact_expr),
            else => for (slot_tys, 0..) |slot_ty, index| {
                try out.append(self.pass.allocator, try self.addExpr(.{ .ty = slot_ty, .data = .{ .tuple_access = .{
                    .tuple = compact_expr,
                    .elem_index = @intCast(index),
                } } }));
            },
        }
    }

    fn privateStateValueFromCompactResult(
        self: *Cloner,
        result: CompactResult,
        compact_expr: Ast.ExprId,
    ) LowerError!PrivateStateValue {
        var leaf_exprs = std.ArrayList(Ast.ExprId).empty;
        defer leaf_exprs.deinit(self.pass.allocator);
        try self.appendCompactSlotExprs(compact_expr, result.slot_tys, &leaf_exprs);

        var index: usize = 0;
        const private_state = try self.privateStateValueFromDemandedKnownValueExprs(result.known_value, leaf_exprs.items, &index);
        if (index != leaf_exprs.items.len) {
            Common.invariant("compact loop result assembly did not consume every leaf");
        }
        return private_state;
    }

    fn privateStateValueFromDemandedKnownValueExprs(
        self: *Cloner,
        known_value: DemandedKnownValue,
        exprs: []const Ast.ExprId,
        index: *usize,
    ) LowerError!PrivateStateValue {
        return switch (known_value) {
            .any,
            .leaf,
            => |ty| blk: {
                if (index.* >= exprs.len) Common.invariant("compact loop result assembly ran out of leaves");
                const expr = exprs[index.*];
                index.* += 1;
                break :blk PrivateStateValue{ .leaf = .{
                    .ty = ty,
                    .expr = expr,
                } };
            },
            .tag => |tag| .{ .tag = .{
                .ty = tag.ty,
                .name = tag.name,
                .payloads = try self.privateStateIndexedValuesFromDemandedKnownValueExprs(tag.payloads, exprs, index),
            } },
            .record => |record| blk: {
                const fields = try self.pass.arena.allocator().alloc(PrivateStateField, record.fields.len);
                for (record.fields, fields) |field, *out| {
                    out.* = .{
                        .name = field.name,
                        .value = try self.privateStateValueFromDemandedKnownValueExprs(field.known_value, exprs, index),
                    };
                }
                break :blk PrivateStateValue{ .record = .{
                    .ty = record.ty,
                    .fields = fields,
                } };
            },
            .tuple => |tuple| .{ .tuple = .{
                .ty = tuple.ty,
                .items = try self.privateStateIndexedValuesFromDemandedKnownValueExprs(tuple.items, exprs, index),
            } },
            .nominal => |nominal| blk: {
                const backing = if (nominal.backing) |backing_known_value| backing: {
                    const stored = try self.pass.arena.allocator().create(PrivateStateValue);
                    stored.* = try self.privateStateValueFromDemandedKnownValueExprs(backing_known_value.*, exprs, index);
                    break :backing stored;
                } else null;
                break :blk PrivateStateValue{ .nominal = .{
                    .ty = nominal.ty,
                    .backing = backing,
                } };
            },
            .callable => |callable| .{ .callable = .{
                .ty = callable.ty,
                .fn_id = callable.fn_id,
                .captures = try self.privateStateIndexedValuesFromDemandedKnownValueExprs(callable.captures, exprs, index),
            } },
            .finite_tags,
            .compact_finite_tags,
            => |finite_tags| blk: {
                if (index.* >= exprs.len) Common.invariant("compact finite tag result had no compact slot");
                const compact_expr = exprs[index.*];
                index.* += 1;
                break :blk PrivateStateValue{ .compact_finite_tags = .{
                    .source = finite_tags,
                    .compact_expr = compact_expr,
                } };
            },
            .finite_callables,
            .compact_finite_callables,
            => |finite_callables| blk: {
                if (index.* >= exprs.len) Common.invariant("compact finite callable result had no compact slot");
                const compact_expr = exprs[index.*];
                index.* += 1;
                break :blk PrivateStateValue{ .compact_finite_callables = .{
                    .source = finite_callables,
                    .compact_expr = compact_expr,
                } };
            },
        };
    }

    fn privateStateIndexedValuesFromDemandedKnownValueExprs(
        self: *Cloner,
        known_values: []const DemandedKnownIndexedValue,
        exprs: []const Ast.ExprId,
        index: *usize,
    ) LowerError![]const PrivateStateIndexedValue {
        const values = try self.pass.arena.allocator().alloc(PrivateStateIndexedValue, known_values.len);
        for (known_values, values) |known_value, *out| {
            out.* = .{
                .index = known_value.index,
                .value = try self.privateStateValueFromDemandedKnownValueExprs(known_value.known_value, exprs, index),
            };
        }
        return values;
    }

    fn cloneStateLoopFromDemandedKnownValues(
        self: *Cloner,
        ty: Type.TypeId,
        loop: anytype,
        params: []const Ast.TypedLocal,
        values: []const Value,
        known_values: []DemandedKnownValue,
        demands: []ValueDemand,
        result_demand: ValueDemand,
    ) LowerError!Value {
        const compact_result = try self.compactResultForDemand(ty, result_demand);
        const state_loop_ty = if (compact_result) |result| result.ty else ty;

        var state_loop_iterations: usize = 0;
        while (true) {
            state_loop_iterations += 1;
            if (state_loop_iterations > 1000) Common.invariant("state loop demand feedback did not converge");

            const state_start_len = self.pass.program.state_loop_states.items.len;
            const state_start: u32 = @intCast(state_start_len);
            var states = std.ArrayList(SparseStateLoopState).empty;
            defer states.deinit(self.pass.allocator);

            var state_demands_changed = false;
            var provenance = std.ArrayList(LoopLocalProvenance).empty;
            defer provenance.deinit(self.pass.allocator);

            try self.state_loop_stack.append(self.pass.allocator, .{
                .params = params,
                .values = values,
                .states = &states,
                .demands = demands,
                .result_demand = result_demand,
                .compact_result = compact_result,
                .provenance = &provenance,
                .changed = &state_demands_changed,
            });
            errdefer _ = self.state_loop_stack.pop();

            const demanded_entry_values = try self.pass.allocator.alloc(Value, values.len);
            defer self.pass.allocator.free(demanded_entry_values);
            for (values, demands, demanded_entry_values) |value, demand, *out| {
                out.* = try self.applyValueDemand(value, demand);
            }

            // State identity and entry split are a paired output of applying
            // the normalized demand to the original entry value: when the
            // demanded entry is sparse private state, the state key set is
            // derived from that exact private shape, in this loop's own
            // demand-reference resolution context.
            for (demanded_entry_values, known_values) |demanded_entry, *known_value| {
                if (demanded_entry == .private_state) {
                    known_value.* = try self.demandedKnownValueFromPrivateStateLoopStateShape(demanded_entry.private_state);
                }
            }

            const state_keys = try demandedKnownValueProducts(self.pass.allocator, self.pass.arena.allocator(), known_values);
            for (state_keys) |state_values| {
                if (state_values.len != params.len) Common.invariant("state_loop key arity differed from loop params");
                _ = try self.appendSparseState(&states, state_values);
            }

            var entry_state_index: ?usize = null;
            for (state_keys, 0..) |state_values, index| {
                if (!demandedKnownValuesMatchValues(self.pass.program, state_values, demanded_entry_values)) continue;
                if (entry_state_index != null) Common.invariant("state_loop edge matched multiple states");
                entry_state_index = index;
            }
            const selected_entry_state_index = entry_state_index orelse {
                _ = self.state_loop_stack.pop();
                self.pass.program.state_loop_states.shrinkRetainingCapacity(state_start_len);
                if (compact_result != null) Common.invariant("optimized loop private result could not select an entry state");
                const initial_span = (try self.valuesToOutputExprSpan(values)) orelse
                    Common.invariant("optimized loop entry values could neither select a state nor be emitted as ordinary loop initials");
                return .{ .expr = try self.addExpr(.{ .ty = ty, .data = .{ .loop_ = .{
                    .params = loop.params,
                    .initial_values = initial_span,
                    .body = try self.cloneExpr(loop.body),
                } } }) };
            };

            const entry_state = states.items[selected_entry_state_index];

            var entry_values = std.ArrayList(Ast.ExprId).empty;
            defer entry_values.deinit(self.pass.allocator);
            var entry_pending_lets = std.ArrayList(PendingLet).empty;
            defer entry_pending_lets.deinit(self.pass.allocator);
            for (entry_state.values, demanded_entry_values) |known_value, value| {
                if (!try self.appendExprsFromDemandedKnownValueCollectingLets(known_value, value, &entry_values, &entry_pending_lets)) {
                    Common.invariant("state_loop initial value could not be split into entry state params");
                }
            }

            var state_index: usize = 0;
            while (state_index < states.items.len) : (state_index += 1) {
                const state = states.items[state_index];
                provenance.clearRetainingCapacity();

                const change_start = self.changes.items.len;
                var state_params = std.ArrayList(Ast.TypedLocal).empty;
                defer state_params.deinit(self.pass.allocator);
                defer self.restore(change_start);

                for (params, state.values) |param, known_value| {
                    var path = std.ArrayList(DemandPathStep).empty;
                    defer path.deinit(self.pass.allocator);
                    const private_state = try self.privateStateValueFromDemandedKnownValueLoopParamArgs(
                        known_value,
                        &state_params,
                        param.local,
                        &path,
                        &provenance,
                    );
                    try self.putSubst(param.local, .{ .private_state = private_state });
                }

                const state_params_span = try self.pass.program.addTypedLocalSpan(state_params.items);
                try self.state_param_stack.append(self.pass.allocator, state_params.items);
                defer _ = self.state_param_stack.pop();
                const maybe_state_body: ?Ast.ExprId = self.cloneStateLoopBodyExpr(loop.body, compact_result, result_demand) catch |err| switch (err) {
                    error.LoopStateDemandGrew => blk: {
                        if (!state_demands_changed) return err;
                        break :blk null;
                    },
                    else => |other| return other,
                };
                const state_body = maybe_state_body orelse break;

                if (state_demands_changed) break;

                self.pass.program.state_loop_states.items[@intFromEnum(state.id)] = .{
                    .params = state_params_span,
                    .body = state_body,
                };
            }

            if (state_demands_changed) {
                const closed_demands = try self.pass.allocator.alloc(ValueDemand, demands.len);
                defer self.pass.allocator.free(closed_demands);
                for (demands, closed_demands) |demand, *closed| {
                    closed.* = try self.closeLoopDemandRefs(demand);
                }
                self.pass.program.state_loop_states.shrinkRetainingCapacity(state_start_len);
                _ = self.state_loop_stack.pop();
                try self.refreshDemandedKnownValuesFromValueDemands(values, closed_demands, known_values);
                continue;
            }

            _ = self.state_loop_stack.pop();

            const state_span: Ast.Span(Ast.StateLoopState) = .{
                .start = state_start,
                .len = @intCast(states.items.len),
            };
            const state_loop_expr = try self.addExpr(.{ .ty = state_loop_ty, .data = .{ .state_loop = .{
                .entry_state = entry_state.id,
                .entry_values = try self.pass.program.addExprSpan(entry_values.items),
                .states = state_span,
            } } });
            const entry_expr = try self.blockPendingLetsAroundExpr(state_loop_ty, state_loop_expr, entry_pending_lets.items);
            if (compact_result) |result| {
                const result_local = try self.pass.program.addLocal(self.pass.symbols.fresh(), state_loop_ty);
                const result_local_expr = try self.addExpr(.{
                    .ty = state_loop_ty,
                    .data = .{ .local = result_local },
                });
                const private_result = try self.privateStateValueFromCompactResult(result, result_local_expr);
                const pending = [_]PendingLet{.{
                    .local = result_local,
                    .ty = state_loop_ty,
                    .value = .{ .cloned = entry_expr },
                }};
                return try self.wrapPendingLets(.{ .private_state = private_result }, &pending, false);
            }
            return .{ .expr = entry_expr };
        }
    }

    fn cloneStateLoopBodyExpr(
        self: *Cloner,
        body: Ast.ExprId,
        compact_result: ?CompactResult,
        result_demand: ValueDemand,
    ) LowerError!Ast.ExprId {
        if (compact_result) |result| return try self.cloneCompactLoopBodyExpr(body, result, result_demand);
        return try self.materialize(try self.cloneExprValueWithDemand(body, result_demand));
    }

    fn knownValueProducts(self: *Cloner, known_values: []const KnownValue) Allocator.Error![]const []const KnownValue {
        const options = try self.pass.allocator.alloc([]const KnownValue, known_values.len);
        defer self.pass.allocator.free(options);
        for (known_values, 0..) |known_value, index| {
            options[index] = try self.expandKnownValue(known_value);
        }

        var products = std.ArrayList([]const KnownValue).empty;
        defer products.deinit(self.pass.allocator);
        const current = try self.pass.allocator.alloc(KnownValue, known_values.len);
        defer self.pass.allocator.free(current);

        try self.appendKnownValueProducts(options, 0, current, &products);
        return try self.pass.arena.allocator().dupe([]const KnownValue, products.items);
    }

    fn appendKnownValueProducts(
        self: *Cloner,
        options: []const []const KnownValue,
        index: usize,
        current: []KnownValue,
        products: *std.ArrayList([]const KnownValue),
    ) Allocator.Error!void {
        if (index == options.len) {
            try products.append(self.pass.allocator, try self.pass.arena.allocator().dupe(KnownValue, current));
            return;
        }

        for (options[index]) |option| {
            current[index] = option;
            try self.appendKnownValueProducts(options, index + 1, current, products);
        }
    }

    fn expandKnownValue(self: *Cloner, known_value: KnownValue) Allocator.Error![]const KnownValue {
        return switch (known_value) {
            .any,
            .leaf,
            => try self.singleKnownValue(known_value),
            .tag => |tag| try self.expandKnownTag(tag),
            .record => |record| try self.expandKnownRecord(record),
            .tuple => |tuple| try self.expandKnownTuple(tuple),
            .nominal => |nominal| try self.expandKnownNominal(nominal),
            .callable => |callable| try self.expandKnownCallable(callable),
            .finite_tags => |finite_tags| try self.expandKnownTags(finite_tags),
            .finite_callables => |finite_callables| try self.expandKnownCallables(finite_callables),
        };
    }

    fn singleKnownValue(self: *Cloner, known_value: KnownValue) Allocator.Error![]const KnownValue {
        const values = try self.pass.arena.allocator().alloc(KnownValue, 1);
        values[0] = known_value;
        return values;
    }

    fn expandKnownRecord(self: *Cloner, record: KnownRecord) Allocator.Error![]const KnownValue {
        const child_values = try self.pass.allocator.alloc(KnownValue, record.fields.len);
        defer self.pass.allocator.free(child_values);
        for (record.fields, 0..) |field, index| {
            child_values[index] = field.known_value;
        }

        const products = try self.knownValueProducts(child_values);
        const alternatives = try self.pass.arena.allocator().alloc(KnownValue, products.len);
        for (products, alternatives) |product, *out| {
            const fields = try self.pass.arena.allocator().alloc(KnownField, record.fields.len);
            for (record.fields, product, fields) |field, field_known_value, *field_out| {
                field_out.* = .{
                    .name = field.name,
                    .known_value = field_known_value,
                };
            }
            out.* = .{ .record = .{
                .ty = record.ty,
                .fields = fields,
            } };
        }
        return alternatives;
    }

    fn expandKnownTuple(self: *Cloner, tuple: KnownTuple) Allocator.Error![]const KnownValue {
        const products = try self.knownValueProducts(tuple.items);
        const alternatives = try self.pass.arena.allocator().alloc(KnownValue, products.len);
        for (products, alternatives) |product, *out| {
            out.* = .{ .tuple = .{
                .ty = tuple.ty,
                .items = product,
            } };
        }
        return alternatives;
    }

    fn expandKnownNominal(self: *Cloner, nominal: KnownNominal) Allocator.Error![]const KnownValue {
        const backing_alternatives = try self.expandKnownValue(nominal.backing.*);
        const alternatives = try self.pass.arena.allocator().alloc(KnownValue, backing_alternatives.len);
        for (backing_alternatives, alternatives) |backing, *out| {
            const stored = try self.pass.arena.allocator().create(KnownValue);
            stored.* = backing;
            out.* = .{ .nominal = .{
                .ty = nominal.ty,
                .backing = stored,
            } };
        }
        return alternatives;
    }

    fn expandKnownTag(self: *Cloner, tag: KnownTag) Allocator.Error![]const KnownValue {
        const products = try self.knownValueProducts(tag.payloads);
        const alternatives = try self.pass.arena.allocator().alloc(KnownValue, products.len);
        for (products, alternatives) |product, *out| {
            out.* = .{ .tag = .{
                .ty = tag.ty,
                .name = tag.name,
                .payloads = product,
            } };
        }
        return alternatives;
    }

    fn expandKnownTags(self: *Cloner, finite_tags: KnownTags) Allocator.Error![]const KnownValue {
        var alternatives = std.ArrayList(KnownValue).empty;
        defer alternatives.deinit(self.pass.allocator);
        for (finite_tags.alternatives) |tag| {
            const expanded = try self.expandKnownTag(tag);
            try alternatives.appendSlice(self.pass.allocator, expanded);
        }
        return try self.pass.arena.allocator().dupe(KnownValue, alternatives.items);
    }

    fn expandKnownCallable(self: *Cloner, callable: KnownCallable) Allocator.Error![]const KnownValue {
        const products = try self.knownValueProducts(callable.captures);
        const alternatives = try self.pass.arena.allocator().alloc(KnownValue, products.len);
        for (products, alternatives) |product, *out| {
            out.* = .{ .callable = .{
                .ty = callable.ty,
                .fn_id = callable.fn_id,
                .captures = product,
            } };
        }
        return alternatives;
    }

    fn expandKnownCallables(self: *Cloner, finite_callables: KnownCallables) Allocator.Error![]const KnownValue {
        var alternatives = std.ArrayList(KnownValue).empty;
        defer alternatives.deinit(self.pass.allocator);
        for (finite_callables.alternatives) |callable| {
            const expanded = try self.expandKnownCallable(callable);
            try alternatives.appendSlice(self.pass.allocator, expanded);
        }
        return try self.pass.arena.allocator().dupe(KnownValue, alternatives.items);
    }

    fn stateForDemandedKnownValues(self: *Cloner, states: []const SparseStateLoopState, values: []const DemandedKnownValue) ?SparseStateLoopState {
        var found: ?SparseStateLoopState = null;
        for (states) |state| {
            if (!demandedKnownValuesEql(self.pass.program, state.values, values)) continue;
            if (found != null) Common.invariant("state_loop key matched multiple states");
            found = state;
        }
        return found;
    }

    fn appendSparseState(
        self: *Cloner,
        states: *std.ArrayList(SparseStateLoopState),
        values: []const DemandedKnownValue,
    ) Allocator.Error!SparseStateLoopState {
        const id: Ast.StateLoopStateId = @enumFromInt(@as(u32, @intCast(self.pass.program.state_loop_states.items.len)));
        try self.pass.program.state_loop_states.append(self.pass.program.allocator, undefined);
        const state = SparseStateLoopState{
            .id = id,
            .values = values,
        };
        try states.append(self.pass.allocator, state);
        return state;
    }

    fn demandedStateValuesFromValues(
        self: *Cloner,
        demands: []const ValueDemand,
        values: []const Value,
    ) LowerError![]const DemandedKnownValue {
        if (demands.len != values.len) Common.invariant("state_loop demand arity differed from continue values");
        const demanded_values = try self.pass.arena.allocator().alloc(DemandedKnownValue, values.len);
        try self.refreshDemandedKnownValuesFromValueDemands(values, demands, demanded_values);
        for (demanded_values) |*demanded| {
            demanded.* = try self.compactDemandedKnownValue(demanded.*);
        }
        return demanded_values;
    }

    fn refreshDemandedKnownValuesFromValueDemands(
        self: *Cloner,
        values: []const Value,
        demands: []const ValueDemand,
        out_values: []DemandedKnownValue,
    ) LowerError!void {
        if (demands.len != values.len or out_values.len != values.len) {
            Common.invariant("state_loop demand/value arity differed while refreshing demanded state");
        }
        for (demands, values, out_values) |demand, value, *out| {
            const ty = valueType(self.pass.program, value);
            const demanded = try self.demandedKnownValueFromLoopStateValueDemand(value, demand);
            out.* = demanded orelse blk: {
                break :blk DemandedKnownValue{ .any = ty };
            };
        }
    }

    fn demandedKnownValueFromLoopStateValueDemand(
        self: *Cloner,
        value: Value,
        demand: ValueDemand,
    ) LowerError!?DemandedKnownValue {
        if (try self.demandedKnownValueFromValueDemand(value, demand)) |demanded| {
            return demanded;
        }

        if (value == .private_state) {
            return try self.demandedKnownValueFromPrivateStateLoopStateShape(value.private_state);
        }

        if (self.valueCanMaterializePublic(value)) return null;

        const private_state = (try self.privateStateValueFromValueDemand(value, .materialize)) orelse return null;
        return try self.demandedKnownValueFromPrivateStateLoopStateShape(private_state);
    }

    fn demandedKnownValueFromValueDemand(
        self: *Cloner,
        value: Value,
        demand: ValueDemand,
    ) LowerError!?DemandedKnownValue {
        if (try self.demandedKnownValueFromAvailableValueDemand(value, demand)) |demanded| {
            return demanded;
        }

        if (try self.pass.knownValueFromValue(value)) |known_value| {
            return try demandedKnownValueFromDemand(self, self.pass.program, self.pass.arena.allocator(), known_value, demand);
        }

        return null;
    }

    fn demandedKnownValueFromAvailableValueDemand(
        self: *Cloner,
        value: Value,
        demand: ValueDemand,
    ) LowerError!?DemandedKnownValue {
        if (value == .private_state) {
            return try self.demandedKnownValueFromPrivateStateDemand(value.private_state, demand);
        }

        switch (value) {
            .let_,
            .if_,
            .match_,
            => {
                if (try self.privateStateValueFromValueDemand(value, demand)) |private_state| {
                    if (try self.demandedKnownValueFromPrivateStateDemand(private_state, demand)) |demanded| {
                        return demanded;
                    }
                }
            },
            else => {},
        }

        if (valueDemandRequiresPrivateState(demand)) {
            if (try self.privateStateValueFromValueDemand(value, demand)) |private_state| {
                if (try self.demandedKnownValueFromPrivateStateDemand(private_state, demand)) |demanded| {
                    return demanded;
                }
            }
        }

        if (value == .callable) {
            if (try self.demandedKnownValueFromCallableValueDemand(value.callable, demand)) |demanded| {
                return demanded;
            }
        }

        if (value == .record) {
            if (try self.demandedKnownValueFromRecordValueDemand(value.record, demand)) |demanded| {
                return demanded;
            }
        }

        const private_state = (try self.privateStateValueFromValueDemand(value, demand)) orelse return null;
        return try self.demandedKnownValueFromPrivateStateDemand(private_state, demand);
    }

    fn demandedKnownValueFromCallableValueDemand(
        self: *Cloner,
        callable: CallableValue,
        demand: ValueDemand,
    ) LowerError!?DemandedKnownValue {
        const resolved_demand = self.resolveLoopDemandRef(demand);
        const capture_demands = switch (resolved_demand) {
            .none => return null,
            .materialize => captures: {
                const captures = try self.pass.arena.allocator().alloc(ValueDemand, callable.captures.len);
                @memset(captures, .materialize);
                break :captures captures;
            },
            .callable => |callable_demand| captures: {
                var effective = callable_demand;
                if (callable_demand.result) |result_demand| {
                    const derived = try self.callableDemandForCallableValueWithResultDemand(callable, result_demand.*);
                    if (derived == .callable) {
                        const merged = try self.mergeValueDemand(.{ .callable = effective }, derived);
                        if (merged == .callable) effective = merged.callable;
                    }
                }
                break :captures effective.captures;
            },
            .loop_param => Common.invariant("loop demand reference did not resolve before demanded-known callable conversion"),
            .fn_param => Common.invariant("function demand reference did not resolve before demanded-known callable conversion"),
            .record,
            .tuple,
            .tag,
            .nominal,
            => return null,
        };

        var captures = std.ArrayList(DemandedKnownIndexedValue).empty;
        defer captures.deinit(self.pass.allocator);
        for (capture_demands, 0..) |capture_demand, index| {
            if (capture_demand == .none) continue;
            if (index >= callable.captures.len) {
                Common.invariant("callable value demand capture index exceeded capture count");
            }
            const capture_value = callable.captures[index];
            const demanded_capture = (try self.demandedKnownValueFromValueDemand(capture_value, capture_demand)) orelse
                DemandedKnownValue{ .any = valueType(self.pass.program, capture_value) };
            try captures.append(self.pass.allocator, .{
                .index = @intCast(index),
                .known_value = demanded_capture,
            });
        }

        return .{ .callable = .{
            .ty = callable.ty,
            .fn_id = callable.fn_id,
            .captures = try self.pass.arena.allocator().dupe(DemandedKnownIndexedValue, captures.items),
        } };
    }

    fn demandedKnownValueFromRecordValueDemand(
        self: *Cloner,
        record: RecordValue,
        demand: ValueDemand,
    ) LowerError!?DemandedKnownValue {
        const resolved_demand = self.resolveLoopDemandRef(demand);
        var fields = std.ArrayList(DemandedKnownField).empty;
        defer fields.deinit(self.pass.allocator);

        switch (resolved_demand) {
            .none => return null,
            .materialize => {
                for (record.fields) |field| {
                    const demanded_field = (try self.demandedKnownValueFromValueDemand(field.value, .materialize)) orelse
                        DemandedKnownValue{ .any = valueType(self.pass.program, field.value) };
                    try fields.append(self.pass.allocator, .{
                        .name = field.name,
                        .known_value = demanded_field,
                    });
                }
            },
            .record => |field_demands| {
                for (field_demands) |field_demand| {
                    if (field_demand.demand.* == .none) continue;
                    const field_value = fieldFromRecord(self.pass.program, record, field_demand.name) orelse return null;
                    const demanded_field = (try self.demandedKnownValueFromValueDemand(field_value, field_demand.demand.*)) orelse
                        DemandedKnownValue{ .any = valueType(self.pass.program, field_value) };
                    try fields.append(self.pass.allocator, .{
                        .name = field_demand.name,
                        .known_value = demanded_field,
                    });
                }
            },
            .loop_param => Common.invariant("loop demand reference did not resolve before demanded-known record conversion"),
            .fn_param => Common.invariant("function demand reference did not resolve before demanded-known record conversion"),
            .tuple,
            .tag,
            .nominal,
            .callable,
            => return null,
        }

        if (fields.items.len == 0) return null;
        return .{ .record = .{
            .ty = record.ty,
            .fields = try self.pass.arena.allocator().dupe(DemandedKnownField, fields.items),
        } };
    }

    fn demandedKnownValueFromPrivateStateDemand(
        self: *Cloner,
        value: PrivateStateValue,
        demand: ValueDemand,
    ) LowerError!?DemandedKnownValue {
        self.demanded_known_depth += 1;
        defer self.demanded_known_depth -= 1;
        if (self.demanded_known_depth > 1000) Common.invariant("private-state demanded-known derivation did not converge");

        const resolved_demand = self.resolveLoopDemandRef(demand);
        if (value == .leaf) {
            return switch (resolved_demand) {
                .none => null,
                else => DemandedKnownValue{ .leaf = value.leaf.ty },
            };
        }

        switch (value) {
            .nominal => |nominal| {
                const backing = nominal.backing orelse return null;
                const backing_demand = switch (resolved_demand) {
                    .nominal => |nominal_demand| nominal_demand.*,
                    else => resolved_demand,
                };
                const demanded_backing = (try self.demandedKnownValueFromPrivateStateDemand(backing.*, backing_demand)) orelse return null;
                const stored = try self.pass.arena.allocator().create(DemandedKnownValue);
                stored.* = demanded_backing;
                return .{ .nominal = .{
                    .ty = nominal.ty,
                    .backing = stored,
                } };
            },
            else => {},
        }

        return switch (resolved_demand) {
            .none => null,
            .materialize => try self.demandedKnownValueFromPrivateStateShape(value),
            .loop_param => Common.invariant("loop demand reference did not resolve before demanded-known private-state conversion"),
            .fn_param => Common.invariant("function demand reference did not resolve before demanded-known private-state conversion"),
            .nominal => null,
            .record => |field_demands| blk: {
                const record = switch (value) {
                    .record => |record| record,
                    else => break :blk null,
                };

                var fields = std.ArrayList(DemandedKnownField).empty;
                defer fields.deinit(self.pass.allocator);
                for (field_demands) |field_demand| {
                    if (field_demand.demand.* == .none) continue;
                    const field_value = privateStateFieldByName(self.pass.program, record.fields, field_demand.name) orelse break :blk null;
                    const demanded_field = (try self.demandedKnownValueFromPrivateStateDemand(field_value, field_demand.demand.*)) orelse break :blk null;
                    try fields.append(self.pass.allocator, .{
                        .name = field_demand.name,
                        .known_value = demanded_field,
                    });
                }
                if (fields.items.len == 0) break :blk null;
                break :blk DemandedKnownValue{ .record = .{
                    .ty = record.ty,
                    .fields = try self.pass.arena.allocator().dupe(DemandedKnownField, fields.items),
                } };
            },
            .tuple => |item_demands| blk: {
                const tuple = switch (value) {
                    .tuple => |tuple| tuple,
                    else => break :blk null,
                };

                const items = (try self.demandedKnownIndexedValuesFromPrivateStateItemDemands(tuple.items, item_demands)) orelse break :blk null;
                if (items.len == 0) break :blk null;
                break :blk DemandedKnownValue{ .tuple = .{
                    .ty = tuple.ty,
                    .items = items,
                } };
            },
            .tag => |tag_demand| blk: {
                if (value == .compact_finite_tags) {
                    const source_known = try knownValueFromDemandedKnownValue(
                        self.pass.program,
                        self.pass.arena.allocator(),
                        .{ .finite_tags = value.compact_finite_tags.source },
                    );
                    break :blk try demandedKnownValueFromDemand(
                        self,
                        self.pass.program,
                        self.pass.arena.allocator(),
                        source_known,
                        .{ .tag = tag_demand },
                    );
                }

                const tag = switch (value) {
                    .tag => |tag| tag,
                    else => break :blk null,
                };
                const payload_demands = if (tagAlternativeDemandByName(self.pass.program, tag_demand.alternatives, tag.name)) |alternative|
                    alternative.payloads
                else
                    &.{};
                break :blk DemandedKnownValue{ .tag = .{
                    .ty = tag.ty,
                    .name = tag.name,
                    .payloads = (try self.demandedKnownIndexedValuesFromPrivateStateItemDemands(tag.payloads, payload_demands)) orelse break :blk null,
                } };
            },
            .callable => |callable_demand| blk: {
                var effective_callable_demand = callable_demand;
                if (callable_demand.result) |result_demand| {
                    if (try self.callableDemandForPrivateStateValueWithResultDemand(value, result_demand.*)) |derived| {
                        const merged = try self.mergeValueDemand(.{ .callable = effective_callable_demand }, derived);
                        if (merged != .callable) break :blk null;
                        effective_callable_demand = merged.callable;
                    }
                    if (privateStateCallable(value)) |private_callable| {
                        if (private_callable.captures.len > 0) {
                            const finite_identity_demand = try self.finiteStateIdentityDemandFromPrivateCallable(private_callable);
                            if (finite_identity_demand == .callable) {
                                const merged = try self.mergeValueDemand(.{ .callable = effective_callable_demand }, finite_identity_demand);
                                if (merged != .callable) break :blk null;
                                effective_callable_demand = merged.callable;
                            }
                        }
                    }
                    if (value == .compact_finite_callables) {
                        const alternative_demand = try self.finiteStateIdentityDemandFromPrivateState(value);
                        if (alternative_demand == .callable) {
                            const merged = try self.mergeValueDemand(.{ .callable = effective_callable_demand }, alternative_demand);
                            if (merged != .callable) break :blk null;
                            effective_callable_demand = merged.callable;
                        }
                    }
                }

                if (value == .compact_finite_callables) {
                    const source_known = try knownValueFromDemandedKnownValue(
                        self.pass.program,
                        self.pass.arena.allocator(),
                        .{ .finite_callables = value.compact_finite_callables.source },
                    );
                    break :blk try demandedKnownValueFromDemand(
                        self,
                        self.pass.program,
                        self.pass.arena.allocator(),
                        source_known,
                        .{ .callable = effective_callable_demand },
                    );
                }

                const callable = switch (value) {
                    .callable => |callable| callable,
                    else => break :blk null,
                };
                break :blk DemandedKnownValue{ .callable = .{
                    .ty = callable.ty,
                    .fn_id = callable.fn_id,
                    .captures = (try self.demandedKnownIndexedValuesFromPrivateStateCallableCaptureDemands(callable, effective_callable_demand.captures)) orelse break :blk null,
                } };
            },
        };
    }

    fn demandedKnownValueFromPrivateStateShape(
        self: *Cloner,
        value: PrivateStateValue,
    ) Allocator.Error!DemandedKnownValue {
        return switch (value) {
            .leaf => |leaf| .{ .leaf = leaf.ty },
            .record => |record| blk: {
                const fields = try self.pass.arena.allocator().alloc(DemandedKnownField, record.fields.len);
                for (record.fields, fields) |field, *out| {
                    out.* = .{
                        .name = field.name,
                        .known_value = try self.demandedKnownValueFromPrivateStateShape(field.value),
                    };
                }
                break :blk DemandedKnownValue{ .record = .{
                    .ty = record.ty,
                    .fields = fields,
                } };
            },
            .tuple => |tuple| .{ .tuple = .{
                .ty = tuple.ty,
                .items = try self.demandedKnownIndexedValuesFromPrivateStateShape(tuple.items),
            } },
            .tag => |tag| .{ .tag = .{
                .ty = tag.ty,
                .name = tag.name,
                .payloads = try self.demandedKnownIndexedValuesFromPrivateStateShape(tag.payloads),
            } },
            .nominal => |nominal| blk: {
                const backing = if (nominal.backing) |private_backing| backing: {
                    const stored = try self.pass.arena.allocator().create(DemandedKnownValue);
                    stored.* = try self.demandedKnownValueFromPrivateStateShape(private_backing.*);
                    break :backing stored;
                } else null;
                break :blk DemandedKnownValue{ .nominal = .{
                    .ty = nominal.ty,
                    .backing = backing,
                } };
            },
            .callable => |callable| .{ .callable = .{
                .ty = callable.ty,
                .fn_id = callable.fn_id,
                .captures = try self.demandedKnownIndexedValuesFromPrivateStateShape(callable.captures),
            } },
            .compact_finite_tags => |finite_tags| .{ .finite_tags = finite_tags.source },
            .compact_finite_callables => |finite_callables| .{ .finite_callables = finite_callables.source },
        };
    }

    fn demandedKnownValueFromPrivateStateLoopStateShape(
        self: *Cloner,
        value: PrivateStateValue,
    ) Allocator.Error!DemandedKnownValue {
        return switch (value) {
            .leaf => |leaf| .{ .leaf = leaf.ty },
            .record => |record| blk: {
                const fields = try self.pass.arena.allocator().alloc(DemandedKnownField, record.fields.len);
                for (record.fields, fields) |field, *out| {
                    out.* = .{
                        .name = field.name,
                        .known_value = try self.demandedKnownValueFromPrivateStateLoopStateShape(field.value),
                    };
                }
                break :blk DemandedKnownValue{ .record = .{
                    .ty = record.ty,
                    .fields = fields,
                } };
            },
            .tuple => |tuple| .{ .tuple = .{
                .ty = tuple.ty,
                .items = try self.demandedKnownIndexedValuesFromPrivateStateLoopStateShape(tuple.items),
            } },
            .tag => |tag| .{ .tag = .{
                .ty = tag.ty,
                .name = tag.name,
                .payloads = try self.demandedKnownIndexedValuesFromPrivateStateLoopStateShape(tag.payloads),
            } },
            .nominal => |nominal| blk: {
                const backing = if (nominal.backing) |private_backing| backing: {
                    const stored = try self.pass.arena.allocator().create(DemandedKnownValue);
                    stored.* = try self.demandedKnownValueFromPrivateStateLoopStateShape(private_backing.*);
                    break :backing stored;
                } else null;
                break :blk DemandedKnownValue{ .nominal = .{
                    .ty = nominal.ty,
                    .backing = backing,
                } };
            },
            .callable => |callable| .{ .callable = .{
                .ty = callable.ty,
                .fn_id = callable.fn_id,
                .captures = try self.demandedKnownIndexedValuesFromPrivateStateLoopStateShape(callable.captures),
            } },
            .compact_finite_tags => |finite_tags| .{ .compact_finite_tags = finite_tags.source },
            .compact_finite_callables => |finite_callables| .{ .compact_finite_callables = finite_callables.source },
        };
    }

    fn demandedKnownIndexedValuesFromPrivateStateShape(
        self: *Cloner,
        values: []const PrivateStateIndexedValue,
    ) Allocator.Error![]const DemandedKnownIndexedValue {
        const out = try self.pass.arena.allocator().alloc(DemandedKnownIndexedValue, values.len);
        for (values, out) |value, *out_value| {
            out_value.* = .{
                .index = value.index,
                .known_value = try self.demandedKnownValueFromPrivateStateShape(value.value),
            };
        }
        return out;
    }

    fn demandedKnownIndexedValuesFromPrivateStateLoopStateShape(
        self: *Cloner,
        values: []const PrivateStateIndexedValue,
    ) Allocator.Error![]const DemandedKnownIndexedValue {
        const out = try self.pass.arena.allocator().alloc(DemandedKnownIndexedValue, values.len);
        for (values, out) |value, *out_value| {
            out_value.* = .{
                .index = value.index,
                .known_value = try self.demandedKnownValueFromPrivateStateLoopStateShape(value.value),
            };
        }
        return out;
    }

    fn demandedKnownIndexedValuesFromPrivateStateItemDemands(
        self: *Cloner,
        indexed: []const PrivateStateIndexedValue,
        demands: []const ItemDemand,
    ) LowerError!?[]const DemandedKnownIndexedValue {
        var values = std.ArrayList(DemandedKnownIndexedValue).empty;
        defer values.deinit(self.pass.allocator);
        for (demands) |demand| {
            if (demand.demand.* == .none) continue;
            const child = privateStateIndexedValueByIndex(indexed, demand.index) orelse return null;
            const demanded_child = (try self.demandedKnownValueFromPrivateStateDemand(child, demand.demand.*)) orelse return null;
            try values.append(self.pass.allocator, .{
                .index = demand.index,
                .known_value = demanded_child,
            });
        }
        return try self.pass.arena.allocator().dupe(DemandedKnownIndexedValue, values.items);
    }

    fn demandedKnownIndexedValuesFromPrivateStateCallableCaptureDemands(
        self: *Cloner,
        callable: PrivateStateCallable,
        demands: []const ValueDemand,
    ) LowerError!?[]const DemandedKnownIndexedValue {
        const source_fn = self.pass.program.fns.items[@intFromEnum(callable.fn_id)];
        const source_captures = self.pass.program.typedLocalSpan(source_fn.captures);

        var values = std.ArrayList(DemandedKnownIndexedValue).empty;
        defer values.deinit(self.pass.allocator);

        var index: usize = 0;
        while (index < source_captures.len and index < demands.len) : (index += 1) {
            const demand = demands[index];
            if (demand == .none) continue;
            const child = (try self.privateStateCallableCaptureValue(callable, index)) orelse return null;
            const demanded_child = (try self.demandedKnownValueFromValueDemand(child, demand)) orelse blk: {
                break :blk DemandedKnownValue{ .any = valueType(self.pass.program, child) };
            };
            try values.append(self.pass.allocator, .{
                .index = @intCast(index),
                .known_value = demanded_child,
            });
        }

        return try self.pass.arena.allocator().dupe(DemandedKnownIndexedValue, values.items);
    }

    fn cloneLoopUnwrappedLet(
        self: *Cloner,
        ty: Type.TypeId,
        loop: anytype,
        params: []const Ast.TypedLocal,
        values: []const Value,
        source_initials: ?[]const ?ExprValueSource,
        initial_demands: []const ValueDemand,
        result_demand: ValueDemand,
    ) LowerError!?Ast.ExprId {
        for (values, 0..) |value, value_index| {
            const let_value = switch (value) {
                .let_ => |let_value| let_value,
                else => continue,
            };

            var unwrapped_values = try self.pass.allocator.dupe(Value, values);
            defer self.pass.allocator.free(unwrapped_values);
            unwrapped_values[value_index] = let_value.body.*;

            const unwrapped_sources = if (source_initials) |sources| sources: {
                const refreshed_sources = try self.pass.allocator.dupe(?ExprValueSource, sources);
                refreshed_sources[value_index] = null;
                break :sources refreshed_sources;
            } else null;
            defer if (unwrapped_sources) |sources| self.pass.allocator.free(sources);

            const change_start = self.changes.items.len;
            defer self.restore(change_start);
            const scoped_start = self.scopedLocalsLen();
            defer self.restoreScopedLocals(scoped_start);
            for (let_value.lets) |pending| {
                try self.scoped_locals.append(self.pass.allocator, pending.local);
            }
            try self.bindPendingLetKnownValues(let_value.lets);

            const body = try self.materialize(try self.cloneLoopFromInitialValues(ty, loop, params, unwrapped_values, unwrapped_sources, initial_demands, result_demand));
            return try self.wrapPendingLetsAroundExpr(ty, body, let_value.lets);
        }

        return null;
    }

    fn cloneLoopDistributedIf(
        self: *Cloner,
        ty: Type.TypeId,
        loop: anytype,
        params: []const Ast.TypedLocal,
        values: []const Value,
        source_initials: ?[]const ?ExprValueSource,
        initial_demands: []const ValueDemand,
        result_demand: ValueDemand,
    ) LowerError!?Ast.ExprId {
        for (values, 0..) |value, value_index| {
            const if_value = switch (value) {
                .if_ => |if_value| if_value,
                else => continue,
            };
            const branches = try self.pass.allocator.alloc(Ast.IfBranch, if_value.branches.len);
            defer self.pass.allocator.free(branches);
            var branch_values = try self.pass.allocator.dupe(Value, values);
            defer self.pass.allocator.free(branch_values);
            const branch_sources = if (source_initials) |sources|
                try self.pass.allocator.dupe(?ExprValueSource, sources)
            else
                null;
            defer if (branch_sources) |sources| self.pass.allocator.free(sources);

            for (if_value.branches, 0..) |branch, branch_index| {
                branch_values[value_index] = branch.body;
                if (branch_sources) |sources| sources[value_index] = branch.source_body;
                branches[branch_index] = .{
                    .cond = branch.cond,
                    .body = try self.materialize(try self.cloneLoopFromInitialValues(ty, loop, params, branch_values, branch_sources, initial_demands, result_demand)),
                };
            }

            branch_values[value_index] = if_value.final_else.*;
            if (branch_sources) |sources| sources[value_index] = if_value.final_else_source;
            const final_else = try self.materialize(try self.cloneLoopFromInitialValues(ty, loop, params, branch_values, branch_sources, initial_demands, result_demand));

            return try self.addExpr(.{ .ty = ty, .data = .{ .if_ = .{
                .branches = try self.pass.program.addIfBranchSpan(branches),
                .final_else = final_else,
            } } });
        }

        return null;
    }

    fn projectableLoopKnownValueForValue(self: *Cloner, known_value: KnownValue, value: Value) Allocator.Error!?KnownValue {
        return switch (value) {
            .record => |record_value| blk: {
                const record_known_value = switch (known_value) {
                    .record => |record| record,
                    else => break :blk null,
                };
                if (record_known_value.fields.len != record_value.fields.len) Common.invariant("record loop state changed field count before specialization");
                const fields = try self.pass.arena.allocator().alloc(KnownField, record_known_value.fields.len);
                for (record_known_value.fields, record_value.fields, 0..) |field_known_value, field_value, index| {
                    if (field_known_value.name != field_value.name) Common.invariant("record loop state changed field order before specialization");
                    const projected = try self.projectableLoopKnownValueForValue(field_known_value.known_value, field_value.value);
                    fields[index] = .{
                        .name = field_known_value.name,
                        .known_value = projected orelse .{ .any = known_valueType(field_known_value.known_value) },
                    };
                }
                break :blk KnownValue{ .record = .{
                    .ty = record_known_value.ty,
                    .fields = fields,
                } };
            },
            .tuple => |tuple_value| blk: {
                const tuple_known_value = switch (known_value) {
                    .tuple => |tuple| tuple,
                    else => break :blk null,
                };
                if (tuple_known_value.items.len != tuple_value.items.len) Common.invariant("tuple loop state changed item count before specialization");
                const items = try self.pass.arena.allocator().alloc(KnownValue, tuple_known_value.items.len);
                for (tuple_known_value.items, tuple_value.items, 0..) |item_known_value, item_value, index| {
                    items[index] = (try self.projectableLoopKnownValueForValue(item_known_value, item_value)) orelse
                        .{ .any = known_valueType(item_known_value) };
                }
                break :blk KnownValue{ .tuple = .{
                    .ty = tuple_known_value.ty,
                    .items = items,
                } };
            },
            .nominal => |nominal_value| blk: {
                const nominal_known_value = switch (known_value) {
                    .nominal => |nominal| nominal,
                    else => break :blk null,
                };
                const backing = (try self.projectableLoopKnownValueForValue(nominal_known_value.backing.*, nominal_value.backing.*)) orelse break :blk null;
                const stored = try self.pass.arena.allocator().create(KnownValue);
                stored.* = backing;
                break :blk KnownValue{ .nominal = .{
                    .ty = nominal_known_value.ty,
                    .backing = stored,
                } };
            },
            .callable => |callable_value| blk: {
                const callable_known_value = switch (known_value) {
                    .callable => |callable| callable,
                    .finite_callables => |finite_callables| {
                        for (finite_callables.alternatives) |alternative| {
                            if (!sameType(self.pass.program, alternative.ty, callable_value.ty) or
                                !callableTargetMatches(self.pass.program, alternative.fn_id, callable_value.fn_id) or
                                alternative.captures.len != callable_value.captures.len)
                            {
                                continue;
                            }

                            const captures = try self.pass.arena.allocator().alloc(KnownValue, alternative.captures.len);
                            for (alternative.captures, callable_value.captures, 0..) |capture_known_value, capture_value, index| {
                                const projected = try self.projectableLoopKnownValueForValue(capture_known_value, capture_value);
                                captures[index] = projected orelse .{ .any = known_valueType(capture_known_value) };
                            }
                            break :blk KnownValue{ .callable = .{
                                .ty = alternative.ty,
                                .fn_id = alternative.fn_id,
                                .captures = captures,
                            } };
                        }
                        break :blk null;
                    },
                    else => break :blk null,
                };
                if (!sameType(self.pass.program, callable_known_value.ty, callable_value.ty) or
                    !callableTargetMatches(self.pass.program, callable_known_value.fn_id, callable_value.fn_id) or
                    callable_known_value.captures.len != callable_value.captures.len)
                {
                    break :blk null;
                }
                const captures = try self.pass.arena.allocator().alloc(KnownValue, callable_known_value.captures.len);
                for (callable_known_value.captures, callable_value.captures, 0..) |capture_known_value, capture_value, index| {
                    const projected = try self.projectableLoopKnownValueForValue(capture_known_value, capture_value);
                    captures[index] = projected orelse .{ .any = known_valueType(capture_known_value) };
                }
                break :blk KnownValue{ .callable = .{
                    .ty = callable_known_value.ty,
                    .fn_id = callable_known_value.fn_id,
                    .captures = captures,
                } };
            },
            .finite_tags => |finite_value| blk: {
                const finite_known_value = switch (known_value) {
                    .finite_tags => |finite_tags| finite_tags,
                    else => break :blk null,
                };
                if (!sameType(self.pass.program, finite_known_value.ty, finite_value.ty) or
                    finite_known_value.alternatives.len != finite_value.alternatives.len)
                {
                    break :blk null;
                }
                const alternatives = try self.pass.arena.allocator().alloc(KnownTag, finite_known_value.alternatives.len);
                for (finite_known_value.alternatives, finite_value.alternatives, 0..) |known_alternative, value_alternative, index| {
                    if (!sameType(self.pass.program, known_alternative.ty, value_alternative.ty) or
                        known_alternative.name != value_alternative.name or
                        known_alternative.payloads.len != value_alternative.payloads.len)
                    {
                        break :blk null;
                    }
                    const payloads = try self.pass.arena.allocator().alloc(KnownValue, known_alternative.payloads.len);
                    for (known_alternative.payloads, value_alternative.payloads, 0..) |payload_known_value, payload_value, payload_index| {
                        const projected = try self.projectableLoopKnownValueForValue(payload_known_value, payload_value);
                        payloads[payload_index] = projected orelse .{ .any = known_valueType(payload_known_value) };
                    }
                    alternatives[index] = .{
                        .ty = known_alternative.ty,
                        .name = known_alternative.name,
                        .payloads = payloads,
                    };
                }
                break :blk KnownValue{ .finite_tags = .{
                    .ty = finite_known_value.ty,
                    .alternatives = alternatives,
                } };
            },
            .finite_callables => |finite_value| blk: {
                const finite_known_value = switch (known_value) {
                    .finite_callables => |finite_callables| finite_callables,
                    else => break :blk null,
                };
                if (!sameType(self.pass.program, finite_known_value.ty, finite_value.ty) or
                    finite_known_value.alternatives.len != finite_value.alternatives.len)
                {
                    break :blk null;
                }
                const alternatives = try self.pass.arena.allocator().alloc(KnownCallable, finite_known_value.alternatives.len);
                for (finite_known_value.alternatives, finite_value.alternatives, 0..) |known_alternative, value_alternative, index| {
                    if (!sameType(self.pass.program, known_alternative.ty, value_alternative.ty) or
                        !callableTargetMatches(self.pass.program, known_alternative.fn_id, value_alternative.fn_id) or
                        known_alternative.captures.len != value_alternative.captures.len)
                    {
                        break :blk null;
                    }
                    const captures = try self.pass.arena.allocator().alloc(KnownValue, known_alternative.captures.len);
                    for (known_alternative.captures, value_alternative.captures, 0..) |capture_known_value, capture_value, capture_index| {
                        const projected = try self.projectableLoopKnownValueForValue(capture_known_value, capture_value);
                        captures[capture_index] = projected orelse .{ .any = known_valueType(capture_known_value) };
                    }
                    alternatives[index] = .{
                        .ty = known_alternative.ty,
                        .fn_id = known_alternative.fn_id,
                        .captures = captures,
                    };
                }
                break :blk KnownValue{ .finite_callables = .{
                    .ty = finite_known_value.ty,
                    .alternatives = alternatives,
                } };
            },
            .let_ => |let_value| try self.projectableLoopKnownValueForValue(known_value, let_value.body.*),
            .if_ => null,
            .match_ => null,
            .private_state => null,
            .expr_with_known_value => |known| if (known_valueCanProjectFromExpr(known_value))
                known_value
            else if (canReadFieldsFromExpr(self.pass.program, known.expr))
                try self.projectableLoopKnownValueFromExpr(known.known_value)
            else if (known_valueCanProjectFromExpr(known.known_value))
                known.known_value
            else
                null,
            .tag => |tag_value| switch (known_value) {
                .tag => |tag_known_value| blk: {
                    if (!sameType(self.pass.program, tag_known_value.ty, tag_value.ty) or
                        tag_known_value.name != tag_value.name or
                        tag_known_value.payloads.len != tag_value.payloads.len)
                    {
                        break :blk null;
                    }
                    const payloads = try self.pass.arena.allocator().alloc(KnownValue, tag_known_value.payloads.len);
                    for (tag_known_value.payloads, tag_value.payloads, 0..) |payload_known_value, payload_value, index| {
                        const projected = try self.projectableLoopKnownValueForValue(payload_known_value, payload_value);
                        payloads[index] = projected orelse .{ .any = known_valueType(payload_known_value) };
                    }
                    break :blk KnownValue{ .tag = .{
                        .ty = tag_known_value.ty,
                        .name = tag_known_value.name,
                        .payloads = payloads,
                    } };
                },
                .finite_tags => |finite_tags| blk: {
                    for (finite_tags.alternatives) |alternative| {
                        if (!sameType(self.pass.program, alternative.ty, tag_value.ty) or
                            alternative.name != tag_value.name or
                            alternative.payloads.len != tag_value.payloads.len)
                        {
                            continue;
                        }

                        const payloads = try self.pass.arena.allocator().alloc(KnownValue, alternative.payloads.len);
                        for (alternative.payloads, tag_value.payloads, 0..) |payload_known_value, payload_value, index| {
                            const projected = try self.projectableLoopKnownValueForValue(payload_known_value, payload_value);
                            payloads[index] = projected orelse .{ .any = known_valueType(payload_known_value) };
                        }
                        break :blk KnownValue{ .tag = .{
                            .ty = alternative.ty,
                            .name = alternative.name,
                            .payloads = payloads,
                        } };
                    }
                    break :blk null;
                },
                else => null,
            },
            .expr,
            => if (known_valueCanProjectFromExpr(known_value)) known_value else null,
        };
    }

    fn projectableLoopKnownValueFromExpr(self: *Cloner, known_value: KnownValue) Allocator.Error!?KnownValue {
        if (known_valueCanProjectFromExpr(known_value)) return known_value;

        return switch (known_value) {
            .any => known_value,
            .leaf => known_value,
            .record => |record| blk: {
                const fields = try self.pass.arena.allocator().alloc(KnownField, record.fields.len);
                for (record.fields, fields) |field, *out| {
                    out.* = .{
                        .name = field.name,
                        .known_value = (try self.projectableLoopKnownValueFromExpr(field.known_value)) orelse
                            .{ .any = known_valueType(field.known_value) },
                    };
                }
                break :blk KnownValue{ .record = .{
                    .ty = record.ty,
                    .fields = fields,
                } };
            },
            .tuple => |tuple| blk: {
                const items = try self.pass.arena.allocator().alloc(KnownValue, tuple.items.len);
                for (tuple.items, items) |item, *out| {
                    out.* = (try self.projectableLoopKnownValueFromExpr(item)) orelse
                        .{ .any = known_valueType(item) };
                }
                break :blk KnownValue{ .tuple = .{
                    .ty = tuple.ty,
                    .items = items,
                } };
            },
            .nominal => |nominal| blk: {
                const backing = (try self.projectableLoopKnownValueFromExpr(nominal.backing.*)) orelse break :blk null;
                const stored = try self.pass.arena.allocator().create(KnownValue);
                stored.* = backing;
                break :blk KnownValue{ .nominal = .{
                    .ty = nominal.ty,
                    .backing = stored,
                } };
            },
            .tag,
            .callable,
            .finite_tags,
            .finite_callables,
            => null,
        };
    }

    fn cloneBlock(self: *Cloner, ty: Type.TypeId, block: anytype) LowerError!Ast.ExprId {
        const change_start = self.changes.items.len;
        defer self.restore(change_start);
        const scoped_start = self.scopedLocalsLen();
        defer self.restoreScopedLocals(scoped_start);

        const source = try self.pass.allocator.dupe(Ast.StmtId, self.pass.program.stmtSpan(block.statements));
        defer self.pass.allocator.free(source);

        var statements = std.ArrayList(Ast.StmtId).empty;
        defer statements.deinit(self.pass.allocator);
        for (source, 0..) |stmt, index| {
            try self.cloneStmtInto(stmt, &statements, .{
                .statements = source[index + 1 ..],
                .final_expr = block.final_expr,
            }, .materialize);
        }

        return try self.addExpr(.{ .ty = ty, .data = .{ .block = .{
            .statements = try self.pass.program.addStmtSpan(statements.items),
            .final_expr = try self.cloneExpr(block.final_expr),
        } } });
    }

    fn cloneBlockValue(self: *Cloner, ty: Type.TypeId, block: anytype) LowerError!Value {
        return try self.cloneBlockValueWithFinalDemand(ty, block, false);
    }

    fn cloneBlockValueDemandingKnownValue(self: *Cloner, ty: Type.TypeId, block: anytype) LowerError!Value {
        return try self.cloneBlockValueWithFinalDemand(ty, block, true);
    }

    fn cloneBlockValueWithFinalDemand(
        self: *Cloner,
        ty: Type.TypeId,
        block: anytype,
        demand_final_known_value: bool,
    ) LowerError!Value {
        const change_start = self.changes.items.len;
        defer self.restore(change_start);
        const scoped_start = self.scopedLocalsLen();
        defer self.restoreScopedLocals(scoped_start);

        const source = try self.pass.allocator.dupe(Ast.StmtId, self.pass.program.stmtSpan(block.statements));
        defer self.pass.allocator.free(source);

        var statements = std.ArrayList(Ast.StmtId).empty;
        defer statements.deinit(self.pass.allocator);
        for (source, 0..) |stmt, index| {
            try self.cloneStmtInto(stmt, &statements, .{
                .statements = source[index + 1 ..],
                .final_expr = block.final_expr,
            }, .materialize);
        }

        const final_value = if (demand_final_known_value)
            try self.cloneExprValueDemandingKnownValue(block.final_expr)
        else
            try self.cloneExprValue(block.final_expr);
        if (demand_final_known_value) {
            if (statements.items.len == 0) return final_value;

            var pending_lets = std.ArrayList(PendingLet).empty;
            defer pending_lets.deinit(self.pass.allocator);
            if (try self.appendPendingLetsFromStatements(statements.items, &pending_lets)) {
                return try self.wrapPendingLets(final_value, pending_lets.items, true);
            }
        }

        const final_expr = try self.materialize(final_value);
        const block_expr = try self.addExpr(.{ .ty = ty, .data = .{ .block = .{
            .statements = try self.pass.program.addStmtSpan(statements.items),
            .final_expr = final_expr,
        } } });

        const known_value = (try self.pass.knownValueFromValue(final_value)) orelse return .{ .expr = block_expr };
        return .{ .expr_with_known_value = .{
            .expr = block_expr,
            .known_value = known_value,
        } };
    }

    fn cloneContinue(self: *Cloner, ty: Type.TypeId, continue_: anytype) LowerError!Ast.ExprData {
        const loop = self.loop_stack.getLastOrNull() orelse {
            const state_loop = self.state_loop_stack.getLastOrNull() orelse return .{ .continue_ = .{
                .values = try self.cloneExprSpan(continue_.values),
            } };
            return try self.cloneStateContinue(ty, state_loop, continue_);
        };
        const values = self.pass.program.exprSpan(continue_.values);
        const source_values = try self.pass.allocator.dupe(Ast.ExprId, values);
        defer self.pass.allocator.free(source_values);
        if (source_values.len != loop.values.len) Common.invariant("continue value count differed from active loop arity");

        var pending_statements = std.ArrayList(Ast.StmtId).empty;
        defer pending_statements.deinit(self.pass.allocator);

        const pending_change_start = self.changes.items.len;
        defer self.restore(pending_change_start);
        const scoped_start = self.scopedLocalsLen();
        defer self.restoreScopedLocals(scoped_start);

        const continue_values = try self.pass.allocator.alloc(Value, source_values.len);
        defer self.pass.allocator.free(continue_values);

        for (source_values, 0..) |value_expr, index| {
            var value = try self.cloneExprValueWithDemand(value_expr, try self.continueValueDemand(index));
            while (value == .let_) {
                try self.appendPendingLetStmts(value.let_.lets, &pending_statements);
                try self.appendPendingLetScopedLocals(value.let_.lets);
                try self.bindPendingLetKnownValues(value.let_.lets);
                value = value.let_.body.*;
            }
            value = try self.hoistNestedLetsFromValue(value, &pending_statements);
            continue_values[index] = value;
        }

        const continue_data = try self.cloneContinueDataFromValues(ty, loop, continue_values);
        if (pending_statements.items.len == 0) return continue_data;

        const continue_expr = try self.addExpr(.{ .ty = ty, .data = continue_data });
        return .{ .block = .{
            .statements = try self.pass.program.addStmtSpan(pending_statements.items),
            .final_expr = continue_expr,
        } };
    }

    fn cloneStateContinue(self: *Cloner, ty: Type.TypeId, state_loop: SparseStateLoopPattern, continue_: anytype) LowerError!Ast.ExprData {
        const values = self.pass.program.exprSpan(continue_.values);
        const source_values = try self.pass.allocator.dupe(Ast.ExprId, values);
        defer self.pass.allocator.free(source_values);
        if (state_loop.states.items.len == 0) Common.invariant("state_continue had no possible target states");

        const arity = state_loop.states.items[0].values.len;
        if (source_values.len != arity) Common.invariant("state_continue value count differed from state_loop arity");

        var pending_statements = std.ArrayList(Ast.StmtId).empty;
        defer pending_statements.deinit(self.pass.allocator);

        const pending_change_start = self.changes.items.len;
        defer self.restore(pending_change_start);
        const scoped_start = self.scopedLocalsLen();
        defer self.restoreScopedLocals(scoped_start);

        const continue_values = try self.pass.allocator.alloc(Value, source_values.len);
        defer self.pass.allocator.free(continue_values);

        for (source_values, 0..) |value_expr, index| {
            var value = try self.cloneExprValueWithDemand(value_expr, .{ .loop_param = index });
            while (value == .let_) {
                try self.appendPendingLetStmts(value.let_.lets, &pending_statements);
                try self.appendPendingLetScopedLocals(value.let_.lets);
                try self.bindPendingLetKnownValues(value.let_.lets);
                value = value.let_.body.*;
            }
            value = try self.hoistNestedLetsFromValue(value, &pending_statements);
            continue_values[index] = value;
        }

        const continue_data = try self.cloneStateContinueDataFromValues(ty, state_loop, continue_values);
        if (pending_statements.items.len == 0) return continue_data;

        const continue_expr = try self.addExpr(.{ .ty = ty, .data = continue_data });
        return .{ .block = .{
            .statements = try self.pass.program.addStmtSpan(pending_statements.items),
            .final_expr = continue_expr,
        } };
    }

    fn stateLoopValueDemands(self: *Cloner, state_loop: SparseStateLoopPattern, arity: usize) LowerError![]ValueDemand {
        const demands = try self.pass.allocator.alloc(ValueDemand, arity);
        @memset(demands, .none);
        if (state_loop.demands.len != arity) Common.invariant("state_loop analysis demand arity differed from state arity");
        for (state_loop.demands, demands) |demand, *out| {
            out.* = demand;
        }

        for (state_loop.states.items) |state| {
            if (state.values.len != arity) Common.invariant("state_loop state arity differed while computing continue demand");
            for (state.values, 0..) |known_value, index| {
                demands[index] = try self.mergeValueDemand(
                    demands[index],
                    try self.pass.valueDemandFromDemandedKnownValue(known_value),
                );
            }
        }

        return demands;
    }

    fn selectCorrelatedStateIfBranch(
        self: *Cloner,
        original_values: []const Value,
        selected_values: []Value,
        demands: []const ValueDemand,
        selected_index: usize,
        control: IfValue,
        branch_index: usize,
        final_else: bool,
    ) LowerError!void {
        for (original_values, selected_values, 0..) |original, *selected, index| {
            if (index == selected_index) continue;
            const other = switch (original) {
                .if_ => |if_value| if_value,
                else => continue,
            };
            if (!ifValueControlEql(control, other)) continue;
            const branch_body = if (final_else)
                other.final_else.*
            else
                other.branches[branch_index].body;
            selected.* = try self.applyValueDemand(branch_body, demands[index]);
        }
    }

    fn selectCorrelatedIfBranch(
        original_values: []const Value,
        selected_values: []Value,
        selected_index: usize,
        control: IfValue,
        branch_index: usize,
        final_else: bool,
    ) void {
        for (original_values, selected_values, 0..) |original, *selected, index| {
            if (index == selected_index) continue;
            const other = switch (original) {
                .if_ => |if_value| if_value,
                else => continue,
            };
            if (!ifValueControlEql(control, other)) continue;
            selected.* = if (final_else)
                other.final_else.*
            else
                other.branches[branch_index].body;
        }
    }

    fn selectCorrelatedMatchBranch(
        original_values: []const Value,
        selected_values: []Value,
        selected_index: usize,
        control: MatchValue,
        branch_index: usize,
    ) void {
        for (original_values, selected_values, 0..) |original, *selected, index| {
            if (index == selected_index) continue;
            const other = switch (original) {
                .match_ => |match_value| match_value,
                else => continue,
            };
            if (!matchValueControlEql(control, other)) continue;
            selected.* = other.branches[branch_index].body;
        }
    }

    fn selectCorrelatedStateMatchBranch(
        self: *Cloner,
        original_values: []const Value,
        selected_values: []Value,
        demands: []const ValueDemand,
        selected_index: usize,
        control: MatchValue,
        branch_index: usize,
    ) LowerError!void {
        for (original_values, selected_values, 0..) |original, *selected, index| {
            if (index == selected_index) continue;
            const other = switch (original) {
                .match_ => |match_value| match_value,
                else => continue,
            };
            if (!matchValueControlEql(control, other)) continue;
            selected.* = try self.cloneMatchValueBranchBodyWithDemand(other.branches[branch_index], demands[index]);
        }
    }

    fn cloneStateContinueDataFromValues(
        self: *Cloner,
        ty: Type.TypeId,
        state_loop: SparseStateLoopPattern,
        values: []const Value,
    ) LowerError!Ast.ExprData {
        const demands = try self.stateLoopValueDemands(state_loop, values.len);
        defer self.pass.allocator.free(demands);

        for (values, 0..) |value, value_index| {
            const let_value = switch (value) {
                .let_ => |let_value| let_value,
                else => continue,
            };

            var unwrapped_values = try self.pass.allocator.dupe(Value, values);
            defer self.pass.allocator.free(unwrapped_values);
            unwrapped_values[value_index] = let_value.body.*;

            const change_start = self.changes.items.len;
            defer self.restore(change_start);
            const scoped_start = self.scopedLocalsLen();
            defer self.restoreScopedLocals(scoped_start);
            try self.appendPendingLetScopedLocals(let_value.lets);
            try self.bindPendingLetKnownValues(let_value.lets);

            const continue_expr = try self.addExpr(.{
                .ty = ty,
                .data = try self.cloneStateContinueDataFromValues(ty, state_loop, unwrapped_values),
            });
            const wrapped = try self.wrapPendingLetsAroundExpr(ty, continue_expr, let_value.lets);
            return .{ .block = .{
                .statements = try self.pass.program.addStmtSpan(&.{}),
                .final_expr = wrapped,
            } };
        }

        for (values, 0..) |value, value_index| {
            const if_value = switch (value) {
                .if_ => |if_value| if_value,
                else => continue,
            };

            const branches = try self.pass.allocator.alloc(Ast.IfBranch, if_value.branches.len);
            defer self.pass.allocator.free(branches);
            var branch_values = try self.pass.allocator.dupe(Value, values);
            defer self.pass.allocator.free(branch_values);

            for (if_value.branches, 0..) |branch, branch_index| {
                branch_values[value_index] = try self.applyValueDemand(branch.body, demands[value_index]);
                try self.selectCorrelatedStateIfBranch(values, branch_values, demands, value_index, if_value, branch_index, false);
                branches[branch_index] = .{
                    .cond = branch.cond,
                    .body = try self.addExpr(.{
                        .ty = ty,
                        .data = try self.cloneStateContinueDataFromValues(ty, state_loop, branch_values),
                    }),
                };
            }

            branch_values[value_index] = try self.applyValueDemand(if_value.final_else.*, demands[value_index]);
            try self.selectCorrelatedStateIfBranch(values, branch_values, demands, value_index, if_value, 0, true);
            const final_else = try self.addExpr(.{
                .ty = ty,
                .data = try self.cloneStateContinueDataFromValues(ty, state_loop, branch_values),
            });

            return .{ .if_ = .{
                .branches = try self.pass.program.addIfBranchSpan(branches),
                .final_else = final_else,
            } };
        }

        for (values, 0..) |value, value_index| {
            const match_value = switch (value) {
                .match_ => |match_value| match_value,
                else => continue,
            };

            const branches = try self.pass.allocator.alloc(Ast.Branch, match_value.branches.len);
            defer self.pass.allocator.free(branches);
            var branch_values = try self.pass.allocator.dupe(Value, values);
            defer self.pass.allocator.free(branch_values);

            for (match_value.branches, 0..) |branch, branch_index| {
                branch_values[value_index] = try self.cloneMatchValueBranchBodyWithDemand(branch, demands[value_index]);
                try self.selectCorrelatedStateMatchBranch(values, branch_values, demands, value_index, match_value, branch_index);
                const scoped_start = self.scopedLocalsLen();
                defer self.restoreScopedLocals(scoped_start);
                try self.appendPatternScopedLocals(branch.pat);
                branches[branch_index] = .{
                    .pat = branch.pat,
                    .guard = branch.guard,
                    .body = try self.addExpr(.{
                        .ty = ty,
                        .data = try self.cloneStateContinueDataFromValues(ty, state_loop, branch_values),
                    }),
                };
            }

            return .{ .match_ = .{
                .scrutinee = match_value.scrutinee,
                .branches = try self.pass.program.addBranchSpan(branches),
                .comptime_site = match_value.comptime_site,
            } };
        }

        const state_values = try self.demandedStateValuesFromValues(demands, values);
        const target_state = self.stateForDemandedKnownValues(state_loop.states.items, state_values) orelse
            try self.appendSparseState(state_loop.states, state_values);

        var new_values = std.ArrayList(Ast.ExprId).empty;
        defer new_values.deinit(self.pass.allocator);

        for (target_state.values, values) |known_value, value| {
            if (!try self.appendExprsFromDemandedKnownValue(known_value, value, &new_values)) {
                Common.invariant("state_continue value could not be split into target state params");
            }
        }

        return .{ .state_continue = .{
            .target_state = target_state.id,
            .values = try self.pass.program.addExprSpan(new_values.items),
        } };
    }

    fn hoistNestedLetsFromValue(
        self: *Cloner,
        value: Value,
        pending_statements: *std.ArrayList(Ast.StmtId),
    ) LowerError!Value {
        return switch (value) {
            .let_ => |let_value| blk: {
                try self.appendPendingLetStmts(let_value.lets, pending_statements);
                try self.appendPendingLetScopedLocals(let_value.lets);
                try self.bindPendingLetKnownValues(let_value.lets);
                break :blk try self.hoistNestedLetsFromValue(let_value.body.*, pending_statements);
            },
            .tag => |tag| blk: {
                const payloads = try self.pass.arena.allocator().alloc(Value, tag.payloads.len);
                for (tag.payloads, payloads) |payload, *out| {
                    out.* = try self.hoistNestedLetsFromValue(payload, pending_statements);
                }
                break :blk Value{ .tag = .{
                    .ty = tag.ty,
                    .name = tag.name,
                    .payloads = payloads,
                } };
            },
            .record => |record| blk: {
                const fields = try self.pass.arena.allocator().alloc(FieldValue, record.fields.len);
                for (record.fields, fields) |field, *out| {
                    out.* = .{
                        .name = field.name,
                        .value = try self.hoistNestedLetsFromValue(field.value, pending_statements),
                    };
                }
                break :blk Value{ .record = .{
                    .ty = record.ty,
                    .fields = fields,
                } };
            },
            .tuple => |tuple| blk: {
                const items = try self.pass.arena.allocator().alloc(Value, tuple.items.len);
                for (tuple.items, items) |item, *out| {
                    out.* = try self.hoistNestedLetsFromValue(item, pending_statements);
                }
                break :blk Value{ .tuple = .{
                    .ty = tuple.ty,
                    .items = items,
                } };
            },
            .nominal => |nominal| blk: {
                const backing = try self.pass.arena.allocator().create(Value);
                backing.* = try self.hoistNestedLetsFromValue(nominal.backing.*, pending_statements);
                break :blk Value{ .nominal = .{
                    .ty = nominal.ty,
                    .backing = backing,
                } };
            },
            .callable => |callable| blk: {
                const captures = try self.pass.arena.allocator().alloc(Value, callable.captures.len);
                for (callable.captures, captures) |capture, *out| {
                    out.* = try self.hoistNestedLetsFromValue(capture, pending_statements);
                }
                break :blk Value{ .callable = .{
                    .ty = callable.ty,
                    .fn_id = callable.fn_id,
                    .captures = captures,
                } };
            },
            .finite_tags => |finite_tags| blk: {
                const alternatives = try self.pass.arena.allocator().alloc(TagValue, finite_tags.alternatives.len);
                for (finite_tags.alternatives, alternatives) |alternative, *out| {
                    const payloads = try self.pass.arena.allocator().alloc(Value, alternative.payloads.len);
                    for (alternative.payloads, payloads) |payload, *payload_out| {
                        payload_out.* = try self.hoistNestedLetsFromValue(payload, pending_statements);
                    }
                    out.* = .{
                        .ty = alternative.ty,
                        .name = alternative.name,
                        .payloads = payloads,
                    };
                }
                break :blk Value{ .finite_tags = .{
                    .ty = finite_tags.ty,
                    .selector = finite_tags.selector,
                    .alternatives = alternatives,
                } };
            },
            .finite_callables => |finite_callables| blk: {
                const alternatives = try self.pass.arena.allocator().alloc(CallableValue, finite_callables.alternatives.len);
                for (finite_callables.alternatives, alternatives) |alternative, *out| {
                    const captures = try self.pass.arena.allocator().alloc(Value, alternative.captures.len);
                    for (alternative.captures, captures) |capture, *capture_out| {
                        capture_out.* = try self.hoistNestedLetsFromValue(capture, pending_statements);
                    }
                    out.* = .{
                        .ty = alternative.ty,
                        .fn_id = alternative.fn_id,
                        .captures = captures,
                    };
                }
                break :blk Value{ .finite_callables = .{
                    .ty = finite_callables.ty,
                    .selector = finite_callables.selector,
                    .alternatives = alternatives,
                } };
            },
            .if_,
            .match_,
            .expr,
            .expr_with_known_value,
            .private_state,
            => value,
        };
    }

    fn cloneContinueDataFromValues(
        self: *Cloner,
        ty: Type.TypeId,
        loop: LoopPattern,
        values: []const Value,
    ) LowerError!Ast.ExprData {
        for (values, 0..) |value, value_index| {
            const let_value = switch (value) {
                .let_ => |let_value| let_value,
                else => continue,
            };

            var unwrapped_values = try self.pass.allocator.dupe(Value, values);
            defer self.pass.allocator.free(unwrapped_values);
            unwrapped_values[value_index] = let_value.body.*;

            const change_start = self.changes.items.len;
            defer self.restore(change_start);
            const scoped_start = self.scopedLocalsLen();
            defer self.restoreScopedLocals(scoped_start);
            try self.appendPendingLetScopedLocals(let_value.lets);
            try self.bindPendingLetKnownValues(let_value.lets);

            const continue_expr = try self.addExpr(.{
                .ty = ty,
                .data = try self.cloneContinueDataFromValues(ty, loop, unwrapped_values),
            });
            const wrapped = try self.wrapPendingLetsAroundExpr(ty, continue_expr, let_value.lets);
            return .{ .block = .{
                .statements = try self.pass.program.addStmtSpan(&.{}),
                .final_expr = wrapped,
            } };
        }

        for (values, 0..) |value, value_index| {
            const if_value = switch (value) {
                .if_ => |if_value| if_value,
                else => continue,
            };

            const branches = try self.pass.allocator.alloc(Ast.IfBranch, if_value.branches.len);
            defer self.pass.allocator.free(branches);
            var branch_values = try self.pass.allocator.dupe(Value, values);
            defer self.pass.allocator.free(branch_values);

            for (if_value.branches, 0..) |branch, branch_index| {
                branch_values[value_index] = branch.body;
                selectCorrelatedIfBranch(values, branch_values, value_index, if_value, branch_index, false);
                branches[branch_index] = .{
                    .cond = branch.cond,
                    .body = try self.addExpr(.{
                        .ty = ty,
                        .data = try self.cloneContinueDataFromValues(ty, loop, branch_values),
                    }),
                };
            }

            branch_values[value_index] = if_value.final_else.*;
            selectCorrelatedIfBranch(values, branch_values, value_index, if_value, 0, true);
            const final_else = try self.addExpr(.{
                .ty = ty,
                .data = try self.cloneContinueDataFromValues(ty, loop, branch_values),
            });

            return .{ .if_ = .{
                .branches = try self.pass.program.addIfBranchSpan(branches),
                .final_else = final_else,
            } };
        }

        for (values, 0..) |value, value_index| {
            const match_value = switch (value) {
                .match_ => |match_value| match_value,
                else => continue,
            };

            const branches = try self.pass.allocator.alloc(Ast.Branch, match_value.branches.len);
            defer self.pass.allocator.free(branches);
            var branch_values = try self.pass.allocator.dupe(Value, values);
            defer self.pass.allocator.free(branch_values);

            for (match_value.branches, 0..) |branch, branch_index| {
                branch_values[value_index] = branch.body;
                selectCorrelatedMatchBranch(values, branch_values, value_index, match_value, branch_index);
                branches[branch_index] = .{
                    .pat = branch.pat,
                    .guard = branch.guard,
                    .body = try self.addExpr(.{
                        .ty = ty,
                        .data = try self.cloneContinueDataFromValues(ty, loop, branch_values),
                    }),
                };
            }

            return .{ .match_ = .{
                .scrutinee = match_value.scrutinee,
                .branches = try self.pass.program.addBranchSpan(branches),
                .comptime_site = match_value.comptime_site,
            } };
        }

        var new_values = std.ArrayList(Ast.ExprId).empty;
        defer new_values.deinit(self.pass.allocator);

        for (loop.values, values, 0..) |known_value, value, index| {
            if (!knownValueMatchesValue(self.pass.program, known_value, value) or !try self.appendExprsFromValue(known_value, value, &new_values)) {
                const refined = try self.refineLoopKnownValueForValue(known_value, value);
                if (try self.noteLoopRefinement(loop, index, refined)) {
                    try self.appendUninitializedExprsForKnownValue(known_value, &new_values);
                } else if (!try self.appendFieldReadExprsFromValue(known_value, value, &new_values)) {
                    Common.invariant("loop continue value could not be split after stable refinement");
                }
                continue;
            }
        }

        return .{ .continue_ = .{
            .values = try self.pass.program.addExprSpan(new_values.items),
        } };
    }

    fn noteLoopRefinement(self: *Cloner, loop: LoopPattern, index: usize, refinement: KnownValue) Allocator.Error!bool {
        if (index >= loop.refinements.len) Common.invariant("loop refinement index exceeded active loop state");
        const merged = if (loop.refinements[index]) |existing|
            try self.commonLoopKnownValue(existing, refinement)
        else
            refinement;
        if (known_valueEql(self.pass.program, loop.values[index], merged)) return false;
        loop.refinements[index] = merged;
        return true;
    }

    fn noteLoopDemandIfLocalExpr(
        self: *Cloner,
        expr_id: Ast.ExprId,
        demand: ValueDemand,
    ) LowerError!void {
        if (self.loop_stack.getLastOrNull()) |loop| {
            for (loop.params, 0..) |param, index| {
                if (index >= loop.demands.len) Common.invariant("loop demand index exceeded active loop state");
                const local_demand = try self.localDemandInExpr(param.local, expr_id, demand);
                if (local_demand == .none) continue;
                loop.demands[index] = try self.mergeActiveLoopParamDemand(loop, index, loop.demands[index], local_demand);
            }
            return;
        }
        const state_loop = self.state_loop_stack.getLastOrNull() orelse return;
        for (state_loop.params, 0..) |param, index| {
            if (index >= state_loop.demands.len or index >= state_loop.values.len) Common.invariant("state loop demand index exceeded active loop state");
            const local_demand = try self.localDemandInExpr(param.local, expr_id, demand);
            if (local_demand == .none) continue;
            try self.mergeActiveStateLoopParamDemand(state_loop, index, local_demand);
        }
    }

    const ActiveStateLoopParam = struct {
        loop: SparseStateLoopPattern,
        param_index: usize,
    };

    /// Loop-lifetime demand slots outlive every function-demand frame, so a
    /// stored slot demand must not reference one: a frame reference stored in
    /// a loop slot dies with its frame and silently swallows later merges.
    /// Active references are resolved to their current frame-slot demand
    /// (cutting self-references); references whose frame already ended carry
    /// no demand, matching loop-demand closure.
    fn loopSlotDemand(self: *Cloner, demand: ValueDemand) LowerError!ValueDemand {
        var seen = std.ArrayList(usize).empty;
        defer seen.deinit(self.pass.allocator);
        return try self.loopSlotDemandSeen(demand, &seen);
    }

    fn loopSlotDemandSeen(
        self: *Cloner,
        demand: ValueDemand,
        seen: *std.ArrayList(usize),
    ) LowerError!ValueDemand {
        return switch (demand) {
            .none,
            .materialize,
            .loop_param,
            => demand,
            .fn_param => |demand_ref| blk: {
                if (!self.functionDemandSlotIdIsActive(demand_ref)) break :blk .none;
                const root_ref = self.canonicalFunctionDemandSlotId(demand_ref);
                for (seen.items) |seen_node| {
                    if (seen_node == root_ref.node) break :blk .none;
                }
                try seen.append(self.pass.allocator, root_ref.node);
                defer _ = seen.pop();
                const resolved = self.activeFunctionDemandSlot(root_ref).*;
                if (resolved == .fn_param and functionDemandSlotIdEql(resolved.fn_param, root_ref)) break :blk .none;
                break :blk try self.loopSlotDemandSeen(resolved, seen);
            },
            .record => |fields| blk: {
                const closed_fields = try self.pass.arena.allocator().alloc(FieldDemand, fields.len);
                for (fields, closed_fields) |field, *closed| {
                    closed.* = .{
                        .name = field.name,
                        .demand = try self.pass.storedDemand(try self.loopSlotDemandSeen(field.demand.*, seen)),
                    };
                }
                break :blk ValueDemand{ .record = closed_fields };
            },
            .tuple => |items| blk: {
                const closed_items = try self.pass.arena.allocator().alloc(ItemDemand, items.len);
                for (items, closed_items) |item, *closed| {
                    closed.* = .{
                        .index = item.index,
                        .demand = try self.pass.storedDemand(try self.loopSlotDemandSeen(item.demand.*, seen)),
                    };
                }
                break :blk ValueDemand{ .tuple = closed_items };
            },
            .tag => |tag| blk: {
                const alternatives = try self.pass.arena.allocator().alloc(TagAlternativeDemand, tag.alternatives.len);
                for (tag.alternatives, alternatives) |alternative, *closed_alternative| {
                    const payloads = try self.pass.arena.allocator().alloc(ItemDemand, alternative.payloads.len);
                    for (alternative.payloads, payloads) |payload, *closed_payload| {
                        closed_payload.* = .{
                            .index = payload.index,
                            .demand = try self.pass.storedDemand(try self.loopSlotDemandSeen(payload.demand.*, seen)),
                        };
                    }
                    closed_alternative.* = .{
                        .name = alternative.name,
                        .payloads = payloads,
                    };
                }
                break :blk ValueDemand{ .tag = .{ .alternatives = alternatives } };
            },
            .nominal => |backing| ValueDemand{
                .nominal = try self.pass.storedDemand(try self.loopSlotDemandSeen(backing.*, seen)),
            },
            .callable => |callable| blk: {
                const captures = try self.pass.arena.allocator().alloc(ValueDemand, callable.captures.len);
                for (callable.captures, captures) |capture, *closed_capture| {
                    closed_capture.* = try self.loopSlotDemandSeen(capture, seen);
                }
                const result = if (callable.result) |result_demand|
                    try self.pass.storedDemand(try self.loopSlotDemandSeen(result_demand.*, seen))
                else
                    null;
                break :blk ValueDemand{ .callable = .{
                    .captures = captures,
                    .result = result,
                } };
            },
        };
    }

    fn activeStateLoopOwningParam(self: *Cloner, source_local: Ast.LocalId) ?ActiveStateLoopParam {
        var stack_index = self.state_loop_stack.items.len;
        while (stack_index > 0) {
            stack_index -= 1;
            const loop = self.state_loop_stack.items[stack_index];
            for (loop.params, 0..) |param, param_index| {
                if (param.local != source_local) continue;
                return .{ .loop = loop, .param_index = param_index };
            }
        }
        return null;
    }

    fn noteLoopStateCallableDemand(
        self: *Cloner,
        callable: PrivateStateCallable,
        origin: PrivateStateLoopOrigin,
        source_captures: []const Ast.TypedLocal,
        demand: ValueDemand,
    ) LowerError!void {
        const owner = self.activeStateLoopOwningParam(origin.source_local) orelse
            Common.invariant("loop-state callable was called outside its owning loop fixed point");
        const capture_demands = try self.pass.arena.allocator().alloc(ValueDemand, source_captures.len);
        var has_observed_demand = demand != .none;
        for (source_captures, capture_demands) |source_capture, *out| {
            out.* = if (demand == .none)
                self.plannedLocalDemand(callable.fn_id, source_capture.local)
            else
                try self.functionLocalDemand(callable.fn_id, source_capture.local, demand);
            if (out.* != .none) has_observed_demand = true;
        }
        if (!has_observed_demand) return;
        const callable_demand = try self.callableDemandWithResult(capture_demands, demand);
        const observed = try self.demandAtPath(origin.path, callable_demand);
        try self.mergeActiveStateLoopParamDemand(owner.loop, owner.param_index, observed);
    }

    fn mergeActiveLoopParamDemand(
        self: *Cloner,
        loop: LoopPattern,
        index: usize,
        existing: ValueDemand,
        incoming: ValueDemand,
    ) LowerError!ValueDemand {
        if (loop.source_values) |source_values| {
            if (index >= source_values.len) Common.invariant("loop source-value demand index exceeded active loop arity");
            return try self.mergeLoopValueParamDemand(source_values[index], existing, incoming);
        }
        if (index >= loop.values.len) Common.invariant("loop known-value demand index exceeded active loop arity");
        return try self.mergeLoopParamDemand(loop.values[index], existing, incoming);
    }

    fn mergeActiveStateLoopParamDemand(
        self: *Cloner,
        loop: SparseStateLoopPattern,
        index: usize,
        incoming: ValueDemand,
    ) LowerError!void {
        if (index >= loop.values.len) Common.invariant("state loop source-value demand index exceeded active loop arity");
        if (incoming == .none) return;

        if (self.activeLoopDemandMergeFrame(index)) |frame_index| {
            try self.queueLoopDemandMergeInput(frame_index, incoming);
            return;
        }

        try self.loop_demand_merge_stack.append(self.pass.allocator, .{
            .index = index,
            .extras = .empty,
        });
        const frame_index = self.loop_demand_merge_stack.items.len - 1;
        defer {
            self.loop_demand_merge_stack.items[frame_index].extras.deinit(self.pass.allocator);
            _ = self.loop_demand_merge_stack.pop();
        }

        try self.mergeStateLoopDemandInputRaw(loop, index, incoming);
        var extra_index: usize = 0;
        var normalize_iterations: usize = 0;
        while (true) {
            while (extra_index < self.loop_demand_merge_stack.items[frame_index].extras.items.len) {
                if (extra_index > 1000) Common.invariant("state loop demand merge input queue did not converge");
                const extra = self.loop_demand_merge_stack.items[frame_index].extras.items[extra_index];
                extra_index += 1;
                try self.mergeStateLoopDemandInputRaw(loop, index, extra);
            }

            normalize_iterations += 1;
            if (normalize_iterations > 1000) Common.invariant("state loop demand normalization did not converge");

            const current = loop.demands[index];
            const normalized = try self.loopSlotDemand(try self.normalizeLoopValueParamDemand(loop.values[index], current));
            if (try self.valueDemandEqlInActiveContext(current, normalized)) break;
            loop.demands[index] = normalized;
            loop.changed.* = true;
            self.demand_cache_epoch += 1;
        }
    }

    fn activeLoopDemandMergeFrame(self: *Cloner, index: usize) ?usize {
        var stack_index = self.loop_demand_merge_stack.items.len;
        while (stack_index > 0) {
            stack_index -= 1;
            if (self.loop_demand_merge_stack.items[stack_index].index == index) return stack_index;
        }
        return null;
    }

    fn queueLoopDemandMergeInput(self: *Cloner, frame_index: usize, incoming: ValueDemand) Allocator.Error!void {
        const frame = &self.loop_demand_merge_stack.items[frame_index];
        for (frame.extras.items) |extra| {
            if (try self.valueDemandEqlInActiveContext(extra, incoming)) return;
        }
        try frame.extras.append(self.pass.allocator, incoming);
    }

    fn mergeStateLoopDemandInputRaw(
        self: *Cloner,
        loop: SparseStateLoopPattern,
        index: usize,
        incoming: ValueDemand,
    ) LowerError!void {
        const current = loop.demands[index];
        if (try self.valueDemandEqlInActiveContext(current, incoming)) return;
        const merged = try self.mergeValueDemand(current, incoming);
        const stored = try self.loopSlotDemand(merged);
        if (try self.valueDemandEqlInActiveContext(current, stored)) return;
        loop.demands[index] = stored;
        loop.changed.* = true;
        self.demand_cache_epoch += 1;
    }

    fn mergeLoopParamDemand(
        self: *Cloner,
        known_value: KnownValue,
        existing: ValueDemand,
        incoming: ValueDemand,
    ) LowerError!ValueDemand {
        if (incoming == .loop_param) return existing;
        const merged = try self.mergeValueDemand(existing, incoming);
        return try self.loopSlotDemand(try self.normalizeLoopParamDemand(known_value, merged));
    }

    fn mergeLoopValueParamDemand(
        self: *Cloner,
        value: Value,
        existing: ValueDemand,
        incoming: ValueDemand,
    ) LowerError!ValueDemand {
        if (incoming == .loop_param) return existing;
        const merged = try self.mergeValueDemand(existing, incoming);
        return try self.loopSlotDemand(try self.normalizeLoopValueParamDemand(value, merged));
    }

    fn normalizeLoopParamDemand(
        self: *Cloner,
        known_value: KnownValue,
        demand: ValueDemand,
    ) LowerError!ValueDemand {
        switch (demand) {
            .none, .materialize => return demand,
            else => {},
        }

        const expanded = try self.expandLoopCallableCaptureDemandsKnown(known_value, demand);
        const demanded = (try demandedKnownValueFromDemand(
            self,
            self.pass.program,
            self.pass.arena.allocator(),
            known_value,
            expanded,
        )) orelse return expanded;

        const state_shape = try self.pass.valueDemandFromDemandedKnownValue(demanded);
        return try self.mergeValueDemand(expanded, state_shape);
    }

    fn expandLoopCallableCaptureDemandsKnown(
        self: *Cloner,
        known_value: KnownValue,
        demand: ValueDemand,
    ) LowerError!ValueDemand {
        return switch (demand) {
            .none,
            .materialize,
            .loop_param,
            .fn_param,
            .nominal,
            .tuple,
            .tag,
            => demand,
            .record => |field_demands| blk: {
                var changed = false;
                const expanded_fields = try self.pass.arena.allocator().alloc(FieldDemand, field_demands.len);
                for (field_demands, expanded_fields) |field_demand, *out| {
                    const field_known = fieldKnownValueFromKnownValue(self.pass.program, known_value, field_demand.name) orelse {
                        out.* = field_demand;
                        continue;
                    };
                    const expanded = try self.expandLoopCallableCaptureDemandsKnown(field_known, field_demand.demand.*);
                    changed = true;
                    out.* = .{
                        .name = field_demand.name,
                        .demand = try self.pass.storedDemand(expanded),
                    };
                }
                break :blk if (changed) ValueDemand{ .record = expanded_fields } else demand;
            },
            .callable => |callable_demand| blk: {
                const result_demand = callable_demand.result orelse break :blk demand;
                var merged: ValueDemand = demand;
                switch (known_value) {
                    .callable => |callable| {
                        const derived = try self.callableDemandForFnWithResultDemand(
                            callable.fn_id,
                            self.sourceCaptureCount(callable.fn_id),
                            result_demand.*,
                        );
                        merged = try self.mergeValueDemand(merged, derived);
                    },
                    .finite_callables => |finite_callables| for (finite_callables.alternatives) |alternative| {
                        const derived = try self.callableDemandForFnWithResultDemand(
                            alternative.fn_id,
                            self.sourceCaptureCount(alternative.fn_id),
                            result_demand.*,
                        );
                        merged = try self.mergeValueDemand(merged, derived);
                    },
                    else => {},
                }
                break :blk merged;
            },
        };
    }

    fn normalizeLoopValueParamDemand(
        self: *Cloner,
        value: Value,
        demand: ValueDemand,
    ) LowerError!ValueDemand {
        switch (demand) {
            .none, .materialize => return demand,
            else => {},
        }

        const expanded = try self.expandLoopCallableCaptureDemands(value, demand);
        const demanded = (try self.demandedKnownValueFromValueDemand(value, expanded)) orelse return expanded;
        const state_shape = try self.pass.valueDemandFromDemandedKnownValue(demanded);
        return try self.mergeValueDemand(expanded, state_shape);
    }

    /// Normalized loop demand connects callable result demand to per-target
    /// capture demand before any split consumes the demand vector. The
    /// derivation is deliberately context-free: a loop state key serves every
    /// iteration, so entry-known capture values must not prune capture demand
    /// that only later iterations need.
    fn expandLoopCallableCaptureDemands(
        self: *Cloner,
        value: Value,
        demand: ValueDemand,
    ) LowerError!ValueDemand {
        switch (value) {
            .let_ => |let_value| return try self.expandLoopCallableCaptureDemands(let_value.body.*, demand),
            .expr_with_known_value => |known| if (known.value) |inner| {
                return try self.expandLoopCallableCaptureDemands(inner.*, demand);
            },
            else => {},
        }
        return switch (demand) {
            .none,
            .materialize,
            .loop_param,
            .fn_param,
            .nominal,
            .tuple,
            .tag,
            => demand,
            .record => |field_demands| blk: {
                var changed = false;
                const expanded_fields = try self.pass.arena.allocator().alloc(FieldDemand, field_demands.len);
                for (field_demands, expanded_fields) |field_demand, *out| {
                    const field_value = valueRecordFieldForDemand(self.pass.program, value, field_demand.name) orelse {
                        out.* = field_demand;
                        continue;
                    };
                    const expanded = try self.expandLoopCallableCaptureDemands(field_value, field_demand.demand.*);
                    changed = true;
                    out.* = .{
                        .name = field_demand.name,
                        .demand = try self.pass.storedDemand(expanded),
                    };
                }
                break :blk if (changed) ValueDemand{ .record = expanded_fields } else demand;
            },
            .callable => |callable_demand| blk: {
                const result_demand = callable_demand.result orelse break :blk demand;
                var merged: ValueDemand = demand;
                for (try self.callableTargetsForDemandExpansion(value)) |target| {
                    const derived = try self.callableDemandForFnWithResultDemand(
                        target.fn_id,
                        target.capture_count,
                        result_demand.*,
                    );
                    merged = try self.mergeValueDemand(merged, derived);
                }
                break :blk merged;
            },
        };
    }

    /// Clone a binding value under its derived demand, expanding callable
    /// result demand against the cloned producer until the demand is stable.
    /// Loop-carried bindings need this: demand derived from the binding's
    /// consumers cannot include per-target capture demand until the producer
    /// is cloned, and the binding is the last point where the original
    /// producer can be recloned under the grown normalized demand.
    fn cloneBindingValueWithExpandedDemand(
        self: *Cloner,
        value_expr: Ast.ExprId,
        demand: *ValueDemand,
    ) LowerError!Value {
        if (!valueDemandContainsLoopParam(demand.*)) {
            return try self.cloneExprValueWithDemand(value_expr, demand.*);
        }
        var expand_iterations: usize = 0;
        while (true) {
            expand_iterations += 1;
            if (expand_iterations > 1000) Common.invariant("binding demand expansion did not converge");
            const change_start = self.changes.items.len;
            const cloned = try self.cloneExprValueWithDemand(value_expr, demand.*);
            const expanded = try self.expandLoopCallableCaptureDemands(cloned, demand.*);
            if (try self.valueDemandEqlInActiveContext(demand.*, expanded)) return cloned;
            demand.* = expanded;
            self.restore(change_start);
        }
    }

    const CallableDemandExpansionTarget = struct {
        fn_id: Ast.FnId,
        capture_count: usize,
    };

    fn callableTargetsForDemandExpansion(self: *Cloner, value: Value) LowerError![]const CallableDemandExpansionTarget {
        var targets = std.ArrayList(CallableDemandExpansionTarget).empty;
        defer targets.deinit(self.pass.allocator);
        switch (value) {
            .callable => |callable| try targets.append(self.pass.allocator, .{
                .fn_id = callable.fn_id,
                .capture_count = self.sourceCaptureCount(callable.fn_id),
            }),
            .finite_callables => |finite_callables| for (finite_callables.alternatives) |alternative| {
                try targets.append(self.pass.allocator, .{
                    .fn_id = alternative.fn_id,
                    .capture_count = self.sourceCaptureCount(alternative.fn_id),
                });
            },
            .private_state => |private_state| {
                if (privateStateCallable(private_state)) |private_callable| {
                    try targets.append(self.pass.allocator, .{
                        .fn_id = private_callable.fn_id,
                        .capture_count = self.sourceCaptureCount(private_callable.fn_id),
                    });
                } else if (private_state == .compact_finite_callables) {
                    for (private_state.compact_finite_callables.source.alternatives) |alternative| {
                        try targets.append(self.pass.allocator, .{
                            .fn_id = alternative.fn_id,
                            .capture_count = self.sourceCaptureCount(alternative.fn_id),
                        });
                    }
                }
            },
            .expr_with_known_value => |known| switch (known.known_value) {
                .callable => |callable| try targets.append(self.pass.allocator, .{
                    .fn_id = callable.fn_id,
                    .capture_count = self.sourceCaptureCount(callable.fn_id),
                }),
                .finite_callables => |finite_callables| for (finite_callables.alternatives) |alternative| {
                    try targets.append(self.pass.allocator, .{
                        .fn_id = alternative.fn_id,
                        .capture_count = self.sourceCaptureCount(alternative.fn_id),
                    });
                },
                else => {},
            },
            else => {},
        }
        return try self.pass.arena.allocator().dupe(CallableDemandExpansionTarget, targets.items);
    }

    fn sourceCaptureCount(self: *Cloner, fn_id: Ast.FnId) usize {
        const source_fn = self.pass.program.fns.items[@intFromEnum(fn_id)];
        return self.pass.program.typedLocalSpan(source_fn.captures).len;
    }

    fn valueDemandContainsLoopParam(demand: ValueDemand) bool {
        return switch (demand) {
            .none, .materialize, .fn_param => false,
            .loop_param => true,
            .record => |fields| blk: {
                for (fields) |field| {
                    if (valueDemandContainsLoopParam(field.demand.*)) break :blk true;
                }
                break :blk false;
            },
            .tuple => |items| blk: {
                for (items) |item| {
                    if (valueDemandContainsLoopParam(item.demand.*)) break :blk true;
                }
                break :blk false;
            },
            .tag => |tag| blk: {
                for (tag.alternatives) |alternative| {
                    for (alternative.payloads) |payload| {
                        if (valueDemandContainsLoopParam(payload.demand.*)) break :blk true;
                    }
                }
                break :blk false;
            },
            .nominal => |backing| valueDemandContainsLoopParam(backing.*),
            .callable => |callable| blk: {
                for (callable.captures) |capture| {
                    if (valueDemandContainsLoopParam(capture)) break :blk true;
                }
                if (callable.result) |result| {
                    if (valueDemandContainsLoopParam(result.*)) break :blk true;
                }
                break :blk false;
            },
        };
    }

    fn valueRecordFieldForDemand(program: *const Ast.Program, value: Value, name: names.RecordFieldNameId) ?Value {
        return switch (value) {
            .record => |record| blk: {
                for (record.fields) |field| {
                    if (program.names.recordFieldLabelTextEql(field.name, name)) break :blk field.value;
                }
                break :blk null;
            },
            .nominal => |nominal| valueRecordFieldForDemand(program, nominal.backing.*, name),
            .private_state => |private_state| switch (private_state) {
                .record => |record| blk: {
                    const field_value = privateStateFieldByName(program, record.fields, name) orelse break :blk null;
                    break :blk Value{ .private_state = field_value };
                },
                .nominal => |nominal| blk: {
                    const backing = nominal.backing orelse break :blk null;
                    break :blk valueRecordFieldForDemand(program, .{ .private_state = backing.* }, name);
                },
                else => null,
            },
            else => null,
        };
    }

    fn refineLoopKnownValueForValue(self: *Cloner, known_value: KnownValue, value: Value) LowerError!KnownValue {
        if (knownValueMatchesValue(self.pass.program, known_value, value)) return known_value;

        return switch (known_value) {
            .any => if (value == .private_state)
                (try sparseKnownValueFromPrivateState(self.pass.program, self.pass.arena.allocator(), value.private_state)) orelse known_value
            else
                known_value,
            .leaf => known_value,
            .record => |record| blk: {
                if (recordFromValue(value)) |record_value| {
                    var fields = std.ArrayList(KnownField).empty;
                    defer fields.deinit(self.pass.allocator);
                    for (record_value.fields) |field_value| {
                        const field_known_value = fieldKnownValueFromKnownValue(self.pass.program, .{ .record = record }, field_value.name) orelse
                            KnownValue{ .any = valueType(self.pass.program, field_value.value) };
                        try fields.append(self.pass.allocator, .{
                            .name = field_value.name,
                            .known_value = try self.refineLoopKnownValueForValue(field_known_value, field_value.value),
                        });
                    }
                    break :blk KnownValue{ .record = .{
                        .ty = record.ty,
                        .fields = try self.pass.arena.allocator().dupe(KnownField, fields.items),
                    } };
                }

                const receiver = projectableExprFromValue(value) orelse break :blk KnownValue{ .any = record.ty };
                if (!self.exprReferencesAvailableBindings(receiver)) break :blk KnownValue{ .any = record.ty };
                if (!canReadFieldsFromExpr(self.pass.program, receiver)) break :blk KnownValue{ .any = record.ty };
                const actual_known_value = switch (value) {
                    .expr_with_known_value => |known_value_expr| known_value_expr.known_value,
                    else => null,
                };
                const fields = try self.pass.arena.allocator().alloc(KnownField, record.fields.len);
                for (record.fields, 0..) |field, index| {
                    const actual_field = if (actual_known_value) |actual|
                        fieldKnownValueFromKnownValue(self.pass.program, actual, field.name)
                    else
                        null;
                    const field_expr = try self.addExpr(.{ .ty = known_valueType(field.known_value), .data = .{ .field_access = .{
                        .receiver = receiver,
                        .field = field.name,
                    } } });
                    const field_value = if (actual_field) |actual|
                        valueFromProjectedExpr(field_expr, actual)
                    else
                        Value{ .expr = field_expr };
                    fields[index] = .{
                        .name = field.name,
                        .known_value = try self.refineLoopKnownValueForValue(field.known_value, field_value),
                    };
                }
                break :blk KnownValue{ .record = .{ .ty = record.ty, .fields = fields } };
            },
            .tuple => |tuple| blk: {
                const items = try self.pass.arena.allocator().alloc(KnownValue, tuple.items.len);
                if (tupleFromValue(value)) |tuple_value| {
                    if (tuple.items.len != tuple_value.items.len) Common.invariant("tuple loop state changed item count");
                    for (tuple.items, tuple_value.items, 0..) |item, item_value, index| {
                        items[index] = try self.refineLoopKnownValueForValue(item, item_value);
                    }
                    break :blk KnownValue{ .tuple = .{ .ty = tuple.ty, .items = items } };
                }

                const receiver = projectableExprFromValue(value) orelse break :blk KnownValue{ .any = tuple.ty };
                if (!self.exprReferencesAvailableBindings(receiver)) break :blk KnownValue{ .any = tuple.ty };
                if (!canReadFieldsFromExpr(self.pass.program, receiver)) break :blk KnownValue{ .any = tuple.ty };
                const actual_known_value = switch (value) {
                    .expr_with_known_value => |known_value_expr| known_value_expr.known_value,
                    else => null,
                };
                for (tuple.items, 0..) |item, index| {
                    const actual_item = if (actual_known_value) |actual|
                        itemKnownValueFromKnownValue(actual, @as(u32, @intCast(index)))
                    else
                        null;
                    const item_expr = try self.addExpr(.{ .ty = known_valueType(item), .data = .{ .tuple_access = .{
                        .tuple = receiver,
                        .elem_index = @as(u32, @intCast(index)),
                    } } });
                    const item_value = if (actual_item) |actual|
                        valueFromProjectedExpr(item_expr, actual)
                    else
                        Value{ .expr = item_expr };
                    items[index] = try self.refineLoopKnownValueForValue(item, item_value);
                }
                break :blk KnownValue{ .tuple = .{ .ty = tuple.ty, .items = items } };
            },
            .nominal => |nominal| blk: {
                const value_nominal = switch (value) {
                    .nominal => |nominal_value| nominal_value,
                    else => break :blk KnownValue{ .any = nominal.ty },
                };
                const backing = try self.pass.arena.allocator().create(KnownValue);
                backing.* = try self.refineLoopKnownValueForValue(nominal.backing.*, value_nominal.backing.*);
                break :blk KnownValue{ .nominal = .{ .ty = nominal.ty, .backing = backing } };
            },
            .tag => |tag| blk: {
                if (value == .expr_with_known_value) {
                    if (value.expr_with_known_value.value == null) break :blk KnownValue{ .any = tag.ty };
                    break :blk try self.commonLoopKnownValue(known_value, value.expr_with_known_value.known_value);
                }
                const value_tag = switch (value) {
                    .tag => |tag_value| tag_value,
                    else => break :blk KnownValue{ .any = tag.ty },
                };
                const value_known_value = (try self.pass.knownValueFromValue(.{ .tag = value_tag })) orelse break :blk KnownValue{ .any = tag.ty };
                break :blk try self.commonLoopKnownValue(known_value, value_known_value);
            },
            .callable => |callable| blk: {
                if (value == .expr_with_known_value) {
                    if (value.expr_with_known_value.value == null) break :blk KnownValue{ .any = callable.ty };
                    break :blk try self.commonLoopKnownValue(known_value, value.expr_with_known_value.known_value);
                }
                const callable_value = switch (value) {
                    .callable => |callable_value| callable_value,
                    else => break :blk KnownValue{ .any = callable.ty },
                };
                const value_known_value = (try self.pass.knownValueFromValue(.{ .callable = callable_value })) orelse break :blk KnownValue{ .any = callable.ty };
                break :blk try self.commonLoopKnownValue(known_value, value_known_value);
            },
            .finite_tags => |finite_tags| blk: {
                switch (value) {
                    .expr_with_known_value => |known_value_expr| {
                        if (known_value_expr.value == null) break :blk KnownValue{ .any = finite_tags.ty };
                        break :blk try self.commonLoopKnownValue(known_value, known_value_expr.known_value);
                    },
                    .tag => |tag_value| {
                        const value_known_value = (try self.pass.knownValueFromValue(.{ .tag = tag_value })) orelse break :blk KnownValue{ .any = finite_tags.ty };
                        break :blk try self.commonLoopKnownValue(known_value, value_known_value);
                    },
                    .finite_tags => |finite_value| {
                        const value_known_value = (try self.pass.knownValueFromValue(.{ .finite_tags = finite_value })) orelse break :blk KnownValue{ .any = finite_tags.ty };
                        break :blk try self.commonLoopKnownValue(known_value, value_known_value);
                    },
                    else => break :blk KnownValue{ .any = finite_tags.ty },
                }
            },
            .finite_callables => |finite_callables| blk: {
                switch (value) {
                    .expr_with_known_value => |known_value_expr| {
                        if (known_value_expr.value == null) break :blk KnownValue{ .any = finite_callables.ty };
                        break :blk try self.commonLoopKnownValue(known_value, known_value_expr.known_value);
                    },
                    .callable => |callable_value| {
                        const value_known_value = (try self.pass.knownValueFromValue(.{ .callable = callable_value })) orelse break :blk KnownValue{ .any = finite_callables.ty };
                        break :blk try self.commonLoopKnownValue(known_value, value_known_value);
                    },
                    .finite_callables => |finite_value| {
                        const value_known_value = (try self.pass.knownValueFromValue(.{ .finite_callables = finite_value })) orelse break :blk KnownValue{ .any = finite_callables.ty };
                        break :blk try self.commonLoopKnownValue(known_value, value_known_value);
                    },
                    else => break :blk KnownValue{ .any = finite_callables.ty },
                }
            },
        };
    }

    fn commonLoopKnownValue(self: *Cloner, lhs: KnownValue, rhs: KnownValue) Allocator.Error!KnownValue {
        if (known_valueEql(self.pass.program, lhs, rhs)) return lhs;
        const ty = known_valueType(lhs);
        if (!sameType(self.pass.program, ty, known_valueType(rhs))) Common.invariant("loop state refinement changed type");
        if (try commonKnownTags(self.pass.program, self.pass.arena.allocator(), lhs, rhs)) |finite_tags| {
            return finite_tags;
        }
        if (try commonKnownCallables(self.pass.program, self.pass.arena.allocator(), lhs, rhs)) |finite_callables| {
            return finite_callables;
        }
        if (std.meta.activeTag(lhs) != std.meta.activeTag(rhs)) return .{ .any = ty };

        return switch (lhs) {
            .any => .{ .any = ty },
            .leaf => .{ .leaf = ty },
            .record => |lhs_record| blk: {
                const rhs_record = rhs.record;
                if (lhs_record.fields.len != rhs_record.fields.len) break :blk KnownValue{ .any = ty };
                const fields = try self.pass.arena.allocator().alloc(KnownField, lhs_record.fields.len);
                for (lhs_record.fields, rhs_record.fields, 0..) |lhs_field, rhs_field, index| {
                    if (lhs_field.name != rhs_field.name) break :blk KnownValue{ .any = ty };
                    fields[index] = .{
                        .name = lhs_field.name,
                        .known_value = try self.commonLoopKnownValue(lhs_field.known_value, rhs_field.known_value),
                    };
                }
                break :blk KnownValue{ .record = .{ .ty = lhs_record.ty, .fields = fields } };
            },
            .tuple => |lhs_tuple| blk: {
                const rhs_tuple = rhs.tuple;
                if (lhs_tuple.items.len != rhs_tuple.items.len) break :blk KnownValue{ .any = ty };
                const items = try self.pass.arena.allocator().alloc(KnownValue, lhs_tuple.items.len);
                for (lhs_tuple.items, rhs_tuple.items, 0..) |lhs_item, rhs_item, index| {
                    items[index] = try self.commonLoopKnownValue(lhs_item, rhs_item);
                }
                break :blk KnownValue{ .tuple = .{ .ty = lhs_tuple.ty, .items = items } };
            },
            .nominal => |lhs_nominal| blk: {
                const rhs_nominal = rhs.nominal;
                const backing = try self.pass.arena.allocator().create(KnownValue);
                backing.* = try self.commonLoopKnownValue(lhs_nominal.backing.*, rhs_nominal.backing.*);
                break :blk KnownValue{ .nominal = .{ .ty = lhs_nominal.ty, .backing = backing } };
            },
            .callable => |lhs_callable| blk: {
                const rhs_callable = rhs.callable;
                if (!callableTargetMatches(self.pass.program, lhs_callable.fn_id, rhs_callable.fn_id) or
                    lhs_callable.captures.len != rhs_callable.captures.len)
                {
                    break :blk KnownValue{ .any = ty };
                }
                const captures = try self.pass.arena.allocator().alloc(KnownValue, lhs_callable.captures.len);
                for (lhs_callable.captures, rhs_callable.captures, 0..) |lhs_capture, rhs_capture, index| {
                    captures[index] = try self.commonLoopKnownValue(lhs_capture, rhs_capture);
                }
                break :blk KnownValue{ .callable = .{
                    .ty = lhs_callable.ty,
                    .fn_id = lhs_callable.fn_id,
                    .captures = captures,
                } };
            },
            .tag => .{ .any = ty },
            .finite_tags => .{ .any = ty },
            .finite_callables => .{ .any = ty },
        };
    }

    fn valuesToExprSpan(self: *Cloner, values: []const Value) LowerError!Ast.Span(Ast.ExprId) {
        const exprs = try self.pass.allocator.alloc(Ast.ExprId, values.len);
        defer self.pass.allocator.free(exprs);
        for (values, 0..) |value, index| {
            exprs[index] = try self.materialize(value);
        }
        return try self.pass.program.addExprSpan(exprs);
    }

    fn valuesToOutputExprSpan(self: *Cloner, values: []const Value) LowerError!?Ast.Span(Ast.ExprId) {
        const exprs = try self.pass.allocator.alloc(Ast.ExprId, values.len);
        defer self.pass.allocator.free(exprs);
        for (values, 0..) |value, index| {
            exprs[index] = (try self.outputExprFromValue(value)) orelse return null;
        }
        return try self.pass.program.addExprSpan(exprs);
    }

    fn ensureCallPatternForValues(self: *Cloner, fn_id: Ast.FnId, values: []const Value) LowerError!void {
        const capture_values = try self.directCallCaptureValues(fn_id);
        defer if (capture_values) |captures| self.pass.allocator.free(captures);
        _ = try self.ensureCallPatternForValuesWithDemandAndCaptures(fn_id, capture_values, values, .materialize);
    }

    fn ensureCallPatternForValuesWithDemand(
        self: *Cloner,
        fn_id: Ast.FnId,
        values: []const Value,
        result_demand: ValueDemand,
    ) LowerError!?usize {
        const capture_values = try self.directCallCaptureValues(fn_id);
        defer if (capture_values) |captures| self.pass.allocator.free(captures);
        return try self.ensureCallPatternForValuesWithDemandAndCaptures(fn_id, capture_values, values, result_demand);
    }

    fn ensureCallPatternForValuesWithDemandAndCaptures(
        self: *Cloner,
        fn_id: Ast.FnId,
        capture_values: ?[]const Value,
        values: []const Value,
        result_demand: ValueDemand,
    ) LowerError!?usize {
        const raw = @intFromEnum(fn_id);
        if (raw >= self.pass.plans.len) return null;
        const closed_result_demand = try self.closeLoopDemandRefs(result_demand);

        const fn_captures = self.pass.program.typedLocalSpan(self.pass.program.fns.items[raw].captures);
        if (capture_values) |captures| {
            if (captures.len != fn_captures.len) Common.invariant("call-pattern capture value count differed from lifted function capture arity");
        }
        const fn_args = self.pass.program.typedLocalSpan(self.pass.program.fns.items[raw].args);
        if (values.len != fn_args.len) Common.invariant("direct call arity differed from lifted function arity");

        const compact_result = try self.compactResultForDemand(self.pass.program.fns.items[raw].ret, closed_result_demand);
        const known_captures = try self.pass.arena.allocator().alloc(CallPatternCapture, fn_captures.len);
        @memset(known_captures, .unused);
        const known_values = try self.pass.arena.allocator().alloc(DemandedKnownValue, values.len);
        var has_constructor = false;
        for (fn_captures, 0..) |capture, index| {
            if (!self.pass.plans[raw].used_captures[index]) continue;
            const worker_capture_demand = try self.functionLocalDemand(fn_id, capture.local, closed_result_demand);
            if (worker_capture_demand == .none) continue;
            const capture_value = if (capture_values) |captures| captures[index] else return null;
            if (try self.demandedKnownValueFromValueDemand(capture_value, worker_capture_demand)) |known_value| {
                known_captures[index] = .{ .split = known_value };
                has_constructor = has_constructor or demandedKnownValueHasStructure(known_value);
            } else {
                known_captures[index] = .residual;
            }
        }
        for (values, 0..) |value, index| {
            if (self.pass.plans[raw].used_args[index]) {
                const worker_arg_demand = try self.functionLocalDemand(fn_id, fn_args[index].local, closed_result_demand);
                if (try self.demandedKnownValueFromValueDemand(value, worker_arg_demand)) |known_value| {
                    known_values[index] = known_value;
                    if (worker_arg_demand != .none) {
                        has_constructor = has_constructor or demandedKnownValueHasStructure(known_value);
                    }
                    continue;
                }
            }
            known_values[index] = .{ .any = valueType(self.pass.program, value) };
        }
        if (!has_constructor and compact_result == null) return null;
        const pattern: CallPattern = .{
            .captures = known_captures,
            .args = known_values,
        };
        for (self.pass.plans[raw].specs.items, 0..) |spec, spec_index| {
            if (specEql(self.pass.program, spec, pattern, closed_result_demand)) return spec_index;
        }
        const spec_index = self.pass.plans[raw].specs.items.len;
        try self.pass.plans[raw].specs.append(self.pass.allocator, .{
            .pattern = pattern,
            .result_demand = closed_result_demand,
            .compact_result = compact_result,
        });
        try self.pass.reserveWorker(@enumFromInt(@as(u32, @intCast(raw))), spec_index);
        try self.refineReservedCallPatternResult(fn_id, spec_index);
        return spec_index;
    }

    fn refineReservedCallPatternResult(
        self: *Cloner,
        fn_id: Ast.FnId,
        spec_index: usize,
    ) LowerError!void {
        const raw = @intFromEnum(fn_id);
        if (raw >= self.pass.plans.len) Common.invariant("reserved call-pattern source fn exceeded plan count");
        const spec = self.pass.plans[raw].specs.items[spec_index];
        if (spec.compact_result == null) return;

        const source_fn = self.pass.program.fns.items[raw];
        const source_body = self.pass.originalBody(fn_id) orelse switch (source_fn.body) {
            .roc => |body| body,
            .hosted => return,
        };
        const spec_fn_id = spec.fn_id orelse Common.invariant("reserved call-pattern result refinement saw unreserved worker");

        var probe = Cloner.init(self.pass, fn_id, spec_fn_id, spec.pattern);
        defer probe.deinit();
        try probe.bindCallPatternArgs(self.pass.program.fns.items[@intFromEnum(spec_fn_id)].args);

        const source_args = self.pass.program.typedLocalSpan(source_fn.args);
        const active_values = try self.pass.allocator.alloc(Value, source_args.len);
        defer self.pass.allocator.free(active_values);
        for (source_args, active_values) |source_arg, *value| {
            value.* = probe.subst.get(source_arg.local) orelse
                Common.invariant("reserved call-pattern argument was not bound during result refinement");
        }
        const active_args = try probe.directCallActiveArgsFromValues(active_values);
        try probe.inline_stack.append(self.pass.allocator, .{
            .fn_id = fn_id,
            .args = active_args,
        });
        defer {
            const popped = probe.inline_stack.pop() orelse Common.invariant("call-pattern result refinement inline stack underflow");
            if (popped.fn_id != fn_id) Common.invariant("call-pattern result refinement inline stack was corrupted");
        }

        const value = try probe.cloneExprValueWithDemand(source_body, spec.result_demand);
        const demanded = (try probe.demandedKnownValueFromValueDemand(value, spec.result_demand)) orelse return;
        self.pass.plans[raw].specs.items[spec_index].compact_result = try probe.compactResultFromDemandedKnownValue(demanded);
    }

    fn directCallExprFromValues(
        self: *Cloner,
        ty: Type.TypeId,
        callee: Ast.FnId,
        is_cold: bool,
        values: []const Value,
    ) LowerError!Ast.ExprId {
        const capture_values = try self.directCallCaptureValues(callee);
        defer if (capture_values) |captures| self.pass.allocator.free(captures);
        return try self.directCallExprFromValuesAndCaptures(ty, callee, is_cold, capture_values, values);
    }

    fn directCallExprFromValuesAndCaptures(
        self: *Cloner,
        ty: Type.TypeId,
        callee: Ast.FnId,
        is_cold: bool,
        capture_values: ?[]const Value,
        values: []const Value,
    ) LowerError!Ast.ExprId {
        const raw = @intFromEnum(callee);
        if (!is_cold and raw < self.pass.plans.len) {
            if (self.record_call_patterns) {
                _ = try self.ensureCallPatternForValuesWithDemandAndCaptures(callee, capture_values, values, .materialize);
            }

            for (self.pass.plans[raw].specs.items) |spec| {
                if (spec.result_demand != .materialize) continue;
                const spec_fn_id = spec.fn_id orelse
                    Common.invariant("call-pattern specialization id was not assigned before cloning value call");
                var rewritten_args = std.ArrayList(Ast.ExprId).empty;
                defer rewritten_args.deinit(self.pass.allocator);

                if (try self.appendCallArgValues(spec.pattern, capture_values, values, &rewritten_args)) {
                    const residual_captures = (try self.residualCaptureValuesForCallPattern(callee, spec.pattern, capture_values)) orelse continue;
                    defer self.pass.allocator.free(residual_captures);
                    const expected_arg_count = callPatternArgCount(spec.pattern);
                    if (rewritten_args.items.len != expected_arg_count) {
                        Common.invariant("call-pattern direct-call rewrite produced the wrong argument count");
                    }
                    const call_expr = try self.addExpr(.{ .ty = ty, .data = .{ .call_proc = .{
                        .callee = .{ .lifted = spec_fn_id },
                        .args = try self.pass.program.addExprSpan(rewritten_args.items),
                        .is_cold = is_cold,
                    } } });
                    return if (residual_captures.len != 0)
                        try self.wrapDirectCallCaptureValueLets(ty, spec_fn_id, residual_captures, call_expr)
                    else
                        call_expr;
                }
            }
        }

        const materialized_args = try self.valuesToExprSpan(values);
        const call_expr = try self.addExpr(.{ .ty = ty, .data = .{ .call_proc = .{
            .callee = .{ .lifted = callee },
            .args = materialized_args,
            .is_cold = is_cold,
        } } });
        return if (capture_values) |captures|
            try self.wrapDirectCallCaptureValueLets(ty, callee, captures, call_expr)
        else
            call_expr;
    }

    fn directCallValueFromValuesWithDemand(
        self: *Cloner,
        ty: Type.TypeId,
        callee: Ast.FnId,
        is_cold: bool,
        values: []const Value,
        demand: ValueDemand,
    ) LowerError!Value {
        if (demand == .none or demand == .materialize) {
            return .{ .expr = try self.directCallExprFromValues(ty, callee, is_cold, values) };
        }

        const capture_values = try self.directCallCaptureValues(callee);
        defer if (capture_values) |captures| self.pass.allocator.free(captures);
        return try self.directCallValueFromValuesWithDemandAndCaptures(ty, callee, is_cold, capture_values, values, demand);
    }

    fn directCallValueFromValuesWithDemandAndCaptures(
        self: *Cloner,
        ty: Type.TypeId,
        callee: Ast.FnId,
        is_cold: bool,
        capture_values: ?[]const Value,
        values: []const Value,
        demand: ValueDemand,
    ) LowerError!Value {
        const closed_demand = try self.closeLoopDemandRefs(demand);
        if (closed_demand == .none or closed_demand == .materialize) {
            return .{ .expr = try self.directCallExprFromValuesAndCaptures(ty, callee, is_cold, capture_values, values) };
        }

        const raw = @intFromEnum(callee);
        if (!is_cold and raw < self.pass.plans.len) {
            if (self.record_call_patterns) {
                _ = try self.ensureCallPatternForValuesWithDemandAndCaptures(callee, capture_values, values, closed_demand);
            }

            for (self.pass.plans[raw].specs.items) |spec| {
                if (!valueDemandEql(self.pass.program, spec.result_demand, closed_demand)) continue;
                const spec_fn_id = spec.fn_id orelse
                    Common.invariant("demand-keyed call-pattern specialization id was not assigned before cloning value call");

                var rewritten_args = std.ArrayList(Ast.ExprId).empty;
                defer rewritten_args.deinit(self.pass.allocator);

                if (try self.appendCallArgValues(spec.pattern, capture_values, values, &rewritten_args)) {
                    const residual_captures = (try self.residualCaptureValuesForCallPattern(callee, spec.pattern, capture_values)) orelse continue;
                    defer self.pass.allocator.free(residual_captures);
                    const expected_arg_count = callPatternArgCount(spec.pattern);
                    if (rewritten_args.items.len != expected_arg_count) {
                        Common.invariant("demand-keyed direct-call rewrite produced the wrong argument count");
                    }
                    const result = spec.compact_result orelse
                        {
                            Common.invariant("demand-keyed direct call matched a materializing worker");
                        };
                    const call_expr = try self.addExpr(.{ .ty = result.ty, .data = .{ .call_proc = .{
                        .callee = .{ .lifted = spec_fn_id },
                        .args = try self.pass.program.addExprSpan(rewritten_args.items),
                        .is_cold = is_cold,
                    } } });
                    const wrapped_call = if (residual_captures.len != 0)
                        try self.wrapDirectCallCaptureValueLets(result.ty, spec_fn_id, residual_captures, call_expr)
                    else
                        call_expr;
                    return .{ .private_state = try self.privateStateValueFromCompactResult(result, wrapped_call) };
                }
            }
        }

        Common.invariant("demanded direct call could not be represented by a demand-keyed worker");
    }

    fn appendCallArgValues(
        self: *Cloner,
        pattern: CallPattern,
        capture_values: ?[]const Value,
        values: []const Value,
        out: *std.ArrayList(Ast.ExprId),
    ) LowerError!bool {
        var has_capture_pattern = false;
        for (pattern.captures) |known_value| {
            if (known_value == .split) {
                has_capture_pattern = true;
                break;
            }
        }
        if (has_capture_pattern) {
            const captures = capture_values orelse return false;
            if (pattern.captures.len != captures.len) Common.invariant("call-pattern capture arity differed from direct call capture value arity");
            for (pattern.captures, captures) |known_value, value| {
                const pattern_capture = switch (known_value) {
                    .unused,
                    .residual,
                    => continue,
                    .split => |split| split,
                };
                if (!demandedKnownValueMatchesValue(self.pass.program, pattern_capture, value)) return false;
                if (!try self.appendExprsFromDemandedKnownValue(pattern_capture, value, out)) return false;
            }
        }
        if (pattern.args.len != values.len) Common.invariant("call-pattern arity differed from direct call value arity");
        for (pattern.args, values) |known_value, value| {
            if (!demandedKnownValueMatchesValue(self.pass.program, known_value, value)) return false;
            if (!try self.appendExprsFromDemandedKnownValue(known_value, value, out)) return false;
        }
        return true;
    }

    fn residualCaptureValuesForCallPattern(
        self: *Cloner,
        source_fn_id: Ast.FnId,
        pattern: CallPattern,
        capture_values: ?[]const Value,
    ) Allocator.Error!?[]const Value {
        const source_fn = self.pass.program.fns.items[@intFromEnum(source_fn_id)];
        const source_captures = self.pass.program.typedLocalSpan(source_fn.captures);
        if (source_captures.len != pattern.captures.len) Common.invariant("call-pattern capture count differed from source function capture arity");

        var residual_count: usize = 0;
        for (pattern.captures) |capture| {
            if (capture == .residual) residual_count += 1;
        }

        const values = try self.pass.allocator.alloc(Value, residual_count);
        errdefer self.pass.allocator.free(values);
        if (residual_count == 0) return values;

        const captures = capture_values orelse {
            self.pass.allocator.free(values);
            return null;
        };
        if (captures.len != source_captures.len) Common.invariant("call-pattern capture value count differed from source function capture arity");

        var out_index: usize = 0;
        for (pattern.captures, captures) |capture, value| {
            if (capture != .residual) continue;
            values[out_index] = value;
            out_index += 1;
        }
        if (out_index != values.len) Common.invariant("residual capture projection count changed while projecting values");

        return values;
    }

    fn appendCallArgValueForKnownValue(
        self: *Cloner,
        known_value: KnownValue,
        value: Value,
        out: *std.ArrayList(Ast.ExprId),
    ) LowerError!bool {
        switch (known_value) {
            .any => {
                const expr = (try self.outputExprFromValue(value)) orelse return false;
                try out.append(self.pass.allocator, expr);
                return true;
            },
            else => {
                if (!knownValueMatchesValue(self.pass.program, known_value, value)) return false;
                return try self.appendExprsFromValue(known_value, value, out);
            },
        }
    }

    fn cloneCallProcExpr(self: *Cloner, ty: Type.TypeId, call: @import("../monotype/ast.zig").CallProc) LowerError!Ast.ExprId {
        const data = try self.cloneCallProcData(call);
        const cloned_call = switch (data) {
            .call_proc => |cloned| cloned,
            else => Common.invariant("direct call cloning produced a non-call expression"),
        };
        const call_expr = try self.addExpr(.{ .ty = ty, .data = data });
        return try self.wrapDirectCallCaptureLets(ty, Ast.callProcCallee(cloned_call), call_expr);
    }

    fn cloneCallProcData(self: *Cloner, call: @import("../monotype/ast.zig").CallProc) LowerError!Ast.ExprData {
        if (call.is_cold) {
            return .{ .call_proc = .{
                .callee = call.callee,
                .args = try self.cloneExprSpan(call.args),
                .is_cold = true,
            } };
        }

        const callee = Ast.callProcCallee(call);
        const raw = @intFromEnum(callee);
        if (raw < self.pass.plans.len) {
            const source_args = self.pass.program.exprSpan(call.args);
            const args = try self.pass.allocator.dupe(Ast.ExprId, source_args);
            defer self.pass.allocator.free(args);

            const values = try self.pass.allocator.alloc(Value, args.len);
            defer self.pass.allocator.free(values);
            for (args, 0..) |arg, index| {
                values[index] = try self.cloneExprValue(arg);
            }
            const capture_values = try self.directCallCaptureValues(callee);
            defer if (capture_values) |captures| self.pass.allocator.free(captures);
            if (self.record_call_patterns) {
                _ = try self.ensureCallPatternForValuesWithDemandAndCaptures(callee, capture_values, values, .materialize);
            }

            for (self.pass.plans[raw].specs.items) |spec| {
                if (spec.result_demand != .materialize) continue;
                const spec_fn_id = spec.fn_id orelse
                    Common.invariant("call-pattern specialization id was not assigned before cloning calls");
                var rewritten_args = std.ArrayList(Ast.ExprId).empty;
                defer rewritten_args.deinit(self.pass.allocator);

                if (try self.appendCallArgValues(spec.pattern, capture_values, values, &rewritten_args)) {
                    const expected_arg_count = callPatternArgCount(spec.pattern);
                    if (rewritten_args.items.len != expected_arg_count) {
                        Common.invariant("cloned direct-call rewrite produced the wrong argument count");
                    }
                    return .{ .call_proc = .{
                        .callee = .{ .lifted = spec_fn_id },
                        .args = try self.pass.program.addExprSpan(rewritten_args.items),
                        .is_cold = call.is_cold,
                    } };
                }
            }
            const materialized_args = try self.cloneDirectCallBoundaryArgs(call.args);
            return .{ .call_proc = .{
                .callee = call.callee,
                .args = materialized_args,
                .is_cold = call.is_cold,
            } };
        }
        const materialized_args = try self.cloneDirectCallBoundaryArgs(call.args);
        return .{ .call_proc = .{
            .callee = call.callee,
            .args = materialized_args,
            .is_cold = call.is_cold,
        } };
    }

    fn wrapDirectCallCaptureLets(self: *Cloner, ty: Type.TypeId, callee: Ast.FnId, call_expr: Ast.ExprId) LowerError!Ast.ExprId {
        const callee_fn = self.pass.program.fns.items[@intFromEnum(callee)];
        const captures = self.pass.program.typedLocalSpan(callee_fn.captures);
        if (captures.len == 0) return call_expr;

        const values = try self.pass.allocator.alloc(?Ast.ExprId, captures.len);
        defer self.pass.allocator.free(values);
        for (captures, 0..) |capture, index| {
            const value = self.subst.get(capture.local) orelse {
                values[index] = null;
                continue;
            };
            const value_expr = try self.materialize(value);
            const value_local = localExpr(self.pass.program, value_expr);
            values[index] = if (value_local != null and value_local.? == capture.local) null else value_expr;
        }

        var result = call_expr;
        var index = values.len;
        while (index > 0) {
            index -= 1;
            const value_expr = values[index] orelse continue;
            const pat = try self.pass.program.addPat(.{
                .ty = captures[index].ty,
                .data = .{ .bind = captures[index].local },
            });
            result = try self.addExpr(.{ .ty = ty, .data = .{ .let_ = .{
                .bind = pat,
                .value = value_expr,
                .rest = result,
            } } });
        }
        return result;
    }

    fn wrapDirectCallCaptureValueLets(
        self: *Cloner,
        ty: Type.TypeId,
        callee: Ast.FnId,
        capture_values: []const Value,
        call_expr: Ast.ExprId,
    ) LowerError!Ast.ExprId {
        const callee_fn = self.pass.program.fns.items[@intFromEnum(callee)];
        const captures = self.pass.program.typedLocalSpan(callee_fn.captures);
        if (captures.len != capture_values.len) Common.invariant("direct call capture value count differed from callee capture arity");
        if (captures.len == 0) return call_expr;

        const values = try self.pass.allocator.alloc(?Ast.ExprId, captures.len);
        defer self.pass.allocator.free(values);
        for (captures, capture_values, 0..) |capture, value, index| {
            const value_expr = try self.materialize(value);
            const value_local = localExpr(self.pass.program, value_expr);
            values[index] = if (value_local != null and value_local.? == capture.local) null else value_expr;
        }

        var result = call_expr;
        var index = values.len;
        while (index > 0) {
            index -= 1;
            const value_expr = values[index] orelse continue;
            const pat = try self.pass.program.addPat(.{
                .ty = captures[index].ty,
                .data = .{ .bind = captures[index].local },
            });
            result = try self.addExpr(.{ .ty = ty, .data = .{ .let_ = .{
                .bind = pat,
                .value = value_expr,
                .rest = result,
            } } });
        }

        return result;
    }

    fn appendExprsFromValue(
        self: *Cloner,
        known_value: KnownValue,
        value: Value,
        out: *std.ArrayList(Ast.ExprId),
    ) LowerError!bool {
        return try self.appendFieldReadExprsFromValue(known_value, value, out);
    }

    fn privateStateOutputExpr(self: *Cloner, value: PrivateStateValue) LowerError!?Ast.ExprId {
        const leaf_expr = privateStateLeafExpr(value) orelse return null;
        const substituted = (try self.substitutedPrivateLeafValue(value)) orelse return leaf_expr;
        if (substituted == .private_state and privateStateEql(self.pass.program, substituted.private_state, value)) {
            return leaf_expr;
        }
        return (try self.outputExprFromSubstitutedLeafValue(substituted)) orelse leaf_expr;
    }

    fn outputExprFromSubstitutedLeafValue(self: *Cloner, value: Value) LowerError!?Ast.ExprId {
        return try self.outputExprFromValue(value);
    }

    fn outputExprFromValue(self: *Cloner, value: Value) LowerError!?Ast.ExprId {
        if (value == .expr) {
            if (!self.exprReferencesAvailableBindings(value.expr)) return null;
            return value.expr;
        }

        if (value == .expr_with_known_value) {
            const known = value.expr_with_known_value;
            if (try self.substitutedKnownExprValue(known)) |substituted| {
                if (!self.valueCanMaterializePublic(substituted)) return null;
                return try self.materializePublic(substituted);
            }
            if (!self.exprCanSubstitute(known.expr)) {
                if (known.value) |structured| {
                    if (self.valueCanMaterializePublic(structured.*)) {
                        return try self.materializePublic(structured.*);
                    }
                }
                if (!self.exprReferencesAvailableBindings(known.expr)) return null;
            }
            return known.expr;
        }

        if (!self.valueCanMaterializePublic(value)) return null;
        return try self.materializePublic(value);
    }

    fn outputExprFromValueWithPendingLets(
        self: *Cloner,
        value: Value,
        pending_lets: []const PendingLet,
    ) LowerError!?Ast.ExprId {
        if (pending_lets.len == 0) return try self.outputExprFromValue(value);

        const scoped_start = self.scopedLocalsLen();
        defer self.restoreScopedLocals(scoped_start);
        for (pending_lets) |pending| {
            try self.scoped_locals.append(self.pass.allocator, pending.local);
        }

        const change_start = self.changes.items.len;
        defer self.restore(change_start);
        try self.bindPendingLetKnownValues(pending_lets);

        return try self.outputExprFromValue(value);
    }

    fn valueAtDemandedLeafType(self: *Cloner, ty: Type.TypeId, value: Value) Allocator.Error!Value {
        if (try self.backingValueForDemandedNamedType(ty, value)) |backing| {
            return try self.namedValueFromBackingValue(ty, backing);
        }
        if (sameType(self.pass.program, ty, valueType(self.pass.program, value))) return value;

        const backing_ty = nominalBackingType(self.pass.program, ty) orelse return value;
        if (!sameType(self.pass.program, backing_ty, valueType(self.pass.program, value))) return value;

        return try self.namedValueFromBackingValue(ty, value);
    }

    fn namedValueFromBackingValue(self: *Cloner, ty: Type.TypeId, backing_value: Value) Allocator.Error!Value {
        if (backing_value == .private_state) {
            const backing = try self.pass.arena.allocator().create(PrivateStateValue);
            backing.* = backing_value.private_state;
            return .{ .private_state = .{ .nominal = .{
                .ty = ty,
                .backing = backing,
            } } };
        }

        return .{ .nominal = .{
            .ty = ty,
            .backing = try self.copyValue(backing_value),
        } };
    }

    fn backingValueForDemandedNamedType(self: *Cloner, ty: Type.TypeId, value: Value) Allocator.Error!?Value {
        const backing_ty = nominalBackingType(self.pass.program, ty) orelse return null;

        if (sameType(self.pass.program, backing_ty, valueType(self.pass.program, value))) return value;
        if (!sameType(self.pass.program, ty, valueType(self.pass.program, value))) return null;

        return switch (value) {
            .record => |record| .{ .record = .{
                .ty = backing_ty,
                .fields = record.fields,
            } },
            .tuple => |tuple| .{ .tuple = .{
                .ty = backing_ty,
                .items = tuple.items,
            } },
            .tag => |tag| .{ .tag = .{
                .ty = backing_ty,
                .name = tag.name,
                .payloads = tag.payloads,
            } },
            .private_state => |private_state| if (try self.privateBackingValueForDemandedNamedType(backing_ty, private_state)) |backing|
                Value{ .private_state = backing }
            else
                null,
            .nominal,
            .expr,
            .expr_with_known_value,
            .let_,
            .if_,
            .match_,
            .callable,
            .finite_tags,
            .finite_callables,
            => null,
        };
    }

    fn privateBackingValueForDemandedNamedType(
        self: *Cloner,
        backing_ty: Type.TypeId,
        value: PrivateStateValue,
    ) Allocator.Error!?PrivateStateValue {
        if (sameType(self.pass.program, backing_ty, privateStateValueType(value))) return value;

        return switch (value) {
            .record => |record| .{ .record = .{
                .ty = backing_ty,
                .fields = record.fields,
            } },
            .tuple => |tuple| .{ .tuple = .{
                .ty = backing_ty,
                .items = tuple.items,
            } },
            .tag => |tag| .{ .tag = .{
                .ty = backing_ty,
                .name = tag.name,
                .payloads = tag.payloads,
            } },
            .leaf,
            .nominal,
            .callable,
            .compact_finite_tags,
            .compact_finite_callables,
            => null,
        };
    }

    fn substitutedKnownExprValue(self: *Cloner, known: ExprWithKnownValue) LowerError!?Value {
        var seen = std.ArrayList(Ast.ExprId).empty;
        defer seen.deinit(self.pass.allocator);
        return try self.substitutedExprValueAvoidingCycles(known.expr, &seen);
    }

    fn substitutedExprValueAvoidingCycles(
        self: *Cloner,
        expr_id: Ast.ExprId,
        seen: *std.ArrayList(Ast.ExprId),
    ) LowerError!?Value {
        const substituted = (try self.substitutedExistingFieldOrTupleReadValue(expr_id, seen)) orelse return null;
        if (valueIsExpr(substituted, expr_id)) return null;
        if (!sameType(self.pass.program, self.pass.program.exprs.items[@intFromEnum(expr_id)].ty, valueType(self.pass.program, substituted))) {
            Common.invariant("substituted expression changed type");
        }

        if (projectableExprFromValue(substituted)) |next_expr| {
            for (seen.items) |seen_expr| {
                if (seen_expr == next_expr) return null;
            }
            if ((try self.substitutedFieldOrTupleReadValue(next_expr)) != null) {
                return try self.substitutedExprValueAvoidingCycles(next_expr, seen);
            }
        }

        return substituted;
    }

    fn substitutedExistingFieldOrTupleReadValue(
        self: *Cloner,
        expr_id: Ast.ExprId,
        seen: *std.ArrayList(Ast.ExprId),
    ) LowerError!?Value {
        for (seen.items) |seen_expr| {
            if (seen_expr == expr_id) return null;
        }
        try seen.append(self.pass.allocator, expr_id);

        const expr = self.pass.program.exprs.items[@intFromEnum(expr_id)];
        return switch (expr.data) {
            .local => |local| self.subst.get(local),
            .field_access => |field| blk: {
                const receiver = (try self.substitutedExistingFieldOrTupleReadValue(field.receiver, seen)) orelse break :blk null;
                break :blk fieldFromValue(self.pass.program, receiver, field.field);
            },
            .tuple_access => |access| blk: {
                const receiver = (try self.substitutedExistingFieldOrTupleReadValue(access.tuple, seen)) orelse break :blk null;
                break :blk itemFromValue(receiver, access.elem_index);
            },
            .comptime_branch_taken => |taken| try self.substitutedExistingFieldOrTupleReadValue(taken.body, seen),
            else => null,
        };
    }

    fn appendUninitializedExprsForKnownValue(
        self: *Cloner,
        known_value: KnownValue,
        out: *std.ArrayList(Ast.ExprId),
    ) LowerError!void {
        switch (known_value) {
            .any,
            .leaf,
            => |ty| try out.append(self.pass.allocator, try self.addExpr(.{ .ty = ty, .data = .uninitialized })),
            .tag => |tag| {
                for (tag.payloads) |payload| try self.appendUninitializedExprsForKnownValue(payload, out);
            },
            .record => |record| {
                for (record.fields) |field| try self.appendUninitializedExprsForKnownValue(field.known_value, out);
            },
            .tuple => |tuple| {
                for (tuple.items) |item| try self.appendUninitializedExprsForKnownValue(item, out);
            },
            .nominal => |nominal| try self.appendUninitializedExprsForKnownValue(nominal.backing.*, out),
            .callable => |callable| {
                for (callable.captures) |capture| try self.appendUninitializedExprsForKnownValue(capture, out);
            },
            .finite_callables => |finite_callables| {
                const selector_ty = try self.pass.primitiveType(.u64);
                try out.append(self.pass.allocator, try self.addExpr(.{ .ty = selector_ty, .data = .uninitialized }));
                for (finite_callables.alternatives) |alternative| {
                    for (alternative.captures) |capture| try self.appendUninitializedExprsForKnownValue(capture, out);
                }
            },
            .finite_tags => |finite_tags| {
                const selector_ty = try self.pass.primitiveType(.u64);
                try out.append(self.pass.allocator, try self.addExpr(.{ .ty = selector_ty, .data = .uninitialized }));
                for (finite_tags.alternatives) |alternative| {
                    for (alternative.payloads) |payload| try self.appendUninitializedExprsForKnownValue(payload, out);
                }
            },
        }
    }

    fn appendUninitializedExprsForDemandedKnownValue(
        self: *Cloner,
        known_value: DemandedKnownValue,
        out: *std.ArrayList(Ast.ExprId),
    ) LowerError!void {
        switch (known_value) {
            .any,
            .leaf,
            => |ty| try out.append(self.pass.allocator, try self.addExpr(.{ .ty = ty, .data = .uninitialized })),
            .tag => |tag| {
                for (tag.payloads) |payload| try self.appendUninitializedExprsForDemandedKnownValue(payload.known_value, out);
            },
            .record => |record| {
                for (record.fields) |field| try self.appendUninitializedExprsForDemandedKnownValue(field.known_value, out);
            },
            .tuple => |tuple| {
                for (tuple.items) |item| try self.appendUninitializedExprsForDemandedKnownValue(item.known_value, out);
            },
            .nominal => |nominal| {
                if (nominal.backing) |backing| try self.appendUninitializedExprsForDemandedKnownValue(backing.*, out);
            },
            .callable => |callable| {
                for (callable.captures) |capture| try self.appendUninitializedExprsForDemandedKnownValue(capture.known_value, out);
            },
            .compact_finite_callables => |finite_callables| {
                const compact_ty = try self.pass.compactFiniteCallablesType(finite_callables);
                try out.append(self.pass.allocator, try self.addExpr(.{ .ty = compact_ty, .data = .uninitialized }));
            },
            .compact_finite_tags => |finite_tags| {
                const compact_ty = try self.pass.compactFiniteTagsType(finite_tags);
                try out.append(self.pass.allocator, try self.addExpr(.{ .ty = compact_ty, .data = .uninitialized }));
            },
            .finite_callables => |finite_callables| {
                const selector_ty = try self.pass.primitiveType(.u64);
                try out.append(self.pass.allocator, try self.addExpr(.{ .ty = selector_ty, .data = .uninitialized }));
                for (finite_callables.alternatives) |alternative| {
                    for (alternative.captures) |capture| try self.appendUninitializedExprsForDemandedKnownValue(capture.known_value, out);
                }
            },
            .finite_tags => |finite_tags| {
                const selector_ty = try self.pass.primitiveType(.u64);
                try out.append(self.pass.allocator, try self.addExpr(.{ .ty = selector_ty, .data = .uninitialized }));
                for (finite_tags.alternatives) |alternative| {
                    for (alternative.payloads) |payload| try self.appendUninitializedExprsForDemandedKnownValue(payload.known_value, out);
                }
            },
        }
    }

    fn appendFieldReadExprsFromValue(
        self: *Cloner,
        known_value: KnownValue,
        value: Value,
        out: *std.ArrayList(Ast.ExprId),
    ) LowerError!bool {
        switch (known_value) {
            .any,
            .leaf,
            => {},
            else => if (value == .expr_with_known_value) {
                if (value.expr_with_known_value.value) |structured_value| {
                    if (try self.appendFieldReadExprsFromValue(known_value, structured_value.*, out)) return true;
                }
            },
        }

        if (value != .expr_with_known_value and
            known_value != .finite_tags and
            known_value != .finite_callables and
            knownValueMatchesValue(self.pass.program, known_value, value))
        {
            const demanded = try materializedDemandedKnownValue(self.pass.arena.allocator(), known_value);
            return try self.appendExprsFromDemandedKnownValue(demanded, value, out);
        }

        switch (known_value) {
            .any,
            .leaf,
            => {
                if (value == .private_state) {
                    if (try self.privateStateOutputExpr(value.private_state)) |expr| {
                        try out.append(self.pass.allocator, expr);
                        return true;
                    }
                    if (!privateStateCanMaterializePublic(self.pass.program, value.private_state)) return false;
                    try out.append(self.pass.allocator, try self.materializePublic(value));
                    return true;
                }
                try out.append(self.pass.allocator, (try self.outputExprFromValue(value)) orelse return false);
                return true;
            },
            .record => |record| {
                if (recordFromValue(value)) |record_value| {
                    for (record.fields) |field_known_value| {
                        const field_value = fieldFromRecord(self.pass.program, record_value, field_known_value.name) orelse return false;
                        if (!try self.appendFieldReadExprsFromValue(field_known_value.known_value, field_value, out)) return false;
                    }
                    return true;
                }

                const receiver = projectableExprFromValue(value) orelse return false;
                if (!self.exprReferencesAvailableBindings(receiver)) return false;
                if (!canReadFieldsFromExpr(self.pass.program, receiver)) return false;
                const actual_known_value = switch (value) {
                    .expr_with_known_value => |known_value_expr| known_value_expr.known_value,
                    else => null,
                };
                for (record.fields) |field| {
                    const actual_field = if (actual_known_value) |actual|
                        fieldKnownValueFromKnownValue(self.pass.program, actual, field.name)
                    else
                        null;
                    const field_expr = try self.addExpr(.{ .ty = known_valueType(field.known_value), .data = .{ .field_access = .{
                        .receiver = receiver,
                        .field = field.name,
                    } } });
                    const field_value = if (actual_field) |actual|
                        valueFromProjectedExpr(field_expr, actual)
                    else
                        Value{ .expr = field_expr };
                    if (!try self.appendFieldReadExprsFromValue(field.known_value, field_value, out)) return false;
                }
                return true;
            },
            .tuple => |tuple| {
                if (tupleFromValue(value)) |tuple_value| {
                    if (tuple.items.len != tuple_value.items.len) return false;
                    for (tuple.items, tuple_value.items) |item_known_value, item_value| {
                        if (!try self.appendFieldReadExprsFromValue(item_known_value, item_value, out)) return false;
                    }
                    return true;
                }

                const receiver = projectableExprFromValue(value) orelse return false;
                if (!self.exprReferencesAvailableBindings(receiver)) return false;
                if (!canReadFieldsFromExpr(self.pass.program, receiver)) return false;
                const actual_known_value = switch (value) {
                    .expr_with_known_value => |known_value_expr| known_value_expr.known_value,
                    else => null,
                };
                for (tuple.items, 0..) |item, index| {
                    const actual_item = if (actual_known_value) |actual|
                        itemKnownValueFromKnownValue(actual, @as(u32, @intCast(index)))
                    else
                        null;
                    const item_expr = try self.addExpr(.{ .ty = known_valueType(item), .data = .{ .tuple_access = .{
                        .tuple = receiver,
                        .elem_index = @as(u32, @intCast(index)),
                    } } });
                    const item_value = if (actual_item) |actual|
                        valueFromProjectedExpr(item_expr, actual)
                    else
                        Value{ .expr = item_expr };
                    if (!try self.appendFieldReadExprsFromValue(item, item_value, out)) return false;
                }
                return true;
            },
            .nominal => |nominal| {
                const backing_value = switch (value) {
                    .nominal => |nominal_value| nominal_value.backing.*,
                    else => value,
                };
                return try self.appendFieldReadExprsFromValue(nominal.backing.*, backing_value, out);
            },
            .callable => |callable| {
                const callable_value = switch (value) {
                    .callable => |callable_value| callable_value,
                    else => return false,
                };
                if (!callableTargetMatches(self.pass.program, callable.fn_id, callable_value.fn_id) or
                    callable.captures.len != callable_value.captures.len)
                {
                    return false;
                }
                for (callable.captures, callable_value.captures) |capture_known_value, capture_value| {
                    if (!try self.appendFieldReadExprsFromValue(capture_known_value, capture_value, out)) return false;
                }
                return true;
            },
            .finite_callables => |finite_callables| {
                if (value == .finite_callables) {
                    const finite_value = value.finite_callables;
                    if (!knownCallablesMatchesValue(self.pass.program, finite_callables, finite_value)) return false;
                    try out.append(self.pass.allocator, finite_value.selector);
                    for (finite_callables.alternatives, finite_value.alternatives) |alternative_known_value, alternative_value| {
                        for (alternative_known_value.captures, alternative_value.captures) |capture_known_value, capture_value| {
                            if (!try self.appendFieldReadExprsFromValue(capture_known_value, capture_value, out)) return false;
                        }
                    }
                    return true;
                }
                const callable_value = switch (value) {
                    .callable => |callable_value| callable_value,
                    else => return false,
                };
                const active_index = finiteCallableAlternativeIndex(self.pass.program, finite_callables.alternatives, callable_value) orelse return false;
                try out.append(self.pass.allocator, try self.selectorLiteral(@intCast(active_index)));
                for (finite_callables.alternatives, 0..) |alternative_known_value, alternative_index| {
                    if (alternative_index == active_index) {
                        for (alternative_known_value.captures, callable_value.captures) |capture_known_value, capture_value| {
                            if (!try self.appendFieldReadExprsFromValue(capture_known_value, capture_value, out)) return false;
                        }
                    } else {
                        for (alternative_known_value.captures) |capture_known_value| {
                            try self.appendUninitializedExprsForKnownValue(capture_known_value, out);
                        }
                    }
                }
                return true;
            },
            .finite_tags => |finite_tags| {
                if (value == .finite_tags) {
                    const finite_value = value.finite_tags;
                    if (!knownTagsMatchesValue(self.pass.program, finite_tags, finite_value)) return false;
                    try out.append(self.pass.allocator, finite_value.selector);
                    for (finite_tags.alternatives, finite_value.alternatives) |alternative_known_value, alternative_value| {
                        for (alternative_known_value.payloads, alternative_value.payloads) |payload_known_value, payload_value| {
                            if (!try self.appendFieldReadExprsFromValue(payload_known_value, payload_value, out)) return false;
                        }
                    }
                    return true;
                }
                const tag_value = switch (value) {
                    .tag => |tag_value| tag_value,
                    else => return false,
                };
                const active_index = finiteTagAlternativeIndex(self.pass.program, finite_tags.alternatives, tag_value) orelse return false;
                try out.append(self.pass.allocator, try self.selectorLiteral(@intCast(active_index)));
                for (finite_tags.alternatives, 0..) |alternative_known_value, alternative_index| {
                    if (alternative_index == active_index) {
                        for (alternative_known_value.payloads, tag_value.payloads) |payload_known_value, payload_value| {
                            if (!try self.appendFieldReadExprsFromValue(payload_known_value, payload_value, out)) return false;
                        }
                    } else {
                        for (alternative_known_value.payloads) |payload_known_value| {
                            try self.appendUninitializedExprsForKnownValue(payload_known_value, out);
                        }
                    }
                }
                return true;
            },
            .tag,
            => return false,
        }
    }

    fn appendFieldReadExprsFromValueCollectingLets(
        self: *Cloner,
        known_value: KnownValue,
        value: Value,
        out: *std.ArrayList(Ast.ExprId),
        pending_lets: *std.ArrayList(PendingLet),
    ) LowerError!bool {
        if (value == .let_) {
            const let_value = value.let_;
            try self.appendPendingLetsUnique(pending_lets, let_value.lets);
            const change_start = self.changes.items.len;
            defer self.restore(change_start);
            const pending_start = self.activePendingLetsLen();
            const scoped_start = try self.pushPendingLetScope(let_value.lets);
            defer self.popPendingLetScope(scoped_start, pending_start);
            return try self.appendFieldReadExprsFromValueCollectingLets(known_value, let_value.body.*, out, pending_lets);
        }
        return try self.appendFieldReadExprsFromValue(known_value, value, out);
    }

    fn appendExprsFromDemandedKnownValue(
        self: *Cloner,
        known_value: DemandedKnownValue,
        value: Value,
        out: *std.ArrayList(Ast.ExprId),
    ) LowerError!bool {
        var pending_lets = std.ArrayList(PendingLet).empty;
        defer pending_lets.deinit(self.pass.allocator);

        var extracted = std.ArrayList(Ast.ExprId).empty;
        defer extracted.deinit(self.pass.allocator);

        if (!try self.appendExprsFromDemandedKnownValueCollectingLets(known_value, value, &extracted, &pending_lets)) return false;

        for (extracted.items) |expr| {
            const expr_ty = self.pass.program.exprs.items[@intFromEnum(expr)].ty;
            try out.append(self.pass.allocator, try self.wrapPendingLetsAroundExpr(expr_ty, expr, pending_lets.items));
        }
        return true;
    }

    fn appendExprsFromDemandedKnownValueCollectingLets(
        self: *Cloner,
        known_value: DemandedKnownValue,
        value: Value,
        out: *std.ArrayList(Ast.ExprId),
        pending_lets: *std.ArrayList(PendingLet),
    ) LowerError!bool {
        if (value == .let_) {
            const let_value = value.let_;
            try self.appendPendingLetsUnique(pending_lets, let_value.lets);
            const change_start = self.changes.items.len;
            defer self.restore(change_start);
            const pending_start = self.activePendingLetsLen();
            const scoped_start = try self.pushPendingLetScope(let_value.lets);
            defer self.popPendingLetScope(scoped_start, pending_start);
            return try self.appendExprsFromDemandedKnownValueCollectingLets(known_value, let_value.body.*, out, pending_lets);
        }
        if (value == .expr) {
            var seen = std.ArrayList(Ast.ExprId).empty;
            defer seen.deinit(self.pass.allocator);
            if (try self.substitutedExprValueAvoidingCycles(value.expr, &seen)) |substituted| {
                return try self.appendExprsFromDemandedKnownValueCollectingLets(known_value, substituted, out, pending_lets);
            }
        }
        if (value == .expr_with_known_value) {
            if (try self.substitutedKnownExprValue(value.expr_with_known_value)) |substituted| {
                return try self.appendExprsFromDemandedKnownValueCollectingLets(known_value, substituted, out, pending_lets);
            }
        }
        const leaf_demand = switch (known_value) {
            .any,
            .leaf,
            => true,
            else => false,
        };
        if (!leaf_demand and value == .if_) {
            return try self.appendIfExprsFromDemandedKnownValue(known_value, value.if_, out);
        }
        if (!leaf_demand and value == .match_) {
            return try self.appendMatchExprsFromDemandedKnownValue(known_value, value.match_, out);
        }

        switch (known_value) {
            .any,
            .leaf,
            => |leaf_ty| {
                const leaf_value = try self.valueAtDemandedLeafType(leaf_ty, value);
                if (leaf_value == .private_state) {
                    if (try self.privateStateOutputExpr(leaf_value.private_state)) |expr| {
                        try out.append(self.pass.allocator, expr);
                    } else if (privateStateCanMaterializePublic(self.pass.program, leaf_value.private_state)) {
                        try out.append(self.pass.allocator, try self.materialize(.{ .private_state = leaf_value.private_state }));
                    } else {
                        return false;
                    }
                    return true;
                }
                const expr = (try self.outputExprFromValueWithPendingLets(leaf_value, pending_lets.items)) orelse {
                    if (leaf_value == .expr and !exprContainsEscapingControlTransfer(self.pass.program, leaf_value.expr)) {
                        const reusable = (try self.tryMakeExprReusableForMatch(leaf_value.expr, pending_lets)) orelse return false;
                        try out.append(self.pass.allocator, reusable);
                        return true;
                    }
                    if (leaf_value == .expr_with_known_value and !exprContainsEscapingControlTransfer(self.pass.program, leaf_value.expr_with_known_value.expr)) {
                        const reusable = (try self.tryMakeExprReusableForMatch(leaf_value.expr_with_known_value.expr, pending_lets)) orelse return false;
                        try out.append(self.pass.allocator, reusable);
                        return true;
                    }
                    return false;
                };
                try out.append(self.pass.allocator, expr);
                return true;
            },
            .record => |record| {
                if (value == .private_state) private_record: {
                    for (record.fields) |field_known_value| {
                        const field_value = privateStateField(self.pass.program, value.private_state, field_known_value.name) orelse break :private_record;
                        if (!try self.appendExprsFromDemandedKnownValueCollectingLets(field_known_value.known_value, .{ .private_state = field_value }, out, pending_lets)) break :private_record;
                    }
                    return true;
                }

                if (recordFromValue(value)) |record_value| {
                    for (record.fields) |field_known_value| {
                        const field_value = fieldFromRecord(self.pass.program, record_value, field_known_value.name) orelse return false;
                        if (!try self.appendExprsFromDemandedKnownValueCollectingLets(field_known_value.known_value, field_value, out, pending_lets)) return false;
                    }
                    return true;
                }

                var projected = true;
                for (record.fields) |field_known_value| {
                    const field_value = (try self.fieldFromKnownValue(value, field_known_value.name)) orelse {
                        projected = false;
                        break;
                    };
                    if (!try self.appendExprsFromDemandedKnownValueCollectingLets(field_known_value.known_value, field_value, out, pending_lets)) {
                        projected = false;
                        break;
                    }
                }
                if (projected) return true;

                const receiver = projectableExprFromValue(value) orelse return false;
                if (!self.exprReferencesAvailableBindings(receiver)) return false;
                if (!canReadFieldsFromExpr(self.pass.program, receiver)) return false;
                for (record.fields) |field| {
                    const field_expr = try self.addExpr(.{ .ty = demandedKnownValueType(field.known_value), .data = .{ .field_access = .{
                        .receiver = receiver,
                        .field = field.name,
                    } } });
                    if (!try self.appendExprsFromDemandedKnownValueCollectingLets(field.known_value, .{ .expr = field_expr }, out, pending_lets)) return false;
                }
                return true;
            },
            .tuple => |tuple| {
                if (value == .private_state) private_tuple: {
                    for (tuple.items) |item_known_value| {
                        const item_value = privateStateItem(value.private_state, item_known_value.index) orelse break :private_tuple;
                        if (!try self.appendExprsFromDemandedKnownValueCollectingLets(item_known_value.known_value, .{ .private_state = item_value }, out, pending_lets)) break :private_tuple;
                    }
                    return true;
                }

                if (tupleFromValue(value)) |tuple_value| {
                    for (tuple.items) |item_known_value| {
                        if (item_known_value.index >= tuple_value.items.len) return false;
                        if (!try self.appendExprsFromDemandedKnownValueCollectingLets(item_known_value.known_value, tuple_value.items[item_known_value.index], out, pending_lets)) return false;
                    }
                    return true;
                }

                var projected = true;
                for (tuple.items) |item_known_value| {
                    const item_value = (try self.itemFromKnownValue(value, item_known_value.index)) orelse {
                        projected = false;
                        break;
                    };
                    if (!try self.appendExprsFromDemandedKnownValueCollectingLets(item_known_value.known_value, item_value, out, pending_lets)) {
                        projected = false;
                        break;
                    }
                }
                if (projected) return true;

                const receiver = projectableExprFromValue(value) orelse return false;
                if (!self.exprReferencesAvailableBindings(receiver)) return false;
                if (!canReadFieldsFromExpr(self.pass.program, receiver)) return false;
                for (tuple.items) |item| {
                    const item_expr = try self.addExpr(.{ .ty = demandedKnownValueType(item.known_value), .data = .{ .tuple_access = .{
                        .tuple = receiver,
                        .elem_index = item.index,
                    } } });
                    if (!try self.appendExprsFromDemandedKnownValueCollectingLets(item.known_value, .{ .expr = item_expr }, out, pending_lets)) return false;
                }
                return true;
            },
            .nominal => |nominal| {
                const backing = nominal.backing orelse return true;
                if (value == .private_state) {
                    const private_nominal = switch (value.private_state) {
                        .nominal => |private_nominal| private_nominal,
                        else => return try self.appendExprsFromDemandedKnownValueCollectingLets(backing.*, value, out, pending_lets),
                    };
                    const backing_value = private_nominal.backing orelse return false;
                    return try self.appendExprsFromDemandedKnownValueCollectingLets(backing.*, .{ .private_state = backing_value.* }, out, pending_lets);
                }
                const backing_value = switch (value) {
                    .nominal => |nominal_value| nominal_value.backing.*,
                    .expr_with_known_value => |known| blk: {
                        const known_nominal = switch (known.known_value) {
                            .nominal => |known_nominal| known_nominal,
                            else => break :blk value,
                        };
                        if (!sameType(self.pass.program, nominal.ty, known_nominal.ty)) return false;
                        const known_backing = known_nominal.backing;
                        const known_expr = self.pass.program.exprs.items[@intFromEnum(known.expr)];
                        if (known_expr.data == .nominal) {
                            break :blk valueFromProjectedExpr(known_expr.data.nominal, known_backing.*);
                        }
                        if (known.value) |structured| {
                            if (structured.* == .nominal) break :blk structured.*.nominal.backing.*;
                        }
                        break :blk value;
                    },
                    else => value,
                };
                return try self.appendExprsFromDemandedKnownValueCollectingLets(backing.*, backing_value, out, pending_lets);
            },
            .tag => |tag| {
                if (value == .expr_with_known_value) {
                    if (!demandedKnownValueMatchesKnownValue(self.pass.program, known_value, value.expr_with_known_value.known_value)) return false;
                    return tag.payloads.len == 0;
                }
                if (value == .private_state) {
                    const private_tag = privateStateTag(value.private_state) orelse return false;
                    if (!sameType(self.pass.program, tag.ty, private_tag.ty) or tag.name != private_tag.name) return false;
                    for (tag.payloads) |payload_known_value| {
                        const payload_value = privateStateIndexedValueByIndex(private_tag.payloads, payload_known_value.index) orelse return false;
                        if (!try self.appendExprsFromDemandedKnownValueCollectingLets(payload_known_value.known_value, .{ .private_state = payload_value }, out, pending_lets)) return false;
                    }
                    return true;
                }

                const tag_value = tagFromValue(value) orelse return false;
                if (!sameType(self.pass.program, tag.ty, tag_value.ty) or tag.name != tag_value.name) return false;
                for (tag.payloads) |payload_known_value| {
                    if (payload_known_value.index >= tag_value.payloads.len) return false;
                    if (!try self.appendExprsFromDemandedKnownValueCollectingLets(payload_known_value.known_value, tag_value.payloads[payload_known_value.index], out, pending_lets)) return false;
                }
                return true;
            },
            .callable => |callable| {
                if (value == .expr_with_known_value) {
                    if (!demandedKnownValueMatchesKnownValue(self.pass.program, known_value, value.expr_with_known_value.known_value)) return false;
                    return callable.captures.len == 0;
                }
                if (value == .private_state) {
                    const private_callable = privateStateCallable(value.private_state) orelse return false;
                    if (!sameType(self.pass.program, callable.ty, private_callable.ty) or
                        !callableTargetMatches(self.pass.program, callable.fn_id, private_callable.fn_id))
                    {
                        return false;
                    }
                    for (callable.captures) |capture_known_value| {
                        const capture_value = privateStateIndexedValueByIndex(private_callable.captures, capture_known_value.index) orelse return false;
                        if (!try self.appendExprsFromDemandedKnownValueCollectingLets(capture_known_value.known_value, .{ .private_state = capture_value }, out, pending_lets)) return false;
                    }
                    return true;
                }

                if (value == .if_) {
                    if (!demandedKnownValueMatchesValue(self.pass.program, known_value, value)) return false;
                    for (callable.captures) |capture_known_value| {
                        const capture_demand = try self.pass.valueDemandFromDemandedKnownValue(capture_known_value.known_value);
                        const capture_value = (try self.callableCaptureFromIfValue(value.if_, callable, capture_known_value.index, capture_demand)) orelse return false;
                        if (!try self.appendExprsFromDemandedKnownValueCollectingLets(capture_known_value.known_value, capture_value, out, pending_lets)) return false;
                    }
                    return true;
                }

                if (value == .match_) {
                    if (!demandedKnownValueMatchesValue(self.pass.program, known_value, value)) return false;
                    for (callable.captures) |capture_known_value| {
                        const capture_demand = try self.pass.valueDemandFromDemandedKnownValue(capture_known_value.known_value);
                        const capture_value = (try self.callableCaptureFromMatchValue(value.match_, callable, capture_known_value.index, capture_demand)) orelse return false;
                        if (!try self.appendExprsFromDemandedKnownValueCollectingLets(capture_known_value.known_value, capture_value, out, pending_lets)) return false;
                    }
                    return true;
                }

                const callable_value = switch (value) {
                    .callable => |callable_value| callable_value,
                    else => {
                        return false;
                    },
                };
                if (!sameType(self.pass.program, callable.ty, callable_value.ty) or
                    !callableTargetMatches(self.pass.program, callable.fn_id, callable_value.fn_id))
                {
                    return false;
                }
                for (callable.captures) |capture_known_value| {
                    if (capture_known_value.index >= callable_value.captures.len) {
                        return false;
                    }
                    if (!try self.appendExprsFromDemandedKnownValueCollectingLets(capture_known_value.known_value, callable_value.captures[capture_known_value.index], out, pending_lets)) {
                        return false;
                    }
                }
                return true;
            },
            .finite_tags => |finite_tags| return try self.appendDemandedFiniteTagsExprs(finite_tags, value, out, pending_lets),
            .compact_finite_tags => |finite_tags| {
                const compact_expr = (try self.compactFiniteTagsExpr(finite_tags, value, pending_lets)) orelse return false;
                try out.append(self.pass.allocator, compact_expr);
                return true;
            },
            .finite_callables => |finite_callables| return try self.appendDemandedFiniteCallablesExprs(finite_callables, value, out, pending_lets),
            .compact_finite_callables => |finite_callables| {
                const compact_expr = (try self.compactFiniteCallablesExpr(finite_callables, value, pending_lets)) orelse return false;
                try out.append(self.pass.allocator, compact_expr);
                return true;
            },
        }
    }

    fn appendDemandedFiniteTagsExprs(
        self: *Cloner,
        finite_tags: DemandedKnownTags,
        value: Value,
        out: *std.ArrayList(Ast.ExprId),
        pending_lets: *std.ArrayList(PendingLet),
    ) LowerError!bool {
        switch (value) {
            .let_ => |let_value| {
                try self.appendPendingLetsUnique(pending_lets, let_value.lets);
                const change_start = self.changes.items.len;
                defer self.restore(change_start);
                const pending_start = self.activePendingLetsLen();
                const scoped_start = try self.pushPendingLetScope(let_value.lets);
                defer self.popPendingLetScope(scoped_start, pending_start);
                return try self.appendDemandedFiniteTagsExprs(finite_tags, let_value.body.*, out, pending_lets);
            },
            .expr_with_known_value => |known| {
                if (known.value) |structured| {
                    if (try self.appendDemandedFiniteTagsExprs(finite_tags, structured.*, out, pending_lets)) return true;
                }
                return false;
            },
            .finite_tags => |finite_value| {
                if (!sameType(self.pass.program, finite_tags.ty, finite_value.ty)) return false;
                try out.append(self.pass.allocator, finite_value.selector);
                for (finite_tags.alternatives) |alternative| {
                    const value_alternative = finiteTagValueAlternative(self.pass.program, finite_value.alternatives, alternative) orelse return false;
                    for (alternative.payloads) |payload| {
                        if (payload.index >= value_alternative.payloads.len) return false;
                        if (!try self.appendExprsFromDemandedKnownValueCollectingLets(payload.known_value, value_alternative.payloads[payload.index], out, pending_lets)) return false;
                    }
                }
                return true;
            },
            .tag => |tag| {
                const active_index = demandedFiniteTagAlternativeIndexForValue(self.pass.program, finite_tags.alternatives, tag) orelse return false;
                try out.append(self.pass.allocator, try self.selectorLiteral(@intCast(active_index)));
                for (finite_tags.alternatives, 0..) |alternative, alternative_index| {
                    if (alternative_index == active_index) {
                        for (alternative.payloads) |payload| {
                            if (payload.index >= tag.payloads.len) return false;
                            if (!try self.appendExprsFromDemandedKnownValueCollectingLets(payload.known_value, tag.payloads[payload.index], out, pending_lets)) return false;
                        }
                    } else {
                        for (alternative.payloads) |payload| {
                            try self.appendUninitializedExprsForDemandedKnownValue(payload.known_value, out);
                        }
                    }
                }
                return true;
            },
            .private_state => |private_state| {
                const tag = privateStateTag(private_state) orelse return false;
                const active_index = demandedFiniteTagAlternativeIndexForPrivateState(self.pass.program, finite_tags.alternatives, tag) orelse return false;
                try out.append(self.pass.allocator, try self.selectorLiteral(@intCast(active_index)));
                for (finite_tags.alternatives, 0..) |alternative, alternative_index| {
                    if (alternative_index == active_index) {
                        for (alternative.payloads) |payload| {
                            const private_payload = privateStateIndexedValueByIndex(tag.payloads, payload.index) orelse return false;
                            if (!try self.appendExprsFromDemandedKnownValueCollectingLets(payload.known_value, .{ .private_state = private_payload }, out, pending_lets)) return false;
                        }
                    } else {
                        for (alternative.payloads) |payload| {
                            try self.appendUninitializedExprsForDemandedKnownValue(payload.known_value, out);
                        }
                    }
                }
                return true;
            },
            else => return false,
        }
    }

    fn appendDemandedFiniteCallablesExprs(
        self: *Cloner,
        finite_callables: DemandedKnownCallables,
        value: Value,
        out: *std.ArrayList(Ast.ExprId),
        pending_lets: *std.ArrayList(PendingLet),
    ) LowerError!bool {
        switch (value) {
            .let_ => |let_value| {
                try self.appendPendingLetsUnique(pending_lets, let_value.lets);
                const change_start = self.changes.items.len;
                defer self.restore(change_start);
                const pending_start = self.activePendingLetsLen();
                const scoped_start = try self.pushPendingLetScope(let_value.lets);
                defer self.popPendingLetScope(scoped_start, pending_start);
                return try self.appendDemandedFiniteCallablesExprs(finite_callables, let_value.body.*, out, pending_lets);
            },
            .expr_with_known_value => |known| {
                if (known.value) |structured| {
                    if (try self.appendDemandedFiniteCallablesExprs(finite_callables, structured.*, out, pending_lets)) return true;
                }
                return false;
            },
            .finite_callables => |finite_value| {
                if (!sameType(self.pass.program, finite_callables.ty, finite_value.ty)) return false;
                try out.append(self.pass.allocator, finite_value.selector);
                for (finite_callables.alternatives) |alternative| {
                    const value_alternative = finiteCallableValueAlternative(self.pass.program, finite_value.alternatives, alternative) orelse return false;
                    for (alternative.captures) |capture| {
                        if (capture.index >= value_alternative.captures.len) return false;
                        if (!try self.appendExprsFromDemandedKnownValueCollectingLets(capture.known_value, value_alternative.captures[capture.index], out, pending_lets)) return false;
                    }
                }
                return true;
            },
            .callable => |callable| {
                const active_index = demandedFiniteCallableAlternativeIndexForValue(self.pass.program, finite_callables.alternatives, callable) orelse return false;
                try out.append(self.pass.allocator, try self.selectorLiteral(@intCast(active_index)));
                for (finite_callables.alternatives, 0..) |alternative, alternative_index| {
                    if (alternative_index == active_index) {
                        for (alternative.captures) |capture| {
                            if (capture.index >= callable.captures.len) return false;
                            if (!try self.appendExprsFromDemandedKnownValueCollectingLets(capture.known_value, callable.captures[capture.index], out, pending_lets)) return false;
                        }
                    } else {
                        for (alternative.captures) |capture| {
                            try self.appendUninitializedExprsForDemandedKnownValue(capture.known_value, out);
                        }
                    }
                }
                return true;
            },
            .private_state => |private_state| {
                const callable = privateStateCallable(private_state) orelse return false;
                const active_index = demandedFiniteCallableAlternativeIndexForPrivateState(self.pass.program, finite_callables.alternatives, callable) orelse return false;
                try out.append(self.pass.allocator, try self.selectorLiteral(@intCast(active_index)));
                for (finite_callables.alternatives, 0..) |alternative, alternative_index| {
                    if (alternative_index == active_index) {
                        for (alternative.captures) |capture| {
                            const private_capture = privateStateIndexedValueByIndex(callable.captures, capture.index) orelse return false;
                            if (!try self.appendExprsFromDemandedKnownValueCollectingLets(capture.known_value, .{ .private_state = private_capture }, out, pending_lets)) return false;
                        }
                    } else {
                        for (alternative.captures) |capture| {
                            try self.appendUninitializedExprsForDemandedKnownValue(capture.known_value, out);
                        }
                    }
                }
                return true;
            },
            else => return false,
        }
    }

    fn compactFiniteTagsExpr(
        self: *Cloner,
        finite_tags: DemandedKnownTags,
        value: Value,
        pending_lets: *std.ArrayList(PendingLet),
    ) LowerError!?Ast.ExprId {
        switch (value) {
            .let_ => |let_value| {
                const change_start = self.changes.items.len;
                defer self.restore(change_start);
                const pending_start = self.activePendingLetsLen();
                const scoped_start = try self.pushPendingLetScope(let_value.lets);
                defer self.popPendingLetScope(scoped_start, pending_start);

                const body = (try self.compactFiniteTagsExpr(finite_tags, let_value.body.*, pending_lets)) orelse return null;
                return try self.wrapPendingLetsAroundExpr(
                    self.pass.program.exprs.items[@intFromEnum(body)].ty,
                    body,
                    let_value.lets,
                );
            },
            .if_ => |if_value| {
                const compact_ty = try self.pass.compactFiniteTagsType(finite_tags);
                const branches = try self.pass.allocator.alloc(Ast.IfBranch, if_value.branches.len);
                defer self.pass.allocator.free(branches);
                for (if_value.branches, branches) |branch, *out| {
                    out.* = .{
                        .cond = branch.cond,
                        .body = (try self.compactFiniteTagsExpr(finite_tags, branch.body, pending_lets)) orelse return null,
                    };
                }
                return try self.addExpr(.{ .ty = compact_ty, .data = .{ .if_ = .{
                    .branches = try self.pass.program.addIfBranchSpan(branches),
                    .final_else = (try self.compactFiniteTagsExpr(finite_tags, if_value.final_else.*, pending_lets)) orelse return null,
                } } });
            },
            .match_ => |match_value| {
                const compact_ty = try self.pass.compactFiniteTagsType(finite_tags);
                const branches = try self.pass.allocator.alloc(Ast.Branch, match_value.branches.len);
                defer self.pass.allocator.free(branches);
                for (match_value.branches, branches) |branch, *out| {
                    const scoped_start = self.scopedLocalsLen();
                    defer self.restoreScopedLocals(scoped_start);
                    try self.appendPatternScopedLocals(branch.pat);
                    out.* = .{
                        .pat = branch.pat,
                        .guard = branch.guard,
                        .body = (try self.compactFiniteTagsExpr(finite_tags, branch.body, pending_lets)) orelse return null,
                    };
                }
                return try self.addExpr(.{ .ty = compact_ty, .data = .{ .match_ = .{
                    .scrutinee = match_value.scrutinee,
                    .branches = try self.pass.program.addBranchSpan(branches),
                    .comptime_site = match_value.comptime_site,
                } } });
            },
            .private_state => |private_state| switch (private_state) {
                .compact_finite_tags => |compact| {
                    if (!demandedKnownValueEql(self.pass.program, .{ .finite_tags = finite_tags }, .{ .finite_tags = compact.source })) return null;
                    return compact.compact_expr;
                },
                else => {
                    const tag = privateStateTag(private_state) orelse return null;
                    return try self.compactFiniteTagExprFromPrivateTag(finite_tags, tag, pending_lets);
                },
            },
            .tag => |tag| return try self.compactFiniteTagExprFromTagValue(finite_tags, tag, pending_lets),
            .finite_tags => |finite_value| return try self.compactFiniteTagExprFromFiniteValue(finite_tags, finite_value, pending_lets),
            .expr_with_known_value => |known| {
                if (known.value) |structured| {
                    if (try self.compactFiniteTagsExpr(finite_tags, structured.*, pending_lets)) |compact| return compact;
                }
                return try self.compactFiniteTagExprFromRawExpr(finite_tags, known.expr);
            },
            .expr => |expr| return try self.compactFiniteTagExprFromRawExpr(finite_tags, expr),
            else => return null,
        }
    }

    fn compactFiniteTagExprFromFiniteValue(
        self: *Cloner,
        finite_tags: DemandedKnownTags,
        finite_value: FiniteTagsValue,
        pending_lets: *std.ArrayList(PendingLet),
    ) LowerError!?Ast.ExprId {
        if (!sameType(self.pass.program, finite_tags.ty, finite_value.ty)) return null;
        if (finite_value.alternatives.len == 0) Common.invariant("finite tag compact construction had no alternatives");
        if (finite_value.alternatives.len == 1) {
            return try self.compactFiniteTagExprFromTagValue(finite_tags, finite_value.alternatives[0], pending_lets);
        }

        const compact_ty = try self.pass.compactFiniteTagsType(finite_tags);
        const branch_count = finite_value.alternatives.len - 1;
        const branches = try self.pass.allocator.alloc(Ast.IfBranch, branch_count);
        defer self.pass.allocator.free(branches);
        for (finite_value.alternatives[0..branch_count], branches, 0..) |alternative, *branch, index| {
            branch.* = .{
                .cond = try self.selectorEquals(finite_value.selector, @intCast(index)),
                .body = (try self.compactFiniteTagExprFromTagValue(finite_tags, alternative, pending_lets)) orelse return null,
            };
        }

        return try self.addExpr(.{ .ty = compact_ty, .data = .{ .if_ = .{
            .branches = try self.pass.program.addIfBranchSpan(branches),
            .final_else = (try self.compactFiniteTagExprFromTagValue(finite_tags, finite_value.alternatives[branch_count], pending_lets)) orelse return null,
        } } });
    }

    fn compactFiniteTagExprFromTagValue(
        self: *Cloner,
        finite_tags: DemandedKnownTags,
        tag: TagValue,
        pending_lets: *std.ArrayList(PendingLet),
    ) LowerError!?Ast.ExprId {
        const alternative_index = demandedTagAlternativeIndex(self.pass.program, finite_tags.alternatives, tag.name) orelse return null;
        const alternative = finite_tags.alternatives[alternative_index];
        var payload_exprs = std.ArrayList(Ast.ExprId).empty;
        defer payload_exprs.deinit(self.pass.allocator);
        for (alternative.payloads) |payload| {
            if (payload.index >= tag.payloads.len) return null;
            if (!try self.appendExprsFromDemandedKnownValueCollectingLets(payload.known_value, tag.payloads[payload.index], &payload_exprs, pending_lets)) {
                return null;
            }
        }
        return try self.compactFiniteTagExprFromPayloadExprs(finite_tags, alternative_index, payload_exprs.items);
    }

    fn compactFiniteTagExprFromPrivateTag(
        self: *Cloner,
        finite_tags: DemandedKnownTags,
        tag: PrivateStateTag,
        pending_lets: *std.ArrayList(PendingLet),
    ) LowerError!?Ast.ExprId {
        const alternative_index = demandedTagAlternativeIndex(self.pass.program, finite_tags.alternatives, tag.name) orelse return null;
        const alternative = finite_tags.alternatives[alternative_index];
        var payload_exprs = std.ArrayList(Ast.ExprId).empty;
        defer payload_exprs.deinit(self.pass.allocator);
        for (alternative.payloads) |payload| {
            const private_payload = privateStateIndexedValueByIndex(tag.payloads, payload.index) orelse return null;
            if (!try self.appendExprsFromDemandedKnownValueCollectingLets(payload.known_value, .{ .private_state = private_payload }, &payload_exprs, pending_lets)) return null;
        }
        return try self.compactFiniteTagExprFromPayloadExprs(finite_tags, alternative_index, payload_exprs.items);
    }

    fn compactFiniteTagExprFromRawExpr(
        self: *Cloner,
        finite_tags: DemandedKnownTags,
        expr: Ast.ExprId,
    ) LowerError!?Ast.ExprId {
        const source_tags = tagUnionTypeTags(self.pass.program, finite_tags.ty) orelse return null;
        const compact_ty = try self.pass.compactFiniteTagsType(finite_tags);
        const branches = try self.pass.allocator.alloc(Ast.Branch, source_tags.len);
        defer self.pass.allocator.free(branches);

        for (source_tags, branches) |source_tag, *branch| {
            const alternative_index = demandedTagAlternativeIndex(self.pass.program, finite_tags.alternatives, source_tag.name) orelse return null;
            const alternative = finite_tags.alternatives[alternative_index];
            const source_payload_tys = self.pass.program.types.span(source_tag.payloads);
            const payload_pats = try self.pass.allocator.alloc(Ast.PatId, source_payload_tys.len);
            defer self.pass.allocator.free(payload_pats);
            const payload_values = try self.pass.arena.allocator().alloc(Value, source_payload_tys.len);

            for (source_payload_tys, payload_pats, payload_values) |payload_ty, *payload_pat, *payload_value| {
                const local = try self.pass.program.addLocal(self.pass.symbols.fresh(), payload_ty);
                payload_pat.* = try self.pass.program.addPat(.{
                    .ty = payload_ty,
                    .data = .{ .bind = local },
                });
                payload_value.* = .{ .expr = try self.addExpr(.{
                    .ty = payload_ty,
                    .data = .{ .local = local },
                }) };
            }

            const branch_pat = try self.pass.program.addPat(.{
                .ty = finite_tags.ty,
                .data = .{ .tag = .{
                    .name = source_tag.name,
                    .payloads = try self.pass.program.addPatSpan(payload_pats),
                } },
            });
            const scoped_start = self.scopedLocalsLen();
            defer self.restoreScopedLocals(scoped_start);
            try self.appendPatternScopedLocals(branch_pat);

            var payload_exprs = std.ArrayList(Ast.ExprId).empty;
            defer payload_exprs.deinit(self.pass.allocator);
            var pending_lets = std.ArrayList(PendingLet).empty;
            defer pending_lets.deinit(self.pass.allocator);
            for (alternative.payloads) |payload| {
                if (payload.index >= payload_values.len) return null;
                if (!try self.appendExprsFromDemandedKnownValueCollectingLets(payload.known_value, payload_values[payload.index], &payload_exprs, &pending_lets)) return null;
            }
            var body = try self.compactFiniteTagExprFromPayloadExprs(finite_tags, alternative_index, payload_exprs.items);
            body = try self.wrapPendingLetsAroundExpr(compact_ty, body, pending_lets.items);

            branch.* = .{
                .pat = branch_pat,
                .guard = null,
                .body = body,
            };
        }

        return try self.addExpr(.{ .ty = compact_ty, .data = .{ .match_ = .{
            .scrutinee = expr,
            .branches = try self.pass.program.addBranchSpan(branches),
            .comptime_site = null,
        } } });
    }

    fn compactFiniteTagExprFromPayloadExprs(
        self: *Cloner,
        finite_tags: DemandedKnownTags,
        alternative_index: usize,
        payload_exprs: []const Ast.ExprId,
    ) LowerError!Ast.ExprId {
        const compact_ty = try self.pass.compactFiniteTagsType(finite_tags);
        if (finite_tags.alternatives.len == 1) {
            if (alternative_index != 0) Common.invariant("singleton compact finite tag used a nonzero alternative index");
            return try self.compactLeafTupleExpr(compact_ty, payload_exprs);
        }
        const alternative = finite_tags.alternatives[alternative_index];
        return try self.addExpr(.{ .ty = compact_ty, .data = .{ .tag = .{
            .name = alternative.name,
            .payloads = try self.pass.program.addExprSpan(payload_exprs),
        } } });
    }

    fn compactFiniteCallablesExpr(
        self: *Cloner,
        finite_callables: DemandedKnownCallables,
        value: Value,
        pending_lets: *std.ArrayList(PendingLet),
    ) LowerError!?Ast.ExprId {
        switch (value) {
            .let_ => |let_value| {
                const change_start = self.changes.items.len;
                defer self.restore(change_start);
                const pending_start = self.activePendingLetsLen();
                const scoped_start = try self.pushPendingLetScope(let_value.lets);
                defer self.popPendingLetScope(scoped_start, pending_start);

                const body = (try self.compactFiniteCallablesExpr(finite_callables, let_value.body.*, pending_lets)) orelse return null;
                return try self.wrapPendingLetsAroundExpr(
                    self.pass.program.exprs.items[@intFromEnum(body)].ty,
                    body,
                    let_value.lets,
                );
            },
            .if_ => |if_value| {
                const compact_ty = try self.pass.compactFiniteCallablesType(finite_callables);
                const branches = try self.pass.allocator.alloc(Ast.IfBranch, if_value.branches.len);
                defer self.pass.allocator.free(branches);
                for (if_value.branches, branches) |branch, *out| {
                    out.* = .{
                        .cond = branch.cond,
                        .body = (try self.compactFiniteCallablesExpr(finite_callables, branch.body, pending_lets)) orelse return null,
                    };
                }
                return try self.addExpr(.{ .ty = compact_ty, .data = .{ .if_ = .{
                    .branches = try self.pass.program.addIfBranchSpan(branches),
                    .final_else = (try self.compactFiniteCallablesExpr(finite_callables, if_value.final_else.*, pending_lets)) orelse return null,
                } } });
            },
            .match_ => |match_value| {
                const compact_ty = try self.pass.compactFiniteCallablesType(finite_callables);
                const branches = try self.pass.allocator.alloc(Ast.Branch, match_value.branches.len);
                defer self.pass.allocator.free(branches);
                for (match_value.branches, branches) |branch, *out| {
                    const scoped_start = self.scopedLocalsLen();
                    defer self.restoreScopedLocals(scoped_start);
                    try self.appendPatternScopedLocals(branch.pat);
                    out.* = .{
                        .pat = branch.pat,
                        .guard = branch.guard,
                        .body = (try self.compactFiniteCallablesExpr(finite_callables, branch.body, pending_lets)) orelse return null,
                    };
                }
                return try self.addExpr(.{ .ty = compact_ty, .data = .{ .match_ = .{
                    .scrutinee = match_value.scrutinee,
                    .branches = try self.pass.program.addBranchSpan(branches),
                    .comptime_site = match_value.comptime_site,
                } } });
            },
            .private_state => |private_state| switch (private_state) {
                .compact_finite_callables => |compact| {
                    if (!demandedKnownValueEql(self.pass.program, .{ .finite_callables = finite_callables }, .{ .finite_callables = compact.source })) return null;
                    return compact.compact_expr;
                },
                else => {
                    const callable = privateStateCallable(private_state) orelse return null;
                    return try self.compactFiniteCallableExprFromPrivateCallable(finite_callables, callable, pending_lets);
                },
            },
            .callable => |callable| return try self.compactFiniteCallableExprFromCallableValue(finite_callables, callable, pending_lets),
            .finite_callables => |finite_value| return try self.compactFiniteCallablesExprFromFiniteValue(finite_callables, finite_value, pending_lets),
            .expr_with_known_value => |known| if (known.value) |structured|
                return try self.compactFiniteCallablesExpr(finite_callables, structured.*, pending_lets)
            else
                return null,
            else => return null,
        }
    }

    fn compactFiniteCallablesExprFromFiniteValue(
        self: *Cloner,
        finite_callables: DemandedKnownCallables,
        finite_value: FiniteCallablesValue,
        pending_lets: *std.ArrayList(PendingLet),
    ) LowerError!?Ast.ExprId {
        if (!sameType(self.pass.program, finite_callables.ty, finite_value.ty)) return null;
        if (finite_value.alternatives.len == 0) Common.invariant("finite callable compact construction had no alternatives");
        if (finite_value.alternatives.len == 1) {
            return try self.compactFiniteCallableExprFromCallableValue(finite_callables, finite_value.alternatives[0], pending_lets);
        }

        const compact_ty = try self.pass.compactFiniteCallablesType(finite_callables);
        const branch_count = finite_value.alternatives.len - 1;
        const branches = try self.pass.allocator.alloc(Ast.IfBranch, branch_count);
        defer self.pass.allocator.free(branches);
        for (finite_value.alternatives[0..branch_count], branches, 0..) |alternative, *branch, index| {
            branch.* = .{
                .cond = try self.selectorEquals(finite_value.selector, @intCast(index)),
                .body = (try self.compactFiniteCallableExprFromCallableValue(finite_callables, alternative, pending_lets)) orelse return null,
            };
        }

        return try self.addExpr(.{ .ty = compact_ty, .data = .{ .if_ = .{
            .branches = try self.pass.program.addIfBranchSpan(branches),
            .final_else = (try self.compactFiniteCallableExprFromCallableValue(finite_callables, finite_value.alternatives[branch_count], pending_lets)) orelse return null,
        } } });
    }

    fn compactFiniteCallableExprFromCallableValue(
        self: *Cloner,
        finite_callables: DemandedKnownCallables,
        callable: CallableValue,
        pending_lets: *std.ArrayList(PendingLet),
    ) LowerError!?Ast.ExprId {
        const alternative_index = demandedCallableAlternativeIndex(self.pass.program, finite_callables.alternatives, callable.ty, callable.fn_id) orelse return null;
        const alternative = finite_callables.alternatives[alternative_index];
        var capture_exprs = std.ArrayList(Ast.ExprId).empty;
        defer capture_exprs.deinit(self.pass.allocator);
        for (alternative.captures) |capture| {
            if (capture.index >= callable.captures.len) return null;
            if (!try self.appendExprsFromDemandedKnownValueCollectingLets(capture.known_value, callable.captures[capture.index], &capture_exprs, pending_lets)) return null;
        }
        return try self.compactFiniteCallableExprFromCaptureExprs(finite_callables, alternative_index, capture_exprs.items);
    }

    fn compactFiniteCallableExprFromPrivateCallable(
        self: *Cloner,
        finite_callables: DemandedKnownCallables,
        callable: PrivateStateCallable,
        pending_lets: *std.ArrayList(PendingLet),
    ) LowerError!?Ast.ExprId {
        const alternative_index = demandedCallableAlternativeIndex(self.pass.program, finite_callables.alternatives, callable.ty, callable.fn_id) orelse return null;
        const alternative = finite_callables.alternatives[alternative_index];
        var capture_exprs = std.ArrayList(Ast.ExprId).empty;
        defer capture_exprs.deinit(self.pass.allocator);
        for (alternative.captures) |capture| {
            const private_capture = privateStateIndexedValueByIndex(callable.captures, capture.index) orelse return null;
            if (!try self.appendExprsFromDemandedKnownValueCollectingLets(capture.known_value, .{ .private_state = private_capture }, &capture_exprs, pending_lets)) return null;
        }
        return try self.compactFiniteCallableExprFromCaptureExprs(finite_callables, alternative_index, capture_exprs.items);
    }

    fn compactFiniteCallableExprFromCaptureExprs(
        self: *Cloner,
        finite_callables: DemandedKnownCallables,
        alternative_index: usize,
        capture_exprs: []const Ast.ExprId,
    ) LowerError!Ast.ExprId {
        const compact_ty = try self.pass.compactFiniteCallablesType(finite_callables);
        if (finite_callables.alternatives.len == 1) {
            if (alternative_index != 0) Common.invariant("singleton compact finite callable used a nonzero alternative index");
            return try self.compactLeafTupleExpr(compact_ty, capture_exprs);
        }
        const tag_name = try self.pass.compactCallableAlternativeTagName(alternative_index);
        return try self.addExpr(.{ .ty = compact_ty, .data = .{ .tag = .{
            .name = tag_name,
            .payloads = try self.pass.program.addExprSpan(capture_exprs),
        } } });
    }

    fn matchValueFromTagUnionExpr(
        self: *Cloner,
        scrutinee: Ast.ExprId,
        ty: Type.TypeId,
    ) LowerError!?MatchValue {
        const tags = tagUnionTypeTags(self.pass.program, ty) orelse return null;
        if (tags.len == 0) return null;

        const branches = try self.pass.arena.allocator().alloc(MatchValueBranch, tags.len);
        for (tags, branches) |tag, *branch| {
            const payload_tys = self.pass.program.types.span(tag.payloads);
            const payload_pats = try self.pass.allocator.alloc(Ast.PatId, payload_tys.len);
            defer self.pass.allocator.free(payload_pats);

            const payload_values = try self.pass.arena.allocator().alloc(Value, payload_tys.len);
            for (payload_tys, payload_pats, payload_values) |payload_ty, *payload_pat, *payload_value| {
                const local = try self.pass.program.addLocal(self.pass.symbols.fresh(), payload_ty);
                payload_pat.* = try self.pass.program.addPat(.{
                    .ty = payload_ty,
                    .data = .{ .bind = local },
                });
                const local_expr = try self.addExpr(.{
                    .ty = payload_ty,
                    .data = .{ .local = local },
                });
                payload_value.* = .{ .expr = local_expr };
            }

            branch.* = .{
                .pat = try self.pass.program.addPat(.{
                    .ty = ty,
                    .data = .{ .tag = .{
                        .name = tag.name,
                        .payloads = try self.pass.program.addPatSpan(payload_pats),
                    } },
                }),
                .guard = null,
                .body = .{ .tag = .{
                    .ty = ty,
                    .name = tag.name,
                    .payloads = payload_values,
                } },
            };
        }

        return MatchValue{
            .ty = ty,
            .scrutinee = scrutinee,
            .branches = branches,
            .comptime_site = null,
        };
    }

    fn appendIfExprsFromDemandedKnownValue(
        self: *Cloner,
        known_value: DemandedKnownValue,
        if_value: IfValue,
        out: *std.ArrayList(Ast.ExprId),
    ) LowerError!bool {
        const demand = try self.pass.valueDemandFromDemandedKnownValue(known_value);
        var final_leaves = std.ArrayList(Ast.ExprId).empty;
        defer final_leaves.deinit(self.pass.allocator);
        const demanded_final = try self.applyValueDemand(if_value.final_else.*, demand);
        if (!try self.appendExprsFromDemandedKnownValue(known_value, demanded_final, &final_leaves)) {
            return false;
        }

        var branch_leaf_sets = std.ArrayList([]Ast.ExprId).empty;
        defer {
            for (branch_leaf_sets.items) |leaves| self.pass.allocator.free(leaves);
            branch_leaf_sets.deinit(self.pass.allocator);
        }

        for (if_value.branches) |branch| {
            var leaves = std.ArrayList(Ast.ExprId).empty;
            defer leaves.deinit(self.pass.allocator);
            const demanded_body = try self.applyValueDemand(branch.body, demand);
            if (!try self.appendExprsFromDemandedKnownValue(known_value, demanded_body, &leaves)) {
                return false;
            }
            if (leaves.items.len != final_leaves.items.len) {
                return false;
            }
            try branch_leaf_sets.append(self.pass.allocator, try self.pass.allocator.dupe(Ast.ExprId, leaves.items));
        }

        for (final_leaves.items, 0..) |final_leaf, leaf_index| {
            const leaf_ty = self.pass.program.exprs.items[@intFromEnum(final_leaf)].ty;
            const branches = try self.pass.allocator.alloc(Ast.IfBranch, if_value.branches.len);
            defer self.pass.allocator.free(branches);
            for (if_value.branches, branches, 0..) |branch, *out_branch, branch_index| {
                out_branch.* = .{
                    .cond = branch.cond,
                    .body = branch_leaf_sets.items[branch_index][leaf_index],
                };
            }
            try out.append(self.pass.allocator, try self.addExpr(.{ .ty = leaf_ty, .data = .{ .if_ = .{
                .branches = try self.pass.program.addIfBranchSpan(branches),
                .final_else = final_leaf,
            } } }));
        }
        return true;
    }

    fn appendMatchExprsFromDemandedKnownValue(
        self: *Cloner,
        known_value: DemandedKnownValue,
        match_value: MatchValue,
        out: *std.ArrayList(Ast.ExprId),
    ) LowerError!bool {
        const demand = try self.pass.valueDemandFromDemandedKnownValue(known_value);
        var branch_leaf_sets = std.ArrayList([]Ast.ExprId).empty;
        defer {
            for (branch_leaf_sets.items) |leaves| self.pass.allocator.free(leaves);
            branch_leaf_sets.deinit(self.pass.allocator);
        }

        var leaf_count: ?usize = null;
        for (match_value.branches) |branch| {
            const scoped_start = self.scopedLocalsLen();
            defer self.restoreScopedLocals(scoped_start);
            try self.appendPatternScopedLocals(branch.pat);

            var leaves = std.ArrayList(Ast.ExprId).empty;
            defer leaves.deinit(self.pass.allocator);
            const demanded_body = try self.cloneMatchValueBranchBodyWithDemand(branch, demand);
            if (!try self.appendExprsFromDemandedKnownValue(known_value, demanded_body, &leaves)) return false;
            if (leaf_count) |expected| {
                if (leaves.items.len != expected) return false;
            } else {
                leaf_count = leaves.items.len;
            }
            try branch_leaf_sets.append(self.pass.allocator, try self.pass.allocator.dupe(Ast.ExprId, leaves.items));
        }

        const count = leaf_count orelse return false;
        for (0..count) |leaf_index| {
            const first_leaf = branch_leaf_sets.items[0][leaf_index];
            const leaf_ty = self.pass.program.exprs.items[@intFromEnum(first_leaf)].ty;
            const branches = try self.pass.allocator.alloc(Ast.Branch, match_value.branches.len);
            defer self.pass.allocator.free(branches);
            for (match_value.branches, branches, 0..) |branch, *out_branch, branch_index| {
                out_branch.* = .{
                    .pat = branch.pat,
                    .guard = branch.guard,
                    .body = branch_leaf_sets.items[branch_index][leaf_index],
                };
            }
            try out.append(self.pass.allocator, try self.addExpr(.{ .ty = leaf_ty, .data = .{ .match_ = .{
                .scrutinee = match_value.scrutinee,
                .branches = try self.pass.program.addBranchSpan(branches),
                .comptime_site = match_value.comptime_site,
            } } }));
        }
        return true;
    }

    fn callableCaptureFromIfValue(
        self: *Cloner,
        if_value: IfValue,
        callable: DemandedKnownCallable,
        capture_index: u32,
        capture_demand: ValueDemand,
    ) LowerError!?Value {
        const branches = try self.pass.arena.allocator().alloc(IfValueBranch, if_value.branches.len);
        var capture_ty: ?Type.TypeId = null;
        const callable_demand = try self.callableCaptureDemand(capture_index, capture_demand);
        for (if_value.branches, branches) |branch, *out| {
            const branch_body = try self.applyValueDemand(branch.body, callable_demand);
            const capture = (try self.callableCaptureFromValue(branch_body, callable, capture_index)) orelse return null;
            if (capture_ty == null) capture_ty = valueType(self.pass.program, capture);
            out.* = .{
                .cond = branch.cond,
                .body = capture,
            };
        }

        const final_body = try self.applyValueDemand(if_value.final_else.*, callable_demand);
        const final_capture = (try self.callableCaptureFromValue(final_body, callable, capture_index)) orelse return null;
        if (capture_ty == null) capture_ty = valueType(self.pass.program, final_capture);
        const final_else = try self.pass.arena.allocator().create(Value);
        final_else.* = final_capture;

        return Value{ .if_ = .{
            .ty = capture_ty orelse return null,
            .branches = branches,
            .final_else = final_else,
        } };
    }

    fn callableCaptureFromMatchValue(
        self: *Cloner,
        match_value: MatchValue,
        callable: DemandedKnownCallable,
        capture_index: u32,
        capture_demand: ValueDemand,
    ) LowerError!?Value {
        const branches = try self.pass.arena.allocator().alloc(MatchValueBranch, match_value.branches.len);
        var capture_ty: ?Type.TypeId = null;
        const callable_demand = try self.callableCaptureDemand(capture_index, capture_demand);
        for (match_value.branches, branches) |branch, *out| {
            const branch_value = try self.cloneMatchValueBranchBodyWithDemand(branch, callable_demand);
            const capture = (try self.callableCaptureFromValue(branch_value, callable, capture_index)) orelse return null;
            if (capture_ty == null) capture_ty = valueType(self.pass.program, capture);
            const source = if (branch.source) |source| source_blk: {
                break :source_blk MatchValueBranchSource{
                    .scrutinee = source.scrutinee,
                    .pat = source.pat,
                    .guard = source.guard,
                    .body = source.body,
                    .scrutinee_known_value = source.scrutinee_known_value,
                    .scrutinee_value = source.scrutinee_value,
                    .bindings = source.bindings,
                    .pending_lets = source.pending_lets,
                    .read = .{ .callable_capture = .{
                        .callable = callable,
                        .capture_index = capture_index,
                    } },
                };
            } else null;
            out.* = .{
                .pat = branch.pat,
                .guard = branch.guard,
                .body = capture,
                .source = source,
            };
        }

        return Value{ .match_ = .{
            .ty = capture_ty orelse return null,
            .scrutinee = match_value.scrutinee,
            .branches = branches,
            .comptime_site = match_value.comptime_site,
        } };
    }

    fn callableCaptureDemand(
        self: *Cloner,
        capture_index: u32,
        capture_demand: ValueDemand,
    ) Allocator.Error!ValueDemand {
        const captures = try self.pass.arena.allocator().alloc(ValueDemand, @as(usize, capture_index) + 1);
        @memset(captures, .none);
        captures[capture_index] = capture_demand;
        return .{ .callable = .{ .captures = captures } };
    }

    fn callableCaptureFromValue(
        self: *Cloner,
        value: Value,
        callable: DemandedKnownCallable,
        capture_index: u32,
    ) LowerError!?Value {
        if (value == .let_) {
            const capture = (try self.callableCaptureFromValue(value.let_.body.*, callable, capture_index)) orelse return null;
            return try self.wrapPendingLets(capture, value.let_.lets, true);
        }

        if (value == .private_state) {
            if (privateStateCallable(value.private_state)) |private_callable| {
                if (!sameType(self.pass.program, callable.ty, private_callable.ty) or
                    !callableTargetMatches(self.pass.program, callable.fn_id, private_callable.fn_id))
                {
                    return null;
                }
                const capture = privateStateIndexedValueByIndex(private_callable.captures, capture_index) orelse return null;
                return .{ .private_state = capture };
            }

            return null;
        }

        if (value == .finite_callables) {
            var found: ?Value = null;
            for (value.finite_callables.alternatives) |alternative| {
                if (!sameType(self.pass.program, callable.ty, alternative.ty) or
                    !callableTargetMatches(self.pass.program, callable.fn_id, alternative.fn_id))
                {
                    continue;
                }
                if (capture_index >= alternative.captures.len) return null;
                if (found != null) return null;
                found = alternative.captures[capture_index];
            }
            return found;
        }

        const callable_value = switch (value) {
            .callable => |callable_value| callable_value,
            else => return null,
        };
        if (!sameType(self.pass.program, callable.ty, callable_value.ty) or
            !callableTargetMatches(self.pass.program, callable.fn_id, callable_value.fn_id) or
            capture_index >= callable_value.captures.len)
        {
            return null;
        }
        return callable_value.captures[capture_index];
    }

    fn selectorLiteral(self: *Cloner, value: u64) LowerError!Ast.ExprId {
        const selector_ty = try self.pass.primitiveType(.u64);
        return try self.addExpr(.{
            .ty = selector_ty,
            .data = .{ .int_lit = unsignedIntLiteral(value) },
        });
    }

    fn selectorEquals(self: *Cloner, selector: Ast.ExprId, value: u64) LowerError!Ast.ExprId {
        const bool_ty = try self.pass.primitiveType(.bool);
        const literal = try self.selectorLiteral(value);
        const args = try self.pass.program.addExprSpan(&.{ selector, literal });
        return try self.addExpr(.{
            .ty = bool_ty,
            .data = .{ .low_level = .{
                .op = .num_is_eq,
                .args = args,
            } },
        });
    }

    fn cloneFieldAccess(self: *Cloner, ty: Type.TypeId, field: anytype) LowerError!Ast.ExprId {
        try self.noteLoopDemandIfLocalExpr(
            field.receiver,
            try self.pass.demandRecordField(field.field, .materialize),
        );
        const receiver = try self.cloneExprValueDemandingKnownValue(field.receiver);
        if (try self.fieldFromKnownValue(receiver, field.field)) |value| return try self.materialize(value);
        return try self.addExpr(.{ .ty = ty, .data = .{ .field_access = .{
            .receiver = try self.materialize(receiver),
            .field = field.field,
        } } });
    }

    fn cloneTupleAccess(self: *Cloner, ty: Type.TypeId, access: anytype) LowerError!Ast.ExprId {
        try self.noteLoopDemandIfLocalExpr(
            access.tuple,
            try self.pass.demandTupleItem(access.elem_index, .materialize),
        );
        const receiver = try self.cloneExprValueDemandingKnownValue(access.tuple);
        if (try self.itemFromKnownValue(receiver, access.elem_index)) |value| return try self.materialize(value);
        return try self.addExpr(.{ .ty = ty, .data = .{ .tuple_access = .{
            .tuple = try self.materialize(receiver),
            .elem_index = access.elem_index,
        } } });
    }

    fn fieldFromKnownValue(self: *Cloner, receiver: Value, field: names.RecordFieldNameId) LowerError!?Value {
        if (receiver == .let_) {
            const let_value = receiver.let_;
            const field_value = (try self.fieldFromKnownValue(let_value.body.*, field)) orelse return null;
            return try self.wrapPendingLets(field_value, let_value.lets, true);
        }
        if (receiver == .if_) {
            const if_value = receiver.if_;
            const final_else = try self.pass.arena.allocator().create(Value);
            final_else.* = (try self.fieldFromKnownValue(if_value.final_else.*, field)) orelse return null;

            const branches = try self.pass.arena.allocator().alloc(IfValueBranch, if_value.branches.len);
            for (if_value.branches, branches) |branch, *out| {
                out.* = .{
                    .cond = branch.cond,
                    .body = (try self.fieldFromKnownValue(branch.body, field)) orelse return null,
                };
            }

            const field_ty = recordFieldType(self.pass.program, if_value.ty, field) orelse valueType(self.pass.program, final_else.*);
            return Value{ .if_ = .{
                .ty = field_ty,
                .branches = branches,
                .final_else = final_else,
            } };
        }
        if (receiver == .match_) {
            const match_value = receiver.match_;
            const branches = try self.pass.arena.allocator().alloc(MatchValueBranch, match_value.branches.len);
            var field_ty = recordFieldType(self.pass.program, match_value.ty, field);
            for (match_value.branches, branches) |branch, *out| {
                const body = (try self.fieldFromKnownValue(branch.body, field)) orelse return null;
                if (field_ty == null) field_ty = valueType(self.pass.program, body);
                const source = if (branch.source) |source| source_blk: {
                    break :source_blk MatchValueBranchSource{
                        .scrutinee = source.scrutinee,
                        .pat = source.pat,
                        .guard = source.guard,
                        .body = try self.addExpr(.{ .ty = valueType(self.pass.program, body), .data = .{ .field_access = .{
                            .receiver = source.body,
                            .field = field,
                        } } }),
                        .scrutinee_known_value = source.scrutinee_known_value,
                        .scrutinee_value = source.scrutinee_value,
                        .bindings = source.bindings,
                        .pending_lets = source.pending_lets,
                    };
                } else null;
                out.* = .{
                    .pat = branch.pat,
                    .guard = branch.guard,
                    .body = body,
                    .source = source,
                };
            }

            return Value{ .match_ = .{
                .ty = field_ty orelse return null,
                .scrutinee = match_value.scrutinee,
                .branches = branches,
                .comptime_site = match_value.comptime_site,
            } };
        }
        if (fieldFromValue(self.pass.program, receiver, field)) |value| return value;

        if (receiver == .private_state) {
            // A carried private child is the same checked data as the public
            // field, so projection through the checked identity is exact; a
            // missing child keeps the public-boundary invariant intact.
            const field_value = privateStateField(self.pass.program, receiver.private_state, field) orelse return null;
            return Value{ .private_state = field_value };
        }

        const known_value_expr = switch (receiver) {
            .expr_with_known_value => |known_value_expr| known_value_expr,
            else => return null,
        };
        if (!canReadFieldsFromExpr(self.pass.program, known_value_expr.expr)) return null;

        const field_known_value = fieldKnownValueFromKnownValue(self.pass.program, known_value_expr.known_value, field) orelse return null;
        const field_expr = try self.addExpr(.{ .ty = known_valueType(field_known_value), .data = .{ .field_access = .{
            .receiver = known_value_expr.expr,
            .field = field,
        } } });
        return valueFromProjectedExpr(field_expr, field_known_value);
    }

    fn itemFromKnownValue(self: *Cloner, receiver: Value, index: u32) LowerError!?Value {
        if (receiver == .let_) {
            const let_value = receiver.let_;
            const item_value = (try self.itemFromKnownValue(let_value.body.*, index)) orelse return null;
            return try self.wrapPendingLets(item_value, let_value.lets, true);
        }
        if (receiver == .if_) {
            const if_value = receiver.if_;
            const final_else = try self.pass.arena.allocator().create(Value);
            final_else.* = (try self.itemFromKnownValue(if_value.final_else.*, index)) orelse return null;

            const branches = try self.pass.arena.allocator().alloc(IfValueBranch, if_value.branches.len);
            for (if_value.branches, branches) |branch, *out| {
                out.* = .{
                    .cond = branch.cond,
                    .body = (try self.itemFromKnownValue(branch.body, index)) orelse return null,
                };
            }

            const item_ty = tupleItemType(self.pass.program, if_value.ty, index) orelse valueType(self.pass.program, final_else.*);
            return Value{ .if_ = .{
                .ty = item_ty,
                .branches = branches,
                .final_else = final_else,
            } };
        }
        if (receiver == .match_) {
            const match_value = receiver.match_;
            const branches = try self.pass.arena.allocator().alloc(MatchValueBranch, match_value.branches.len);
            var item_ty = tupleItemType(self.pass.program, match_value.ty, index);
            for (match_value.branches, branches) |branch, *out| {
                const body = (try self.itemFromKnownValue(branch.body, index)) orelse return null;
                if (item_ty == null) item_ty = valueType(self.pass.program, body);
                const source = if (branch.source) |source| source_blk: {
                    break :source_blk MatchValueBranchSource{
                        .scrutinee = source.scrutinee,
                        .pat = source.pat,
                        .guard = source.guard,
                        .body = try self.addExpr(.{ .ty = valueType(self.pass.program, body), .data = .{ .tuple_access = .{
                            .tuple = source.body,
                            .elem_index = index,
                        } } }),
                        .scrutinee_known_value = source.scrutinee_known_value,
                        .scrutinee_value = source.scrutinee_value,
                        .bindings = source.bindings,
                        .pending_lets = source.pending_lets,
                    };
                } else null;
                out.* = .{
                    .pat = branch.pat,
                    .guard = branch.guard,
                    .body = body,
                    .source = source,
                };
            }

            return Value{ .match_ = .{
                .ty = item_ty orelse return null,
                .scrutinee = match_value.scrutinee,
                .branches = branches,
                .comptime_site = match_value.comptime_site,
            } };
        }
        if (itemFromValue(receiver, index)) |value| return value;

        const known_value_expr = switch (receiver) {
            .expr_with_known_value => |known_value_expr| known_value_expr,
            else => return null,
        };
        if (!canReadFieldsFromExpr(self.pass.program, known_value_expr.expr)) return null;

        const item_known_value = itemKnownValueFromKnownValue(known_value_expr.known_value, index) orelse return null;
        const item_expr = try self.addExpr(.{ .ty = known_valueType(item_known_value), .data = .{ .tuple_access = .{
            .tuple = known_value_expr.expr,
            .elem_index = index,
        } } });
        return valueFromProjectedExpr(item_expr, item_known_value);
    }

    fn cloneIfValue(self: *Cloner, ty: Type.TypeId, if_: anytype) LowerError!Value {
        const source_branches = try self.pass.allocator.dupe(Ast.IfBranch, self.pass.program.ifBranchSpan(if_.branches));
        defer self.pass.allocator.free(source_branches);

        return try self.cloneIfValueFromBranches(ty, source_branches, 0, if_.final_else);
    }

    fn cloneIfValueFromBranches(
        self: *Cloner,
        ty: Type.TypeId,
        source_branches: []const Ast.IfBranch,
        index: usize,
        final_else: Ast.ExprId,
    ) LowerError!Value {
        if (index == source_branches.len) {
            return try self.cloneExprValueDemandingKnownValue(final_else);
        }

        const branch = source_branches[index];
        const cond_value = try self.cloneExprValueDemandingKnownValue(branch.cond);
        if (knownIfConditionBoolTag(self.pass.program, cond_value)) |cond| {
            if (cond) return try self.cloneScopedExprValueDemandingKnownValue(branch.body);
            return try self.cloneIfValueFromBranches(ty, source_branches, index + 1, final_else);
        }
        if (finiteBoolTagsValue(self.pass.program, cond_value)) |finite_bool| {
            const true_value = try self.cloneScopedExprValueDemandingKnownValue(branch.body);
            const false_value = try self.cloneIfValueFromBranches(ty, source_branches, index + 1, final_else);
            return try self.selectFiniteBoolValue(ty, finite_bool, true_value, false_value);
        }

        const if_branches = try self.pass.arena.allocator().alloc(IfValueBranch, 1);
        const active_pending_lets = try self.snapshotActivePendingLets();
        const active_scoped_locals = try self.snapshotScopedLocals();
        const active_bindings = try self.snapshotSubstBindings();
        if_branches[0] = .{
            .cond = try self.materialize(cond_value),
            .body = try self.cloneScopedExprValueDemandingKnownValue(branch.body),
            .source_body = .{
                .expr = branch.body,
                .pending_lets = active_pending_lets,
                .scoped_locals = active_scoped_locals,
                .bindings = active_bindings,
            },
        };
        const else_value = try self.pass.arena.allocator().create(Value);
        else_value.* = try self.cloneIfValueFromBranches(ty, source_branches, index + 1, final_else);
        return .{ .if_ = .{
            .ty = ty,
            .branches = if_branches,
            .final_else = else_value,
            .final_else_source = if (index + 1 == source_branches.len) .{
                .expr = final_else,
                .pending_lets = active_pending_lets,
                .scoped_locals = active_scoped_locals,
                .bindings = active_bindings,
            } else null,
        } };
    }

    fn cloneScopedExprValueDemandingKnownValue(self: *Cloner, expr_id: Ast.ExprId) LowerError!Value {
        const change_start = self.changes.items.len;
        const value = try self.cloneExprValueDemandingKnownValue(expr_id);
        self.restore(change_start);
        return value;
    }

    fn selectFiniteBoolValue(
        self: *Cloner,
        ty: Type.TypeId,
        finite_bool: FiniteTagsValue,
        true_value: Value,
        false_value: Value,
    ) LowerError!Value {
        if (finite_bool.alternatives.len == 0) {
            Common.invariant("finite Bool value had no alternatives");
        }
        if (finite_bool.alternatives.len == 1) {
            const cond = boolTagValue(self.pass.program, finite_bool.alternatives[0]) orelse
                Common.invariant("finite Bool alternative was not Bool");
            return if (cond) true_value else false_value;
        }

        const branch_count = finite_bool.alternatives.len - 1;
        const branches = try self.pass.arena.allocator().alloc(IfValueBranch, branch_count);
        for (finite_bool.alternatives[0..branch_count], branches, 0..) |alternative, *out, alternative_index| {
            const cond = boolTagValue(self.pass.program, alternative) orelse
                Common.invariant("finite Bool alternative was not Bool");
            out.* = .{
                .cond = try self.selectorEquals(finite_bool.selector, @intCast(alternative_index)),
                .body = if (cond) true_value else false_value,
            };
        }

        const final_cond = boolTagValue(self.pass.program, finite_bool.alternatives[branch_count]) orelse
            Common.invariant("finite Bool final alternative was not Bool");
        const final_else = try self.pass.arena.allocator().create(Value);
        final_else.* = if (final_cond) true_value else false_value;
        return .{ .if_ = .{
            .ty = ty,
            .branches = branches,
            .final_else = final_else,
        } };
    }

    fn cloneMatchJoinedValue(
        self: *Cloner,
        ty: Type.TypeId,
        scrutinee_expr: Ast.ExprId,
        match: @import("../monotype/ast.zig").MatchExpr,
        scrutinee_known_value: ?KnownValue,
        scrutinee_value: ?Value,
    ) LowerError!Value {
        const source_branches = try self.pass.allocator.dupe(Ast.Branch, self.pass.program.branchSpan(match.branches));
        defer self.pass.allocator.free(source_branches);

        var value_branches = std.ArrayList(MatchValueBranch).empty;
        defer value_branches.deinit(self.pass.allocator);

        for (source_branches) |branch| {
            if (scrutinee_known_value) |known_value| {
                if (patternDefinitelyExcludedByKnownValue(self.pass.program, branch.pat, known_value)) continue;
            }
            const change_start = self.changes.items.len;
            if (scrutinee_known_value) |known_value| {
                _ = try self.bindPatToExprWithKnownValueAndValue(branch.pat, known_value, scrutinee_value);
            }
            {
                const scoped_start = self.scopedLocalsLen();
                defer self.restoreScopedLocals(scoped_start);
                try self.appendPatternScopedLocals(branch.pat);

                const cloned_branch = Ast.Branch{
                    .pat = try self.clonePat(branch.pat),
                    .guard = if (branch.guard) |guard| try self.cloneExpr(guard) else null,
                    .body = undefined,
                };
                const body_value = try self.cloneExprValueDemandingKnownValue(branch.body);
                try value_branches.append(self.pass.allocator, .{
                    .pat = cloned_branch.pat,
                    .guard = cloned_branch.guard,
                    .body = body_value,
                    .source = .{
                        .scrutinee = match.scrutinee,
                        .pat = branch.pat,
                        .guard = branch.guard,
                        .body = branch.body,
                        .scrutinee_known_value = scrutinee_known_value,
                        .scrutinee_value = if (scrutinee_value) |value| try self.copyValue(value) else null,
                        .bindings = try self.snapshotSubst(),
                        .pending_lets = try self.snapshotActivePendingLets(),
                    },
                });
            }
            self.restore(change_start);
        }

        return .{ .match_ = .{
            .ty = ty,
            .scrutinee = scrutinee_expr,
            .branches = try self.pass.arena.allocator().dupe(MatchValueBranch, value_branches.items),
            .comptime_site = match.comptime_site,
        } };
    }

    fn cloneMatchJoinedValueWithDemand(
        self: *Cloner,
        ty: Type.TypeId,
        scrutinee_expr: Ast.ExprId,
        match: @import("../monotype/ast.zig").MatchExpr,
        scrutinee_known_value: ?KnownValue,
        scrutinee_value: ?Value,
        demand: ValueDemand,
    ) LowerError!Value {
        const source_branches = try self.pass.allocator.dupe(Ast.Branch, self.pass.program.branchSpan(match.branches));
        defer self.pass.allocator.free(source_branches);

        var value_branches = std.ArrayList(MatchValueBranch).empty;
        defer value_branches.deinit(self.pass.allocator);

        for (source_branches) |branch| {
            if (scrutinee_known_value) |known_value| {
                if (patternDefinitelyExcludedByKnownValue(self.pass.program, branch.pat, known_value)) continue;
            }
            const change_start = self.changes.items.len;
            if (scrutinee_known_value) |known_value| {
                _ = try self.bindPatToExprWithKnownValueAndValue(branch.pat, known_value, scrutinee_value);
            }
            {
                const scoped_start = self.scopedLocalsLen();
                defer self.restoreScopedLocals(scoped_start);
                try self.appendPatternScopedLocals(branch.pat);

                const cloned_branch = Ast.Branch{
                    .pat = try self.clonePat(branch.pat),
                    .guard = if (branch.guard) |guard| try self.cloneExpr(guard) else null,
                    .body = undefined,
                };
                const body_value = try self.cloneExprValueWithDemand(branch.body, demand);
                try value_branches.append(self.pass.allocator, .{
                    .pat = cloned_branch.pat,
                    .guard = cloned_branch.guard,
                    .body = body_value,
                    .source = .{
                        .scrutinee = match.scrutinee,
                        .pat = branch.pat,
                        .guard = branch.guard,
                        .body = branch.body,
                        .scrutinee_known_value = scrutinee_known_value,
                        .scrutinee_value = if (scrutinee_value) |value| try self.copyValue(value) else null,
                        .bindings = try self.snapshotSubst(),
                        .pending_lets = try self.snapshotActivePendingLets(),
                    },
                });
            }
            self.restore(change_start);
        }

        return .{ .match_ = .{
            .ty = ty,
            .scrutinee = scrutinee_expr,
            .branches = try self.pass.arena.allocator().dupe(MatchValueBranch, value_branches.items),
            .comptime_site = match.comptime_site,
        } };
    }

    fn cloneMatchStructuredScrutineeValue(
        self: *Cloner,
        ty: Type.TypeId,
        scrutinee: Value,
        match: @import("../monotype/ast.zig").MatchExpr,
    ) LowerError!?Value {
        return switch (scrutinee) {
            .let_ => |let_value| blk: {
                const change_start = self.changes.items.len;
                defer self.restore(change_start);
                const pending_start = self.activePendingLetsLen();
                const scoped_start = try self.pushPendingLetScope(let_value.lets);
                defer self.popPendingLetScope(scoped_start, pending_start);

                const body = (try self.cloneMatchStructuredScrutineeValue(ty, let_value.body.*, match)) orelse {
                    break :blk null;
                };
                break :blk try self.wrapPendingLets(body, let_value.lets, true);
            },
            .if_ => |if_value| try self.cloneMatchIfValue(ty, if_value, match),
            .match_ => |match_value| try self.cloneMatchMatchValue(ty, match_value, match),
            else => null,
        };
    }

    fn cloneMatchStructuredScrutineeValueWithDemand(
        self: *Cloner,
        ty: Type.TypeId,
        scrutinee: Value,
        match: @import("../monotype/ast.zig").MatchExpr,
        demand: ValueDemand,
    ) LowerError!?Value {
        return switch (scrutinee) {
            .let_ => |let_value| blk: {
                const change_start = self.changes.items.len;
                defer self.restore(change_start);
                const pending_start = self.activePendingLetsLen();
                const scoped_start = try self.pushPendingLetScope(let_value.lets);
                defer self.popPendingLetScope(scoped_start, pending_start);

                const body = (try self.cloneMatchStructuredScrutineeValueWithDemand(ty, let_value.body.*, match, demand)) orelse break :blk null;
                break :blk try self.wrapPendingLets(body, let_value.lets, demand != .none);
            },
            .if_ => |if_value| try self.cloneMatchIfValueWithDemand(ty, if_value, match, demand),
            .match_ => |match_value| try self.cloneMatchMatchValueWithDemand(ty, match_value, match, demand),
            else => null,
        };
    }

    fn cloneMatchIfValue(
        self: *Cloner,
        ty: Type.TypeId,
        if_value: IfValue,
        match: @import("../monotype/ast.zig").MatchExpr,
    ) LowerError!Value {
        const branches = try self.pass.arena.allocator().alloc(IfValueBranch, if_value.branches.len);
        for (if_value.branches, 0..) |branch, index| {
            branches[index] = .{
                .cond = branch.cond,
                .body = try self.cloneMatchScrutineeBranchValue(ty, branch.body, match),
            };
        }

        const final_else = try self.pass.arena.allocator().create(Value);
        final_else.* = try self.cloneMatchScrutineeBranchValue(ty, if_value.final_else.*, match);

        return .{ .if_ = .{
            .ty = ty,
            .branches = branches,
            .final_else = final_else,
        } };
    }

    fn cloneMatchIfValueWithDemand(
        self: *Cloner,
        ty: Type.TypeId,
        if_value: IfValue,
        match: @import("../monotype/ast.zig").MatchExpr,
        demand: ValueDemand,
    ) LowerError!?Value {
        const branches = try self.pass.arena.allocator().alloc(IfValueBranch, if_value.branches.len);
        for (if_value.branches, 0..) |branch, index| {
            const body = (try self.cloneMatchScrutineeBranchValueWithDemand(ty, branch.body, match, demand)) orelse {
                return null;
            };
            branches[index] = .{
                .cond = branch.cond,
                .body = body,
            };
        }

        const final_else = try self.pass.arena.allocator().create(Value);
        final_else.* = (try self.cloneMatchScrutineeBranchValueWithDemand(ty, if_value.final_else.*, match, demand)) orelse {
            return null;
        };

        return .{ .if_ = .{
            .ty = ty,
            .branches = branches,
            .final_else = final_else,
        } };
    }

    fn cloneMatchMatchValue(
        self: *Cloner,
        ty: Type.TypeId,
        match_value: MatchValue,
        outer_match: @import("../monotype/ast.zig").MatchExpr,
    ) LowerError!Value {
        const branches = try self.pass.arena.allocator().alloc(MatchValueBranch, match_value.branches.len);
        for (match_value.branches, 0..) |branch, index| {
            const scoped_start = self.scopedLocalsLen();
            defer self.restoreScopedLocals(scoped_start);
            try self.appendPatternScopedLocals(branch.pat);

            branches[index] = .{
                .pat = branch.pat,
                .guard = branch.guard,
                .body = try self.cloneMatchScrutineeBranchValue(ty, branch.body, outer_match),
                .source = try self.matchBranchSourceThroughMatch(branch.source, ty, outer_match.branches, outer_match.comptime_site),
            };
        }

        return .{ .match_ = .{
            .ty = ty,
            .scrutinee = match_value.scrutinee,
            .branches = branches,
            .comptime_site = match_value.comptime_site,
        } };
    }

    fn cloneMatchMatchValueWithDemand(
        self: *Cloner,
        ty: Type.TypeId,
        match_value: MatchValue,
        outer_match: @import("../monotype/ast.zig").MatchExpr,
        demand: ValueDemand,
    ) LowerError!?Value {
        const outer_scrutinee_demand = try self.matchScrutineeDemand(outer_match.branches, demand);
        const branches = try self.pass.arena.allocator().alloc(MatchValueBranch, match_value.branches.len);
        for (match_value.branches, 0..) |branch, index| {
            const branch_body = try self.cloneMatchValueBranchBodyWithDemand(branch, outer_scrutinee_demand);
            branches[index] = .{
                .pat = branch.pat,
                .guard = branch.guard,
                .body = (try self.cloneMatchScrutineeBranchValueWithDemand(ty, branch_body, outer_match, demand)) orelse return null,
                .source = try self.matchBranchSourceThroughMatch(branch.source, ty, outer_match.branches, outer_match.comptime_site),
            };
        }

        return .{ .match_ = .{
            .ty = ty,
            .scrutinee = match_value.scrutinee,
            .branches = branches,
            .comptime_site = match_value.comptime_site,
        } };
    }

    fn cloneMatchScrutineeBranchValue(
        self: *Cloner,
        ty: Type.TypeId,
        scrutinee: Value,
        match: @import("../monotype/ast.zig").MatchExpr,
    ) LowerError!Value {
        const scrutinee_demand = try self.matchScrutineeDemand(match.branches, .materialize);
        const demanded_scrutinee = try self.applyValueDemand(scrutinee, scrutinee_demand);
        if (try self.simplifyKnownMatchValueMode(ty, demanded_scrutinee, match.branches, .strict, true)) |value| return value;
        if (try self.cloneMatchStructuredScrutineeValue(ty, demanded_scrutinee, match)) |value| return value;

        const public_scrutinee = try self.publicScrutineeForRuntimeMatch(match.scrutinee, demanded_scrutinee);
        const scrutinee_expr = try self.materialize(public_scrutinee);
        if (try self.cloneCaseOfCaseValue(ty, scrutinee_expr, match.branches)) |value| return value;
        const scrutinee_known_value = try self.pass.knownValueFromValue(public_scrutinee);
        return try self.cloneMatchJoinedValue(ty, scrutinee_expr, match, scrutinee_known_value, public_scrutinee);
    }

    fn cloneMatchScrutineeBranchValueWithDemand(
        self: *Cloner,
        ty: Type.TypeId,
        scrutinee: Value,
        match: @import("../monotype/ast.zig").MatchExpr,
        demand: ValueDemand,
    ) LowerError!?Value {
        const scrutinee_demand = try self.matchScrutineeDemand(match.branches, demand);
        const demanded_scrutinee = try self.applyValueDemand(scrutinee, scrutinee_demand);
        if (try self.simplifyKnownMatchValueWithDemandMode(ty, demanded_scrutinee, match.branches, demand, .speculative)) |value| return value;
        if (try self.cloneMatchStructuredScrutineeValueWithDemand(ty, demanded_scrutinee, match, demand)) |value| return value;

        if (demanded_scrutinee == .private_state and !privateStateCanMaterializePublic(self.pass.program, demanded_scrutinee.private_state)) return null;
        const scrutinee_expr = try self.materialize(demanded_scrutinee);
        const scrutinee_known_value = try self.pass.knownValueFromValue(demanded_scrutinee);
        return try self.cloneMatchJoinedValueWithDemand(ty, scrutinee_expr, match, scrutinee_known_value, demanded_scrutinee, demand);
    }

    fn matchBranchSourceThroughMatch(
        self: *Cloner,
        maybe_source: ?MatchValueBranchSource,
        ty: Type.TypeId,
        branches: Ast.Span(Ast.Branch),
        comptime_site: ?Ast.ComptimeSiteId,
    ) LowerError!?MatchValueBranchSource {
        const source = maybe_source orelse return null;
        if (source.read != .none) return null;
        return MatchValueBranchSource{
            .scrutinee = source.scrutinee,
            .pat = source.pat,
            .guard = source.guard,
            .body = try self.addExpr(.{ .ty = ty, .data = .{ .match_ = .{
                .scrutinee = source.body,
                .branches = branches,
                .comptime_site = comptime_site,
            } } }),
            .scrutinee_known_value = source.scrutinee_known_value,
            .scrutinee_value = source.scrutinee_value,
            .bindings = source.bindings,
            .pending_lets = source.pending_lets,
        };
    }

    fn cloneMatch(self: *Cloner, ty: Type.TypeId, match: @import("../monotype/ast.zig").MatchExpr) LowerError!Ast.ExprId {
        const scrutinee = try self.cloneMatchScrutineeValue(match, .materialize);
        if (try self.simplifyKnownMatch(ty, scrutinee, match.branches)) |body| return body;

        const public_scrutinee = try self.publicScrutineeForRuntimeMatch(match.scrutinee, scrutinee);
        const scrutinee_expr = try self.materialize(public_scrutinee);
        const scrutinee_known_value = try self.pass.knownValueFromValue(public_scrutinee);
        return try self.addExpr(.{ .ty = ty, .data = .{ .match_ = .{
            .scrutinee = scrutinee_expr,
            .branches = try self.cloneBranchSpanWithScrutineeKnownValue(match.branches, scrutinee_known_value),
            .comptime_site = match.comptime_site,
        } } });
    }

    fn publicScrutineeForRuntimeMatch(
        self: *Cloner,
        source_scrutinee: Ast.ExprId,
        demanded_scrutinee: Value,
    ) LowerError!Value {
        const source_ty = self.pass.program.exprs.items[@intFromEnum(source_scrutinee)].ty;
        if (!sameType(self.pass.program, source_ty, valueType(self.pass.program, demanded_scrutinee))) {
            return try self.cloneExprValueWithDemand(source_scrutinee, .materialize);
        }
        if (!self.valueCanMaterializePublic(demanded_scrutinee)) {
            return try self.cloneExprValueWithDemand(source_scrutinee, .materialize);
        }
        return demanded_scrutinee;
    }

    fn cloneMatchValueWithDemand(
        self: *Cloner,
        ty: Type.TypeId,
        match: @import("../monotype/ast.zig").MatchExpr,
        demand: ValueDemand,
    ) LowerError!Value {
        const scrutinee = try self.cloneMatchScrutineeValue(match, demand);
        if (try self.simplifyKnownMatchValueWithDemand(ty, scrutinee, match.branches, demand)) |value| return value;
        if (try self.cloneMatchStructuredScrutineeValueWithDemand(ty, scrutinee, match, demand)) |value| return value;

        const public_scrutinee = try self.publicScrutineeForRuntimeMatch(match.scrutinee, scrutinee);
        const scrutinee_expr = try self.materialize(public_scrutinee);
        const scrutinee_known_value = try self.pass.knownValueFromValue(public_scrutinee);
        return try self.cloneMatchJoinedValueWithDemand(ty, scrutinee_expr, match, scrutinee_known_value, public_scrutinee, demand);
    }

    fn cloneMatchScrutineeValue(self: *Cloner, match: @import("../monotype/ast.zig").MatchExpr, result_demand: ValueDemand) LowerError!Value {
        const demand = try self.matchScrutineeDemand(match.branches, result_demand);
        if (demand == .none) return try self.cloneExprValueDemandingKnownValue(match.scrutinee);
        return try self.cloneExprValueWithDemand(match.scrutinee, demand);
    }

    fn matchScrutineeDemand(self: *Cloner, branches_span: Ast.Span(Ast.Branch), result_demand: ValueDemand) LowerError!ValueDemand {
        var demand: ValueDemand = .none;
        for (self.pass.program.branchSpan(branches_span)) |branch| {
            var branch_demand = try self.patternDemandInExpr(branch.pat, branch.body, result_demand);
            if (branch.guard) |guard| {
                branch_demand = try self.mergeValueDemand(branch_demand, try self.patternDemandInExpr(branch.pat, guard, .materialize));
            }
            demand = try self.mergeValueDemand(demand, branch_demand);
        }
        return demand;
    }

    fn matchValueScrutineeDemand(
        self: *Cloner,
        branches: []const MatchValueBranch,
        result_demand: ValueDemand,
    ) LowerError!ValueDemand {
        var demand: ValueDemand = .none;
        for (branches) |branch| {
            var branch_demand = try self.patternDemandInValue(branch.pat, branch.body, result_demand);
            if (branch.guard) |guard| {
                branch_demand = try self.mergeValueDemand(branch_demand, try self.patternDemandInExpr(branch.pat, guard, .materialize));
            }
            demand = try self.mergeValueDemand(demand, branch_demand);
        }
        return demand;
    }

    fn patternDemandInExpr(self: *Cloner, pat_id: Ast.PatId, expr_id: Ast.ExprId, context: ValueDemand) LowerError!ValueDemand {
        const pat = self.pass.program.pats.items[@intFromEnum(pat_id)];
        return switch (pat.data) {
            .bind => |local| try self.localDemandInExpr(local, expr_id, context),
            .wildcard => .none,
            .as => |as| try self.mergeValueDemand(
                try self.patternDemandInExpr(as.pattern, expr_id, context),
                try self.localDemandInExpr(as.local, expr_id, context),
            ),
            .record => |fields_span| blk: {
                const fields = self.pass.program.recordDestructSpan(fields_span);
                var demands = std.ArrayList(FieldDemand).empty;
                defer demands.deinit(self.pass.allocator);
                for (fields) |field| {
                    const field_demand = try self.patternDemandInExpr(field.pattern, expr_id, context);
                    if (field_demand == .none) continue;
                    try demands.append(self.pass.allocator, .{
                        .name = field.name,
                        .demand = try self.pass.storedDemand(field_demand),
                    });
                }
                if (demands.items.len == 0) break :blk .none;
                break :blk ValueDemand{ .record = try self.pass.arena.allocator().dupe(FieldDemand, demands.items) };
            },
            .tuple => |items_span| blk: {
                const pats = self.pass.program.patSpan(items_span);
                var demands = std.ArrayList(ItemDemand).empty;
                defer demands.deinit(self.pass.allocator);
                for (pats, 0..) |child_pat, index| {
                    const item_demand = try self.patternDemandInExpr(child_pat, expr_id, context);
                    if (item_demand == .none) continue;
                    try demands.append(self.pass.allocator, .{
                        .index = @intCast(index),
                        .demand = try self.pass.storedDemand(item_demand),
                    });
                }
                if (demands.items.len == 0) break :blk .none;
                break :blk ValueDemand{ .tuple = try self.pass.arena.allocator().dupe(ItemDemand, demands.items) };
            },
            .tag => |tag_pat| blk: {
                const pats = self.pass.program.patSpan(tag_pat.payloads);
                var demands = std.ArrayList(ItemDemand).empty;
                defer demands.deinit(self.pass.allocator);
                for (pats, 0..) |child_pat, index| {
                    const payload_demand = try self.patternDemandInExpr(child_pat, expr_id, context);
                    if (payload_demand == .none) continue;
                    try demands.append(self.pass.allocator, .{
                        .index = @intCast(index),
                        .demand = try self.pass.storedDemand(payload_demand),
                    });
                }
                const alternatives = try self.pass.arena.allocator().alloc(TagAlternativeDemand, 1);
                alternatives[0] = .{
                    .name = tag_pat.name,
                    .payloads = try self.pass.arena.allocator().dupe(ItemDemand, demands.items),
                };
                break :blk ValueDemand{ .tag = .{
                    .alternatives = alternatives,
                } };
            },
            .nominal => |backing_pat| blk: {
                const backing_demand = try self.patternDemandInExpr(backing_pat, expr_id, context);
                if (backing_demand == .none) break :blk .none;
                break :blk ValueDemand{ .nominal = try self.pass.storedDemand(backing_demand) };
            },
            .list,
            .int_lit,
            .dec_lit,
            .frac_f32_lit,
            .frac_f64_lit,
            .str_lit,
            .str_pattern,
            => .materialize,
        };
    }

    fn patternDemandInValue(self: *Cloner, pat_id: Ast.PatId, value: Value, context: ValueDemand) LowerError!ValueDemand {
        const pat = self.pass.program.pats.items[@intFromEnum(pat_id)];
        return switch (pat.data) {
            .bind => |local| try self.localDemandInValue(local, value, context),
            .wildcard => .none,
            .as => |as| try self.mergeValueDemand(
                try self.patternDemandInValue(as.pattern, value, context),
                try self.localDemandInValue(as.local, value, context),
            ),
            .record => |fields_span| blk: {
                const fields = self.pass.program.recordDestructSpan(fields_span);
                var demands = std.ArrayList(FieldDemand).empty;
                defer demands.deinit(self.pass.allocator);
                for (fields) |field| {
                    const field_demand = try self.patternDemandInValue(field.pattern, value, context);
                    if (field_demand == .none) continue;
                    try demands.append(self.pass.allocator, .{
                        .name = field.name,
                        .demand = try self.pass.storedDemand(field_demand),
                    });
                }
                if (demands.items.len == 0) break :blk .none;
                break :blk ValueDemand{ .record = try self.pass.arena.allocator().dupe(FieldDemand, demands.items) };
            },
            .tuple => |items_span| blk: {
                const pats = self.pass.program.patSpan(items_span);
                var demands = std.ArrayList(ItemDemand).empty;
                defer demands.deinit(self.pass.allocator);
                for (pats, 0..) |child_pat, index| {
                    const item_demand = try self.patternDemandInValue(child_pat, value, context);
                    if (item_demand == .none) continue;
                    try demands.append(self.pass.allocator, .{
                        .index = @intCast(index),
                        .demand = try self.pass.storedDemand(item_demand),
                    });
                }
                if (demands.items.len == 0) break :blk .none;
                break :blk ValueDemand{ .tuple = try self.pass.arena.allocator().dupe(ItemDemand, demands.items) };
            },
            .tag => |tag_pat| blk: {
                const pats = self.pass.program.patSpan(tag_pat.payloads);
                var demands = std.ArrayList(ItemDemand).empty;
                defer demands.deinit(self.pass.allocator);
                for (pats, 0..) |child_pat, index| {
                    const payload_demand = try self.patternDemandInValue(child_pat, value, context);
                    if (payload_demand == .none) continue;
                    try demands.append(self.pass.allocator, .{
                        .index = @intCast(index),
                        .demand = try self.pass.storedDemand(payload_demand),
                    });
                }
                const alternatives = try self.pass.arena.allocator().alloc(TagAlternativeDemand, 1);
                alternatives[0] = .{
                    .name = tag_pat.name,
                    .payloads = try self.pass.arena.allocator().dupe(ItemDemand, demands.items),
                };
                break :blk ValueDemand{ .tag = .{
                    .alternatives = alternatives,
                } };
            },
            .nominal => |backing_pat| blk: {
                const backing_demand = try self.patternDemandInValue(backing_pat, value, context);
                if (backing_demand == .none) break :blk .none;
                break :blk ValueDemand{ .nominal = try self.pass.storedDemand(backing_demand) };
            },
            .list,
            .int_lit,
            .dec_lit,
            .frac_f32_lit,
            .frac_f64_lit,
            .str_lit,
            .str_pattern,
            => .materialize,
        };
    }

    fn localDemandInExpr(self: *Cloner, local: Ast.LocalId, expr_id: Ast.ExprId, context: ValueDemand) LowerError!ValueDemand {
        if (context == .none) return .none;
        const expr = self.pass.program.exprs.items[@intFromEnum(expr_id)];
        if (expr.data == .local and expr.data.local == local) return context;

        const local_cache_key: LocalDemandCacheId = .{
            .local = @intFromEnum(local),
            .expr = @intFromEnum(expr_id),
        };
        if (self.local_demand_cache_index.get(local_cache_key)) |indices| {
            var cache_index = indices.items.len;
            while (cache_index > 0) {
                cache_index -= 1;
                const entry = self.local_demand_cache.items[indices.items[cache_index]];
                if (entry.depends_on_active_demands and entry.demand_epoch != self.demand_cache_epoch) continue;
                if (entry.subst_scope_id != self.subst_scope_id) continue;
                if (!try self.valueDemandRefsAreActive(entry.context)) continue;
                if (!try self.valueDemandRefsAreActive(entry.demand)) continue;
                if (!try self.valueDemandEqlInActiveContext(entry.context, context)) continue;
                return entry.demand;
            }
        }

        const demand_resolves_before = self.active_demand_resolves;
        var demand: ValueDemand = .none;
        try self.mergeLocalDemandInExpr(local, expr_id, context, &demand);
        const local_cache_entry_index = self.local_demand_cache.items.len;
        try self.local_demand_cache.append(self.pass.allocator, .{
            .demand_epoch = self.demand_cache_epoch,
            .subst_scope_id = self.subst_scope_id,
            .depends_on_active_demands = valueDemandContainsActiveRef(context) or
                self.active_demand_resolves != demand_resolves_before,
            .local = local,
            .expr = expr_id,
            .context = context,
            .demand = demand,
        });
        const local_index_entry = try self.local_demand_cache_index.getOrPut(local_cache_key);
        if (!local_index_entry.found_existing) local_index_entry.value_ptr.* = .empty;
        try local_index_entry.value_ptr.append(self.pass.allocator, local_cache_entry_index);
        return demand;
    }

    fn localDemandInValue(self: *Cloner, local: Ast.LocalId, value: Value, context: ValueDemand) LowerError!ValueDemand {
        var demand: ValueDemand = .none;
        try self.mergeLocalDemandInValue(local, value, context, &demand);
        return demand;
    }

    fn activeFunctionDemandSlot(self: *Cloner, demand_ref: FunctionDemandSlotId) *ValueDemand {
        if (demand_ref.node >= self.function_demand_nodes.items.len) Common.invariant("function demand reference node exceeded demand graph");
        return self.function_demand_nodes.items[demand_ref.node].slot;
    }

    fn demandFrameIsActive(self: *Cloner, frame_id: usize) bool {
        for (self.demand_stack.items) |frame| {
            if (frame.id == frame_id) return true;
        }
        return false;
    }

    fn canonicalFunctionDemandSlotId(self: *Cloner, demand_ref: FunctionDemandSlotId) FunctionDemandSlotId {
        var current = demand_ref;
        var depth: usize = 0;
        while (true) {
            depth += 1;
            if (depth > self.function_demand_nodes.items.len * 2 + 1) Common.invariant("cyclic function demand reference aliases");
            if (current.node >= self.function_demand_nodes.items.len) Common.invariant("function demand reference node exceeded demand graph");
            const node = &self.function_demand_nodes.items[current.node];
            if (node.parent) |parent| {
                current = .{ .node = parent };
                continue;
            }
            const slot = node.slot;
            if (slot.* != .fn_param) return current;
            const next = slot.fn_param;
            if (functionDemandSlotIdEql(current, next)) return current;
            current = next;
        }
    }

    fn activeFunctionDemandSlotId(self: *Cloner, demand: ValueDemand) ?ValueDemand {
        if (demand != .fn_param) return null;
        if (!self.functionDemandSlotIdIsActive(demand.fn_param)) return null;
        const demand_ref = self.canonicalFunctionDemandSlotId(demand.fn_param);
        const resolved = self.activeFunctionDemandSlot(demand_ref).*;
        return if (resolved == .fn_param and functionDemandSlotIdEql(resolved.fn_param, demand_ref)) null else resolved;
    }

    fn functionDemandSlotIdIsActive(self: *Cloner, demand_ref: FunctionDemandSlotId) bool {
        if (demand_ref.node >= self.function_demand_nodes.items.len) return false;
        const root_ref = self.canonicalFunctionDemandSlotId(demand_ref);
        if (root_ref.node >= self.function_demand_nodes.items.len) return false;
        return self.demandFrameIsActive(self.function_demand_nodes.items[root_ref.node].frame_id);
    }

    fn valueDemandRefsAreActive(self: *Cloner, demand: ValueDemand) Allocator.Error!bool {
        var seen = std.ArrayList(*const ValueDemand).empty;
        defer seen.deinit(self.pass.allocator);
        return try self.valueDemandRefsAreActiveSeen(demand, &seen);
    }

    fn valueDemandPtrRefsAreActive(
        self: *Cloner,
        demand: *const ValueDemand,
        seen: *std.ArrayList(*const ValueDemand),
    ) Allocator.Error!bool {
        for (seen.items) |seen_demand| {
            if (seen_demand == demand) return true;
        }
        try seen.append(self.pass.allocator, demand);
        return try self.valueDemandRefsAreActiveSeen(demand.*, seen);
    }

    fn valueDemandRefsAreActiveSeen(
        self: *Cloner,
        demand: ValueDemand,
        seen: *std.ArrayList(*const ValueDemand),
    ) Allocator.Error!bool {
        return switch (demand) {
            .none,
            .materialize,
            => true,
            .loop_param => |index| blk: {
                if (self.loop_stack.getLastOrNull()) |loop| break :blk index < loop.demands.len;
                if (self.state_loop_stack.getLastOrNull()) |state_loop| break :blk index < state_loop.demands.len;
                break :blk false;
            },
            .fn_param => |demand_ref| self.functionDemandSlotIdIsActive(demand_ref),
            .record => |fields| blk: {
                for (fields) |field| {
                    if (!try self.valueDemandPtrRefsAreActive(field.demand, seen)) break :blk false;
                }
                break :blk true;
            },
            .tuple => |items| blk: {
                for (items) |item| {
                    if (!try self.valueDemandPtrRefsAreActive(item.demand, seen)) break :blk false;
                }
                break :blk true;
            },
            .tag => |tag| blk: {
                for (tag.alternatives) |alternative| {
                    for (alternative.payloads) |payload| {
                        if (!try self.valueDemandPtrRefsAreActive(payload.demand, seen)) break :blk false;
                    }
                }
                break :blk true;
            },
            .nominal => |backing| try self.valueDemandPtrRefsAreActive(backing, seen),
            .callable => |callable| blk: {
                for (callable.captures, 0..) |_, index| {
                    if (!try self.valueDemandPtrRefsAreActive(&callable.captures[index], seen)) break :blk false;
                }
                if (callable.result) |result| {
                    if (!try self.valueDemandPtrRefsAreActive(result, seen)) break :blk false;
                }
                break :blk true;
            },
        };
    }

    fn resolveLoopDemandRef(self: *Cloner, demand: ValueDemand) ValueDemand {
        return switch (demand) {
            .loop_param => |index| blk: {
                self.active_demand_resolves +%= 1;
                if (self.loop_stack.getLastOrNull()) |loop| {
                    if (index >= loop.demands.len) Common.invariant("loop demand reference index exceeded active loop arity");
                    break :blk loop.demands[index];
                }
                if (self.state_loop_stack.getLastOrNull()) |state_loop| {
                    if (index >= state_loop.demands.len) Common.invariant("state loop demand reference index exceeded active loop arity");
                    break :blk state_loop.demands[index];
                }
                Common.invariant("loop demand reference escaped active loop demand solving");
            },
            .fn_param => |demand_ref| blk: {
                self.active_demand_resolves +%= 1;
                const resolved_ref = self.canonicalFunctionDemandSlotId(demand_ref);
                break :blk self.activeFunctionDemandSlot(resolved_ref).*;
            },
            else => demand,
        };
    }

    fn closeLoopDemandRefs(self: *Cloner, demand: ValueDemand) Allocator.Error!ValueDemand {
        var seen_nodes = std.ArrayList(usize).empty;
        defer seen_nodes.deinit(self.pass.allocator);
        var seen_ptrs = std.ArrayList(*const ValueDemand).empty;
        defer seen_ptrs.deinit(self.pass.allocator);
        return try self.closeLoopDemandRefsSeen(demand, &seen_nodes, &seen_ptrs);
    }

    fn closeLoopDemandRefsSeen(
        self: *Cloner,
        demand: ValueDemand,
        seen_nodes: *std.ArrayList(usize),
        seen_ptrs: *std.ArrayList(*const ValueDemand),
    ) Allocator.Error!ValueDemand {
        return switch (demand) {
            .none,
            .materialize,
            => demand,
            .fn_param => |demand_ref| blk: {
                if (!self.functionDemandSlotIdIsActive(demand_ref)) {
                    break :blk ValueDemand.none;
                }
                const root_ref = self.canonicalFunctionDemandSlotId(demand_ref);
                for (seen_nodes.items) |seen_node| {
                    if (seen_node == root_ref.node) break :blk ValueDemand.none;
                }
                try seen_nodes.append(self.pass.allocator, root_ref.node);
                defer _ = seen_nodes.pop();

                const resolved = self.activeFunctionDemandSlot(root_ref).*;
                if (resolved == .fn_param and functionDemandSlotIdEql(resolved.fn_param, root_ref)) {
                    break :blk ValueDemand.none;
                }
                break :blk try self.closeLoopDemandRefsSeen(resolved, seen_nodes, seen_ptrs);
            },
            .loop_param => blk: {
                const resolved = self.resolveLoopDemandRef(demand);
                if (resolved == .loop_param) Common.invariant("loop demand reference did not resolve before call-boundary specialization");
                break :blk try self.closeLoopDemandRefsSeen(resolved, seen_nodes, seen_ptrs);
            },
            .record => |fields| blk: {
                const closed_fields = try self.pass.arena.allocator().alloc(FieldDemand, fields.len);
                for (fields, closed_fields) |field, *closed| {
                    closed.* = .{
                        .name = field.name,
                        .demand = try self.pass.storedDemand(try self.closeLoopDemandPtrRefsSeen(field.demand, seen_nodes, seen_ptrs)),
                    };
                }
                break :blk ValueDemand{ .record = closed_fields };
            },
            .tuple => |items| blk: {
                const closed_items = try self.pass.arena.allocator().alloc(ItemDemand, items.len);
                for (items, closed_items) |item, *closed| {
                    closed.* = .{
                        .index = item.index,
                        .demand = try self.pass.storedDemand(try self.closeLoopDemandPtrRefsSeen(item.demand, seen_nodes, seen_ptrs)),
                    };
                }
                break :blk ValueDemand{ .tuple = closed_items };
            },
            .tag => |tag| blk: {
                const alternatives = try self.pass.arena.allocator().alloc(TagAlternativeDemand, tag.alternatives.len);
                for (tag.alternatives, alternatives) |alternative, *closed_alternative| {
                    const payloads = try self.pass.arena.allocator().alloc(ItemDemand, alternative.payloads.len);
                    for (alternative.payloads, payloads) |payload, *closed_payload| {
                        closed_payload.* = .{
                            .index = payload.index,
                            .demand = try self.pass.storedDemand(try self.closeLoopDemandPtrRefsSeen(payload.demand, seen_nodes, seen_ptrs)),
                        };
                    }
                    closed_alternative.* = .{
                        .name = alternative.name,
                        .payloads = payloads,
                    };
                }
                break :blk ValueDemand{ .tag = .{ .alternatives = alternatives } };
            },
            .nominal => |backing| ValueDemand{
                .nominal = try self.pass.storedDemand(try self.closeLoopDemandPtrRefsSeen(backing, seen_nodes, seen_ptrs)),
            },
            .callable => |callable| blk: {
                const captures = try self.pass.arena.allocator().alloc(ValueDemand, callable.captures.len);
                for (callable.captures, captures) |capture, *closed_capture| {
                    closed_capture.* = try self.closeLoopDemandRefsSeen(capture, seen_nodes, seen_ptrs);
                }
                const result = if (callable.result) |result_demand|
                    try self.pass.storedDemand(try self.closeLoopDemandPtrRefsSeen(result_demand, seen_nodes, seen_ptrs))
                else
                    null;
                break :blk ValueDemand{ .callable = .{
                    .captures = captures,
                    .result = result,
                } };
            },
        };
    }

    fn closeLoopDemandPtrRefsSeen(
        self: *Cloner,
        demand: *const ValueDemand,
        seen_nodes: *std.ArrayList(usize),
        seen_ptrs: *std.ArrayList(*const ValueDemand),
    ) Allocator.Error!ValueDemand {
        for (seen_ptrs.items) |seen_demand| {
            if (seen_demand == demand) return .none;
        }
        try seen_ptrs.append(self.pass.allocator, demand);
        defer _ = seen_ptrs.pop();
        return try self.closeLoopDemandRefsSeen(demand.*, seen_nodes, seen_ptrs);
    }

    fn decompositionDemand(self: *Cloner, demand: ValueDemand) ValueDemand {
        return switch (demand) {
            .loop_param => if (self.loop_stack.items.len != 0 or self.state_loop_stack.items.len != 0)
                self.resolveLoopDemandRef(demand)
            else
                .none,
            .fn_param => blk: {
                if (!self.functionDemandSlotIdIsActive(demand.fn_param)) break :blk .none;
                const demand_ref = self.canonicalFunctionDemandSlotId(demand.fn_param);
                const resolved = self.activeFunctionDemandSlot(demand_ref).*;
                if (resolved == .none) break :blk ValueDemand{ .fn_param = demand_ref };
                if (resolved == .fn_param and functionDemandSlotIdEql(resolved.fn_param, demand_ref)) break :blk ValueDemand{ .fn_param = demand_ref };
                break :blk resolved;
            },
            else => demand,
        };
    }

    fn activeLoopDemandRef(self: *Cloner, demand: ValueDemand) ?ValueDemand {
        if (demand != .loop_param) return null;
        const index = demand.loop_param;
        if (self.loop_stack.getLastOrNull()) |loop| {
            if (index >= loop.demands.len) Common.invariant("loop demand reference index exceeded active loop arity");
            const resolved = loop.demands[index];
            return if (resolved == .loop_param) null else resolved;
        }
        if (self.state_loop_stack.getLastOrNull()) |state_loop| {
            if (index >= state_loop.demands.len) Common.invariant("state loop demand reference index exceeded active loop arity");
            const resolved = state_loop.demands[index];
            return if (resolved == .loop_param) null else resolved;
        }
        return null;
    }

    fn demandSlotEndpoint(self: *Cloner, demand: ValueDemand) ?DemandSlotEndpoint {
        return switch (demand) {
            .loop_param => |index| .{ .kind = .loop_param, .id = index },
            .fn_param => |demand_ref| blk: {
                if (!self.functionDemandSlotIdIsActive(demand_ref)) break :blk null;
                break :blk .{
                    .kind = .fn_param,
                    .id = self.canonicalFunctionDemandSlotId(demand_ref).node,
                };
            },
            else => null,
        };
    }

    fn valueDemandEqlInActiveContext(self: *Cloner, lhs: ValueDemand, rhs: ValueDemand) Allocator.Error!bool {
        const scratch_start = self.demand_slot_edge_scratch.items.len;
        defer self.demand_slot_edge_scratch.shrinkRetainingCapacity(scratch_start);
        return try self.valueDemandEqlInActiveContextSeen(lhs, rhs, &self.demand_slot_edge_scratch);
    }

    fn valueDemandEqlInActiveContextSeen(
        self: *Cloner,
        lhs: ValueDemand,
        rhs: ValueDemand,
        seen: *std.ArrayList(DemandSlotEdge),
    ) Allocator.Error!bool {
        const lhs_ref = self.demandSlotEndpoint(lhs);
        const rhs_ref = self.demandSlotEndpoint(rhs);
        if (lhs_ref) |lhs_key| {
            if (rhs_ref) |rhs_key| {
                if (demandSlotEndpointEql(lhs_key, rhs_key)) return true;
            }
        }
        if (lhs_ref != null or rhs_ref != null) {
            const pair: DemandSlotEdge = .{ .lhs = lhs_ref, .rhs = rhs_ref };
            for (seen.items) |existing| {
                if (demandSlotEdgeEql(existing, pair)) return true;
            }
            try seen.append(self.pass.allocator, pair);
        }

        if (self.activeLoopDemandRef(lhs)) |resolved| return try self.valueDemandEqlInActiveContextSeen(resolved, rhs, seen);
        if (self.activeLoopDemandRef(rhs)) |resolved| return try self.valueDemandEqlInActiveContextSeen(lhs, resolved, seen);
        if (self.activeFunctionDemandSlotId(lhs)) |resolved| return try self.valueDemandEqlInActiveContextSeen(resolved, rhs, seen);
        if (self.activeFunctionDemandSlotId(rhs)) |resolved| return try self.valueDemandEqlInActiveContextSeen(lhs, resolved, seen);

        if (std.meta.activeTag(lhs) != std.meta.activeTag(rhs)) return false;
        return switch (lhs) {
            .none,
            .materialize,
            => true,
            .loop_param => lhs.loop_param == rhs.loop_param,
            .fn_param => functionDemandSlotIdEql(lhs.fn_param, rhs.fn_param),
            .record => |lhs_fields| blk: {
                const rhs_fields = rhs.record;
                if (lhs_fields.len != rhs_fields.len) break :blk false;
                for (lhs_fields) |lhs_field| {
                    const rhs_field = fieldDemandByName(self.pass.program, rhs_fields, lhs_field.name) orelse break :blk false;
                    if (!try self.valueDemandEqlInActiveContextSeen(lhs_field.demand.*, rhs_field.demand.*, seen)) break :blk false;
                }
                break :blk true;
            },
            .tuple => |lhs_items| blk: {
                const rhs_items = rhs.tuple;
                if (lhs_items.len != rhs_items.len) break :blk false;
                for (lhs_items) |lhs_item| {
                    const rhs_item = itemDemandByIndex(rhs_items, lhs_item.index) orelse break :blk false;
                    if (!try self.valueDemandEqlInActiveContextSeen(lhs_item.demand.*, rhs_item.demand.*, seen)) break :blk false;
                }
                break :blk true;
            },
            .tag => |lhs_tag| blk: {
                const rhs_alternatives = rhs.tag.alternatives;
                if (lhs_tag.alternatives.len != rhs_alternatives.len) break :blk false;
                for (lhs_tag.alternatives) |lhs_alternative| {
                    const rhs_alternative = tagAlternativeDemandByName(self.pass.program, rhs_alternatives, lhs_alternative.name) orelse break :blk false;
                    if (lhs_alternative.payloads.len != rhs_alternative.payloads.len) break :blk false;
                    for (lhs_alternative.payloads) |lhs_payload| {
                        const rhs_payload = itemDemandByIndex(rhs_alternative.payloads, lhs_payload.index) orelse break :blk false;
                        if (!try self.valueDemandEqlInActiveContextSeen(lhs_payload.demand.*, rhs_payload.demand.*, seen)) break :blk false;
                    }
                }
                break :blk true;
            },
            .nominal => try self.valueDemandEqlInActiveContextSeen(lhs.nominal.*, rhs.nominal.*, seen),
            .callable => |lhs_callable| blk: {
                const rhs_callable = rhs.callable;
                const captures_len = @max(lhs_callable.captures.len, rhs_callable.captures.len);
                for (0..captures_len) |index| {
                    const lhs_capture = callableCaptureDemandAt(lhs_callable.captures, index);
                    const rhs_capture = callableCaptureDemandAt(rhs_callable.captures, index);
                    if (!try self.valueDemandEqlInActiveContextSeen(lhs_capture, rhs_capture, seen)) break :blk false;
                }
                const lhs_result = callableResultDemand(lhs_callable.result);
                const rhs_result = callableResultDemand(rhs_callable.result);
                if (!try self.valueDemandEqlInActiveContextSeen(lhs_result, rhs_result, seen)) break :blk false;
                break :blk true;
            },
        };
    }

    fn mergeValueDemand(self: *Cloner, existing: ValueDemand, incoming: ValueDemand) LowerError!ValueDemand {
        self.merge_value_demand_depth += 1;
        defer self.merge_value_demand_depth -= 1;
        if (self.merge_value_demand_depth > 1000) Common.invariant("value demand merge recursion did not converge");

        if (existing == .materialize or incoming == .materialize) return .materialize;
        if (existing == .none) return incoming;
        if (incoming == .none) return existing;

        if (existing == .loop_param and incoming == .loop_param) {
            return if (existing.loop_param == incoming.loop_param) existing else .materialize;
        }

        if (existing == .fn_param and incoming == .fn_param) {
            return .{ .fn_param = try self.mergeFunctionDemandSlotIds(existing.fn_param, incoming.fn_param) };
        }

        if (existing == .loop_param) {
            if (self.loop_stack.getLastOrNull()) |loop| {
                if (existing.loop_param >= loop.demands.len) Common.invariant("loop demand reference index exceeded active loop arity");
                if (try self.valueDemandEqlInActiveContext(loop.demands[existing.loop_param], incoming)) return existing;
                const merged = try self.mergeActiveLoopParamDemand(loop, existing.loop_param, loop.demands[existing.loop_param], incoming);
                loop.demands[existing.loop_param] = merged;
                return existing;
            }
            if (self.state_loop_stack.getLastOrNull()) |state_loop| {
                if (existing.loop_param >= state_loop.demands.len) Common.invariant("state loop demand reference index exceeded active loop arity");
                if (try self.valueDemandEqlInActiveContext(state_loop.demands[existing.loop_param], incoming)) return existing;
                try self.mergeActiveStateLoopParamDemand(state_loop, existing.loop_param, incoming);
                return existing;
            }
            return try self.pass.mergeValueDemand(existing, incoming);
        }

        if (incoming == .loop_param) {
            if (self.loop_stack.getLastOrNull()) |loop| {
                if (incoming.loop_param >= loop.demands.len) Common.invariant("loop demand reference index exceeded active loop arity");
                if (try self.valueDemandEqlInActiveContext(loop.demands[incoming.loop_param], existing)) return incoming;
                const merged = try self.mergeActiveLoopParamDemand(loop, incoming.loop_param, loop.demands[incoming.loop_param], existing);
                loop.demands[incoming.loop_param] = merged;
                return incoming;
            }
            if (self.state_loop_stack.getLastOrNull()) |state_loop| {
                if (incoming.loop_param >= state_loop.demands.len) Common.invariant("state loop demand reference index exceeded active loop arity");
                if (try self.valueDemandEqlInActiveContext(state_loop.demands[incoming.loop_param], existing)) return incoming;
                try self.mergeActiveStateLoopParamDemand(state_loop, incoming.loop_param, existing);
                return incoming;
            }
            return try self.pass.mergeValueDemand(existing, incoming);
        }

        if (existing == .fn_param) {
            return .{ .fn_param = try self.mergeFunctionDemandSlotId(existing.fn_param, incoming) };
        }

        if (incoming == .fn_param) {
            return .{ .fn_param = try self.mergeFunctionDemandSlotId(incoming.fn_param, existing) };
        }

        if (std.meta.activeTag(existing) != std.meta.activeTag(incoming)) return .materialize;

        return switch (existing) {
            .none, .materialize, .loop_param, .fn_param => unreachable,
            .record => try self.mergeRecordDemand(existing.record, incoming.record),
            .tuple => try self.mergeTupleDemand(existing.tuple, incoming.tuple),
            .tag => blk: {
                const alternatives = try self.mergeTagDemand(existing.tag.alternatives, incoming.tag.alternatives);
                break :blk ValueDemand{ .tag = .{ .alternatives = alternatives } };
            },
            .nominal => blk: {
                const merged = try self.mergeValueDemand(existing.nominal.*, incoming.nominal.*);
                break :blk ValueDemand{ .nominal = try self.pass.storedDemand(merged) };
            },
            .callable => |existing_callable| blk: {
                const incoming_callable = incoming.callable;
                const captures_len = @max(existing_callable.captures.len, incoming_callable.captures.len);
                const captures = try self.pass.arena.allocator().alloc(ValueDemand, captures_len);
                for (captures, 0..) |*out, index| {
                    const existing_capture = if (index < existing_callable.captures.len) existing_callable.captures[index] else .none;
                    const incoming_capture = if (index < incoming_callable.captures.len) incoming_callable.captures[index] else .none;
                    out.* = try self.mergeValueDemand(existing_capture, incoming_capture);
                }
                const result = if (existing_callable.result) |existing_result| result: {
                    if (incoming_callable.result) |incoming_result| {
                        const merged = try self.mergeValueDemand(existing_result.*, incoming_result.*);
                        break :result try self.pass.storedDemand(merged);
                    }
                    break :result existing_result;
                } else incoming_callable.result;
                break :blk ValueDemand{ .callable = .{ .captures = captures, .result = result } };
            },
        };
    }

    fn mergeRecordDemand(
        self: *Cloner,
        existing: []const FieldDemand,
        incoming: []const FieldDemand,
    ) LowerError!ValueDemand {
        var fields = std.ArrayList(FieldDemand).empty;
        defer fields.deinit(self.pass.allocator);
        try fields.appendSlice(self.pass.allocator, existing);

        for (incoming) |incoming_field| {
            for (fields.items) |*field| {
                if (!self.pass.program.names.recordFieldLabelTextEql(field.name, incoming_field.name)) continue;
                const merged = try self.mergeValueDemand(field.demand.*, incoming_field.demand.*);
                field.demand = try self.pass.storedDemand(merged);
                break;
            } else {
                try fields.append(self.pass.allocator, incoming_field);
            }
        }

        return .{ .record = try self.pass.arena.allocator().dupe(FieldDemand, fields.items) };
    }
    fn mergeTupleDemand(
        self: *Cloner,
        existing: []const ItemDemand,
        incoming: []const ItemDemand,
    ) LowerError!ValueDemand {
        var items = std.ArrayList(ItemDemand).empty;
        defer items.deinit(self.pass.allocator);
        try items.appendSlice(self.pass.allocator, existing);

        for (incoming) |incoming_item| {
            for (items.items) |*item| {
                if (item.index != incoming_item.index) continue;
                const merged = try self.mergeValueDemand(item.demand.*, incoming_item.demand.*);
                item.demand = try self.pass.storedDemand(merged);
                break;
            } else {
                try items.append(self.pass.allocator, incoming_item);
            }
        }

        return .{ .tuple = try self.pass.arena.allocator().dupe(ItemDemand, items.items) };
    }

    fn mergeTagDemand(
        self: *Cloner,
        existing: []const TagAlternativeDemand,
        incoming: []const TagAlternativeDemand,
    ) LowerError![]const TagAlternativeDemand {
        var alternatives = std.ArrayList(TagAlternativeDemand).empty;
        defer alternatives.deinit(self.pass.allocator);
        try alternatives.appendSlice(self.pass.allocator, existing);

        for (incoming) |incoming_alternative| {
            for (alternatives.items) |*alternative| {
                if (!self.pass.program.names.tagLabelTextEql(alternative.name, incoming_alternative.name)) continue;
                const merged = try self.mergeTupleDemand(alternative.payloads, incoming_alternative.payloads);
                alternative.payloads = merged.tuple;
                break;
            } else {
                try alternatives.append(self.pass.allocator, incoming_alternative);
            }
        }

        return try self.pass.arena.allocator().dupe(TagAlternativeDemand, alternatives.items);
    }

    fn activeFunctionDemandMergeFrame(self: *Cloner, demand_ref: FunctionDemandSlotId) ?usize {
        const root_ref = self.canonicalFunctionDemandSlotId(demand_ref);
        var index = self.function_demand_merge_stack.items.len;
        while (index > 0) {
            index -= 1;
            if (functionDemandSlotIdEql(self.function_demand_merge_stack.items[index].root, root_ref)) return index;
        }
        return null;
    }

    fn queueFunctionDemandMergeInput(
        self: *Cloner,
        frame_index: usize,
        incoming: ValueDemand,
    ) Allocator.Error!void {
        const frame = &self.function_demand_merge_stack.items[frame_index];
        const slot = self.activeFunctionDemandSlot(frame.root);
        const current = if (slot.* == .fn_param and functionDemandSlotIdEql(slot.fn_param, frame.root)) .none else slot.*;
        if (try self.valueDemandEqlInActiveContext(current, incoming)) return;
        for (frame.extras.items) |extra| {
            if (try self.valueDemandEqlInActiveContext(extra, incoming)) return;
        }
        try frame.extras.append(self.pass.allocator, incoming);
    }

    fn mergeFunctionDemandInput(
        self: *Cloner,
        root_ref: FunctionDemandSlotId,
        incoming: ValueDemand,
    ) LowerError!void {
        const slot = self.activeFunctionDemandSlot(root_ref);
        const current = if (slot.* == .fn_param and functionDemandSlotIdEql(slot.fn_param, root_ref)) .none else slot.*;
        if (try self.valueDemandEqlInActiveContext(current, incoming)) return;
        slot.* = try self.mergeValueDemand(current, incoming);
        self.demand_cache_epoch += 1;
    }

    fn mergeFunctionDemandSlotId(self: *Cloner, demand_ref: FunctionDemandSlotId, incoming: ValueDemand) LowerError!FunctionDemandSlotId {
        const root_ref = self.canonicalFunctionDemandSlotId(demand_ref);
        if (incoming == .fn_param) return try self.mergeFunctionDemandSlotIds(root_ref, incoming.fn_param);

        if (self.activeFunctionDemandMergeFrame(root_ref)) |frame_index| {
            try self.queueFunctionDemandMergeInput(frame_index, incoming);
            return root_ref;
        }

        try self.function_demand_merge_stack.append(self.pass.allocator, .{
            .root = root_ref,
            .extras = .empty,
        });
        const frame_index = self.function_demand_merge_stack.items.len - 1;
        defer {
            self.function_demand_merge_stack.items[frame_index].extras.deinit(self.pass.allocator);
            _ = self.function_demand_merge_stack.pop();
        }

        try self.mergeFunctionDemandInput(root_ref, incoming);
        var extra_index: usize = 0;
        while (extra_index < self.function_demand_merge_stack.items[frame_index].extras.items.len) {
            if (extra_index > 1000) Common.invariant("function demand merge input queue did not converge");
            const extra = self.function_demand_merge_stack.items[frame_index].extras.items[extra_index];
            extra_index += 1;
            try self.mergeFunctionDemandInput(root_ref, extra);
        }

        return root_ref;
    }

    fn mergeFunctionDemandSlotIds(self: *Cloner, lhs: FunctionDemandSlotId, rhs: FunctionDemandSlotId) LowerError!FunctionDemandSlotId {
        const lhs_root = self.canonicalFunctionDemandSlotId(lhs);
        const rhs_root = self.canonicalFunctionDemandSlotId(rhs);
        if (functionDemandSlotIdEql(lhs_root, rhs_root)) return lhs_root;

        const root_ref = if (functionDemandSlotIdBefore(lhs_root, rhs_root)) lhs_root else rhs_root;
        const child_ref = if (functionDemandSlotIdBefore(lhs_root, rhs_root)) rhs_root else lhs_root;

        const root_slot = self.activeFunctionDemandSlot(root_ref);
        const child_slot = self.activeFunctionDemandSlot(child_ref);
        const root_demand = if (root_slot.* == .fn_param and functionDemandSlotIdEql(root_slot.fn_param, root_ref)) .none else root_slot.*;
        const child_demand = if (child_slot.* == .fn_param and functionDemandSlotIdEql(child_slot.fn_param, child_ref)) .none else child_slot.*;

        self.function_demand_nodes.items[child_ref.node].parent = root_ref.node;
        child_slot.* = .{ .fn_param = root_ref };
        root_slot.* = try self.mergeValueDemand(root_demand, child_demand);
        self.demand_cache_epoch += 1;

        return root_ref;
    }

    fn mergeLocalDemand(self: *Cloner, out: *ValueDemand, incoming: ValueDemand) LowerError!void {
        out.* = try self.mergeValueDemand(out.*, incoming);
    }

    fn demandAtPath(self: *Cloner, path: []const DemandPathStep, demand: ValueDemand) Allocator.Error!ValueDemand {
        if (demand == .none) return .none;

        var current = demand;
        var index = path.len;
        while (index > 0) {
            index -= 1;
            current = switch (path[index]) {
                .record_field => |field| try self.pass.demandRecordField(field, current),
                .tuple_item => |item_index| try self.pass.demandTupleItem(item_index, current),
                .tag_payload => |payload_path| blk: {
                    const payloads = try self.pass.arena.allocator().alloc(ItemDemand, 1);
                    payloads[0] = .{
                        .index = payload_path.index,
                        .demand = try self.pass.storedDemand(current),
                    };
                    const alternatives = try self.pass.arena.allocator().alloc(TagAlternativeDemand, 1);
                    alternatives[0] = .{
                        .name = payload_path.name,
                        .payloads = payloads,
                    };
                    break :blk ValueDemand{ .tag = .{ .alternatives = alternatives } };
                },
                .nominal_backing => ValueDemand{ .nominal = try self.pass.storedDemand(current) },
                .callable_capture => |capture_index| blk: {
                    const captures = try self.pass.arena.allocator().alloc(ValueDemand, @as(usize, capture_index) + 1);
                    @memset(captures, .none);
                    captures[@intCast(capture_index)] = current;
                    break :blk ValueDemand{ .callable = .{ .captures = captures } };
                },
            };
        }
        return current;
    }

    fn demandForSplitLocal(self: *Cloner, source_local: Ast.LocalId, expr_local: Ast.LocalId, context: ValueDemand) LowerError!ValueDemand {
        if (source_local == expr_local) return context;
        var demand: ValueDemand = .none;
        if (self.loop_stack.getLastOrNull()) |loop| {
            for (loop.provenance.items) |split_local| {
                if (split_local.local != expr_local or split_local.source_local != source_local) continue;
                demand = try self.mergeValueDemand(demand, try self.demandAtPath(split_local.path, context));
            }
            return demand;
        }
        if (self.state_loop_stack.getLastOrNull()) |state_loop| {
            for (state_loop.provenance.items) |split_local| {
                if (split_local.local != expr_local or split_local.source_local != source_local) continue;
                demand = try self.mergeValueDemand(demand, try self.demandAtPath(split_local.path, context));
            }
        }
        return demand;
    }

    fn splitLocalMayDemandLocal(self: *Cloner, source_local: Ast.LocalId, expr_local: Ast.LocalId) bool {
        if (self.loop_stack.getLastOrNull()) |loop| {
            for (loop.provenance.items) |split_local| {
                if (split_local.local == expr_local and split_local.source_local == source_local) return true;
            }
            return false;
        }
        if (self.state_loop_stack.getLastOrNull()) |state_loop| {
            for (state_loop.provenance.items) |split_local| {
                if (split_local.local == expr_local and split_local.source_local == source_local) return true;
            }
        }
        return false;
    }

    fn boundLocalMayDemandLocal(
        self: *Cloner,
        expr_local: Ast.LocalId,
        source_local: Ast.LocalId,
        visited: *std.ArrayList(Ast.LocalId),
    ) Allocator.Error!bool {
        if (expr_local == source_local) return true;

        for (visited.items) |seen| {
            if (seen == expr_local) return false;
        }
        try visited.append(self.pass.allocator, expr_local);
        defer _ = visited.pop();

        if (self.subst.get(expr_local)) |value| {
            if (try self.valueMayDemandLocalInCurrentContextSeen(value, source_local, visited)) return true;
        }

        return self.splitLocalMayDemandLocal(source_local, expr_local);
    }

    fn boundLocalMayDemandLocalInCurrentContext(self: *Cloner, expr_local: Ast.LocalId, source_local: Ast.LocalId) Allocator.Error!bool {
        var visited = std.ArrayList(Ast.LocalId).empty;
        defer visited.deinit(self.pass.allocator);
        return try self.boundLocalMayDemandLocal(expr_local, source_local, &visited);
    }

    fn exprSpanMayDemandLocalInCurrentContext(
        self: *Cloner,
        span: Ast.Span(Ast.ExprId),
        source_local: Ast.LocalId,
        visited: *std.ArrayList(Ast.LocalId),
    ) Allocator.Error!bool {
        for (self.pass.program.exprSpan(span)) |expr_id| {
            if (try self.exprMayDemandLocalInCurrentContextSeen(expr_id, source_local, visited)) return true;
        }
        return false;
    }

    fn fieldExprSpanMayDemandLocalInCurrentContext(
        self: *Cloner,
        span: Ast.Span(Ast.FieldExpr),
        source_local: Ast.LocalId,
        visited: *std.ArrayList(Ast.LocalId),
    ) Allocator.Error!bool {
        for (self.pass.program.fieldExprSpan(span)) |field| {
            if (try self.exprMayDemandLocalInCurrentContextSeen(field.value, source_local, visited)) return true;
        }
        return false;
    }

    fn stmtMayDemandLocalInCurrentContext(
        self: *Cloner,
        stmt_id: Ast.StmtId,
        source_local: Ast.LocalId,
        visited: *std.ArrayList(Ast.LocalId),
    ) Allocator.Error!bool {
        return switch (self.pass.program.stmts.items[@intFromEnum(stmt_id)]) {
            .let_ => |let_| try self.exprMayDemandLocalInCurrentContextSeen(let_.value, source_local, visited),
            .expr,
            .expect,
            .dbg,
            .return_,
            => |expr| try self.exprMayDemandLocalInCurrentContextSeen(expr, source_local, visited),
            .uninitialized,
            .crash,
            => false,
        };
    }

    fn stmtSpanMayDemandLocalInCurrentContext(
        self: *Cloner,
        span: Ast.Span(Ast.StmtId),
        source_local: Ast.LocalId,
        visited: *std.ArrayList(Ast.LocalId),
    ) Allocator.Error!bool {
        for (self.pass.program.stmtSpan(span)) |stmt_id| {
            if (try self.stmtMayDemandLocalInCurrentContext(stmt_id, source_local, visited)) return true;
        }
        return false;
    }

    fn fnRefMayDemandLocalInCurrentContext(
        self: *Cloner,
        fn_id: Ast.FnId,
        source_local: Ast.LocalId,
        visited: *std.ArrayList(Ast.LocalId),
    ) Allocator.Error!bool {
        const source_fn = self.pass.program.fns.items[@intFromEnum(fn_id)];
        for (self.pass.program.typedLocalSpan(source_fn.captures)) |capture| {
            if (try self.boundLocalMayDemandLocal(capture.local, source_local, visited)) return true;
        }
        return false;
    }

    fn exprMayDemandLocalInCurrentContext(self: *Cloner, expr_id: Ast.ExprId, source_local: Ast.LocalId) Allocator.Error!bool {
        var visited = std.ArrayList(Ast.LocalId).empty;
        defer visited.deinit(self.pass.allocator);
        return try self.exprMayDemandLocalInCurrentContextSeen(expr_id, source_local, &visited);
    }

    fn exprMayDemandLocalInCurrentContextSeen(
        self: *Cloner,
        expr_id: Ast.ExprId,
        source_local: Ast.LocalId,
        visited: *std.ArrayList(Ast.LocalId),
    ) Allocator.Error!bool {
        return switch (self.pass.program.exprs.items[@intFromEnum(expr_id)].data) {
            .local => |expr_local| try self.boundLocalMayDemandLocal(expr_local, source_local, visited),
            .unit,
            .int_lit,
            .frac_f32_lit,
            .frac_f64_lit,
            .dec_lit,
            .str_lit,
            .static_data,
            .def_ref,
            .fn_def,
            .crash,
            .comptime_exhaustiveness_failed,
            .uninitialized,
            .uninitialized_payload,
            => false,
            .fn_ref => |fn_id| try self.fnRefMayDemandLocalInCurrentContext(fn_id, source_local, visited),
            .fn_ref_captures => |fn_ref| try self.exprSpanMayDemandLocalInCurrentContext(fn_ref.captures, source_local, visited),
            .lambda => |lambda| blk: {
                for (self.pass.program.typedLocalSpan(lambda.args)) |arg| {
                    if (arg.local == source_local) break :blk false;
                }
                break :blk try self.exprMayDemandLocalInCurrentContextSeen(lambda.body, source_local, visited);
            },
            .static_data_candidate => |candidate| try self.exprMayDemandLocalInCurrentContextSeen(candidate.restored_expr, source_local, visited),
            .list,
            .tuple,
            => |items| try self.exprSpanMayDemandLocalInCurrentContext(items, source_local, visited),
            .record => |fields| try self.fieldExprSpanMayDemandLocalInCurrentContext(fields, source_local, visited),
            .tag => |tag| try self.exprSpanMayDemandLocalInCurrentContext(tag.payloads, source_local, visited),
            .nominal,
            .return_,
            .dbg,
            .expect,
            => |child| try self.exprMayDemandLocalInCurrentContextSeen(child, source_local, visited),
            .expect_err => |expect_err| try self.exprMayDemandLocalInCurrentContextSeen(expect_err.msg, source_local, visited),
            .comptime_branch_taken => |taken| try self.exprMayDemandLocalInCurrentContextSeen(taken.body, source_local, visited),
            .let_ => |let_| try self.exprMayDemandLocalInCurrentContextSeen(let_.value, source_local, visited) or
                try self.exprMayDemandLocalInCurrentContextSeen(let_.rest, source_local, visited),
            .call_value => |call| try self.exprMayDemandLocalInCurrentContextSeen(call.callee, source_local, visited) or
                try self.exprSpanMayDemandLocalInCurrentContext(call.args, source_local, visited),
            .call_proc => |call| try self.exprSpanMayDemandLocalInCurrentContext(call.args, source_local, visited),
            .low_level => |call| try self.exprSpanMayDemandLocalInCurrentContext(call.args, source_local, visited),
            .field_access => |field| try self.exprMayDemandLocalInCurrentContextSeen(field.receiver, source_local, visited),
            .tuple_access => |access| try self.exprMayDemandLocalInCurrentContextSeen(access.tuple, source_local, visited),
            .structural_eq => |eq| try self.exprMayDemandLocalInCurrentContextSeen(eq.lhs, source_local, visited) or
                try self.exprMayDemandLocalInCurrentContextSeen(eq.rhs, source_local, visited),
            .structural_hash => |hash| try self.exprMayDemandLocalInCurrentContextSeen(hash.value, source_local, visited) or
                try self.exprMayDemandLocalInCurrentContextSeen(hash.hasher, source_local, visited),
            .match_ => |match| blk: {
                if (try self.exprMayDemandLocalInCurrentContextSeen(match.scrutinee, source_local, visited)) break :blk true;
                for (self.pass.program.branchSpan(match.branches)) |branch| {
                    if (branch.guard) |guard| {
                        if (try self.exprMayDemandLocalInCurrentContextSeen(guard, source_local, visited)) break :blk true;
                    }
                    if (try self.exprMayDemandLocalInCurrentContextSeen(branch.body, source_local, visited)) break :blk true;
                }
                break :blk false;
            },
            .if_ => |if_| blk: {
                for (self.pass.program.ifBranchSpan(if_.branches)) |branch| {
                    if (try self.exprMayDemandLocalInCurrentContextSeen(branch.cond, source_local, visited) or
                        try self.exprMayDemandLocalInCurrentContextSeen(branch.body, source_local, visited))
                    {
                        break :blk true;
                    }
                }
                break :blk try self.exprMayDemandLocalInCurrentContextSeen(if_.final_else, source_local, visited);
            },
            .block => |block| try self.stmtSpanMayDemandLocalInCurrentContext(block.statements, source_local, visited) or
                try self.exprMayDemandLocalInCurrentContextSeen(block.final_expr, source_local, visited),
            .loop_ => |loop| try self.exprSpanMayDemandLocalInCurrentContext(loop.initial_values, source_local, visited) or
                try self.exprMayDemandLocalInCurrentContextSeen(loop.body, source_local, visited),
            .state_loop => |state_loop| blk: {
                if (try self.exprSpanMayDemandLocalInCurrentContext(state_loop.entry_values, source_local, visited)) break :blk true;
                for (self.pass.program.stateLoopStateSpan(state_loop.states)) |state| {
                    if (try self.exprMayDemandLocalInCurrentContextSeen(state.body, source_local, visited)) break :blk true;
                }
                break :blk false;
            },
            .break_ => |maybe| if (maybe) |value|
                try self.exprMayDemandLocalInCurrentContextSeen(value, source_local, visited)
            else
                false,
            .continue_ => |continue_| try self.exprSpanMayDemandLocalInCurrentContext(continue_.values, source_local, visited),
            .state_continue => |continue_| try self.exprSpanMayDemandLocalInCurrentContext(continue_.values, source_local, visited),
            .if_initialized_payload => |payload_switch| try self.exprMayDemandLocalInCurrentContextSeen(payload_switch.cond, source_local, visited) or
                payload_switch.payload == source_local or
                try self.exprMayDemandLocalInCurrentContextSeen(payload_switch.initialized, source_local, visited) or
                try self.exprMayDemandLocalInCurrentContextSeen(payload_switch.uninitialized, source_local, visited),
            .try_sequence => |sequence| try self.exprMayDemandLocalInCurrentContextSeen(sequence.try_expr, source_local, visited) or
                if (sequence.ok_local == source_local) false else try self.exprMayDemandLocalInCurrentContextSeen(sequence.ok_body, source_local, visited),
            .try_record_sequence => |sequence| try self.exprMayDemandLocalInCurrentContextSeen(sequence.try_expr, source_local, visited) or
                if (sequence.value_local == source_local or sequence.rest_local == source_local)
                    false
                else
                    try self.exprMayDemandLocalInCurrentContextSeen(sequence.ok_body, source_local, visited),
        };
    }

    fn valueMayDemandLocalInCurrentContext(
        self: *Cloner,
        value: Value,
        source_local: Ast.LocalId,
    ) Allocator.Error!bool {
        var visited = std.ArrayList(Ast.LocalId).empty;
        defer visited.deinit(self.pass.allocator);
        return try self.valueMayDemandLocalInCurrentContextSeen(value, source_local, &visited);
    }

    fn valueMayDemandLocalInCurrentContextSeen(
        self: *Cloner,
        value: Value,
        source_local: Ast.LocalId,
        visited: *std.ArrayList(Ast.LocalId),
    ) Allocator.Error!bool {
        return switch (value) {
            .expr => |expr| try self.exprMayDemandLocalInCurrentContextSeen(expr, source_local, visited),
            .expr_with_known_value => |known| try self.exprMayDemandLocalInCurrentContextSeen(known.expr, source_local, visited) or
                if (known.value) |structured|
                    try self.valueMayDemandLocalInCurrentContextSeen(structured.*, source_local, visited)
                else
                    false,
            .let_ => |let_value| blk: {
                for (let_value.lets) |pending| {
                    const expr = switch (pending.value) {
                        .source => |source| source,
                        .cloned => |cloned| cloned,
                    };
                    if (try self.exprMayDemandLocalInCurrentContextSeen(expr, source_local, visited)) break :blk true;
                }
                break :blk try self.valueMayDemandLocalInCurrentContextSeen(let_value.body.*, source_local, visited);
            },
            .if_ => |if_value| blk: {
                for (if_value.branches) |branch| {
                    if (try self.exprMayDemandLocalInCurrentContextSeen(branch.cond, source_local, visited) or
                        try self.valueMayDemandLocalInCurrentContextSeen(branch.body, source_local, visited))
                    {
                        break :blk true;
                    }
                }
                break :blk try self.valueMayDemandLocalInCurrentContextSeen(if_value.final_else.*, source_local, visited);
            },
            .match_ => |match_value| blk: {
                if (try self.exprMayDemandLocalInCurrentContextSeen(match_value.scrutinee, source_local, visited)) break :blk true;
                for (match_value.branches) |branch| {
                    if (branch.guard) |guard| {
                        if (try self.exprMayDemandLocalInCurrentContextSeen(guard, source_local, visited)) break :blk true;
                    }
                    if (try self.valueMayDemandLocalInCurrentContextSeen(branch.body, source_local, visited)) break :blk true;
                }
                break :blk false;
            },
            .tag => |tag| blk: {
                for (tag.payloads) |payload| {
                    if (try self.valueMayDemandLocalInCurrentContextSeen(payload, source_local, visited)) break :blk true;
                }
                break :blk false;
            },
            .record => |record| blk: {
                for (record.fields) |field| {
                    if (try self.valueMayDemandLocalInCurrentContextSeen(field.value, source_local, visited)) break :blk true;
                }
                break :blk false;
            },
            .tuple => |tuple| blk: {
                for (tuple.items) |item| {
                    if (try self.valueMayDemandLocalInCurrentContextSeen(item, source_local, visited)) break :blk true;
                }
                break :blk false;
            },
            .nominal => |nominal| try self.valueMayDemandLocalInCurrentContextSeen(nominal.backing.*, source_local, visited),
            .callable => |callable| blk: {
                for (callable.captures) |capture| {
                    if (try self.valueMayDemandLocalInCurrentContextSeen(capture, source_local, visited)) break :blk true;
                }
                break :blk false;
            },
            .finite_tags => |finite_tags| blk: {
                if (try self.exprMayDemandLocalInCurrentContextSeen(finite_tags.selector, source_local, visited)) break :blk true;
                for (finite_tags.alternatives) |alternative| {
                    for (alternative.payloads) |payload| {
                        if (try self.valueMayDemandLocalInCurrentContextSeen(payload, source_local, visited)) break :blk true;
                    }
                }
                break :blk false;
            },
            .finite_callables => |finite_callables| blk: {
                if (try self.exprMayDemandLocalInCurrentContextSeen(finite_callables.selector, source_local, visited)) break :blk true;
                for (finite_callables.alternatives) |alternative| {
                    for (alternative.captures) |capture| {
                        if (try self.valueMayDemandLocalInCurrentContextSeen(capture, source_local, visited)) break :blk true;
                    }
                }
                break :blk false;
            },
            .private_state => |private_state| try self.privateStateMayDemandLocalInCurrentContextSeen(private_state, source_local, visited),
        };
    }

    fn privateStateMayDemandLocalInCurrentContextSeen(
        self: *Cloner,
        value: PrivateStateValue,
        source_local: Ast.LocalId,
        visited: *std.ArrayList(Ast.LocalId),
    ) Allocator.Error!bool {
        return switch (value) {
            .leaf => |leaf| try self.exprMayDemandLocalInCurrentContextSeen(leaf.expr, source_local, visited),
            .tag => |tag| blk: {
                for (tag.payloads) |payload| {
                    if (try self.privateStateMayDemandLocalInCurrentContextSeen(payload.value, source_local, visited)) break :blk true;
                }
                break :blk false;
            },
            .record => |record| blk: {
                for (record.fields) |field| {
                    if (try self.privateStateMayDemandLocalInCurrentContextSeen(field.value, source_local, visited)) break :blk true;
                }
                break :blk false;
            },
            .tuple => |tuple| blk: {
                for (tuple.items) |item| {
                    if (try self.privateStateMayDemandLocalInCurrentContextSeen(item.value, source_local, visited)) break :blk true;
                }
                break :blk false;
            },
            .nominal => |nominal| if (nominal.backing) |backing|
                try self.privateStateMayDemandLocalInCurrentContextSeen(backing.*, source_local, visited)
            else
                false,
            .callable => |callable| blk: {
                for (callable.captures) |capture| {
                    if (try self.privateStateMayDemandLocalInCurrentContextSeen(capture.value, source_local, visited)) break :blk true;
                }
                break :blk false;
            },
            .compact_finite_tags => |finite_tags| try self.exprMayDemandLocalInCurrentContextSeen(finite_tags.compact_expr, source_local, visited),
            .compact_finite_callables => |finite_callables| try self.exprMayDemandLocalInCurrentContextSeen(finite_callables.compact_expr, source_local, visited),
        };
    }

    fn loopProvenanceLen(self: *Cloner) ?usize {
        const loop = self.loop_stack.getLastOrNull() orelse return null;
        return loop.provenance.items.len;
    }

    fn restoreLoopProvenance(self: *Cloner, mark: ?usize) void {
        const len = mark orelse return;
        const loop = self.loop_stack.getLastOrNull() orelse return;
        loop.provenance.shrinkRetainingCapacity(len);
    }

    fn appendDemandPath(path: *std.ArrayList(DemandPathStep), allocator: Allocator, steps: []const DemandPathStep) Allocator.Error!void {
        try path.appendSlice(allocator, steps);
    }

    fn loopDemandPathForExpr(
        self: *Cloner,
        source_local: Ast.LocalId,
        expr_id: Ast.ExprId,
        path: *std.ArrayList(DemandPathStep),
    ) Allocator.Error!bool {
        const expr = self.pass.program.exprs.items[@intFromEnum(expr_id)];
        switch (expr.data) {
            .local => |expr_local| {
                if (expr_local == source_local) return true;
                const loop = self.loop_stack.getLastOrNull() orelse return false;
                for (loop.provenance.items) |provenance| {
                    if (provenance.local != expr_local or provenance.source_local != source_local) continue;
                    try appendDemandPath(path, self.pass.allocator, provenance.path);
                    return true;
                }
                return false;
            },
            .field_access => |field| {
                if (!try self.loopDemandPathForExpr(source_local, field.receiver, path)) return false;
                try path.append(self.pass.allocator, .{ .record_field = field.field });
                return true;
            },
            .tuple_access => |access| {
                if (!try self.loopDemandPathForExpr(source_local, access.tuple, path)) return false;
                try path.append(self.pass.allocator, .{ .tuple_item = access.elem_index });
                return true;
            },
            .comptime_branch_taken => |taken| return try self.loopDemandPathForExpr(source_local, taken.body, path),
            else => return false,
        }
    }

    fn appendLoopAliasForExpr(self: *Cloner, alias_local: Ast.LocalId, expr_id: Ast.ExprId) Allocator.Error!void {
        const loop = self.loop_stack.getLastOrNull() orelse return;
        for (loop.params) |param| {
            var path = std.ArrayList(DemandPathStep).empty;
            defer path.deinit(self.pass.allocator);
            if (!try self.loopDemandPathForExpr(param.local, expr_id, &path)) continue;
            try self.appendLoopSplitLocal(loop.provenance, alias_local, param.local, path.items);
        }
    }

    fn valueIsExpr(value: Value, expr_id: Ast.ExprId) bool {
        return switch (value) {
            .expr => |value_expr| value_expr == expr_id,
            .expr_with_known_value => |known_value_expr| known_value_expr.expr == expr_id,
            else => false,
        };
    }

    fn mergeLocalDemandInPrivateStateValue(
        self: *Cloner,
        local: Ast.LocalId,
        value: PrivateStateValue,
        context: ValueDemand,
        out: *ValueDemand,
    ) LowerError!void {
        var path = std.ArrayList(DemandPathStep).empty;
        defer path.deinit(self.pass.allocator);
        return self.mergeLocalDemandInPrivateStateValueAtPath(local, null, value, context, &path, out);
    }

    fn mergeProjectedPrivateStateDemand(
        self: *Cloner,
        local: Ast.LocalId,
        subst_local: ?Ast.LocalId,
        path: []const DemandPathStep,
        demand: ValueDemand,
        out: *ValueDemand,
    ) LowerError!void {
        const source = subst_local orelse return;
        const path_demand = try self.demandAtPath(path, demand);
        const split_demand = try self.demandForSplitLocal(local, source, path_demand);
        try self.mergeLocalDemand(out, split_demand);
    }

    fn mergeLocalDemandInPrivateStateValueAtPath(
        self: *Cloner,
        local: Ast.LocalId,
        subst_local: ?Ast.LocalId,
        value: PrivateStateValue,
        context: ValueDemand,
        path: *std.ArrayList(DemandPathStep),
        out: *ValueDemand,
    ) LowerError!void {
        switch (value) {
            .leaf => |leaf| try self.mergeLocalDemandInExpr(local, leaf.expr, context, out),
            .record => |record| {
                switch (self.decompositionDemand(context)) {
                    .record => |field_demands| {
                        for (field_demands) |field_demand| {
                            try path.append(self.pass.allocator, .{ .record_field = field_demand.name });
                            defer _ = path.pop();
                            const field_value = privateStateFieldByName(self.pass.program, record.fields, field_demand.name) orelse {
                                try self.mergeProjectedPrivateStateDemand(local, subst_local, path.items, field_demand.demand.*, out);
                                continue;
                            };
                            try self.mergeLocalDemandInPrivateStateValueAtPath(local, subst_local, field_value, field_demand.demand.*, path, out);
                        }
                    },
                    .none => {},
                    else => for (record.fields) |field| {
                        try path.append(self.pass.allocator, .{ .record_field = field.name });
                        defer _ = path.pop();
                        try self.mergeLocalDemandInPrivateStateValueAtPath(local, subst_local, field.value, .materialize, path, out);
                    },
                }
            },
            .tuple => |tuple| {
                switch (self.decompositionDemand(context)) {
                    .tuple => |item_demands| {
                        for (item_demands) |item_demand| {
                            try path.append(self.pass.allocator, .{ .tuple_item = item_demand.index });
                            defer _ = path.pop();
                            const item_value = privateStateIndexedValueByIndex(tuple.items, item_demand.index) orelse {
                                try self.mergeProjectedPrivateStateDemand(local, subst_local, path.items, item_demand.demand.*, out);
                                continue;
                            };
                            try self.mergeLocalDemandInPrivateStateValueAtPath(local, subst_local, item_value, item_demand.demand.*, path, out);
                        }
                    },
                    .none => {},
                    else => for (tuple.items) |item| {
                        try path.append(self.pass.allocator, .{ .tuple_item = item.index });
                        defer _ = path.pop();
                        try self.mergeLocalDemandInPrivateStateValueAtPath(local, subst_local, item.value, .materialize, path, out);
                    },
                }
            },
            .tag => |tag| {
                switch (self.decompositionDemand(context)) {
                    .tag => |tag_demand| {
                        if (tagAlternativeDemandByName(self.pass.program, tag_demand.alternatives, tag.name)) |alternative_demand| {
                            for (alternative_demand.payloads) |payload_demand| {
                                try path.append(self.pass.allocator, .{ .tag_payload = .{
                                    .name = tag.name,
                                    .index = payload_demand.index,
                                } });
                                defer _ = path.pop();
                                const payload = privateStateIndexedValueByIndex(tag.payloads, payload_demand.index) orelse {
                                    try self.mergeProjectedPrivateStateDemand(local, subst_local, path.items, payload_demand.demand.*, out);
                                    continue;
                                };
                                try self.mergeLocalDemandInPrivateStateValueAtPath(local, subst_local, payload, payload_demand.demand.*, path, out);
                            }
                        }
                    },
                    .none => {},
                    else => for (tag.payloads) |payload| {
                        try path.append(self.pass.allocator, .{ .tag_payload = .{
                            .name = tag.name,
                            .index = payload.index,
                        } });
                        defer _ = path.pop();
                        try self.mergeLocalDemandInPrivateStateValueAtPath(local, subst_local, payload.value, .materialize, path, out);
                    },
                }
            },
            .nominal => |nominal| {
                const resolved_context = self.decompositionDemand(context);
                const backing_context = switch (resolved_context) {
                    .nominal => |nominal_demand| nominal_demand.*,
                    else => resolved_context,
                };
                try path.append(self.pass.allocator, .nominal_backing);
                defer _ = path.pop();
                const backing = nominal.backing orelse {
                    try self.mergeProjectedPrivateStateDemand(local, subst_local, path.items, backing_context, out);
                    return;
                };
                try self.mergeLocalDemandInPrivateStateValueAtPath(local, subst_local, backing.*, backing_context, path, out);
            },
            .callable => |callable| {
                switch (self.decompositionDemand(context)) {
                    .callable => |callable_demand| {
                        var effective_context = ValueDemand{ .callable = callable_demand };
                        if (callable_demand.result) |result_demand| {
                            const derived = try self.callableDemandForPrivateStateCallableWithResultDemand(callable, result_demand.*);
                            effective_context = try self.mergeValueDemand(effective_context, derived);
                        }
                        if (effective_context != .callable) Common.invariant("private callable demand merge produced non-callable demand");
                        const source_fn = self.pass.program.fns.items[@intFromEnum(callable.fn_id)];
                        const source_captures = self.pass.program.typedLocalSpan(source_fn.captures);
                        for (source_captures, 0..) |_, index| {
                            const capture_demand = callableCaptureDemandForPreservedValue(effective_context.callable, index);
                            if (capture_demand == .none) continue;
                            try path.append(self.pass.allocator, .{ .callable_capture = @intCast(index) });
                            defer _ = path.pop();
                            const capture = privateStateIndexedValueByIndex(callable.captures, @intCast(index)) orelse {
                                try self.mergeProjectedPrivateStateDemand(local, subst_local, path.items, capture_demand, out);
                                continue;
                            };
                            try self.mergeLocalDemandInPrivateStateValueAtPath(local, subst_local, capture, capture_demand, path, out);
                        }
                    },
                    .none => {},
                    else => for (callable.captures) |capture| {
                        try path.append(self.pass.allocator, .{ .callable_capture = capture.index });
                        defer _ = path.pop();
                        try self.mergeLocalDemandInPrivateStateValueAtPath(local, subst_local, capture.value, .materialize, path, out);
                    },
                }
            },
            .compact_finite_tags => |finite_tags| {
                switch (self.decompositionDemand(context)) {
                    .tag => |tag_demand| {
                        for (tag_demand.alternatives) |alternative_demand| {
                            for (alternative_demand.payloads) |payload_demand| {
                                try path.append(self.pass.allocator, .{ .tag_payload = .{
                                    .name = alternative_demand.name,
                                    .index = payload_demand.index,
                                } });
                                defer _ = path.pop();
                                try self.mergeProjectedPrivateStateDemand(local, subst_local, path.items, payload_demand.demand.*, out);
                            }
                        }
                    },
                    .none => {},
                    else => try self.mergeLocalDemandInExpr(local, finite_tags.compact_expr, .materialize, out),
                }
            },
            .compact_finite_callables => |finite_callables| {
                switch (self.decompositionDemand(context)) {
                    .callable => |callable_demand| {
                        for (finite_callables.source.alternatives) |alternative| {
                            var effective_context = ValueDemand{ .callable = callable_demand };
                            if (callable_demand.result) |result_demand| {
                                const source_fn = self.pass.program.fns.items[@intFromEnum(alternative.fn_id)];
                                const source_captures = self.pass.program.typedLocalSpan(source_fn.captures);
                                const derived = try self.callableDemandForFnWithResultDemand(
                                    alternative.fn_id,
                                    source_captures.len,
                                    result_demand.*,
                                );
                                effective_context = try self.mergeValueDemand(effective_context, derived);
                            }
                            if (effective_context != .callable) Common.invariant("compact finite callable demand merge produced non-callable demand");

                            for (effective_context.callable.captures, 0..) |capture_demand, capture_index| {
                                if (capture_demand == .none) continue;
                                try path.append(self.pass.allocator, .{ .callable_capture = @intCast(capture_index) });
                                defer _ = path.pop();
                                try self.mergeProjectedPrivateStateDemand(local, subst_local, path.items, capture_demand, out);
                            }
                        }
                    },
                    .none => {},
                    else => try self.mergeLocalDemandInExpr(local, finite_callables.compact_expr, .materialize, out),
                }
            },
        }
    }

    fn mergeLocalDemandInSubstValue(
        self: *Cloner,
        local: Ast.LocalId,
        subst_local: Ast.LocalId,
        value: Value,
        context: ValueDemand,
        out: *ValueDemand,
    ) LowerError!void {
        switch (value) {
            .private_state => |private_state| {
                var path = std.ArrayList(DemandPathStep).empty;
                defer path.deinit(self.pass.allocator);
                try self.mergeLocalDemandInPrivateStateValueAtPath(local, subst_local, private_state, context, &path, out);
            },
            else => try self.mergeLocalDemandInValue(local, value, context, out),
        }
    }

    fn mergeLocalDemandInCapturedLocal(
        self: *Cloner,
        local: Ast.LocalId,
        capture: Ast.TypedLocal,
        context: ValueDemand,
        out: *ValueDemand,
    ) LowerError!void {
        if (context == .none) return;

        if (capture.local == local) {
            try self.mergeLocalDemand(out, context);
            return;
        }

        if (self.subst.get(capture.local)) |value| {
            try self.mergeLocalDemandInSubstValue(local, capture.local, value, context, out);
        }

        try self.mergeLocalDemand(out, try self.demandForSplitLocal(local, capture.local, context));
    }

    fn mergeLocalDemandInPendingLetValue(
        self: *Cloner,
        local: Ast.LocalId,
        value: PendingLetValue,
        context: ValueDemand,
        out: *ValueDemand,
    ) LowerError!void {
        const expr = switch (value) {
            .source => |expr| expr,
            .cloned => |expr| expr,
        };
        try self.mergeLocalDemandInExpr(local, expr, context, out);
    }

    fn mergeLocalDemandInValue(
        self: *Cloner,
        local: Ast.LocalId,
        value: Value,
        context: ValueDemand,
        out: *ValueDemand,
    ) LowerError!void {
        switch (value) {
            .expr => |expr_id| try self.mergeLocalDemandInExpr(local, expr_id, context, out),
            .expr_with_known_value => |known_value_expr| {
                if (known_value_expr.value) |structured_value| {
                    try self.mergeLocalDemandInValue(local, structured_value.*, context, out);
                } else {
                    try self.mergeLocalDemandInExpr(local, known_value_expr.expr, context, out);
                }
            },
            .let_ => |let_value| {
                for (let_value.lets) |pending| try self.mergeLocalDemandInPendingLetValue(local, pending.value, .materialize, out);
                try self.mergeLocalDemandInValue(local, let_value.body.*, context, out);
            },
            .if_ => |if_value| {
                for (if_value.branches) |branch| {
                    try self.mergeLocalDemandInExpr(local, branch.cond, .materialize, out);
                    try self.mergeLocalDemandInValue(local, branch.body, context, out);
                }
                try self.mergeLocalDemandInValue(local, if_value.final_else.*, context, out);
            },
            .match_ => |match_value| {
                try self.mergeLocalDemandInExpr(local, match_value.scrutinee, try self.matchValueScrutineeDemand(match_value.branches, context), out);
                for (match_value.branches) |branch| {
                    if (branch.guard) |guard| try self.mergeLocalDemandInExpr(local, guard, .materialize, out);
                    try self.mergeLocalDemandInValue(local, branch.body, context, out);
                }
            },
            .tag => |tag| {
                switch (self.decompositionDemand(context)) {
                    .tag => |tag_demand| {
                        if (tagAlternativeDemandByName(self.pass.program, tag_demand.alternatives, tag.name)) |alternative_demand| {
                            for (alternative_demand.payloads) |payload_demand| {
                                if (payload_demand.index >= tag.payloads.len) continue;
                                try self.mergeLocalDemandInValue(local, tag.payloads[payload_demand.index], payload_demand.demand.*, out);
                            }
                        }
                    },
                    .none => {},
                    else => for (tag.payloads) |payload| try self.mergeLocalDemandInValue(local, payload, .materialize, out),
                }
            },
            .record => |record| {
                switch (self.decompositionDemand(context)) {
                    .record => |field_demands| {
                        for (field_demands) |field_demand| {
                            const field_value = fieldValueByName(self.pass.program, record.fields, field_demand.name) orelse continue;
                            try self.mergeLocalDemandInValue(local, field_value, field_demand.demand.*, out);
                        }
                    },
                    .none => {},
                    else => for (record.fields) |field| try self.mergeLocalDemandInValue(local, field.value, .materialize, out),
                }
            },
            .tuple => |tuple| {
                switch (self.decompositionDemand(context)) {
                    .tuple => |item_demands| {
                        for (item_demands) |item_demand| {
                            if (item_demand.index >= tuple.items.len) continue;
                            try self.mergeLocalDemandInValue(local, tuple.items[item_demand.index], item_demand.demand.*, out);
                        }
                    },
                    .none => {},
                    else => for (tuple.items) |item| try self.mergeLocalDemandInValue(local, item, .materialize, out),
                }
            },
            .nominal => |nominal| {
                const resolved_context = self.decompositionDemand(context);
                try self.mergeLocalDemandInValue(local, nominal.backing.*, switch (resolved_context) {
                    .nominal => |nominal_demand| nominal_demand.*,
                    else => resolved_context,
                }, out);
            },
            .callable => |callable| {
                switch (self.decompositionDemand(context)) {
                    .callable => |callable_demand| {
                        var effective_context = ValueDemand{ .callable = callable_demand };
                        if (callable_demand.result) |result_demand| {
                            const derived = try self.callableDemandForCallableValueWithResultDemand(callable, result_demand.*);
                            effective_context = try self.mergeValueDemand(effective_context, derived);
                        }
                        if (effective_context != .callable) Common.invariant("callable demand merge produced non-callable demand");

                        for (callable.captures, 0..) |capture, index| {
                            const capture_demand = callableCaptureDemandForPreservedValue(effective_context.callable, index);
                            if (capture_demand == .none) continue;
                            try self.mergeLocalDemandInValue(local, capture, capture_demand, out);
                        }
                    },
                    .none => {},
                    else => for (callable.captures) |capture| try self.mergeLocalDemandInValue(local, capture, .materialize, out),
                }
            },
            .finite_tags => |finite_tags| {
                try self.mergeLocalDemandInExpr(local, finite_tags.selector, .materialize, out);
                switch (self.decompositionDemand(context)) {
                    .tag => |tag_demand| {
                        for (finite_tags.alternatives) |alternative| {
                            const alternative_demand = tagAlternativeDemandByName(self.pass.program, tag_demand.alternatives, alternative.name) orelse continue;
                            for (alternative_demand.payloads) |payload_demand| {
                                if (payload_demand.index >= alternative.payloads.len) continue;
                                try self.mergeLocalDemandInValue(local, alternative.payloads[payload_demand.index], payload_demand.demand.*, out);
                            }
                        }
                    },
                    .none => {},
                    else => for (finite_tags.alternatives) |alternative| {
                        for (alternative.payloads) |payload| try self.mergeLocalDemandInValue(local, payload, .materialize, out);
                    },
                }
            },
            .finite_callables => |finite_callables| {
                try self.mergeLocalDemandInExpr(local, finite_callables.selector, .materialize, out);
                switch (self.decompositionDemand(context)) {
                    .callable => |callable_demand| {
                        for (finite_callables.alternatives) |alternative| {
                            var effective_context = ValueDemand{ .callable = callable_demand };
                            if (callable_demand.result) |result_demand| {
                                const derived = try self.callableDemandForFnWithResultDemand(
                                    alternative.fn_id,
                                    alternative.captures.len,
                                    result_demand.*,
                                );
                                effective_context = try self.mergeValueDemand(effective_context, derived);
                            }
                            if (effective_context != .callable) Common.invariant("finite callable demand merge produced non-callable demand");

                            for (alternative.captures, 0..) |capture, index| {
                                const capture_demand = callableCaptureDemandForPreservedValue(effective_context.callable, index);
                                if (capture_demand == .none) continue;
                                try self.mergeLocalDemandInValue(local, capture, capture_demand, out);
                            }
                        }
                    },
                    .none => {},
                    else => for (finite_callables.alternatives) |alternative| {
                        for (alternative.captures) |capture| try self.mergeLocalDemandInValue(local, capture, .materialize, out);
                    },
                }
            },
            .private_state => |private_state| try self.mergeLocalDemandInPrivateStateValue(local, private_state, context, out),
        }
    }

    fn mergeLocalDemandInExpr(
        self: *Cloner,
        local: Ast.LocalId,
        expr_id: Ast.ExprId,
        context: ValueDemand,
        out: *ValueDemand,
    ) LowerError!void {
        if (context == .none) return;
        for (self.local_demand_stack.items) |frame| {
            if (frame.local == local and frame.expr == expr_id and try self.valueDemandEqlInActiveContext(frame.context, context)) return;
        }
        if (self.local_demand_stack.items.len > 200) {
            Common.invariant("local demand recursion did not converge");
        }
        try self.local_demand_stack.append(self.pass.allocator, .{
            .local = local,
            .expr = expr_id,
            .context = context,
        });
        defer _ = self.local_demand_stack.pop();

        const expr = self.pass.program.exprs.items[@intFromEnum(expr_id)];
        switch (expr.data) {
            .local => |expr_local| {
                if (expr_local == local) {
                    try self.mergeLocalDemand(out, context);
                    return;
                }
                if (self.subst.get(expr_local)) |value| {
                    if (!valueIsExpr(value, expr_id)) {
                        try self.mergeLocalDemandInSubstValue(local, expr_local, value, context, out);
                    }
                }
                const split_demand = try self.demandForSplitLocal(local, expr_local, context);
                try self.mergeLocalDemand(out, split_demand);
            },
            .field_access => |field| {
                try self.mergeLocalDemandInExpr(
                    local,
                    field.receiver,
                    try self.pass.demandRecordField(field.field, context),
                    out,
                );
            },
            .tuple_access => |access| {
                try self.mergeLocalDemandInExpr(
                    local,
                    access.tuple,
                    try self.pass.demandTupleItem(access.elem_index, context),
                    out,
                );
            },
            .continue_ => |continue_| {
                for (self.pass.program.exprSpan(continue_.values), 0..) |value, index| {
                    try self.mergeLocalDemandInExpr(local, value, try self.continueValueDemand(index), out);
                }
            },
            .state_continue => |continue_| {
                for (self.pass.program.exprSpan(continue_.values), 0..) |value, index| {
                    try self.mergeLocalDemandInExpr(local, value, try self.continueValueDemand(index), out);
                }
            },
            .let_ => |let_| {
                const value_demand = try self.patternDemandInExpr(let_.bind, let_.rest, context);
                try self.mergeLocalDemandInExpr(local, let_.value, value_demand, out);
                try self.mergeLocalDemandInExpr(local, let_.rest, context, out);
            },
            .block => |block| {
                const statements = self.pass.program.stmtSpan(block.statements);
                for (statements, 0..) |stmt, index| {
                    try self.mergeLocalDemandInStmtTail(local, stmt, .{
                        .statements = statements[index + 1 ..],
                        .final_expr = block.final_expr,
                    }, context, out);
                }
                try self.mergeLocalDemandInExpr(local, block.final_expr, context, out);
            },
            .if_ => |if_| {
                for (self.pass.program.ifBranchSpan(if_.branches)) |branch| {
                    try self.mergeLocalDemandInExpr(local, branch.cond, .materialize, out);
                    try self.mergeLocalDemandInExpr(local, branch.body, context, out);
                }
                try self.mergeLocalDemandInExpr(local, if_.final_else, context, out);
            },
            .match_ => |match| {
                try self.mergeLocalDemandInExpr(local, match.scrutinee, try self.matchScrutineeDemand(match.branches, context), out);
                for (self.pass.program.branchSpan(match.branches)) |branch| {
                    if (branch.guard) |guard| try self.mergeLocalDemandInExpr(local, guard, .materialize, out);
                    try self.mergeLocalDemandInExpr(local, branch.body, context, out);
                }
            },
            .list,
            => |items| {
                for (self.pass.program.exprSpan(items)) |item| try self.mergeLocalDemandInExpr(local, item, .materialize, out);
            },
            .tuple => |items_span| {
                const items = self.pass.program.exprSpan(items_span);
                switch (self.decompositionDemand(context)) {
                    .tuple => |item_demands| {
                        for (item_demands) |item_demand| {
                            if (item_demand.index >= items.len) continue;
                            try self.mergeLocalDemandInExpr(local, items[item_demand.index], item_demand.demand.*, out);
                        }
                    },
                    .none => {},
                    else => for (items) |item| try self.mergeLocalDemandInExpr(local, item, .materialize, out),
                }
            },
            .record => |fields| {
                const source_fields = self.pass.program.fieldExprSpan(fields);
                switch (self.decompositionDemand(context)) {
                    .record => |field_demands| {
                        for (field_demands) |field_demand| {
                            for (source_fields) |field| {
                                if (!self.pass.program.names.recordFieldLabelTextEql(field.name, field_demand.name)) continue;
                                try self.mergeLocalDemandInExpr(local, field.value, field_demand.demand.*, out);
                                break;
                            }
                        }
                    },
                    .none => {},
                    else => for (source_fields) |field| try self.mergeLocalDemandInExpr(local, field.value, .materialize, out),
                }
            },
            .tag => |tag| {
                const payloads = self.pass.program.exprSpan(tag.payloads);
                switch (self.decompositionDemand(context)) {
                    .tag => |tag_demand| {
                        if (tagAlternativeDemandByName(self.pass.program, tag_demand.alternatives, tag.name)) |alternative_demand| {
                            for (alternative_demand.payloads) |payload_demand| {
                                if (payload_demand.index >= payloads.len) continue;
                                try self.mergeLocalDemandInExpr(local, payloads[payload_demand.index], payload_demand.demand.*, out);
                            }
                        }
                    },
                    .none => {},
                    else => for (payloads) |payload| try self.mergeLocalDemandInExpr(local, payload, .materialize, out),
                }
            },
            .nominal,
            .return_,
            .dbg,
            .expect,
            => |child| try self.mergeLocalDemandInExpr(local, child, context, out),
            .break_ => |maybe_child| if (maybe_child) |child| try self.mergeLocalDemandInExpr(local, child, self.activeBreakResultDemand(context), out),
            .comptime_branch_taken => |taken| try self.mergeLocalDemandInExpr(local, taken.body, context, out),
            .call_value => |call| {
                const callee_demand = try self.callableDemandForCalleeExprWithResultDemand(call.callee, context);
                try self.mergeLocalDemandInExpr(local, call.callee, callee_demand, out);
                try self.mergeCallValueArgDemandsInExpr(local, call, context, out);
            },
            .call_proc => |call| {
                try self.mergeCallProcDemandsInExpr(local, call, context, out);
            },
            .low_level => |call| {
                for (self.pass.program.exprSpan(call.args)) |arg| try self.mergeLocalDemandInExpr(local, arg, .materialize, out);
            },
            .structural_eq => |eq| {
                try self.mergeLocalDemandInExpr(local, eq.lhs, .materialize, out);
                try self.mergeLocalDemandInExpr(local, eq.rhs, .materialize, out);
            },
            .structural_hash => |hash| {
                try self.mergeLocalDemandInExpr(local, hash.value, .materialize, out);
                try self.mergeLocalDemandInExpr(local, hash.hasher, .materialize, out);
            },
            .loop_ => |loop| {
                const loop_demands = try self.loopParamDemands(loop, context);
                defer self.pass.allocator.free(loop_demands);

                const initials = self.pass.program.exprSpan(loop.initial_values);
                if (initials.len != loop_demands.len) Common.invariant("loop initial value count differed from loop demand count");
                for (initials, loop_demands) |initial, demand| {
                    try self.mergeLocalDemandInExpr(local, initial, demand, out);
                }

                const params = self.pass.program.typedLocalSpan(loop.params);
                const loop_known_values = try self.pass.allocator.alloc(KnownValue, params.len);
                defer self.pass.allocator.free(loop_known_values);
                for (params, loop_known_values) |param, *known_value| {
                    known_value.* = .{ .any = param.ty };
                }

                const refinements = try self.pass.allocator.alloc(?KnownValue, params.len);
                defer self.pass.allocator.free(refinements);
                @memset(refinements, null);

                var provenance = std.ArrayList(LoopLocalProvenance).empty;
                defer provenance.deinit(self.pass.allocator);

                try self.loop_stack.append(self.pass.allocator, .{
                    .params = params,
                    .values = loop_known_values,
                    .refinements = refinements,
                    .demands = loop_demands,
                    .result_demand = context,
                    .provenance = &provenance,
                });
                defer _ = self.loop_stack.pop();

                try self.mergeLocalDemandInExpr(local, loop.body, context, out);
            },
            .state_loop => |state_loop| {
                for (self.pass.program.exprSpan(state_loop.entry_values)) |initial| try self.mergeLocalDemandInExpr(local, initial, .materialize, out);
                for (self.pass.program.stateLoopStateSpan(state_loop.states)) |state| {
                    try self.mergeLocalDemandInExpr(local, state.body, .materialize, out);
                }
            },
            .if_initialized_payload => |payload_switch| {
                try self.mergeLocalDemandInExpr(local, payload_switch.cond, .materialize, out);
                try self.mergeLocalDemandInExpr(local, payload_switch.initialized, context, out);
                try self.mergeLocalDemandInExpr(local, payload_switch.uninitialized, context, out);
            },
            .try_sequence => |sequence| {
                try self.mergeLocalDemandInExpr(local, sequence.try_expr, .materialize, out);
                try self.mergeLocalDemandInExpr(local, sequence.ok_body, context, out);
            },
            .try_record_sequence => |sequence| {
                try self.mergeLocalDemandInExpr(local, sequence.try_expr, .materialize, out);
                try self.mergeLocalDemandInExpr(local, sequence.ok_body, context, out);
            },
            .static_data_candidate => |candidate| try self.mergeLocalDemandInExpr(local, candidate.restored_expr, context, out),
            .expect_err => |expect_err| try self.mergeLocalDemandInExpr(local, expect_err.msg, .materialize, out),
            .fn_ref => |fn_id| {
                const source_fn = self.pass.program.fns.items[@intFromEnum(fn_id)];
                const source_captures = self.pass.program.typedLocalSpan(source_fn.captures);
                const effective_context = switch (context) {
                    .callable => |callable| blk: {
                        var effective = ValueDemand{ .callable = callable };
                        if (callable.result) |result_demand| {
                            const derived = try self.callableDemandForFnWithResultDemand(
                                fn_id,
                                source_captures.len,
                                result_demand.*,
                            );
                            effective = try self.mergeValueDemand(effective, derived);
                            if (effective != .callable) Common.invariant("fn_ref callable demand merge produced non-callable demand");
                        }
                        break :blk effective.callable;
                    },
                    else => null,
                };
                for (source_captures, 0..) |capture, index| {
                    const capture_demand = switch (context) {
                        .none => .none,
                        .callable => callableCaptureDemandForPreservedValue(effective_context.?, index),
                        else => .materialize,
                    };
                    try self.mergeLocalDemandInCapturedLocal(local, capture, capture_demand, out);
                }
            },
            .fn_ref_captures => |fn_ref| {
                const source_fn = self.pass.program.fns.items[@intFromEnum(fn_ref.target)];
                const source_captures = self.pass.program.typedLocalSpan(source_fn.captures);
                const capture_exprs = self.pass.program.exprSpan(fn_ref.captures);
                if (source_captures.len != capture_exprs.len) {
                    Common.invariant("explicit function reference capture count differed from target function captures");
                }
                const effective_context = switch (context) {
                    .callable => |callable| blk: {
                        var effective = ValueDemand{ .callable = callable };
                        if (callable.result) |result_demand| {
                            const derived = try self.callableDemandForFnWithResultDemand(
                                fn_ref.target,
                                source_captures.len,
                                result_demand.*,
                            );
                            effective = try self.mergeValueDemand(effective, derived);
                            if (effective != .callable) Common.invariant("fn_ref callable demand merge produced non-callable demand");
                        }
                        break :blk effective.callable;
                    },
                    else => null,
                };
                for (capture_exprs, 0..) |capture_expr, index| {
                    const capture_demand = switch (context) {
                        .none => .none,
                        .callable => callableCaptureDemandForPreservedValue(effective_context.?, index),
                        else => .materialize,
                    };
                    try self.mergeLocalDemandInExpr(local, capture_expr, capture_demand, out);
                }
            },
            .unit,
            .int_lit,
            .frac_f32_lit,
            .frac_f64_lit,
            .dec_lit,
            .str_lit,
            .static_data,
            .lambda,
            .def_ref,
            .fn_def,
            .crash,
            .comptime_exhaustiveness_failed,
            .uninitialized,
            .uninitialized_payload,
            => {},
        }
    }

    fn mergeLocalDemandInStmtTail(
        self: *Cloner,
        local: Ast.LocalId,
        stmt_id: Ast.StmtId,
        tail: BlockTail,
        context: ValueDemand,
        out: *ValueDemand,
    ) LowerError!void {
        switch (self.pass.program.stmts.items[@intFromEnum(stmt_id)]) {
            .let_ => |let_| {
                var value_demand: ValueDemand = if (let_.recursive)
                    .materialize
                else
                    try self.patternDemandInBlockTail(let_.pat, tail, context);
                // A let whose pattern demands nothing still evaluates its
                // init when the init is not discardable, so the init remains
                // a use site for locals it references.
                if (value_demand == .none and
                    !(try discardedExprIsEffectFree(self.pass.program, self.pass.allocator, let_.value)))
                {
                    value_demand = .materialize;
                }
                try self.mergeLocalDemandInExpr(local, let_.value, value_demand, out);
            },
            .expr,
            => |expr| try self.mergeLocalDemandInExpr(local, expr, try self.stmtExprDemand(expr, context), out),
            .expect,
            .dbg,
            => |expr| try self.mergeLocalDemandInExpr(local, expr, .materialize, out),
            .return_ => |expr| try self.mergeLocalDemandInExpr(local, expr, context, out),
            .uninitialized,
            .crash,
            => {},
        }
    }

    fn stmtExprDemand(self: *Cloner, expr_id: Ast.ExprId, context: ValueDemand) Allocator.Error!ValueDemand {
        const expr = self.pass.program.exprs.items[@intFromEnum(expr_id)];
        return switch (expr.data) {
            .break_,
            .return_,
            => context,
            .comptime_branch_taken => |taken| try self.stmtExprDemand(taken.body, context),
            else => .materialize,
        };
    }

    fn patternDemandInBlockTail(
        self: *Cloner,
        pat_id: Ast.PatId,
        tail: BlockTail,
        context: ValueDemand,
    ) LowerError!ValueDemand {
        const pat = self.pass.program.pats.items[@intFromEnum(pat_id)];
        return switch (pat.data) {
            .bind => |local| try self.localDemandInBlockTail(local, tail, context),
            .wildcard => .none,
            .as => |as| try self.mergeValueDemand(
                try self.patternDemandInBlockTail(as.pattern, tail, context),
                try self.localDemandInBlockTail(as.local, tail, context),
            ),
            .record => |fields_span| blk: {
                const fields = self.pass.program.recordDestructSpan(fields_span);
                var demands = std.ArrayList(FieldDemand).empty;
                defer demands.deinit(self.pass.allocator);
                for (fields) |field| {
                    const field_demand = try self.patternDemandInBlockTail(field.pattern, tail, context);
                    if (field_demand == .none) continue;
                    try demands.append(self.pass.allocator, .{
                        .name = field.name,
                        .demand = try self.pass.storedDemand(field_demand),
                    });
                }
                if (demands.items.len == 0) break :blk .none;
                break :blk ValueDemand{ .record = try self.pass.arena.allocator().dupe(FieldDemand, demands.items) };
            },
            .tuple => |items_span| blk: {
                const pats = self.pass.program.patSpan(items_span);
                var demands = std.ArrayList(ItemDemand).empty;
                defer demands.deinit(self.pass.allocator);
                for (pats, 0..) |child_pat, index| {
                    const item_demand = try self.patternDemandInBlockTail(child_pat, tail, context);
                    if (item_demand == .none) continue;
                    try demands.append(self.pass.allocator, .{
                        .index = @intCast(index),
                        .demand = try self.pass.storedDemand(item_demand),
                    });
                }
                if (demands.items.len == 0) break :blk .none;
                break :blk ValueDemand{ .tuple = try self.pass.arena.allocator().dupe(ItemDemand, demands.items) };
            },
            .tag => |tag_pat| blk: {
                const pats = self.pass.program.patSpan(tag_pat.payloads);
                var demands = std.ArrayList(ItemDemand).empty;
                defer demands.deinit(self.pass.allocator);
                for (pats, 0..) |child_pat, index| {
                    const payload_demand = try self.patternDemandInBlockTail(child_pat, tail, context);
                    if (payload_demand == .none) continue;
                    try demands.append(self.pass.allocator, .{
                        .index = @intCast(index),
                        .demand = try self.pass.storedDemand(payload_demand),
                    });
                }
                const alternatives = try self.pass.arena.allocator().alloc(TagAlternativeDemand, 1);
                alternatives[0] = .{
                    .name = tag_pat.name,
                    .payloads = try self.pass.arena.allocator().dupe(ItemDemand, demands.items),
                };
                break :blk ValueDemand{ .tag = .{
                    .alternatives = alternatives,
                } };
            },
            .nominal => |backing_pat| blk: {
                const backing_demand = try self.patternDemandInBlockTail(backing_pat, tail, context);
                if (backing_demand == .none) break :blk .none;
                break :blk ValueDemand{ .nominal = try self.pass.storedDemand(backing_demand) };
            },
            .list,
            .int_lit,
            .dec_lit,
            .frac_f32_lit,
            .frac_f64_lit,
            .str_lit,
            .str_pattern,
            => .materialize,
        };
    }

    fn localDemandInBlockTail(
        self: *Cloner,
        local: Ast.LocalId,
        tail: BlockTail,
        context: ValueDemand,
    ) LowerError!ValueDemand {
        var demand: ValueDemand = .none;
        for (tail.statements, 0..) |stmt, index| {
            try self.mergeLocalDemandInStmtTail(local, stmt, .{
                .statements = tail.statements[index + 1 ..],
                .final_expr = tail.final_expr,
            }, context, &demand);
        }
        try self.mergeLocalDemandInExpr(local, tail.final_expr, context, &demand);
        return demand;
    }

    fn mergeCallValueArgDemandsInExpr(
        self: *Cloner,
        local: Ast.LocalId,
        call: anytype,
        context: ValueDemand,
        out: *ValueDemand,
    ) LowerError!void {
        const args = self.pass.program.exprSpan(call.args);
        if (try self.exprSubstitutedValueNoInline(call.callee)) |value| {
            if (try self.mergeCallValueArgDemandsForValue(local, value, args, context, out)) return;
            for (args) |arg| try self.mergeLocalDemandInExpr(local, arg, .materialize, out);
            return;
        }

        const known_value = (try self.exprKnownValueNoInline(call.callee)) orelse {
            for (args) |arg| try self.mergeLocalDemandInExpr(local, arg, .materialize, out);
            return;
        };

        switch (known_value) {
            .callable => |callable| try self.mergeCallableArgDemandsInExpr(local, callable.fn_id, args, context, out),
            .finite_callables => |finite_callables| {
                for (finite_callables.alternatives) |alternative| {
                    try self.mergeCallableArgDemandsInExpr(local, alternative.fn_id, args, context, out);
                }
            },
            else => {
                for (args) |arg| try self.mergeLocalDemandInExpr(local, arg, .materialize, out);
            },
        }
    }

    fn mergeCallValueArgDemandsForValue(
        self: *Cloner,
        local: Ast.LocalId,
        value: Value,
        args: []const Ast.ExprId,
        context: ValueDemand,
        out: *ValueDemand,
    ) LowerError!bool {
        switch (value) {
            .callable => |callable| {
                try self.mergeCallableArgDemandsInExpr(local, callable.fn_id, args, context, out);
                return true;
            },
            .finite_callables => |finite_callables| {
                for (finite_callables.alternatives) |alternative| {
                    try self.mergeCallableArgDemandsInExpr(local, alternative.fn_id, args, context, out);
                }
                return true;
            },
            .private_state => |private_state| {
                if (privateStateCallable(private_state)) |callable| {
                    try self.mergeCallableArgDemandsInExpr(local, callable.fn_id, args, context, out);
                    return true;
                }
                return false;
            },
            .nominal => |nominal| return try self.mergeCallValueArgDemandsForValue(local, nominal.backing.*, args, context, out),
            .let_ => |let_value| return try self.mergeCallValueArgDemandsForValue(local, let_value.body.*, args, context, out),
            .expr_with_known_value => |known| if (known.value) |structured|
                return try self.mergeCallValueArgDemandsForValue(local, structured.*, args, context, out)
            else
                return false,
            else => return false,
        }
    }

    fn mergeCallableArgDemandsInExpr(
        self: *Cloner,
        local: Ast.LocalId,
        fn_id: Ast.FnId,
        args: []const Ast.ExprId,
        context: ValueDemand,
        out: *ValueDemand,
    ) LowerError!void {
        const source_fn = self.pass.program.fns.items[@intFromEnum(fn_id)];
        const source_args = self.pass.program.typedLocalSpan(source_fn.args);
        if (source_args.len != args.len) {
            for (args) |arg| try self.mergeLocalDemandInExpr(local, arg, .materialize, out);
            return;
        }
        for (source_args, args) |source_arg, arg| {
            if (!try self.exprMayDemandLocalInCurrentContext(arg, local)) continue;
            try self.mergeLocalDemandInExpr(
                local,
                arg,
                try self.functionLocalDemand(fn_id, source_arg.local, context),
                out,
            );
        }
    }

    /// A direct call that optimized lowering cannot inline is a public
    /// boundary: its arguments and captures must be ordinary public values.
    /// Demand derivation and call cloning both consume this one predicate so
    /// the demanded split can never omit a child a boundary later needs.
    fn directCallIsPublicBoundary(self: *Cloner, callee: Ast.FnId) bool {
        const source_fn = self.pass.program.fns.items[@intFromEnum(callee)];
        const body = self.pass.originalBody(callee) orelse switch (source_fn.body) {
            .roc => |body| body,
            .hosted => return true,
        };
        return exprContainsReturn(self.pass.program, body);
    }

    fn mergeCallProcDemandsInExpr(
        self: *Cloner,
        local: Ast.LocalId,
        call: anytype,
        context: ValueDemand,
        out: *ValueDemand,
    ) LowerError!void {
        const args = self.pass.program.exprSpan(call.args);
        if (call.is_cold) {
            for (args) |arg| try self.mergeLocalDemandInExpr(local, arg, .materialize, out);
            return;
        }

        const callee = Ast.callProcCallee(call);
        const source_fn = self.pass.program.fns.items[@intFromEnum(callee)];
        const source_args = self.pass.program.typedLocalSpan(source_fn.args);
        if (source_args.len != args.len) {
            Common.invariant("direct call arity differed from lifted function arity");
        }

        if (self.directCallIsPublicBoundary(callee)) {
            for (args) |arg| {
                if (!try self.exprMayDemandLocalInCurrentContext(arg, local)) continue;
                try self.mergeLocalDemandInExpr(local, arg, .materialize, out);
            }
            for (self.pass.program.typedLocalSpan(source_fn.captures)) |capture| {
                if (!try self.boundLocalMayDemandLocalInCurrentContext(capture.local, local)) continue;
                try self.mergeLocalDemandInCapturedLocal(local, capture, .materialize, out);
            }
            return;
        }

        for (source_args, args) |source_arg, arg| {
            if (!try self.exprMayDemandLocalInCurrentContext(arg, local)) continue;
            try self.mergeLocalDemandInExpr(
                local,
                arg,
                try self.functionLocalDemand(callee, source_arg.local, context),
                out,
            );
        }

        for (self.pass.program.typedLocalSpan(source_fn.captures)) |capture| {
            if (!try self.boundLocalMayDemandLocalInCurrentContext(capture.local, local)) continue;
            try self.mergeLocalDemandInCapturedLocal(
                local,
                capture,
                try self.functionLocalDemand(callee, capture.local, context),
                out,
            );
        }
    }

    fn loopParamDemands(self: *Cloner, loop: anytype, result_demand: ValueDemand) LowerError![]ValueDemand {
        const params = self.pass.program.typedLocalSpan(loop.params);
        const initials = self.pass.program.exprSpan(loop.initial_values);
        if (params.len != initials.len) Common.invariant("loop parameter count differed from initial value count while computing demand");

        const demands = try self.pass.allocator.alloc(ValueDemand, params.len);
        @memset(demands, .none);

        const known_values = try self.pass.allocator.alloc(KnownValue, params.len);
        defer self.pass.allocator.free(known_values);
        for (params, known_values) |param, *known_value| {
            known_value.* = .{ .any = param.ty };
        }

        const refinements = try self.pass.allocator.alloc(?KnownValue, params.len);
        defer self.pass.allocator.free(refinements);
        @memset(refinements, null);

        var loop_param_iterations: usize = 0;
        while (true) {
            loop_param_iterations += 1;
            if (loop_param_iterations > 1000) Common.invariant("loop parameter demand loop did not converge");
            var changed = false;

            var provenance = std.ArrayList(LoopLocalProvenance).empty;
            defer provenance.deinit(self.pass.allocator);

            try self.loop_stack.append(self.pass.allocator, .{
                .params = params,
                .values = known_values,
                .refinements = refinements,
                .demands = demands,
                .result_demand = result_demand,
                .provenance = &provenance,
            });
            for (params, 0..) |param, index| {
                const observed = try self.localDemandInExpr(param.local, loop.body, result_demand);
                const merged = try self.mergeLoopParamDemand(known_values[index], demands[index], observed);
                if (!try self.valueDemandEqlInActiveContext(demands[index], merged)) {
                    demands[index] = merged;
                    changed = true;
                    self.demand_cache_epoch += 1;
                }
            }
            _ = self.loop_stack.pop();

            if (!changed) return demands;
        }
    }

    fn continueValueDemand(self: *Cloner, index: usize) Allocator.Error!ValueDemand {
        if (self.loop_stack.getLastOrNull()) |loop| {
            if (index >= loop.demands.len) return .materialize;
            return .{ .loop_param = index };
        }
        if (self.state_loop_stack.getLastOrNull()) |state_loop| {
            if (state_loop.states.items.len == 0 or index >= state_loop.states.items[0].values.len) return .materialize;
            return .{ .loop_param = index };
        }
        return .materialize;
    }

    fn simplifyKnownMatch(self: *Cloner, ty: Type.TypeId, scrutinee: Value, branches_span: Ast.Span(Ast.Branch)) LowerError!?Ast.ExprId {
        if (try self.simplifyKnownMatchValueWithKnownValuePreservation(ty, scrutinee, branches_span, false)) |value| {
            return try self.materialize(value);
        }
        return null;
    }

    fn simplifyKnownMatchValue(self: *Cloner, ty: Type.TypeId, scrutinee: Value, branches_span: Ast.Span(Ast.Branch)) LowerError!?Value {
        return try self.simplifyKnownMatchValueWithKnownValuePreservation(ty, scrutinee, branches_span, true);
    }

    fn simplifyKnownMatchValueWithDemand(
        self: *Cloner,
        ty: Type.TypeId,
        scrutinee: Value,
        branches_span: Ast.Span(Ast.Branch),
        demand: ValueDemand,
    ) LowerError!?Value {
        return try self.simplifyKnownMatchValueWithDemandMode(ty, scrutinee, branches_span, demand, .strict);
    }

    fn simplifyKnownMatchValueWithDemandMode(
        self: *Cloner,
        ty: Type.TypeId,
        scrutinee: Value,
        branches_span: Ast.Span(Ast.Branch),
        demand: ValueDemand,
        mode: KnownMatchMode,
    ) LowerError!?Value {
        switch (scrutinee) {
            .expr,
            .expr_with_known_value,
            .match_,
            => return null,
            .let_ => |let_value| {
                const change_start = self.changes.items.len;
                defer self.restore(change_start);
                const pending_start = self.activePendingLetsLen();
                const scoped_start = try self.pushPendingLetScope(let_value.lets);
                defer self.popPendingLetScope(scoped_start, pending_start);

                const body = (try self.simplifyKnownMatchValueWithDemandMode(ty, let_value.body.*, branches_span, demand, mode)) orelse return null;
                return try self.wrapPendingLets(body, let_value.lets, demand != .none);
            },
            .if_ => |if_value| return try self.simplifyKnownMatchIfValueWithDemand(ty, if_value, branches_span, demand),
            .finite_tags => |finite_tags| return try self.simplifyKnownMatchFiniteTagsValueWithDemand(ty, finite_tags, branches_span, demand, mode),
            .private_state => |private_state| switch (private_state) {
                .leaf => return null,
                .compact_finite_tags => |finite_tags| return try self.simplifyKnownMatchCompactFiniteTagsValueWithDemand(ty, finite_tags, branches_span, demand, mode),
                else => {},
            },
            else => {},
        }

        const branches = self.pass.program.branchSpan(branches_span);
        for (branches, 0..) |branch, branch_index| {
            const demand_context: ValueDemand = if (demand == .none) .materialize else demand;
            var pending_lets = std.ArrayList(PendingLet).empty;
            defer pending_lets.deinit(self.pass.allocator);

            const change_start = self.changes.items.len;
            const unsafe_count = self.unsafeLeafCount(scrutinee);
            switch (try self.bindPatToMatchValue(branch.pat, scrutinee, branch.body, demand_context, unsafe_count, &pending_lets)) {
                .matched => {},
                .no_match => {
                    self.restore(change_start);
                    continue;
                },
                .unsupported => {
                    self.restore(change_start);
                    return null;
                },
            }
            if (branch.guard) |guard| {
                const pending_start = self.activePendingLetsLen();
                const scoped_start = try self.pushPendingLetScope(pending_lets.items);
                const guard_expr = try self.cloneExpr(guard);
                const body = try self.cloneExprValueWithDemand(branch.body, demand);
                self.popPendingLetScope(scoped_start, pending_start);
                self.restore(change_start);

                const final_else = try self.pass.arena.allocator().create(Value);
                const rest_span = try self.pass.program.addBranchSpan(branches[branch_index + 1 ..]);
                final_else.* = (try self.simplifyKnownMatchValueWithDemandMode(ty, scrutinee, rest_span, demand, mode)) orelse
                    return null;

                const if_branches = try self.pass.arena.allocator().alloc(IfValueBranch, 1);
                if_branches[0] = .{
                    .cond = guard_expr,
                    .body = body,
                };
                return try self.wrapPendingLets(.{ .if_ = .{
                    .ty = ty,
                    .branches = if_branches,
                    .final_else = final_else,
                } }, pending_lets.items, demand != .none);
            }
            if (exprContainsEscapingControlTransfer(self.pass.program, branch.body)) {
                switch (mode) {
                    .speculative => {
                        self.restore(change_start);
                        return null;
                    },
                    .strict => {
                        const pending_start = self.activePendingLetsLen();
                        const scoped_start = try self.pushPendingLetScope(pending_lets.items);
                        defer self.popPendingLetScope(scoped_start, pending_start);
                        const body = try self.wrapPendingLetsAroundExpr(ty, try self.cloneExpr(branch.body), pending_lets.items);
                        self.restore(change_start);
                        return Value{ .expr = body };
                    },
                }
            }
            const pending_start = self.activePendingLetsLen();
            const scoped_start = try self.pushPendingLetScope(pending_lets.items);
            defer self.popPendingLetScope(scoped_start, pending_start);
            const body = try self.cloneExprValueWithDemand(branch.body, demand);
            self.restore(change_start);
            return try self.wrapPendingLets(body, pending_lets.items, demand != .none);
        }

        if (scrutinee == .private_state and !privateStateCanMaterializePublic(self.pass.program, scrutinee.private_state)) {
            return null;
        }
        switch (mode) {
            .strict => Common.invariant("known constructor match had no matching branch"),
            .speculative => return null,
        }
    }

    fn simplifyKnownMatchIfValueWithDemand(
        self: *Cloner,
        ty: Type.TypeId,
        if_value: IfValue,
        branches_span: Ast.Span(Ast.Branch),
        demand: ValueDemand,
    ) LowerError!?Value {
        const branches = try self.pass.arena.allocator().alloc(IfValueBranch, if_value.branches.len);
        for (if_value.branches, 0..) |branch, index| {
            const simplified = try self.simplifyKnownMatchValueWithDemandMode(ty, branch.body, branches_span, demand, .speculative);
            branches[index] = .{
                .cond = branch.cond,
                .body = simplified orelse return null,
            };
        }

        const final_else = try self.pass.arena.allocator().create(Value);
        const simplified_final_else = try self.simplifyKnownMatchValueWithDemandMode(ty, if_value.final_else.*, branches_span, demand, .speculative);
        final_else.* = simplified_final_else orelse return null;

        return .{ .if_ = .{
            .ty = ty,
            .branches = branches,
            .final_else = final_else,
        } };
    }

    fn simplifyKnownMatchFiniteTagsValueWithDemand(
        self: *Cloner,
        ty: Type.TypeId,
        finite_tags: FiniteTagsValue,
        branches_span: Ast.Span(Ast.Branch),
        demand: ValueDemand,
        mode: KnownMatchMode,
    ) LowerError!?Value {
        if (finite_tags.alternatives.len == 0) {
            Common.invariant("finite tag match had no alternatives");
        }
        if (finite_tags.alternatives.len == 1) {
            return try self.simplifyKnownMatchValueWithDemandMode(ty, .{ .tag = finite_tags.alternatives[0] }, branches_span, demand, mode);
        }

        const branch_count = finite_tags.alternatives.len - 1;
        const branches = try self.pass.arena.allocator().alloc(IfValueBranch, branch_count);
        for (finite_tags.alternatives[0..branch_count], branches, 0..) |alternative, *branch, index| {
            const body = (try self.simplifyKnownMatchValueWithDemandMode(ty, .{ .tag = alternative }, branches_span, demand, mode)) orelse {
                return null;
            };
            branch.* = .{
                .cond = try self.selectorEquals(finite_tags.selector, @intCast(index)),
                .body = body,
            };
        }

        const final_else = try self.pass.arena.allocator().create(Value);
        final_else.* = (try self.simplifyKnownMatchValueWithDemandMode(ty, .{ .tag = finite_tags.alternatives[branch_count] }, branches_span, demand, mode)) orelse {
            return null;
        };

        return .{ .if_ = .{
            .ty = ty,
            .branches = branches,
            .final_else = final_else,
        } };
    }

    fn simplifyKnownMatchCompactFiniteTagsValueWithDemand(
        self: *Cloner,
        ty: Type.TypeId,
        finite_tags: PrivateStateCompactFiniteTags,
        branches_span: Ast.Span(Ast.Branch),
        demand: ValueDemand,
        mode: KnownMatchMode,
    ) LowerError!?Value {
        if (finite_tags.source.alternatives.len == 1) {
            const private_tag = try self.compactFiniteTagPrivateStateFromExpr(finite_tags.source, finite_tags.compact_expr);
            return try self.simplifyKnownMatchValueWithDemandMode(
                ty,
                .{ .private_state = .{ .tag = private_tag } },
                branches_span,
                demand,
                mode,
            );
        }

        const branches = (try self.compactFiniteTagsMatchBranchesWithDemand(ty, finite_tags, branches_span, demand, mode)) orelse return null;
        return .{ .match_ = .{
            .ty = ty,
            .branches = branches,
            .scrutinee = finite_tags.compact_expr,
            .comptime_site = null,
        } };
    }

    fn simplifyKnownMatchValueWithKnownValuePreservation(
        self: *Cloner,
        ty: Type.TypeId,
        scrutinee: Value,
        branches_span: Ast.Span(Ast.Branch),
        preserve_branch_known_value: bool,
    ) LowerError!?Value {
        return try self.simplifyKnownMatchValueMode(ty, scrutinee, branches_span, .strict, preserve_branch_known_value);
    }

    fn simplifyKnownMatchValueMode(
        self: *Cloner,
        ty: Type.TypeId,
        scrutinee: Value,
        branches_span: Ast.Span(Ast.Branch),
        mode: KnownMatchMode,
        preserve_branch_known_value: bool,
    ) LowerError!?Value {
        switch (scrutinee) {
            .expr,
            .expr_with_known_value,
            => return null,
            .let_ => |let_value| {
                const change_start = self.changes.items.len;
                defer self.restore(change_start);
                const pending_start = self.activePendingLetsLen();
                const scoped_start = try self.pushPendingLetScope(let_value.lets);
                defer self.popPendingLetScope(scoped_start, pending_start);

                const body = (try self.simplifyKnownMatchValueMode(ty, let_value.body.*, branches_span, mode, preserve_branch_known_value)) orelse return null;
                return try self.wrapPendingLets(body, let_value.lets, true);
            },
            .if_ => |if_value| return try self.simplifyKnownMatchIfValue(ty, if_value, branches_span, preserve_branch_known_value),
            .match_ => |match_value| return try self.simplifyKnownMatchMatchValue(ty, match_value, branches_span, preserve_branch_known_value),
            .finite_tags => |finite_tags| return try self.simplifyKnownMatchFiniteTagsValue(ty, finite_tags, branches_span, mode, preserve_branch_known_value),
            .private_state => |private_state| switch (private_state) {
                .leaf => return null,
                .compact_finite_tags => |finite_tags| return try self.simplifyKnownMatchCompactFiniteTagsValue(ty, finite_tags, branches_span, mode, preserve_branch_known_value),
                else => {},
            },
            else => {},
        }
        const branches = self.pass.program.branchSpan(branches_span);
        for (branches, 0..) |branch, branch_index| {
            var pending_lets = std.ArrayList(PendingLet).empty;
            defer pending_lets.deinit(self.pass.allocator);

            const change_start = self.changes.items.len;
            const unsafe_count = self.unsafeLeafCount(scrutinee);
            switch (try self.bindPatToMatchValue(branch.pat, scrutinee, branch.body, .materialize, unsafe_count, &pending_lets)) {
                .matched => {},
                .no_match => {
                    self.restore(change_start);
                    continue;
                },
                .unsupported => {
                    self.restore(change_start);
                    return null;
                },
            }
            if (branch.guard) |guard| {
                const pending_start = self.activePendingLetsLen();
                const scoped_start = try self.pushPendingLetScope(pending_lets.items);
                const guard_expr = try self.cloneExpr(guard);
                const body = try self.cloneExprValue(branch.body);
                self.popPendingLetScope(scoped_start, pending_start);
                self.restore(change_start);

                const final_else = try self.pass.arena.allocator().create(Value);
                const rest_span = try self.pass.program.addBranchSpan(branches[branch_index + 1 ..]);
                final_else.* = (try self.simplifyKnownMatchValueMode(ty, scrutinee, rest_span, mode, preserve_branch_known_value)) orelse
                    return null;

                const if_branches = try self.pass.arena.allocator().alloc(IfValueBranch, 1);
                if_branches[0] = .{
                    .cond = guard_expr,
                    .body = body,
                };
                return try self.wrapPendingLets(.{ .if_ = .{
                    .ty = ty,
                    .branches = if_branches,
                    .final_else = final_else,
                } }, pending_lets.items, preserve_branch_known_value);
            }
            if (exprContainsEscapingControlTransfer(self.pass.program, branch.body)) {
                switch (mode) {
                    .speculative => {
                        self.restore(change_start);
                        return null;
                    },
                    .strict => {
                        const pending_start = self.activePendingLetsLen();
                        const scoped_start = try self.pushPendingLetScope(pending_lets.items);
                        defer self.popPendingLetScope(scoped_start, pending_start);
                        const body = try self.wrapPendingLetsAroundExpr(ty, try self.cloneExpr(branch.body), pending_lets.items);
                        self.restore(change_start);
                        return Value{ .expr = body };
                    },
                }
            }
            const pending_start = self.activePendingLetsLen();
            const scoped_start = try self.pushPendingLetScope(pending_lets.items);
            defer self.popPendingLetScope(scoped_start, pending_start);
            const body = try self.cloneExprValue(branch.body);
            self.restore(change_start);
            return try self.wrapPendingLets(body, pending_lets.items, preserve_branch_known_value);
        }
        switch (mode) {
            .strict => {
                if (scrutinee == .private_state and !privateStateCanMaterializePublic(self.pass.program, scrutinee.private_state)) return null;
                Common.invariant("known constructor match had no matching branch");
            },
            .speculative => return null,
        }
    }

    fn simplifyKnownMatchIfValue(
        self: *Cloner,
        ty: Type.TypeId,
        if_value: IfValue,
        branches_span: Ast.Span(Ast.Branch),
        preserve_branch_known_value: bool,
    ) LowerError!?Value {
        const branches = try self.pass.arena.allocator().alloc(IfValueBranch, if_value.branches.len);
        for (if_value.branches, 0..) |branch, index| {
            const simplified = try self.simplifyKnownMatchValueMode(ty, branch.body, branches_span, .speculative, preserve_branch_known_value);
            branches[index] = .{
                .cond = branch.cond,
                .body = simplified orelse return null,
            };
        }

        const final_else = try self.pass.arena.allocator().create(Value);
        const simplified_final_else = try self.simplifyKnownMatchValueMode(ty, if_value.final_else.*, branches_span, .speculative, preserve_branch_known_value);
        final_else.* = simplified_final_else orelse return null;

        return .{ .if_ = .{
            .ty = ty,
            .branches = branches,
            .final_else = final_else,
        } };
    }

    fn simplifyKnownMatchMatchValue(
        self: *Cloner,
        ty: Type.TypeId,
        match_value: MatchValue,
        branches_span: Ast.Span(Ast.Branch),
        preserve_branch_known_value: bool,
    ) LowerError!?Value {
        const branches = try self.pass.arena.allocator().alloc(MatchValueBranch, match_value.branches.len);
        for (match_value.branches, 0..) |branch, index| {
            const simplified = try self.simplifyKnownMatchValueMode(ty, branch.body, branches_span, .speculative, preserve_branch_known_value);
            branches[index] = .{
                .pat = branch.pat,
                .guard = branch.guard,
                .body = simplified orelse return null,
                .source = try self.matchBranchSourceThroughMatch(branch.source, ty, branches_span, null),
            };
        }

        return .{ .match_ = .{
            .ty = ty,
            .scrutinee = match_value.scrutinee,
            .branches = branches,
            .comptime_site = match_value.comptime_site,
        } };
    }

    fn simplifyKnownMatchFiniteTagsValue(
        self: *Cloner,
        ty: Type.TypeId,
        finite_tags: FiniteTagsValue,
        branches_span: Ast.Span(Ast.Branch),
        mode: KnownMatchMode,
        preserve_branch_known_value: bool,
    ) LowerError!?Value {
        if (finite_tags.alternatives.len == 0) {
            Common.invariant("finite tag match had no alternatives");
        }
        if (finite_tags.alternatives.len == 1) {
            return try self.simplifyKnownMatchValueMode(ty, .{ .tag = finite_tags.alternatives[0] }, branches_span, mode, preserve_branch_known_value);
        }

        const branch_count = finite_tags.alternatives.len - 1;
        const branches = try self.pass.arena.allocator().alloc(IfValueBranch, branch_count);
        for (finite_tags.alternatives[0..branch_count], branches, 0..) |alternative, *branch, index| {
            const body = (try self.simplifyKnownMatchValueMode(ty, .{ .tag = alternative }, branches_span, mode, preserve_branch_known_value)) orelse {
                return null;
            };
            branch.* = .{
                .cond = try self.selectorEquals(finite_tags.selector, @intCast(index)),
                .body = body,
            };
        }

        const final_else = try self.pass.arena.allocator().create(Value);
        final_else.* = (try self.simplifyKnownMatchValueMode(ty, .{ .tag = finite_tags.alternatives[branch_count] }, branches_span, mode, preserve_branch_known_value)) orelse {
            return null;
        };

        return .{ .if_ = .{
            .ty = ty,
            .branches = branches,
            .final_else = final_else,
        } };
    }

    fn simplifyKnownMatchCompactFiniteTagsValue(
        self: *Cloner,
        ty: Type.TypeId,
        finite_tags: PrivateStateCompactFiniteTags,
        branches_span: Ast.Span(Ast.Branch),
        mode: KnownMatchMode,
        preserve_branch_known_value: bool,
    ) LowerError!?Value {
        if (finite_tags.source.alternatives.len == 1) {
            const private_tag = try self.compactFiniteTagPrivateStateFromExpr(finite_tags.source, finite_tags.compact_expr);
            return try self.simplifyKnownMatchValueMode(
                ty,
                .{ .private_state = .{ .tag = private_tag } },
                branches_span,
                mode,
                preserve_branch_known_value,
            );
        }

        const branches = (try self.compactFiniteTagsMatchBranches(ty, finite_tags, branches_span, mode, preserve_branch_known_value)) orelse return null;
        return .{ .match_ = .{
            .ty = ty,
            .branches = branches,
            .scrutinee = finite_tags.compact_expr,
            .comptime_site = null,
        } };
    }

    fn compactFiniteTagPrivateStateFromExpr(
        self: *Cloner,
        source: DemandedKnownTags,
        compact_expr: Ast.ExprId,
    ) LowerError!PrivateStateTag {
        if (source.alternatives.len != 1) Common.invariant("compact singleton tag reconstruction got multiple alternatives");
        const alternative = source.alternatives[0];

        var slot_tys = std.ArrayList(Type.TypeId).empty;
        defer slot_tys.deinit(self.pass.allocator);
        try self.pass.appendCompactIndexedValueTypes(alternative.payloads, &slot_tys);

        var payload_exprs = std.ArrayList(Ast.ExprId).empty;
        defer payload_exprs.deinit(self.pass.allocator);
        try self.appendCompactSlotExprs(compact_expr, slot_tys.items, &payload_exprs);

        var index: usize = 0;
        const payloads = try self.privateStateIndexedValuesFromDemandedKnownValueExprs(alternative.payloads, payload_exprs.items, &index);
        if (index != payload_exprs.items.len) Common.invariant("compact singleton tag reconstruction did not consume every slot");
        return .{
            .ty = alternative.ty,
            .name = alternative.name,
            .payloads = payloads,
        };
    }

    fn compactFiniteTagsMatchBranchesWithDemand(
        self: *Cloner,
        ty: Type.TypeId,
        finite_tags: PrivateStateCompactFiniteTags,
        branches_span: Ast.Span(Ast.Branch),
        demand: ValueDemand,
        mode: KnownMatchMode,
    ) LowerError!?[]const MatchValueBranch {
        const source = finite_tags.source;
        const branches = try self.pass.arena.allocator().alloc(MatchValueBranch, source.alternatives.len);
        for (source.alternatives, branches) |alternative, *branch| {
            const active = try self.compactFiniteTagAlternativePatternAndState(source, alternative);
            const scoped_start = self.scopedLocalsLen();
            defer self.restoreScopedLocals(scoped_start);
            try self.appendPatternScopedLocals(active.pat);
            const body = (try self.simplifyKnownMatchValueWithDemandMode(
                ty,
                .{ .private_state = .{ .tag = active.private_state } },
                branches_span,
                demand,
                mode,
            )) orelse return null;
            branch.* = .{
                .pat = active.pat,
                .guard = null,
                .body = body,
                .source = try self.compactFiniteTagBranchSource(
                    ty,
                    finite_tags,
                    active,
                    branches_span,
                ),
            };
        }
        return branches;
    }

    fn compactFiniteTagsMatchBranches(
        self: *Cloner,
        ty: Type.TypeId,
        finite_tags: PrivateStateCompactFiniteTags,
        branches_span: Ast.Span(Ast.Branch),
        mode: KnownMatchMode,
        preserve_branch_known_value: bool,
    ) LowerError!?[]const MatchValueBranch {
        const source = finite_tags.source;
        const branches = try self.pass.arena.allocator().alloc(MatchValueBranch, source.alternatives.len);
        for (source.alternatives, branches) |alternative, *branch| {
            const active = try self.compactFiniteTagAlternativePatternAndState(source, alternative);
            const scoped_start = self.scopedLocalsLen();
            defer self.restoreScopedLocals(scoped_start);
            try self.appendPatternScopedLocals(active.pat);
            const body = (try self.simplifyKnownMatchValueMode(
                ty,
                .{ .private_state = .{ .tag = active.private_state } },
                branches_span,
                mode,
                preserve_branch_known_value,
            )) orelse return null;
            branch.* = .{
                .pat = active.pat,
                .guard = null,
                .body = body,
                .source = try self.compactFiniteTagBranchSource(
                    ty,
                    finite_tags,
                    active,
                    branches_span,
                ),
            };
        }
        return branches;
    }

    fn compactFiniteTagBranchSource(
        self: *Cloner,
        ty: Type.TypeId,
        finite_tags: PrivateStateCompactFiniteTags,
        active: CompactFiniteTagActive,
        branches_span: Ast.Span(Ast.Branch),
    ) LowerError!MatchValueBranchSource {
        const source_scrutinee = try self.privateStateExprWithUninitializedHoles(.{ .tag = active.private_state });
        const source_body = try self.addExpr(.{ .ty = ty, .data = .{ .match_ = .{
            .scrutinee = source_scrutinee,
            .branches = branches_span,
            .comptime_site = null,
        } } });

        return .{
            .scrutinee = finite_tags.compact_expr,
            .pat = active.pat,
            .guard = null,
            .body = source_body,
            .scrutinee_known_value = try self.compactFiniteTagActiveKnownValue(finite_tags.source, active),
            .scrutinee_value = null,
            .bindings = try self.snapshotSubst(),
            .pending_lets = try self.snapshotActivePendingLets(),
        };
    }

    fn privateStateExprWithUninitializedHoles(
        self: *Cloner,
        value: PrivateStateValue,
    ) LowerError!Ast.ExprId {
        return switch (value) {
            .leaf => |leaf| leaf.expr,
            .tag => |tag| blk: {
                const payload_tys = tagTypePayloads(self.pass.program, tag.ty, tag.name) orelse
                    Common.invariant("private tag referenced a tag absent from its type");
                const payloads = try self.pass.allocator.alloc(Ast.ExprId, payload_tys.len);
                defer self.pass.allocator.free(payloads);
                for (payload_tys, payloads, 0..) |payload_ty, *payload_expr, index| {
                    payload_expr.* = if (privateStateIndexedValueByIndex(tag.payloads, @intCast(index))) |payload|
                        try self.privateStateExprWithUninitializedHoles(payload)
                    else
                        try self.addExpr(.{ .ty = payload_ty, .data = .uninitialized });
                }
                break :blk try self.addExpr(.{ .ty = tag.ty, .data = .{ .tag = .{
                    .name = tag.name,
                    .payloads = try self.pass.program.addExprSpan(payloads),
                } } });
            },
            .record => |record| blk: {
                const field_tys = recordTypeFields(self.pass.program, record.ty);
                const fields = try self.pass.allocator.alloc(Ast.FieldExpr, field_tys.len);
                defer self.pass.allocator.free(fields);
                for (field_tys, fields) |field_ty, *field| {
                    field.* = .{
                        .name = field_ty.name,
                        .value = if (privateStateFieldByName(self.pass.program, record.fields, field_ty.name)) |field_value|
                            try self.privateStateExprWithUninitializedHoles(field_value)
                        else
                            try self.addExpr(.{ .ty = field_ty.ty, .data = .uninitialized }),
                    };
                }
                break :blk try self.addExpr(.{ .ty = record.ty, .data = .{
                    .record = try self.pass.program.addFieldExprSpan(fields),
                } });
            },
            .tuple => |tuple| blk: {
                const item_tys = tupleTypeItems(self.pass.program, tuple.ty);
                const items = try self.pass.allocator.alloc(Ast.ExprId, item_tys.len);
                defer self.pass.allocator.free(items);
                for (item_tys, items, 0..) |item_ty, *item_expr, index| {
                    item_expr.* = if (privateStateIndexedValueByIndex(tuple.items, @intCast(index))) |item|
                        try self.privateStateExprWithUninitializedHoles(item)
                    else
                        try self.addExpr(.{ .ty = item_ty, .data = .uninitialized });
                }
                break :blk try self.addExpr(.{ .ty = tuple.ty, .data = .{
                    .tuple = try self.pass.program.addExprSpan(items),
                } });
            },
            .nominal => |nominal| blk: {
                const backing = nominal.backing orelse
                    break :blk try self.addExpr(.{ .ty = nominal.ty, .data = .uninitialized });
                break :blk try self.addExpr(.{ .ty = nominal.ty, .data = .{
                    .nominal = try self.privateStateExprWithUninitializedHoles(backing.*),
                } });
            },
            .callable => |callable| blk: {
                const source_fn = self.pass.program.fns.items[@intFromEnum(callable.fn_id)];
                const source_captures = self.pass.program.typedLocalSpan(source_fn.captures);
                const captures = try self.pass.allocator.alloc(Ast.ExprId, source_captures.len);
                defer self.pass.allocator.free(captures);
                for (source_captures, captures, 0..) |source_capture, *capture_expr, index| {
                    capture_expr.* = if (privateStateIndexedValueByIndex(callable.captures, @intCast(index))) |capture|
                        try self.privateStateExprWithUninitializedHoles(capture)
                    else
                        try self.addExpr(.{ .ty = source_capture.ty, .data = .uninitialized });
                }
                break :blk try self.materializeExplicitCallableRef(callable.ty, callable.fn_id, captures);
            },
            .compact_finite_tags => |finite_tags| finite_tags.compact_expr,
            .compact_finite_callables => |finite_callables| finite_callables.compact_expr,
        };
    }

    fn compactFiniteTagActiveKnownValue(
        self: *Cloner,
        source: DemandedKnownTags,
        active: CompactFiniteTagActive,
    ) Allocator.Error!KnownValue {
        const pat = self.pass.program.pats.items[@intFromEnum(active.pat)];
        const tag_pat = switch (pat.data) {
            .tag => |tag_pat| tag_pat,
            else => Common.invariant("compact finite tag branch pattern was not a tag"),
        };

        var slot_tys = std.ArrayList(Type.TypeId).empty;
        defer slot_tys.deinit(self.pass.allocator);
        var matched = false;
        for (source.alternatives) |alternative| {
            if (alternative.name != tag_pat.name) continue;
            try self.pass.appendCompactIndexedValueTypes(alternative.payloads, &slot_tys);
            matched = true;
            break;
        }
        if (!matched) Common.invariant("compact finite tag branch source had no matching alternative");

        const payloads = try self.pass.arena.allocator().alloc(KnownValue, slot_tys.items.len);
        for (slot_tys.items, payloads) |slot_ty, *payload| {
            payload.* = .{ .any = slot_ty };
        }

        return .{ .tag = .{
            .ty = pat.ty,
            .name = tag_pat.name,
            .payloads = payloads,
        } };
    }

    fn compactFiniteTagAlternativePatternAndState(
        self: *Cloner,
        source: DemandedKnownTags,
        alternative: DemandedKnownTag,
    ) LowerError!CompactFiniteTagActive {
        const compact_ty = try self.pass.compactFiniteTagsType(source);
        var slot_tys = std.ArrayList(Type.TypeId).empty;
        defer slot_tys.deinit(self.pass.allocator);
        try self.pass.appendCompactIndexedValueTypes(alternative.payloads, &slot_tys);

        const payload_pats = try self.pass.allocator.alloc(Ast.PatId, slot_tys.items.len);
        defer self.pass.allocator.free(payload_pats);
        const payload_exprs = try self.pass.allocator.alloc(Ast.ExprId, slot_tys.items.len);
        defer self.pass.allocator.free(payload_exprs);

        for (slot_tys.items, payload_pats, payload_exprs) |slot_ty, *payload_pat, *payload_expr| {
            const local = try self.pass.program.addLocal(self.pass.symbols.fresh(), slot_ty);
            payload_pat.* = try self.pass.program.addPat(.{
                .ty = slot_ty,
                .data = .{ .bind = local },
            });
            payload_expr.* = try self.addExpr(.{
                .ty = slot_ty,
                .data = .{ .local = local },
            });
        }

        var index: usize = 0;
        const private_payloads = try self.privateStateIndexedValuesFromDemandedKnownValueExprs(alternative.payloads, payload_exprs, &index);
        if (index != payload_exprs.len) {
            Common.invariant("compact finite tag branch did not consume every payload slot");
        }

        return .{
            .pat = try self.pass.program.addPat(.{
                .ty = compact_ty,
                .data = .{ .tag = .{
                    .name = alternative.name,
                    .payloads = try self.pass.program.addPatSpan(payload_pats),
                } },
            }),
            .private_state = .{
                .ty = alternative.ty,
                .name = alternative.name,
                .payloads = private_payloads,
            },
        };
    }

    fn bindPatToMatchValue(
        self: *Cloner,
        pat_id: Ast.PatId,
        value: Value,
        body: Ast.ExprId,
        context: ValueDemand,
        unsafe_count: usize,
        pending_lets: *std.ArrayList(PendingLet),
    ) LowerError!MatchBindResult {
        const pat = self.pass.program.pats.items[@intFromEnum(pat_id)];
        switch (pat.data) {
            .bind => |local| {
                const prepared = (try self.valueForMatchLocal(local, value, body, unsafe_count, pending_lets)) orelse return .unsupported;
                try self.putSubst(local, prepared);
                return .{ .matched = prepared };
            },
            .wildcard => {
                const prepared = (try self.tryMakeReusableForMatch(value, pending_lets)) orelse return .unsupported;
                return .{ .matched = prepared };
            },
            .as => |as| {
                const as_uses = localUseCountInExpr(self.pass.program, as.local, body);
                const base = if (self.valueCanSubstitute(value) or
                    (unsafe_count == 1 and as_uses == 1 and localUseBeforeEffect(self.pass.program, as.local, body)))
                    value
                else
                    (try self.tryMakeReusableForMatch(value, pending_lets)) orelse return .unsupported;
                const prepared = switch (try self.bindPatToMatchValue(as.pattern, base, body, context, unsafe_count, pending_lets)) {
                    .matched => |prepared| prepared,
                    .no_match => return .no_match,
                    .unsupported => return .unsupported,
                };
                try self.putSubst(as.local, prepared);
                return .{ .matched = prepared };
            },
            .record => |fields_span| {
                const fields = try self.copyRecordDestructSpan(fields_span);
                defer self.pass.allocator.free(fields);
                if (recordFromValue(value)) |record| {
                    const prepared_fields = try self.pass.arena.allocator().alloc(FieldValue, record.fields.len);
                    for (record.fields, 0..) |field, index| {
                        if (recordPatField(self.pass.program, fields, field.name)) |field_pat| {
                            const prepared = switch (try self.bindPatToMatchValue(field_pat, field.value, body, context, unsafe_count, pending_lets)) {
                                .matched => |prepared| prepared,
                                .no_match => return .no_match,
                                .unsupported => return .unsupported,
                            };
                            prepared_fields[index] = .{
                                .name = field.name,
                                .value = prepared,
                            };
                        } else {
                            prepared_fields[index] = .{
                                .name = field.name,
                                .value = (try self.tryMakeReusableForMatch(field.value, pending_lets)) orelse return .unsupported,
                            };
                        }
                    }
                    return .{ .matched = .{ .record = .{
                        .ty = record.ty,
                        .fields = prepared_fields,
                    } } };
                }
                const projected_value = if (!self.valueCanSubstitute(value) and projectableExprFromValue(value) != null)
                    (try self.tryMakeReusableForMatch(value, pending_lets)) orelse return .unsupported
                else
                    value;
                for (fields) |field| {
                    const field_demand = try self.patternDemandInExpr(field.pattern, body, context);
                    const field_ty = self.pass.program.pats.items[@intFromEnum(field.pattern)].ty;
                    const field_value = (try self.fieldFromPatternValue(projected_value, field.name, field_ty)) orelse {
                        if (field_demand == .none) continue;
                        return .unsupported;
                    };
                    switch (try self.bindPatToMatchValue(field.pattern, field_value, body, context, unsafe_count, pending_lets)) {
                        .matched => {},
                        .no_match => return .no_match,
                        .unsupported => return .unsupported,
                    }
                }
                const prepared = (try self.tryMakeReusableForMatch(projected_value, pending_lets)) orelse return .unsupported;
                return .{ .matched = prepared };
            },
            .tuple => |items_span| {
                const pats = try self.copyPatSpan(items_span);
                defer self.pass.allocator.free(pats);
                if (tupleFromValue(value)) |tuple| {
                    if (pats.len != tuple.items.len) return .no_match;
                    const items = try self.pass.arena.allocator().alloc(Value, tuple.items.len);
                    for (pats, tuple.items, 0..) |child_pat, child_value, index| {
                        items[index] = switch (try self.bindPatToMatchValue(child_pat, child_value, body, context, unsafe_count, pending_lets)) {
                            .matched => |prepared| prepared,
                            .no_match => return .no_match,
                            .unsupported => return .unsupported,
                        };
                    }
                    return .{ .matched = .{ .tuple = .{
                        .ty = tuple.ty,
                        .items = items,
                    } } };
                }
                const projected_value = if (!self.valueCanSubstitute(value) and projectableExprFromValue(value) != null)
                    (try self.tryMakeReusableForMatch(value, pending_lets)) orelse return .unsupported
                else
                    value;
                for (pats, 0..) |child_pat, index| {
                    const item_demand = try self.patternDemandInExpr(child_pat, body, context);
                    const item_ty = self.pass.program.pats.items[@intFromEnum(child_pat)].ty;
                    const item_value = (try self.itemFromPatternValue(projected_value, @intCast(index), item_ty)) orelse {
                        if (item_demand == .none) continue;
                        return .unsupported;
                    };
                    switch (try self.bindPatToMatchValue(child_pat, item_value, body, context, unsafe_count, pending_lets)) {
                        .matched => {},
                        .no_match => return .no_match,
                        .unsupported => return .unsupported,
                    }
                }
                const prepared = (try self.tryMakeReusableForMatch(projected_value, pending_lets)) orelse return .unsupported;
                return .{ .matched = prepared };
            },
            .tag => |tag_pat| {
                const pats = try self.copyPatSpan(tag_pat.payloads);
                defer self.pass.allocator.free(pats);
                if (tagFromValue(value)) |tag| {
                    if (tag.name != tag_pat.name) return .no_match;
                    if (pats.len != tag.payloads.len) return .no_match;
                    const payloads = try self.pass.arena.allocator().alloc(Value, tag.payloads.len);
                    for (pats, tag.payloads, 0..) |child_pat, child_value, index| {
                        payloads[index] = switch (try self.bindPatToMatchValue(child_pat, child_value, body, context, unsafe_count, pending_lets)) {
                            .matched => |prepared| prepared,
                            .no_match => return .no_match,
                            .unsupported => return .unsupported,
                        };
                    }
                    return .{ .matched = .{ .tag = .{
                        .ty = tag.ty,
                        .name = tag.name,
                        .payloads = payloads,
                    } } };
                }

                const private_tag = switch (value) {
                    .private_state => |private_state| privateStateTag(private_state) orelse {
                        if (privateStateLeafMatchesZeroPayloadSingleTag(self.pass.program, private_state, tag_pat.name, pats.len)) {
                            return .{ .matched = value };
                        }
                        return .unsupported;
                    },
                    else => return .unsupported,
                };
                if (private_tag.name != tag_pat.name) return .no_match;
                for (pats, 0..) |child_pat, index| {
                    const payload_demand = try self.patternDemandInExpr(child_pat, body, context);
                    const child_value = privateStateIndexedValueByIndex(private_tag.payloads, @intCast(index)) orelse {
                        if (payload_demand == .none) continue;
                        return .unsupported;
                    };
                    switch (try self.bindPatToMatchValue(child_pat, .{ .private_state = child_value }, body, context, unsafe_count, pending_lets)) {
                        .matched => {},
                        .no_match => return .no_match,
                        .unsupported => return .unsupported,
                    }
                }
                return .{ .matched = value };
            },
            .nominal => |backing_pat| {
                const nominal = switch (value) {
                    .nominal => |nominal| nominal,
                    else => return .unsupported,
                };
                const backing = try self.pass.arena.allocator().create(Value);
                backing.* = switch (try self.bindPatToMatchValue(backing_pat, nominal.backing.*, body, context, unsafe_count, pending_lets)) {
                    .matched => |prepared| prepared,
                    .no_match => return .no_match,
                    .unsupported => return .unsupported,
                };
                return .{ .matched = .{ .nominal = .{
                    .ty = nominal.ty,
                    .backing = backing,
                } } };
            },
            // List patterns are not statically destructured during
            // specialization; keep the runtime match.
            .list,
            .int_lit,
            .dec_lit,
            .frac_f32_lit,
            .frac_f64_lit,
            .str_lit,
            .str_pattern,
            => return .unsupported,
        }
    }

    fn valueForMatchLocal(
        self: *Cloner,
        local: Ast.LocalId,
        value: Value,
        body: Ast.ExprId,
        unsafe_count: usize,
        pending_lets: *std.ArrayList(PendingLet),
    ) LowerError!?Value {
        const uses = localUseCountInExpr(self.pass.program, local, body);
        if (self.valueCanSubstitute(value) or
            (unsafe_count == 1 and uses == 1 and localUseBeforeEffect(self.pass.program, local, body) and self.valueCanMaterializePublic(value)))
        {
            return value;
        }
        return try self.tryMakeReusableForMatch(value, pending_lets);
    }

    fn valueForInlineLocal(
        self: *Cloner,
        local: Ast.LocalId,
        value: Value,
        body: Ast.ExprId,
        pending_lets: *std.ArrayList(PendingLet),
    ) LowerError!Value {
        const uses = localMaxUseCountPerPathInExpr(self.pass.program, local, body);
        if (uses == 0) return value;
        if (self.valueCanSubstitute(value) or
            (uses == 1 and localUseBeforeEffect(self.pass.program, local, body) and
                self.valueCanMaterializePublic(value) and self.valueReferencesInlineSafeBindings(value)))
        {
            return value;
        }
        if (!self.valueCanMaterializePublic(value)) return value;
        return try self.makeReusableForMatch(value, pending_lets);
    }

    /// A raw value substituted into an inlined body may be re-materialized at
    /// any public boundary the body reaches, so its expressions must reference
    /// only bindings that stay available there: direct references, active
    /// pending lets, and loop or state parameters. Region-scoped bindings do
    /// not qualify; such values are bound to a pending let instead.
    fn valueReferencesInlineSafeBindings(self: *Cloner, value: Value) bool {
        self.inline_safe_binding_check = true;
        defer self.inline_safe_binding_check = false;
        return self.valueLeafExprsReferenceAvailableBindings(value);
    }

    fn valueLeafExprsReferenceAvailableBindings(self: *Cloner, value: Value) bool {
        return switch (value) {
            .expr => |expr| self.exprReferencesAvailableBindings(expr),
            .expr_with_known_value => |known_value_expr| self.exprReferencesAvailableBindings(known_value_expr.expr),
            .let_ => |let_value| blk: {
                for (let_value.lets) |pending| {
                    const init_expr = switch (pending.value) {
                        .source => |source| source,
                        .cloned => |cloned| cloned,
                    };
                    if (!self.exprReferencesAvailableBindings(init_expr)) break :blk false;
                }
                break :blk self.valueLeafExprsReferenceAvailableBindings(let_value.body.*);
            },
            .if_ => |if_value| blk: {
                for (if_value.branches) |branch| {
                    if (!self.exprReferencesAvailableBindings(branch.cond)) break :blk false;
                    if (!self.valueLeafExprsReferenceAvailableBindings(branch.body)) break :blk false;
                }
                break :blk self.valueLeafExprsReferenceAvailableBindings(if_value.final_else.*);
            },
            .match_ => |match_value| blk: {
                if (!self.exprReferencesAvailableBindings(match_value.scrutinee)) break :blk false;
                for (match_value.branches) |branch| {
                    if (branch.guard) |guard| {
                        if (!self.exprReferencesAvailableBindings(guard)) break :blk false;
                    }
                    if (!self.valueLeafExprsReferenceAvailableBindings(branch.body)) break :blk false;
                }
                break :blk true;
            },
            .tag => |tag| blk: {
                for (tag.payloads) |payload| {
                    if (!self.valueLeafExprsReferenceAvailableBindings(payload)) break :blk false;
                }
                break :blk true;
            },
            .record => |record| blk: {
                for (record.fields) |field| {
                    if (!self.valueLeafExprsReferenceAvailableBindings(field.value)) break :blk false;
                }
                break :blk true;
            },
            .tuple => |tuple| blk: {
                for (tuple.items) |item| {
                    if (!self.valueLeafExprsReferenceAvailableBindings(item)) break :blk false;
                }
                break :blk true;
            },
            .nominal => |nominal| self.valueLeafExprsReferenceAvailableBindings(nominal.backing.*),
            .callable => |callable| blk: {
                for (callable.captures) |capture| {
                    if (!self.valueLeafExprsReferenceAvailableBindings(capture)) break :blk false;
                }
                break :blk true;
            },
            .finite_tags => |finite_tags| blk: {
                if (!self.exprReferencesAvailableBindings(finite_tags.selector)) break :blk false;
                for (finite_tags.alternatives) |alternative| {
                    for (alternative.payloads) |payload| {
                        if (!self.valueLeafExprsReferenceAvailableBindings(payload)) break :blk false;
                    }
                }
                break :blk true;
            },
            .finite_callables => |finite_callables| blk: {
                if (!self.exprReferencesAvailableBindings(finite_callables.selector)) break :blk false;
                for (finite_callables.alternatives) |alternative| {
                    for (alternative.captures) |capture| {
                        if (!self.valueLeafExprsReferenceAvailableBindings(capture)) break :blk false;
                    }
                }
                break :blk true;
            },
            .private_state => true,
        };
    }

    fn unsafeLeafCount(self: *Cloner, value: Value) usize {
        return switch (value) {
            .expr => |expr| if (self.exprCanSubstitute(expr)) 0 else 1,
            .expr_with_known_value => |known_value_expr| if (self.exprCanSubstitute(known_value_expr.expr)) 0 else 1,
            .let_ => |let_value| blk: {
                var count: usize = let_value.lets.len;
                count += self.unsafeLeafCount(let_value.body.*);
                break :blk count;
            },
            .if_ => |if_value| blk: {
                var count: usize = 0;
                for (if_value.branches) |branch| {
                    if (!self.exprCanSubstitute(branch.cond)) count += 1;
                    count += self.unsafeLeafCount(branch.body);
                }
                count += self.unsafeLeafCount(if_value.final_else.*);
                break :blk count;
            },
            .match_ => |match_value| blk: {
                var count: usize = if (self.exprCanSubstitute(match_value.scrutinee)) 0 else 1;
                for (match_value.branches) |branch| {
                    if (branch.guard) |guard| {
                        if (!self.exprCanSubstitute(guard)) count += 1;
                    }
                    count += self.unsafeLeafCount(branch.body);
                }
                break :blk count;
            },
            .tag => |tag| blk: {
                var count: usize = 0;
                for (tag.payloads) |payload| count += self.unsafeLeafCount(payload);
                break :blk count;
            },
            .record => |record| blk: {
                var count: usize = 0;
                for (record.fields) |field| count += self.unsafeLeafCount(field.value);
                break :blk count;
            },
            .tuple => |tuple| blk: {
                var count: usize = 0;
                for (tuple.items) |item| count += self.unsafeLeafCount(item);
                break :blk count;
            },
            .nominal => |nominal| self.unsafeLeafCount(nominal.backing.*),
            .callable => |callable| blk: {
                var count: usize = 0;
                for (callable.captures) |capture| count += self.unsafeLeafCount(capture);
                break :blk count;
            },
            .finite_tags => |finite_tags| blk: {
                var count: usize = if (self.exprCanSubstitute(finite_tags.selector)) 0 else 1;
                for (finite_tags.alternatives) |alternative| {
                    for (alternative.payloads) |payload| count += self.unsafeLeafCount(payload);
                }
                break :blk count;
            },
            .finite_callables => |finite_callables| blk: {
                var count: usize = if (self.exprCanSubstitute(finite_callables.selector)) 0 else 1;
                for (finite_callables.alternatives) |alternative| {
                    for (alternative.captures) |capture| count += self.unsafeLeafCount(capture);
                }
                break :blk count;
            },
            .private_state => 0,
        };
    }

    fn structuredValueFromExprWithKnownValue(
        self: *Cloner,
        known_value_expr: ExprWithKnownValue,
    ) LowerError!?*const Value {
        if (known_value_expr.value) |value| return value;
        const structured = (try self.structuredValueFromExpr(known_value_expr.expr, known_value_expr.known_value)) orelse return null;
        return try self.copyValue(structured);
    }

    fn structuredValueFromExpr(
        self: *Cloner,
        expr_id: Ast.ExprId,
        known_value: KnownValue,
    ) LowerError!?Value {
        if (try self.exprSubstitutedValueNoInline(expr_id)) |substituted| return substituted;

        const expr = self.pass.program.exprs.items[@intFromEnum(expr_id)];
        return switch (expr.data) {
            .tag => |tag| blk: {
                const known_tag = switch (known_value) {
                    .tag => |known_tag| known_tag,
                    else => return null,
                };
                const source_payloads = self.pass.program.exprSpan(tag.payloads);
                if (source_payloads.len != known_tag.payloads.len) return null;
                const payloads = try self.pass.arena.allocator().alloc(Value, source_payloads.len);
                for (source_payloads, known_tag.payloads, payloads) |payload_expr, payload_known, *out| {
                    out.* = (try self.structuredValueFromExpr(payload_expr, payload_known)) orelse
                        valueFromProjectedExpr(payload_expr, payload_known);
                }
                break :blk Value{ .tag = .{
                    .ty = known_tag.ty,
                    .name = known_tag.name,
                    .payloads = payloads,
                } };
            },
            .record => |fields_span| blk: {
                const known_record = switch (known_value) {
                    .record => |known_record| known_record,
                    else => return null,
                };
                const source_fields = self.pass.program.fieldExprSpan(fields_span);
                const fields = try self.pass.arena.allocator().alloc(FieldValue, source_fields.len);
                for (source_fields, fields) |field, *out| {
                    const field_known = fieldKnownValueFromKnownValue(self.pass.program, known_value, field.name) orelse
                        KnownValue{ .any = self.pass.program.exprs.items[@intFromEnum(field.value)].ty };
                    out.* = .{
                        .name = field.name,
                        .value = (try self.structuredValueFromExpr(field.value, field_known)) orelse
                            valueFromProjectedExpr(field.value, field_known),
                    };
                }
                break :blk Value{ .record = .{
                    .ty = known_record.ty,
                    .fields = fields,
                } };
            },
            .tuple => |items_span| blk: {
                const known_tuple = switch (known_value) {
                    .tuple => |known_tuple| known_tuple,
                    else => return null,
                };
                const source_items = self.pass.program.exprSpan(items_span);
                if (source_items.len != known_tuple.items.len) return null;
                const items = try self.pass.arena.allocator().alloc(Value, source_items.len);
                for (source_items, known_tuple.items, items) |item_expr, item_known, *out| {
                    out.* = (try self.structuredValueFromExpr(item_expr, item_known)) orelse
                        valueFromProjectedExpr(item_expr, item_known);
                }
                break :blk Value{ .tuple = .{
                    .ty = known_tuple.ty,
                    .items = items,
                } };
            },
            .nominal => |backing_expr| blk: {
                const known_nominal = switch (known_value) {
                    .nominal => |known_nominal| known_nominal,
                    else => return null,
                };
                const backing = try self.pass.arena.allocator().create(Value);
                backing.* = (try self.structuredValueFromExpr(backing_expr, known_nominal.backing.*)) orelse
                    valueFromProjectedExpr(backing_expr, known_nominal.backing.*);
                break :blk Value{ .nominal = .{
                    .ty = known_nominal.ty,
                    .backing = backing,
                } };
            },
            .fn_ref => |fn_id| blk: {
                const callable_value = try self.callableValue(expr.ty, fn_id);
                if (callable_value == .callable) break :blk callable_value;
                const known_callable = switch (known_value) {
                    .callable => |known_callable| known_callable,
                    else => return null,
                };
                if (known_callable.captures.len != 0) return null;
                break :blk valueFromProjectedExpr(expr_id, known_value);
            },
            .fn_ref_captures => blk: {
                break :blk valueFromProjectedExpr(expr_id, known_value);
            },
            .comptime_branch_taken => |taken| try self.structuredValueFromExpr(taken.body, known_value),
            .unit,
            .int_lit,
            .frac_f32_lit,
            .frac_f64_lit,
            .dec_lit,
            .str_lit,
            .static_data,
            .list,
            .local,
            .field_access,
            .tuple_access,
            => valueFromProjectedExpr(expr_id, known_value),
            else => null,
        };
    }

    fn tryMakeReusableForMatch(self: *Cloner, value: Value, pending_lets: *std.ArrayList(PendingLet)) LowerError!?Value {
        const pending_start = pending_lets.items.len;
        const change_start = self.changes.items.len;
        const result = try self.makeReusableForMatchOrNull(value, pending_lets);
        if (result == null) {
            pending_lets.shrinkRetainingCapacity(pending_start);
            self.restore(change_start);
            return null;
        }
        return result.?;
    }

    fn makeReusableForMatch(self: *Cloner, value: Value, pending_lets: *std.ArrayList(PendingLet)) LowerError!Value {
        return (try self.tryMakeReusableForMatch(value, pending_lets)) orelse
            Common.invariant("value could not be made reusable for match");
    }

    fn makeReusableForMatchOrNull(self: *Cloner, value: Value, pending_lets: *std.ArrayList(PendingLet)) LowerError!?Value {
        if (projectableExprFromValue(value)) |expr| {
            var seen = std.ArrayList(Ast.ExprId).empty;
            defer seen.deinit(self.pass.allocator);
            if (try self.substitutedExprValueAvoidingCycles(expr, &seen)) |substituted| {
                if (!valueIsExpr(substituted, expr)) {
                    return try self.tryMakeReusableForMatch(substituted, pending_lets);
                }
            }
        }
        if (self.valueCanSubstitute(value)) return value;
        if (self.valueContainsEscapingControlTransfer(value)) return value;
        return switch (value) {
            .expr => |expr| blk: {
                const ty = self.pass.program.exprs.items[@intFromEnum(expr)].ty;
                const pending_value = (try self.tryPendingLetValueForReusableExpr(expr, pending_lets.items)) orelse return null;
                const local = try self.pass.program.addLocal(self.pass.symbols.fresh(), ty);
                try pending_lets.append(self.pass.allocator, .{
                    .local = local,
                    .ty = ty,
                    .value = pending_value,
                });
                break :blk Value{ .expr = try self.addExpr(.{
                    .ty = ty,
                    .data = .{ .local = local },
                }) };
            },
            .expr_with_known_value => |known_value_expr| blk: {
                const ty = self.pass.program.exprs.items[@intFromEnum(known_value_expr.expr)].ty;
                const pending_value = (try self.tryPendingLetValueForReusableExpr(known_value_expr.expr, pending_lets.items)) orelse return null;
                const local = try self.pass.program.addLocal(self.pass.symbols.fresh(), ty);
                const structured_value = try self.structuredValueFromExprWithKnownValue(known_value_expr);
                try pending_lets.append(self.pass.allocator, .{
                    .local = local,
                    .ty = ty,
                    .value = pending_value,
                    .known_value = known_value_expr.known_value,
                    .structured_value = structured_value,
                });
                const local_expr = try self.addExpr(.{
                    .ty = ty,
                    .data = .{ .local = local },
                });
                break :blk Value{ .expr_with_known_value = .{
                    .expr = local_expr,
                    .known_value = known_value_expr.known_value,
                    .value = structured_value,
                } };
            },
            .let_ => |let_value| blk: {
                var body_pending_lets = std.ArrayList(PendingLet).empty;
                defer body_pending_lets.deinit(self.pass.allocator);

                const change_start = self.changes.items.len;
                defer self.restore(change_start);
                const pending_start = self.activePendingLetsLen();
                const scoped_start = try self.pushPendingLetScope(let_value.lets);
                defer self.popPendingLetScope(scoped_start, pending_start);

                const body = (try self.tryMakeReusableForMatch(let_value.body.*, &body_pending_lets)) orelse return null;
                const lets = try self.pass.arena.allocator().alloc(PendingLet, let_value.lets.len + body_pending_lets.items.len);
                @memcpy(lets[0..let_value.lets.len], let_value.lets);
                @memcpy(lets[let_value.lets.len..], body_pending_lets.items);
                break :blk Value{ .let_ = .{
                    .lets = lets,
                    .body = try self.copyValue(body),
                } };
            },
            .if_ => |if_value| blk: {
                const branches = try self.pass.arena.allocator().alloc(IfValueBranch, if_value.branches.len);
                for (if_value.branches, 0..) |branch, index| {
                    var branch_pending_lets = std.ArrayList(PendingLet).empty;
                    defer branch_pending_lets.deinit(self.pass.allocator);
                    const branch_body = (try self.tryMakeReusableForMatch(branch.body, &branch_pending_lets)) orelse return null;
                    branches[index] = .{
                        .cond = (try self.tryMakeExprReusableForMatch(branch.cond, pending_lets)) orelse return null,
                        .body = try self.wrapPendingLets(branch_body, branch_pending_lets.items, true),
                    };
                }
                const final_else = try self.pass.arena.allocator().create(Value);
                var else_pending_lets = std.ArrayList(PendingLet).empty;
                defer else_pending_lets.deinit(self.pass.allocator);
                const else_body = (try self.tryMakeReusableForMatch(if_value.final_else.*, &else_pending_lets)) orelse return null;
                final_else.* = try self.wrapPendingLets(else_body, else_pending_lets.items, true);
                break :blk Value{ .if_ = .{
                    .ty = if_value.ty,
                    .branches = branches,
                    .final_else = final_else,
                } };
            },
            .match_ => |match_value| blk: {
                const branches = try self.pass.arena.allocator().alloc(MatchValueBranch, match_value.branches.len);
                for (match_value.branches, 0..) |branch, index| {
                    const scoped_start = self.scopedLocalsLen();
                    defer self.restoreScopedLocals(scoped_start);
                    try self.appendPatternScopedLocals(branch.pat);

                    var branch_pending_lets = std.ArrayList(PendingLet).empty;
                    defer branch_pending_lets.deinit(self.pass.allocator);
                    const branch_body = (try self.tryMakeReusableForMatch(branch.body, &branch_pending_lets)) orelse return null;
                    branches[index] = .{
                        .pat = branch.pat,
                        .guard = if (branch.guard) |guard| (try self.tryMakeExprReusableForMatch(guard, pending_lets)) orelse return null else null,
                        .body = try self.wrapPendingLets(branch_body, branch_pending_lets.items, true),
                        .source = branch.source,
                    };
                }
                break :blk Value{ .match_ = .{
                    .ty = match_value.ty,
                    .scrutinee = (try self.tryMakeExprReusableForMatch(match_value.scrutinee, pending_lets)) orelse return null,
                    .branches = branches,
                    .comptime_site = match_value.comptime_site,
                } };
            },
            .tag => |tag| blk: {
                const payloads = try self.pass.arena.allocator().alloc(Value, tag.payloads.len);
                for (tag.payloads, 0..) |payload, index| {
                    payloads[index] = (try self.tryMakeReusableForMatch(payload, pending_lets)) orelse return null;
                }
                break :blk Value{ .tag = .{
                    .ty = tag.ty,
                    .name = tag.name,
                    .payloads = payloads,
                } };
            },
            .record => |record| blk: {
                const fields = try self.pass.arena.allocator().alloc(FieldValue, record.fields.len);
                for (record.fields, 0..) |field, index| {
                    fields[index] = .{
                        .name = field.name,
                        .value = (try self.tryMakeReusableForMatch(field.value, pending_lets)) orelse return null,
                    };
                }
                break :blk Value{ .record = .{
                    .ty = record.ty,
                    .fields = fields,
                } };
            },
            .tuple => |tuple| blk: {
                const items = try self.pass.arena.allocator().alloc(Value, tuple.items.len);
                for (tuple.items, 0..) |item, index| {
                    items[index] = (try self.tryMakeReusableForMatch(item, pending_lets)) orelse return null;
                }
                break :blk Value{ .tuple = .{
                    .ty = tuple.ty,
                    .items = items,
                } };
            },
            .nominal => |nominal| blk: {
                const backing = try self.pass.arena.allocator().create(Value);
                backing.* = (try self.tryMakeReusableForMatch(nominal.backing.*, pending_lets)) orelse return null;
                break :blk Value{ .nominal = .{
                    .ty = nominal.ty,
                    .backing = backing,
                } };
            },
            .callable => |callable| blk: {
                const captures = try self.pass.arena.allocator().alloc(Value, callable.captures.len);
                for (callable.captures, 0..) |capture, index| {
                    captures[index] = (try self.tryMakeReusableForMatch(capture, pending_lets)) orelse return null;
                }
                break :blk Value{ .callable = .{
                    .ty = callable.ty,
                    .fn_id = callable.fn_id,
                    .captures = captures,
                } };
            },
            .finite_tags => |finite_tags| blk: {
                const alternatives = try self.pass.arena.allocator().alloc(TagValue, finite_tags.alternatives.len);
                for (finite_tags.alternatives, alternatives) |alternative, *out| {
                    const payloads = try self.pass.arena.allocator().alloc(Value, alternative.payloads.len);
                    for (alternative.payloads, payloads) |payload, *payload_out| {
                        payload_out.* = (try self.tryMakeReusableForMatch(payload, pending_lets)) orelse return null;
                    }
                    out.* = .{
                        .ty = alternative.ty,
                        .name = alternative.name,
                        .payloads = payloads,
                    };
                }
                break :blk Value{ .finite_tags = .{
                    .ty = finite_tags.ty,
                    .selector = (try self.tryMakeExprReusableForMatch(finite_tags.selector, pending_lets)) orelse return null,
                    .alternatives = alternatives,
                } };
            },
            .finite_callables => |finite_callables| blk: {
                const alternatives = try self.pass.arena.allocator().alloc(CallableValue, finite_callables.alternatives.len);
                for (finite_callables.alternatives, alternatives) |alternative, *out| {
                    const captures = try self.pass.arena.allocator().alloc(Value, alternative.captures.len);
                    for (alternative.captures, captures) |capture, *capture_out| {
                        capture_out.* = (try self.tryMakeReusableForMatch(capture, pending_lets)) orelse return null;
                    }
                    out.* = .{
                        .ty = alternative.ty,
                        .fn_id = alternative.fn_id,
                        .captures = captures,
                    };
                }
                break :blk Value{ .finite_callables = .{
                    .ty = finite_callables.ty,
                    .selector = (try self.tryMakeExprReusableForMatch(finite_callables.selector, pending_lets)) orelse return null,
                    .alternatives = alternatives,
                } };
            },
            .private_state => |private_state| Value{ .private_state = (try self.tryMakePrivateStateReusableForMatch(private_state, pending_lets)) orelse return null },
        };
    }

    fn tryMakePrivateStateReusableForMatch(
        self: *Cloner,
        value: PrivateStateValue,
        pending_lets: *std.ArrayList(PendingLet),
    ) LowerError!?PrivateStateValue {
        return try self.makePrivateStateReusableForMatchOrNull(value, pending_lets);
    }

    fn makePrivateStateReusableForMatch(
        self: *Cloner,
        value: PrivateStateValue,
        pending_lets: *std.ArrayList(PendingLet),
    ) LowerError!PrivateStateValue {
        return (try self.tryMakePrivateStateReusableForMatch(value, pending_lets)) orelse
            Common.invariant("private state could not be made reusable for match");
    }

    fn makePrivateStateReusableForMatchOrNull(
        self: *Cloner,
        value: PrivateStateValue,
        pending_lets: *std.ArrayList(PendingLet),
    ) LowerError!?PrivateStateValue {
        return switch (value) {
            .leaf => |leaf| .{ .leaf = .{
                .ty = leaf.ty,
                .expr = (try self.tryMakeExprReusableForMatch(leaf.expr, pending_lets)) orelse return null,
            } },
            .tag => |tag| blk: {
                const payloads = try self.pass.arena.allocator().alloc(PrivateStateIndexedValue, tag.payloads.len);
                for (tag.payloads, payloads) |payload, *out| {
                    out.* = .{
                        .index = payload.index,
                        .value = (try self.tryMakePrivateStateReusableForMatch(payload.value, pending_lets)) orelse return null,
                    };
                }
                break :blk PrivateStateValue{ .tag = .{
                    .ty = tag.ty,
                    .name = tag.name,
                    .payloads = payloads,
                } };
            },
            .record => |record| blk: {
                const fields = try self.pass.arena.allocator().alloc(PrivateStateField, record.fields.len);
                for (record.fields, fields) |field, *out| {
                    out.* = .{
                        .name = field.name,
                        .value = (try self.tryMakePrivateStateReusableForMatch(field.value, pending_lets)) orelse return null,
                    };
                }
                break :blk PrivateStateValue{ .record = .{
                    .ty = record.ty,
                    .fields = fields,
                } };
            },
            .tuple => |tuple| blk: {
                const items = try self.pass.arena.allocator().alloc(PrivateStateIndexedValue, tuple.items.len);
                for (tuple.items, items) |item, *out| {
                    out.* = .{
                        .index = item.index,
                        .value = (try self.tryMakePrivateStateReusableForMatch(item.value, pending_lets)) orelse return null,
                    };
                }
                break :blk PrivateStateValue{ .tuple = .{
                    .ty = tuple.ty,
                    .items = items,
                } };
            },
            .nominal => |nominal| blk: {
                const backing = if (nominal.backing) |backing_value| backing: {
                    const stored = try self.pass.arena.allocator().create(PrivateStateValue);
                    stored.* = (try self.tryMakePrivateStateReusableForMatch(backing_value.*, pending_lets)) orelse return null;
                    break :backing stored;
                } else null;
                break :blk PrivateStateValue{ .nominal = .{
                    .ty = nominal.ty,
                    .backing = backing,
                } };
            },
            .callable => |callable| blk: {
                const captures = try self.pass.arena.allocator().alloc(PrivateStateIndexedValue, callable.captures.len);
                for (callable.captures, captures) |capture, *out| {
                    out.* = .{
                        .index = capture.index,
                        .value = (try self.tryMakePrivateStateReusableForMatch(capture.value, pending_lets)) orelse return null,
                    };
                }
                break :blk PrivateStateValue{ .callable = .{
                    .ty = callable.ty,
                    .fn_id = callable.fn_id,
                    .captures = captures,
                    .loop_origin = callable.loop_origin,
                } };
            },
            .compact_finite_tags => |finite_tags| .{ .compact_finite_tags = .{
                .source = finite_tags.source,
                .compact_expr = (try self.tryMakeExprReusableForMatch(finite_tags.compact_expr, pending_lets)) orelse return null,
            } },
            .compact_finite_callables => |finite_callables| .{ .compact_finite_callables = .{
                .source = finite_callables.source,
                .compact_expr = (try self.tryMakeExprReusableForMatch(finite_callables.compact_expr, pending_lets)) orelse return null,
            } },
        };
    }

    fn tryMakeExprReusableForMatch(
        self: *Cloner,
        expr: Ast.ExprId,
        pending_lets: *std.ArrayList(PendingLet),
    ) LowerError!?Ast.ExprId {
        const pending_start = pending_lets.items.len;
        const result = try self.makeExprReusableForMatchOrNull(expr, pending_lets);
        if (result == null) {
            pending_lets.shrinkRetainingCapacity(pending_start);
            return null;
        }
        return result.?;
    }

    fn makeExprReusableForMatch(
        self: *Cloner,
        expr: Ast.ExprId,
        pending_lets: *std.ArrayList(PendingLet),
    ) LowerError!Ast.ExprId {
        return (try self.tryMakeExprReusableForMatch(expr, pending_lets)) orelse
            Common.invariant("expression could not be made reusable for match");
    }

    fn makeExprReusableForMatchOrNull(
        self: *Cloner,
        expr: Ast.ExprId,
        pending_lets: *std.ArrayList(PendingLet),
    ) LowerError!?Ast.ExprId {
        if (self.exprCanSubstitute(expr)) return expr;
        if (exprContainsEscapingControlTransfer(self.pass.program, expr)) return expr;

        const ty = self.pass.program.exprs.items[@intFromEnum(expr)].ty;
        const pending_value = (try self.tryPendingLetValueForReusableExpr(expr, pending_lets.items)) orelse return null;
        const local = try self.pass.program.addLocal(self.pass.symbols.fresh(), ty);
        try pending_lets.append(self.pass.allocator, .{
            .local = local,
            .ty = ty,
            .value = pending_value,
            .known_value = try self.pass.constructorKnownValue(expr),
        });
        return try self.addExpr(.{
            .ty = ty,
            .data = .{ .local = local },
        });
    }

    fn tryPendingLetValueForReusableExpr(
        self: *Cloner,
        expr: Ast.ExprId,
        previous_pending_lets: []const PendingLet,
    ) LowerError!?PendingLetValue {
        if (self.exprReferencesAvailableBindings(expr)) return .{ .cloned = expr };
        if (try self.exprReferencesAvailableBindingsWithPendingLets(expr, previous_pending_lets)) {
            return .{ .source = expr };
        }
        const cloned = try self.cloneExpr(expr);
        if (self.exprReferencesAvailableBindings(cloned)) {
            return .{ .cloned = cloned };
        }
        return null;
    }

    fn exprReferencesAvailableBindingsWithPendingLets(
        self: *Cloner,
        expr: Ast.ExprId,
        pending_lets: []const PendingLet,
    ) LowerError!bool {
        const change_start = self.changes.items.len;
        defer self.restore(change_start);

        const pending_start = self.activePendingLetsLen();
        const scoped_start = try self.pushPendingLetScope(pending_lets);
        defer self.popPendingLetScope(scoped_start, pending_start);

        return self.exprReferencesAvailableBindings(expr);
    }

    fn valueCanMaterializePublic(self: *Cloner, value: Value) bool {
        switch (value) {
            .expr => |expr| return self.exprReferencesAvailableBindings(expr),
            .expr_with_known_value => |known_value_expr| return self.exprReferencesAvailableBindings(known_value_expr.expr),
            .let_ => |let_value| return self.valueCanMaterializePublic(let_value.body.*),
            .if_ => |if_value| {
                for (if_value.branches) |branch| {
                    if (!self.valueCanMaterializePublic(branch.body)) return false;
                }
                return self.valueCanMaterializePublic(if_value.final_else.*);
            },
            .match_ => |match_value| {
                for (match_value.branches) |branch| {
                    if (!self.valueCanMaterializePublic(branch.body)) return false;
                }
                return true;
            },
            .tag => |tag| {
                for (tag.payloads) |payload| {
                    if (!self.valueCanMaterializePublic(payload)) return false;
                }
                return true;
            },
            .record => |record| {
                for (record.fields) |field| {
                    if (!self.valueCanMaterializePublic(field.value)) {
                        return false;
                    }
                }
                return true;
            },
            .tuple => |tuple| {
                for (tuple.items) |item| {
                    if (!self.valueCanMaterializePublic(item)) return false;
                }
                return true;
            },
            .nominal => |nominal| {
                const can_materialize = self.valueCanMaterializePublic(nominal.backing.*);
                return can_materialize;
            },
            .callable => |callable| return self.callableCapturesCanMaterializePublic(callable),
            .finite_tags => |finite_tags| {
                for (finite_tags.alternatives) |alternative| {
                    for (alternative.payloads) |payload| {
                        if (!self.valueCanMaterializePublic(payload)) return false;
                    }
                }
                return true;
            },
            .finite_callables => |finite_callables| {
                for (finite_callables.alternatives) |alternative| {
                    for (alternative.captures) |capture| {
                        if (!self.valueCanMaterializePublic(capture)) return false;
                    }
                }
                return true;
            },
            .private_state => |private_state| return privateStateCanMaterializePublic(self.pass.program, private_state) and
                self.privateStateLeavesCanMaterializePublic(private_state),
        }
    }

    fn privateStateLeavesCanMaterializePublic(self: *Cloner, value: PrivateStateValue) bool {
        return switch (value) {
            .leaf => |leaf| self.exprReferencesAvailableBindings(leaf.expr),
            .tag => |tag| blk: {
                for (tag.payloads) |payload| {
                    if (!self.privateStateLeavesCanMaterializePublic(payload.value)) break :blk false;
                }
                break :blk true;
            },
            .record => |record| blk: {
                for (record.fields) |field| {
                    if (!self.privateStateLeavesCanMaterializePublic(field.value)) break :blk false;
                }
                break :blk true;
            },
            .tuple => |tuple| blk: {
                for (tuple.items) |item| {
                    if (!self.privateStateLeavesCanMaterializePublic(item.value)) break :blk false;
                }
                break :blk true;
            },
            .nominal => |nominal| if (nominal.backing) |backing|
                self.privateStateLeavesCanMaterializePublic(backing.*)
            else
                true,
            .callable => |callable| blk: {
                for (callable.captures) |capture| {
                    if (!self.privateStateLeavesCanMaterializePublic(capture.value)) break :blk false;
                }
                break :blk true;
            },
            .compact_finite_tags,
            .compact_finite_callables,
            => false,
        };
    }

    fn callableCapturesCanMaterializePublic(self: *Cloner, callable: CallableValue) bool {
        for (callable.captures) |capture| {
            if (!self.valueCanMaterializePublic(capture)) return false;
        }
        return true;
    }

    fn privateStateValueFromIfDemand(
        self: *Cloner,
        if_value: IfValue,
        demand: ValueDemand,
        pending_lets: ?*std.ArrayList(PendingLet),
    ) LowerError!?PrivateStateValue {
        return switch (demand) {
            .tag => try self.privateFiniteTagsFromIfDemand(if_value, demand, pending_lets),
            .callable => try self.privateFiniteCallablesFromIfDemand(if_value, demand, pending_lets),
            else => null,
        };
    }

    fn privateStateValueFromMatchDemand(
        self: *Cloner,
        match_value: MatchValue,
        demand: ValueDemand,
        pending_lets: ?*std.ArrayList(PendingLet),
    ) LowerError!?PrivateStateValue {
        return switch (demand) {
            .tag => try self.privateFiniteTagsFromMatchDemand(match_value, demand, pending_lets),
            .callable => try self.privateFiniteCallablesFromMatchDemand(match_value, demand, pending_lets),
            else => null,
        };
    }

    fn privateFiniteCallablesFromIfDemand(
        self: *Cloner,
        if_value: IfValue,
        demand: ValueDemand,
        pending_lets: ?*std.ArrayList(PendingLet),
    ) LowerError!?PrivateStateValue {
        return try self.privateCompactFiniteCallablesFromDemand(.{ .if_ = if_value }, demand, pending_lets);
    }

    fn privateFiniteCallablesFromMatchDemand(
        self: *Cloner,
        match_value: MatchValue,
        demand: ValueDemand,
        pending_lets: ?*std.ArrayList(PendingLet),
    ) LowerError!?PrivateStateValue {
        return try self.privateCompactFiniteCallablesFromDemand(.{ .match_ = match_value }, demand, pending_lets);
    }

    fn privateFiniteTagsFromIfDemand(
        self: *Cloner,
        if_value: IfValue,
        demand: ValueDemand,
        pending_lets: ?*std.ArrayList(PendingLet),
    ) LowerError!?PrivateStateValue {
        return try self.privateCompactFiniteTagsFromDemand(.{ .if_ = if_value }, demand, pending_lets);
    }

    fn privateFiniteTagsFromMatchDemand(
        self: *Cloner,
        match_value: MatchValue,
        demand: ValueDemand,
        pending_lets: ?*std.ArrayList(PendingLet),
    ) LowerError!?PrivateStateValue {
        return try self.privateCompactFiniteTagsFromDemand(.{ .match_ = match_value }, demand, pending_lets);
    }

    fn privateCompactFiniteTagsFromDemand(
        self: *Cloner,
        value: Value,
        demand: ValueDemand,
        maybe_pending_lets: ?*std.ArrayList(PendingLet),
    ) LowerError!?PrivateStateValue {
        const known_value = (try self.knownValueFromValueAllowingSparsePrivateState(value)) orelse KnownValue{ .any = valueType(self.pass.program, value) };
        const demanded = (try demandedKnownValueFromDemand(
            self,
            self.pass.program,
            self.pass.arena.allocator(),
            known_value,
            demand,
        )) orelse return null;
        const finite_tags = switch (demanded) {
            .finite_tags => |finite_tags| finite_tags,
            else => return null,
        };

        var local_pending_lets = std.ArrayList(PendingLet).empty;
        defer local_pending_lets.deinit(self.pass.allocator);
        const pending_lets = maybe_pending_lets orelse &local_pending_lets;

        var compact_expr = (try self.compactFiniteTagsExpr(finite_tags, value, pending_lets)) orelse return null;
        if (maybe_pending_lets == null) {
            compact_expr = try self.wrapPendingLetsAroundExpr(
                self.pass.program.exprs.items[@intFromEnum(compact_expr)].ty,
                compact_expr,
                local_pending_lets.items,
            );
        }
        return .{ .compact_finite_tags = .{
            .source = finite_tags,
            .compact_expr = compact_expr,
        } };
    }

    fn privateCompactFiniteCallablesFromDemand(
        self: *Cloner,
        value: Value,
        demand: ValueDemand,
        maybe_pending_lets: ?*std.ArrayList(PendingLet),
    ) LowerError!?PrivateStateValue {
        const known_value = (try self.knownValueFromValueAllowingSparsePrivateState(value)) orelse return null;
        const demanded = (try demandedKnownValueFromDemand(
            self,
            self.pass.program,
            self.pass.arena.allocator(),
            known_value,
            demand,
        )) orelse return null;
        const finite_callables = switch (demanded) {
            .finite_callables => |finite_callables| finite_callables,
            .callable => |callable| blk: {
                const alternatives = try self.pass.arena.allocator().alloc(DemandedKnownCallable, 1);
                alternatives[0] = callable;
                break :blk DemandedKnownCallables{
                    .ty = callable.ty,
                    .alternatives = alternatives,
                };
            },
            else => return null,
        };

        var local_pending_lets = std.ArrayList(PendingLet).empty;
        defer local_pending_lets.deinit(self.pass.allocator);
        const pending_lets = maybe_pending_lets orelse &local_pending_lets;

        var compact_expr = (try self.compactFiniteCallablesExpr(finite_callables, value, pending_lets)) orelse return null;
        if (maybe_pending_lets == null) {
            compact_expr = try self.wrapPendingLetsAroundExpr(
                self.pass.program.exprs.items[@intFromEnum(compact_expr)].ty,
                compact_expr,
                local_pending_lets.items,
            );
        }
        return .{ .compact_finite_callables = .{
            .source = finite_callables,
            .compact_expr = compact_expr,
        } };
    }

    fn knownValueFromValueAllowingSparsePrivateState(
        self: *Cloner,
        value: Value,
    ) Allocator.Error!?KnownValue {
        return switch (value) {
            .let_ => |let_value| try self.knownValueFromValueAllowingSparsePrivateState(let_value.body.*),
            .if_ => |if_value| blk: {
                var joined: ?KnownValue = null;
                for (if_value.branches) |branch| {
                    const branch_known = (try self.knownValueFromValueAllowingSparsePrivateState(branch.body)) orelse break :blk null;
                    joined = if (joined) |existing|
                        (try joinKnownValuesInArena(self.pass.program, self.pass.arena.allocator(), existing, branch_known)) orelse break :blk null
                    else
                        branch_known;
                }
                const final_known = (try self.knownValueFromValueAllowingSparsePrivateState(if_value.final_else.*)) orelse break :blk null;
                break :blk if (joined) |existing|
                    (try joinKnownValuesInArena(self.pass.program, self.pass.arena.allocator(), existing, final_known)) orelse null
                else
                    final_known;
            },
            .match_ => |match_value| blk: {
                var joined: ?KnownValue = null;
                for (match_value.branches) |branch| {
                    const branch_known = (try self.knownValueFromValueAllowingSparsePrivateState(branch.body)) orelse break :blk null;
                    joined = if (joined) |existing|
                        (try joinKnownValuesInArena(self.pass.program, self.pass.arena.allocator(), existing, branch_known)) orelse break :blk null
                    else
                        branch_known;
                }
                break :blk joined;
            },
            .private_state => |private_state| try sparseKnownValueFromPrivateState(self.pass.program, self.pass.arena.allocator(), private_state),
            else => try self.pass.knownValueFromValue(value),
        };
    }

    fn wrapPendingLets(self: *Cloner, body: Value, pending_lets: []const PendingLet, preserve_known_value: bool) LowerError!Value {
        if (pending_lets.len == 0) return body;

        if (self.valueContainsEscapingControlTransfer(body)) {
            if (try self.wrapPendingLetsAroundControlTransferValue(valueType(self.pass.program, body), body, pending_lets)) |wrapped| return wrapped;
            const lets = try self.pass.arena.allocator().dupe(PendingLet, pending_lets);
            return .{ .let_ = .{
                .lets = lets,
                .body = try self.copyValue(body),
            } };
        }

        const known_value = if (preserve_known_value) try self.pass.knownValueFromValue(body) else null;
        if (known_value != null or !self.valueCanMaterializePublic(body)) {
            const lets = try self.pass.arena.allocator().dupe(PendingLet, pending_lets);
            return .{ .let_ = .{
                .lets = lets,
                .body = try self.copyValue(body),
            } };
        }

        const ty = valueType(self.pass.program, body);
        const change_start = self.changes.items.len;
        defer self.restore(change_start);
        const pending_start = self.activePendingLetsLen();
        const scoped_start = try self.pushPendingLetScope(pending_lets);
        defer self.popPendingLetScope(scoped_start, pending_start);

        var result = try self.materialize(body);
        result = try self.wrapPendingLetsAroundExpr(ty, result, pending_lets);
        return .{ .expr = result };
    }

    fn controlTransferValueExpr(self: *Cloner, value: Value) LowerError!?Ast.ExprId {
        return switch (value) {
            .expr => |expr| expr,
            .let_ => |let_value| blk: {
                const body_expr = (try self.controlTransferValueExpr(let_value.body.*)) orelse break :blk null;
                break :blk try self.wrapPendingLetsAroundExpr(valueType(self.pass.program, let_value.body.*), body_expr, let_value.lets);
            },
            else => null,
        };
    }

    fn wrapPendingLetsAroundControlTransferValue(
        self: *Cloner,
        ty: Type.TypeId,
        body: Value,
        pending_lets: []const PendingLet,
    ) LowerError!?Value {
        const body_expr = (try self.controlTransferValueExpr(body)) orelse return null;
        return Value{ .expr = try self.wrapPendingLetsAroundExpr(ty, body_expr, pending_lets) };
    }

    fn wrapPendingLetsAroundExpr(
        self: *Cloner,
        ty: Type.TypeId,
        body_expr: Ast.ExprId,
        pending_lets: []const PendingLet,
    ) LowerError!Ast.ExprId {
        var result = body_expr;
        var index = pending_lets.len;
        while (index > 0) {
            index -= 1;
            const pending = pending_lets[index];
            const pat = try self.pass.program.addPat(.{
                .ty = pending.ty,
                .data = .{ .bind = pending.local },
            });
            const value_expr = blk: {
                const change_start = self.changes.items.len;
                defer self.restore(change_start);

                const pending_start = self.activePendingLetsLen();
                const scoped_start = try self.pushPendingLetScope(pending_lets[0..index]);
                defer self.popPendingLetScope(scoped_start, pending_start);

                break :blk try self.pendingLetValueExpr(pending.value);
            };
            result = try self.addExpr(.{ .ty = ty, .data = .{ .let_ = .{
                .bind = pat,
                .value = value_expr,
                .rest = result,
            } } });
        }
        return result;
    }

    fn blockPendingLetsAroundExpr(
        self: *Cloner,
        ty: Type.TypeId,
        body_expr: Ast.ExprId,
        pending_lets: []const PendingLet,
    ) LowerError!Ast.ExprId {
        if (pending_lets.len == 0) return body_expr;

        var statements = std.ArrayList(Ast.StmtId).empty;
        defer statements.deinit(self.pass.allocator);

        const scoped_start = self.scopedLocalsLen();
        defer self.restoreScopedLocals(scoped_start);

        try self.appendPendingLetStmts(pending_lets, &statements);

        return try self.addExpr(.{ .ty = ty, .data = .{ .block = .{
            .statements = try self.pass.program.addStmtSpan(statements.items),
            .final_expr = body_expr,
        } } });
    }

    fn pendingLetValueExpr(self: *Cloner, value: PendingLetValue) LowerError!Ast.ExprId {
        return switch (value) {
            .source => |expr| try self.cloneExpr(expr),
            .cloned => |expr| expr,
        };
    }

    fn cloneCaseOfCaseValue(
        self: *Cloner,
        ty: Type.TypeId,
        scrutinee_expr: Ast.ExprId,
        outer_branches_span: Ast.Span(Ast.Branch),
    ) LowerError!?Value {
        const scrutinee_data = self.pass.program.exprs.items[@intFromEnum(scrutinee_expr)].data;
        const inner_match = switch (scrutinee_data) {
            .match_ => |match| match,
            else => return null,
        };

        const outer_branches = self.pass.program.branchSpan(outer_branches_span);
        for (outer_branches) |branch| {
            if (branch.guard != null) return null;
        }

        const inner_branches = try self.pass.allocator.dupe(Ast.Branch, self.pass.program.branchSpan(inner_match.branches));
        defer self.pass.allocator.free(inner_branches);

        var rewritten = try self.pass.allocator.alloc(Ast.Branch, inner_branches.len);
        defer self.pass.allocator.free(rewritten);

        for (inner_branches, 0..) |inner_branch, index| {
            const inner_value = try self.cloneExprValue(inner_branch.body);
            const outer_value = (try self.simplifyKnownMatchValueMode(ty, inner_value, outer_branches_span, .speculative, true)) orelse return null;
            rewritten[index] = .{
                .pat = inner_branch.pat,
                .guard = inner_branch.guard,
                .body = try self.materialize(outer_value),
            };
        }

        return .{ .expr = try self.addExpr(.{ .ty = ty, .data = .{ .match_ = .{
            .scrutinee = inner_match.scrutinee,
            .branches = try self.pass.program.addBranchSpan(rewritten),
            .comptime_site = inner_match.comptime_site,
        } } }) };
    }

    fn inlineCallableCallValue(
        self: *Cloner,
        ty: Type.TypeId,
        callable: CallableValue,
        args_span: Ast.Span(Ast.ExprId),
        demand_result_known_value: bool,
    ) LowerError!Value {
        for (self.inline_stack.items) |active| {
            if (active.fn_id == callable.fn_id) {
                return .{ .expr = try self.addExpr(.{ .ty = ty, .data = .{ .call_value = .{
                    .callee = try self.materialize(.{ .callable = callable }),
                    .args = try self.cloneExprSpan(args_span),
                } } }) };
            }
        }

        const source_fn = self.pass.program.fns.items[@intFromEnum(callable.fn_id)];
        const body = self.pass.originalBody(callable.fn_id) orelse switch (source_fn.body) {
            .roc => |body| body,
            .hosted => {
                return .{ .expr = try self.addExpr(.{ .ty = ty, .data = .{ .call_value = .{
                    .callee = try self.materialize(.{ .callable = callable }),
                    .args = try self.cloneExprSpan(args_span),
                } } }) };
            },
        };
        if (exprContainsReturn(self.pass.program, body)) {
            return .{ .expr = try self.addExpr(.{ .ty = ty, .data = .{ .call_value = .{
                .callee = try self.materialize(.{ .callable = callable }),
                .args = try self.cloneExprSpan(args_span),
            } } }) };
        }

        const source_args = try self.pass.allocator.dupe(Ast.TypedLocal, self.pass.program.typedLocalSpan(source_fn.args));
        defer self.pass.allocator.free(source_args);
        const args = try self.pass.allocator.dupe(Ast.ExprId, self.pass.program.exprSpan(args_span));
        defer self.pass.allocator.free(args);
        if (source_args.len != args.len) Common.invariant("callable call arity differed from lifted function arity");

        const source_captures = try self.pass.allocator.dupe(Ast.TypedLocal, self.pass.program.typedLocalSpan(source_fn.captures));
        defer self.pass.allocator.free(source_captures);
        if (source_captures.len != callable.captures.len) {
            Common.invariant("callable value capture count differed from lifted function capture count");
        }

        var pending_lets = std.ArrayList(PendingLet).empty;
        defer pending_lets.deinit(self.pass.allocator);

        const change_start = self.changes.items.len;
        defer self.restore(change_start);

        const prepared_captures = try self.pass.allocator.alloc(Value, callable.captures.len);
        defer self.pass.allocator.free(prepared_captures);
        for (source_captures, callable.captures, 0..) |source_capture, capture_value, index| {
            prepared_captures[index] = try self.valueForInlineLocal(source_capture.local, capture_value, body, &pending_lets);
            try self.putSubst(source_capture.local, prepared_captures[index]);
        }

        const arg_values = try self.pass.allocator.alloc(Value, args.len);
        defer self.pass.allocator.free(arg_values);
        const callee_uses = if (@intFromEnum(callable.fn_id) < self.pass.plans.len)
            self.pass.plans[@intFromEnum(callable.fn_id)].used_args
        else
            &.{};
        const callee_demands = if (@intFromEnum(callable.fn_id) < self.pass.plans.len)
            self.pass.plans[@intFromEnum(callable.fn_id)].arg_demands
        else
            &.{};
        for (args, 0..) |arg_expr, index| {
            if (index < callee_uses.len and callee_uses[index]) {
                try self.noteLoopDemandIfLocalExpr(arg_expr, callee_demands[index]);
            }
            arg_values[index] = try self.cloneExprValue(arg_expr);
        }

        var unsafe_count: usize = 0;
        for (prepared_captures) |capture_value| unsafe_count += self.unsafeLeafCount(capture_value);
        for (arg_values) |arg_value| unsafe_count += self.unsafeLeafCount(arg_value);

        const prepared_args = try self.pass.allocator.alloc(Value, arg_values.len);
        defer self.pass.allocator.free(prepared_args);
        for (source_args, arg_values, 0..) |source_arg, arg_value, index| {
            prepared_args[index] = try self.valueForInlineLocal(source_arg.local, arg_value, body, &pending_lets);
        }

        try self.inline_stack.append(self.pass.allocator, .{ .fn_id = callable.fn_id });
        defer {
            const popped = self.inline_stack.pop() orelse Common.invariant("call-pattern inline stack underflow");
            if (popped.fn_id != callable.fn_id) Common.invariant("call-pattern inline stack was corrupted");
        }

        for (source_args, prepared_args, args) |source_arg, arg_value, arg_expr| {
            try self.putSubst(source_arg.local, arg_value);
            try self.appendLoopAliasForExpr(source_arg.local, arg_expr);
        }

        const pending_start = self.activePendingLetsLen();
        const pending_scope_start = try self.pushPendingLetScope(pending_lets.items);
        defer self.popPendingLetScope(pending_scope_start, pending_start);

        const body_value = if (demand_result_known_value)
            try self.cloneExprValueDemandingKnownValue(body)
        else
            try self.cloneExprValue(body);
        return try self.wrapPendingLets(body_value, pending_lets.items, demand_result_known_value);
    }

    fn callKnownValue(
        self: *Cloner,
        ty: Type.TypeId,
        callee: Value,
        args_span: Ast.Span(Ast.ExprId),
        demand_result_known_value: bool,
    ) LowerError!Value {
        return switch (callee) {
            .callable => |callable| try self.inlineCallableCallValue(ty, callable, args_span, demand_result_known_value),
            .private_state => |private_state| switch (private_state) {
                .callable => |callable| try self.inlinePrivateStateCallableCallValueWithDemand(ty, callable, args_span, .materialize),
                .compact_finite_callables => |finite_callables| try self.callCompactFiniteCallablesValueWithDemand(ty, finite_callables, args_span, .materialize),
                .leaf => .{ .expr = try self.addExpr(.{ .ty = ty, .data = .{ .call_value = .{
                    .callee = try self.materialize(callee),
                    .args = try self.cloneExprSpan(args_span),
                } } }) },
                else => Common.invariant("non-callable private state reached callable call"),
            },
            .finite_callables => |finite_callables| try self.callFiniteCallablesValue(ty, finite_callables, args_span, demand_result_known_value),
            .if_ => |if_value| try self.callIfValue(ty, if_value, args_span, demand_result_known_value),
            else => .{ .expr = try self.addExpr(.{ .ty = ty, .data = .{ .call_value = .{
                .callee = try self.materialize(callee),
                .args = try self.cloneExprSpan(args_span),
            } } }) },
        };
    }

    fn callKnownValueWithDemand(
        self: *Cloner,
        ty: Type.TypeId,
        callee: Value,
        args_span: Ast.Span(Ast.ExprId),
        demand: ValueDemand,
    ) LowerError!Value {
        return switch (callee) {
            .callable => |callable| try self.callKnownCallableValueWithDemand(ty, callable, args_span, demand),
            .private_state => |private_state| switch (private_state) {
                .callable => |callable| try self.inlinePrivateStateCallableCallValueWithDemand(ty, callable, args_span, demand),
                .compact_finite_callables => |finite_callables| try self.callCompactFiniteCallablesValueWithDemand(ty, finite_callables, args_span, demand),
                .leaf => .{ .expr = try self.addExpr(.{ .ty = ty, .data = .{ .call_value = .{
                    .callee = try self.materialize(callee),
                    .args = try self.cloneExprSpan(args_span),
                } } }) },
                else => Common.invariant("non-callable private state reached callable call"),
            },
            .finite_callables => |finite_callables| try self.callFiniteCallablesValueWithDemand(ty, finite_callables, args_span, demand),
            .if_ => |if_value| try self.callIfValueWithDemand(ty, if_value, args_span, demand),
            else => .{ .expr = try self.addExpr(.{ .ty = ty, .data = .{ .call_value = .{
                .callee = try self.materialize(callee),
                .args = try self.cloneExprSpan(args_span),
            } } }) },
        };
    }

    fn callKnownCallableValueWithDemand(
        self: *Cloner,
        ty: Type.TypeId,
        callable: CallableValue,
        args_span: Ast.Span(Ast.ExprId),
        demand: ValueDemand,
    ) LowerError!Value {
        const source_fn = self.pass.program.fns.items[@intFromEnum(callable.fn_id)];
        const source_args = try self.pass.allocator.dupe(Ast.TypedLocal, self.pass.program.typedLocalSpan(source_fn.args));
        defer self.pass.allocator.free(source_args);
        const source_captures = self.pass.program.typedLocalSpan(source_fn.captures);
        if (source_captures.len != callable.captures.len) {
            Common.invariant("callable value capture count differed from lifted function capture count");
        }

        const args = try self.pass.allocator.dupe(Ast.ExprId, self.pass.program.exprSpan(args_span));
        defer self.pass.allocator.free(args);
        if (source_args.len != args.len) Common.invariant("callable call arity differed from lifted function arity");

        var pending_lets = std.ArrayList(PendingLet).empty;
        defer pending_lets.deinit(self.pass.allocator);

        const arg_values = try self.pass.allocator.alloc(Value, args.len);
        defer self.pass.allocator.free(arg_values);
        for (source_args, args, 0..) |source_arg, arg_expr, index| {
            const arg_demand = try self.functionLocalDemand(callable.fn_id, source_arg.local, demand);
            if (arg_demand != .none) {
                try self.noteLoopDemandIfLocalExpr(arg_expr, arg_demand);
                arg_values[index] = try self.cloneExprValueWithDemand(arg_expr, arg_demand);
            } else if (try discardedExprIsEffectFree(self.pass.program, self.pass.allocator, arg_expr)) {
                arg_values[index] = try self.exprValueForDemandNoInline(arg_expr);
            } else {
                arg_values[index] = try self.preserveDiscardedArgEffect(arg_expr, &pending_lets);
            }
        }

        const call_value = try self.directCallValueFromValuesWithDemandAndCaptures(
            ty,
            callable.fn_id,
            false,
            callable.captures,
            arg_values,
            demand,
        );
        return try self.wrapPendingLets(call_value, pending_lets.items, demand != .none);
    }

    fn inlinePrivateStateCallableCallValueWithDemand(
        self: *Cloner,
        ty: Type.TypeId,
        callable: PrivateStateCallable,
        args_span: Ast.Span(Ast.ExprId),
        demand: ValueDemand,
    ) LowerError!Value {
        const source_fn = self.pass.program.fns.items[@intFromEnum(callable.fn_id)];
        const body = self.pass.originalBody(callable.fn_id) orelse switch (source_fn.body) {
            .roc => |body| body,
            .hosted => {
                if (privateStateCallableCanMaterializePublic(self.pass.program, callable)) {
                    return .{ .expr = try self.addExpr(.{ .ty = ty, .data = .{ .call_value = .{
                        .callee = try self.materialize(.{ .private_state = .{ .callable = callable } }),
                        .args = try self.cloneExprSpan(args_span),
                    } } }) };
                }
                Common.invariant("sparse private callable reached uninlinable hosted call");
            },
        };
        if (exprContainsReturn(self.pass.program, body)) {
            if (privateStateCallableCanMaterializePublic(self.pass.program, callable)) {
                return .{ .expr = try self.addExpr(.{ .ty = ty, .data = .{ .call_value = .{
                    .callee = try self.materialize(.{ .private_state = .{ .callable = callable } }),
                    .args = try self.cloneExprSpan(args_span),
                } } }) };
            }
            Common.invariant("sparse private callable reached uninlinable return-containing body");
        }

        const source_args = try self.pass.allocator.dupe(Ast.TypedLocal, self.pass.program.typedLocalSpan(source_fn.args));
        defer self.pass.allocator.free(source_args);
        const args = try self.pass.allocator.dupe(Ast.ExprId, self.pass.program.exprSpan(args_span));
        defer self.pass.allocator.free(args);
        if (source_args.len != args.len) Common.invariant("private callable call arity differed from lifted function arity");

        const source_captures = try self.pass.allocator.dupe(Ast.TypedLocal, self.pass.program.typedLocalSpan(source_fn.captures));
        defer self.pass.allocator.free(source_captures);
        for (callable.captures) |capture| {
            if (capture.index >= source_captures.len) Common.invariant("private callable capture index exceeded lifted function capture count");
        }

        if (callable.loop_origin) |origin| {
            try self.noteLoopStateCallableDemand(callable, origin, source_captures, demand);
        }

        var pending_lets = std.ArrayList(PendingLet).empty;
        defer pending_lets.deinit(self.pass.allocator);

        const change_start = self.changes.items.len;
        defer self.restore(change_start);
        const provenance_start = self.loopProvenanceLen();
        defer self.restoreLoopProvenance(provenance_start);

        for (source_captures, 0..) |source_capture, index| {
            if (privateStateIndexedValueByIndex(callable.captures, @intCast(index))) |capture| {
                const prepared = try self.valueForInlineLocal(source_capture.local, .{ .private_state = capture }, body, &pending_lets);
                try self.putSubst(source_capture.local, prepared);
            } else {
                const capture_demand = if (demand == .none)
                    self.plannedLocalDemand(callable.fn_id, source_capture.local)
                else
                    try self.functionLocalDemand(callable.fn_id, source_capture.local, demand);
                if (capture_demand != .none and self.subst.get(source_capture.local) != null) continue;
                if (capture_demand != .none) {
                    const capture_value = (try self.privateStateCallableCaptureValue(callable, index)) orelse {
                        if (callable.loop_origin) |origin| {
                            if (self.activeStateLoopOwningParam(origin.source_local)) |owner| {
                                if (owner.loop.changed.*) return error.LoopStateDemandGrew;
                            }
                        }
                        Common.invariant("sparse private callable was missing a demanded capture");
                    };
                    const prepared = try self.valueForInlineLocal(source_capture.local, capture_value, body, &pending_lets);
                    try self.putSubst(source_capture.local, prepared);
                }
            }
        }

        const arg_values = try self.pass.allocator.alloc(Value, args.len);
        defer self.pass.allocator.free(arg_values);
        for (source_args, args, 0..) |source_arg, arg_expr, index| {
            const arg_demand = try self.functionLocalDemand(callable.fn_id, source_arg.local, demand);
            if (arg_demand != .none) {
                try self.noteLoopDemandIfLocalExpr(arg_expr, arg_demand);
                arg_values[index] = try self.cloneExprValueWithDemand(arg_expr, arg_demand);
            } else {
                arg_values[index] = try self.cloneExprValue(arg_expr);
            }
        }

        const prepared_args = try self.pass.allocator.alloc(Value, arg_values.len);
        defer self.pass.allocator.free(prepared_args);
        for (source_args, arg_values, 0..) |source_arg, arg_value, index| {
            prepared_args[index] = try self.valueForInlineLocal(source_arg.local, arg_value, body, &pending_lets);
        }

        try self.inline_stack.append(self.pass.allocator, .{ .fn_id = callable.fn_id });
        defer {
            const popped = self.inline_stack.pop() orelse Common.invariant("call-pattern inline stack underflow");
            if (popped.fn_id != callable.fn_id) Common.invariant("call-pattern inline stack was corrupted");
        }

        for (source_args, prepared_args, args) |source_arg, arg_value, arg_expr| {
            try self.putSubst(source_arg.local, arg_value);
            try self.appendLoopAliasForExpr(source_arg.local, arg_expr);
        }

        const pending_start = self.activePendingLetsLen();
        const pending_scope_start = try self.pushPendingLetScope(pending_lets.items);
        defer self.popPendingLetScope(pending_scope_start, pending_start);

        const body_value = try self.cloneExprValueWithDemand(body, demand);
        return try self.wrapPendingLets(body_value, pending_lets.items, demand != .none);
    }

    fn inlineCallableCallValueWithDemand(
        self: *Cloner,
        ty: Type.TypeId,
        callable: CallableValue,
        args_span: Ast.Span(Ast.ExprId),
        demand: ValueDemand,
    ) LowerError!Value {
        const source_fn = self.pass.program.fns.items[@intFromEnum(callable.fn_id)];
        const body = self.pass.originalBody(callable.fn_id) orelse switch (source_fn.body) {
            .roc => |body| body,
            .hosted => {
                return .{ .expr = try self.addExpr(.{ .ty = ty, .data = .{ .call_value = .{
                    .callee = try self.materialize(.{ .callable = callable }),
                    .args = try self.cloneExprSpan(args_span),
                } } }) };
            },
        };
        if (exprContainsReturn(self.pass.program, body)) {
            return .{ .expr = try self.addExpr(.{ .ty = ty, .data = .{ .call_value = .{
                .callee = try self.materialize(.{ .callable = callable }),
                .args = try self.cloneExprSpan(args_span),
            } } }) };
        }

        const source_args = try self.pass.allocator.dupe(Ast.TypedLocal, self.pass.program.typedLocalSpan(source_fn.args));
        defer self.pass.allocator.free(source_args);
        const args = try self.pass.allocator.dupe(Ast.ExprId, self.pass.program.exprSpan(args_span));
        defer self.pass.allocator.free(args);
        if (source_args.len != args.len) Common.invariant("callable call arity differed from lifted function arity");

        const source_captures = try self.pass.allocator.dupe(Ast.TypedLocal, self.pass.program.typedLocalSpan(source_fn.captures));
        defer self.pass.allocator.free(source_captures);
        if (source_captures.len != callable.captures.len) {
            Common.invariant("callable value capture count differed from lifted function capture count");
        }

        var pending_lets = std.ArrayList(PendingLet).empty;
        defer pending_lets.deinit(self.pass.allocator);

        const change_start = self.changes.items.len;
        defer self.restore(change_start);
        const provenance_start = self.loopProvenanceLen();
        defer self.restoreLoopProvenance(provenance_start);

        const prepared_captures = try self.pass.allocator.alloc(Value, callable.captures.len);
        defer self.pass.allocator.free(prepared_captures);
        for (source_captures, callable.captures, 0..) |source_capture, capture_value, index| {
            prepared_captures[index] = try self.valueForInlineLocal(source_capture.local, capture_value, body, &pending_lets);
            try self.putSubst(source_capture.local, prepared_captures[index]);
        }

        const arg_values = try self.pass.allocator.alloc(Value, args.len);
        defer self.pass.allocator.free(arg_values);
        for (source_args, args, 0..) |source_arg, arg_expr, index| {
            const arg_demand = try self.functionLocalDemand(callable.fn_id, source_arg.local, demand);
            if (arg_demand != .none) {
                try self.noteLoopDemandIfLocalExpr(arg_expr, arg_demand);
                arg_values[index] = try self.cloneExprValueWithDemand(arg_expr, arg_demand);
            } else {
                arg_values[index] = try self.cloneExprValue(arg_expr);
            }
        }

        const prepared_args = try self.pass.allocator.alloc(Value, arg_values.len);
        defer self.pass.allocator.free(prepared_args);
        for (source_args, arg_values, 0..) |source_arg, arg_value, index| {
            prepared_args[index] = try self.valueForInlineLocal(source_arg.local, arg_value, body, &pending_lets);
        }

        try self.inline_stack.append(self.pass.allocator, .{ .fn_id = callable.fn_id });
        defer {
            const popped = self.inline_stack.pop() orelse Common.invariant("call-pattern inline stack underflow");
            if (popped.fn_id != callable.fn_id) Common.invariant("call-pattern inline stack was corrupted");
        }

        for (source_args, prepared_args, args) |source_arg, arg_value, arg_expr| {
            try self.putSubst(source_arg.local, arg_value);
            try self.appendLoopAliasForExpr(source_arg.local, arg_expr);
        }

        const pending_start = self.activePendingLetsLen();
        const pending_scope_start = try self.pushPendingLetScope(pending_lets.items);
        defer self.popPendingLetScope(pending_scope_start, pending_start);

        const body_value = try self.cloneExprValueWithDemand(body, demand);
        return try self.wrapPendingLets(body_value, pending_lets.items, demand != .none);
    }

    fn callCompactFiniteCallablesValueWithDemand(
        self: *Cloner,
        ty: Type.TypeId,
        finite_callables: PrivateStateCompactFiniteCallables,
        args_span: Ast.Span(Ast.ExprId),
        demand: ValueDemand,
    ) LowerError!Value {
        if (finite_callables.source.alternatives.len == 0) {
            Common.invariant("compact finite callable value had no alternatives");
        }
        if (finite_callables.source.alternatives.len == 1) {
            const callable = try self.compactFiniteCallablePrivateStateFromExpr(finite_callables.source, finite_callables.compact_expr);
            return try self.inlinePrivateStateCallableCallValueWithDemand(ty, callable, args_span, demand);
        }

        const compact_ty = try self.pass.compactFiniteCallablesType(finite_callables.source);
        const branches = try self.pass.arena.allocator().alloc(MatchValueBranch, finite_callables.source.alternatives.len);
        for (finite_callables.source.alternatives, branches, 0..) |alternative, *branch, alternative_index| {
            var slot_tys = std.ArrayList(Type.TypeId).empty;
            defer slot_tys.deinit(self.pass.allocator);
            try self.pass.appendCompactIndexedValueTypes(alternative.captures, &slot_tys);

            const capture_pats = try self.pass.allocator.alloc(Ast.PatId, slot_tys.items.len);
            defer self.pass.allocator.free(capture_pats);
            const capture_exprs = try self.pass.allocator.alloc(Ast.ExprId, slot_tys.items.len);
            defer self.pass.allocator.free(capture_exprs);
            for (slot_tys.items, capture_pats, capture_exprs) |slot_ty, *capture_pat, *capture_expr| {
                const local = try self.pass.program.addLocal(self.pass.symbols.fresh(), slot_ty);
                capture_pat.* = try self.pass.program.addPat(.{
                    .ty = slot_ty,
                    .data = .{ .bind = local },
                });
                capture_expr.* = try self.addExpr(.{
                    .ty = slot_ty,
                    .data = .{ .local = local },
                });
            }

            var capture_index: usize = 0;
            const captures = try self.privateStateIndexedValuesFromDemandedKnownValueExprs(alternative.captures, capture_exprs, &capture_index);
            if (capture_index != capture_exprs.len) {
                Common.invariant("compact finite callable branch did not consume every capture slot");
            }
            const scoped_start = self.scopedLocalsLen();
            defer self.restoreScopedLocals(scoped_start);
            for (capture_pats) |capture_pat| {
                try self.appendPatternScopedLocals(capture_pat);
            }
            const tag_name = try self.pass.compactCallableAlternativeTagName(alternative_index);
            branch.* = .{
                .pat = try self.pass.program.addPat(.{
                    .ty = compact_ty,
                    .data = .{ .tag = .{
                        .name = tag_name,
                        .payloads = try self.pass.program.addPatSpan(capture_pats),
                    } },
                }),
                .guard = null,
                .body = try self.inlinePrivateStateCallableCallValueWithDemand(ty, .{
                    .ty = alternative.ty,
                    .fn_id = alternative.fn_id,
                    .captures = captures,
                }, args_span, demand),
            };
        }

        return .{ .match_ = .{
            .ty = ty,
            .branches = branches,
            .scrutinee = finite_callables.compact_expr,
            .comptime_site = null,
        } };
    }

    fn compactFiniteCallablePrivateStateFromExpr(
        self: *Cloner,
        source: DemandedKnownCallables,
        compact_expr: Ast.ExprId,
    ) LowerError!PrivateStateCallable {
        if (source.alternatives.len != 1) Common.invariant("compact singleton callable reconstruction got multiple alternatives");
        const alternative = source.alternatives[0];

        var slot_tys = std.ArrayList(Type.TypeId).empty;
        defer slot_tys.deinit(self.pass.allocator);
        try self.pass.appendCompactIndexedValueTypes(alternative.captures, &slot_tys);

        var capture_exprs = std.ArrayList(Ast.ExprId).empty;
        defer capture_exprs.deinit(self.pass.allocator);
        try self.appendCompactSlotExprs(compact_expr, slot_tys.items, &capture_exprs);

        var index: usize = 0;
        const captures = try self.privateStateIndexedValuesFromDemandedKnownValueExprs(alternative.captures, capture_exprs.items, &index);
        if (index != capture_exprs.items.len) Common.invariant("compact singleton callable reconstruction did not consume every slot");
        return .{
            .ty = alternative.ty,
            .fn_id = alternative.fn_id,
            .captures = captures,
        };
    }

    fn callFiniteCallablesValueWithDemand(
        self: *Cloner,
        ty: Type.TypeId,
        finite_callables: FiniteCallablesValue,
        args_span: Ast.Span(Ast.ExprId),
        demand: ValueDemand,
    ) LowerError!Value {
        if (finite_callables.alternatives.len == 0) {
            Common.invariant("finite callable value had no alternatives");
        }
        if (finite_callables.alternatives.len == 1) {
            return try self.inlineCallableCallValueWithDemand(ty, finite_callables.alternatives[0], args_span, demand);
        }

        const branch_count = finite_callables.alternatives.len - 1;
        const branches = try self.pass.arena.allocator().alloc(IfValueBranch, branch_count);
        for (finite_callables.alternatives[0..branch_count], branches, 0..) |alternative, *branch, index| {
            branch.* = .{
                .cond = try self.selectorEquals(finite_callables.selector, @intCast(index)),
                .body = try self.inlineCallableCallValueWithDemand(ty, alternative, args_span, demand),
            };
        }

        const final_else = try self.pass.arena.allocator().create(Value);
        final_else.* = try self.inlineCallableCallValueWithDemand(ty, finite_callables.alternatives[branch_count], args_span, demand);
        return .{ .if_ = .{
            .ty = ty,
            .branches = branches,
            .final_else = final_else,
        } };
    }

    fn callIfValueWithDemand(
        self: *Cloner,
        ty: Type.TypeId,
        if_value: IfValue,
        args_span: Ast.Span(Ast.ExprId),
        demand: ValueDemand,
    ) LowerError!Value {
        const branches = try self.pass.arena.allocator().alloc(IfValueBranch, if_value.branches.len);
        for (if_value.branches, 0..) |branch, index| {
            branches[index] = .{
                .cond = branch.cond,
                .body = try self.callKnownValueWithDemand(ty, branch.body, args_span, demand),
            };
        }
        const final_else = try self.pass.arena.allocator().create(Value);
        final_else.* = try self.callKnownValueWithDemand(ty, if_value.final_else.*, args_span, demand);
        return .{ .if_ = .{
            .ty = ty,
            .branches = branches,
            .final_else = final_else,
        } };
    }

    fn privateStateCallableValue(self: *Cloner, value: PrivateStateValue) LowerError!?CallableValue {
        return switch (value) {
            .callable => |callable| try self.privateStateCallableToCallableValue(callable),
            .nominal => |nominal| if (nominal.backing) |backing| try self.privateStateCallableValue(backing.*) else null,
            else => null,
        };
    }

    fn privateStateCallableToCallableValue(self: *Cloner, callable: PrivateStateCallable) LowerError!?CallableValue {
        const source_fn = self.pass.program.fns.items[@intFromEnum(callable.fn_id)];
        const source_captures = self.pass.program.typedLocalSpan(source_fn.captures);
        const captures = try self.pass.arena.allocator().alloc(Value, source_captures.len);
        for (callable.captures) |capture| {
            if (capture.index >= source_captures.len) return null;
        }
        for (captures, 0..) |*out, index| {
            const capture = privateStateIndexedValueByIndex(callable.captures, @intCast(index)) orelse return null;
            out.* = .{ .private_state = capture };
        }
        return CallableValue{
            .ty = callable.ty,
            .fn_id = callable.fn_id,
            .captures = captures,
        };
    }

    fn privateStateIndexedValuesAsDenseValues(
        self: *Cloner,
        indexed: []const PrivateStateIndexedValue,
        expected_len: usize,
    ) Allocator.Error!?[]const Value {
        if (!privateStateIndexedValuesAreDense(indexed, expected_len)) return null;

        const values = try self.pass.arena.allocator().alloc(Value, expected_len);
        for (values, 0..) |*out, index| {
            const item = privateStateIndexedValueByIndex(indexed, @intCast(index)) orelse
                Common.invariant("dense private state index lookup failed");
            out.* = .{ .private_state = item };
        }
        return values;
    }

    fn callFiniteCallablesValue(
        self: *Cloner,
        ty: Type.TypeId,
        finite_callables: FiniteCallablesValue,
        args_span: Ast.Span(Ast.ExprId),
        demand_result_known_value: bool,
    ) LowerError!Value {
        if (finite_callables.alternatives.len == 0) {
            Common.invariant("finite callable value had no alternatives");
        }
        if (finite_callables.alternatives.len == 1) {
            return try self.inlineCallableCallValue(ty, finite_callables.alternatives[0], args_span, demand_result_known_value);
        }

        const branch_count = finite_callables.alternatives.len - 1;
        const branches = try self.pass.arena.allocator().alloc(IfValueBranch, branch_count);
        for (finite_callables.alternatives[0..branch_count], branches, 0..) |alternative, *branch, index| {
            branch.* = .{
                .cond = try self.selectorEquals(finite_callables.selector, @intCast(index)),
                .body = try self.inlineCallableCallValue(ty, alternative, args_span, demand_result_known_value),
            };
        }

        const final_else = try self.pass.arena.allocator().create(Value);
        final_else.* = try self.inlineCallableCallValue(ty, finite_callables.alternatives[branch_count], args_span, demand_result_known_value);
        return .{ .if_ = .{
            .ty = ty,
            .branches = branches,
            .final_else = final_else,
        } };
    }

    fn callIfValue(
        self: *Cloner,
        ty: Type.TypeId,
        if_value: IfValue,
        args_span: Ast.Span(Ast.ExprId),
        demand_result_known_value: bool,
    ) LowerError!Value {
        const branches = try self.pass.arena.allocator().alloc(IfValueBranch, if_value.branches.len);
        for (if_value.branches, 0..) |branch, index| {
            branches[index] = .{
                .cond = branch.cond,
                .body = try self.callKnownValue(ty, branch.body, args_span, demand_result_known_value),
            };
        }
        const final_else = try self.pass.arena.allocator().create(Value);
        final_else.* = try self.callKnownValue(ty, if_value.final_else.*, args_span, demand_result_known_value);
        return .{ .if_ = .{
            .ty = ty,
            .branches = branches,
            .final_else = final_else,
        } };
    }

    fn inlineDirectCallValue(
        self: *Cloner,
        callee: Ast.FnId,
        args_span: Ast.Span(Ast.ExprId),
        original_expr: Ast.ExprId,
        demand_result_known_value: bool,
    ) LowerError!Value {
        const source_fn = self.pass.program.fns.items[@intFromEnum(callee)];
        const body = self.pass.originalBody(callee) orelse switch (source_fn.body) {
            .roc => |body| body,
            .hosted => {
                return .{ .expr = try self.cloneExprPlain(original_expr) };
            },
        };
        if (exprContainsReturn(self.pass.program, body)) {
            return .{ .expr = try self.cloneExprPlain(original_expr) };
        }
        if (!self.directInlineCapturesAvailable(source_fn)) {
            return .{ .expr = try self.cloneExprPlain(original_expr) };
        }

        const source_args = try self.pass.allocator.dupe(Ast.TypedLocal, self.pass.program.typedLocalSpan(source_fn.args));
        defer self.pass.allocator.free(source_args);
        const args = try self.pass.allocator.dupe(Ast.ExprId, self.pass.program.exprSpan(args_span));
        defer self.pass.allocator.free(args);
        if (source_args.len != args.len) Common.invariant("direct call arity differed from lifted function arity");

        var pending_lets = std.ArrayList(PendingLet).empty;
        defer pending_lets.deinit(self.pass.allocator);

        const change_start = self.changes.items.len;
        defer self.restore(change_start);
        const provenance_start = self.loopProvenanceLen();
        defer self.restoreLoopProvenance(provenance_start);

        const captures = try self.pass.allocator.dupe(Ast.TypedLocal, self.pass.program.typedLocalSpan(source_fn.captures));
        defer self.pass.allocator.free(captures);
        for (captures) |capture| {
            const value = (try self.directInlineCaptureValue(capture)) orelse
                Common.invariant("direct inline capture availability changed before capture binding");
            if (!self.valueCanBeMadeReusableForMatch(value)) {
                return .{ .expr = try self.cloneExprPlain(original_expr) };
            }
            try self.putSubst(capture.local, try self.makeReusableForMatch(value, &pending_lets));
        }

        const arg_values = try self.pass.allocator.alloc(Value, args.len);
        defer self.pass.allocator.free(arg_values);
        const callee_uses = if (@intFromEnum(callee) < self.pass.plans.len)
            self.pass.plans[@intFromEnum(callee)].used_args
        else
            &.{};
        const callee_demands = if (@intFromEnum(callee) < self.pass.plans.len)
            self.pass.plans[@intFromEnum(callee)].arg_demands
        else
            &.{};
        for (args, 0..) |arg_expr, index| {
            if (index < callee_uses.len and callee_uses[index]) {
                try self.noteLoopDemandIfLocalExpr(arg_expr, callee_demands[index]);
            }
            arg_values[index] = if (index < callee_uses.len and callee_uses[index])
                try self.cloneExprValueDemandingKnownValue(arg_expr)
            else
                try self.cloneExprValue(arg_expr);
        }

        var unsafe_count: usize = 0;
        for (arg_values) |arg_value| unsafe_count += self.unsafeLeafCount(arg_value);
        for (captures) |capture| {
            const value = (try self.directInlineCaptureValue(capture)) orelse
                Common.invariant("direct inline capture availability changed before capture analysis");
            unsafe_count += self.unsafeLeafCount(value);
        }

        const prepared_args = try self.pass.allocator.alloc(Value, arg_values.len);
        defer self.pass.allocator.free(prepared_args);
        for (source_args, arg_values, 0..) |source_arg, arg_value, index| {
            prepared_args[index] = try self.valueForInlineLocal(source_arg.local, arg_value, body, &pending_lets);
        }

        const active_args_for_call = try self.directCallActiveArgsFromValues(prepared_args);
        const active_aliases_for_call = try self.directCallActiveAliasesFromValues(source_args, args, prepared_args);
        for (self.inline_stack.items) |active| {
            if (active.fn_id != callee) continue;
            const active_args = active.args orelse {
                const call_expr = try self.directCallExprFromValues(
                    self.pass.program.exprs.items[@intFromEnum(original_expr)].ty,
                    callee,
                    false,
                    prepared_args,
                );
                return try self.wrapPendingLets(.{ .expr = call_expr }, pending_lets.items, false);
            };
            const compare_aliases = try self.activeComparisonAliases(active.aliases, active_args, active_aliases_for_call, active_args_for_call);
            defer self.pass.allocator.free(compare_aliases);
            if (!activeInlineArgsStrictlyDescend(self.pass.program, active_args, active_args_for_call, compare_aliases)) {
                const call_expr = try self.directCallExprFromValues(
                    self.pass.program.exprs.items[@intFromEnum(original_expr)].ty,
                    callee,
                    false,
                    prepared_args,
                );
                return try self.wrapPendingLets(.{ .expr = call_expr }, pending_lets.items, false);
            }
        }

        try self.inline_stack.append(self.pass.allocator, .{
            .fn_id = callee,
            .args = active_args_for_call,
            .aliases = active_aliases_for_call,
        });
        defer {
            const popped = self.inline_stack.pop() orelse Common.invariant("call-pattern inline stack underflow");
            if (popped.fn_id != callee) Common.invariant("call-pattern inline stack was corrupted");
        }

        for (source_args, prepared_args, args) |source_arg, arg_value, arg_expr| {
            try self.putSubst(source_arg.local, arg_value);
            try self.appendLoopAliasForExpr(source_arg.local, arg_expr);
        }

        const pending_start = self.activePendingLetsLen();
        const pending_scope_start = try self.pushPendingLetScope(pending_lets.items);
        defer self.popPendingLetScope(pending_scope_start, pending_start);

        const body_value = if (demand_result_known_value)
            try self.cloneExprValueDemandingKnownValue(body)
        else
            try self.cloneExprValue(body);
        return try self.wrapPendingLets(body_value, pending_lets.items, demand_result_known_value);
    }

    fn inlineDirectCallValueWithDemand(
        self: *Cloner,
        callee: Ast.FnId,
        args_span: Ast.Span(Ast.ExprId),
        original_expr: Ast.ExprId,
        demand: ValueDemand,
    ) LowerError!Value {
        const source_fn = self.pass.program.fns.items[@intFromEnum(callee)];
        const body = self.pass.originalBody(callee) orelse switch (source_fn.body) {
            .roc => |body| body,
            .hosted => {
                return try self.materializeDirectCallBoundaryForDemand(original_expr, demand);
            },
        };
        if (exprContainsReturn(self.pass.program, body)) {
            return try self.materializeDirectCallBoundaryForDemand(original_expr, demand);
        }
        if (!self.directInlineCapturesAvailable(source_fn)) {
            return try self.materializeDirectCallBoundaryForDemand(original_expr, demand);
        }

        const source_args = try self.pass.allocator.dupe(Ast.TypedLocal, self.pass.program.typedLocalSpan(source_fn.args));
        defer self.pass.allocator.free(source_args);
        const args = try self.pass.allocator.dupe(Ast.ExprId, self.pass.program.exprSpan(args_span));
        defer self.pass.allocator.free(args);
        if (source_args.len != args.len) Common.invariant("direct call arity differed from lifted function arity");

        var pending_lets = std.ArrayList(PendingLet).empty;
        defer pending_lets.deinit(self.pass.allocator);

        const change_start = self.changes.items.len;
        defer self.restore(change_start);
        const provenance_start = self.loopProvenanceLen();
        defer self.restoreLoopProvenance(provenance_start);

        const captures = try self.pass.allocator.dupe(Ast.TypedLocal, self.pass.program.typedLocalSpan(source_fn.captures));
        defer self.pass.allocator.free(captures);
        for (captures) |capture| {
            const value = (try self.directInlineCaptureValue(capture)) orelse
                Common.invariant("direct inline capture availability changed before capture binding");
            if (!self.valueCanBeMadeReusableForMatch(value)) {
                return try self.materializeDirectCallBoundaryForDemand(original_expr, demand);
            }
            try self.putSubst(capture.local, try self.makeReusableForMatch(value, &pending_lets));
        }

        const arg_demands = try self.pass.allocator.alloc(ValueDemand, args.len);
        defer self.pass.allocator.free(arg_demands);
        @memset(arg_demands, .none);
        for (source_args, 0..) |source_arg, index| {
            arg_demands[index] = try self.functionLocalDemand(callee, source_arg.local, demand);
        }
        if (!self.demandStackContains(callee)) {
            const demand_change_start = self.changes.items.len;
            const demand_provenance_start = self.loopProvenanceLen();
            defer self.restoreLoopProvenance(demand_provenance_start);
            defer self.restore(demand_change_start);

            for (source_args, args) |source_arg, arg_expr| {
                try self.putSubst(source_arg.local, try self.exprValueForDemandNoInline(arg_expr));
                try self.appendLoopAliasForExpr(source_arg.local, arg_expr);
            }

            for (source_args, arg_demands) |source_arg, *arg_demand| {
                const observed = try self.localDemandInExpr(source_arg.local, body, demand);
                arg_demand.* = try self.mergeValueDemand(arg_demand.*, observed);
            }
        }

        const arg_values = try self.pass.allocator.alloc(Value, args.len);
        defer self.pass.allocator.free(arg_values);
        for (args, 0..) |arg_expr, index| {
            const arg_demand = arg_demands[index];
            if (arg_demand != .none) {
                try self.noteLoopDemandIfLocalExpr(arg_expr, arg_demand);
                arg_values[index] = try self.cloneExprValueWithDemand(arg_expr, arg_demand);
            } else if (try discardedExprIsEffectFree(self.pass.program, self.pass.allocator, arg_expr)) {
                arg_values[index] = try self.exprValueForDemandNoInline(arg_expr);
            } else {
                arg_values[index] = try self.preserveDiscardedArgEffect(arg_expr, &pending_lets);
            }
        }

        var unsafe_count: usize = 0;
        for (arg_values) |arg_value| unsafe_count += self.unsafeLeafCount(arg_value);
        for (captures) |capture| {
            const value = (try self.directInlineCaptureValue(capture)) orelse
                Common.invariant("direct inline capture availability changed before capture analysis");
            unsafe_count += self.unsafeLeafCount(value);
        }

        const prepared_args = try self.pass.allocator.alloc(Value, arg_values.len);
        defer self.pass.allocator.free(prepared_args);
        for (source_args, arg_values, 0..) |source_arg, arg_value, index| {
            prepared_args[index] = try self.valueForInlineLocal(source_arg.local, arg_value, body, &pending_lets);
        }

        const active_args_for_call = try self.directCallActiveArgsFromValues(prepared_args);
        const active_aliases_for_call = try self.directCallActiveAliasesFromValues(source_args, args, prepared_args);
        for (self.inline_stack.items) |active| {
            if (active.fn_id != callee) continue;
            const call_value = try self.directCallValueFromValuesWithDemand(
                self.pass.program.exprs.items[@intFromEnum(original_expr)].ty,
                callee,
                false,
                prepared_args,
                demand,
            );
            return try self.wrapPendingLets(call_value, pending_lets.items, demand != .none);
        }

        try self.inline_stack.append(self.pass.allocator, .{
            .fn_id = callee,
            .args = active_args_for_call,
            .aliases = active_aliases_for_call,
        });
        defer {
            const popped = self.inline_stack.pop() orelse Common.invariant("call-pattern inline stack underflow");
            if (popped.fn_id != callee) Common.invariant("call-pattern inline stack was corrupted");
        }

        for (source_args, prepared_args, args) |source_arg, arg_value, arg_expr| {
            try self.putSubst(source_arg.local, arg_value);
            try self.appendLoopAliasForExpr(source_arg.local, arg_expr);
        }

        const pending_start = self.activePendingLetsLen();
        const pending_scope_start = try self.pushPendingLetScope(pending_lets.items);
        defer self.popPendingLetScope(pending_scope_start, pending_start);

        const body_value = try self.cloneExprValueWithDemand(body, demand);
        return try self.wrapPendingLets(body_value, pending_lets.items, demand != .none);
    }

    fn activeComparisonAliases(
        self: *Cloner,
        stored_aliases: []const ActiveInlineAlias,
        active_args: []const ActiveInlineArg,
        next_aliases: []const ActiveInlineAlias,
        next_args: []const ActiveInlineArg,
    ) Allocator.Error![]const ActiveInlineAlias {
        var aliases = std.ArrayList(ActiveInlineAlias).empty;
        defer aliases.deinit(self.pass.allocator);
        try aliases.appendSlice(self.pass.allocator, stored_aliases);
        try aliases.appendSlice(self.pass.allocator, next_aliases);
        for (active_args) |arg| {
            if (arg == .private_state) {
                try self.appendCallableCaptureAliases(arg.private_state, &aliases);
            }
        }
        for (next_args) |arg| {
            if (arg == .private_state) {
                try self.appendCallableCaptureAliases(arg.private_state, &aliases);
            }
        }
        return try self.pass.allocator.dupe(ActiveInlineAlias, aliases.items);
    }

    fn appendCallableCaptureAliases(
        self: *Cloner,
        value: PrivateStateValue,
        aliases: *std.ArrayList(ActiveInlineAlias),
    ) Allocator.Error!void {
        switch (value) {
            .leaf => {},
            .tag => |tag| {
                for (tag.payloads) |payload| try self.appendCallableCaptureAliases(payload.value, aliases);
            },
            .record => |record| {
                for (record.fields) |field| try self.appendCallableCaptureAliases(field.value, aliases);
            },
            .tuple => |tuple| {
                for (tuple.items) |item| try self.appendCallableCaptureAliases(item.value, aliases);
            },
            .nominal => |nominal| {
                if (nominal.backing) |backing| try self.appendCallableCaptureAliases(backing.*, aliases);
            },
            .callable => |callable| {
                const source_fn = self.pass.program.fns.items[@intFromEnum(callable.fn_id)];
                const source_captures = self.pass.program.typedLocalSpan(source_fn.captures);
                for (callable.captures) |capture| {
                    if (capture.index >= source_captures.len) {
                        Common.invariant("private callable capture index exceeded lifted function capture count");
                    }
                    const source_local = source_captures[capture.index].local;
                    try aliases.append(self.pass.allocator, .{
                        .local = source_local,
                        .value = .{ .private_state = capture.value },
                    });
                    if (self.subst.get(source_local)) |substituted| {
                        if (localAliasFromValue(self.pass.program, substituted)) |alias_local| {
                            try aliases.append(self.pass.allocator, .{
                                .local = alias_local,
                                .value = .{ .private_state = capture.value },
                            });
                        }
                    }
                    try self.appendCallableCaptureAliases(capture.value, aliases);
                }
            },
            .compact_finite_tags,
            .compact_finite_callables,
            => {},
        }
    }

    fn preserveDiscardedArgEffect(
        self: *Cloner,
        arg_expr: Ast.ExprId,
        pending_lets: *std.ArrayList(PendingLet),
    ) Allocator.Error!Value {
        const ty = self.pass.program.exprs.items[@intFromEnum(arg_expr)].ty;
        const local = try self.pass.program.addLocal(self.pass.symbols.fresh(), ty);
        try pending_lets.append(self.pass.allocator, .{
            .local = local,
            .ty = ty,
            .value = .{ .source = arg_expr },
        });
        return .{ .expr = try self.addExpr(.{
            .ty = ty,
            .data = .{ .local = local },
        }) };
    }

    fn materializeDirectCallBoundaryForDemand(
        self: *Cloner,
        original_expr: Ast.ExprId,
        demand: ValueDemand,
    ) LowerError!Value {
        const original = self.pass.program.exprs.items[@intFromEnum(original_expr)];
        if (original.data == .call_proc and !original.data.call_proc.is_cold) {
            const call_expr = try self.cloneDirectCallBoundaryExpr(original.ty, original.data.call_proc);
            var pending_lets = std.ArrayList(PendingLet).empty;
            defer pending_lets.deinit(self.pass.allocator);
            try self.appendActivePendingLetDependenciesForExpr(call_expr, &pending_lets);
            if (demand == .none or demand == .materialize) {
                return try self.wrapPendingLets(.{ .expr = call_expr }, pending_lets.items, false);
            }

            const local = try self.pass.program.addLocal(self.pass.symbols.fresh(), original.ty);
            const local_expr = try self.addExpr(.{
                .ty = original.ty,
                .data = .{ .local = local },
            });
            try pending_lets.append(self.pass.allocator, .{
                .local = local,
                .ty = original.ty,
                .value = .{ .cloned = call_expr },
            });
            const pending_start = self.activePendingLetsLen();
            const scoped_start = try self.pushPendingLetScope(pending_lets.items);
            defer self.popPendingLetScope(scoped_start, pending_start);
            const demanded = try self.applyValueDemand(.{ .expr = local_expr }, demand);
            return try self.wrapPendingLets(demanded, pending_lets.items, true);
        }
        if (demand == .materialize) {
            return .{ .expr = try self.cloneExprPlain(original_expr) };
        }
        return try self.cloneExprValueDemandingKnownValue(original_expr);
    }

    fn cloneDirectCallBoundaryExpr(
        self: *Cloner,
        ty: Type.TypeId,
        call: @import("../monotype/ast.zig").CallProc,
    ) LowerError!Ast.ExprId {
        const callee = Ast.callProcCallee(call);
        const call_expr = try self.addExpr(.{ .ty = ty, .data = .{ .call_proc = .{
            .callee = call.callee,
            .args = try self.cloneDirectCallBoundaryArgs(call.args),
            .is_cold = call.is_cold,
        } } });
        return try self.wrapDirectCallCaptureLets(ty, callee, call_expr);
    }

    fn cloneDirectCallBoundaryArgs(
        self: *Cloner,
        span: Ast.Span(Ast.ExprId),
    ) LowerError!Ast.Span(Ast.ExprId) {
        const source = try self.pass.allocator.dupe(Ast.ExprId, self.pass.program.exprSpan(span));
        defer self.pass.allocator.free(source);

        const values = try self.pass.allocator.alloc(Ast.ExprId, source.len);
        defer self.pass.allocator.free(values);
        for (source, values) |expr, *out| {
            const value = try self.exprValueForDirectCallBoundaryArg(expr);
            out.* = if (valueIsExpr(value, expr))
                try self.cloneExprPlain(expr)
            else
                try self.materialize(value);
        }
        return try self.pass.program.addExprSpan(values);
    }

    fn directCallCaptureValues(self: *Cloner, fn_id: Ast.FnId) LowerError!?[]const Value {
        const source_fn = self.pass.program.fns.items[@intFromEnum(fn_id)];
        const captures = self.pass.program.typedLocalSpan(source_fn.captures);
        const values = try self.pass.allocator.alloc(Value, captures.len);
        errdefer self.pass.allocator.free(values);

        for (captures, values) |capture, *value| {
            value.* = (try self.directInlineCaptureValue(capture)) orelse {
                self.pass.allocator.free(values);
                return null;
            };
        }

        return values;
    }

    fn functionValueType(self: *Cloner, fn_id: Ast.FnId) Allocator.Error!Type.TypeId {
        const fn_ = self.pass.program.fns.items[@intFromEnum(fn_id)];
        const args = self.pass.program.typedLocalSpan(fn_.args);
        const arg_tys = try self.pass.allocator.alloc(Type.TypeId, args.len);
        defer self.pass.allocator.free(arg_tys);
        for (args, arg_tys) |arg, *out| out.* = arg.ty;
        return try self.pass.program.types.add(.{ .func = .{
            .args = try self.pass.program.types.addSpan(arg_tys),
            .ret = fn_.ret,
        } });
    }

    fn directInlineCapturesAvailable(self: *Cloner, source_fn: Ast.Fn) bool {
        for (self.pass.program.typedLocalSpan(source_fn.captures)) |capture| {
            if (!self.subst.contains(capture.local) and !self.localCanBeReferencedDirectly(capture.local)) return false;
        }
        return true;
    }

    fn directInlineCaptureValue(self: *Cloner, capture: Ast.TypedLocal) LowerError!?Value {
        if (self.subst.get(capture.local)) |value| return value;
        return try self.scopedLocalValue(capture);
    }

    fn fieldFromPatternValue(
        self: *Cloner,
        value: Value,
        field: names.RecordFieldNameId,
        ty: Type.TypeId,
    ) LowerError!?Value {
        if (fieldFromValue(self.pass.program, value, field)) |field_value| return field_value;
        if (value == .let_) {
            const let_value = value.let_;
            const field_value = (try self.fieldFromPatternValue(let_value.body.*, field, ty)) orelse return null;
            return try self.wrapPendingLets(field_value, let_value.lets, true);
        }
        if (value == .if_) {
            const if_value = value.if_;
            const branches = try self.pass.arena.allocator().alloc(IfValueBranch, if_value.branches.len);
            for (if_value.branches, branches) |branch, *out| {
                out.* = .{
                    .cond = branch.cond,
                    .body = (try self.fieldFromPatternValue(branch.body, field, ty)) orelse return null,
                };
            }
            const final_else = try self.pass.arena.allocator().create(Value);
            final_else.* = (try self.fieldFromPatternValue(if_value.final_else.*, field, ty)) orelse return null;
            return Value{ .if_ = .{
                .ty = ty,
                .branches = branches,
                .final_else = final_else,
            } };
        }
        if (value == .match_) {
            const match_value = value.match_;
            const branches = try self.pass.arena.allocator().alloc(MatchValueBranch, match_value.branches.len);
            for (match_value.branches, branches) |branch, *out| {
                const branch_body = try self.cloneMatchValueBranchBodyWithDemand(
                    branch,
                    try self.pass.demandRecordField(field, .materialize),
                );
                out.* = .{
                    .pat = branch.pat,
                    .guard = branch.guard,
                    .body = (try self.fieldFromPatternValue(branch_body, field, ty)) orelse return null,
                };
            }
            return Value{ .match_ = .{
                .ty = ty,
                .scrutinee = match_value.scrutinee,
                .branches = branches,
                .comptime_site = match_value.comptime_site,
            } };
        }
        if (value == .private_state) {
            if (privateStateField(self.pass.program, value.private_state, field)) |field_value| {
                if (!sameType(self.pass.program, ty, privateStateValueType(field_value))) {
                    return null;
                }
                return Value{ .private_state = field_value };
            }
            if (try self.substitutedPrivateLeafValue(value.private_state)) |substituted| {
                if (try self.fieldFromPatternValue(substituted, field, ty)) |field_value| return field_value;
            }
            if (privateStateLeafExpr(value.private_state)) |leaf_expr| {
                if (try self.fieldFromPrivateLeafExpr(leaf_expr, field)) |field_value| return field_value;
            }
        }
        if (value == .expr) {
            if (try self.retargetCrashTailBlock(value.expr, ty)) |expr| return Value{ .expr = expr };
        }

        const projected_from = try self.projectablePatternValue(value);
        const known_value = switch (projected_from) {
            .expr_with_known_value => |known| fieldKnownValueFromKnownValue(self.pass.program, known.known_value, field),
            else => null,
        };
        const receiver = projectableExprFromValue(projected_from) orelse return null;
        if (!canReadFieldsFromExpr(self.pass.program, receiver)) return null;
        const receiver_ty = self.pass.program.exprs.items[@intFromEnum(receiver)].ty;
        if (recordFieldType(self.pass.program, receiver_ty, field) == null) return null;
        const field_expr = try self.addExpr(.{ .ty = ty, .data = .{ .field_access = .{
            .receiver = receiver,
            .field = field,
        } } });
        return if (known_value) |known|
            valueFromProjectedExpr(field_expr, known)
        else
            Value{ .expr = field_expr };
    }

    fn fieldFromPatternValueDemanded(
        self: *Cloner,
        value: Value,
        field: names.RecordFieldNameId,
        ty: Type.TypeId,
        demand: ValueDemand,
    ) LowerError!?Value {
        const resolved_demand = self.resolveLoopDemandRef(demand);
        if (resolved_demand == .none) return try self.fieldFromPatternValue(value, field, ty);
        if (resolved_demand == .loop_param) Common.invariant("loop demand reference did not resolve before field read");
        if (resolved_demand == .fn_param) Common.invariant("function demand reference did not resolve before field read");

        if (value == .let_) {
            const let_value = value.let_;
            const field_value = (try self.fieldFromPatternValueDemanded(let_value.body.*, field, ty, resolved_demand)) orelse return null;
            return try self.wrapPendingLets(field_value, let_value.lets, true);
        }
        if (value == .if_) {
            const if_value = value.if_;
            const branches = try self.pass.arena.allocator().alloc(IfValueBranch, if_value.branches.len);
            for (if_value.branches, branches) |branch, *out| {
                out.* = .{
                    .cond = branch.cond,
                    .body = (try self.fieldFromPatternValueDemanded(branch.body, field, ty, resolved_demand)) orelse return null,
                };
            }
            const final_else = try self.pass.arena.allocator().create(Value);
            final_else.* = (try self.fieldFromPatternValueDemanded(if_value.final_else.*, field, ty, resolved_demand)) orelse return null;
            return Value{ .if_ = .{
                .ty = ty,
                .branches = branches,
                .final_else = final_else,
            } };
        }
        if (value == .match_) {
            const match_value = value.match_;
            const container_demand = try self.pass.demandRecordField(field, resolved_demand);
            const branches = try self.pass.arena.allocator().alloc(MatchValueBranch, match_value.branches.len);
            for (match_value.branches, branches) |branch, *out| {
                const branch_body = try self.cloneMatchValueBranchBodyWithDemand(branch, container_demand);
                out.* = .{
                    .pat = branch.pat,
                    .guard = branch.guard,
                    .body = (try self.fieldFromPatternValueDemanded(branch_body, field, ty, resolved_demand)) orelse return null,
                };
            }
            return Value{ .match_ = .{
                .ty = ty,
                .scrutinee = match_value.scrutinee,
                .branches = branches,
                .comptime_site = match_value.comptime_site,
            } };
        }
        if (value == .expr) {
            if (!canReadFieldsFromExpr(self.pass.program, value.expr)) {
                const expr = self.pass.program.exprs.items[@intFromEnum(value.expr)];
                if (expr.data == .loop_) {
                    if (recordFieldType(self.pass.program, expr.ty, field) == null) return null;
                    const projected = try self.addExpr(.{ .ty = ty, .data = .{ .field_access = .{
                        .receiver = value.expr,
                        .field = field,
                    } } });
                    return try self.applyValueDemand(Value{ .expr = projected }, resolved_demand);
                }
                const demanded_value = try self.cloneExprValueWithDemand(value.expr, try self.pass.demandRecordField(field, resolved_demand));
                const field_value = (try self.fieldFromPatternValue(demanded_value, field, ty)) orelse {
                    if (demanded_value == .expr) {
                        if (try self.retargetCrashTailBlock(demanded_value.expr, ty)) |retargeted| {
                            return try self.applyValueDemand(Value{ .expr = retargeted }, resolved_demand);
                        }
                        const receiver_ty = self.pass.program.exprs.items[@intFromEnum(demanded_value.expr)].ty;
                        if (recordFieldType(self.pass.program, receiver_ty, field) == null) return null;
                        const projected = try self.addExpr(.{ .ty = ty, .data = .{ .field_access = .{
                            .receiver = demanded_value.expr,
                            .field = field,
                        } } });
                        return try self.applyValueDemand(Value{ .expr = projected }, resolved_demand);
                    }
                    return null;
                };
                return try self.applyValueDemand(field_value, resolved_demand);
            }
        }

        const field_value = (try self.fieldFromPatternValue(value, field, ty)) orelse return null;
        return try self.applyValueDemand(field_value, resolved_demand);
    }

    fn itemFromPatternValue(
        self: *Cloner,
        value: Value,
        index: u32,
        ty: Type.TypeId,
    ) LowerError!?Value {
        if (itemFromValue(value, index)) |item_value| return item_value;
        if (value == .let_) {
            const let_value = value.let_;
            const item_value = (try self.itemFromPatternValue(let_value.body.*, index, ty)) orelse return null;
            return try self.wrapPendingLets(item_value, let_value.lets, true);
        }
        if (value == .if_) {
            const if_value = value.if_;
            const branches = try self.pass.arena.allocator().alloc(IfValueBranch, if_value.branches.len);
            for (if_value.branches, branches) |branch, *out| {
                out.* = .{
                    .cond = branch.cond,
                    .body = (try self.itemFromPatternValue(branch.body, index, ty)) orelse return null,
                };
            }
            const final_else = try self.pass.arena.allocator().create(Value);
            final_else.* = (try self.itemFromPatternValue(if_value.final_else.*, index, ty)) orelse return null;
            return Value{ .if_ = .{
                .ty = ty,
                .branches = branches,
                .final_else = final_else,
            } };
        }
        if (value == .match_) {
            const match_value = value.match_;
            const branches = try self.pass.arena.allocator().alloc(MatchValueBranch, match_value.branches.len);
            for (match_value.branches, branches) |branch, *out| {
                const branch_body = try self.cloneMatchValueBranchBodyWithDemand(
                    branch,
                    try self.pass.demandTupleItem(index, .materialize),
                );
                const body = (try self.itemFromPatternValue(branch_body, index, ty)) orelse {
                    return null;
                };
                out.* = .{
                    .pat = branch.pat,
                    .guard = branch.guard,
                    .body = body,
                };
            }
            return Value{ .match_ = .{
                .ty = ty,
                .scrutinee = match_value.scrutinee,
                .branches = branches,
                .comptime_site = match_value.comptime_site,
            } };
        }
        if (value == .private_state) {
            if (privateStateItem(value.private_state, index)) |item_value| {
                if (!sameType(self.pass.program, ty, privateStateValueType(item_value))) return null;
                return Value{ .private_state = item_value };
            }
            if (try self.substitutedPrivateLeafValue(value.private_state)) |substituted| {
                if (try self.itemFromPatternValue(substituted, index, ty)) |item_value| return item_value;
            }
            if (privateStateLeafExpr(value.private_state)) |leaf_expr| {
                if (try self.itemFromPrivateLeafExpr(leaf_expr, index)) |item_value| return item_value;
            }
        }
        if (value == .expr) {
            if (try self.retargetCrashTailBlock(value.expr, ty)) |expr| return Value{ .expr = expr };
        }

        const projected_from = try self.projectablePatternValue(value);
        const known_value = switch (projected_from) {
            .expr_with_known_value => |known| itemKnownValueFromKnownValue(known.known_value, index),
            else => null,
        };
        const receiver = projectableExprFromValue(projected_from) orelse return null;
        if (!canReadFieldsFromExpr(self.pass.program, receiver)) return null;
        const receiver_ty = self.pass.program.exprs.items[@intFromEnum(receiver)].ty;
        if (tupleItemType(self.pass.program, receiver_ty, index) == null) return null;
        const item_expr = try self.addExpr(.{ .ty = ty, .data = .{ .tuple_access = .{
            .tuple = receiver,
            .elem_index = index,
        } } });
        return if (known_value) |known|
            valueFromProjectedExpr(item_expr, known)
        else
            Value{ .expr = item_expr };
    }

    fn itemFromPatternValueDemanded(
        self: *Cloner,
        value: Value,
        index: u32,
        ty: Type.TypeId,
        demand: ValueDemand,
    ) LowerError!?Value {
        const resolved_demand = self.resolveLoopDemandRef(demand);
        if (resolved_demand == .none) return try self.itemFromPatternValue(value, index, ty);
        if (resolved_demand == .loop_param) Common.invariant("loop demand reference did not resolve before tuple item read");
        if (resolved_demand == .fn_param) Common.invariant("function demand reference did not resolve before tuple item read");

        if (value == .let_) {
            const let_value = value.let_;
            const item_value = (try self.itemFromPatternValueDemanded(let_value.body.*, index, ty, resolved_demand)) orelse return null;
            return try self.wrapPendingLets(item_value, let_value.lets, true);
        }
        if (value == .if_) {
            const if_value = value.if_;
            const branches = try self.pass.arena.allocator().alloc(IfValueBranch, if_value.branches.len);
            for (if_value.branches, branches) |branch, *out| {
                out.* = .{
                    .cond = branch.cond,
                    .body = (try self.itemFromPatternValueDemanded(branch.body, index, ty, resolved_demand)) orelse return null,
                };
            }
            const final_else = try self.pass.arena.allocator().create(Value);
            final_else.* = (try self.itemFromPatternValueDemanded(if_value.final_else.*, index, ty, resolved_demand)) orelse return null;
            return Value{ .if_ = .{
                .ty = ty,
                .branches = branches,
                .final_else = final_else,
            } };
        }
        if (value == .match_) {
            const match_value = value.match_;
            const container_demand = try self.pass.demandTupleItem(index, resolved_demand);
            const branches = try self.pass.arena.allocator().alloc(MatchValueBranch, match_value.branches.len);
            for (match_value.branches, branches) |branch, *out| {
                const branch_body = try self.cloneMatchValueBranchBodyWithDemand(branch, container_demand);
                const projected_body = (try self.itemFromPatternValueDemanded(branch_body, index, ty, resolved_demand)) orelse {
                    return null;
                };
                out.* = .{
                    .pat = branch.pat,
                    .guard = branch.guard,
                    .body = projected_body,
                };
            }
            return Value{ .match_ = .{
                .ty = ty,
                .scrutinee = match_value.scrutinee,
                .branches = branches,
                .comptime_site = match_value.comptime_site,
            } };
        }
        if (value == .expr and !canReadFieldsFromExpr(self.pass.program, value.expr)) {
            const expr = self.pass.program.exprs.items[@intFromEnum(value.expr)];
            if (expr.data == .loop_) {
                if (tupleItemType(self.pass.program, expr.ty, index) == null) return null;
                const projected = try self.addExpr(.{ .ty = ty, .data = .{ .tuple_access = .{
                    .tuple = value.expr,
                    .elem_index = index,
                } } });
                return try self.applyValueDemand(Value{ .expr = projected }, resolved_demand);
            }
            const demanded_value = try self.cloneExprValueWithDemand(value.expr, try self.pass.demandTupleItem(index, resolved_demand));
            const item_value = (try self.itemFromPatternValue(demanded_value, index, ty)) orelse {
                if (demanded_value == .expr) {
                    if (try self.retargetCrashTailBlock(demanded_value.expr, ty)) |retargeted| {
                        return try self.applyValueDemand(Value{ .expr = retargeted }, resolved_demand);
                    }
                    const receiver_ty = self.pass.program.exprs.items[@intFromEnum(demanded_value.expr)].ty;
                    if (tupleItemType(self.pass.program, receiver_ty, index) == null) return null;
                    const projected = try self.addExpr(.{ .ty = ty, .data = .{ .tuple_access = .{
                        .tuple = demanded_value.expr,
                        .elem_index = index,
                    } } });
                    return try self.applyValueDemand(Value{ .expr = projected }, resolved_demand);
                }
                return null;
            };
            return try self.applyValueDemand(item_value, resolved_demand);
        }

        const item_value = (try self.itemFromPatternValue(value, index, ty)) orelse return null;
        return try self.applyValueDemand(item_value, resolved_demand);
    }

    fn retargetCrashTailBlock(
        self: *Cloner,
        expr_id: Ast.ExprId,
        ty: Type.TypeId,
    ) LowerError!?Ast.ExprId {
        const expr = self.pass.program.exprs.items[@intFromEnum(expr_id)];
        const block = switch (expr.data) {
            .block => |block| block,
            else => return null,
        };
        const final_expr = self.pass.program.exprs.items[@intFromEnum(block.final_expr)];
        const crash_msg = switch (final_expr.data) {
            .crash => |msg| msg,
            else => return null,
        };
        const retargeted_crash = try self.addExpr(.{ .ty = ty, .data = .{ .crash = crash_msg } });
        return try self.addExpr(.{ .ty = ty, .data = .{ .block = .{
            .statements = block.statements,
            .final_expr = retargeted_crash,
        } } });
    }

    fn substitutedPrivateLeafValue(self: *Cloner, value: PrivateStateValue) LowerError!?Value {
        const leaf_expr = privateStateLeafExpr(value) orelse return null;
        return try self.substitutedFieldOrTupleReadValue(leaf_expr);
    }

    fn substitutedFieldOrTupleReadValue(self: *Cloner, expr_id: Ast.ExprId) LowerError!?Value {
        const expr = self.pass.program.exprs.items[@intFromEnum(expr_id)];
        return switch (expr.data) {
            .local => |local| self.subst.get(local),
            .field_access => |field| blk: {
                const receiver = (try self.substitutedFieldOrTupleReadValue(field.receiver)) orelse break :blk null;
                break :blk try self.fieldFromPatternValue(receiver, field.field, expr.ty);
            },
            .tuple_access => |access| blk: {
                const receiver = (try self.substitutedFieldOrTupleReadValue(access.tuple)) orelse break :blk null;
                break :blk try self.itemFromPatternValue(receiver, access.elem_index, expr.ty);
            },
            .comptime_branch_taken => |taken| try self.substitutedFieldOrTupleReadValue(taken.body),
            else => null,
        };
    }

    fn normalizedPrivateStateValue(self: *Cloner, value: PrivateStateValue) LowerError!PrivateStateValue {
        return switch (value) {
            .leaf => |leaf| blk: {
                const substituted = (try self.substitutedPrivateLeafValue(value)) orelse break :blk value;
                if (substituted == .private_state and privateStateEql(self.pass.program, substituted.private_state, value)) {
                    break :blk value;
                }
                if (!sameType(self.pass.program, leaf.ty, valueType(self.pass.program, substituted))) {
                    break :blk value;
                }
                const normalized = if (substituted == .private_state)
                    try self.normalizedPrivateStateValue(substituted.private_state)
                else
                    (try self.privateStateLeafFromValue(substituted)) orelse value;
                break :blk normalized;
            },
            .tag => |tag| blk: {
                const payloads = try self.pass.arena.allocator().alloc(PrivateStateIndexedValue, tag.payloads.len);
                for (tag.payloads, payloads) |payload, *out| {
                    out.* = .{
                        .index = payload.index,
                        .value = try self.normalizedPrivateStateValue(payload.value),
                    };
                }
                break :blk PrivateStateValue{ .tag = .{
                    .ty = tag.ty,
                    .name = tag.name,
                    .payloads = payloads,
                } };
            },
            .record => |record| blk: {
                const fields = try self.pass.arena.allocator().alloc(PrivateStateField, record.fields.len);
                for (record.fields, fields) |field, *out| {
                    out.* = .{
                        .name = field.name,
                        .value = try self.normalizedPrivateStateValue(field.value),
                    };
                }
                break :blk PrivateStateValue{ .record = .{
                    .ty = record.ty,
                    .fields = fields,
                } };
            },
            .tuple => |tuple| blk: {
                const items = try self.pass.arena.allocator().alloc(PrivateStateIndexedValue, tuple.items.len);
                for (tuple.items, items) |item, *out| {
                    out.* = .{
                        .index = item.index,
                        .value = try self.normalizedPrivateStateValue(item.value),
                    };
                }
                break :blk PrivateStateValue{ .tuple = .{
                    .ty = tuple.ty,
                    .items = items,
                } };
            },
            .nominal => |nominal| blk: {
                const backing = if (nominal.backing) |backing_value| backing: {
                    const stored = try self.pass.arena.allocator().create(PrivateStateValue);
                    stored.* = try self.normalizedPrivateStateValue(backing_value.*);
                    break :backing stored;
                } else null;
                break :blk PrivateStateValue{ .nominal = .{
                    .ty = nominal.ty,
                    .backing = backing,
                } };
            },
            .callable => |callable| blk: {
                const captures = try self.pass.arena.allocator().alloc(PrivateStateIndexedValue, callable.captures.len);
                for (callable.captures, captures) |capture, *out| {
                    out.* = .{
                        .index = capture.index,
                        .value = try self.normalizedPrivateStateValue(capture.value),
                    };
                }
                break :blk PrivateStateValue{ .callable = .{
                    .ty = callable.ty,
                    .fn_id = callable.fn_id,
                    .captures = captures,
                    .loop_origin = callable.loop_origin,
                } };
            },
            .compact_finite_tags,
            .compact_finite_callables,
            => value,
        };
    }

    fn projectablePatternValue(
        self: *Cloner,
        value: Value,
    ) LowerError!Value {
        if (projectableExprFromValue(value)) |expr| {
            if (canReadFieldsFromExpr(self.pass.program, expr)) return value;
        }
        return value;
    }

    fn fieldFromPrivateLeafExpr(
        self: *Cloner,
        expr_id: Ast.ExprId,
        field: names.RecordFieldNameId,
    ) LowerError!?Value {
        const expr = self.pass.program.exprs.items[@intFromEnum(expr_id)];
        const fields_span = switch (expr.data) {
            .record => |fields| fields,
            else => return null,
        };

        for (self.pass.program.fieldExprSpan(fields_span)) |field_expr| {
            if (field_expr.name != field) continue;
            return Value{ .private_state = .{ .leaf = .{
                .ty = self.pass.program.exprs.items[@intFromEnum(field_expr.value)].ty,
                .expr = field_expr.value,
            } } };
        }

        return null;
    }

    fn itemFromPrivateLeafExpr(
        self: *Cloner,
        expr_id: Ast.ExprId,
        index: u32,
    ) LowerError!?Value {
        const expr = self.pass.program.exprs.items[@intFromEnum(expr_id)];
        const items_span = switch (expr.data) {
            .tuple => |items| items,
            else => return null,
        };
        const items = self.pass.program.exprSpan(items_span);
        if (index >= items.len) return null;
        return Value{ .private_state = .{ .leaf = .{
            .ty = self.pass.program.exprs.items[@intFromEnum(items[index])].ty,
            .expr = items[index],
        } } };
    }

    fn bindPatToValue(self: *Cloner, pat_id: Ast.PatId, value: Value) LowerError!bool {
        const pat = self.pass.program.pats.items[@intFromEnum(pat_id)];
        switch (pat.data) {
            .bind => |local| {
                try self.putSubst(local, value);
                return true;
            },
            .wildcard => return true,
            .as => |as| {
                if (!try self.bindPatToValue(as.pattern, value)) return false;
                try self.putSubst(as.local, value);
                return true;
            },
            .record => |fields_span| {
                const fields = try self.copyRecordDestructSpan(fields_span);
                defer self.pass.allocator.free(fields);
                if (recordFromValue(value)) |record| {
                    for (fields) |field| {
                        const field_value = fieldFromRecord(self.pass.program, record, field.name) orelse return false;
                        if (!try self.bindPatToValue(field.pattern, field_value)) return false;
                    }
                    return true;
                }
                for (fields) |field| {
                    const field_ty = self.pass.program.pats.items[@intFromEnum(field.pattern)].ty;
                    const field_value = (try self.fieldFromPatternValue(value, field.name, field_ty)) orelse return false;
                    if (!try self.bindPatToValue(field.pattern, field_value)) return false;
                }
                return true;
            },
            .tuple => |items_span| {
                const pats = try self.copyPatSpan(items_span);
                defer self.pass.allocator.free(pats);
                if (tupleFromValue(value)) |tuple| {
                    if (pats.len != tuple.items.len) return false;
                    for (pats, tuple.items) |child_pat, child_value| {
                        if (!try self.bindPatToValue(child_pat, child_value)) return false;
                    }
                    return true;
                }
                for (pats, 0..) |child_pat, index| {
                    const item_ty = self.pass.program.pats.items[@intFromEnum(child_pat)].ty;
                    const item_value = (try self.itemFromPatternValue(value, @intCast(index), item_ty)) orelse return false;
                    if (!try self.bindPatToValue(child_pat, item_value)) return false;
                }
                return true;
            },
            .tag => |tag_pat| {
                const pats = try self.copyPatSpan(tag_pat.payloads);
                defer self.pass.allocator.free(pats);
                if (tagFromValue(value)) |tag| {
                    if (tag.name != tag_pat.name) return false;
                    if (pats.len != tag.payloads.len) return false;
                    for (pats, tag.payloads) |child_pat, child_value| {
                        if (!try self.bindPatToValue(child_pat, child_value)) return false;
                    }
                    return true;
                }

                const private_tag = switch (value) {
                    .private_state => |private_state| privateStateTag(private_state) orelse return false,
                    else => return false,
                };
                if (private_tag.name != tag_pat.name) {
                    return false;
                }
                for (pats, 0..) |child_pat, index| {
                    const child_value = privateStateIndexedValueByIndex(private_tag.payloads, @intCast(index)) orelse {
                        return false;
                    };
                    if (!try self.bindPatToValue(child_pat, .{ .private_state = child_value })) {
                        return false;
                    }
                }
                return true;
            },
            .nominal => |backing_pat| {
                const nominal = switch (value) {
                    .nominal => |nominal| nominal,
                    else => return false,
                };
                return try self.bindPatToValue(backing_pat, nominal.backing.*);
            },
            // List patterns are not statically bound during specialization.
            .list,
            .int_lit,
            .dec_lit,
            .frac_f32_lit,
            .frac_f64_lit,
            .str_lit,
            .str_pattern,
            => return false,
        }
    }

    fn bindPatToDemandedValue(
        self: *Cloner,
        pat_id: Ast.PatId,
        value: Value,
        demand: ValueDemand,
    ) LowerError!bool {
        if (demand == .none) return true;
        if (demand == .materialize) return try self.bindPatToValue(pat_id, value);

        const pat = self.pass.program.pats.items[@intFromEnum(pat_id)];
        switch (pat.data) {
            .bind => |local| {
                try self.putSubst(local, value);
                return true;
            },
            .wildcard => return true,
            .as => |as| {
                if (!try self.bindPatToDemandedValue(as.pattern, value, demand)) return false;
                try self.putSubst(as.local, value);
                return true;
            },
            .record => |fields_span| {
                const field_demands = switch (demand) {
                    .record => |field_demands| field_demands,
                    else => return try self.bindPatToValue(pat_id, value),
                };
                const fields = try self.copyRecordDestructSpan(fields_span);
                defer self.pass.allocator.free(fields);
                for (fields) |field| {
                    const field_demand = fieldDemandByName(self.pass.program, field_demands, field.name) orelse continue;
                    const field_ty = self.pass.program.pats.items[@intFromEnum(field.pattern)].ty;
                    const field_value = (try self.fieldFromPatternValueDemanded(value, field.name, field_ty, field_demand.demand.*)) orelse return false;
                    if (!try self.bindPatToDemandedValue(field.pattern, field_value, field_demand.demand.*)) return false;
                }
                return true;
            },
            .tuple => |items_span| {
                const item_demands = switch (demand) {
                    .tuple => |item_demands| item_demands,
                    else => return try self.bindPatToValue(pat_id, value),
                };
                const pats = try self.copyPatSpan(items_span);
                defer self.pass.allocator.free(pats);
                for (pats, 0..) |child_pat, index| {
                    const item_demand = itemDemandByIndex(item_demands, @intCast(index)) orelse continue;
                    const item_ty = self.pass.program.pats.items[@intFromEnum(child_pat)].ty;
                    const item_value = (try self.itemFromPatternValueDemanded(value, @intCast(index), item_ty, item_demand.demand.*)) orelse {
                        return false;
                    };
                    if (!try self.bindPatToDemandedValue(child_pat, item_value, item_demand.demand.*)) {
                        return false;
                    }
                }
                return true;
            },
            .tag => |tag_pat| {
                const tag_demand = switch (demand) {
                    .tag => |tag_demand| tag_demand,
                    else => return try self.bindPatToValue(pat_id, value),
                };
                if (!patternTagChoiceMatchesValue(self.pass.program, pat_id, value)) return false;
                const pats = try self.copyPatSpan(tag_pat.payloads);
                defer self.pass.allocator.free(pats);
                const alternative_demand = tagAlternativeDemandByName(self.pass.program, tag_demand.alternatives, tag_pat.name) orelse return true;
                for (pats, 0..) |child_pat, index| {
                    const payload_demand = itemDemandByIndex(alternative_demand.payloads, @intCast(index)) orelse continue;
                    const payload_value = tagPayloadFromValue(value, @intCast(index)) orelse return false;
                    if (!try self.bindPatToDemandedValue(child_pat, payload_value, payload_demand.demand.*)) return false;
                }
                return true;
            },
            .nominal => |backing_pat| {
                const backing_demand = switch (demand) {
                    .nominal => |backing_demand| backing_demand.*,
                    else => return try self.bindPatToValue(pat_id, value),
                };
                const backing_value = switch (value) {
                    .nominal => |nominal| nominal.backing.*,
                    .private_state => |private_state| switch (private_state) {
                        .nominal => |nominal| if (nominal.backing) |backing| Value{ .private_state = backing.* } else return false,
                        else => value,
                    },
                    else => value,
                };
                return try self.bindPatToDemandedValue(backing_pat, backing_value, backing_demand);
            },
            .list,
            .int_lit,
            .dec_lit,
            .frac_f32_lit,
            .frac_f64_lit,
            .str_lit,
            .str_pattern,
            => return false,
        }
    }

    fn bindPatToReusableValue(self: *Cloner, pat_id: Ast.PatId, value: Value) LowerError!bool {
        if (!self.valueCanSubstitute(value)) return false;
        return try self.bindPatToValue(pat_id, value);
    }

    fn bindPatToSingleUseTailValue(self: *Cloner, pat_id: Ast.PatId, value: Value, tail: BlockTail) LowerError!bool {
        const pat = self.pass.program.pats.items[@intFromEnum(pat_id)];
        switch (pat.data) {
            .bind => |local| {
                const uses = localMaxUseCountPerPathInBlockTail(self.pass.program, local, tail);
                const before_effect = localUseBeforeEffectInBlockTail(self.pass.program, local, tail);
                if (uses != 1) return false;
                if (!before_effect) return false;
                try self.putSubst(local, value);
                return true;
            },
            .wildcard,
            .as,
            .record,
            .tuple,
            .list,
            .tag,
            .nominal,
            .int_lit,
            .dec_lit,
            .frac_f32_lit,
            .frac_f64_lit,
            .str_lit,
            .str_pattern,
            => return false,
        }
    }

    fn bindPatToSingleUseRestValue(self: *Cloner, pat_id: Ast.PatId, value: Value, rest: Ast.ExprId) LowerError!bool {
        return try self.bindPatToSingleUseTailValue(pat_id, value, .{
            .statements = &.{},
            .final_expr = rest,
        });
    }

    fn bindPatToMaterializedKnownValue(self: *Cloner, pat_id: Ast.PatId, value: Value) LowerError!bool {
        const known_value = (try self.pass.knownValueFromValue(value)) orelse return false;
        return try self.bindPatToExprWithKnownValueAndValue(pat_id, known_value, value);
    }

    fn bindPatToExprWithKnownValue(self: *Cloner, pat_id: Ast.PatId, known_value: KnownValue) LowerError!bool {
        return try self.bindPatToExprWithKnownValueAndValue(pat_id, known_value, null);
    }

    fn bindPatToExprWithKnownValueAndValue(
        self: *Cloner,
        pat_id: Ast.PatId,
        known_value: KnownValue,
        maybe_value: ?Value,
    ) LowerError!bool {
        const pat = self.pass.program.pats.items[@intFromEnum(pat_id)];
        switch (pat.data) {
            .bind => |local| {
                const local_ty = self.pass.program.locals.items[@intFromEnum(local)].ty;
                const local_expr = try self.addExpr(.{
                    .ty = local_ty,
                    .data = .{ .local = local },
                });
                try self.putSubst(local, .{ .expr_with_known_value = .{
                    .expr = local_expr,
                    .known_value = known_value,
                    .value = if (maybe_value) |value| try self.copyValue(value) else null,
                } });
                return true;
            },
            .wildcard => return true,
            .as => |as| {
                if (!try self.bindPatToExprWithKnownValueAndValue(as.pattern, known_value, maybe_value)) return false;
                const local_ty = self.pass.program.locals.items[@intFromEnum(as.local)].ty;
                const local_expr = try self.addExpr(.{
                    .ty = local_ty,
                    .data = .{ .local = as.local },
                });
                try self.putSubst(as.local, .{ .expr_with_known_value = .{
                    .expr = local_expr,
                    .known_value = known_value,
                    .value = if (maybe_value) |value| try self.copyValue(value) else null,
                } });
                return true;
            },
            .record => |fields_span| {
                const fields = try self.copyRecordDestructSpan(fields_span);
                defer self.pass.allocator.free(fields);
                for (fields) |field| {
                    const field_known_value = fieldKnownValueFromKnownValue(self.pass.program, known_value, field.name) orelse
                        KnownValue{ .any = self.pass.program.pats.items[@intFromEnum(field.pattern)].ty };
                    const field_value = if (maybe_value) |value| fieldFromValue(self.pass.program, value, field.name) else null;
                    if (!try self.bindPatToExprWithKnownValueAndValue(field.pattern, field_known_value, field_value)) return false;
                }
                return true;
            },
            .tuple => |items_span| {
                const pats = try self.copyPatSpan(items_span);
                defer self.pass.allocator.free(pats);
                for (pats, 0..) |child_pat, index| {
                    const item_known_value = itemKnownValueFromKnownValue(known_value, @as(u32, @intCast(index))) orelse
                        KnownValue{ .any = self.pass.program.pats.items[@intFromEnum(child_pat)].ty };
                    const item_value = if (maybe_value) |value| itemFromValue(value, @intCast(index)) else null;
                    if (!try self.bindPatToExprWithKnownValueAndValue(child_pat, item_known_value, item_value)) return false;
                }
                return true;
            },
            .tag => |tag_pat| {
                const pats = try self.copyPatSpan(tag_pat.payloads);
                defer self.pass.allocator.free(pats);
                if (knownTagForPattern(known_value, tag_pat.name)) |tag_known_value| {
                    if (pats.len != tag_known_value.payloads.len) return false;
                    for (pats, tag_known_value.payloads, 0..) |child_pat, payload_known_value, index| {
                        const payload_value = if (maybe_value) |value| tagPayloadFromValue(value, @intCast(index)) else null;
                        if (!try self.bindPatToExprWithKnownValueAndValue(child_pat, payload_known_value, payload_value)) return false;
                    }
                } else {
                    for (pats, 0..) |child_pat, index| {
                        const payload_known_value = KnownValue{ .any = self.pass.program.pats.items[@intFromEnum(child_pat)].ty };
                        const payload_value = if (maybe_value) |value| tagPayloadFromValue(value, @intCast(index)) else null;
                        if (!try self.bindPatToExprWithKnownValueAndValue(child_pat, payload_known_value, payload_value)) return false;
                    }
                }
                return true;
            },
            .nominal => |backing_pat| {
                const backing_known_value = switch (known_value) {
                    .nominal => |nominal| nominal.backing.*,
                    else => KnownValue{ .any = self.pass.program.pats.items[@intFromEnum(backing_pat)].ty },
                };
                const backing_value = if (maybe_value) |value| switch (value) {
                    .nominal => |nominal| nominal.backing.*,
                    else => value,
                } else null;
                return try self.bindPatToExprWithKnownValueAndValue(backing_pat, backing_known_value, backing_value);
            },
            .list,
            .int_lit,
            .dec_lit,
            .frac_f32_lit,
            .frac_f64_lit,
            .str_lit,
            .str_pattern,
            => return false,
        }
    }

    fn upgradePatternBindingsWithKnownValue(
        self: *Cloner,
        pat_id: Ast.PatId,
        known_value: KnownValue,
    ) LowerError!void {
        const pat = self.pass.program.pats.items[@intFromEnum(pat_id)];
        switch (pat.data) {
            .bind => |local| try self.upgradePatternBindLocalWithKnownValue(local, known_value),
            .wildcard => {},
            .as => |as| {
                try self.upgradePatternBindingsWithKnownValue(as.pattern, known_value);
                try self.upgradePatternBindLocalWithKnownValue(as.local, known_value);
            },
            .record => |fields_span| {
                const fields = try self.copyRecordDestructSpan(fields_span);
                defer self.pass.allocator.free(fields);
                for (fields) |field| {
                    const field_known_value = fieldKnownValueFromKnownValue(self.pass.program, known_value, field.name) orelse
                        KnownValue{ .any = self.pass.program.pats.items[@intFromEnum(field.pattern)].ty };
                    try self.upgradePatternBindingsWithKnownValue(field.pattern, field_known_value);
                }
            },
            .tuple => |items_span| {
                const pats = try self.copyPatSpan(items_span);
                defer self.pass.allocator.free(pats);
                for (pats, 0..) |child_pat, index| {
                    const item_known_value = itemKnownValueFromKnownValue(known_value, @as(u32, @intCast(index))) orelse
                        KnownValue{ .any = self.pass.program.pats.items[@intFromEnum(child_pat)].ty };
                    try self.upgradePatternBindingsWithKnownValue(child_pat, item_known_value);
                }
            },
            .tag => |tag_pat| {
                const pats = try self.copyPatSpan(tag_pat.payloads);
                defer self.pass.allocator.free(pats);
                if (knownTagForPattern(known_value, tag_pat.name)) |tag_known_value| {
                    if (pats.len != tag_known_value.payloads.len) return;
                    for (pats, tag_known_value.payloads) |child_pat, payload_known_value| {
                        try self.upgradePatternBindingsWithKnownValue(child_pat, payload_known_value);
                    }
                } else {
                    for (pats) |child_pat| {
                        try self.upgradePatternBindingsWithKnownValue(child_pat, .{
                            .any = self.pass.program.pats.items[@intFromEnum(child_pat)].ty,
                        });
                    }
                }
            },
            .nominal => |backing_pat| {
                const backing_known_value = switch (known_value) {
                    .nominal => |nominal| nominal.backing.*,
                    else => KnownValue{ .any = self.pass.program.pats.items[@intFromEnum(backing_pat)].ty },
                };
                try self.upgradePatternBindingsWithKnownValue(backing_pat, backing_known_value);
            },
            .list,
            .int_lit,
            .dec_lit,
            .frac_f32_lit,
            .frac_f64_lit,
            .str_lit,
            .str_pattern,
            => {},
        }
    }

    fn upgradePatternBindLocalWithKnownValue(
        self: *Cloner,
        local: Ast.LocalId,
        known_value: KnownValue,
    ) Allocator.Error!void {
        if (known_value == .any) return;
        const existing = self.subst.get(local) orelse return;
        switch (existing) {
            .expr => |expr| try self.putSubst(local, .{ .expr_with_known_value = .{
                .expr = expr,
                .known_value = known_value,
            } }),
            .expr_with_known_value => |known| try self.putSubst(local, .{ .expr_with_known_value = .{
                .expr = known.expr,
                .known_value = known_value,
                .value = known.value,
            } }),
            else => {},
        }
    }

    fn copyPatSpan(self: *Cloner, span: Ast.Span(Ast.PatId)) Allocator.Error![]Ast.PatId {
        return try self.pass.allocator.dupe(Ast.PatId, self.pass.program.patSpan(span));
    }

    fn copyRecordDestructSpan(self: *Cloner, span: Ast.Span(Ast.RecordDestruct)) Allocator.Error![]Ast.RecordDestruct {
        return try self.pass.allocator.dupe(Ast.RecordDestruct, self.pass.program.recordDestructSpan(span));
    }

    fn clonePat(self: *Cloner, pat_id: Ast.PatId) Allocator.Error!Ast.PatId {
        const pat = self.pass.program.pats.items[@intFromEnum(pat_id)];
        const data: Ast.PatData = switch (pat.data) {
            .bind => |local| .{ .bind = local },
            .wildcard => .wildcard,
            .as => |as| .{ .as = .{
                .pattern = try self.clonePat(as.pattern),
                .local = as.local,
            } },
            .record => |fields| .{ .record = try self.cloneRecordDestructSpan(fields) },
            .tuple => |items| .{ .tuple = try self.clonePatSpan(items) },
            .list => |list| .{ .list = .{
                .patterns = try self.clonePatSpan(list.patterns),
                .rest = if (list.rest) |rest| .{
                    .index = rest.index,
                    .pattern = if (rest.pattern) |rest_pattern| try self.clonePat(rest_pattern) else null,
                } else null,
            } },
            .tag => |tag| .{ .tag = .{
                .name = tag.name,
                .payloads = try self.clonePatSpan(tag.payloads),
            } },
            .nominal => |backing| .{ .nominal = try self.clonePat(backing) },
            .int_lit => |value| .{ .int_lit = value },
            .dec_lit => |value| .{ .dec_lit = value },
            .frac_f32_lit => |value| .{ .frac_f32_lit = value },
            .frac_f64_lit => |value| .{ .frac_f64_lit = value },
            .str_lit => |value| .{ .str_lit = value },
            .str_pattern => |str| .{ .str_pattern = try self.cloneStrPattern(str) },
        };
        return try self.pass.program.addPat(.{ .ty = pat.ty, .data = data });
    }

    fn cloneStrPattern(self: *Cloner, str: Ast.StrPattern) Allocator.Error!Ast.StrPattern {
        const input_steps = self.pass.program.strPatternStepSpan(str.steps);
        const output_steps = try self.pass.allocator.alloc(Ast.StrPatternStep, input_steps.len);
        defer self.pass.allocator.free(output_steps);

        for (input_steps, output_steps) |input_step, *output_step| {
            output_step.* = .{
                .capture = if (input_step.capture) |capture| try self.clonePat(capture) else null,
                .delimiter = input_step.delimiter,
            };
        }

        return .{
            .prefix = str.prefix,
            .steps = try self.pass.program.addStrPatternStepSpan(output_steps),
            .end = str.end,
        };
    }

    fn cloneStmtInto(
        self: *Cloner,
        stmt_id: Ast.StmtId,
        out: *std.ArrayList(Ast.StmtId),
        tail: BlockTail,
        context: ValueDemand,
    ) LowerError!void {
        const saved_loc = self.current_loc;
        defer self.current_loc = saved_loc;
        const saved_region = self.current_region;
        defer self.current_region = saved_region;
        self.current_loc = self.pass.program.stmtLoc(stmt_id);
        self.current_region = self.pass.program.stmtRegion(stmt_id);

        const stmt = self.pass.program.stmts.items[@intFromEnum(stmt_id)];
        const cloned: Ast.Stmt = switch (stmt) {
            .uninitialized => |pat| blk: {
                try self.appendPatternScopedLocals(pat);
                break :blk .{ .uninitialized = try self.clonePat(pat) };
            },
            .let_ => |let_| blk: {
                var pattern_demand: ValueDemand = if (let_.recursive)
                    .materialize
                else
                    try self.patternDemandInBlockTail(let_.pat, tail, context);
                var value = if (let_.recursive)
                    try self.cloneExprValue(let_.value)
                else
                    try self.cloneBindingValueWithExpandedDemand(let_.value, &pattern_demand);
                if (!let_.recursive) {
                    while (value == .let_) {
                        try self.appendPendingLetStmts(value.let_.lets, out);
                        value = value.let_.body.*;
                    }

                    var pending_lets = std.ArrayList(PendingLet).empty;
                    defer pending_lets.deinit(self.pass.allocator);

                    const reusable_pending_start = pending_lets.items.len;
                    if (try self.tryMakeReusableForMatch(value, &pending_lets)) |reusable| {
                        const bind_change_start = self.changes.items.len;
                        if (try self.bindPatToReusableValue(let_.pat, reusable)) {
                            try self.appendPendingLetStmts(pending_lets.items, out);
                            return;
                        }
                        self.restore(bind_change_start);
                        pending_lets.shrinkRetainingCapacity(reusable_pending_start);
                    }

                    const bind_change_start = self.changes.items.len;
                    if (try self.bindPatToSingleUseTailValue(let_.pat, value, tail)) {
                        return;
                    }
                    self.restore(bind_change_start);

                    const demanded_drop_discards_effect = pattern_demand == .none and
                        !(try discardedExprIsEffectFree(self.pass.program, self.pass.allocator, let_.value));
                    if (!demanded_drop_discards_effect and
                        try self.bindPatToDemandedValue(let_.pat, value, pattern_demand))
                    {
                        return;
                    }
                    self.restore(bind_change_start);
                }
                const value_expr = try self.materialize(value);
                if (!let_.recursive and try self.bindPatToReusableValue(let_.pat, value)) {
                    return;
                }
                _ = try self.bindPatToMaterializedKnownValue(let_.pat, value);
                // The emitted statement binds these locals for the rest of the
                // block being cloned; the enclosing block clone restores them.
                try self.appendPatternScopedLocals(let_.pat);
                break :blk .{ .let_ = .{
                    .pat = try self.clonePat(let_.pat),
                    .value = value_expr,
                    .recursive = let_.recursive,
                    .comptime_site = let_.comptime_site,
                } };
            },
            .expr => |expr| blk: {
                const non_binding_change_start = self.changes.items.len;
                defer self.restore(non_binding_change_start);
                const non_binding_scoped_start = self.scopedLocalsLen();
                defer self.restoreScopedLocals(non_binding_scoped_start);
                const non_binding_provenance_start = self.loopProvenanceLen();
                defer self.restoreLoopProvenance(non_binding_provenance_start);

                break :blk .{ .expr = try self.cloneStmtExpr(expr, context) };
            },
            .expect => |expr| blk: {
                const non_binding_change_start = self.changes.items.len;
                defer self.restore(non_binding_change_start);
                const non_binding_scoped_start = self.scopedLocalsLen();
                defer self.restoreScopedLocals(non_binding_scoped_start);
                const non_binding_provenance_start = self.loopProvenanceLen();
                defer self.restoreLoopProvenance(non_binding_provenance_start);

                break :blk .{ .expect = try self.cloneExpr(expr) };
            },
            .dbg => |expr| blk: {
                const non_binding_change_start = self.changes.items.len;
                defer self.restore(non_binding_change_start);
                const non_binding_scoped_start = self.scopedLocalsLen();
                defer self.restoreScopedLocals(non_binding_scoped_start);
                const non_binding_provenance_start = self.loopProvenanceLen();
                defer self.restoreLoopProvenance(non_binding_provenance_start);

                break :blk .{ .dbg = try self.cloneExpr(expr) };
            },
            .return_ => |expr| blk: {
                const non_binding_change_start = self.changes.items.len;
                defer self.restore(non_binding_change_start);
                const non_binding_scoped_start = self.scopedLocalsLen();
                defer self.restoreScopedLocals(non_binding_scoped_start);
                const non_binding_provenance_start = self.loopProvenanceLen();
                defer self.restoreLoopProvenance(non_binding_provenance_start);

                break :blk .{ .return_ = try self.materialize(try self.cloneExprValueWithDemand(expr, context)) };
            },
            .crash => |msg| .{ .crash = msg },
        };
        try out.append(self.pass.allocator, try self.addStmt(cloned));
        switch (cloned) {
            .let_ => |let_| try self.appendPatternScopedLocals(let_.pat),
            .uninitialized => |pat| try self.appendPatternScopedLocals(pat),
            else => {},
        }
    }

    fn cloneStmtExpr(self: *Cloner, expr_id: Ast.ExprId, context: ValueDemand) LowerError!Ast.ExprId {
        const expr = self.pass.program.exprs.items[@intFromEnum(expr_id)];
        return switch (expr.data) {
            .break_,
            .return_,
            => try self.materialize(try self.cloneExprValueWithDemand(expr_id, context)),
            .comptime_branch_taken => |taken| try self.cloneStmtExpr(taken.body, context),
            else => if (exprContainsEscapingControlTransfer(self.pass.program, expr_id))
                try self.materialize(try self.cloneExprValueWithDemand(expr_id, context))
            else
                try self.cloneExpr(expr_id),
        };
    }

    fn appendPendingLetStmts(
        self: *Cloner,
        pending_lets: []const PendingLet,
        out: *std.ArrayList(Ast.StmtId),
    ) LowerError!void {
        for (pending_lets) |pending| {
            const pat = try self.pass.program.addPat(.{
                .ty = pending.ty,
                .data = .{ .bind = pending.local },
            });
            try out.append(self.pass.allocator, try self.addStmt(.{ .let_ = .{
                .pat = pat,
                .value = try self.pendingLetValueExpr(pending.value),
                .recursive = false,
                .comptime_site = null,
            } }));
            try self.scoped_locals.append(self.pass.allocator, pending.local);
        }
    }

    fn bindPendingLetKnownValues(self: *Cloner, pending_lets: []const PendingLet) LowerError!void {
        for (pending_lets) |pending| {
            const known_value = pending.known_value orelse continue;
            const local_expr = try self.addExpr(.{
                .ty = pending.ty,
                .data = .{ .local = pending.local },
            });
            try self.putSubst(pending.local, .{ .expr_with_known_value = .{
                .expr = local_expr,
                .known_value = known_value,
                .value = pending.structured_value,
            } });
        }
    }

    fn appendPendingLetsUnique(
        self: *Cloner,
        out: *std.ArrayList(PendingLet),
        pending_lets: []const PendingLet,
    ) Allocator.Error!void {
        for (pending_lets) |pending| {
            var seen = false;
            for (out.items) |existing| {
                if (existing.local == pending.local) {
                    seen = true;
                    break;
                }
            }
            if (!seen) try out.append(self.pass.allocator, pending);
        }
    }

    fn appendPendingLetsFromStatements(
        self: *Cloner,
        statements: []const Ast.StmtId,
        out: *std.ArrayList(PendingLet),
    ) Allocator.Error!bool {
        for (statements) |stmt_id| {
            const stmt = self.pass.program.stmts.items[@intFromEnum(stmt_id)];
            const let_ = switch (stmt) {
                .let_ => |let_| let_,
                .expr => |expr| {
                    if (try discardedExprIsEffectFree(self.pass.program, self.pass.allocator, expr)) continue;
                    // An effectful statement rides along as a pending let on a
                    // fresh ignored local so a structured block value can
                    // escape without materializing; the pending let emits the
                    // effect, in order, wherever the value is consumed.
                    const stmt_ty = self.pass.program.exprs.items[@intFromEnum(expr)].ty;
                    const fresh_local = try self.pass.program.addLocal(self.pass.symbols.fresh(), stmt_ty);
                    try out.append(self.pass.allocator, .{
                        .local = fresh_local,
                        .ty = stmt_ty,
                        .value = .{ .source = expr },
                    });
                    continue;
                },
                else => return false,
            };
            if (let_.recursive) return false;
            const pat = self.pass.program.pats.items[@intFromEnum(let_.pat)];
            const local = switch (pat.data) {
                .bind => |local| local,
                else => return false,
            };
            try out.append(self.pass.allocator, .{
                .local = local,
                .ty = pat.ty,
                .value = .{ .source = let_.value },
                .known_value = try self.pass.constructorKnownValue(let_.value),
            });
        }
        return true;
    }

    fn cloneExprSpan(self: *Cloner, span: Ast.Span(Ast.ExprId)) LowerError!Ast.Span(Ast.ExprId) {
        const source = try self.pass.allocator.dupe(Ast.ExprId, self.pass.program.exprSpan(span));
        defer self.pass.allocator.free(source);

        const values = try self.pass.allocator.alloc(Ast.ExprId, source.len);
        defer self.pass.allocator.free(values);
        for (source, 0..) |expr, index| values[index] = try self.cloneExpr(expr);
        return try self.pass.program.addExprSpan(values);
    }

    fn clonePatSpan(self: *Cloner, span: Ast.Span(Ast.PatId)) Allocator.Error!Ast.Span(Ast.PatId) {
        const source = try self.pass.allocator.dupe(Ast.PatId, self.pass.program.patSpan(span));
        defer self.pass.allocator.free(source);

        const values = try self.pass.allocator.alloc(Ast.PatId, source.len);
        defer self.pass.allocator.free(values);
        for (source, 0..) |pat, index| values[index] = try self.clonePat(pat);
        return try self.pass.program.addPatSpan(values);
    }

    fn cloneFieldExprSpan(self: *Cloner, span: Ast.Span(Ast.FieldExpr)) LowerError!Ast.Span(Ast.FieldExpr) {
        const source = try self.pass.allocator.dupe(Ast.FieldExpr, self.pass.program.fieldExprSpan(span));
        defer self.pass.allocator.free(source);

        const values = try self.pass.allocator.alloc(Ast.FieldExpr, source.len);
        defer self.pass.allocator.free(values);
        for (source, 0..) |field, index| {
            values[index] = .{
                .name = field.name,
                .value = try self.cloneExpr(field.value),
            };
        }
        return try self.pass.program.addFieldExprSpan(values);
    }

    fn cloneRecordDestructSpan(self: *Cloner, span: Ast.Span(Ast.RecordDestruct)) Allocator.Error!Ast.Span(Ast.RecordDestruct) {
        const source = try self.pass.allocator.dupe(Ast.RecordDestruct, self.pass.program.recordDestructSpan(span));
        defer self.pass.allocator.free(source);

        const values = try self.pass.allocator.alloc(Ast.RecordDestruct, source.len);
        defer self.pass.allocator.free(values);
        for (source, 0..) |field, index| {
            values[index] = .{
                .name = field.name,
                .pattern = try self.clonePat(field.pattern),
            };
        }
        return try self.pass.program.addRecordDestructSpan(values);
    }

    fn cloneBranchSpanWithScrutineeKnownValue(
        self: *Cloner,
        span: Ast.Span(Ast.Branch),
        scrutinee_known_value: ?KnownValue,
    ) LowerError!Ast.Span(Ast.Branch) {
        const source = try self.pass.allocator.dupe(Ast.Branch, self.pass.program.branchSpan(span));
        defer self.pass.allocator.free(source);

        var values = std.ArrayList(Ast.Branch).empty;
        defer values.deinit(self.pass.allocator);
        for (source) |branch| {
            if (scrutinee_known_value) |known_value| {
                if (patternDefinitelyExcludedByKnownValue(self.pass.program, branch.pat, known_value)) continue;
            }
            const change_start = self.changes.items.len;
            if (scrutinee_known_value) |known_value| {
                _ = try self.bindPatToExprWithKnownValue(branch.pat, known_value);
            }
            {
                const scoped_start = self.scopedLocalsLen();
                defer self.restoreScopedLocals(scoped_start);
                try self.appendPatternScopedLocals(branch.pat);
                try values.append(self.pass.allocator, .{
                    .pat = try self.clonePat(branch.pat),
                    .guard = if (branch.guard) |guard| try self.cloneExpr(guard) else null,
                    .body = try self.cloneExpr(branch.body),
                });
            }
            self.restore(change_start);
        }
        return try self.pass.program.addBranchSpan(values.items);
    }

    fn cloneIfBranchSpan(self: *Cloner, span: Ast.Span(Ast.IfBranch)) LowerError!Ast.Span(Ast.IfBranch) {
        const source = try self.pass.allocator.dupe(Ast.IfBranch, self.pass.program.ifBranchSpan(span));
        defer self.pass.allocator.free(source);

        const values = try self.pass.allocator.alloc(Ast.IfBranch, source.len);
        defer self.pass.allocator.free(values);
        for (source, 0..) |branch, index| {
            const change_start = self.changes.items.len;
            values[index] = .{
                .cond = try self.cloneExpr(branch.cond),
                .body = try self.cloneExpr(branch.body),
            };
            self.restore(change_start);
        }
        return try self.pass.program.addIfBranchSpan(values);
    }

    fn cloneStateLoopExprData(self: *Cloner, state_loop: anytype) LowerError!Ast.ExprData {
        const source = try self.pass.allocator.dupe(Ast.StateLoopState, self.pass.program.stateLoopStateSpan(state_loop.states));
        defer self.pass.allocator.free(source);

        var map_changes = std.ArrayList(StateLoopStateMapChange).empty;
        defer {
            var index = map_changes.items.len;
            while (index > 0) {
                index -= 1;
                const change = map_changes.items[index];
                if (change.previous) |previous| {
                    self.state_loop_state_map.put(change.id, previous) catch
                        Common.invariant("failed to restore state_loop state map entry");
                } else {
                    _ = self.state_loop_state_map.remove(change.id);
                }
            }
            map_changes.deinit(self.pass.allocator);
        }

        const start: u32 = @intCast(self.pass.program.state_loop_states.items.len);
        try self.pass.program.state_loop_states.ensureUnusedCapacity(self.pass.program.allocator, source.len);
        for (source, 0..) |_, index| {
            const old_id: Ast.StateLoopStateId = @enumFromInt(state_loop.states.start + @as(u32, @intCast(index)));
            const new_id: Ast.StateLoopStateId = @enumFromInt(start + @as(u32, @intCast(index)));
            try map_changes.append(self.pass.allocator, .{
                .id = old_id,
                .previous = self.state_loop_state_map.get(old_id),
            });
            try self.state_loop_state_map.put(old_id, new_id);
            self.pass.program.state_loop_states.appendAssumeCapacity(undefined);
        }

        const entry_state = self.cloneStateLoopStateId(state_loop.entry_state);
        const entry_values = try self.cloneExprSpan(state_loop.entry_values);

        for (source, 0..) |state, index| {
            const params = self.pass.program.typedLocalSpan(state.params);
            try self.state_param_stack.append(self.pass.allocator, params);
            defer _ = self.state_param_stack.pop();

            self.pass.program.state_loop_states.items[start + index] = .{
                .params = state.params,
                .body = try self.cloneExpr(state.body),
            };
        }

        return .{ .state_loop = .{
            .entry_state = entry_state,
            .entry_values = entry_values,
            .states = .{ .start = start, .len = @intCast(source.len) },
        } };
    }

    fn cloneStateLoopStateId(self: *Cloner, id: Ast.StateLoopStateId) Ast.StateLoopStateId {
        return self.state_loop_state_map.get(id) orelse
            Common.invariant("state_continue reached SpecConstr clone before its state_loop reserved the target state");
    }

    fn stateLoopStateIsMappedTarget(self: *Cloner, id: Ast.StateLoopStateId) bool {
        var values = self.state_loop_state_map.valueIterator();
        while (values.next()) |mapped| {
            if (mapped.* == id) return true;
        }
        return false;
    }

    fn activeSparseStateLoopOwnsState(self: *Cloner, id: Ast.StateLoopStateId) bool {
        var stack_index = self.state_loop_stack.items.len;
        while (stack_index > 0) {
            stack_index -= 1;
            const state_loop = self.state_loop_stack.items[stack_index];
            for (state_loop.states.items) |state| {
                if (state.id == id) return true;
            }
        }
        return false;
    }

    fn cloneStateContinueExprData(self: *Cloner, continue_: anytype) LowerError!Ast.ExprData {
        if (self.state_loop_state_map.get(continue_.target_state)) |target_state| {
            return .{ .state_continue = .{
                .target_state = target_state,
                .values = try self.cloneExprSpan(continue_.values),
            } };
        }
        if (self.stateLoopStateIsMappedTarget(continue_.target_state)) {
            return .{ .state_continue = .{
                .target_state = continue_.target_state,
                .values = try self.cloneExprSpan(continue_.values),
            } };
        }
        if (self.activeSparseStateLoopOwnsState(continue_.target_state)) {
            return .{ .state_continue = .{
                .target_state = continue_.target_state,
                .values = try self.cloneExprSpan(continue_.values),
            } };
        }
        Common.invariant("state_continue reached SpecConstr clone before its state_loop reserved the target state");
    }

    fn materialize(self: *Cloner, value: Value) LowerError!Ast.ExprId {
        switch (value) {
            .expr => |expr| {
                if (self.exprReferencesAvailableBindings(expr)) return expr;
                var seen = std.ArrayList(Ast.ExprId).empty;
                defer seen.deinit(self.pass.allocator);
                if (try self.substitutedExprValueAvoidingCycles(expr, &seen)) |substituted| {
                    if (!valueIsExpr(substituted, expr)) return try self.materialize(substituted);
                }
                const cloned = try self.cloneExprPlain(expr);
                if (!self.exprReferencesAvailableBindings(cloned)) {
                    const cloned_items = self.pass.program.exprs.items[@intFromEnum(cloned)].data;
                    if (cloned_items == .list) {
                        for (self.pass.program.exprSpan(cloned_items.list)) |elem| {
                            const elem_data = self.pass.program.exprs.items[@intFromEnum(elem)].data;
                            std.debug.print(" elem={s}", .{@tagName(elem_data)});
                            if (elem_data == .local) {
                                std.debug.print("(l{d} pending={any} direct={any})", .{
                                    @intFromEnum(elem_data.local),
                                    self.pendingLetIsActive(elem_data.local),
                                    self.localCanBeReferencedDirectly(elem_data.local),
                                });
                            }
                        }
                    }
                    std.debug.print("\n", .{});
                    Common.invariant("materialized expression still referenced unavailable bindings");
                }
                return cloned;
            },
            .expr_with_known_value => |known_value_expr| {
                if (try self.substitutedKnownExprValue(known_value_expr)) |substituted| {
                    return try self.materialize(substituted);
                }
                return known_value_expr.expr;
            },
            .let_ => |let_value| {
                const change_start = self.changes.items.len;
                defer self.restore(change_start);
                const pending_start = self.activePendingLetsLen();
                const scoped_start = try self.pushPendingLetScope(let_value.lets);
                defer self.popPendingLetScope(scoped_start, pending_start);

                const body = try self.materialize(let_value.body.*);
                return try self.wrapPendingLetsAroundExpr(valueType(self.pass.program, let_value.body.*), body, let_value.lets);
            },
            .if_ => |if_value| {
                const branches = try self.pass.allocator.alloc(Ast.IfBranch, if_value.branches.len);
                defer self.pass.allocator.free(branches);
                for (if_value.branches, 0..) |branch, index| {
                    branches[index] = .{
                        .cond = branch.cond,
                        .body = try self.materialize(branch.body),
                    };
                }
                return try self.addExpr(.{ .ty = if_value.ty, .data = .{ .if_ = .{
                    .branches = try self.pass.program.addIfBranchSpan(branches),
                    .final_else = try self.materialize(if_value.final_else.*),
                } } });
            },
            .match_ => |match_value| {
                const branches = try self.pass.allocator.alloc(Ast.Branch, match_value.branches.len);
                defer self.pass.allocator.free(branches);
                for (match_value.branches, 0..) |branch, index| {
                    const scoped_start = self.scopedLocalsLen();
                    defer self.restoreScopedLocals(scoped_start);
                    try self.appendPatternScopedLocals(branch.pat);
                    branches[index] = .{
                        .pat = branch.pat,
                        .guard = branch.guard,
                        .body = try self.materialize(branch.body),
                    };
                }
                return try self.addExpr(.{ .ty = match_value.ty, .data = .{ .match_ = .{
                    .scrutinee = match_value.scrutinee,
                    .branches = try self.pass.program.addBranchSpan(branches),
                    .comptime_site = match_value.comptime_site,
                } } });
            },
            .tag => |tag| {
                const payloads = try self.pass.allocator.alloc(Ast.ExprId, tag.payloads.len);
                defer self.pass.allocator.free(payloads);
                for (tag.payloads, 0..) |payload, index| {
                    payloads[index] = try self.materialize(payload);
                }
                return try self.addExpr(.{ .ty = tag.ty, .data = .{ .tag = .{
                    .name = tag.name,
                    .payloads = try self.pass.program.addExprSpan(payloads),
                } } });
            },
            .record => |record| {
                const fields = try self.pass.allocator.alloc(Ast.FieldExpr, record.fields.len);
                defer self.pass.allocator.free(fields);
                for (record.fields, 0..) |field, index| {
                    fields[index] = .{
                        .name = field.name,
                        .value = try self.materialize(field.value),
                    };
                }
                return try self.addExpr(.{ .ty = record.ty, .data = .{
                    .record = try self.pass.program.addFieldExprSpan(fields),
                } });
            },
            .tuple => |tuple| {
                const items = try self.pass.allocator.alloc(Ast.ExprId, tuple.items.len);
                defer self.pass.allocator.free(items);
                for (tuple.items, 0..) |item, index| {
                    items[index] = try self.materialize(item);
                }
                return try self.addExpr(.{ .ty = tuple.ty, .data = .{
                    .tuple = try self.pass.program.addExprSpan(items),
                } });
            },
            .nominal => |nominal| return try self.addExpr(.{ .ty = nominal.ty, .data = .{
                .nominal = try self.materialize(nominal.backing.*),
            } }),
            .callable => |callable| return try self.materializeCallable(callable),
            .finite_tags => |finite_tags| return try self.materialize(try self.finiteTagsAsIfValue(finite_tags)),
            .finite_callables => |finite_callables| return try self.materialize(try self.finiteCallablesAsIfValue(finite_callables)),
            .private_state => |private_state| {
                if (!privateStateCanMaterializePublic(self.pass.program, private_state)) {
                    Common.invariant("sparse private state reached materialization");
                }
                return try self.materialize(try self.publicValueFromPrivateState(private_state));
            },
        }
    }

    fn materializePublic(self: *Cloner, value: Value) LowerError!Ast.ExprId {
        switch (value) {
            .expr => |expr| return expr,
            .expr_with_known_value => |known_value_expr| {
                if (try self.substitutedKnownExprValue(known_value_expr)) |substituted| {
                    return try self.materializePublic(substituted);
                }
                return known_value_expr.expr;
            },
            .let_ => |let_value| {
                const body = try self.materializePublic(let_value.body.*);
                return try self.wrapPendingLetsAroundExpr(valueType(self.pass.program, let_value.body.*), body, let_value.lets);
            },
            .if_ => |if_value| {
                const branches = try self.pass.allocator.alloc(Ast.IfBranch, if_value.branches.len);
                defer self.pass.allocator.free(branches);
                for (if_value.branches, 0..) |branch, index| {
                    branches[index] = .{
                        .cond = branch.cond,
                        .body = try self.materializePublic(branch.body),
                    };
                }
                return try self.addExpr(.{ .ty = if_value.ty, .data = .{ .if_ = .{
                    .branches = try self.pass.program.addIfBranchSpan(branches),
                    .final_else = try self.materializePublic(if_value.final_else.*),
                } } });
            },
            .match_ => |match_value| {
                const branches = try self.pass.allocator.alloc(Ast.Branch, match_value.branches.len);
                defer self.pass.allocator.free(branches);
                for (match_value.branches, 0..) |branch, index| {
                    const scoped_start = self.scopedLocalsLen();
                    defer self.restoreScopedLocals(scoped_start);
                    try self.appendPatternScopedLocals(branch.pat);
                    branches[index] = .{
                        .pat = branch.pat,
                        .guard = branch.guard,
                        .body = try self.materializePublic(branch.body),
                    };
                }
                return try self.addExpr(.{ .ty = match_value.ty, .data = .{ .match_ = .{
                    .scrutinee = match_value.scrutinee,
                    .branches = try self.pass.program.addBranchSpan(branches),
                    .comptime_site = match_value.comptime_site,
                } } });
            },
            .tag => |tag| {
                const payloads = try self.pass.allocator.alloc(Ast.ExprId, tag.payloads.len);
                defer self.pass.allocator.free(payloads);
                for (tag.payloads, 0..) |payload, index| {
                    payloads[index] = try self.materializePublic(payload);
                }
                return try self.addExpr(.{ .ty = tag.ty, .data = .{ .tag = .{
                    .name = tag.name,
                    .payloads = try self.pass.program.addExprSpan(payloads),
                } } });
            },
            .record => |record| {
                const fields = try self.pass.allocator.alloc(Ast.FieldExpr, record.fields.len);
                defer self.pass.allocator.free(fields);
                for (record.fields, 0..) |field, index| {
                    fields[index] = .{
                        .name = field.name,
                        .value = try self.materializePublic(field.value),
                    };
                }
                return try self.addExpr(.{ .ty = record.ty, .data = .{
                    .record = try self.pass.program.addFieldExprSpan(fields),
                } });
            },
            .tuple => |tuple| {
                const items = try self.pass.allocator.alloc(Ast.ExprId, tuple.items.len);
                defer self.pass.allocator.free(items);
                for (tuple.items, 0..) |item, index| {
                    items[index] = try self.materializePublic(item);
                }
                return try self.addExpr(.{ .ty = tuple.ty, .data = .{
                    .tuple = try self.pass.program.addExprSpan(items),
                } });
            },
            .nominal => |nominal| return try self.addExpr(.{ .ty = nominal.ty, .data = .{
                .nominal = try self.materializePublic(nominal.backing.*),
            } }),
            .callable => |callable| return try self.materializePublicCallable(callable),
            .finite_tags => |finite_tags| return try self.materializePublic(try self.finiteTagsAsIfValue(finite_tags)),
            .finite_callables => |finite_callables| return try self.materializePublic(try self.finiteCallablesAsIfValue(finite_callables)),
            .private_state => |private_state| return try self.materializePublic(try self.publicValueFromPrivateState(private_state)),
        }
    }

    fn publicValueFromPrivateState(self: *Cloner, private_state: PrivateStateValue) LowerError!Value {
        return switch (private_state) {
            .leaf => |leaf| .{ .expr = leaf.expr },
            .tag => |tag| .{ .tag = try self.publicTagValueFromPrivateState(tag) },
            .record => |record| blk: {
                if (!privateStateRecordIsDense(self.pass.program, record)) {
                    Common.invariant("sparse private record reached public materialization");
                }
                const fields = try self.pass.arena.allocator().alloc(FieldValue, record.fields.len);
                for (record.fields, fields) |field, *out| {
                    out.* = .{
                        .name = field.name,
                        .value = .{ .private_state = field.value },
                    };
                }
                break :blk Value{ .record = .{
                    .ty = record.ty,
                    .fields = fields,
                } };
            },
            .tuple => |tuple| .{ .tuple = .{
                .ty = tuple.ty,
                .items = (try self.privateStateIndexedValuesAsDenseValues(tuple.items, tupleTypeItems(self.pass.program, tuple.ty).len)) orelse
                    Common.invariant("sparse private tuple reached public materialization"),
            } },
            .nominal => |nominal| blk: {
                const backing = nominal.backing orelse
                    Common.invariant("sparse private nominal reached public materialization");
                const value = try self.pass.arena.allocator().create(Value);
                value.* = .{ .private_state = backing.* };
                break :blk Value{ .nominal = .{
                    .ty = nominal.ty,
                    .backing = value,
                } };
            },
            .callable => |callable| .{ .callable = try self.publicCallableValueFromPrivateState(callable) },
            .compact_finite_tags,
            .compact_finite_callables,
            => Common.invariant("compact private finite state reached public materialization"),
        };
    }

    fn publicTagValueFromPrivateState(self: *Cloner, tag: PrivateStateTag) LowerError!TagValue {
        const expected_payloads = tagTypePayloads(self.pass.program, tag.ty, tag.name) orelse
            Common.invariant("private tag referenced a tag absent from its type");
        return .{
            .ty = tag.ty,
            .name = tag.name,
            .payloads = (try self.privateStateIndexedValuesAsDenseValues(tag.payloads, expected_payloads.len)) orelse
                Common.invariant("sparse private tag reached public materialization"),
        };
    }

    fn publicCallableValueFromPrivateState(self: *Cloner, callable: PrivateStateCallable) LowerError!CallableValue {
        const source_fn = self.pass.program.fns.items[@intFromEnum(callable.fn_id)];
        const source_captures = self.pass.program.typedLocalSpan(source_fn.captures);
        const captures = try self.pass.arena.allocator().alloc(Value, source_captures.len);
        const seen = try self.pass.allocator.alloc(bool, source_captures.len);
        defer self.pass.allocator.free(seen);
        @memset(seen, false);

        for (callable.captures) |capture| {
            if (capture.index >= source_captures.len) {
                Common.invariant("private callable capture index exceeded public capture count");
            }
            captures[capture.index] = .{ .private_state = capture.value };
            seen[capture.index] = true;
        }

        for (seen) |capture_seen| {
            if (!capture_seen) Common.invariant("sparse private callable reached public materialization");
        }

        return .{
            .ty = callable.ty,
            .fn_id = callable.fn_id,
            .captures = captures,
        };
    }

    fn materializePublicCallable(self: *Cloner, callable: CallableValue) LowerError!Ast.ExprId {
        if (!self.callableCapturesCanMaterializePublic(callable)) {
            return try self.materializeCallable(callable);
        }

        const source_fn = self.pass.program.fns.items[@intFromEnum(callable.fn_id)];
        for (self.pass.program.typedLocalSpan(source_fn.captures)) |capture| {
            if (self.subst.contains(capture.local)) return try self.materializeCallable(callable);
        }
        return try self.materializeCallableWithCaptures(
            callable.ty,
            callable.fn_id,
            source_fn.captures,
            callable.captures,
        );
    }

    fn finiteTagsAsIfValue(self: *Cloner, finite_tags: FiniteTagsValue) LowerError!Value {
        if (finite_tags.alternatives.len == 0) {
            Common.invariant("finite tag value had no alternatives");
        }
        if (finite_tags.alternatives.len == 1) {
            return .{ .tag = finite_tags.alternatives[0] };
        }

        const branch_count = finite_tags.alternatives.len - 1;
        const branches = try self.pass.arena.allocator().alloc(IfValueBranch, branch_count);
        for (finite_tags.alternatives[0..branch_count], branches, 0..) |alternative, *branch, index| {
            branch.* = .{
                .cond = try self.selectorEquals(finite_tags.selector, @intCast(index)),
                .body = .{ .tag = alternative },
            };
        }

        const final_else = try self.pass.arena.allocator().create(Value);
        final_else.* = .{ .tag = finite_tags.alternatives[branch_count] };
        return .{ .if_ = .{
            .ty = finite_tags.ty,
            .branches = branches,
            .final_else = final_else,
        } };
    }

    fn finiteCallablesAsIfValue(self: *Cloner, finite_callables: FiniteCallablesValue) LowerError!Value {
        if (finite_callables.alternatives.len == 0) {
            Common.invariant("finite callable value had no alternatives");
        }
        if (finite_callables.alternatives.len == 1) {
            return .{ .callable = finite_callables.alternatives[0] };
        }

        const branch_count = finite_callables.alternatives.len - 1;
        const branches = try self.pass.arena.allocator().alloc(IfValueBranch, branch_count);
        for (finite_callables.alternatives[0..branch_count], branches, 0..) |alternative, *branch, index| {
            branch.* = .{
                .cond = try self.selectorEquals(finite_callables.selector, @intCast(index)),
                .body = .{ .callable = alternative },
            };
        }

        const final_else = try self.pass.arena.allocator().create(Value);
        final_else.* = .{ .callable = finite_callables.alternatives[branch_count] };
        return .{ .if_ = .{
            .ty = finite_callables.ty,
            .branches = branches,
            .final_else = final_else,
        } };
    }

    fn materializeCallable(self: *Cloner, callable: CallableValue) LowerError!Ast.ExprId {
        const fn_ = self.pass.program.fns.items[@intFromEnum(callable.fn_id)];
        const captures = self.pass.program.typedLocalSpan(fn_.captures);
        if (captures.len != callable.captures.len) {
            Common.invariant("callable value capture count differed from lifted function capture count");
        }

        var all_original = true;
        for (captures, callable.captures) |capture, value| {
            if (self.subst.contains(capture.local)) {
                all_original = false;
                break;
            }
            const expr = switch (value) {
                .expr => |expr| expr,
                else => {
                    all_original = false;
                    break;
                },
            };
            const local = localExpr(self.pass.program, expr) orelse {
                all_original = false;
                break;
            };
            if (local != capture.local) {
                all_original = false;
                break;
            }
        }

        if (!all_original) {
            return try self.specializedCallableRef(callable);
        }

        return try self.addExpr(.{ .ty = callable.ty, .data = .{ .fn_ref = callable.fn_id } });
    }

    fn materializeExplicitCallableRef(
        self: *Cloner,
        ty: Type.TypeId,
        fn_id: Ast.FnId,
        capture_exprs: []const Ast.ExprId,
    ) Allocator.Error!Ast.ExprId {
        return try self.addExpr(.{ .ty = ty, .data = .{ .fn_ref_captures = .{
            .target = fn_id,
            .captures = try self.pass.program.addExprSpan(capture_exprs),
        } } });
    }

    fn specializedCallableRef(self: *Cloner, callable: CallableValue) LowerError!Ast.ExprId {
        const capture_patterns = try self.callableCapturePatterns(callable);
        if (self.existingCallableSpecialization(callable.fn_id, capture_patterns)) |existing| {
            const existing_fn = self.pass.program.fns.items[@intFromEnum(existing)];
            return try self.materializeCallableWithCapturePatterns(
                callable.ty,
                existing,
                existing_fn.captures,
                capture_patterns,
                callable.captures,
            );
        }

        const source_fn = self.pass.program.fns.items[@intFromEnum(callable.fn_id)];
        const source_body = self.pass.originalBody(callable.fn_id) orelse switch (source_fn.body) {
            .roc => |body| body,
            .hosted => Common.invariant("hosted callable value needed capture substitution"),
        };

        const source_captures = try self.pass.allocator.dupe(Ast.TypedLocal, self.pass.program.typedLocalSpan(source_fn.captures));
        defer self.pass.allocator.free(source_captures);
        if (source_captures.len != callable.captures.len) {
            Common.invariant("callable value capture count differed from lifted function capture count");
        }

        var captures = std.ArrayList(Ast.TypedLocal).empty;
        defer captures.deinit(self.pass.allocator);

        const capture_values = try self.pass.allocator.alloc(?PrivateStateValue, capture_patterns.len);
        defer self.pass.allocator.free(capture_values);
        @memset(capture_values, null);

        const change_start = self.changes.items.len;
        defer self.restore(change_start);

        for (capture_patterns, capture_values) |capture_pattern, *capture_value| {
            if (capture_pattern) |pattern| {
                capture_value.* = try self.privateStateValueFromDemandedKnownValueArgs(pattern, &captures);
            }
        }

        const captures_span = try self.pass.program.addTypedLocalSpan(captures.items);

        const source_args = try self.pass.allocator.dupe(Ast.TypedLocal, self.pass.program.typedLocalSpan(source_fn.args));
        defer self.pass.allocator.free(source_args);
        const args = try self.pass.allocator.alloc(Ast.TypedLocal, source_args.len);
        defer self.pass.allocator.free(args);
        for (source_args, 0..) |source_arg, index| {
            const local = try self.pass.program.addLocal(self.pass.symbols.fresh(), source_arg.ty);
            args[index] = .{ .local = local, .ty = source_arg.ty };
        }
        const args_span = try self.pass.program.addTypedLocalSpan(args);

        const fn_id: Ast.FnId = @enumFromInt(@as(u32, @intCast(self.pass.program.fns.items.len)));
        const symbol = self.pass.symbols.fresh();
        try self.pass.program.fns.append(self.pass.allocator, .{
            .symbol = symbol,
            .source = source_fn.source,
            .args = args_span,
            .captures = captures_span,
            .body = .hosted,
            .ret = source_fn.ret,
        });
        try self.pass.callable_specializations.append(self.pass.allocator, .{
            .source_fn = callable.fn_id,
            .captures = capture_patterns,
            .fn_id = fn_id,
        });
        try self.pass.copyProcDebugName(source_fn.symbol, symbol);

        const result = try self.materializeCallableWithCapturePatterns(
            callable.ty,
            fn_id,
            captures_span,
            capture_patterns,
            callable.captures,
        );

        var body_cloner = Cloner.initForBaseBody(self.pass, fn_id);
        defer body_cloner.deinit();

        for (source_captures, capture_values) |source_capture, capture_value| {
            if (capture_value) |value| {
                try body_cloner.putSubst(source_capture.local, .{ .private_state = value });
            }
        }

        for (source_args, args) |source_arg, arg| {
            const arg_expr = try self.addExpr(.{
                .ty = arg.ty,
                .data = .{ .local = arg.local },
            });
            try body_cloner.putSubst(source_arg.local, .{ .expr = arg_expr });
        }

        const cloned_body = try body_cloner.cloneExpr(source_body);
        self.pass.program.fns.items[@intFromEnum(fn_id)] = .{
            .symbol = symbol,
            .source = source_fn.source,
            .args = args_span,
            .captures = captures_span,
            .body = .{ .roc = cloned_body },
            .ret = source_fn.ret,
        };

        return result;
    }

    fn callableCapturePatterns(self: *Cloner, callable: CallableValue) LowerError![]const ?DemandedKnownValue {
        const source_fn = self.pass.program.fns.items[@intFromEnum(callable.fn_id)];
        const source_captures = self.pass.program.typedLocalSpan(source_fn.captures);
        if (source_captures.len != callable.captures.len) {
            Common.invariant("callable value capture count differed from lifted function capture count");
        }

        const captures = try self.pass.arena.allocator().alloc(?DemandedKnownValue, callable.captures.len);
        for (source_captures, callable.captures, captures) |source_capture, capture, *out| {
            const demand = try self.functionLocalDemand(callable.fn_id, source_capture.local, .materialize);
            if (demand == .none) {
                out.* = null;
                continue;
            }

            if (try self.demandedKnownValueFromAvailableValueDemand(capture, demand)) |pattern| {
                out.* = try self.compactDemandedKnownValue(pattern);
                continue;
            }

            if (capture == .private_state and !privateStateCanMaterializePublic(self.pass.program, capture.private_state)) {
                Common.invariant("sparse callable capture could not satisfy demanded callable specialization");
            }

            const known_value = (try self.pass.knownValueFromValue(capture)) orelse
                KnownValue{ .any = valueType(self.pass.program, capture) };
            out.* = try self.compactDemandedKnownValue(try materializedDemandedKnownValue(self.pass.arena.allocator(), known_value));
        }
        return captures;
    }

    fn existingCallableSpecialization(
        self: *Cloner,
        source_fn: Ast.FnId,
        capture_patterns: []const ?DemandedKnownValue,
    ) ?Ast.FnId {
        for (self.pass.callable_specializations.items) |specialization| {
            if (specialization.source_fn != source_fn) continue;
            if (specialization.captures.len != capture_patterns.len) continue;
            var matches = true;
            for (specialization.captures, capture_patterns) |existing, requested| {
                if (existing == null or requested == null) {
                    if (existing != null or requested != null) {
                        matches = false;
                        break;
                    }
                    continue;
                }
                if (!demandedKnownValueEql(self.pass.program, existing.?, requested.?)) {
                    matches = false;
                    break;
                }
            }
            if (matches) return specialization.fn_id;
        }
        return null;
    }

    fn materializeCallableWithCapturePatterns(
        self: *Cloner,
        ty: Type.TypeId,
        fn_id: Ast.FnId,
        captures_span: Ast.Span(Ast.TypedLocal),
        capture_patterns: []const ?DemandedKnownValue,
        values: []const Value,
    ) LowerError!Ast.ExprId {
        var flattened = std.ArrayList(Ast.ExprId).empty;
        defer flattened.deinit(self.pass.allocator);
        var pending_lets = std.ArrayList(PendingLet).empty;
        defer pending_lets.deinit(self.pass.allocator);

        if (capture_patterns.len != values.len) {
            Common.invariant("callable capture pattern count differed from capture value count");
        }
        for (capture_patterns, values) |capture_pattern, value| {
            const pattern = capture_pattern orelse continue;
            if (!try self.appendCaptureExprsFromDemandedKnownValue(pattern, value, &flattened, &pending_lets)) {
                Common.invariant("callable capture value could not be split into requested capture pattern");
            }
        }

        const captures = self.pass.program.typedLocalSpan(captures_span);
        if (captures.len != flattened.items.len) {
            Common.invariant("split callable capture count differed between specialization and materialization");
        }
        return try self.wrapPendingLetsAroundExpr(
            ty,
            try self.materializeExplicitCallableRef(ty, fn_id, flattened.items),
            pending_lets.items,
        );
    }

    fn appendCaptureExprsFromDemandedKnownValue(
        self: *Cloner,
        pattern: DemandedKnownValue,
        value: Value,
        out: *std.ArrayList(Ast.ExprId),
        pending_lets: *std.ArrayList(PendingLet),
    ) LowerError!bool {
        if (value == .let_) {
            const let_value = value.let_;
            try self.appendPendingLetsUnique(pending_lets, let_value.lets);
            const change_start = self.changes.items.len;
            defer self.restore(change_start);
            const pending_start = self.activePendingLetsLen();
            const scoped_start = try self.pushPendingLetScope(let_value.lets);
            defer self.popPendingLetScope(scoped_start, pending_start);
            return try self.appendCaptureExprsFromDemandedKnownValue(pattern, let_value.body.*, out, pending_lets);
        }

        switch (pattern) {
            .any,
            .leaf,
            => |ty| {
                const leaf_value = try self.valueAtDemandedLeafType(ty, value);
                try out.append(self.pass.allocator, try self.materialize(leaf_value));
                return true;
            },
            else => {},
        }

        return try self.appendExprsFromDemandedKnownValueCollectingLets(pattern, value, out, pending_lets);
    }

    fn appendCaptureExprsFromValue(
        self: *Cloner,
        known_value: KnownValue,
        value: Value,
        out: *std.ArrayList(Ast.ExprId),
        pending_lets: *std.ArrayList(PendingLet),
    ) LowerError!bool {
        const demanded = try materializedDemandedKnownValue(self.pass.arena.allocator(), known_value);
        return try self.appendCaptureExprsFromDemandedKnownValue(demanded, value, out, pending_lets);
    }

    fn materializeCallableWithCaptures(
        self: *Cloner,
        ty: Type.TypeId,
        fn_id: Ast.FnId,
        captures_span: Ast.Span(Ast.TypedLocal),
        values: []const Value,
    ) LowerError!Ast.ExprId {
        const captures = try self.pass.allocator.dupe(Ast.TypedLocal, self.pass.program.typedLocalSpan(captures_span));
        defer self.pass.allocator.free(captures);
        if (captures.len != values.len) {
            Common.invariant("callable value capture count differed from specialized function capture count");
        }

        const value_exprs = try self.pass.allocator.alloc(Ast.ExprId, values.len);
        defer self.pass.allocator.free(value_exprs);
        for (values, 0..) |value, index| {
            value_exprs[index] = try self.materializePublic(value);
        }

        return try self.materializeExplicitCallableRef(ty, fn_id, value_exprs);
    }

    fn copyValue(self: *Cloner, value: Value) Allocator.Error!*const Value {
        const out = try self.pass.arena.allocator().create(Value);
        out.* = value;
        return out;
    }

    fn snapshotSubst(self: *Cloner) Allocator.Error![]const SavedBinding {
        var bindings = std.ArrayList(SavedBinding).empty;
        defer bindings.deinit(self.pass.allocator);

        var iterator = self.subst.iterator();
        while (iterator.next()) |entry| {
            try bindings.append(self.pass.allocator, .{
                .local = entry.key_ptr.*,
                .value = entry.value_ptr.*,
            });
        }

        return try self.pass.arena.allocator().dupe(SavedBinding, bindings.items);
    }

    fn putSubst(self: *Cloner, local: Ast.LocalId, value: Value) Allocator.Error!void {
        const local_ty = self.pass.program.locals.items[@intFromEnum(local)].ty;
        const value_ty = valueType(self.pass.program, value);
        if (!sameType(self.pass.program, local_ty, value_ty)) {
            Common.invariant("substitution value type differed from local type");
        }
        const previous = self.subst.get(local);
        try self.changes.append(self.pass.allocator, .{
            .key = .{ .local = local },
            .previous = previous,
            .previous_scope_id = self.subst_scope_id,
        });
        try self.subst.put(local, value);
        self.subst_scope_id = self.next_subst_scope_id;
        self.next_subst_scope_id += 1;
    }

    fn restore(self: *Cloner, start: usize) void {
        const changed = self.changes.items.len != start;
        const restored_scope_id = if (changed) self.changes.items[start].previous_scope_id else self.subst_scope_id;
        var index = self.changes.items.len;
        while (index > start) {
            index -= 1;
            const change = self.changes.items[index];
            switch (change.key) {
                .local => |local| {
                    if (change.previous) |previous| {
                        self.subst.putAssumeCapacity(local, previous);
                    } else {
                        _ = self.subst.remove(local);
                    }
                },
            }
        }
        self.changes.shrinkRetainingCapacity(start);
        self.subst_scope_id = restored_scope_id;
    }

    fn addExpr(self: *Cloner, expr: Ast.Expr) Allocator.Error!Ast.ExprId {
        const saved_loc = self.pass.program.current_loc;
        defer self.pass.program.current_loc = saved_loc;
        const saved_region = self.pass.program.current_region;
        defer self.pass.program.current_region = saved_region;
        self.pass.program.current_loc = self.current_loc;
        self.pass.program.current_region = self.current_region;
        const expr_id = try self.pass.program.addExpr(expr);
        return expr_id;
    }

    fn addStmt(self: *Cloner, stmt: Ast.Stmt) LowerError!Ast.StmtId {
        const saved_loc = self.pass.program.current_loc;
        defer self.pass.program.current_loc = saved_loc;
        const saved_region = self.pass.program.current_region;
        defer self.pass.program.current_region = saved_region;
        self.pass.program.current_loc = self.current_loc;
        self.pass.program.current_region = self.current_region;
        return try self.pass.program.addStmt(stmt);
    }
};

fn localExpr(program: *const Ast.Program, expr_id: Ast.ExprId) ?Ast.LocalId {
    return switch (program.exprs.items[@intFromEnum(expr_id)].data) {
        .local => |local| local,
        else => null,
    };
}

fn localAliasFromValue(program: *const Ast.Program, value: Value) ?Ast.LocalId {
    return switch (value) {
        .expr => |expr| localExpr(program, expr),
        .expr_with_known_value => |known| localExpr(program, known.expr),
        .private_state => |private_state| if (privateStateLeafExpr(private_state)) |expr| localExpr(program, expr) else null,
        else => null,
    };
}

fn pendingLetValueContainsEscapingControlTransfer(program: *const Ast.Program, value: PendingLetValue) bool {
    return switch (value) {
        .source => |expr| exprContainsEscapingControlTransfer(program, expr),
        .cloned => |expr| exprContainsEscapingControlTransfer(program, expr),
    };
}

fn localInTypedLocalSpan(locals: []const Ast.TypedLocal, local: Ast.LocalId) bool {
    for (locals) |candidate| {
        if (candidate.local == local) return true;
    }
    return false;
}

/// A pending let may be cloned later in a different loop context. Control
/// transfers that escape the expression being lifted must therefore remain in
/// their original place so their target stays the same.
fn stmtAlwaysEscapesControlTransfer(program: *const Ast.Program, stmt_id: Ast.StmtId) bool {
    return stmtAlwaysEscapesControlTransferDepth(program, stmt_id, 0, 0);
}

fn stmtAlwaysEscapesControlTransferDepth(
    program: *const Ast.Program,
    stmt_id: Ast.StmtId,
    loop_depth: usize,
    state_loop_depth: usize,
) bool {
    return switch (program.stmts.items[@intFromEnum(stmt_id)]) {
        .return_ => true,
        .expr,
        .expect,
        .dbg,
        => |expr_id| exprAlwaysEscapesControlTransferDepth(program, expr_id, loop_depth, state_loop_depth),
        .let_ => |let_| exprAlwaysEscapesControlTransferDepth(program, let_.value, loop_depth, state_loop_depth),
        .crash => true,
        .uninitialized => false,
    };
}

fn exprAlwaysEscapesControlTransferDepth(
    program: *const Ast.Program,
    expr_id: Ast.ExprId,
    loop_depth: usize,
    state_loop_depth: usize,
) bool {
    return switch (program.exprs.items[@intFromEnum(expr_id)].data) {
        .return_,
        .crash,
        .comptime_exhaustiveness_failed,
        => true,
        .break_ => |maybe| loop_depth == 0 or if (maybe) |value|
            exprAlwaysEscapesControlTransferDepth(program, value, loop_depth, state_loop_depth)
        else
            false,
        .continue_ => |continue_| loop_depth == 0 or
            exprSpanAlwaysEscapesControlTransferDepth(program, continue_.values, loop_depth, state_loop_depth),
        .state_continue => |continue_| state_loop_depth == 0 or
            exprSpanAlwaysEscapesControlTransferDepth(program, continue_.values, loop_depth, state_loop_depth),
        .comptime_branch_taken => |taken| exprAlwaysEscapesControlTransferDepth(program, taken.body, loop_depth, state_loop_depth),
        .let_ => |let_| exprAlwaysEscapesControlTransferDepth(program, let_.value, loop_depth, state_loop_depth) or
            exprAlwaysEscapesControlTransferDepth(program, let_.rest, loop_depth, state_loop_depth),
        .nominal,
        .dbg,
        .expect,
        => |child| exprAlwaysEscapesControlTransferDepth(program, child, loop_depth, state_loop_depth),
        .expect_err => |expect_err| exprAlwaysEscapesControlTransferDepth(program, expect_err.msg, loop_depth, state_loop_depth),
        .block => |block| blockAlwaysEscapesControlTransferDepth(program, block.statements, block.final_expr, loop_depth, state_loop_depth),
        .if_ => |if_| blk: {
            for (program.ifBranchSpan(if_.branches)) |branch| {
                if (!exprAlwaysEscapesControlTransferDepth(program, branch.body, loop_depth, state_loop_depth)) break :blk false;
            }
            break :blk exprAlwaysEscapesControlTransferDepth(program, if_.final_else, loop_depth, state_loop_depth);
        },
        .match_ => |match| blk: {
            for (program.branchSpan(match.branches)) |branch| {
                if (!exprAlwaysEscapesControlTransferDepth(program, branch.body, loop_depth, state_loop_depth)) break :blk false;
            }
            break :blk true;
        },
        .if_initialized_payload => |payload_switch| exprAlwaysEscapesControlTransferDepth(program, payload_switch.initialized, loop_depth, state_loop_depth) and
            exprAlwaysEscapesControlTransferDepth(program, payload_switch.uninitialized, loop_depth, state_loop_depth),
        .try_sequence => |sequence| exprAlwaysEscapesControlTransferDepth(program, sequence.try_expr, loop_depth, state_loop_depth) or
            exprAlwaysEscapesControlTransferDepth(program, sequence.ok_body, loop_depth, state_loop_depth),
        .try_record_sequence => |sequence| exprAlwaysEscapesControlTransferDepth(program, sequence.try_expr, loop_depth, state_loop_depth) or
            exprAlwaysEscapesControlTransferDepth(program, sequence.ok_body, loop_depth, state_loop_depth),
        .loop_ => |loop| exprSpanAlwaysEscapesControlTransferDepth(program, loop.initial_values, loop_depth, state_loop_depth),
        .state_loop => |state_loop| exprSpanAlwaysEscapesControlTransferDepth(program, state_loop.entry_values, loop_depth, state_loop_depth),
        .local,
        .unit,
        .int_lit,
        .frac_f32_lit,
        .frac_f64_lit,
        .dec_lit,
        .str_lit,
        .static_data,
        .uninitialized,
        .uninitialized_payload,
        .fn_ref,
        .fn_ref_captures,
        .list,
        .tuple,
        .record,
        .tag,
        .lambda,
        .def_ref,
        .fn_def,
        .call_value,
        .call_proc,
        .low_level,
        .field_access,
        .tuple_access,
        .structural_eq,
        .structural_hash,
        => false,
        .static_data_candidate => |candidate| exprAlwaysEscapesControlTransferDepth(program, candidate.restored_expr, loop_depth, state_loop_depth),
    };
}

fn exprSpanAlwaysEscapesControlTransferDepth(
    program: *const Ast.Program,
    span: Ast.Span(Ast.ExprId),
    loop_depth: usize,
    state_loop_depth: usize,
) bool {
    for (program.exprSpan(span)) |expr_id| {
        if (exprAlwaysEscapesControlTransferDepth(program, expr_id, loop_depth, state_loop_depth)) return true;
    }
    return false;
}

fn blockAlwaysEscapesControlTransferDepth(
    program: *const Ast.Program,
    statements: Ast.Span(Ast.StmtId),
    final_expr: Ast.ExprId,
    loop_depth: usize,
    state_loop_depth: usize,
) bool {
    for (program.stmtSpan(statements)) |stmt_id| {
        if (stmtAlwaysEscapesControlTransferDepth(program, stmt_id, loop_depth, state_loop_depth)) return true;
    }
    return exprAlwaysEscapesControlTransferDepth(program, final_expr, loop_depth, state_loop_depth);
}

fn exprContainsEscapingControlTransfer(program: *const Ast.Program, expr_id: Ast.ExprId) bool {
    return exprContainsEscapingControlTransferDepth(program, expr_id, 0, 0);
}

fn exprContainsEscapingControlTransferDepth(
    program: *const Ast.Program,
    expr_id: Ast.ExprId,
    loop_depth: usize,
    state_loop_depth: usize,
) bool {
    return switch (program.exprs.items[@intFromEnum(expr_id)].data) {
        .return_ => true,
        .break_ => |maybe| loop_depth == 0 or if (maybe) |value|
            exprContainsEscapingControlTransferDepth(program, value, loop_depth, state_loop_depth)
        else
            false,
        .continue_ => |continue_| loop_depth == 0 or
            exprSpanContainsEscapingControlTransferDepth(program, continue_.values, loop_depth, state_loop_depth),
        .state_continue => |continue_| state_loop_depth == 0 or
            exprSpanContainsEscapingControlTransferDepth(program, continue_.values, loop_depth, state_loop_depth),
        .local,
        .unit,
        .int_lit,
        .frac_f32_lit,
        .frac_f64_lit,
        .dec_lit,
        .str_lit,
        .static_data,
        .uninitialized,
        .uninitialized_payload,
        .fn_ref,
        .crash,
        .comptime_exhaustiveness_failed,
        => false,
        .fn_ref_captures => |fn_ref| exprSpanContainsEscapingControlTransferDepth(program, fn_ref.captures, loop_depth, state_loop_depth),
        .static_data_candidate => |candidate| exprContainsEscapingControlTransferDepth(program, candidate.restored_expr, loop_depth, state_loop_depth),
        .list,
        .tuple,
        => |items| exprSpanContainsEscapingControlTransferDepth(program, items, loop_depth, state_loop_depth),
        .record => |fields| blk: {
            for (program.fieldExprSpan(fields)) |field| {
                if (exprContainsEscapingControlTransferDepth(program, field.value, loop_depth, state_loop_depth)) break :blk true;
            }
            break :blk false;
        },
        .tag => |tag| exprSpanContainsEscapingControlTransferDepth(program, tag.payloads, loop_depth, state_loop_depth),
        .nominal,
        .dbg,
        .expect,
        => |child| exprContainsEscapingControlTransferDepth(program, child, loop_depth, state_loop_depth),
        .expect_err => |expect_err| exprContainsEscapingControlTransferDepth(program, expect_err.msg, loop_depth, state_loop_depth),
        .comptime_branch_taken => |taken| exprContainsEscapingControlTransferDepth(program, taken.body, loop_depth, state_loop_depth),
        .let_ => |let_| exprContainsEscapingControlTransferDepth(program, let_.value, loop_depth, state_loop_depth) or
            exprContainsEscapingControlTransferDepth(program, let_.rest, loop_depth, state_loop_depth),
        .lambda,
        .def_ref,
        .fn_def,
        => Common.invariant("pre-lift function expression reached call-pattern control-transfer scan"),
        .call_value => |call| exprContainsEscapingControlTransferDepth(program, call.callee, loop_depth, state_loop_depth) or
            exprSpanContainsEscapingControlTransferDepth(program, call.args, loop_depth, state_loop_depth),
        .call_proc => |call| exprSpanContainsEscapingControlTransferDepth(program, call.args, loop_depth, state_loop_depth),
        .low_level => |call| exprSpanContainsEscapingControlTransferDepth(program, call.args, loop_depth, state_loop_depth),
        .field_access => |field| exprContainsEscapingControlTransferDepth(program, field.receiver, loop_depth, state_loop_depth),
        .tuple_access => |access| exprContainsEscapingControlTransferDepth(program, access.tuple, loop_depth, state_loop_depth),
        .structural_eq => |eq| exprContainsEscapingControlTransferDepth(program, eq.lhs, loop_depth, state_loop_depth) or
            exprContainsEscapingControlTransferDepth(program, eq.rhs, loop_depth, state_loop_depth),
        .structural_hash => |h| exprContainsEscapingControlTransferDepth(program, h.value, loop_depth, state_loop_depth) or
            exprContainsEscapingControlTransferDepth(program, h.hasher, loop_depth, state_loop_depth),
        .match_ => |match| blk: {
            if (exprContainsEscapingControlTransferDepth(program, match.scrutinee, loop_depth, state_loop_depth)) break :blk true;
            for (program.branchSpan(match.branches)) |branch| {
                if (branch.guard) |guard| {
                    if (exprContainsEscapingControlTransferDepth(program, guard, loop_depth, state_loop_depth)) break :blk true;
                }
                if (exprContainsEscapingControlTransferDepth(program, branch.body, loop_depth, state_loop_depth)) break :blk true;
            }
            break :blk false;
        },
        .if_ => |if_| blk: {
            for (program.ifBranchSpan(if_.branches)) |branch| {
                if (exprContainsEscapingControlTransferDepth(program, branch.cond, loop_depth, state_loop_depth) or
                    exprContainsEscapingControlTransferDepth(program, branch.body, loop_depth, state_loop_depth))
                {
                    break :blk true;
                }
            }
            break :blk exprContainsEscapingControlTransferDepth(program, if_.final_else, loop_depth, state_loop_depth);
        },
        .if_initialized_payload => |payload_switch| exprContainsEscapingControlTransferDepth(program, payload_switch.cond, loop_depth, state_loop_depth) or
            exprContainsEscapingControlTransferDepth(program, payload_switch.initialized, loop_depth, state_loop_depth) or
            exprContainsEscapingControlTransferDepth(program, payload_switch.uninitialized, loop_depth, state_loop_depth),
        .try_sequence => |sequence| exprContainsEscapingControlTransferDepth(program, sequence.try_expr, loop_depth, state_loop_depth) or
            exprContainsEscapingControlTransferDepth(program, sequence.ok_body, loop_depth, state_loop_depth),
        .try_record_sequence => |sequence| exprContainsEscapingControlTransferDepth(program, sequence.try_expr, loop_depth, state_loop_depth) or
            exprContainsEscapingControlTransferDepth(program, sequence.ok_body, loop_depth, state_loop_depth),
        .block => |block| stmtSpanContainsEscapingControlTransferDepth(program, block.statements, loop_depth, state_loop_depth) or
            exprContainsEscapingControlTransferDepth(program, block.final_expr, loop_depth, state_loop_depth),
        .loop_ => |loop| exprSpanContainsEscapingControlTransferDepth(program, loop.initial_values, loop_depth, state_loop_depth) or
            exprContainsEscapingControlTransferDepth(program, loop.body, loop_depth + 1, state_loop_depth),
        .state_loop => |state_loop| blk: {
            if (exprSpanContainsEscapingControlTransferDepth(program, state_loop.entry_values, loop_depth, state_loop_depth)) break :blk true;
            for (program.stateLoopStateSpan(state_loop.states)) |state| {
                if (exprContainsEscapingControlTransferDepth(program, state.body, loop_depth, state_loop_depth + 1)) break :blk true;
            }
            break :blk false;
        },
    };
}

fn exprSpanContainsEscapingControlTransferDepth(
    program: *const Ast.Program,
    span: Ast.Span(Ast.ExprId),
    loop_depth: usize,
    state_loop_depth: usize,
) bool {
    for (program.exprSpan(span)) |expr_id| {
        if (exprContainsEscapingControlTransferDepth(program, expr_id, loop_depth, state_loop_depth)) return true;
    }
    return false;
}

fn stmtContainsEscapingControlTransferDepth(
    program: *const Ast.Program,
    stmt_id: Ast.StmtId,
    loop_depth: usize,
    state_loop_depth: usize,
) bool {
    return switch (program.stmts.items[@intFromEnum(stmt_id)]) {
        .return_ => true,
        .let_ => |let_| exprContainsEscapingControlTransferDepth(program, let_.value, loop_depth, state_loop_depth),
        .expr,
        .expect,
        .dbg,
        => |expr_id| exprContainsEscapingControlTransferDepth(program, expr_id, loop_depth, state_loop_depth),
        .uninitialized,
        .crash,
        => false,
    };
}

fn stmtSpanContainsEscapingControlTransferDepth(
    program: *const Ast.Program,
    span: Ast.Span(Ast.StmtId),
    loop_depth: usize,
    state_loop_depth: usize,
) bool {
    for (program.stmtSpan(span)) |stmt_id| {
        if (stmtContainsEscapingControlTransferDepth(program, stmt_id, loop_depth, state_loop_depth)) return true;
    }
    return false;
}

/// A body with an early return can be cloned into a worker with the same return
/// target, but it cannot be directly inlined into a different caller body.
fn exprContainsReturn(program: *const Ast.Program, expr_id: Ast.ExprId) bool {
    return switch (program.exprs.items[@intFromEnum(expr_id)].data) {
        .return_ => true,
        .local,
        .unit,
        .int_lit,
        .frac_f32_lit,
        .frac_f64_lit,
        .dec_lit,
        .str_lit,
        .static_data,
        .uninitialized,
        .uninitialized_payload,
        .fn_ref,
        .crash,
        .comptime_exhaustiveness_failed,
        => false,
        .fn_ref_captures => |fn_ref| exprSpanContainsReturn(program, fn_ref.captures),
        .static_data_candidate => |candidate| exprContainsReturn(program, candidate.restored_expr),
        .list,
        .tuple,
        => |items| exprSpanContainsReturn(program, items),
        .record => |fields| blk: {
            for (program.fieldExprSpan(fields)) |field| {
                if (exprContainsReturn(program, field.value)) break :blk true;
            }
            break :blk false;
        },
        .tag => |tag| exprSpanContainsReturn(program, tag.payloads),
        .nominal,
        .dbg,
        .expect,
        => |child| exprContainsReturn(program, child),
        .expect_err => |expect_err| exprContainsReturn(program, expect_err.msg),
        .comptime_branch_taken => |taken| exprContainsReturn(program, taken.body),
        .let_ => |let_| exprContainsReturn(program, let_.value) or exprContainsReturn(program, let_.rest),
        .lambda,
        .def_ref,
        .fn_def,
        => Common.invariant("pre-lift function expression reached call-pattern return scan"),
        .call_value => |call| exprContainsReturn(program, call.callee) or exprSpanContainsReturn(program, call.args),
        .call_proc => |call| exprSpanContainsReturn(program, call.args),
        .low_level => |call| exprSpanContainsReturn(program, call.args),
        .field_access => |field| exprContainsReturn(program, field.receiver),
        .tuple_access => |access| exprContainsReturn(program, access.tuple),
        .structural_eq => |eq| exprContainsReturn(program, eq.lhs) or exprContainsReturn(program, eq.rhs),
        .structural_hash => |h| exprContainsReturn(program, h.value) or exprContainsReturn(program, h.hasher),
        .match_ => |match| blk: {
            if (exprContainsReturn(program, match.scrutinee)) break :blk true;
            for (program.branchSpan(match.branches)) |branch| {
                if (branch.guard) |guard| {
                    if (exprContainsReturn(program, guard)) break :blk true;
                }
                if (exprContainsReturn(program, branch.body)) break :blk true;
            }
            break :blk false;
        },
        .if_ => |if_| blk: {
            for (program.ifBranchSpan(if_.branches)) |branch| {
                if (exprContainsReturn(program, branch.cond) or exprContainsReturn(program, branch.body)) {
                    break :blk true;
                }
            }
            break :blk exprContainsReturn(program, if_.final_else);
        },
        .if_initialized_payload => |payload_switch| exprContainsReturn(program, payload_switch.cond) or
            exprContainsReturn(program, payload_switch.initialized) or
            exprContainsReturn(program, payload_switch.uninitialized),
        .try_sequence => |sequence| exprContainsReturn(program, sequence.try_expr) or
            exprContainsReturn(program, sequence.ok_body),
        .try_record_sequence => |sequence| exprContainsReturn(program, sequence.try_expr) or
            exprContainsReturn(program, sequence.ok_body),
        .block => |block| stmtSpanContainsReturn(program, block.statements) or exprContainsReturn(program, block.final_expr),
        .loop_ => |loop| exprSpanContainsReturn(program, loop.initial_values) or exprContainsReturn(program, loop.body),
        .state_loop => |state_loop| blk: {
            if (exprSpanContainsReturn(program, state_loop.entry_values)) break :blk true;
            for (program.stateLoopStateSpan(state_loop.states)) |state| {
                if (exprContainsReturn(program, state.body)) break :blk true;
            }
            break :blk false;
        },
        .break_ => |maybe| if (maybe) |value| exprContainsReturn(program, value) else false,
        .continue_ => |continue_| exprSpanContainsReturn(program, continue_.values),
        .state_continue => |continue_| exprSpanContainsReturn(program, continue_.values),
    };
}

fn exprSpanContainsReturn(program: *const Ast.Program, span: Ast.Span(Ast.ExprId)) bool {
    for (program.exprSpan(span)) |expr_id| {
        if (exprContainsReturn(program, expr_id)) return true;
    }
    return false;
}

fn stmtContainsReturn(program: *const Ast.Program, stmt_id: Ast.StmtId) bool {
    return switch (program.stmts.items[@intFromEnum(stmt_id)]) {
        .return_ => true,
        .let_ => |let_| exprContainsReturn(program, let_.value),
        .expr,
        .expect,
        .dbg,
        => |expr_id| exprContainsReturn(program, expr_id),
        .uninitialized,
        .crash,
        => false,
    };
}

fn stmtSpanContainsReturn(program: *const Ast.Program, span: Ast.Span(Ast.StmtId)) bool {
    for (program.stmtSpan(span)) |stmt_id| {
        if (stmtContainsReturn(program, stmt_id)) return true;
    }
    return false;
}

fn localUseCountInExpr(program: *const Ast.Program, local: Ast.LocalId, expr_id: Ast.ExprId) usize {
    return switch (program.exprs.items[@intFromEnum(expr_id)].data) {
        .local => |seen| if (seen == local) 1 else 0,
        .unit,
        .int_lit,
        .frac_f32_lit,
        .frac_f64_lit,
        .dec_lit,
        .str_lit,
        .static_data,
        .fn_ref,
        .crash,
        .comptime_exhaustiveness_failed,
        .uninitialized,
        .uninitialized_payload,
        => 0,
        .fn_ref_captures => |fn_ref| localUseCountInExprSpan(program, local, fn_ref.captures),
        .static_data_candidate => |candidate| localUseCountInExpr(program, local, candidate.restored_expr),
        .list,
        .tuple,
        => |items| localUseCountInExprSpan(program, local, items),
        .record => |fields| blk: {
            var count: usize = 0;
            for (program.fieldExprSpan(fields)) |field| count += localUseCountInExpr(program, local, field.value);
            break :blk count;
        },
        .tag => |tag| localUseCountInExprSpan(program, local, tag.payloads),
        .nominal,
        .return_,
        .dbg,
        .expect,
        => |child| localUseCountInExpr(program, local, child),
        .expect_err => |expect_err| localUseCountInExpr(program, local, expect_err.msg),
        .comptime_branch_taken => |taken| localUseCountInExpr(program, local, taken.body),
        .let_ => |let_| localUseCountInExpr(program, local, let_.value) + localUseCountInExpr(program, local, let_.rest),
        .lambda,
        .def_ref,
        .fn_def,
        => 0,
        .call_value => |call| localUseCountInExpr(program, local, call.callee) + localUseCountInExprSpan(program, local, call.args),
        .call_proc => |call| localUseCountInExprSpan(program, local, call.args),
        .low_level => |call| localUseCountInExprSpan(program, local, call.args),
        .field_access => |field| localUseCountInExpr(program, local, field.receiver),
        .tuple_access => |access| localUseCountInExpr(program, local, access.tuple),
        .structural_eq => |eq| localUseCountInExpr(program, local, eq.lhs) + localUseCountInExpr(program, local, eq.rhs),
        .structural_hash => |h| localUseCountInExpr(program, local, h.value) + localUseCountInExpr(program, local, h.hasher),
        .match_ => |match| blk: {
            var count = localUseCountInExpr(program, local, match.scrutinee);
            for (program.branchSpan(match.branches)) |branch| {
                if (branch.guard) |guard| count += localUseCountInExpr(program, local, guard);
                count += localUseCountInExpr(program, local, branch.body);
            }
            break :blk count;
        },
        .if_ => |if_| blk: {
            var count: usize = 0;
            for (program.ifBranchSpan(if_.branches)) |branch| {
                count += localUseCountInExpr(program, local, branch.cond);
                count += localUseCountInExpr(program, local, branch.body);
            }
            count += localUseCountInExpr(program, local, if_.final_else);
            break :blk count;
        },
        .block => |block| blk: {
            var count: usize = 0;
            for (program.stmtSpan(block.statements)) |stmt| count += localUseCountInStmt(program, local, stmt);
            count += localUseCountInExpr(program, local, block.final_expr);
            break :blk count;
        },
        .loop_ => |loop| localUseCountInExprSpan(program, local, loop.initial_values) + localUseCountInExpr(program, local, loop.body),
        .state_loop => |state_loop| blk: {
            var count = localUseCountInExprSpan(program, local, state_loop.entry_values);
            for (program.stateLoopStateSpan(state_loop.states)) |state| {
                count += localUseCountInExpr(program, local, state.body);
            }
            break :blk count;
        },
        .break_ => |maybe| if (maybe) |value| localUseCountInExpr(program, local, value) else 0,
        .continue_ => |continue_| localUseCountInExprSpan(program, local, continue_.values),
        .state_continue => |continue_| localUseCountInExprSpan(program, local, continue_.values),
        .if_initialized_payload => |payload_switch| localUseCountInExpr(program, local, payload_switch.cond) +
            (if (payload_switch.payload == local) @as(usize, 1) else 0) +
            localUseCountInExpr(program, local, payload_switch.initialized) +
            localUseCountInExpr(program, local, payload_switch.uninitialized),
        .try_sequence => |sequence| localUseCountInExpr(program, local, sequence.try_expr) +
            if (sequence.ok_local == local) 0 else localUseCountInExpr(program, local, sequence.ok_body),
        .try_record_sequence => |sequence| localUseCountInExpr(program, local, sequence.try_expr) +
            if (sequence.value_local == local or sequence.rest_local == local) 0 else localUseCountInExpr(program, local, sequence.ok_body),
    };
}

fn localUseCountInExprSpan(program: *const Ast.Program, local: Ast.LocalId, span: Ast.Span(Ast.ExprId)) usize {
    var count: usize = 0;
    for (program.exprSpan(span)) |expr| count += localUseCountInExpr(program, local, expr);
    return count;
}

fn pendingLetValueUsesLocal(program: *const Ast.Program, value: PendingLetValue, local: Ast.LocalId) bool {
    return switch (value) {
        .source => |expr| localUseCountInExpr(program, local, expr) != 0,
        .cloned => |expr| localUseCountInExpr(program, local, expr) != 0,
    };
}

fn localUseCountInBlockTail(program: *const Ast.Program, local: Ast.LocalId, tail: BlockTail) usize {
    var count: usize = 0;
    for (tail.statements) |stmt_id| count += localUseCountInStmt(program, local, stmt_id);
    count += localUseCountInExpr(program, local, tail.final_expr);
    return count;
}

fn patternUsedInExpr(program: *const Ast.Program, pat_id: Ast.PatId, expr_id: Ast.ExprId) bool {
    const pat = program.pats.items[@intFromEnum(pat_id)];
    return switch (pat.data) {
        .bind => |local| localUseCountInExpr(program, local, expr_id) != 0,
        .wildcard,
        .int_lit,
        .dec_lit,
        .frac_f32_lit,
        .frac_f64_lit,
        .str_lit,
        .str_pattern,
        => false,
        .as => |as| localUseCountInExpr(program, as.local, expr_id) != 0 or
            patternUsedInExpr(program, as.pattern, expr_id),
        .record => |fields_span| {
            for (program.recordDestructSpan(fields_span)) |field| {
                if (patternUsedInExpr(program, field.pattern, expr_id)) return true;
            }
            return false;
        },
        .tuple => |items_span| {
            for (program.patSpan(items_span)) |child| {
                if (patternUsedInExpr(program, child, expr_id)) return true;
            }
            return false;
        },
        .list => |list| {
            for (program.patSpan(list.patterns)) |child| {
                if (patternUsedInExpr(program, child, expr_id)) return true;
            }
            if (list.rest) |rest| {
                if (rest.pattern) |rest_pattern| {
                    if (patternUsedInExpr(program, rest_pattern, expr_id)) return true;
                }
            }
            return false;
        },
        .tag => |tag| {
            for (program.patSpan(tag.payloads)) |child| {
                if (patternUsedInExpr(program, child, expr_id)) return true;
            }
            return false;
        },
        .nominal => |backing| patternUsedInExpr(program, backing, expr_id),
    };
}

fn localMaxUseCountPerPathInExpr(program: *const Ast.Program, local: Ast.LocalId, expr_id: Ast.ExprId) usize {
    return switch (program.exprs.items[@intFromEnum(expr_id)].data) {
        .local => |seen| if (seen == local) 1 else 0,
        .unit,
        .int_lit,
        .frac_f32_lit,
        .frac_f64_lit,
        .dec_lit,
        .str_lit,
        .static_data,
        .fn_ref,
        .crash,
        .comptime_exhaustiveness_failed,
        .uninitialized,
        .uninitialized_payload,
        .lambda,
        .def_ref,
        .fn_def,
        => 0,
        .fn_ref_captures => |fn_ref| localMaxUseCountPerPathInExprSpan(program, local, fn_ref.captures),
        .static_data_candidate => |candidate| localMaxUseCountPerPathInExpr(program, local, candidate.restored_expr),
        .list,
        .tuple,
        => |items| localMaxUseCountPerPathInExprSpan(program, local, items),
        .record => |fields| blk: {
            var count: usize = 0;
            for (program.fieldExprSpan(fields)) |field| count += localMaxUseCountPerPathInExpr(program, local, field.value);
            break :blk count;
        },
        .tag => |tag| localMaxUseCountPerPathInExprSpan(program, local, tag.payloads),
        .nominal,
        .return_,
        .dbg,
        .expect,
        => |child| localMaxUseCountPerPathInExpr(program, local, child),
        .expect_err => |expect_err| localMaxUseCountPerPathInExpr(program, local, expect_err.msg),
        .comptime_branch_taken => |taken| localMaxUseCountPerPathInExpr(program, local, taken.body),
        .let_ => |let_| localMaxUseCountPerPathInExpr(program, local, let_.value) +
            localMaxUseCountPerPathInExpr(program, local, let_.rest),
        .call_value => |call| localMaxUseCountPerPathInExpr(program, local, call.callee) +
            localMaxUseCountPerPathInExprSpan(program, local, call.args),
        .call_proc => |call| localMaxUseCountPerPathInExprSpan(program, local, call.args),
        .low_level => |call| localMaxUseCountPerPathInExprSpan(program, local, call.args),
        .field_access => |field| localMaxUseCountPerPathInExpr(program, local, field.receiver),
        .tuple_access => |access| localMaxUseCountPerPathInExpr(program, local, access.tuple),
        .structural_eq => |eq| localMaxUseCountPerPathInExpr(program, local, eq.lhs) +
            localMaxUseCountPerPathInExpr(program, local, eq.rhs),
        .structural_hash => |h| localMaxUseCountPerPathInExpr(program, local, h.value) +
            localMaxUseCountPerPathInExpr(program, local, h.hasher),
        .match_ => |match| blk: {
            const scrutinee_count = localMaxUseCountPerPathInExpr(program, local, match.scrutinee);
            var max_branch_count: usize = 0;
            for (program.branchSpan(match.branches)) |branch| {
                var branch_count: usize = if (branch.guard) |guard|
                    localMaxUseCountPerPathInExpr(program, local, guard)
                else
                    0;
                branch_count += localMaxUseCountPerPathInExpr(program, local, branch.body);
                max_branch_count = @max(max_branch_count, branch_count);
            }
            break :blk scrutinee_count + max_branch_count;
        },
        .if_ => |if_| blk: {
            var count: usize = 0;
            var max_branch_count: usize = 0;
            for (program.ifBranchSpan(if_.branches)) |branch| {
                count += localMaxUseCountPerPathInExpr(program, local, branch.cond);
                max_branch_count = @max(max_branch_count, localMaxUseCountPerPathInExpr(program, local, branch.body));
            }
            max_branch_count = @max(max_branch_count, localMaxUseCountPerPathInExpr(program, local, if_.final_else));
            break :blk count + max_branch_count;
        },
        .block => |block| blk: {
            var count: usize = 0;
            for (program.stmtSpan(block.statements)) |stmt| count += localMaxUseCountPerPathInStmt(program, local, stmt);
            count += localMaxUseCountPerPathInExpr(program, local, block.final_expr);
            break :blk count;
        },
        .loop_ => |loop| blk: {
            const initial_count = localMaxUseCountPerPathInExprSpan(program, local, loop.initial_values);
            const body_count = localMaxUseCountPerPathInExpr(program, local, loop.body);
            break :blk initial_count + if (body_count == 0) @as(usize, 0) else @max(body_count, 2);
        },
        .state_loop => |state_loop| blk: {
            const initial_count = localMaxUseCountPerPathInExprSpan(program, local, state_loop.entry_values);
            var max_state_count: usize = 0;
            for (program.stateLoopStateSpan(state_loop.states)) |state| {
                max_state_count = @max(max_state_count, localMaxUseCountPerPathInExpr(program, local, state.body));
            }
            break :blk initial_count + if (max_state_count == 0) @as(usize, 0) else @max(max_state_count, 2);
        },
        .break_ => |maybe| if (maybe) |value| localMaxUseCountPerPathInExpr(program, local, value) else 0,
        .continue_ => |continue_| localMaxUseCountPerPathInExprSpan(program, local, continue_.values),
        .state_continue => |continue_| localMaxUseCountPerPathInExprSpan(program, local, continue_.values),
        .if_initialized_payload => |payload_switch| localMaxUseCountPerPathInExpr(program, local, payload_switch.cond) +
            @max(
                (if (payload_switch.payload == local) @as(usize, 1) else 0) +
                    localMaxUseCountPerPathInExpr(program, local, payload_switch.initialized),
                localMaxUseCountPerPathInExpr(program, local, payload_switch.uninitialized),
            ),
        .try_sequence => |sequence| localMaxUseCountPerPathInExpr(program, local, sequence.try_expr) +
            if (sequence.ok_local == local) 0 else localMaxUseCountPerPathInExpr(program, local, sequence.ok_body),
        .try_record_sequence => |sequence| localMaxUseCountPerPathInExpr(program, local, sequence.try_expr) +
            if (sequence.value_local == local or sequence.rest_local == local) 0 else localMaxUseCountPerPathInExpr(program, local, sequence.ok_body),
    };
}

fn localMaxUseCountPerPathInExprSpan(program: *const Ast.Program, local: Ast.LocalId, span: Ast.Span(Ast.ExprId)) usize {
    var count: usize = 0;
    for (program.exprSpan(span)) |expr| count += localMaxUseCountPerPathInExpr(program, local, expr);
    return count;
}

fn discardedExprIsEffectFree(program: *const Ast.Program, allocator: Allocator, expr_id: Ast.ExprId) Allocator.Error!bool {
    const active_fns = try allocator.alloc(bool, program.fns.items.len);
    defer allocator.free(active_fns);
    @memset(active_fns, false);
    return try discardedExprIsEffectFreeInner(program, expr_id, active_fns);
}

fn discardedExprIsEffectFreeInner(program: *const Ast.Program, expr_id: Ast.ExprId, active_fns: []bool) Allocator.Error!bool {
    return switch (program.exprs.items[@intFromEnum(expr_id)].data) {
        .local,
        .unit,
        .int_lit,
        .frac_f32_lit,
        .frac_f64_lit,
        .dec_lit,
        .str_lit,
        .static_data,
        .fn_ref,
        .uninitialized,
        .uninitialized_payload,
        => true,
        .fn_ref_captures => |fn_ref| blk: {
            for (program.exprSpan(fn_ref.captures)) |capture| {
                if (!try discardedExprIsEffectFreeInner(program, capture, active_fns)) break :blk false;
            }
            break :blk true;
        },
        .static_data_candidate => |candidate| discardedExprIsEffectFreeInner(program, candidate.restored_expr, active_fns),
        .list,
        .tuple,
        => |items| try discardedExprSpanIsEffectFree(program, items, active_fns),
        .record => |fields| blk: {
            for (program.fieldExprSpan(fields)) |field| {
                if (!try discardedExprIsEffectFreeInner(program, field.value, active_fns)) break :blk false;
            }
            break :blk true;
        },
        .tag => |tag| try discardedExprSpanIsEffectFree(program, tag.payloads, active_fns),
        .nominal => |backing| discardedExprIsEffectFreeInner(program, backing, active_fns),
        .let_ => |let_| try discardedExprIsEffectFreeInner(program, let_.value, active_fns) and
            try discardedExprIsEffectFreeInner(program, let_.rest, active_fns),
        .field_access => |field| discardedExprIsEffectFreeInner(program, field.receiver, active_fns),
        .tuple_access => |access| discardedExprIsEffectFreeInner(program, access.tuple, active_fns),
        .comptime_branch_taken => |taken| discardedExprIsEffectFreeInner(program, taken.body, active_fns),
        .low_level => |call| discardedLowLevelIsEffectFree(call.op) and
            try discardedExprSpanIsEffectFree(program, call.args, active_fns),
        .structural_eq => |eq| try discardedExprIsEffectFreeInner(program, eq.lhs, active_fns) and
            try discardedExprIsEffectFreeInner(program, eq.rhs, active_fns),
        .structural_hash => |hash| try discardedExprIsEffectFreeInner(program, hash.value, active_fns) and
            try discardedExprIsEffectFreeInner(program, hash.hasher, active_fns),
        .if_ => |if_| blk: {
            for (program.ifBranchSpan(if_.branches)) |branch| {
                if (!try discardedExprIsEffectFreeInner(program, branch.cond, active_fns)) break :blk false;
                if (!try discardedExprIsEffectFreeInner(program, branch.body, active_fns)) break :blk false;
            }
            break :blk try discardedExprIsEffectFreeInner(program, if_.final_else, active_fns);
        },
        .match_ => |match| blk: {
            if (!try discardedExprIsEffectFreeInner(program, match.scrutinee, active_fns)) break :blk false;
            for (program.branchSpan(match.branches)) |branch| {
                if (branch.guard) |guard| {
                    if (!try discardedExprIsEffectFreeInner(program, guard, active_fns)) break :blk false;
                }
                if (!try discardedExprIsEffectFreeInner(program, branch.body, active_fns)) break :blk false;
            }
            break :blk true;
        },
        .block => |block| blk: {
            for (program.stmtSpan(block.statements)) |stmt| {
                if (!try discardedStmtIsEffectFree(program, stmt, active_fns)) break :blk false;
            }
            break :blk try discardedExprIsEffectFreeInner(program, block.final_expr, active_fns);
        },
        .call_proc => |call| blk: {
            if (!try discardedExprSpanIsEffectFree(program, call.args, active_fns)) break :blk false;

            const callee = Ast.callProcCallee(call);
            const callee_index = @intFromEnum(callee);
            if (callee_index >= active_fns.len or active_fns[callee_index]) break :blk false;

            const source_fn = program.fns.items[callee_index];
            const body = switch (source_fn.body) {
                .roc => |body| body,
                .hosted => break :blk false,
            };
            if (exprContainsReturn(program, body)) break :blk false;

            active_fns[callee_index] = true;
            defer active_fns[callee_index] = false;
            break :blk try discardedExprIsEffectFreeInner(program, body, active_fns);
        },
        .lambda,
        .def_ref,
        .fn_def,
        .call_value,
        .loop_,
        .state_loop,
        .break_,
        .continue_,
        .state_continue,
        .return_,
        .dbg,
        .expect,
        .expect_err,
        .crash,
        .comptime_exhaustiveness_failed,
        .if_initialized_payload,
        .try_sequence,
        .try_record_sequence,
        => false,
    };
}

fn discardedStmtIsEffectFree(program: *const Ast.Program, stmt_id: Ast.StmtId, active_fns: []bool) Allocator.Error!bool {
    return switch (program.stmts.items[@intFromEnum(stmt_id)]) {
        .uninitialized => true,
        .let_ => |let_| !let_.recursive and try discardedExprIsEffectFreeInner(program, let_.value, active_fns),
        .expr => |expr| discardedExprIsEffectFreeInner(program, expr, active_fns),
        .expect,
        .dbg,
        .return_,
        .crash,
        => false,
    };
}

fn discardedLowLevelIsEffectFree(op: can.CIR.Expr.LowLevel) bool {
    return switch (op) {
        .crash,
        .ptr_store,
        .num_div_by,
        .num_div_trunc_by,
        .num_rem_by,
        .num_mod_by,
        => false,
        else => blk: {
            const rc_effect = op.rcEffect();
            break :blk !rc_effect.may_allocate and
                !rc_effect.may_retain_or_release and
                rc_effect.consume_args == 0 and
                rc_effect.may_runtime_uniqueness_check_args == 0;
        },
    };
}

fn discardedExprSpanIsEffectFree(program: *const Ast.Program, span: Ast.Span(Ast.ExprId), active_fns: []bool) Allocator.Error!bool {
    for (program.exprSpan(span)) |expr| {
        if (!try discardedExprIsEffectFreeInner(program, expr, active_fns)) return false;
    }
    return true;
}

fn localUseCountInStmt(program: *const Ast.Program, local: Ast.LocalId, stmt_id: Ast.StmtId) usize {
    return switch (program.stmts.items[@intFromEnum(stmt_id)]) {
        .uninitialized => 0,
        .let_ => |let_| localUseCountInExpr(program, local, let_.value),
        .expr,
        .expect,
        .dbg,
        .return_,
        => |expr| localUseCountInExpr(program, local, expr),
        .crash => 0,
    };
}

fn localMaxUseCountPerPathInStmt(program: *const Ast.Program, local: Ast.LocalId, stmt_id: Ast.StmtId) usize {
    return switch (program.stmts.items[@intFromEnum(stmt_id)]) {
        .uninitialized => 0,
        .let_ => |let_| localMaxUseCountPerPathInExpr(program, local, let_.value),
        .expr,
        .expect,
        .dbg,
        .return_,
        => |expr| localMaxUseCountPerPathInExpr(program, local, expr),
        .crash => 0,
    };
}

fn localMaxUseCountPerPathInBlockTail(program: *const Ast.Program, local: Ast.LocalId, tail: BlockTail) usize {
    var count: usize = 0;
    for (tail.statements) |stmt| count += localMaxUseCountPerPathInStmt(program, local, stmt);
    count += localMaxUseCountPerPathInExpr(program, local, tail.final_expr);
    return count;
}

const LocalUseScan = struct {
    seen_effect: bool = false,
    found_before_effect: bool = false,
    found_after_effect: bool = false,
};

fn localUseBeforeEffectInBlockTail(program: *const Ast.Program, local: Ast.LocalId, tail: BlockTail) bool {
    var scan: LocalUseScan = .{};
    for (tail.statements) |stmt| scanLocalUseInStmt(program, local, stmt, &scan);
    scanLocalUseInExpr(program, local, tail.final_expr, &scan);
    return scan.found_before_effect and !scan.found_after_effect;
}

fn localUseBeforeEffect(program: *const Ast.Program, local: Ast.LocalId, expr_id: Ast.ExprId) bool {
    var scan: LocalUseScan = .{};
    scanLocalUseInExpr(program, local, expr_id, &scan);
    return scan.found_before_effect and !scan.found_after_effect;
}

fn scanLocalUseInExpr(program: *const Ast.Program, local: Ast.LocalId, expr_id: Ast.ExprId, scan: *LocalUseScan) void {
    const expr = program.exprs.items[@intFromEnum(expr_id)];
    switch (expr.data) {
        .local => |seen| {
            if (seen == local) {
                if (scan.seen_effect) {
                    scan.found_after_effect = true;
                } else {
                    scan.found_before_effect = true;
                }
            }
        },
        .unit,
        .int_lit,
        .frac_f32_lit,
        .frac_f64_lit,
        .dec_lit,
        .str_lit,
        .static_data,
        .fn_ref,
        .uninitialized,
        .uninitialized_payload,
        => {},
        .fn_ref_captures => |fn_ref| scanLocalUseInExprSpan(program, local, fn_ref.captures, scan),
        .static_data_candidate => |candidate| scanLocalUseInExpr(program, local, candidate.restored_expr, scan),
        .crash, .comptime_exhaustiveness_failed => scan.seen_effect = true,
        .list,
        .tuple,
        => |items| scanLocalUseInExprSpan(program, local, items, scan),
        .record => |fields| {
            for (program.fieldExprSpan(fields)) |field| scanLocalUseInExpr(program, local, field.value, scan);
        },
        .tag => |tag| scanLocalUseInExprSpan(program, local, tag.payloads, scan),
        .nominal => |child| scanLocalUseInExpr(program, local, child, scan),
        .return_ => |child| {
            scanLocalUseInExpr(program, local, child, scan);
            scan.seen_effect = true;
        },
        .dbg,
        .expect,
        => |child| {
            scanLocalUseInExpr(program, local, child, scan);
            scan.seen_effect = true;
        },
        .expect_err => |expect_err| {
            scanLocalUseInExpr(program, local, expect_err.msg, scan);
            scan.seen_effect = true;
        },
        .comptime_branch_taken => |taken| scanLocalUseInExpr(program, local, taken.body, scan),
        .let_ => |let_| {
            scanLocalUseInExpr(program, local, let_.value, scan);
            scanLocalUseInExpr(program, local, let_.rest, scan);
        },
        .lambda,
        .def_ref,
        .fn_def,
        => {},
        .call_value => |call| {
            scanLocalUseInExpr(program, local, call.callee, scan);
            scanLocalUseInExprSpan(program, local, call.args, scan);
            scan.seen_effect = true;
        },
        .call_proc => |call| {
            scanLocalUseInExprSpan(program, local, call.args, scan);
            scan.seen_effect = true;
        },
        .low_level => |call| {
            scanLocalUseInExprSpan(program, local, call.args, scan);
            scan.seen_effect = true;
        },
        .field_access => |field| scanLocalUseInExpr(program, local, field.receiver, scan),
        .tuple_access => |access| scanLocalUseInExpr(program, local, access.tuple, scan),
        .structural_eq => |eq| {
            scanLocalUseInExpr(program, local, eq.lhs, scan);
            scanLocalUseInExpr(program, local, eq.rhs, scan);
            scan.seen_effect = true;
        },
        .structural_hash => |h| {
            scanLocalUseInExpr(program, local, h.value, scan);
            scanLocalUseInExpr(program, local, h.hasher, scan);
            scan.seen_effect = true;
        },
        .match_ => |match| {
            scanLocalUseInExpr(program, local, match.scrutinee, scan);
            const after_scrutinee = scan.*;
            var merged = after_scrutinee;
            for (program.branchSpan(match.branches)) |branch| {
                var branch_scan = after_scrutinee;
                if (branch.guard) |guard| scanLocalUseInExpr(program, local, guard, &branch_scan);
                scanLocalUseInExpr(program, local, branch.body, &branch_scan);
                merged.found_before_effect = merged.found_before_effect or branch_scan.found_before_effect;
                merged.found_after_effect = merged.found_after_effect or branch_scan.found_after_effect;
                merged.seen_effect = merged.seen_effect or branch_scan.seen_effect;
            }
            scan.* = merged;
        },
        .if_ => |if_| {
            var condition_scan = scan.*;
            var merged = condition_scan;
            for (program.ifBranchSpan(if_.branches)) |branch| {
                scanLocalUseInExpr(program, local, branch.cond, &condition_scan);
                var branch_scan = condition_scan;
                scanLocalUseInExpr(program, local, branch.body, &branch_scan);
                merged.found_before_effect = merged.found_before_effect or branch_scan.found_before_effect;
                merged.found_after_effect = merged.found_after_effect or branch_scan.found_after_effect;
                merged.seen_effect = merged.seen_effect or branch_scan.seen_effect;
            }
            var else_scan = condition_scan;
            scanLocalUseInExpr(program, local, if_.final_else, &else_scan);
            merged.found_before_effect = merged.found_before_effect or else_scan.found_before_effect;
            merged.found_after_effect = merged.found_after_effect or else_scan.found_after_effect;
            merged.seen_effect = merged.seen_effect or else_scan.seen_effect;
            scan.* = merged;
        },
        .block => |block| {
            for (program.stmtSpan(block.statements)) |stmt| scanLocalUseInStmt(program, local, stmt, scan);
            scanLocalUseInExpr(program, local, block.final_expr, scan);
        },
        .loop_ => |loop| {
            scanLocalUseInExprSpan(program, local, loop.initial_values, scan);
            scanLocalUseInExpr(program, local, loop.body, scan);
        },
        .state_loop => |state_loop| {
            scanLocalUseInExprSpan(program, local, state_loop.entry_values, scan);
            for (program.stateLoopStateSpan(state_loop.states)) |state| {
                scanLocalUseInExpr(program, local, state.body, scan);
            }
        },
        .break_ => |maybe| {
            if (maybe) |value| scanLocalUseInExpr(program, local, value, scan);
            scan.seen_effect = true;
        },
        .continue_ => |continue_| {
            scanLocalUseInExprSpan(program, local, continue_.values, scan);
            scan.seen_effect = true;
        },
        .state_continue => |continue_| {
            scanLocalUseInExprSpan(program, local, continue_.values, scan);
            scan.seen_effect = true;
        },
        .if_initialized_payload => |payload_switch| {
            scanLocalUseInExpr(program, local, payload_switch.cond, scan);

            var initialized_scan = scan.*;
            if (payload_switch.payload == local) {
                if (initialized_scan.seen_effect) {
                    initialized_scan.found_after_effect = true;
                } else {
                    initialized_scan.found_before_effect = true;
                }
            }
            scanLocalUseInExpr(program, local, payload_switch.initialized, &initialized_scan);

            var uninitialized_scan = scan.*;
            scanLocalUseInExpr(program, local, payload_switch.uninitialized, &uninitialized_scan);

            scan.found_before_effect = scan.found_before_effect or initialized_scan.found_before_effect or uninitialized_scan.found_before_effect;
            scan.found_after_effect = scan.found_after_effect or initialized_scan.found_after_effect or uninitialized_scan.found_after_effect;
            scan.seen_effect = scan.seen_effect or initialized_scan.seen_effect or uninitialized_scan.seen_effect;
        },
        .try_sequence => |sequence| {
            scanLocalUseInExpr(program, local, sequence.try_expr, scan);
            if (sequence.ok_local != local) {
                scanLocalUseInExpr(program, local, sequence.ok_body, scan);
            }
            scan.seen_effect = true;
        },
        .try_record_sequence => |sequence| {
            scanLocalUseInExpr(program, local, sequence.try_expr, scan);
            if (sequence.value_local != local and sequence.rest_local != local) {
                scanLocalUseInExpr(program, local, sequence.ok_body, scan);
            }
            scan.seen_effect = true;
        },
    }
}

fn scanLocalUseInExprSpan(
    program: *const Ast.Program,
    local: Ast.LocalId,
    span: Ast.Span(Ast.ExprId),
    scan: *LocalUseScan,
) void {
    for (program.exprSpan(span)) |expr| scanLocalUseInExpr(program, local, expr, scan);
}

fn scanLocalUseInStmt(program: *const Ast.Program, local: Ast.LocalId, stmt_id: Ast.StmtId, scan: *LocalUseScan) void {
    switch (program.stmts.items[@intFromEnum(stmt_id)]) {
        .uninitialized => {},
        .let_ => |let_| scanLocalUseInExpr(program, local, let_.value, scan),
        .expr => |expr| scanLocalUseInExpr(program, local, expr, scan),
        .expect,
        .dbg,
        => |expr| {
            scanLocalUseInExpr(program, local, expr, scan);
            scan.seen_effect = true;
        },
        .return_ => |expr| {
            scanLocalUseInExpr(program, local, expr, scan);
            scan.seen_effect = true;
        },
        .crash => scan.seen_effect = true,
    }
}

fn canReadFieldsFromExpr(program: *const Ast.Program, expr_id: Ast.ExprId) bool {
    return switch (program.exprs.items[@intFromEnum(expr_id)].data) {
        .local,
        .field_access,
        .tuple_access,
        .low_level,
        => true,
        else => false,
    };
}

fn projectableExprFromValue(value: Value) ?Ast.ExprId {
    return switch (value) {
        .expr => |expr| expr,
        .expr_with_known_value => |known_value_expr| known_value_expr.expr,
        .private_state => |private_state| privateStateLeafExpr(private_state),
        else => null,
    };
}

fn exprMayDemandLocal(program: *const Ast.Program, expr_id: Ast.ExprId, local: Ast.LocalId) bool {
    if (localUseCountInExpr(program, local, expr_id) != 0) return true;
    return exprContainsFnRef(program, expr_id);
}

fn exprContainsFnRef(program: *const Ast.Program, expr_id: Ast.ExprId) bool {
    return switch (program.exprs.items[@intFromEnum(expr_id)].data) {
        .fn_ref => true,
        .static_data_candidate => |candidate| exprContainsFnRef(program, candidate.restored_expr),
        .list,
        .tuple,
        => |items| exprSpanContainsFnRef(program, items),
        .record => |fields| blk: {
            for (program.fieldExprSpan(fields)) |field| {
                if (exprContainsFnRef(program, field.value)) break :blk true;
            }
            break :blk false;
        },
        .tag => |tag| exprSpanContainsFnRef(program, tag.payloads),
        .nominal,
        .return_,
        .dbg,
        .expect,
        => |child| exprContainsFnRef(program, child),
        .expect_err => |expect_err| exprContainsFnRef(program, expect_err.msg),
        .comptime_branch_taken => |taken| exprContainsFnRef(program, taken.body),
        .let_ => |let_| exprContainsFnRef(program, let_.value) or exprContainsFnRef(program, let_.rest),
        .call_value => |call| exprContainsFnRef(program, call.callee) or exprSpanContainsFnRef(program, call.args),
        .call_proc => |call| exprSpanContainsFnRef(program, call.args),
        .low_level => |call| exprSpanContainsFnRef(program, call.args),
        .field_access => |field| exprContainsFnRef(program, field.receiver),
        .tuple_access => |access| exprContainsFnRef(program, access.tuple),
        .structural_eq => |eq| exprContainsFnRef(program, eq.lhs) or exprContainsFnRef(program, eq.rhs),
        .structural_hash => |hash| exprContainsFnRef(program, hash.value) or exprContainsFnRef(program, hash.hasher),
        .match_ => |match| blk: {
            if (exprContainsFnRef(program, match.scrutinee)) break :blk true;
            for (program.branchSpan(match.branches)) |branch| {
                if (branch.guard) |guard| {
                    if (exprContainsFnRef(program, guard)) break :blk true;
                }
                if (exprContainsFnRef(program, branch.body)) break :blk true;
            }
            break :blk false;
        },
        .if_ => |if_| blk: {
            for (program.ifBranchSpan(if_.branches)) |branch| {
                if (exprContainsFnRef(program, branch.cond) or exprContainsFnRef(program, branch.body)) break :blk true;
            }
            break :blk exprContainsFnRef(program, if_.final_else);
        },
        .block => |block| blk: {
            for (program.stmtSpan(block.statements)) |stmt_id| {
                switch (program.stmts.items[@intFromEnum(stmt_id)]) {
                    .let_ => |let_| if (exprContainsFnRef(program, let_.value)) break :blk true,
                    .expr,
                    .expect,
                    .dbg,
                    .return_,
                    => |child| if (exprContainsFnRef(program, child)) break :blk true,
                    else => {},
                }
            }
            break :blk exprContainsFnRef(program, block.final_expr);
        },
        .loop_ => |loop| exprSpanContainsFnRef(program, loop.initial_values) or exprContainsFnRef(program, loop.body),
        .state_loop => |state_loop| blk: {
            if (exprSpanContainsFnRef(program, state_loop.entry_values)) break :blk true;
            for (program.stateLoopStateSpan(state_loop.states)) |state| {
                if (exprContainsFnRef(program, state.body)) break :blk true;
            }
            break :blk false;
        },
        .break_ => |maybe| if (maybe) |value| exprContainsFnRef(program, value) else false,
        .continue_ => |continue_| exprSpanContainsFnRef(program, continue_.values),
        .state_continue => |continue_| exprSpanContainsFnRef(program, continue_.values),
        .if_initialized_payload => |payload_switch| exprContainsFnRef(program, payload_switch.cond) or
            exprContainsFnRef(program, payload_switch.initialized) or
            exprContainsFnRef(program, payload_switch.uninitialized),
        .try_sequence => |sequence| exprContainsFnRef(program, sequence.try_expr) or exprContainsFnRef(program, sequence.ok_body),
        .try_record_sequence => |sequence| exprContainsFnRef(program, sequence.try_expr) or exprContainsFnRef(program, sequence.ok_body),
        else => false,
    };
}

fn exprSpanContainsFnRef(program: *const Ast.Program, span: Ast.Span(Ast.ExprId)) bool {
    for (program.exprSpan(span)) |expr_id| {
        if (exprContainsFnRef(program, expr_id)) return true;
    }
    return false;
}

fn valueMayDemandLocal(program: *const Ast.Program, value: Value, local: Ast.LocalId) bool {
    return switch (value) {
        .expr => |expr| exprMayDemandLocal(program, expr, local),
        .expr_with_known_value => |known| exprMayDemandLocal(program, known.expr, local) or
            if (known.value) |structured| valueMayDemandLocal(program, structured.*, local) else false,
        .let_ => |let_value| blk: {
            for (let_value.lets) |pending| {
                const expr = switch (pending.value) {
                    .source => |source| source,
                    .cloned => |cloned| cloned,
                };
                if (exprMayDemandLocal(program, expr, local)) break :blk true;
            }
            break :blk valueMayDemandLocal(program, let_value.body.*, local);
        },
        .if_ => |if_value| blk: {
            for (if_value.branches) |branch| {
                if (exprMayDemandLocal(program, branch.cond, local) or valueMayDemandLocal(program, branch.body, local)) break :blk true;
            }
            break :blk valueMayDemandLocal(program, if_value.final_else.*, local);
        },
        .match_ => |match_value| blk: {
            if (exprMayDemandLocal(program, match_value.scrutinee, local)) break :blk true;
            for (match_value.branches) |branch| {
                if (branch.guard) |guard| {
                    if (exprMayDemandLocal(program, guard, local)) break :blk true;
                }
                if (valueMayDemandLocal(program, branch.body, local)) break :blk true;
            }
            break :blk false;
        },
        .tag => |tag| blk: {
            for (tag.payloads) |payload| {
                if (valueMayDemandLocal(program, payload, local)) break :blk true;
            }
            break :blk false;
        },
        .record => |record| blk: {
            for (record.fields) |field| {
                if (valueMayDemandLocal(program, field.value, local)) break :blk true;
            }
            break :blk false;
        },
        .tuple => |tuple| blk: {
            for (tuple.items) |item| {
                if (valueMayDemandLocal(program, item, local)) break :blk true;
            }
            break :blk false;
        },
        .nominal => |nominal| valueMayDemandLocal(program, nominal.backing.*, local),
        .callable => |callable| blk: {
            for (callable.captures) |capture| {
                if (valueMayDemandLocal(program, capture, local)) break :blk true;
            }
            break :blk false;
        },
        .finite_tags => |finite_tags| blk: {
            if (exprMayDemandLocal(program, finite_tags.selector, local)) break :blk true;
            for (finite_tags.alternatives) |alternative| {
                for (alternative.payloads) |payload| {
                    if (valueMayDemandLocal(program, payload, local)) break :blk true;
                }
            }
            break :blk false;
        },
        .finite_callables => |finite_callables| blk: {
            if (exprMayDemandLocal(program, finite_callables.selector, local)) break :blk true;
            for (finite_callables.alternatives) |alternative| {
                for (alternative.captures) |capture| {
                    if (valueMayDemandLocal(program, capture, local)) break :blk true;
                }
            }
            break :blk false;
        },
        .private_state => |private_state| privateStateMayDemandLocal(program, private_state, local),
    };
}

fn privateStateMayDemandLocal(program: *const Ast.Program, value: PrivateStateValue, local: Ast.LocalId) bool {
    return switch (value) {
        .leaf => |leaf| exprMayDemandLocal(program, leaf.expr, local),
        .tag => |tag| blk: {
            for (tag.payloads) |payload| {
                if (privateStateMayDemandLocal(program, payload.value, local)) break :blk true;
            }
            break :blk false;
        },
        .record => |record| blk: {
            for (record.fields) |field| {
                if (privateStateMayDemandLocal(program, field.value, local)) break :blk true;
            }
            break :blk false;
        },
        .tuple => |tuple| blk: {
            for (tuple.items) |item| {
                if (privateStateMayDemandLocal(program, item.value, local)) break :blk true;
            }
            break :blk false;
        },
        .nominal => |nominal| if (nominal.backing) |backing| privateStateMayDemandLocal(program, backing.*, local) else false,
        .callable => |callable| blk: {
            for (callable.captures) |capture| {
                if (privateStateMayDemandLocal(program, capture.value, local)) break :blk true;
            }
            break :blk false;
        },
        .finite_tags => |finite_tags| blk: {
            if (exprMayDemandLocal(program, finite_tags.selector, local)) break :blk true;
            for (finite_tags.alternatives) |alternative| {
                for (alternative.payloads) |payload| {
                    if (privateStateMayDemandLocal(program, payload.value, local)) break :blk true;
                }
            }
            break :blk false;
        },
        .finite_callables => |finite_callables| blk: {
            if (exprMayDemandLocal(program, finite_callables.selector, local)) break :blk true;
            for (finite_callables.alternatives) |alternative| {
                for (alternative.captures) |capture| {
                    if (privateStateMayDemandLocal(program, capture.value, local)) break :blk true;
                }
            }
            break :blk false;
        },
    };
}

fn valueContainsLocalName(program: *const Ast.Program, value: Value, name: []const u8) bool {
    return switch (value) {
        .expr => |expr| exprContainsLocalName(program, expr, name),
        .expr_with_known_value => |known| exprContainsLocalName(program, known.expr, name) or
            if (known.value) |structured| valueContainsLocalName(program, structured.*, name) else false,
        .let_ => |let_value| blk: {
            for (let_value.lets) |pending| {
                const expr = switch (pending.value) {
                    .source => |source| source,
                    .cloned => |cloned| cloned,
                };
                if (exprContainsLocalName(program, expr, name)) break :blk true;
            }
            break :blk valueContainsLocalName(program, let_value.body.*, name);
        },
        .if_ => |if_value| blk: {
            for (if_value.branches) |branch| {
                if (exprContainsLocalName(program, branch.cond, name) or valueContainsLocalName(program, branch.body, name)) break :blk true;
            }
            break :blk valueContainsLocalName(program, if_value.final_else.*, name);
        },
        .match_ => |match_value| blk: {
            if (exprContainsLocalName(program, match_value.scrutinee, name)) break :blk true;
            for (match_value.branches) |branch| {
                if (branch.guard) |guard| {
                    if (exprContainsLocalName(program, guard, name)) break :blk true;
                }
                if (valueContainsLocalName(program, branch.body, name)) break :blk true;
            }
            break :blk false;
        },
        .tag => |tag| blk: {
            for (tag.payloads) |payload| {
                if (valueContainsLocalName(program, payload, name)) break :blk true;
            }
            break :blk false;
        },
        .record => |record| blk: {
            for (record.fields) |field| {
                if (valueContainsLocalName(program, field.value, name)) break :blk true;
            }
            break :blk false;
        },
        .tuple => |tuple| blk: {
            for (tuple.items) |item| {
                if (valueContainsLocalName(program, item, name)) break :blk true;
            }
            break :blk false;
        },
        .nominal => |nominal| valueContainsLocalName(program, nominal.backing.*, name),
        .callable => |callable| blk: {
            for (callable.captures) |capture| {
                if (valueContainsLocalName(program, capture, name)) break :blk true;
            }
            break :blk false;
        },
        .finite_tags => |finite_tags| blk: {
            if (exprContainsLocalName(program, finite_tags.selector, name)) break :blk true;
            for (finite_tags.alternatives) |alternative| {
                for (alternative.payloads) |payload| {
                    if (valueContainsLocalName(program, payload, name)) break :blk true;
                }
            }
            break :blk false;
        },
        .finite_callables => |finite_callables| blk: {
            if (exprContainsLocalName(program, finite_callables.selector, name)) break :blk true;
            for (finite_callables.alternatives) |alternative| {
                for (alternative.captures) |capture| {
                    if (valueContainsLocalName(program, capture, name)) break :blk true;
                }
            }
            break :blk false;
        },
        .private_state => |private_state| privateStateContainsLocalName(program, private_state, name),
    };
}

fn exprContainsLocalName(program: *const Ast.Program, expr_id: Ast.ExprId, name: []const u8) bool {
    const expr = program.exprs.items[@intFromEnum(expr_id)];
    return switch (expr.data) {
        .local => |local| std.mem.eql(u8, program.localName(local), name),
        .list, .tuple => |span| blk: {
            for (program.exprSpan(span)) |child| {
                if (exprContainsLocalName(program, child, name)) break :blk true;
            }
            break :blk false;
        },
        .record => |span| blk: {
            for (program.fieldExprSpan(span)) |field| {
                if (exprContainsLocalName(program, field.value, name)) break :blk true;
            }
            break :blk false;
        },
        .tag => |tag| blk: {
            for (program.exprSpan(tag.payloads)) |child| {
                if (exprContainsLocalName(program, child, name)) break :blk true;
            }
            break :blk false;
        },
        .nominal => |backing| exprContainsLocalName(program, backing, name),
        .call_value => |call| blk: {
            if (exprContainsLocalName(program, call.callee, name)) break :blk true;
            for (program.exprSpan(call.args)) |arg| {
                if (exprContainsLocalName(program, arg, name)) break :blk true;
            }
            break :blk false;
        },
        .call_proc => |call| blk: {
            for (program.exprSpan(call.args)) |arg| {
                if (exprContainsLocalName(program, arg, name)) break :blk true;
            }
            break :blk false;
        },
        .low_level => |call| blk: {
            for (program.exprSpan(call.args)) |arg| {
                if (exprContainsLocalName(program, arg, name)) break :blk true;
            }
            break :blk false;
        },
        .field_access => |field| exprContainsLocalName(program, field.receiver, name),
        .tuple_access => |access| exprContainsLocalName(program, access.tuple, name),
        .match_ => |match| blk: {
            if (exprContainsLocalName(program, match.scrutinee, name)) break :blk true;
            for (program.branchSpan(match.branches)) |branch| {
                if (branch.guard) |guard| {
                    if (exprContainsLocalName(program, guard, name)) break :blk true;
                }
                if (exprContainsLocalName(program, branch.body, name)) break :blk true;
            }
            break :blk false;
        },
        .if_ => |if_| blk: {
            for (program.ifBranchSpan(if_.branches)) |branch| {
                if (exprContainsLocalName(program, branch.cond, name) or
                    exprContainsLocalName(program, branch.body, name))
                {
                    break :blk true;
                }
            }
            break :blk exprContainsLocalName(program, if_.final_else, name);
        },
        .block => |block| blk: {
            for (program.stmtSpan(block.statements)) |stmt_id| {
                switch (program.stmts.items[@intFromEnum(stmt_id)]) {
                    .let_ => |let_| if (exprContainsLocalName(program, let_.value, name)) break :blk true,
                    .expr => |child| if (exprContainsLocalName(program, child, name)) break :blk true,
                    .expect => |child| if (exprContainsLocalName(program, child, name)) break :blk true,
                    .dbg => |child| if (exprContainsLocalName(program, child, name)) break :blk true,
                    .return_ => |child| if (exprContainsLocalName(program, child, name)) break :blk true,
                    else => {},
                }
            }
            break :blk exprContainsLocalName(program, block.final_expr, name);
        },
        .state_loop => |state_loop| blk: {
            for (program.exprSpan(state_loop.entry_values)) |value| {
                if (exprContainsLocalName(program, value, name)) break :blk true;
            }
            for (program.stateLoopStateSpan(state_loop.states)) |state| {
                if (exprContainsLocalName(program, state.body, name)) break :blk true;
            }
            break :blk false;
        },
        .if_initialized_payload => |switch_| exprContainsLocalName(program, switch_.cond, name) or
            exprContainsLocalName(program, switch_.initialized, name) or
            exprContainsLocalName(program, switch_.uninitialized, name),
        .try_sequence => |try_| exprContainsLocalName(program, try_.try_expr, name) or
            exprContainsLocalName(program, try_.ok_body, name),
        .try_record_sequence => |try_| exprContainsLocalName(program, try_.try_expr, name) or
            exprContainsLocalName(program, try_.ok_body, name),
        .break_ => |maybe| if (maybe) |value| exprContainsLocalName(program, value, name) else false,
        .continue_ => |continue_| blk: {
            for (program.exprSpan(continue_.values)) |value| {
                if (exprContainsLocalName(program, value, name)) break :blk true;
            }
            break :blk false;
        },
        .state_continue => |continue_| blk: {
            for (program.exprSpan(continue_.values)) |value| {
                if (exprContainsLocalName(program, value, name)) break :blk true;
            }
            break :blk false;
        },
        .return_ => |value| exprContainsLocalName(program, value, name),
        .comptime_branch_taken => |taken| exprContainsLocalName(program, taken.body, name),
        .dbg => |child| exprContainsLocalName(program, child, name),
        .expect => |child| exprContainsLocalName(program, child, name),
        .expect_err => |expect_err| exprContainsLocalName(program, expect_err.msg, name),
        else => false,
    };
}

fn privateStateContainsLocalName(program: *const Ast.Program, value: PrivateStateValue, name: []const u8) bool {
    return switch (value) {
        .leaf => |leaf| exprContainsLocalName(program, leaf.expr, name),
        .tag => |tag| blk: {
            for (tag.payloads) |payload| {
                if (privateStateContainsLocalName(program, payload.value, name)) break :blk true;
            }
            break :blk false;
        },
        .record => |record| blk: {
            for (record.fields) |field| {
                if (privateStateContainsLocalName(program, field.value, name)) break :blk true;
            }
            break :blk false;
        },
        .tuple => |tuple| blk: {
            for (tuple.items) |item| {
                if (privateStateContainsLocalName(program, item.value, name)) break :blk true;
            }
            break :blk false;
        },
        .nominal => |nominal| if (nominal.backing) |backing| privateStateContainsLocalName(program, backing.*, name) else false,
        .callable => |callable| blk: {
            for (callable.captures) |capture| {
                if (privateStateContainsLocalName(program, capture.value, name)) break :blk true;
            }
            break :blk false;
        },
        .finite_tags => |finite_tags| blk: {
            if (exprContainsLocalName(program, finite_tags.selector, name)) break :blk true;
            for (finite_tags.alternatives) |alternative| {
                for (alternative.payloads) |payload| {
                    if (privateStateContainsLocalName(program, payload.value, name)) break :blk true;
                }
            }
            break :blk false;
        },
        .finite_callables => |finite_callables| blk: {
            if (exprContainsLocalName(program, finite_callables.selector, name)) break :blk true;
            for (finite_callables.alternatives) |alternative| {
                for (alternative.captures) |capture| {
                    if (privateStateContainsLocalName(program, capture.value, name)) break :blk true;
                }
            }
            break :blk false;
        },
    };
}

fn valueFromProjectedExpr(expr: Ast.ExprId, known_value: KnownValue) Value {
    return switch (known_value) {
        .any => .{ .expr = expr },
        else => .{ .expr_with_known_value = .{
            .expr = expr,
            .known_value = known_value,
        } },
    };
}

fn fieldKnownValueFromKnownValue(
    program: *const Ast.Program,
    known_value: KnownValue,
    name: names.RecordFieldNameId,
) ?KnownValue {
    return switch (known_value) {
        .record => |record| blk: {
            for (record.fields) |field| {
                if (program.names.recordFieldLabelTextEql(field.name, name)) break :blk field.known_value;
            }
            break :blk null;
        },
        .nominal => |nominal| fieldKnownValueFromKnownValue(program, nominal.backing.*, name),
        else => null,
    };
}

fn itemKnownValueFromKnownValue(known_value: KnownValue, index: u32) ?KnownValue {
    return switch (known_value) {
        .tuple => |tuple| if (index < tuple.items.len) tuple.items[index] else null,
        .nominal => |nominal| itemKnownValueFromKnownValue(nominal.backing.*, index),
        else => null,
    };
}

fn knownTagForPattern(known_value: KnownValue, name: names.TagNameId) ?KnownTag {
    return switch (known_value) {
        .tag => |tag| if (tag.name == name) tag else null,
        .finite_tags => |finite_tags| blk: {
            for (finite_tags.alternatives) |alternative| {
                if (alternative.name == name) break :blk alternative;
            }
            break :blk null;
        },
        .nominal => |nominal| knownTagForPattern(nominal.backing.*, name),
        else => null,
    };
}

fn patternDefinitelyExcludedByKnownValue(program: *const Ast.Program, pat_id: Ast.PatId, known_value: KnownValue) bool {
    const pat = program.pats.items[@intFromEnum(pat_id)];
    return switch (pat.data) {
        .as => |as| patternDefinitelyExcludedByKnownValue(program, as.pattern, known_value),
        .nominal => |backing| switch (known_value) {
            .nominal => |nominal| patternDefinitelyExcludedByKnownValue(program, backing, nominal.backing.*),
            else => false,
        },
        .tag => |tag_pat| switch (known_value) {
            .tag,
            .finite_tags,
            => knownTagForPattern(known_value, tag_pat.name) == null,
            .nominal => |nominal| patternDefinitelyExcludedByKnownValue(program, pat_id, nominal.backing.*),
            else => false,
        },
        else => false,
    };
}

fn known_valueType(known_value: KnownValue) Type.TypeId {
    return switch (known_value) {
        .any => |ty| ty,
        .leaf => |ty| ty,
        .tag => |tag| tag.ty,
        .record => |record| record.ty,
        .tuple => |tuple| tuple.ty,
        .nominal => |nominal| nominal.ty,
        .callable => |callable| callable.ty,
        .finite_tags => |finite_tags| finite_tags.ty,
        .finite_callables => |finite_callables| finite_callables.ty,
    };
}

fn knownValueFromPrivateState(program: *const Ast.Program, arena: Allocator, value: PrivateStateValue) Allocator.Error!?KnownValue {
    return switch (value) {
        .leaf => |leaf| .{ .leaf = leaf.ty },
        .tag => |tag| blk: {
            const payload_tys = tagTypePayloads(program, tag.ty, tag.name) orelse break :blk null;
            const payloads = (try knownValuesFromPrivateStateIndexedValues(program, arena, tag.payloads, payload_tys.len)) orelse break :blk null;
            break :blk KnownValue{ .tag = .{
                .ty = tag.ty,
                .name = tag.name,
                .payloads = payloads,
            } };
        },
        .record => |record| blk: {
            const type_fields = recordTypeFields(program, record.ty);
            if (type_fields.len != record.fields.len) break :blk null;
            const fields = try arena.alloc(KnownField, type_fields.len);
            for (type_fields, fields) |type_field, *out| {
                const field = privateStateFieldByName(program, record.fields, type_field.name) orelse break :blk null;
                out.* = .{
                    .name = type_field.name,
                    .known_value = (try knownValueFromPrivateState(program, arena, field)) orelse break :blk null,
                };
            }
            break :blk KnownValue{ .record = .{
                .ty = record.ty,
                .fields = fields,
            } };
        },
        .tuple => |tuple| blk: {
            const type_items = tupleTypeItems(program, tuple.ty);
            const items = (try knownValuesFromPrivateStateIndexedValues(program, arena, tuple.items, type_items.len)) orelse break :blk null;
            break :blk KnownValue{ .tuple = .{
                .ty = tuple.ty,
                .items = items,
            } };
        },
        .nominal => |nominal| blk: {
            const backing = nominal.backing orelse break :blk null;
            const backing_known_value = (try knownValueFromPrivateState(program, arena, backing.*)) orelse break :blk null;
            const stored = try arena.create(KnownValue);
            stored.* = backing_known_value;
            break :blk KnownValue{ .nominal = .{
                .ty = nominal.ty,
                .backing = stored,
            } };
        },
        .callable => |callable| blk: {
            const source_fn = program.fns.items[@intFromEnum(callable.fn_id)];
            const source_captures = program.typedLocalSpan(source_fn.captures);
            const captures = (try knownValuesFromPrivateStateIndexedValues(program, arena, callable.captures, source_captures.len)) orelse break :blk null;
            break :blk KnownValue{ .callable = .{
                .ty = callable.ty,
                .fn_id = callable.fn_id,
                .captures = captures,
            } };
        },
        .compact_finite_tags => |finite_tags| try knownValueFromDemandedKnownValue(program, arena, .{ .finite_tags = finite_tags.source }),
        .compact_finite_callables => |finite_callables| try knownValueFromDemandedKnownValue(program, arena, .{ .finite_callables = finite_callables.source }),
    };
}

fn sparseKnownValueFromPrivateState(program: *const Ast.Program, arena: Allocator, value: PrivateStateValue) Allocator.Error!?KnownValue {
    return switch (value) {
        .leaf => |leaf| .{ .leaf = leaf.ty },
        .record => |record| blk: {
            const fields = try arena.alloc(KnownField, record.fields.len);
            for (record.fields, fields) |field, *out| {
                out.* = .{
                    .name = field.name,
                    .known_value = (try sparseKnownValueFromPrivateState(program, arena, field.value)) orelse break :blk null,
                };
            }
            break :blk KnownValue{ .record = .{
                .ty = record.ty,
                .fields = fields,
            } };
        },
        .nominal => |nominal| blk: {
            const backing = nominal.backing orelse break :blk null;
            const backing_known_value = (try sparseKnownValueFromPrivateState(program, arena, backing.*)) orelse break :blk null;
            const stored = try arena.create(KnownValue);
            stored.* = backing_known_value;
            break :blk KnownValue{ .nominal = .{
                .ty = nominal.ty,
                .backing = stored,
            } };
        },
        .tag => |tag| blk: {
            const payload_tys = tagTypePayloads(program, tag.ty, tag.name) orelse break :blk null;
            const payloads = (try sparseKnownValuesFromPrivateStateIndexedValues(program, arena, tag.payloads, payload_tys.len)) orelse break :blk null;
            break :blk KnownValue{ .tag = .{
                .ty = tag.ty,
                .name = tag.name,
                .payloads = payloads,
            } };
        },
        .tuple => |tuple| blk: {
            const type_items = tupleTypeItems(program, tuple.ty);
            const items = (try sparseKnownValuesFromPrivateStateIndexedValues(program, arena, tuple.items, type_items.len)) orelse break :blk null;
            break :blk KnownValue{ .tuple = .{
                .ty = tuple.ty,
                .items = items,
            } };
        },
        .callable => |callable| blk: {
            const source_fn = program.fns.items[@intFromEnum(callable.fn_id)];
            const source_captures = program.typedLocalSpan(source_fn.captures);
            const captures = (try sparseKnownValuesFromPrivateStateIndexedValues(program, arena, callable.captures, source_captures.len)) orelse break :blk null;
            break :blk KnownValue{ .callable = .{
                .ty = callable.ty,
                .fn_id = callable.fn_id,
                .captures = captures,
            } };
        },
        .compact_finite_tags,
        .compact_finite_callables,
        => try knownValueFromPrivateState(program, arena, value),
    };
}

fn sparseKnownValuesFromPrivateStateIndexedValues(
    program: *const Ast.Program,
    arena: Allocator,
    indexed: []const PrivateStateIndexedValue,
    expected_len: usize,
) Allocator.Error!?[]const KnownValue {
    if (!privateStateIndexedValuesAreDense(indexed, expected_len)) return null;
    for (indexed, 0..) |value, index| {
        if (value.index != index) return null;
    }

    const known_values = try arena.alloc(KnownValue, expected_len);
    for (indexed, known_values) |value, *out| {
        out.* = (try sparseKnownValueFromPrivateState(program, arena, value.value)) orelse return null;
    }
    return known_values;
}

fn knownValuesFromPrivateStateIndexedValues(
    program: *const Ast.Program,
    arena: Allocator,
    indexed: []const PrivateStateIndexedValue,
    expected_len: usize,
) Allocator.Error!?[]const KnownValue {
    if (!privateStateIndexedValuesAreDense(indexed, expected_len)) return null;
    for (indexed, 0..) |value, index| {
        if (value.index != index) return null;
    }

    const known_values = try arena.alloc(KnownValue, expected_len);
    for (indexed, known_values) |value, *out| {
        out.* = (try knownValueFromPrivateState(program, arena, value.value)) orelse return null;
    }
    return known_values;
}

fn valueType(program: *const Ast.Program, value: Value) Type.TypeId {
    return switch (value) {
        .expr => |expr| program.exprs.items[@intFromEnum(expr)].ty,
        .expr_with_known_value => |known_value_expr| program.exprs.items[@intFromEnum(known_value_expr.expr)].ty,
        .let_ => |let_value| valueType(program, let_value.body.*),
        .if_ => |if_value| if_value.ty,
        .match_ => |match_value| match_value.ty,
        .tag => |tag| tag.ty,
        .record => |record| record.ty,
        .tuple => |tuple| tuple.ty,
        .nominal => |nominal| nominal.ty,
        .callable => |callable| callable.ty,
        .finite_tags => |finite_tags| finite_tags.ty,
        .finite_callables => |finite_callables| finite_callables.ty,
        .private_state => |private_state| privateStateValueType(private_state),
    };
}

fn leafKnownValueFromValue(program: *const Ast.Program, value: Value) Allocator.Error!?KnownValue {
    return switch (value) {
        .expr => |expr| switch (program.exprs.items[@intFromEnum(expr)].data) {
            .local => blk: {
                const ty = program.exprs.items[@intFromEnum(expr)].ty;
                if (try typeMayContainRefcounted(program, ty)) break :blk null;
                break :blk KnownValue{ .leaf = ty };
            },
            else => null,
        },
        else => null,
    };
}

fn typeMayContainRefcounted(program: *const Ast.Program, ty: Type.TypeId) Allocator.Error!bool {
    var stack = std.ArrayList(Type.TypeId).empty;
    defer stack.deinit(program.allocator);
    return try typeMayContainRefcountedInner(program, ty, &stack);
}

fn typeMayContainRefcountedInner(
    program: *const Ast.Program,
    ty: Type.TypeId,
    stack: *std.ArrayList(Type.TypeId),
) Allocator.Error!bool {
    for (stack.items) |active| {
        if (active == ty) return true;
    }

    try stack.append(program.allocator, ty);
    defer _ = stack.pop();

    return switch (program.types.get(ty)) {
        .primitive => |primitive| primitive == .str,
        .named => |named| if (named.backing) |backing|
            try typeMayContainRefcountedInner(program, backing.ty, stack)
        else
            true,
        .record => |fields_span| blk: {
            for (program.types.fieldSpan(fields_span)) |field| {
                if (try typeMayContainRefcountedInner(program, field.ty, stack)) break :blk true;
            }
            break :blk false;
        },
        .tuple => |items_span| blk: {
            for (program.types.span(items_span)) |item| {
                if (try typeMayContainRefcountedInner(program, item, stack)) break :blk true;
            }
            break :blk false;
        },
        .tag_union => |tags_span| blk: {
            for (program.types.tagSpan(tags_span)) |tag| {
                for (program.types.span(tag.payloads)) |payload| {
                    if (try typeMayContainRefcountedInner(program, payload, stack)) break :blk true;
                }
            }
            break :blk false;
        },
        .zst => false,
        .list,
        .box,
        .func,
        .erased,
        => true,
    };
}

/// Whether two Monotype ids denote the same type. The type store is not
/// interned: each specialization materializes its own ids, so structurally
/// identical types reached from different specializations (a call site and
/// the callee's own body) carry different ids and compare by digest.
fn sameType(program: *const Ast.Program, lhs: Type.TypeId, rhs: Type.TypeId) bool {
    if (lhs == rhs) return true;
    const lhs_digest = program.types.typeDigest(&program.names, lhs);
    const rhs_digest = program.types.typeDigest(&program.names, rhs);
    return std.mem.eql(u8, &lhs_digest.bytes, &rhs_digest.bytes);
}

fn patternEql(program: *const Ast.Program, lhs: CallPattern, rhs: CallPattern) bool {
    if (lhs.captures.len != rhs.captures.len) return false;
    for (lhs.captures, rhs.captures) |lhs_capture, rhs_capture| {
        if (std.meta.activeTag(lhs_capture) != std.meta.activeTag(rhs_capture)) return false;
        switch (lhs_capture) {
            .unused,
            .residual,
            => {},
            .split => |lhs_known_value| {
                if (!demandedKnownValueEql(program, lhs_known_value, rhs_capture.split)) return false;
            },
        }
    }
    return demandedKnownValuesEql(program, lhs.args, rhs.args);
}

fn callPatternArgCount(pattern: CallPattern) usize {
    var count: usize = 0;
    for (pattern.captures) |capture| {
        if (capture == .split) count += demandedKnownValueArgCount(capture.split);
    }
    count += demandedKnownValuesArgCount(pattern.args);
    return count;
}

fn demandedKnownValuesArgCount(values: []const DemandedKnownValue) usize {
    var count: usize = 0;
    for (values) |value| count += demandedKnownValueArgCount(value);
    return count;
}

fn demandedKnownValueArgCount(value: DemandedKnownValue) usize {
    return switch (value) {
        .any,
        .leaf,
        => 1,
        .tag => |tag| demandedKnownIndexedValuesArgCount(tag.payloads),
        .record => |record| blk: {
            var count: usize = 0;
            for (record.fields) |field| count += demandedKnownValueArgCount(field.known_value);
            break :blk count;
        },
        .tuple => |tuple| demandedKnownIndexedValuesArgCount(tuple.items),
        .nominal => |nominal| if (nominal.backing) |backing| demandedKnownValueArgCount(backing.*) else 0,
        .callable => |callable| demandedKnownIndexedValuesArgCount(callable.captures),
        .finite_tags => |finite_tags| blk: {
            var count: usize = 1;
            for (finite_tags.alternatives) |alternative| count += demandedKnownIndexedValuesArgCount(alternative.payloads);
            break :blk count;
        },
        .finite_callables => |finite_callables| blk: {
            var count: usize = 1;
            for (finite_callables.alternatives) |alternative| count += demandedKnownIndexedValuesArgCount(alternative.captures);
            break :blk count;
        },
        .compact_finite_tags,
        .compact_finite_callables,
        => 1,
    };
}

fn demandedKnownIndexedValuesArgCount(values: []const DemandedKnownIndexedValue) usize {
    var count: usize = 0;
    for (values) |value| count += demandedKnownValueArgCount(value.known_value);
    return count;
}

fn specEql(program: *const Ast.Program, spec: Spec, pattern: CallPattern, result_demand: ValueDemand) bool {
    return patternEql(program, spec.pattern, pattern) and valueDemandEql(program, spec.result_demand, result_demand);
}

fn functionDemandSlotIdEql(lhs: FunctionDemandSlotId, rhs: FunctionDemandSlotId) bool {
    return lhs.node == rhs.node;
}

fn functionDemandRoleRank(role: FunctionDemandRole) u1 {
    return switch (role) {
        .arg => 0,
        .capture => 1,
    };
}

fn functionDemandSlotIdBefore(lhs: FunctionDemandSlotId, rhs: FunctionDemandSlotId) bool {
    return lhs.node < rhs.node;
}

fn demandSlotEndpointEql(lhs: DemandSlotEndpoint, rhs: DemandSlotEndpoint) bool {
    return lhs.kind == rhs.kind and lhs.id == rhs.id;
}

fn optionalDemandSlotEndpointEql(lhs: ?DemandSlotEndpoint, rhs: ?DemandSlotEndpoint) bool {
    if (lhs == null or rhs == null) return lhs == null and rhs == null;
    return demandSlotEndpointEql(lhs.?, rhs.?);
}

fn demandSlotEdgeEql(lhs: DemandSlotEdge, rhs: DemandSlotEdge) bool {
    return optionalDemandSlotEndpointEql(lhs.lhs, rhs.lhs) and
        optionalDemandSlotEndpointEql(lhs.rhs, rhs.rhs);
}

fn valueDemandContainsActiveRef(demand: ValueDemand) bool {
    return switch (demand) {
        .loop_param,
        .fn_param,
        => true,
        .none,
        .materialize,
        => false,
        .record => |fields| blk: {
            for (fields) |field| {
                if (valueDemandContainsActiveRef(field.demand.*)) break :blk true;
            }
            break :blk false;
        },
        .tuple => |items| blk: {
            for (items) |item| {
                if (valueDemandContainsActiveRef(item.demand.*)) break :blk true;
            }
            break :blk false;
        },
        .tag => |tag| blk: {
            for (tag.alternatives) |alternative| {
                for (alternative.payloads) |payload| {
                    if (valueDemandContainsActiveRef(payload.demand.*)) break :blk true;
                }
            }
            break :blk false;
        },
        .nominal => |backing| valueDemandContainsActiveRef(backing.*),
        .callable => |callable| blk: {
            for (callable.captures) |capture| {
                if (valueDemandContainsActiveRef(capture)) break :blk true;
            }
            if (callable.result) |result| {
                if (valueDemandContainsActiveRef(result.*)) break :blk true;
            }
            break :blk false;
        },
    };
}

fn valueDemandEql(program: ?*const Ast.Program, lhs: ValueDemand, rhs: ValueDemand) bool {
    if (std.meta.activeTag(lhs) != std.meta.activeTag(rhs)) return false;
    return switch (lhs) {
        .none,
        .materialize,
        => true,
        .loop_param => lhs.loop_param == rhs.loop_param,
        .fn_param => functionDemandSlotIdEql(lhs.fn_param, rhs.fn_param),
        .record => |lhs_fields| blk: {
            const rhs_fields = rhs.record;
            if (lhs_fields.len != rhs_fields.len) break :blk false;
            for (lhs_fields) |lhs_field| {
                const rhs_field = fieldDemandByName(program, rhs_fields, lhs_field.name) orelse break :blk false;
                if (!valueDemandEql(program, lhs_field.demand.*, rhs_field.demand.*)) break :blk false;
            }
            break :blk true;
        },
        .tuple => |lhs_items| blk: {
            const rhs_items = rhs.tuple;
            if (lhs_items.len != rhs_items.len) break :blk false;
            for (lhs_items) |lhs_item| {
                const rhs_item = itemDemandByIndex(rhs_items, lhs_item.index) orelse break :blk false;
                if (!valueDemandEql(program, lhs_item.demand.*, rhs_item.demand.*)) break :blk false;
            }
            break :blk true;
        },
        .tag => |lhs_tag| blk: {
            const rhs_alternatives = rhs.tag.alternatives;
            if (lhs_tag.alternatives.len != rhs_alternatives.len) break :blk false;
            for (lhs_tag.alternatives) |lhs_alternative| {
                const rhs_alternative = tagAlternativeDemandByName(program, rhs_alternatives, lhs_alternative.name) orelse break :blk false;
                if (lhs_alternative.payloads.len != rhs_alternative.payloads.len) break :blk false;
                for (lhs_alternative.payloads) |lhs_payload| {
                    const rhs_payload = itemDemandByIndex(rhs_alternative.payloads, lhs_payload.index) orelse break :blk false;
                    if (!valueDemandEql(program, lhs_payload.demand.*, rhs_payload.demand.*)) break :blk false;
                }
            }
            break :blk true;
        },
        .nominal => valueDemandEql(program, lhs.nominal.*, rhs.nominal.*),
        .callable => |lhs_callable| blk: {
            const rhs_callable = rhs.callable;
            const captures_len = @max(lhs_callable.captures.len, rhs_callable.captures.len);
            for (0..captures_len) |index| {
                const lhs_capture = callableCaptureDemandAt(lhs_callable.captures, index);
                const rhs_capture = callableCaptureDemandAt(rhs_callable.captures, index);
                if (!valueDemandEql(program, lhs_capture, rhs_capture)) break :blk false;
            }
            if (!valueDemandEql(program, callableResultDemand(lhs_callable.result), callableResultDemand(rhs_callable.result))) break :blk false;
            break :blk true;
        },
    };
}

fn callableCaptureDemandAt(captures: []const ValueDemand, index: usize) ValueDemand {
    return if (index < captures.len) captures[index] else .none;
}

fn callableResultDemand(result: ?*const ValueDemand) ValueDemand {
    return if (result) |demand| demand.* else .none;
}

fn ifValueControlEql(lhs: IfValue, rhs: IfValue) bool {
    if (lhs.branches.len != rhs.branches.len) return false;
    for (lhs.branches, rhs.branches) |lhs_branch, rhs_branch| {
        if (lhs_branch.cond != rhs_branch.cond) return false;
    }
    return true;
}

fn matchValueControlEql(lhs: MatchValue, rhs: MatchValue) bool {
    if (lhs.scrutinee != rhs.scrutinee) return false;
    if (lhs.comptime_site != rhs.comptime_site) return false;
    if (lhs.branches.len != rhs.branches.len) return false;
    for (lhs.branches, rhs.branches) |lhs_branch, rhs_branch| {
        if (lhs_branch.pat != rhs_branch.pat) return false;
        if (lhs_branch.guard != rhs_branch.guard) return false;
    }
    return true;
}

fn fieldDemandByName(
    program: ?*const Ast.Program,
    fields: []const FieldDemand,
    name: names.RecordFieldNameId,
) ?FieldDemand {
    for (fields) |field| {
        if (if (program) |program_ref|
            program_ref.names.recordFieldLabelTextEql(field.name, name)
        else
            field.name == name) return field;
    }
    return null;
}

fn itemDemandByIndex(items: []const ItemDemand, index: u32) ?ItemDemand {
    for (items) |item| {
        if (item.index == index) return item;
    }
    return null;
}

fn tagAlternativeDemandByName(
    program: ?*const Ast.Program,
    alternatives: []const TagAlternativeDemand,
    name: names.TagNameId,
) ?TagAlternativeDemand {
    for (alternatives) |alternative| {
        if (if (program) |program_ref|
            program_ref.names.tagLabelTextEql(alternative.name, name)
        else
            alternative.name == name) return alternative;
    }
    return null;
}

fn joinKnownValuesInArena(
    program: *const Ast.Program,
    arena: Allocator,
    lhs: KnownValue,
    rhs: KnownValue,
) Allocator.Error!?KnownValue {
    if (known_valueEql(program, lhs, rhs)) return lhs;
    if (!sameType(program, known_valueType(lhs), known_valueType(rhs))) return null;
    if (try commonKnownTags(program, arena, lhs, rhs)) |finite_tags| return finite_tags;
    if (try commonKnownCallables(program, arena, lhs, rhs)) |finite_callables| return finite_callables;

    return switch (lhs) {
        .any => |ty| KnownValue{ .any = ty },
        .leaf => |ty| blk: {
            const rhs_ty = switch (rhs) {
                .leaf => |rhs_ty| rhs_ty,
                else => break :blk null,
            };
            break :blk if (sameType(program, ty, rhs_ty)) KnownValue{ .leaf = ty } else null;
        },
        .tag => |lhs_tag| blk: {
            const rhs_tag = switch (rhs) {
                .tag => |tag| tag,
                else => break :blk null,
            };
            if (lhs_tag.name != rhs_tag.name or lhs_tag.payloads.len != rhs_tag.payloads.len) break :blk null;
            const payloads = try arena.alloc(KnownValue, lhs_tag.payloads.len);
            for (lhs_tag.payloads, rhs_tag.payloads, 0..) |lhs_payload, rhs_payload, index| {
                payloads[index] = (try joinKnownValuesInArena(program, arena, lhs_payload, rhs_payload)) orelse
                    (joinUnknownChild(program, lhs_payload, rhs_payload) orelse break :blk null);
            }
            break :blk KnownValue{ .tag = .{
                .ty = lhs_tag.ty,
                .name = lhs_tag.name,
                .payloads = payloads,
            } };
        },
        .record => |lhs_record| blk: {
            const rhs_record = switch (rhs) {
                .record => |record| record,
                else => break :blk null,
            };
            if (lhs_record.fields.len != rhs_record.fields.len) break :blk null;
            const fields = try arena.alloc(KnownField, lhs_record.fields.len);
            for (lhs_record.fields, rhs_record.fields, 0..) |lhs_field, rhs_field, index| {
                if (lhs_field.name != rhs_field.name) break :blk null;
                fields[index] = .{
                    .name = lhs_field.name,
                    .known_value = (try joinKnownValuesInArena(program, arena, lhs_field.known_value, rhs_field.known_value)) orelse
                        (joinUnknownChild(program, lhs_field.known_value, rhs_field.known_value) orelse break :blk null),
                };
            }
            break :blk KnownValue{ .record = .{
                .ty = lhs_record.ty,
                .fields = fields,
            } };
        },
        .tuple => |lhs_tuple| blk: {
            const rhs_tuple = switch (rhs) {
                .tuple => |tuple| tuple,
                else => break :blk null,
            };
            if (lhs_tuple.items.len != rhs_tuple.items.len) break :blk null;
            const items = try arena.alloc(KnownValue, lhs_tuple.items.len);
            for (lhs_tuple.items, rhs_tuple.items, 0..) |lhs_item, rhs_item, index| {
                items[index] = (try joinKnownValuesInArena(program, arena, lhs_item, rhs_item)) orelse
                    (joinUnknownChild(program, lhs_item, rhs_item) orelse break :blk null);
            }
            break :blk KnownValue{ .tuple = .{
                .ty = lhs_tuple.ty,
                .items = items,
            } };
        },
        .nominal => |lhs_nominal| blk: {
            const rhs_nominal = switch (rhs) {
                .nominal => |nominal| nominal,
                else => break :blk null,
            };
            const backing = (try joinKnownValuesInArena(program, arena, lhs_nominal.backing.*, rhs_nominal.backing.*)) orelse break :blk null;
            const stored = try arena.create(KnownValue);
            stored.* = backing;
            break :blk KnownValue{ .nominal = .{
                .ty = lhs_nominal.ty,
                .backing = stored,
            } };
        },
        .callable => |lhs_callable| blk: {
            const rhs_callable = switch (rhs) {
                .callable => |callable| callable,
                else => break :blk null,
            };
            if (!callableTargetMatches(program, lhs_callable.fn_id, rhs_callable.fn_id) or
                lhs_callable.captures.len != rhs_callable.captures.len)
            {
                break :blk null;
            }
            const captures = try arena.alloc(KnownValue, lhs_callable.captures.len);
            for (lhs_callable.captures, rhs_callable.captures, 0..) |lhs_capture, rhs_capture, index| {
                captures[index] = (try joinKnownValuesInArena(program, arena, lhs_capture, rhs_capture)) orelse
                    (joinUnknownChild(program, lhs_capture, rhs_capture) orelse break :blk null);
            }
            break :blk KnownValue{ .callable = .{
                .ty = lhs_callable.ty,
                .fn_id = lhs_callable.fn_id,
                .captures = captures,
            } };
        },
        .finite_tags => null,
        .finite_callables => null,
    };
}

fn joinUnknownChild(program: *const Ast.Program, lhs: KnownValue, rhs: KnownValue) ?KnownValue {
    const lhs_ty = known_valueType(lhs);
    return if (sameType(program, lhs_ty, known_valueType(rhs)))
        KnownValue{ .any = lhs_ty }
    else
        null;
}

fn known_valuesStrictlyDescend(program: *const Ast.Program, active: []const KnownValue, next: []const KnownValue) bool {
    if (active.len != next.len) return false;
    var descended = false;
    for (active, next) |active_known_value, next_known_value| {
        if (known_valueEql(program, active_known_value, next_known_value)) continue;
        if (!known_valueContainsStrictSubknown_value(program, active_known_value, next_known_value)) return false;
        descended = true;
    }
    return descended;
}

fn activeInlineArgsStrictlyDescend(
    program: *const Ast.Program,
    active: []const ActiveInlineArg,
    next: []const ActiveInlineArg,
    aliases: []const ActiveInlineAlias,
) bool {
    if (active.len != next.len) return false;
    var descended = false;
    for (active, next) |active_arg, next_arg| {
        if (activeInlineArgEql(program, active_arg, next_arg, aliases)) continue;
        if (!activeInlineArgContainsStrictSubArg(program, active_arg, next_arg, aliases)) return false;
        descended = true;
    }
    return descended;
}

fn activeInlineArgEql(
    program: *const Ast.Program,
    lhs: ActiveInlineArg,
    rhs: ActiveInlineArg,
    aliases: []const ActiveInlineAlias,
) bool {
    return switch (lhs) {
        .known => |lhs_known| switch (rhs) {
            .known => |rhs_known| known_valueEql(program, lhs_known, rhs_known),
            .private_state => false,
        },
        .private_state => |lhs_private| switch (rhs) {
            .known => false,
            .private_state => |rhs_private| privateStateEqlWithAliases(program, lhs_private, rhs_private, aliases),
        },
    };
}

fn activeInlineArgContainsStrictSubArg(
    program: *const Ast.Program,
    container: ActiveInlineArg,
    needle: ActiveInlineArg,
    aliases: []const ActiveInlineAlias,
) bool {
    return switch (container) {
        .known => |known_container| switch (needle) {
            .known => |known_needle| known_valueContainsStrictSubknown_value(program, known_container, known_needle),
            .private_state => |private_needle| knownValueContainsStrictPrivateState(program, known_container, private_needle),
        },
        .private_state => |private_container| switch (needle) {
            .known => |known_needle| privateStateContainsStrictKnownValue(program, private_container, known_needle),
            .private_state => |private_needle| privateStateContainsStrictSubstate(program, private_container, private_needle, aliases),
        },
    };
}

fn known_valueContainsStrictSubknown_value(program: *const Ast.Program, container: KnownValue, needle: KnownValue) bool {
    return switch (container) {
        .any => false,
        .leaf => false,
        .tag => |tag| {
            for (tag.payloads) |payload| {
                if (known_valueEql(program, payload, needle) or known_valueContainsStrictSubknown_value(program, payload, needle)) return true;
            }
            return false;
        },
        .record => |record| {
            for (record.fields) |field| {
                if (known_valueEql(program, field.known_value, needle) or known_valueContainsStrictSubknown_value(program, field.known_value, needle)) return true;
            }
            return false;
        },
        .tuple => |tuple| {
            for (tuple.items) |item| {
                if (known_valueEql(program, item, needle) or known_valueContainsStrictSubknown_value(program, item, needle)) return true;
            }
            return false;
        },
        .nominal => |nominal| {
            return known_valueEql(program, nominal.backing.*, needle) or known_valueContainsStrictSubknown_value(program, nominal.backing.*, needle);
        },
        .callable => |callable| {
            for (callable.captures) |capture| {
                if (known_valueEql(program, capture, needle) or known_valueContainsStrictSubknown_value(program, capture, needle)) return true;
            }
            return false;
        },
        .finite_tags => |finite_tags| {
            for (finite_tags.alternatives) |alternative| {
                for (alternative.payloads) |payload| {
                    if (known_valueEql(program, payload, needle) or known_valueContainsStrictSubknown_value(program, payload, needle)) return true;
                }
            }
            return false;
        },
        .finite_callables => |finite_callables| {
            for (finite_callables.alternatives) |alternative| {
                for (alternative.captures) |capture| {
                    if (known_valueEql(program, capture, needle) or known_valueContainsStrictSubknown_value(program, capture, needle)) return true;
                }
            }
            return false;
        },
    };
}

fn knownValueContainsStrictPrivateState(program: *const Ast.Program, container: KnownValue, needle: PrivateStateValue) bool {
    return switch (container) {
        .any => false,
        .leaf => false,
        .tag => |tag| {
            for (tag.payloads) |payload| {
                if (knownValueMatchesPrivateState(program, payload, needle) or knownValueContainsStrictPrivateState(program, payload, needle)) return true;
            }
            return false;
        },
        .record => |record| {
            for (record.fields) |field| {
                if (knownValueMatchesPrivateState(program, field.known_value, needle) or knownValueContainsStrictPrivateState(program, field.known_value, needle)) return true;
            }
            return false;
        },
        .tuple => |tuple| {
            for (tuple.items) |item| {
                if (knownValueMatchesPrivateState(program, item, needle) or knownValueContainsStrictPrivateState(program, item, needle)) return true;
            }
            return false;
        },
        .nominal => |nominal| knownValueMatchesPrivateState(program, nominal.backing.*, needle) or
            knownValueContainsStrictPrivateState(program, nominal.backing.*, needle),
        .callable => |callable| {
            for (callable.captures) |capture| {
                if (knownValueMatchesPrivateState(program, capture, needle) or knownValueContainsStrictPrivateState(program, capture, needle)) return true;
            }
            return false;
        },
        .finite_tags => |finite_tags| {
            for (finite_tags.alternatives) |alternative| {
                for (alternative.payloads) |payload| {
                    if (knownValueMatchesPrivateState(program, payload, needle) or knownValueContainsStrictPrivateState(program, payload, needle)) return true;
                }
            }
            return false;
        },
        .finite_callables => |finite_callables| {
            for (finite_callables.alternatives) |alternative| {
                for (alternative.captures) |capture| {
                    if (knownValueMatchesPrivateState(program, capture, needle) or knownValueContainsStrictPrivateState(program, capture, needle)) return true;
                }
            }
            return false;
        },
    };
}

fn privateStateContainsStrictKnownValue(program: *const Ast.Program, container: PrivateStateValue, needle: KnownValue) bool {
    return switch (container) {
        .leaf => false,
        .tag => |tag| {
            for (tag.payloads) |payload| {
                if (knownValueMatchesPrivateState(program, needle, payload.value) or privateStateContainsStrictKnownValue(program, payload.value, needle)) return true;
            }
            return false;
        },
        .record => |record| {
            for (record.fields) |field| {
                if (knownValueMatchesPrivateState(program, needle, field.value) or privateStateContainsStrictKnownValue(program, field.value, needle)) return true;
            }
            return false;
        },
        .tuple => |tuple| {
            for (tuple.items) |item| {
                if (knownValueMatchesPrivateState(program, needle, item.value) or privateStateContainsStrictKnownValue(program, item.value, needle)) return true;
            }
            return false;
        },
        .nominal => |nominal| if (nominal.backing) |backing|
            knownValueMatchesPrivateState(program, needle, backing.*) or privateStateContainsStrictKnownValue(program, backing.*, needle)
        else
            false,
        .callable => |callable| {
            for (callable.captures) |capture| {
                if (knownValueMatchesPrivateState(program, needle, capture.value) or privateStateContainsStrictKnownValue(program, capture.value, needle)) return true;
            }
            return false;
        },
        .compact_finite_tags,
        .compact_finite_callables,
        => false,
    };
}

fn privateStateContainsStrictSubstate(
    program: *const Ast.Program,
    container: PrivateStateValue,
    needle: PrivateStateValue,
    aliases: []const ActiveInlineAlias,
) bool {
    return switch (container) {
        .leaf => |leaf| privateStateIsStrictFieldOrTupleReadFromExpr(program, needle, leaf.expr, aliases),
        .tag => |tag| {
            for (tag.payloads) |payload| {
                if (privateStateEqlWithAliases(program, payload.value, needle, aliases) or privateStateContainsStrictSubstate(program, payload.value, needle, aliases)) return true;
            }
            return false;
        },
        .record => |record| {
            for (record.fields) |field| {
                if (privateStateEqlWithAliases(program, field.value, needle, aliases) or privateStateContainsStrictSubstate(program, field.value, needle, aliases)) return true;
            }
            return false;
        },
        .tuple => |tuple| {
            for (tuple.items) |item| {
                if (privateStateEqlWithAliases(program, item.value, needle, aliases) or privateStateContainsStrictSubstate(program, item.value, needle, aliases)) return true;
            }
            return false;
        },
        .nominal => |nominal| if (nominal.backing) |backing|
            privateStateEqlWithAliases(program, backing.*, needle, aliases) or privateStateContainsStrictSubstate(program, backing.*, needle, aliases)
        else
            false,
        .callable => |callable| {
            for (callable.captures) |capture| {
                if (privateStateEqlWithAliases(program, capture.value, needle, aliases) or privateStateContainsStrictSubstate(program, capture.value, needle, aliases)) return true;
            }
            return false;
        },
        .compact_finite_tags,
        .compact_finite_callables,
        => false,
    };
}

fn privateStateIsStrictFieldOrTupleReadFromExpr(
    program: *const Ast.Program,
    value: PrivateStateValue,
    root: Ast.ExprId,
    aliases: []const ActiveInlineAlias,
) bool {
    return switch (value) {
        .leaf => |leaf| exprIsStrictFieldOrTupleReadFromExpr(program, leaf.expr, root, aliases),
        .tag => |tag| blk: {
            for (tag.payloads) |payload| {
                if (!privateStateIsStrictFieldOrTupleReadFromExpr(program, payload.value, root, aliases)) break :blk false;
            }
            break :blk tag.payloads.len != 0;
        },
        .record => |record| blk: {
            for (record.fields) |field| {
                if (!privateStateIsStrictFieldOrTupleReadFromExpr(program, field.value, root, aliases)) break :blk false;
            }
            break :blk record.fields.len != 0;
        },
        .tuple => |tuple| blk: {
            for (tuple.items) |item| {
                if (!privateStateIsStrictFieldOrTupleReadFromExpr(program, item.value, root, aliases)) break :blk false;
            }
            break :blk tuple.items.len != 0;
        },
        .nominal => |nominal| if (nominal.backing) |backing| privateStateIsStrictFieldOrTupleReadFromExpr(program, backing.*, root, aliases) else false,
        .callable => |callable| blk: {
            for (callable.captures) |capture| {
                if (!privateStateIsStrictFieldOrTupleReadFromExpr(program, capture.value, root, aliases)) break :blk false;
            }
            break :blk callable.captures.len != 0;
        },
        .compact_finite_tags,
        .compact_finite_callables,
        => false,
    };
}

fn exprIsStrictFieldOrTupleReadFromExpr(
    program: *const Ast.Program,
    expr_id: Ast.ExprId,
    root: Ast.ExprId,
    aliases: []const ActiveInlineAlias,
) bool {
    if (expr_id == root) return false;
    const expr = program.exprs.items[@intFromEnum(expr_id)];
    return switch (expr.data) {
        .field_access => |field| exprMatchesRootOrAlias(program, field.receiver, root, aliases) or exprIsStrictFieldOrTupleReadFromExpr(program, field.receiver, root, aliases),
        .tuple_access => |access| exprMatchesRootOrAlias(program, access.tuple, root, aliases) or exprIsStrictFieldOrTupleReadFromExpr(program, access.tuple, root, aliases),
        .comptime_branch_taken => |taken| exprIsStrictFieldOrTupleReadFromExpr(program, taken.body, root, aliases),
        else => false,
    };
}

fn exprMatchesRootOrAlias(
    program: *const Ast.Program,
    expr_id: Ast.ExprId,
    root: Ast.ExprId,
    aliases: []const ActiveInlineAlias,
) bool {
    if (expr_id == root) return true;
    const local = localExpr(program, expr_id) orelse return false;
    for (aliases) |alias| {
        if (alias.local != local) continue;
        return switch (alias.value) {
            .known => false,
            .private_state => |private_state| if (privateStateLeafExpr(private_state)) |leaf_expr| leaf_expr == root else false,
        };
    }
    return false;
}

fn privateStateEqlWithAliases(
    program: *const Ast.Program,
    lhs: PrivateStateValue,
    rhs: PrivateStateValue,
    aliases: []const ActiveInlineAlias,
) bool {
    if (std.meta.activeTag(lhs) != std.meta.activeTag(rhs)) return false;
    return switch (lhs) {
        .leaf => |lhs_leaf| sameType(program, lhs_leaf.ty, rhs.leaf.ty) and
            (lhs_leaf.expr == rhs.leaf.expr or privateStateLeafExprsAliased(program, lhs_leaf.expr, rhs.leaf.expr, aliases)),
        .tag => |lhs_tag| privateStateTagEqlWithAliases(program, lhs_tag, rhs.tag, aliases),
        .record => |lhs_record| blk: {
            const rhs_record = rhs.record;
            if (!sameType(program, lhs_record.ty, rhs_record.ty) or lhs_record.fields.len != rhs_record.fields.len) break :blk false;
            for (lhs_record.fields) |lhs_field| {
                const rhs_field = privateStateFieldByName(program, rhs_record.fields, lhs_field.name) orelse break :blk false;
                if (!privateStateEqlWithAliases(program, lhs_field.value, rhs_field, aliases)) break :blk false;
            }
            break :blk true;
        },
        .tuple => |lhs_tuple| blk: {
            const rhs_tuple = rhs.tuple;
            if (!sameType(program, lhs_tuple.ty, rhs_tuple.ty) or lhs_tuple.items.len != rhs_tuple.items.len) break :blk false;
            for (lhs_tuple.items) |lhs_item| {
                const rhs_item = privateStateIndexedValueByIndex(rhs_tuple.items, lhs_item.index) orelse break :blk false;
                if (!privateStateEqlWithAliases(program, lhs_item.value, rhs_item, aliases)) break :blk false;
            }
            break :blk true;
        },
        .nominal => |lhs_nominal| blk: {
            const rhs_nominal = rhs.nominal;
            if (!sameType(program, lhs_nominal.ty, rhs_nominal.ty)) break :blk false;
            if (lhs_nominal.backing == null or rhs_nominal.backing == null) break :blk lhs_nominal.backing == null and rhs_nominal.backing == null;
            break :blk privateStateEqlWithAliases(program, lhs_nominal.backing.?.*, rhs_nominal.backing.?.*, aliases);
        },
        .callable => |lhs_callable| privateStateCallableEqlWithAliases(program, lhs_callable, rhs.callable, aliases),
        .compact_finite_tags => |lhs_finite| lhs_finite.compact_expr == rhs.compact_finite_tags.compact_expr and
            demandedKnownValueEql(program, .{ .finite_tags = lhs_finite.source }, .{ .finite_tags = rhs.compact_finite_tags.source }),
        .compact_finite_callables => |lhs_finite| lhs_finite.compact_expr == rhs.compact_finite_callables.compact_expr and
            demandedKnownValueEql(program, .{ .finite_callables = lhs_finite.source }, .{ .finite_callables = rhs.compact_finite_callables.source }),
    };
}

fn privateStateTagEqlWithAliases(
    program: *const Ast.Program,
    lhs: PrivateStateTag,
    rhs: PrivateStateTag,
    aliases: []const ActiveInlineAlias,
) bool {
    if (!sameType(program, lhs.ty, rhs.ty) or lhs.name != rhs.name or lhs.payloads.len != rhs.payloads.len) return false;
    for (lhs.payloads) |lhs_payload| {
        const rhs_payload = privateStateIndexedValueByIndex(rhs.payloads, lhs_payload.index) orelse return false;
        if (!privateStateEqlWithAliases(program, lhs_payload.value, rhs_payload, aliases)) return false;
    }
    return true;
}

fn privateStateCallableEqlWithAliases(
    program: *const Ast.Program,
    lhs: PrivateStateCallable,
    rhs: PrivateStateCallable,
    aliases: []const ActiveInlineAlias,
) bool {
    if (!sameType(program, lhs.ty, rhs.ty) or
        !callableTargetMatches(program, lhs.fn_id, rhs.fn_id) or
        lhs.captures.len != rhs.captures.len)
    {
        return false;
    }
    for (lhs.captures) |lhs_capture| {
        const rhs_capture = privateStateIndexedValueByIndex(rhs.captures, lhs_capture.index) orelse return false;
        if (!privateStateEqlWithAliases(program, lhs_capture.value, rhs_capture, aliases)) return false;
    }
    return true;
}

fn privateStateLeafExprsAliased(
    program: *const Ast.Program,
    lhs_expr: Ast.ExprId,
    rhs_expr: Ast.ExprId,
    aliases: []const ActiveInlineAlias,
) bool {
    const lhs = localExpr(program, lhs_expr) orelse return false;
    const rhs = localExpr(program, rhs_expr) orelse return false;
    for (aliases) |lhs_alias| {
        if (lhs_alias.value != .private_state) continue;
        if (activeAliasValueLocal(program, lhs_alias.value) != lhs) continue;
        for (aliases) |rhs_alias| {
            if (rhs_alias.local != lhs_alias.local) continue;
            if (activeAliasValueLocal(program, rhs_alias.value) == rhs) return true;
        }
    }
    for (aliases) |lhs_alias| {
        if (lhs_alias.value != .private_state) continue;
        for (aliases) |rhs_alias| {
            if (rhs_alias.local != lhs_alias.local or rhs_alias.value != .private_state) continue;
            if (privateStateLeafExprsAtSamePath(
                program,
                lhs_alias.value.private_state,
                lhs_expr,
                rhs_alias.value.private_state,
                rhs_expr,
            )) return true;
        }
    }
    return false;
}

fn activeAliasValueLocal(program: *const Ast.Program, value: ActiveInlineArg) ?Ast.LocalId {
    return switch (value) {
        .known => null,
        .private_state => |private_state| if (privateStateLeafExpr(private_state)) |expr| localExpr(program, expr) else null,
    };
}

fn privateStateLeafExprsAtSamePath(
    program: *const Ast.Program,
    lhs: PrivateStateValue,
    lhs_expr: Ast.ExprId,
    rhs: PrivateStateValue,
    rhs_expr: Ast.ExprId,
) bool {
    if (std.meta.activeTag(lhs) != std.meta.activeTag(rhs)) return false;
    return switch (lhs) {
        .leaf => |lhs_leaf| lhs_leaf.expr == lhs_expr and rhs.leaf.expr == rhs_expr,
        .tag => |lhs_tag| blk: {
            const rhs_tag = rhs.tag;
            if (!sameType(program, lhs_tag.ty, rhs_tag.ty) or lhs_tag.name != rhs_tag.name) break :blk false;
            for (lhs_tag.payloads) |lhs_payload| {
                const rhs_payload = privateStateIndexedValueByIndex(rhs_tag.payloads, lhs_payload.index) orelse continue;
                if (privateStateLeafExprsAtSamePath(program, lhs_payload.value, lhs_expr, rhs_payload, rhs_expr)) break :blk true;
            }
            break :blk false;
        },
        .record => |lhs_record| blk: {
            const rhs_record = rhs.record;
            if (!sameType(program, lhs_record.ty, rhs_record.ty)) break :blk false;
            for (lhs_record.fields) |lhs_field| {
                const rhs_field = privateStateFieldByName(program, rhs_record.fields, lhs_field.name) orelse continue;
                if (privateStateLeafExprsAtSamePath(program, lhs_field.value, lhs_expr, rhs_field, rhs_expr)) break :blk true;
            }
            break :blk false;
        },
        .tuple => |lhs_tuple| blk: {
            const rhs_tuple = rhs.tuple;
            if (!sameType(program, lhs_tuple.ty, rhs_tuple.ty)) break :blk false;
            for (lhs_tuple.items) |lhs_item| {
                const rhs_item = privateStateIndexedValueByIndex(rhs_tuple.items, lhs_item.index) orelse continue;
                if (privateStateLeafExprsAtSamePath(program, lhs_item.value, lhs_expr, rhs_item, rhs_expr)) break :blk true;
            }
            break :blk false;
        },
        .nominal => |lhs_nominal| blk: {
            const rhs_nominal = rhs.nominal;
            if (!sameType(program, lhs_nominal.ty, rhs_nominal.ty)) break :blk false;
            const lhs_backing = lhs_nominal.backing orelse break :blk false;
            const rhs_backing = rhs_nominal.backing orelse break :blk false;
            break :blk privateStateLeafExprsAtSamePath(program, lhs_backing.*, lhs_expr, rhs_backing.*, rhs_expr);
        },
        .callable => |lhs_callable| blk: {
            const rhs_callable = rhs.callable;
            if (!sameType(program, lhs_callable.ty, rhs_callable.ty) or !callableTargetMatches(program, lhs_callable.fn_id, rhs_callable.fn_id)) break :blk false;
            for (lhs_callable.captures) |lhs_capture| {
                const rhs_capture = privateStateIndexedValueByIndex(rhs_callable.captures, lhs_capture.index) orelse continue;
                if (privateStateLeafExprsAtSamePath(program, lhs_capture.value, lhs_expr, rhs_capture, rhs_expr)) break :blk true;
            }
            break :blk false;
        },
        .compact_finite_tags,
        .compact_finite_callables,
        => false,
    };
}

fn privateStateEql(program: *const Ast.Program, lhs: PrivateStateValue, rhs: PrivateStateValue) bool {
    if (std.meta.activeTag(lhs) != std.meta.activeTag(rhs)) return false;
    return switch (lhs) {
        .leaf => |lhs_leaf| sameType(program, lhs_leaf.ty, rhs.leaf.ty) and lhs_leaf.expr == rhs.leaf.expr,
        .tag => |lhs_tag| privateStateTagEql(program, lhs_tag, rhs.tag),
        .record => |lhs_record| blk: {
            const rhs_record = rhs.record;
            if (!sameType(program, lhs_record.ty, rhs_record.ty) or lhs_record.fields.len != rhs_record.fields.len) break :blk false;
            for (lhs_record.fields) |lhs_field| {
                const rhs_field = privateStateFieldByName(program, rhs_record.fields, lhs_field.name) orelse break :blk false;
                if (!privateStateEql(program, lhs_field.value, rhs_field)) break :blk false;
            }
            break :blk true;
        },
        .tuple => |lhs_tuple| blk: {
            const rhs_tuple = rhs.tuple;
            if (!sameType(program, lhs_tuple.ty, rhs_tuple.ty) or lhs_tuple.items.len != rhs_tuple.items.len) break :blk false;
            for (lhs_tuple.items) |lhs_item| {
                const rhs_item = privateStateIndexedValueByIndex(rhs_tuple.items, lhs_item.index) orelse break :blk false;
                if (!privateStateEql(program, lhs_item.value, rhs_item)) break :blk false;
            }
            break :blk true;
        },
        .nominal => |lhs_nominal| blk: {
            const rhs_nominal = rhs.nominal;
            if (!sameType(program, lhs_nominal.ty, rhs_nominal.ty)) break :blk false;
            if (lhs_nominal.backing == null or rhs_nominal.backing == null) break :blk lhs_nominal.backing == null and rhs_nominal.backing == null;
            break :blk privateStateEql(program, lhs_nominal.backing.?.*, rhs_nominal.backing.?.*);
        },
        .callable => |lhs_callable| privateStateCallableEql(program, lhs_callable, rhs.callable),
        .compact_finite_tags => |lhs_finite| lhs_finite.compact_expr == rhs.compact_finite_tags.compact_expr and
            demandedKnownValueEql(program, .{ .finite_tags = lhs_finite.source }, .{ .finite_tags = rhs.compact_finite_tags.source }),
        .compact_finite_callables => |lhs_finite| lhs_finite.compact_expr == rhs.compact_finite_callables.compact_expr and
            demandedKnownValueEql(program, .{ .finite_callables = lhs_finite.source }, .{ .finite_callables = rhs.compact_finite_callables.source }),
    };
}

fn privateStateTagEql(program: *const Ast.Program, lhs: PrivateStateTag, rhs: PrivateStateTag) bool {
    if (!sameType(program, lhs.ty, rhs.ty) or lhs.name != rhs.name or lhs.payloads.len != rhs.payloads.len) return false;
    for (lhs.payloads) |lhs_payload| {
        const rhs_payload = privateStateIndexedValueByIndex(rhs.payloads, lhs_payload.index) orelse return false;
        if (!privateStateEql(program, lhs_payload.value, rhs_payload)) return false;
    }
    return true;
}

fn privateStateCallableEql(program: *const Ast.Program, lhs: PrivateStateCallable, rhs: PrivateStateCallable) bool {
    if (!sameType(program, lhs.ty, rhs.ty) or
        !callableTargetMatches(program, lhs.fn_id, rhs.fn_id) or
        lhs.captures.len != rhs.captures.len)
    {
        return false;
    }
    for (lhs.captures) |lhs_capture| {
        const rhs_capture = privateStateIndexedValueByIndex(rhs.captures, lhs_capture.index) orelse return false;
        if (!privateStateEql(program, lhs_capture.value, rhs_capture)) return false;
    }
    return true;
}

fn knownValuesContainFiniteState(known_values: []const KnownValue) bool {
    for (known_values) |known_value| {
        if (knownValueContainsFiniteState(known_value)) return true;
    }
    return false;
}

fn knownValueContainsFiniteState(known_value: KnownValue) bool {
    return switch (known_value) {
        .any,
        .leaf,
        => false,
        .tag => |tag| blk: {
            for (tag.payloads) |payload| {
                if (knownValueContainsFiniteState(payload)) break :blk true;
            }
            break :blk false;
        },
        .record => |record| blk: {
            for (record.fields) |field| {
                if (knownValueContainsFiniteState(field.known_value)) break :blk true;
            }
            break :blk false;
        },
        .tuple => |tuple| blk: {
            for (tuple.items) |item| {
                if (knownValueContainsFiniteState(item)) break :blk true;
            }
            break :blk false;
        },
        .nominal => |nominal| knownValueContainsFiniteState(nominal.backing.*),
        .callable => |callable| blk: {
            for (callable.captures) |capture| {
                if (knownValueContainsFiniteState(capture)) break :blk true;
            }
            break :blk false;
        },
        .finite_tags,
        .finite_callables,
        => true,
    };
}

fn demandedKnownValueFromDemand(
    cloner: ?*Cloner,
    program: ?*const Ast.Program,
    arena: Allocator,
    known_value: KnownValue,
    demand: ValueDemand,
) LowerError!?DemandedKnownValue {
    return switch (demand) {
        .none => null,
        .materialize => try materializedDemandedKnownValue(arena, known_value),
        .loop_param => blk: {
            const active_cloner = cloner orelse Common.invariant("loop demand reference had no active cloner");
            const resolved = active_cloner.resolveLoopDemandRef(demand);
            if (resolved == .loop_param) Common.invariant("loop demand reference resolved to itself");
            break :blk try demandedKnownValueFromDemand(cloner, program, arena, known_value, resolved);
        },
        .fn_param => blk: {
            const active_cloner = cloner orelse Common.invariant("function demand reference had no active cloner");
            const resolved = active_cloner.resolveLoopDemandRef(demand);
            if (resolved == .fn_param) Common.invariant("function demand reference resolved to itself");
            break :blk try demandedKnownValueFromDemand(cloner, program, arena, known_value, resolved);
        },
        .record => |field_demands| blk: {
            if (known_value == .nominal) {
                const demanded_backing = (try demandedKnownValueFromDemand(cloner, program, arena, known_value.nominal.backing.*, demand)) orelse break :blk null;
                const backing = try arena.create(DemandedKnownValue);
                backing.* = demanded_backing;
                break :blk DemandedKnownValue{ .nominal = .{
                    .ty = known_value.nominal.ty,
                    .backing = backing,
                } };
            }
            if (known_value == .any) {
                const program_ref = program orelse break :blk null;
                const ty = known_value.any;
                var fields = std.ArrayList(DemandedKnownField).empty;
                defer fields.deinit(arena);
                for (field_demands) |field_demand| {
                    const field_ty = recordFieldType(program_ref, ty, field_demand.name) orelse continue;
                    const demanded_field = (try demandedKnownValueFromDemand(
                        cloner,
                        program,
                        arena,
                        .{ .any = field_ty },
                        field_demand.demand.*,
                    )) orelse continue;
                    try fields.append(arena, .{
                        .name = field_demand.name,
                        .known_value = demanded_field,
                    });
                }
                if (fields.items.len == 0) break :blk null;
                break :blk DemandedKnownValue{ .record = .{
                    .ty = ty,
                    .fields = try arena.dupe(DemandedKnownField, fields.items),
                } };
            }
            const record = switch (known_value) {
                .record => |record| record,
                else => break :blk null,
            };

            var fields = std.ArrayList(DemandedKnownField).empty;
            defer fields.deinit(arena);
            for (record.fields) |field| {
                const field_demand = fieldDemandByName(program, field_demands, field.name) orelse continue;
                const demanded_field = (try demandedKnownValueFromDemand(cloner, program, arena, field.known_value, field_demand.demand.*)) orelse continue;
                try fields.append(arena, .{
                    .name = field.name,
                    .known_value = demanded_field,
                });
            }
            if (fields.items.len == 0) break :blk null;
            break :blk DemandedKnownValue{ .record = .{
                .ty = record.ty,
                .fields = try arena.dupe(DemandedKnownField, fields.items),
            } };
        },
        .tuple => |item_demands| blk: {
            if (known_value == .nominal) {
                const demanded_backing = (try demandedKnownValueFromDemand(cloner, program, arena, known_value.nominal.backing.*, demand)) orelse break :blk null;
                const backing = try arena.create(DemandedKnownValue);
                backing.* = demanded_backing;
                break :blk DemandedKnownValue{ .nominal = .{
                    .ty = known_value.nominal.ty,
                    .backing = backing,
                } };
            }
            if (known_value == .any) {
                const program_ref = program orelse break :blk null;
                const ty = known_value.any;
                var items = std.ArrayList(DemandedKnownIndexedValue).empty;
                defer items.deinit(arena);
                for (item_demands) |item_demand| {
                    const item_ty = tupleItemType(program_ref, ty, item_demand.index) orelse continue;
                    const demanded_item = (try demandedKnownValueFromDemand(
                        cloner,
                        program,
                        arena,
                        .{ .any = item_ty },
                        item_demand.demand.*,
                    )) orelse continue;
                    try items.append(arena, .{
                        .index = item_demand.index,
                        .known_value = demanded_item,
                    });
                }
                if (items.items.len == 0) break :blk null;
                break :blk DemandedKnownValue{ .tuple = .{
                    .ty = ty,
                    .items = try arena.dupe(DemandedKnownIndexedValue, items.items),
                } };
            }
            const tuple = switch (known_value) {
                .tuple => |tuple| tuple,
                else => break :blk null,
            };

            var items = std.ArrayList(DemandedKnownIndexedValue).empty;
            defer items.deinit(arena);
            for (tuple.items, 0..) |item, index| {
                const item_demand = itemDemandByIndex(item_demands, @intCast(index)) orelse continue;
                const demanded_item = (try demandedKnownValueFromDemand(cloner, program, arena, item, item_demand.demand.*)) orelse continue;
                try items.append(arena, .{
                    .index = @intCast(index),
                    .known_value = demanded_item,
                });
            }
            if (items.items.len == 0) break :blk null;
            break :blk DemandedKnownValue{ .tuple = .{
                .ty = tuple.ty,
                .items = try arena.dupe(DemandedKnownIndexedValue, items.items),
            } };
        },
        .tag => |tag_demand| blk: {
            if (known_value == .nominal) {
                const demanded_backing = (try demandedKnownValueFromDemand(cloner, program, arena, known_value.nominal.backing.*, demand)) orelse break :blk null;
                const backing = try arena.create(DemandedKnownValue);
                backing.* = demanded_backing;
                break :blk DemandedKnownValue{ .nominal = .{
                    .ty = known_value.nominal.ty,
                    .backing = backing,
                } };
            }
            if (known_value == .any) {
                const program_ref = program orelse break :blk null;
                const ty = known_value.any;
                const tags = tagUnionTypeTags(program_ref, ty) orelse break :blk null;
                var alternatives = std.ArrayList(DemandedKnownTag).empty;
                defer alternatives.deinit(arena);

                for (tags) |tag| {
                    const payload_tys = program_ref.types.span(tag.payloads);
                    var payloads = std.ArrayList(DemandedKnownIndexedValue).empty;
                    defer payloads.deinit(arena);
                    if (tagAlternativeDemandByName(program, tag_demand.alternatives, tag.name)) |alternative_demand| {
                        for (alternative_demand.payloads) |payload_demand| {
                            if (payload_demand.index >= payload_tys.len) continue;
                            const demanded_payload = (try demandedKnownValueFromDemand(
                                cloner,
                                program,
                                arena,
                                .{ .any = payload_tys[payload_demand.index] },
                                payload_demand.demand.*,
                            )) orelse continue;
                            try payloads.append(arena, .{
                                .index = payload_demand.index,
                                .known_value = demanded_payload,
                            });
                        }
                    }
                    try alternatives.append(arena, .{
                        .ty = ty,
                        .name = tag.name,
                        .payloads = try arena.dupe(DemandedKnownIndexedValue, payloads.items),
                    });
                }

                if (alternatives.items.len == 0) break :blk null;
                break :blk DemandedKnownValue{ .finite_tags = .{
                    .ty = ty,
                    .alternatives = try arena.dupe(DemandedKnownTag, alternatives.items),
                } };
            }

            switch (known_value) {
                .tag => |tag| {
                    var payloads = std.ArrayList(DemandedKnownIndexedValue).empty;
                    defer payloads.deinit(arena);
                    if (tagAlternativeDemandByName(program, tag_demand.alternatives, tag.name)) |alternative_demand| {
                        for (tag.payloads, 0..) |payload, index| {
                            const payload_demand = itemDemandByIndex(alternative_demand.payloads, @intCast(index)) orelse continue;
                            const demanded_payload = (try demandedKnownValueFromDemand(cloner, program, arena, payload, payload_demand.demand.*)) orelse continue;
                            try payloads.append(arena, .{
                                .index = @intCast(index),
                                .known_value = demanded_payload,
                            });
                        }
                    }
                    break :blk DemandedKnownValue{ .tag = .{
                        .ty = tag.ty,
                        .name = tag.name,
                        .payloads = try arena.dupe(DemandedKnownIndexedValue, payloads.items),
                    } };
                },
                .finite_tags => |finite_tags| {
                    const alternatives = try arena.alloc(DemandedKnownTag, finite_tags.alternatives.len);
                    for (finite_tags.alternatives, alternatives) |alternative, *out| {
                        var payloads = std.ArrayList(DemandedKnownIndexedValue).empty;
                        defer payloads.deinit(arena);
                        if (tagAlternativeDemandByName(program, tag_demand.alternatives, alternative.name)) |alternative_demand| {
                            for (alternative.payloads, 0..) |payload, index| {
                                const payload_demand = itemDemandByIndex(alternative_demand.payloads, @intCast(index)) orelse continue;
                                const demanded_payload = (try demandedKnownValueFromDemand(cloner, program, arena, payload, payload_demand.demand.*)) orelse continue;
                                try payloads.append(arena, .{
                                    .index = @intCast(index),
                                    .known_value = demanded_payload,
                                });
                            }
                        }
                        out.* = .{
                            .ty = alternative.ty,
                            .name = alternative.name,
                            .payloads = try arena.dupe(DemandedKnownIndexedValue, payloads.items),
                        };
                    }
                    break :blk DemandedKnownValue{ .finite_tags = .{
                        .ty = finite_tags.ty,
                        .alternatives = alternatives,
                    } };
                },
                else => break :blk null,
            }
        },
        .nominal => |backing_demand| blk: {
            const nominal = switch (known_value) {
                .nominal => |nominal| nominal,
                else => break :blk null,
            };
            const demanded_backing = (try demandedKnownValueFromDemand(cloner, program, arena, nominal.backing.*, backing_demand.*)) orelse break :blk null;
            const backing = try arena.create(DemandedKnownValue);
            backing.* = demanded_backing;
            break :blk DemandedKnownValue{ .nominal = .{
                .ty = nominal.ty,
                .backing = backing,
            } };
        },
        .callable => |callable_demand| blk: {
            if (known_value == .nominal) {
                const demanded_backing = (try demandedKnownValueFromDemand(cloner, program, arena, known_value.nominal.backing.*, demand)) orelse break :blk null;
                const backing = try arena.create(DemandedKnownValue);
                backing.* = demanded_backing;
                break :blk DemandedKnownValue{ .nominal = .{
                    .ty = known_value.nominal.ty,
                    .backing = backing,
                } };
            }

            switch (known_value) {
                .callable => |callable| {
                    const effective_callable_demand = try effectiveCallableDemandForTarget(
                        cloner,
                        program,
                        arena,
                        callable_demand,
                        callable.fn_id,
                        callable.captures.len,
                        .exact_target,
                    );
                    const captures = try demandedKnownCapturesFromDemand(cloner, program, arena, callable.fn_id, callable.captures, effective_callable_demand);
                    break :blk DemandedKnownValue{ .callable = .{
                        .ty = callable.ty,
                        .fn_id = callable.fn_id,
                        .captures = captures,
                    } };
                },
                .finite_callables => |finite_callables| {
                    const alternatives = try arena.alloc(DemandedKnownCallable, finite_callables.alternatives.len);
                    for (finite_callables.alternatives, alternatives) |alternative, *out| {
                        const effective_callable_demand = try effectiveCallableDemandForTarget(
                            cloner,
                            program,
                            arena,
                            callable_demand,
                            alternative.fn_id,
                            alternative.captures.len,
                            .finite_alternative,
                        );
                        const captures = try demandedKnownCapturesFromDemand(cloner, program, arena, alternative.fn_id, alternative.captures, effective_callable_demand);
                        out.* = .{
                            .ty = alternative.ty,
                            .fn_id = alternative.fn_id,
                            .captures = captures,
                        };
                    }
                    break :blk DemandedKnownValue{ .finite_callables = .{
                        .ty = finite_callables.ty,
                        .alternatives = alternatives,
                    } };
                },
                else => break :blk null,
            }
        },
    };
}

const CallableDemandProjection = enum {
    exact_target,
    finite_alternative,
};

fn effectiveCallableDemandForTarget(
    cloner: ?*Cloner,
    program: ?*const Ast.Program,
    arena: Allocator,
    base_demand: CallableDemand,
    fn_id: Ast.FnId,
    known_capture_count: usize,
    projection: CallableDemandProjection,
) LowerError!CallableDemand {
    const capture_count = sourceCaptureCountForTarget(program, fn_id, known_capture_count);
    var effective = try projectCallableDemandForTarget(arena, base_demand, capture_count, projection);
    if (cloner) |active_cloner| {
        if (base_demand.result) |result_demand| {
            const derived = try active_cloner.callableDemandForFnWithResultDemand(fn_id, capture_count, result_demand.*);
            const merged = try active_cloner.pass.mergeValueDemand(.{ .callable = effective }, derived);
            if (merged == .callable) {
                effective = try projectCallableDemandForTarget(arena, merged.callable, capture_count, projection);
            }
        }
    }
    return effective;
}

fn sourceCaptureCountForTarget(program: ?*const Ast.Program, fn_id: Ast.FnId, known_capture_count: usize) usize {
    const program_ref = program orelse return known_capture_count;
    const source_fn = program_ref.fns.items[@intFromEnum(fn_id)];
    return program_ref.typedLocalSpan(source_fn.captures).len;
}

fn projectCallableDemandForTarget(
    arena: Allocator,
    demand: CallableDemand,
    capture_count: usize,
    projection: CallableDemandProjection,
) Allocator.Error!CallableDemand {
    if (demand.captures.len <= capture_count) return demand;

    switch (projection) {
        .exact_target => {
            for (demand.captures[capture_count..]) |capture_demand| {
                if (capture_demand != .none) Common.invariant("callable demand capture index exceeded target source capture count");
            }
        },
        .finite_alternative => {},
    }

    const captures = try arena.alloc(ValueDemand, capture_count);
    for (captures, demand.captures[0..capture_count]) |*out, capture_demand| {
        out.* = capture_demand;
    }
    return .{
        .captures = captures,
        .result = demand.result,
    };
}

fn knownValueFromDemandedKnownValue(program: *const Ast.Program, arena: Allocator, known_value: DemandedKnownValue) Allocator.Error!KnownValue {
    return switch (known_value) {
        .any => |ty| .{ .any = ty },
        .leaf => |ty| .{ .leaf = ty },
        .tag => |tag| .{ .tag = try knownTagFromDemandedKnownTag(program, arena, tag) },
        .record => |record| blk: {
            const fields = try arena.alloc(KnownField, record.fields.len);
            for (record.fields, fields) |field, *out| {
                out.* = .{
                    .name = field.name,
                    .known_value = try knownValueFromDemandedKnownValue(program, arena, field.known_value),
                };
            }
            break :blk KnownValue{ .record = .{
                .ty = record.ty,
                .fields = fields,
            } };
        },
        .tuple => |tuple| blk: {
            const type_items = tupleTypeItems(program, tuple.ty);
            const items = try arena.alloc(KnownValue, type_items.len);
            for (type_items, items) |item_ty, *out| out.* = .{ .any = item_ty };
            for (tuple.items) |item| {
                if (item.index >= items.len) Common.invariant("demanded tuple item index exceeded tuple type length");
                items[item.index] = try knownValueFromDemandedKnownValue(program, arena, item.known_value);
            }
            break :blk KnownValue{ .tuple = .{
                .ty = tuple.ty,
                .items = items,
            } };
        },
        .nominal => |nominal| blk: {
            const backing = nominal.backing orelse break :blk KnownValue{ .any = nominal.ty };
            const stored = try arena.create(KnownValue);
            stored.* = try knownValueFromDemandedKnownValue(program, arena, backing.*);
            break :blk KnownValue{ .nominal = .{
                .ty = nominal.ty,
                .backing = stored,
            } };
        },
        .callable => |callable| .{ .callable = try knownCallableFromDemandedKnownCallable(program, arena, callable) },
        .finite_tags,
        .compact_finite_tags,
        => |finite_tags| blk: {
            const alternatives = try arena.alloc(KnownTag, finite_tags.alternatives.len);
            for (finite_tags.alternatives, alternatives) |alternative, *out| {
                out.* = try knownTagFromDemandedKnownTag(program, arena, alternative);
            }
            break :blk KnownValue{ .finite_tags = .{
                .ty = finite_tags.ty,
                .alternatives = alternatives,
            } };
        },
        .finite_callables,
        .compact_finite_callables,
        => |finite_callables| blk: {
            const alternatives = try arena.alloc(KnownCallable, finite_callables.alternatives.len);
            for (finite_callables.alternatives, alternatives) |alternative, *out| {
                out.* = try knownCallableFromDemandedKnownCallable(program, arena, alternative);
            }
            break :blk KnownValue{ .finite_callables = .{
                .ty = finite_callables.ty,
                .alternatives = alternatives,
            } };
        },
    };
}

fn knownTagFromDemandedKnownTag(program: *const Ast.Program, arena: Allocator, tag: DemandedKnownTag) Allocator.Error!KnownTag {
    const payload_tys = tagTypePayloads(program, tag.ty, tag.name) orelse
        Common.invariant("demanded tag referenced a tag absent from its type");
    const payloads = try arena.alloc(KnownValue, payload_tys.len);
    for (payload_tys, payloads) |payload_ty, *out| out.* = .{ .any = payload_ty };
    for (tag.payloads) |payload| {
        if (payload.index >= payloads.len) Common.invariant("demanded tag payload index exceeded tag type length");
        payloads[payload.index] = try knownValueFromDemandedKnownValue(program, arena, payload.known_value);
    }
    return .{
        .ty = tag.ty,
        .name = tag.name,
        .payloads = payloads,
    };
}

fn knownCallableFromDemandedKnownCallable(program: *const Ast.Program, arena: Allocator, callable: DemandedKnownCallable) Allocator.Error!KnownCallable {
    const source_fn = program.fns.items[@intFromEnum(callable.fn_id)];
    const source_captures = program.typedLocalSpan(source_fn.captures);
    const captures = try arena.alloc(KnownValue, source_captures.len);
    for (source_captures, captures) |source_capture, *out| out.* = .{ .any = source_capture.ty };
    for (callable.captures) |capture| {
        if (capture.index >= captures.len) Common.invariant("demanded callable capture index exceeded capture count");
        captures[capture.index] = try knownValueFromDemandedKnownValue(program, arena, capture.known_value);
    }
    return .{
        .ty = callable.ty,
        .fn_id = callable.fn_id,
        .captures = captures,
    };
}

fn materializedDemandedKnownValue(arena: Allocator, known_value: KnownValue) Allocator.Error!DemandedKnownValue {
    return switch (known_value) {
        .any => |ty| .{ .any = ty },
        .leaf => |ty| .{ .leaf = ty },
        .tag => |tag| .{ .tag = .{
            .ty = tag.ty,
            .name = tag.name,
            .payloads = try materializedDemandedKnownIndexedValues(arena, tag.payloads),
        } },
        .record => |record| blk: {
            const fields = try arena.alloc(DemandedKnownField, record.fields.len);
            for (record.fields, fields) |field, *out| {
                out.* = .{
                    .name = field.name,
                    .known_value = try materializedDemandedKnownValue(arena, field.known_value),
                };
            }
            break :blk DemandedKnownValue{ .record = .{
                .ty = record.ty,
                .fields = fields,
            } };
        },
        .tuple => |tuple| .{ .tuple = .{
            .ty = tuple.ty,
            .items = try materializedDemandedKnownIndexedValues(arena, tuple.items),
        } },
        .nominal => |nominal| blk: {
            const backing = try arena.create(DemandedKnownValue);
            backing.* = try materializedDemandedKnownValue(arena, nominal.backing.*);
            break :blk DemandedKnownValue{ .nominal = .{
                .ty = nominal.ty,
                .backing = backing,
            } };
        },
        .callable => |callable| .{ .callable = .{
            .ty = callable.ty,
            .fn_id = callable.fn_id,
            .captures = try materializedDemandedKnownIndexedValues(arena, callable.captures),
        } },
        .finite_tags => |finite_tags| blk: {
            const alternatives = try arena.alloc(DemandedKnownTag, finite_tags.alternatives.len);
            for (finite_tags.alternatives, alternatives) |alternative, *out| {
                out.* = .{
                    .ty = alternative.ty,
                    .name = alternative.name,
                    .payloads = try materializedDemandedKnownIndexedValues(arena, alternative.payloads),
                };
            }
            break :blk DemandedKnownValue{ .finite_tags = .{
                .ty = finite_tags.ty,
                .alternatives = alternatives,
            } };
        },
        .finite_callables => |finite_callables| blk: {
            const alternatives = try arena.alloc(DemandedKnownCallable, finite_callables.alternatives.len);
            for (finite_callables.alternatives, alternatives) |alternative, *out| {
                out.* = .{
                    .ty = alternative.ty,
                    .fn_id = alternative.fn_id,
                    .captures = try materializedDemandedKnownIndexedValues(arena, alternative.captures),
                };
            }
            break :blk DemandedKnownValue{ .finite_callables = .{
                .ty = finite_callables.ty,
                .alternatives = alternatives,
            } };
        },
    };
}

fn materializedDemandedKnownIndexedValues(
    arena: Allocator,
    values: []const KnownValue,
) Allocator.Error![]const DemandedKnownIndexedValue {
    const indexed = try arena.alloc(DemandedKnownIndexedValue, values.len);
    for (values, indexed, 0..) |known_value, *out, index| {
        out.* = .{
            .index = @intCast(index),
            .known_value = try materializedDemandedKnownValue(arena, known_value),
        };
    }
    return indexed;
}

fn demandedKnownCapturesFromDemand(
    cloner: ?*Cloner,
    program: ?*const Ast.Program,
    arena: Allocator,
    fn_id: Ast.FnId,
    captures: []const KnownValue,
    demand: CallableDemand,
) LowerError![]const DemandedKnownIndexedValue {
    var demanded = std.ArrayList(DemandedKnownIndexedValue).empty;
    defer demanded.deinit(arena);
    for (demand.captures, 0..) |capture_demand, index| {
        if (capture_demand == .none) continue;
        const demanded_capture = if (index < captures.len)
            (try demandedKnownValueFromDemand(cloner, program, arena, captures[index], capture_demand)) orelse DemandedKnownValue{ .any = known_valueType(captures[index]) }
        else blk: {
            const program_ref = program orelse Common.invariant("missing callable capture demand had no program for source capture type");
            const source_fn = program_ref.fns.items[@intFromEnum(fn_id)];
            const source_captures = program_ref.typedLocalSpan(source_fn.captures);
            if (index >= source_captures.len) Common.invariant("callable demand capture index exceeded lifted function capture count");
            break :blk DemandedKnownValue{ .any = source_captures[index].ty };
        };
        try demanded.append(arena, .{
            .index = @intCast(index),
            .known_value = demanded_capture,
        });
    }
    return try arena.dupe(DemandedKnownIndexedValue, demanded.items);
}

fn demandedKnownValuesContainFiniteState(known_values: []const DemandedKnownValue) bool {
    for (known_values) |known_value| {
        if (demandedKnownValueContainsFiniteState(known_value)) return true;
    }
    return false;
}

fn demandedKnownValueHasStructure(known_value: DemandedKnownValue) bool {
    return switch (known_value) {
        .any,
        .leaf,
        => false,
        .tag,
        .record,
        .tuple,
        .nominal,
        .callable,
        .finite_tags,
        .finite_callables,
        .compact_finite_tags,
        .compact_finite_callables,
        => true,
    };
}

fn valueDemandsRequirePrivateState(demands: []const ValueDemand) bool {
    for (demands) |demand| {
        if (valueDemandRequiresPrivateState(demand)) return true;
    }
    return false;
}

fn valueDemandRequiresPrivateState(demand: ValueDemand) bool {
    return switch (demand) {
        .none,
        .materialize,
        => false,
        .loop_param,
        .fn_param,
        .record,
        .tuple,
        .tag,
        .nominal,
        .callable,
        => true,
    };
}

fn demandedKnownValueContainsFiniteState(known_value: DemandedKnownValue) bool {
    return switch (known_value) {
        .any,
        .leaf,
        => false,
        .tag => |tag| blk: {
            for (tag.payloads) |payload| {
                if (demandedKnownValueContainsFiniteState(payload.known_value)) break :blk true;
            }
            break :blk false;
        },
        .record => |record| blk: {
            for (record.fields) |field| {
                if (demandedKnownValueContainsFiniteState(field.known_value)) break :blk true;
            }
            break :blk false;
        },
        .tuple => |tuple| blk: {
            for (tuple.items) |item| {
                if (demandedKnownValueContainsFiniteState(item.known_value)) break :blk true;
            }
            break :blk false;
        },
        .nominal => |nominal| if (nominal.backing) |backing| demandedKnownValueContainsFiniteState(backing.*) else false,
        .callable => |callable| blk: {
            for (callable.captures) |capture| {
                if (demandedKnownValueContainsFiniteState(capture.known_value)) break :blk true;
            }
            break :blk false;
        },
        .finite_tags,
        .finite_callables,
        .compact_finite_tags,
        .compact_finite_callables,
        => true,
    };
}

fn demandedKnownValueType(known_value: DemandedKnownValue) Type.TypeId {
    return switch (known_value) {
        .any => |ty| ty,
        .leaf => |ty| ty,
        .tag => |tag| tag.ty,
        .record => |record| record.ty,
        .tuple => |tuple| tuple.ty,
        .nominal => |nominal| nominal.ty,
        .callable => |callable| callable.ty,
        .finite_tags => |finite_tags| finite_tags.ty,
        .finite_callables => |finite_callables| finite_callables.ty,
        .compact_finite_tags => |finite_tags| finite_tags.ty,
        .compact_finite_callables => |finite_callables| finite_callables.ty,
    };
}

fn privateStateValueType(value: PrivateStateValue) Type.TypeId {
    return switch (value) {
        .leaf => |leaf| leaf.ty,
        .tag => |tag| tag.ty,
        .record => |record| record.ty,
        .tuple => |tuple| tuple.ty,
        .nominal => |nominal| nominal.ty,
        .callable => |callable| callable.ty,
        .compact_finite_tags => |finite_tags| finite_tags.source.ty,
        .compact_finite_callables => |finite_callables| finite_callables.source.ty,
    };
}

fn privateStateField(
    program: *const Ast.Program,
    value: PrivateStateValue,
    name: names.RecordFieldNameId,
) ?PrivateStateValue {
    return switch (value) {
        .record => |record| privateStateFieldByName(program, record.fields, name),
        .nominal => |nominal| if (nominal.backing) |backing| privateStateField(program, backing.*, name) else null,
        else => null,
    };
}

fn privateStateRecordIsDense(program: *const Ast.Program, record: PrivateStateRecord) bool {
    const type_fields = recordTypeFields(program, record.ty);
    if (type_fields.len != record.fields.len) return false;
    for (type_fields) |type_field| {
        _ = privateStateFieldByName(program, record.fields, type_field.name) orelse return false;
    }
    return true;
}

fn privateStateCanMaterializePublic(program: *const Ast.Program, value: PrivateStateValue) bool {
    return switch (value) {
        .leaf => true,
        .record => |record| blk: {
            const type_fields = recordTypeFields(program, record.ty);
            if (type_fields.len != record.fields.len) break :blk false;
            for (type_fields) |type_field| {
                const field = privateStateFieldByName(program, record.fields, type_field.name) orelse break :blk false;
                if (!sameType(program, type_field.ty, privateStateValueType(field))) break :blk false;
                if (!privateStateCanMaterializePublic(program, field)) break :blk false;
            }
            break :blk true;
        },
        .tuple => |tuple| blk: {
            const type_items = tupleTypeItems(program, tuple.ty);
            if (!privateStateIndexedValuesAreDense(tuple.items, type_items.len)) break :blk false;
            for (type_items, 0..) |item_ty, index| {
                const item = privateStateIndexedValueByIndex(tuple.items, @intCast(index)) orelse break :blk false;
                if (!sameType(program, item_ty, privateStateValueType(item))) break :blk false;
                if (!privateStateCanMaterializePublic(program, item)) break :blk false;
            }
            break :blk true;
        },
        .tag => |tag| privateStateTagCanMaterializePublic(program, tag),
        .nominal => |nominal| blk: {
            const backing = nominal.backing orelse break :blk false;
            const backing_ty = nominalBackingType(program, nominal.ty) orelse break :blk false;
            if (!sameType(program, backing_ty, privateStateValueType(backing.*))) break :blk false;
            break :blk privateStateCanMaterializePublic(program, backing.*);
        },
        .callable => |callable| privateStateCallableCanMaterializePublic(program, callable),
        .compact_finite_tags,
        .compact_finite_callables,
        => false,
    };
}

fn privateStateTagCanMaterializePublic(program: *const Ast.Program, tag: PrivateStateTag) bool {
    const payload_tys = tagTypePayloads(program, tag.ty, tag.name) orelse return false;
    if (!privateStateIndexedValuesAreDense(tag.payloads, payload_tys.len)) return false;
    for (payload_tys, 0..) |payload_ty, index| {
        const payload = privateStateIndexedValueByIndex(tag.payloads, @intCast(index)) orelse return false;
        if (!sameType(program, payload_ty, privateStateValueType(payload))) return false;
        if (!privateStateCanMaterializePublic(program, payload)) return false;
    }
    return true;
}

fn privateStateCallableCanMaterializePublic(program: *const Ast.Program, callable: PrivateStateCallable) bool {
    const source_fn = program.fns.items[@intFromEnum(callable.fn_id)];
    const source_captures = program.typedLocalSpan(source_fn.captures);
    if (!privateStateIndexedValuesAreDense(callable.captures, source_captures.len)) return false;
    for (source_captures, 0..) |source_capture, index| {
        const capture = privateStateIndexedValueByIndex(callable.captures, @intCast(index)) orelse return false;
        if (!sameType(program, source_capture.ty, privateStateValueType(capture))) return false;
        if (!privateStateCanMaterializePublic(program, capture)) return false;
    }
    return true;
}

fn privateStateIndexedValuesAreDense(indexed: []const PrivateStateIndexedValue, expected_len: usize) bool {
    if (indexed.len != expected_len) return false;
    var index: usize = 0;
    while (index < expected_len) : (index += 1) {
        _ = privateStateIndexedValueByIndex(indexed, @intCast(index)) orelse return false;
    }
    return true;
}

fn recordTypeFields(program: *const Ast.Program, ty: Type.TypeId) []const Type.Field {
    return switch (program.types.get(ty)) {
        .record => |fields| program.types.fieldSpan(fields),
        .named => |named| if (named.backing) |backing| recordTypeFields(program, backing.ty) else Common.invariant("named record has no backing"),
        else => Common.invariant("record operation expected record type"),
    };
}

fn recordFieldType(program: *const Ast.Program, ty: Type.TypeId, name: names.RecordFieldNameId) ?Type.TypeId {
    const fields = switch (program.types.get(ty)) {
        .record => |fields| program.types.fieldSpan(fields),
        .named => |named| if (named.backing) |backing| recordTypeFields(program, backing.ty) else return null,
        else => return null,
    };
    for (fields) |field| {
        if (program.names.recordFieldLabelTextEql(field.name, name)) return field.ty;
    }
    return null;
}

fn tupleTypeItems(program: *const Ast.Program, ty: Type.TypeId) []const Type.TypeId {
    return switch (program.types.get(ty)) {
        .tuple => |items| program.types.span(items),
        .named => |named| if (named.backing) |backing| tupleTypeItems(program, backing.ty) else Common.invariant("named tuple has no backing"),
        else => Common.invariant("tuple operation expected tuple type"),
    };
}

fn tupleItemType(program: *const Ast.Program, ty: Type.TypeId, index: u32) ?Type.TypeId {
    const items = switch (program.types.get(ty)) {
        .tuple => |items| program.types.span(items),
        .named => |named| if (named.backing) |backing| tupleTypeItems(program, backing.ty) else return null,
        else => return null,
    };
    if (index >= items.len) return null;
    return items[index];
}

fn tagUnionTypeTags(program: *const Ast.Program, ty: Type.TypeId) ?[]const Type.Tag {
    return switch (program.types.get(ty)) {
        .tag_union => |tags| program.types.tagSpan(tags),
        .named => |named| if (named.backing) |backing| tagUnionTypeTags(program, backing.ty) else return null,
        else => return null,
    };
}

fn checkedTagNameForDemandedTag(program: *const Ast.Program, ty: Type.TypeId, name: names.TagNameId) names.TagNameId {
    const tags = tagUnionTypeTags(program, ty) orelse
        Common.invariant("demanded finite tag had no source tag union type");
    for (tags) |tag| {
        if (program.names.tagLabelTextEql(tag.name, name)) return tag.checked_name;
    }
    Common.invariant("demanded finite tag referenced a tag absent from its source type");
}

fn tagTypePayloads(program: *const Ast.Program, ty: Type.TypeId, name: names.TagNameId) ?[]const Type.TypeId {
    return switch (program.types.get(ty)) {
        .tag_union => |tags| blk: {
            for (program.types.tagSpan(tags)) |tag| {
                if (tag.name == name) break :blk program.types.span(tag.payloads);
            }
            break :blk null;
        },
        .named => |named| if (named.backing) |backing| tagTypePayloads(program, backing.ty, name) else Common.invariant("named tag union has no backing"),
        else => Common.invariant("tag operation expected tag union type"),
    };
}

fn nominalBackingType(program: *const Ast.Program, ty: Type.TypeId) ?Type.TypeId {
    return switch (program.types.get(ty)) {
        .named => |named| if (named.backing) |backing| backing.ty else null,
        else => null,
    };
}

fn privateStateLeafExpr(value: PrivateStateValue) ?Ast.ExprId {
    return switch (value) {
        .leaf => |leaf| leaf.expr,
        else => null,
    };
}

fn privateStateLeafMatchesZeroPayloadSingleTag(
    program: *const Ast.Program,
    value: PrivateStateValue,
    name: names.TagNameId,
    pattern_payload_count: usize,
) bool {
    if (pattern_payload_count != 0) return false;
    if (privateStateLeafExpr(value) == null) return false;
    const tags = tagUnionTypeTags(program, privateStateValueType(value)) orelse return false;
    if (tags.len != 1) return false;
    const tag = tags[0];
    if (tag.name != name) return false;
    return program.types.span(tag.payloads).len == 0;
}

fn privateStateItem(value: PrivateStateValue, index: u32) ?PrivateStateValue {
    return switch (value) {
        .tuple => |tuple| privateStateIndexedValueByIndex(tuple.items, index),
        .nominal => |nominal| if (nominal.backing) |backing| privateStateItem(backing.*, index) else null,
        else => null,
    };
}

fn privateStateTagPayload(value: PrivateStateValue, index: u32) ?PrivateStateValue {
    return switch (value) {
        .tag => |tag| privateStateIndexedValueByIndex(tag.payloads, index),
        .nominal => |nominal| if (nominal.backing) |backing| privateStateTagPayload(backing.*, index) else null,
        else => null,
    };
}

fn privateStateTag(value: PrivateStateValue) ?PrivateStateTag {
    return switch (value) {
        .tag => |tag| tag,
        .nominal => |nominal| if (nominal.backing) |backing| privateStateTag(backing.*) else null,
        else => null,
    };
}

fn privateStateCallableCapture(value: PrivateStateValue, index: u32) ?PrivateStateValue {
    return switch (value) {
        .callable => |callable| privateStateIndexedValueByIndex(callable.captures, index),
        .nominal => |nominal| if (nominal.backing) |backing| privateStateCallableCapture(backing.*, index) else null,
        else => null,
    };
}

fn privateStateCallable(value: PrivateStateValue) ?PrivateStateCallable {
    return switch (value) {
        .callable => |callable| callable,
        .nominal => |nominal| if (nominal.backing) |backing| privateStateCallable(backing.*) else null,
        else => null,
    };
}

fn privateStateFieldByName(
    program: *const Ast.Program,
    fields: []const PrivateStateField,
    name: names.RecordFieldNameId,
) ?PrivateStateValue {
    for (fields) |field| {
        if (program.names.recordFieldLabelTextEql(field.name, name)) return field.value;
    }
    return null;
}

fn fieldValueByName(
    program: *const Ast.Program,
    fields: []const FieldValue,
    name: names.RecordFieldNameId,
) ?Value {
    for (fields) |field| {
        if (program.names.recordFieldLabelTextEql(field.name, name)) return field.value;
    }
    return null;
}

fn privateStateIndexedValueByIndex(items: []const PrivateStateIndexedValue, index: u32) ?PrivateStateValue {
    for (items) |item| {
        if (item.index == index) return item.value;
    }
    return null;
}

fn demandedKnownValuePrivateStateParamCount(known_value: DemandedKnownValue) usize {
    return switch (known_value) {
        .any,
        .leaf,
        => 1,
        .tag => |tag| demandedKnownIndexedValuesPrivateStateParamCount(tag.payloads),
        .record => |record| blk: {
            var count: usize = 0;
            for (record.fields) |field| {
                count += demandedKnownValuePrivateStateParamCount(field.known_value);
            }
            break :blk count;
        },
        .tuple => |tuple| demandedKnownIndexedValuesPrivateStateParamCount(tuple.items),
        .nominal => |nominal| if (nominal.backing) |backing| demandedKnownValuePrivateStateParamCount(backing.*) else 0,
        .callable => |callable| demandedKnownIndexedValuesPrivateStateParamCount(callable.captures),
        .finite_tags => |finite_tags| blk: {
            var max_count: usize = 0;
            for (finite_tags.alternatives) |alternative| {
                max_count = @max(max_count, demandedKnownIndexedValuesPrivateStateParamCount(alternative.payloads));
            }
            break :blk max_count;
        },
        .finite_callables => |finite_callables| blk: {
            var max_count: usize = 0;
            for (finite_callables.alternatives) |alternative| {
                max_count = @max(max_count, demandedKnownIndexedValuesPrivateStateParamCount(alternative.captures));
            }
            break :blk max_count;
        },
        .compact_finite_tags,
        .compact_finite_callables,
        => 1,
    };
}

fn demandedKnownIndexedValuesPrivateStateParamCount(values: []const DemandedKnownIndexedValue) usize {
    var count: usize = 0;
    for (values) |value| {
        count += demandedKnownValuePrivateStateParamCount(value.known_value);
    }
    return count;
}

fn demandedKnownValueEql(program: *const Ast.Program, lhs: DemandedKnownValue, rhs: DemandedKnownValue) bool {
    if (std.meta.activeTag(lhs) != std.meta.activeTag(rhs)) return false;
    return switch (lhs) {
        .any => |lhs_ty| sameType(program, lhs_ty, rhs.any),
        .leaf => |lhs_ty| sameType(program, lhs_ty, rhs.leaf),
        .tag => |lhs_tag| demandedKnownTagEql(program, lhs_tag, rhs.tag),
        .record => |lhs_record| blk: {
            const rhs_record = rhs.record;
            if (!sameType(program, lhs_record.ty, rhs_record.ty) or lhs_record.fields.len != rhs_record.fields.len) break :blk false;
            for (lhs_record.fields) |lhs_field| {
                const rhs_field = demandedKnownFieldByName(rhs_record.fields, lhs_field.name) orelse break :blk false;
                if (!demandedKnownValueEql(program, lhs_field.known_value, rhs_field.known_value)) break :blk false;
            }
            break :blk true;
        },
        .tuple => |lhs_tuple| blk: {
            const rhs_tuple = rhs.tuple;
            if (!sameType(program, lhs_tuple.ty, rhs_tuple.ty) or lhs_tuple.items.len != rhs_tuple.items.len) break :blk false;
            for (lhs_tuple.items) |lhs_item| {
                const rhs_item = demandedKnownIndexedValueByIndex(rhs_tuple.items, lhs_item.index) orelse break :blk false;
                if (!demandedKnownValueEql(program, lhs_item.known_value, rhs_item.known_value)) break :blk false;
            }
            break :blk true;
        },
        .nominal => |lhs_nominal| blk: {
            const rhs_nominal = rhs.nominal;
            if (!sameType(program, lhs_nominal.ty, rhs_nominal.ty)) break :blk false;
            if (lhs_nominal.backing == null or rhs_nominal.backing == null) break :blk lhs_nominal.backing == null and rhs_nominal.backing == null;
            break :blk demandedKnownValueEql(program, lhs_nominal.backing.?.*, rhs_nominal.backing.?.*);
        },
        .callable => |lhs_callable| demandedKnownCallableEql(program, lhs_callable, rhs.callable),
        .finite_tags => |lhs_finite| blk: {
            const rhs_finite = rhs.finite_tags;
            if (!sameType(program, lhs_finite.ty, rhs_finite.ty) or lhs_finite.alternatives.len != rhs_finite.alternatives.len) break :blk false;
            for (lhs_finite.alternatives) |lhs_alternative| {
                for (rhs_finite.alternatives) |rhs_alternative| {
                    if (demandedKnownTagEql(program, lhs_alternative, rhs_alternative)) break;
                } else {
                    break :blk false;
                }
            }
            break :blk true;
        },
        .finite_callables => |lhs_finite| blk: {
            const rhs_finite = rhs.finite_callables;
            if (!sameType(program, lhs_finite.ty, rhs_finite.ty) or lhs_finite.alternatives.len != rhs_finite.alternatives.len) break :blk false;
            for (lhs_finite.alternatives) |lhs_alternative| {
                for (rhs_finite.alternatives) |rhs_alternative| {
                    if (demandedKnownCallableEql(program, lhs_alternative, rhs_alternative)) break;
                } else {
                    break :blk false;
                }
            }
            break :blk true;
        },
        .compact_finite_tags => |lhs_finite| blk: {
            const rhs_finite = rhs.compact_finite_tags;
            if (!sameType(program, lhs_finite.ty, rhs_finite.ty) or lhs_finite.alternatives.len != rhs_finite.alternatives.len) break :blk false;
            for (lhs_finite.alternatives) |lhs_alternative| {
                for (rhs_finite.alternatives) |rhs_alternative| {
                    if (demandedKnownTagEql(program, lhs_alternative, rhs_alternative)) break;
                } else {
                    break :blk false;
                }
            }
            break :blk true;
        },
        .compact_finite_callables => |lhs_finite| blk: {
            const rhs_finite = rhs.compact_finite_callables;
            if (!sameType(program, lhs_finite.ty, rhs_finite.ty) or lhs_finite.alternatives.len != rhs_finite.alternatives.len) break :blk false;
            for (lhs_finite.alternatives) |lhs_alternative| {
                for (rhs_finite.alternatives) |rhs_alternative| {
                    if (demandedKnownCallableEql(program, lhs_alternative, rhs_alternative)) break;
                } else {
                    break :blk false;
                }
            }
            break :blk true;
        },
    };
}

fn demandedKnownTagEql(program: *const Ast.Program, lhs: DemandedKnownTag, rhs: DemandedKnownTag) bool {
    if (!sameType(program, lhs.ty, rhs.ty) or lhs.name != rhs.name or lhs.payloads.len != rhs.payloads.len) return false;
    for (lhs.payloads) |lhs_payload| {
        const rhs_payload = demandedKnownIndexedValueByIndex(rhs.payloads, lhs_payload.index) orelse return false;
        if (!demandedKnownValueEql(program, lhs_payload.known_value, rhs_payload.known_value)) return false;
    }
    return true;
}

fn demandedKnownCallableEql(program: *const Ast.Program, lhs: DemandedKnownCallable, rhs: DemandedKnownCallable) bool {
    if (!sameType(program, lhs.ty, rhs.ty) or
        lhs.fn_id != rhs.fn_id or
        lhs.captures.len != rhs.captures.len)
    {
        return false;
    }
    for (lhs.captures) |lhs_capture| {
        const rhs_capture = demandedKnownIndexedValueByIndex(rhs.captures, lhs_capture.index) orelse return false;
        if (!demandedKnownValueEql(program, lhs_capture.known_value, rhs_capture.known_value)) return false;
    }
    return true;
}

fn demandedKnownFieldByName(fields: []const DemandedKnownField, name: names.RecordFieldNameId) ?DemandedKnownField {
    for (fields) |field| {
        if (field.name == name) return field;
    }
    return null;
}

fn demandedKnownIndexedValueByIndex(items: []const DemandedKnownIndexedValue, index: u32) ?DemandedKnownIndexedValue {
    for (items) |item| {
        if (item.index == index) return item;
    }
    return null;
}

fn demandedKnownValueProducts(
    scratch: Allocator,
    arena: Allocator,
    known_values: []const DemandedKnownValue,
) Allocator.Error![]const []const DemandedKnownValue {
    const options = try scratch.alloc([]const DemandedKnownValue, known_values.len);
    defer scratch.free(options);
    for (known_values, 0..) |known_value, index| {
        options[index] = try expandDemandedKnownValue(scratch, arena, known_value);
    }

    var products = std.ArrayList([]const DemandedKnownValue).empty;
    defer products.deinit(scratch);
    const current = try scratch.alloc(DemandedKnownValue, known_values.len);
    defer scratch.free(current);

    try appendDemandedKnownValueProducts(scratch, arena, options, 0, current, &products);
    return try arena.dupe([]const DemandedKnownValue, products.items);
}

fn appendDemandedKnownValueProducts(
    scratch: Allocator,
    arena: Allocator,
    options: []const []const DemandedKnownValue,
    index: usize,
    current: []DemandedKnownValue,
    products: *std.ArrayList([]const DemandedKnownValue),
) Allocator.Error!void {
    if (index == options.len) {
        try products.append(scratch, try arena.dupe(DemandedKnownValue, current));
        return;
    }

    for (options[index]) |option| {
        current[index] = option;
        try appendDemandedKnownValueProducts(scratch, arena, options, index + 1, current, products);
    }
}

fn expandDemandedKnownValue(
    scratch: Allocator,
    arena: Allocator,
    known_value: DemandedKnownValue,
) Allocator.Error![]const DemandedKnownValue {
    return switch (known_value) {
        .any,
        .leaf,
        => try singleDemandedKnownValue(arena, known_value),
        .tag => |tag| try expandDemandedKnownTag(scratch, arena, tag),
        .record => |record| try expandDemandedKnownRecord(scratch, arena, record),
        .tuple => |tuple| try expandDemandedKnownTuple(scratch, arena, tuple),
        .nominal => |nominal| try expandDemandedKnownNominal(scratch, arena, nominal),
        .callable => |callable| try expandDemandedKnownCallable(scratch, arena, callable),
        .finite_tags => |finite_tags| try expandDemandedKnownTags(scratch, arena, finite_tags),
        .finite_callables => |finite_callables| try expandDemandedKnownCallables(scratch, arena, finite_callables),
        .compact_finite_tags,
        .compact_finite_callables,
        => try singleDemandedKnownValue(arena, known_value),
    };
}

fn singleDemandedKnownValue(arena: Allocator, known_value: DemandedKnownValue) Allocator.Error![]const DemandedKnownValue {
    const values = try arena.alloc(DemandedKnownValue, 1);
    values[0] = known_value;
    return values;
}

fn expandDemandedKnownRecord(
    scratch: Allocator,
    arena: Allocator,
    record: DemandedKnownRecord,
) Allocator.Error![]const DemandedKnownValue {
    const child_values = try scratch.alloc(DemandedKnownValue, record.fields.len);
    defer scratch.free(child_values);
    for (record.fields, 0..) |field, index| {
        child_values[index] = field.known_value;
    }

    const products = try demandedKnownValueProducts(scratch, arena, child_values);
    const alternatives = try arena.alloc(DemandedKnownValue, products.len);
    for (products, alternatives) |product, *out| {
        const fields = try arena.alloc(DemandedKnownField, record.fields.len);
        for (record.fields, product, fields) |field, field_known_value, *field_out| {
            field_out.* = .{
                .name = field.name,
                .known_value = field_known_value,
            };
        }
        out.* = .{ .record = .{
            .ty = record.ty,
            .fields = fields,
        } };
    }
    return alternatives;
}

fn expandDemandedKnownTuple(
    scratch: Allocator,
    arena: Allocator,
    tuple: DemandedKnownTuple,
) Allocator.Error![]const DemandedKnownValue {
    const alternatives = try expandDemandedKnownIndexedValues(scratch, arena, tuple.items);
    const values = try arena.alloc(DemandedKnownValue, alternatives.len);
    for (alternatives, values) |items, *out| {
        out.* = .{ .tuple = .{
            .ty = tuple.ty,
            .items = items,
        } };
    }
    return values;
}

fn expandDemandedKnownNominal(
    scratch: Allocator,
    arena: Allocator,
    nominal: DemandedKnownNominal,
) Allocator.Error![]const DemandedKnownValue {
    const backing = nominal.backing orelse return try singleDemandedKnownValue(arena, .{ .nominal = nominal });
    const backing_alternatives = try expandDemandedKnownValue(scratch, arena, backing.*);
    const alternatives = try arena.alloc(DemandedKnownValue, backing_alternatives.len);
    for (backing_alternatives, alternatives) |backing_alternative, *out| {
        const stored = try arena.create(DemandedKnownValue);
        stored.* = backing_alternative;
        out.* = .{ .nominal = .{
            .ty = nominal.ty,
            .backing = stored,
        } };
    }
    return alternatives;
}

fn expandDemandedKnownTag(
    scratch: Allocator,
    arena: Allocator,
    tag: DemandedKnownTag,
) Allocator.Error![]const DemandedKnownValue {
    const alternatives = try expandDemandedKnownIndexedValues(scratch, arena, tag.payloads);
    const values = try arena.alloc(DemandedKnownValue, alternatives.len);
    for (alternatives, values) |payloads, *out| {
        out.* = .{ .tag = .{
            .ty = tag.ty,
            .name = tag.name,
            .payloads = payloads,
        } };
    }
    return values;
}

fn expandDemandedKnownCallable(
    scratch: Allocator,
    arena: Allocator,
    callable: DemandedKnownCallable,
) Allocator.Error![]const DemandedKnownValue {
    const alternatives = try expandDemandedKnownIndexedValues(scratch, arena, callable.captures);
    const values = try arena.alloc(DemandedKnownValue, alternatives.len);
    for (alternatives, values) |captures, *out| {
        out.* = .{ .callable = .{
            .ty = callable.ty,
            .fn_id = callable.fn_id,
            .captures = captures,
        } };
    }
    return values;
}

fn expandDemandedKnownTags(
    scratch: Allocator,
    arena: Allocator,
    finite_tags: DemandedKnownTags,
) Allocator.Error![]const DemandedKnownValue {
    var alternatives = std.ArrayList(DemandedKnownValue).empty;
    defer alternatives.deinit(scratch);

    for (finite_tags.alternatives) |alternative| {
        const expanded = try expandDemandedKnownTag(scratch, arena, alternative);
        try alternatives.appendSlice(scratch, expanded);
    }

    return try arena.dupe(DemandedKnownValue, alternatives.items);
}

fn expandDemandedKnownCallables(
    scratch: Allocator,
    arena: Allocator,
    finite_callables: DemandedKnownCallables,
) Allocator.Error![]const DemandedKnownValue {
    var alternatives = std.ArrayList(DemandedKnownValue).empty;
    defer alternatives.deinit(scratch);

    for (finite_callables.alternatives) |alternative| {
        const expanded = try expandDemandedKnownCallable(scratch, arena, alternative);
        try alternatives.appendSlice(scratch, expanded);
    }

    return try arena.dupe(DemandedKnownValue, alternatives.items);
}

fn expandDemandedKnownIndexedValues(
    scratch: Allocator,
    arena: Allocator,
    indexed: []const DemandedKnownIndexedValue,
) Allocator.Error![]const []const DemandedKnownIndexedValue {
    const child_values = try scratch.alloc(DemandedKnownValue, indexed.len);
    defer scratch.free(child_values);
    for (indexed, 0..) |child, index| {
        child_values[index] = child.known_value;
    }

    const products = try demandedKnownValueProducts(scratch, arena, child_values);
    const alternatives = try arena.alloc([]const DemandedKnownIndexedValue, products.len);
    for (products, alternatives) |product, *out| {
        const values = try arena.alloc(DemandedKnownIndexedValue, indexed.len);
        for (indexed, product, values) |child, child_known_value, *value_out| {
            value_out.* = .{
                .index = child.index,
                .known_value = child_known_value,
            };
        }
        out.* = values;
    }
    return alternatives;
}

fn known_valueEql(program: *const Ast.Program, lhs: KnownValue, rhs: KnownValue) bool {
    if (std.meta.activeTag(lhs) != std.meta.activeTag(rhs)) return false;
    return switch (lhs) {
        .any => |lhs_ty| sameType(program, lhs_ty, rhs.any),
        .leaf => |lhs_ty| sameType(program, lhs_ty, rhs.leaf),
        .tag => |lhs_tag| blk: {
            const rhs_tag = rhs.tag;
            if (!sameType(program, lhs_tag.ty, rhs_tag.ty) or lhs_tag.name != rhs_tag.name or lhs_tag.payloads.len != rhs_tag.payloads.len) break :blk false;
            for (lhs_tag.payloads, rhs_tag.payloads) |lhs_payload, rhs_payload| {
                if (!known_valueEql(program, lhs_payload, rhs_payload)) break :blk false;
            }
            break :blk true;
        },
        .record => |lhs_record| blk: {
            const rhs_record = rhs.record;
            if (!sameType(program, lhs_record.ty, rhs_record.ty) or lhs_record.fields.len != rhs_record.fields.len) break :blk false;
            for (lhs_record.fields, rhs_record.fields) |lhs_field, rhs_field| {
                if (lhs_field.name != rhs_field.name or !known_valueEql(program, lhs_field.known_value, rhs_field.known_value)) break :blk false;
            }
            break :blk true;
        },
        .tuple => |lhs_tuple| blk: {
            const rhs_tuple = rhs.tuple;
            if (!sameType(program, lhs_tuple.ty, rhs_tuple.ty) or lhs_tuple.items.len != rhs_tuple.items.len) break :blk false;
            for (lhs_tuple.items, rhs_tuple.items) |lhs_item, rhs_item| {
                if (!known_valueEql(program, lhs_item, rhs_item)) break :blk false;
            }
            break :blk true;
        },
        .nominal => |lhs_nominal| {
            const rhs_nominal = rhs.nominal;
            return sameType(program, lhs_nominal.ty, rhs_nominal.ty) and known_valueEql(program, lhs_nominal.backing.*, rhs_nominal.backing.*);
        },
        .callable => |lhs_callable| blk: {
            const rhs_callable = rhs.callable;
            if (!sameType(program, lhs_callable.ty, rhs_callable.ty) or
                !callableTargetMatches(program, lhs_callable.fn_id, rhs_callable.fn_id) or
                lhs_callable.captures.len != rhs_callable.captures.len)
            {
                break :blk false;
            }
            for (lhs_callable.captures, rhs_callable.captures) |lhs_capture, rhs_capture| {
                if (!known_valueEql(program, lhs_capture, rhs_capture)) break :blk false;
            }
            break :blk true;
        },
        .finite_tags => |lhs_finite| knownTagsEql(program, lhs_finite, rhs.finite_tags),
        .finite_callables => |lhs_finite| knownCallablesEql(program, lhs_finite, rhs.finite_callables),
    };
}

fn demandedKnownValuesMatchValues(program: *const Ast.Program, known_values: []const DemandedKnownValue, values: []const Value) bool {
    if (known_values.len != values.len) return false;
    for (known_values, values) |known_value, value| {
        if (!demandedKnownValueMatchesValue(program, known_value, value)) return false;
    }
    return true;
}

fn demandedKnownValuesEql(program: *const Ast.Program, lhs: []const DemandedKnownValue, rhs: []const DemandedKnownValue) bool {
    if (lhs.len != rhs.len) return false;
    for (lhs, rhs) |lhs_value, rhs_value| {
        if (!demandedKnownValueEql(program, lhs_value, rhs_value)) return false;
    }
    return true;
}

fn demandedKnownValueMatchesValue(program: *const Ast.Program, known_value: DemandedKnownValue, value: Value) bool {
    if (value == .private_state) return demandedKnownValueMatchesPrivateState(program, known_value, value.private_state);
    if (value == .let_) return demandedKnownValueMatchesValue(program, known_value, value.let_.body.*);
    if (value == .if_) {
        for (value.if_.branches) |branch| {
            if (!demandedKnownValueMatchesValue(program, known_value, branch.body)) return false;
        }
        return demandedKnownValueMatchesValue(program, known_value, value.if_.final_else.*);
    }
    if (value == .match_) {
        for (value.match_.branches) |branch| {
            if (!demandedKnownValueMatchesValue(program, known_value, branch.body)) return false;
        }
        return true;
    }
    if (value == .expr_with_known_value) {
        if (value.expr_with_known_value.value) |structured_value| {
            if (demandedKnownValueMatchesValue(program, known_value, structured_value.*)) return true;
        }
        return demandedKnownValueMatchesKnownValue(program, known_value, value.expr_with_known_value.known_value);
    }

    return switch (known_value) {
        .any => |ty| sameType(program, ty, valueType(program, value)),
        .leaf => |ty| sameType(program, ty, valueType(program, value)),
        .record => |record| blk: {
            const value_record = recordFromValue(value) orelse break :blk false;
            if (!sameType(program, record.ty, value_record.ty)) break :blk false;
            for (record.fields) |field| {
                const field_value = fieldFromRecord(program, value_record, field.name) orelse break :blk false;
                if (!demandedKnownValueMatchesValue(program, field.known_value, field_value)) break :blk false;
            }
            break :blk true;
        },
        .tuple => |tuple| blk: {
            const value_tuple = tupleFromValue(value) orelse break :blk false;
            if (!sameType(program, tuple.ty, value_tuple.ty)) break :blk false;
            for (tuple.items) |item| {
                if (item.index >= value_tuple.items.len) break :blk false;
                if (!demandedKnownValueMatchesValue(program, item.known_value, value_tuple.items[item.index])) break :blk false;
            }
            break :blk true;
        },
        .nominal => |nominal| blk: {
            const value_nominal = switch (value) {
                .nominal => |value_nominal| value_nominal,
                else => break :blk false,
            };
            if (!sameType(program, nominal.ty, value_nominal.ty)) break :blk false;
            const backing = nominal.backing orelse break :blk true;
            break :blk demandedKnownValueMatchesValue(program, backing.*, value_nominal.backing.*);
        },
        .tag => |tag| blk: {
            const value_tag = tagFromValue(value) orelse break :blk false;
            if (!sameType(program, tag.ty, value_tag.ty) or tag.name != value_tag.name) break :blk false;
            for (tag.payloads) |payload| {
                if (payload.index >= value_tag.payloads.len) break :blk false;
                if (!demandedKnownValueMatchesValue(program, payload.known_value, value_tag.payloads[payload.index])) break :blk false;
            }
            break :blk true;
        },
        .callable => |callable| blk: {
            const value_callable = switch (value) {
                .callable => |value_callable| value_callable,
                else => break :blk false,
            };
            if (!sameType(program, callable.ty, value_callable.ty) or
                !callableTargetMatches(program, callable.fn_id, value_callable.fn_id))
            {
                break :blk false;
            }
            for (callable.captures) |capture| {
                if (capture.index >= value_callable.captures.len) break :blk false;
                if (!demandedKnownValueMatchesValue(program, capture.known_value, value_callable.captures[capture.index])) break :blk false;
            }
            break :blk true;
        },
        .finite_tags => |finite_tags| blk: {
            for (finite_tags.alternatives) |alternative| {
                if (demandedKnownValueMatchesValue(program, .{ .tag = alternative }, value)) break :blk true;
            }
            break :blk false;
        },
        .finite_callables => |finite_callables| blk: {
            const value_callable = switch (value) {
                .callable => |callable| callable,
                else => break :blk false,
            };
            for (finite_callables.alternatives) |alternative| {
                if (demandedKnownCallableMatchesValueAlternative(program, alternative, value_callable)) break :blk true;
            }
            break :blk false;
        },
        .compact_finite_tags => |finite_tags| blk: {
            for (finite_tags.alternatives) |alternative| {
                if (demandedKnownValueMatchesValue(program, .{ .tag = alternative }, value)) break :blk true;
            }
            break :blk false;
        },
        .compact_finite_callables => |finite_callables| blk: {
            const value_callable = switch (value) {
                .callable => |callable| callable,
                else => break :blk false,
            };
            for (finite_callables.alternatives) |alternative| {
                if (demandedKnownCallableMatchesValueAlternative(program, alternative, value_callable)) break :blk true;
            }
            break :blk false;
        },
    };
}

fn demandedKnownValueMatchesKnownValue(program: *const Ast.Program, known_value: DemandedKnownValue, value: KnownValue) bool {
    return switch (known_value) {
        .any => |ty| sameType(program, ty, known_valueType(value)),
        .leaf => |ty| sameType(program, ty, known_valueType(value)),
        .record => |record| blk: {
            if (!sameType(program, record.ty, known_valueType(value))) break :blk false;
            for (record.fields) |field| {
                const field_value = fieldKnownValueFromKnownValue(program, value, field.name) orelse break :blk false;
                if (!demandedKnownValueMatchesKnownValue(program, field.known_value, field_value)) break :blk false;
            }
            break :blk true;
        },
        .tuple => |tuple| blk: {
            if (!sameType(program, tuple.ty, known_valueType(value))) break :blk false;
            for (tuple.items) |item| {
                const item_value = itemKnownValueFromKnownValue(value, item.index) orelse break :blk false;
                if (!demandedKnownValueMatchesKnownValue(program, item.known_value, item_value)) break :blk false;
            }
            break :blk true;
        },
        .nominal => |nominal| blk: {
            const value_nominal = switch (value) {
                .nominal => |value_nominal| value_nominal,
                else => break :blk false,
            };
            if (!sameType(program, nominal.ty, value_nominal.ty)) break :blk false;
            const backing = nominal.backing orelse break :blk true;
            break :blk demandedKnownValueMatchesKnownValue(program, backing.*, value_nominal.backing.*);
        },
        .tag => |tag| blk: {
            const value_tag = switch (value) {
                .tag => |value_tag| value_tag,
                else => break :blk false,
            };
            if (!sameType(program, tag.ty, value_tag.ty) or tag.name != value_tag.name) break :blk false;
            for (tag.payloads) |payload| {
                if (payload.index >= value_tag.payloads.len) break :blk false;
                if (!demandedKnownValueMatchesKnownValue(program, payload.known_value, value_tag.payloads[payload.index])) break :blk false;
            }
            break :blk true;
        },
        .callable => |callable| blk: {
            const value_callable = switch (value) {
                .callable => |value_callable| value_callable,
                else => break :blk false,
            };
            if (!sameType(program, callable.ty, value_callable.ty) or
                !callableTargetMatches(program, callable.fn_id, value_callable.fn_id))
            {
                break :blk false;
            }
            for (callable.captures) |capture| {
                if (capture.index >= value_callable.captures.len) break :blk false;
                if (!demandedKnownValueMatchesKnownValue(program, capture.known_value, value_callable.captures[capture.index])) break :blk false;
            }
            break :blk true;
        },
        .finite_tags => |finite_tags| blk: {
            for (finite_tags.alternatives) |alternative| {
                if (demandedKnownValueMatchesKnownValue(program, .{ .tag = alternative }, value)) break :blk true;
            }
            break :blk false;
        },
        .finite_callables => |finite_callables| blk: {
            const value_callable = switch (value) {
                .callable => |callable| callable,
                else => break :blk false,
            };
            for (finite_callables.alternatives) |alternative| {
                if (demandedKnownCallableMatchesKnownValueAlternative(program, alternative, value_callable)) break :blk true;
            }
            break :blk false;
        },
        .compact_finite_tags => |finite_tags| blk: {
            for (finite_tags.alternatives) |alternative| {
                if (demandedKnownValueMatchesKnownValue(program, .{ .tag = alternative }, value)) break :blk true;
            }
            break :blk false;
        },
        .compact_finite_callables => |finite_callables| blk: {
            const value_callable = switch (value) {
                .callable => |callable| callable,
                else => break :blk false,
            };
            for (finite_callables.alternatives) |alternative| {
                if (demandedKnownCallableMatchesKnownValueAlternative(program, alternative, value_callable)) break :blk true;
            }
            break :blk false;
        },
    };
}

fn demandedKnownValueMatchesPrivateState(program: *const Ast.Program, known_value: DemandedKnownValue, value: PrivateStateValue) bool {
    return switch (known_value) {
        .any => |ty| blk: {
            break :blk sameType(program, ty, privateStateValueType(value)) and privateStateCanMaterializePublic(program, value);
        },
        .leaf => |ty| blk: {
            break :blk sameType(program, ty, privateStateValueType(value)) and privateStateCanMaterializePublic(program, value);
        },
        .record => |record| blk: {
            if (!sameType(program, record.ty, privateStateValueType(value))) break :blk false;
            for (record.fields) |field| {
                const field_value = privateStateField(program, value, field.name) orelse break :blk false;
                if (!demandedKnownValueMatchesPrivateState(program, field.known_value, field_value)) break :blk false;
            }
            break :blk true;
        },
        .tuple => |tuple| blk: {
            if (!sameType(program, tuple.ty, privateStateValueType(value))) break :blk false;
            for (tuple.items) |item| {
                const item_value = privateStateItem(value, item.index) orelse break :blk false;
                if (!demandedKnownValueMatchesPrivateState(program, item.known_value, item_value)) break :blk false;
            }
            break :blk true;
        },
        .nominal => |nominal| blk: {
            const private_nominal = switch (value) {
                .nominal => |private_nominal| private_nominal,
                else => {
                    break :blk false;
                },
            };
            if (!sameType(program, nominal.ty, private_nominal.ty)) {
                break :blk false;
            }
            const backing = nominal.backing orelse break :blk true;
            const private_backing = private_nominal.backing orelse {
                break :blk false;
            };
            const matches = demandedKnownValueMatchesPrivateState(program, backing.*, private_backing.*);
            break :blk matches;
        },
        .tag => |tag| blk: {
            const private_tag = privateStateTag(value) orelse {
                break :blk false;
            };
            if (!sameType(program, tag.ty, private_tag.ty) or tag.name != private_tag.name) {
                break :blk false;
            }
            for (tag.payloads) |payload| {
                const payload_value = privateStateIndexedValueByIndex(private_tag.payloads, payload.index) orelse {
                    break :blk false;
                };
                if (!demandedKnownValueMatchesPrivateState(program, payload.known_value, payload_value)) {
                    break :blk false;
                }
            }
            break :blk true;
        },
        .callable => |callable| blk: {
            const private_callable = privateStateCallable(value) orelse break :blk false;
            if (!sameType(program, callable.ty, private_callable.ty) or
                !callableTargetMatches(program, callable.fn_id, private_callable.fn_id))
            {
                break :blk false;
            }
            for (callable.captures) |capture| {
                const capture_value = privateStateIndexedValueByIndex(private_callable.captures, capture.index) orelse break :blk false;
                if (!demandedKnownValueMatchesPrivateState(program, capture.known_value, capture_value)) break :blk false;
            }
            break :blk true;
        },
        .finite_tags => |finite_tags| blk: {
            for (finite_tags.alternatives) |alternative| {
                if (demandedKnownValueMatchesPrivateState(program, .{ .tag = alternative }, value)) break :blk true;
            }
            break :blk false;
        },
        .finite_callables => |finite_callables| blk: {
            const private_callable = privateStateCallable(value) orelse break :blk false;
            for (finite_callables.alternatives) |alternative| {
                if (demandedKnownCallableMatchesPrivateStateAlternative(program, alternative, private_callable)) break :blk true;
            }
            break :blk false;
        },
        .compact_finite_tags => |finite_tags| blk: {
            if (value == .compact_finite_tags and demandedKnownValueEql(program, .{ .finite_tags = finite_tags }, .{ .finite_tags = value.compact_finite_tags.source })) {
                break :blk true;
            }
            for (finite_tags.alternatives) |alternative| {
                if (demandedKnownValueMatchesPrivateState(program, .{ .tag = alternative }, value)) break :blk true;
            }
            break :blk false;
        },
        .compact_finite_callables => |finite_callables| blk: {
            if (value == .compact_finite_callables and demandedKnownValueEql(program, .{ .finite_callables = finite_callables }, .{ .finite_callables = value.compact_finite_callables.source })) {
                break :blk true;
            }
            const private_callable = privateStateCallable(value) orelse break :blk false;
            for (finite_callables.alternatives) |alternative| {
                if (demandedKnownCallableMatchesPrivateStateAlternative(program, alternative, private_callable)) break :blk true;
            }
            break :blk false;
        },
    };
}

fn demandedKnownCallableMatchesValueAlternative(
    program: *const Ast.Program,
    known_value: DemandedKnownCallable,
    value: CallableValue,
) bool {
    if (!sameType(program, known_value.ty, value.ty) or known_value.fn_id != value.fn_id) return false;
    for (known_value.captures) |capture| {
        if (capture.index >= value.captures.len) return false;
        if (!demandedKnownValueMatchesValue(program, capture.known_value, value.captures[capture.index])) return false;
    }
    return true;
}

fn demandedKnownCallableMatchesKnownValueAlternative(
    program: *const Ast.Program,
    known_value: DemandedKnownCallable,
    value: KnownCallable,
) bool {
    if (!sameType(program, known_value.ty, value.ty) or known_value.fn_id != value.fn_id) return false;
    for (known_value.captures) |capture| {
        if (capture.index >= value.captures.len) return false;
        if (!demandedKnownValueMatchesKnownValue(program, capture.known_value, value.captures[capture.index])) return false;
    }
    return true;
}

fn demandedKnownCallableMatchesPrivateStateAlternative(
    program: *const Ast.Program,
    known_value: DemandedKnownCallable,
    value: PrivateStateCallable,
) bool {
    if (!sameType(program, known_value.ty, value.ty) or known_value.fn_id != value.fn_id) return false;
    for (known_value.captures) |capture| {
        const capture_value = privateStateIndexedValueByIndex(value.captures, capture.index) orelse return false;
        if (!demandedKnownValueMatchesPrivateState(program, capture.known_value, capture_value)) return false;
    }
    return true;
}

fn knownValueMatchesValue(program: *const Ast.Program, known_value: KnownValue, value: Value) bool {
    if (value == .private_state) return knownValueMatchesPrivateState(program, known_value, value.private_state);

    if (value == .expr_with_known_value) {
        if (value.expr_with_known_value.value) |structured_value| {
            if (knownValueMatchesValue(program, known_value, structured_value.*)) return true;
        }
        if (known_value == .any) return sameType(program, known_value.any, valueType(program, value));
        if (known_value == .leaf) return sameType(program, known_value.leaf, valueType(program, value));
        if (!canReadFieldsFromExpr(program, value.expr_with_known_value.expr)) return false;
        return known_valueCanProjectFromExpr(known_value) and knownValueMatchesKnownValue(program, known_value, value.expr_with_known_value.known_value);
    }

    return switch (known_value) {
        .any => |ty| sameType(program, ty, valueType(program, value)),
        .leaf => |ty| sameType(program, ty, valueType(program, value)),
        .tag => |tag| blk: {
            const value_tag = switch (value) {
                .tag => |value_tag| value_tag,
                else => break :blk false,
            };
            if (!sameType(program, tag.ty, value_tag.ty) or tag.name != value_tag.name or tag.payloads.len != value_tag.payloads.len) break :blk false;
            for (tag.payloads, value_tag.payloads) |payload_known_value, payload_value| {
                if (!knownValueMatchesValue(program, payload_known_value, payload_value)) break :blk false;
            }
            break :blk true;
        },
        .record => |record| blk: {
            const value_record = switch (value) {
                .record => |value_record| value_record,
                else => break :blk false,
            };
            if (!sameType(program, record.ty, value_record.ty)) break :blk false;
            for (record.fields) |field_known_value| {
                const field_value = fieldFromRecord(program, value_record, field_known_value.name) orelse break :blk false;
                if (!knownValueMatchesValue(program, field_known_value.known_value, field_value)) break :blk false;
            }
            break :blk true;
        },
        .tuple => |tuple| blk: {
            const value_tuple = switch (value) {
                .tuple => |value_tuple| value_tuple,
                else => break :blk false,
            };
            if (!sameType(program, tuple.ty, value_tuple.ty) or tuple.items.len != value_tuple.items.len) break :blk false;
            for (tuple.items, value_tuple.items) |item_known_value, item_value| {
                if (!knownValueMatchesValue(program, item_known_value, item_value)) break :blk false;
            }
            break :blk true;
        },
        .nominal => |nominal| blk: {
            const value_nominal = switch (value) {
                .nominal => |value_nominal| value_nominal,
                else => break :blk false,
            };
            break :blk sameType(program, nominal.ty, value_nominal.ty) and knownValueMatchesValue(program, nominal.backing.*, value_nominal.backing.*);
        },
        .callable => |callable| blk: {
            const value_callable = switch (value) {
                .callable => |value_callable| value_callable,
                else => break :blk false,
            };
            if (!sameType(program, callable.ty, value_callable.ty) or
                !callableTargetMatches(program, callable.fn_id, value_callable.fn_id) or
                callable.captures.len != value_callable.captures.len)
            {
                break :blk false;
            }
            for (callable.captures, value_callable.captures) |capture_known_value, capture_value| {
                if (!knownValueMatchesValue(program, capture_known_value, capture_value)) break :blk false;
            }
            break :blk true;
        },
        .finite_tags => |finite_tags| blk: {
            switch (value) {
                .tag => |tag| break :blk finiteTagAlternativeIndex(program, finite_tags.alternatives, tag) != null,
                .finite_tags => |finite_value| break :blk knownTagsMatchesValue(program, finite_tags, finite_value),
                else => break :blk false,
            }
        },
        .finite_callables => |finite_callables| blk: {
            switch (value) {
                .callable => |callable| break :blk finiteCallableAlternativeIndex(program, finite_callables.alternatives, callable) != null,
                .finite_callables => |finite_value| break :blk knownCallablesMatchesValue(program, finite_callables, finite_value),
                else => break :blk false,
            }
        },
    };
}

fn knownValueMatchesPrivateState(program: *const Ast.Program, known_value: KnownValue, value: PrivateStateValue) bool {
    return switch (known_value) {
        .any => |ty| sameType(program, ty, privateStateValueType(value)) and privateStateCanMaterializePublic(program, value),
        .leaf => |ty| sameType(program, ty, privateStateValueType(value)) and privateStateCanMaterializePublic(program, value),
        .tag => |tag| blk: {
            const private_tag = privateStateTag(value) orelse break :blk false;
            if (!sameType(program, tag.ty, private_tag.ty) or tag.name != private_tag.name or tag.payloads.len != private_tag.payloads.len) break :blk false;
            for (tag.payloads, 0..) |payload_known_value, index| {
                const payload_value = privateStateIndexedValueByIndex(private_tag.payloads, @intCast(index)) orelse break :blk false;
                if (!knownValueMatchesPrivateState(program, payload_known_value, payload_value)) break :blk false;
            }
            break :blk true;
        },
        .record => |record| blk: {
            if (!sameType(program, record.ty, privateStateValueType(value))) break :blk false;
            for (record.fields) |field| {
                const field_value = privateStateField(program, value, field.name) orelse break :blk false;
                if (!knownValueMatchesPrivateState(program, field.known_value, field_value)) break :blk false;
            }
            break :blk true;
        },
        .tuple => |tuple| blk: {
            if (!sameType(program, tuple.ty, privateStateValueType(value))) break :blk false;
            for (tuple.items, 0..) |item_known_value, index| {
                const item_value = privateStateItem(value, @intCast(index)) orelse break :blk false;
                if (!knownValueMatchesPrivateState(program, item_known_value, item_value)) break :blk false;
            }
            break :blk true;
        },
        .nominal => |nominal| blk: {
            const private_nominal = switch (value) {
                .nominal => |private_nominal| private_nominal,
                else => break :blk false,
            };
            if (!sameType(program, nominal.ty, private_nominal.ty)) break :blk false;
            const backing = private_nominal.backing orelse break :blk false;
            break :blk knownValueMatchesPrivateState(program, nominal.backing.*, backing.*);
        },
        .callable => |callable| blk: {
            const private_callable = privateStateCallable(value) orelse break :blk false;
            if (!sameType(program, callable.ty, private_callable.ty) or
                !callableTargetMatches(program, callable.fn_id, private_callable.fn_id) or
                callable.captures.len != private_callable.captures.len)
            {
                break :blk false;
            }
            for (callable.captures, 0..) |capture_known_value, index| {
                const capture_value = privateStateIndexedValueByIndex(private_callable.captures, @intCast(index)) orelse break :blk false;
                if (!knownValueMatchesPrivateState(program, capture_known_value, capture_value)) break :blk false;
            }
            break :blk true;
        },
        .finite_tags,
        .finite_callables,
        => false,
    };
}

fn known_valueCanProjectFromExpr(known_value: KnownValue) bool {
    return switch (known_value) {
        .any => true,
        .leaf => true,
        .record => |record| blk: {
            for (record.fields) |field| {
                if (!known_valueCanProjectFromExpr(field.known_value)) break :blk false;
            }
            break :blk true;
        },
        .tuple => |tuple| blk: {
            for (tuple.items) |item| {
                if (!known_valueCanProjectFromExpr(item)) break :blk false;
            }
            break :blk true;
        },
        .nominal => |nominal| known_valueCanProjectFromExpr(nominal.backing.*),
        .tag,
        .callable,
        .finite_tags,
        .finite_callables,
        => false,
    };
}

fn knownValueMatchesKnownValue(program: *const Ast.Program, pattern: KnownValue, actual: KnownValue) bool {
    return switch (pattern) {
        .any => |ty| sameType(program, ty, known_valueType(actual)),
        .leaf => |ty| sameType(program, ty, known_valueType(actual)),
        .tag => |pattern_tag| blk: {
            const actual_tag = switch (actual) {
                .tag => |tag| tag,
                else => break :blk false,
            };
            if (!sameType(program, pattern_tag.ty, actual_tag.ty) or
                pattern_tag.name != actual_tag.name or
                pattern_tag.payloads.len != actual_tag.payloads.len)
            {
                break :blk false;
            }
            for (pattern_tag.payloads, actual_tag.payloads) |pattern_payload, actual_payload| {
                if (!knownValueMatchesKnownValue(program, pattern_payload, actual_payload)) break :blk false;
            }
            break :blk true;
        },
        .record => |pattern_record| blk: {
            const actual_record = switch (actual) {
                .record => |record| record,
                else => break :blk false,
            };
            if (!sameType(program, pattern_record.ty, actual_record.ty)) break :blk false;
            for (pattern_record.fields) |pattern_field| {
                const actual_field = fieldKnownValueFromKnownValue(program, actual, pattern_field.name) orelse break :blk false;
                if (!knownValueMatchesKnownValue(program, pattern_field.known_value, actual_field)) break :blk false;
            }
            break :blk true;
        },
        .tuple => |pattern_tuple| blk: {
            const actual_tuple = switch (actual) {
                .tuple => |tuple| tuple,
                else => break :blk false,
            };
            if (!sameType(program, pattern_tuple.ty, actual_tuple.ty) or pattern_tuple.items.len != actual_tuple.items.len) break :blk false;
            for (pattern_tuple.items, actual_tuple.items) |pattern_item, actual_item| {
                if (!knownValueMatchesKnownValue(program, pattern_item, actual_item)) break :blk false;
            }
            break :blk true;
        },
        .nominal => |pattern_nominal| blk: {
            const actual_nominal = switch (actual) {
                .nominal => |nominal| nominal,
                else => break :blk false,
            };
            break :blk sameType(program, pattern_nominal.ty, actual_nominal.ty) and
                knownValueMatchesKnownValue(program, pattern_nominal.backing.*, actual_nominal.backing.*);
        },
        .callable => |pattern_callable| blk: {
            const actual_callable = switch (actual) {
                .callable => |callable| callable,
                else => break :blk false,
            };
            if (!sameType(program, pattern_callable.ty, actual_callable.ty) or
                !callableTargetMatches(program, pattern_callable.fn_id, actual_callable.fn_id) or
                pattern_callable.captures.len != actual_callable.captures.len)
            {
                break :blk false;
            }
            for (pattern_callable.captures, actual_callable.captures) |pattern_capture, actual_capture| {
                if (!knownValueMatchesKnownValue(program, pattern_capture, actual_capture)) break :blk false;
            }
            break :blk true;
        },
        .finite_tags => |pattern_finite| blk: {
            const actual_finite = switch (actual) {
                .finite_tags => |finite_tags| finite_tags,
                .tag => |tag| {
                    break :blk finiteKnownTagContainsKnownTag(program, pattern_finite, tag);
                },
                else => break :blk false,
            };
            break :blk knownTagsContainsKnownValue(program, pattern_finite, actual_finite);
        },
        .finite_callables => |pattern_finite| blk: {
            const actual_finite = switch (actual) {
                .finite_callables => |finite_callables| finite_callables,
                .callable => |callable| {
                    break :blk finiteKnownCallableContainsKnownCallable(program, pattern_finite, callable);
                },
                else => break :blk false,
            };
            break :blk knownCallablesContainsKnownValue(program, pattern_finite, actual_finite);
        },
    };
}

fn commonKnownTags(
    program: *const Ast.Program,
    arena: Allocator,
    lhs: KnownValue,
    rhs: KnownValue,
) Allocator.Error!?KnownValue {
    const ty = known_valueType(lhs);
    var alternatives = std.ArrayList(KnownTag).empty;
    defer alternatives.deinit(arena);

    if (!try appendKnownTagAlternatives(program, arena, &alternatives, lhs)) return null;
    if (!try appendKnownTagAlternatives(program, arena, &alternatives, rhs)) return null;
    if (alternatives.items.len == 0) return null;
    if (alternatives.items.len == 1) return KnownValue{ .tag = alternatives.items[0] };

    const stored = try arena.dupe(KnownTag, alternatives.items);
    return KnownValue{ .finite_tags = .{
        .ty = ty,
        .alternatives = stored,
    } };
}

fn appendKnownTagAlternatives(
    program: *const Ast.Program,
    arena: Allocator,
    out: *std.ArrayList(KnownTag),
    known_value: KnownValue,
) Allocator.Error!bool {
    switch (known_value) {
        .tag => |tag| return try appendTagAlternative(program, arena, out, tag),
        .finite_tags => |finite_tags| {
            for (finite_tags.alternatives) |alternative| {
                if (!try appendTagAlternative(program, arena, out, alternative)) return false;
            }
            return true;
        },
        else => return false,
    }
}

fn appendTagAlternative(
    program: *const Ast.Program,
    arena: Allocator,
    out: *std.ArrayList(KnownTag),
    candidate: KnownTag,
) Allocator.Error!bool {
    for (out.items, 0..) |existing, index| {
        if (existing.name != candidate.name) continue;
        if (!sameType(program, existing.ty, candidate.ty)) return false;
        if (existing.payloads.len != candidate.payloads.len) return false;

        const payloads = try arena.alloc(KnownValue, existing.payloads.len);
        for (existing.payloads, candidate.payloads, payloads) |lhs_payload, rhs_payload, *payload_out| {
            payload_out.* = (try joinKnownValuesInArena(program, arena, lhs_payload, rhs_payload)) orelse
                .{ .any = known_valueType(lhs_payload) };
        }
        out.items[index] = .{
            .ty = existing.ty,
            .name = existing.name,
            .payloads = payloads,
        };
        return true;
    }

    try out.append(arena, candidate);
    return true;
}

fn finiteTagAlternativeIndex(
    program: *const Ast.Program,
    alternatives: []const KnownTag,
    value: TagValue,
) ?usize {
    for (alternatives, 0..) |alternative, index| {
        if (!sameType(program, alternative.ty, value.ty)) continue;
        if (alternative.name != value.name or alternative.payloads.len != value.payloads.len) continue;
        for (alternative.payloads, value.payloads) |payload_known_value, payload_value| {
            if (!knownValueMatchesValue(program, payload_known_value, payload_value)) break;
        } else {
            return index;
        }
    }
    return null;
}

fn demandedFiniteTagAlternativeIndexForValue(
    program: *const Ast.Program,
    alternatives: []const DemandedKnownTag,
    value: TagValue,
) ?usize {
    for (alternatives, 0..) |alternative, index| {
        if (!sameType(program, alternative.ty, value.ty)) continue;
        if (alternative.name != value.name) continue;
        return index;
    }
    return null;
}

fn demandedFiniteTagAlternativeIndexForPrivateState(
    program: *const Ast.Program,
    alternatives: []const DemandedKnownTag,
    value: PrivateStateTag,
) ?usize {
    for (alternatives, 0..) |alternative, index| {
        if (!sameType(program, alternative.ty, value.ty)) continue;
        if (alternative.name != value.name) continue;
        return index;
    }
    return null;
}

fn finiteTagValueAlternative(
    program: *const Ast.Program,
    alternatives: []const TagValue,
    demanded: DemandedKnownTag,
) ?TagValue {
    for (alternatives) |alternative| {
        if (!sameType(program, demanded.ty, alternative.ty)) continue;
        if (demanded.name != alternative.name) continue;
        return alternative;
    }
    return null;
}

fn demandedTagAlternativeIndex(
    program: *const Ast.Program,
    alternatives: []const DemandedKnownTag,
    name: names.TagNameId,
) ?usize {
    for (alternatives, 0..) |alternative, index| {
        if (program.names.tagLabelTextEql(alternative.name, name)) return index;
    }
    return null;
}

fn demandedFiniteCallableAlternativeIndexForValue(
    program: *const Ast.Program,
    alternatives: []const DemandedKnownCallable,
    value: CallableValue,
) ?usize {
    for (alternatives, 0..) |alternative, index| {
        if (!sameType(program, alternative.ty, value.ty)) continue;
        if (alternative.fn_id != value.fn_id) continue;
        return index;
    }
    return null;
}

fn demandedFiniteCallableAlternativeIndexForPrivateState(
    program: *const Ast.Program,
    alternatives: []const DemandedKnownCallable,
    value: PrivateStateCallable,
) ?usize {
    for (alternatives, 0..) |alternative, index| {
        if (!sameType(program, alternative.ty, value.ty)) continue;
        if (alternative.fn_id != value.fn_id) continue;
        return index;
    }
    return null;
}

fn finiteCallableValueAlternative(
    program: *const Ast.Program,
    alternatives: []const CallableValue,
    demanded: DemandedKnownCallable,
) ?CallableValue {
    for (alternatives) |alternative| {
        if (!sameType(program, demanded.ty, alternative.ty)) continue;
        if (!callableTargetMatches(program, demanded.fn_id, alternative.fn_id)) continue;
        return alternative;
    }
    return null;
}

fn demandedCallableAlternativeIndex(
    program: *const Ast.Program,
    alternatives: []const DemandedKnownCallable,
    ty: Type.TypeId,
    fn_id: Ast.FnId,
) ?usize {
    for (alternatives, 0..) |alternative, index| {
        if (!sameType(program, alternative.ty, ty)) continue;
        if (!callableTargetMatches(program, alternative.fn_id, fn_id)) continue;
        return index;
    }
    return null;
}

fn knownTagsMatchesValue(
    program: *const Ast.Program,
    known_value: KnownTags,
    value: FiniteTagsValue,
) bool {
    if (!sameType(program, known_value.ty, value.ty)) return false;
    if (known_value.alternatives.len != value.alternatives.len) return false;
    for (known_value.alternatives, value.alternatives) |known_value_alternative, value_alternative| {
        if (!sameType(program, known_value_alternative.ty, value_alternative.ty)) return false;
        if (known_value_alternative.name != value_alternative.name or known_value_alternative.payloads.len != value_alternative.payloads.len) return false;
        for (known_value_alternative.payloads, value_alternative.payloads) |payload_known_value, payload_value| {
            if (!knownValueMatchesValue(program, payload_known_value, payload_value)) return false;
        }
    }
    return true;
}

fn knownTagsEql(program: *const Ast.Program, lhs: KnownTags, rhs: KnownTags) bool {
    if (!sameType(program, lhs.ty, rhs.ty) or lhs.alternatives.len != rhs.alternatives.len) return false;
    for (lhs.alternatives) |lhs_alternative| {
        for (rhs.alternatives) |rhs_alternative| {
            if (knownTagEql(program, lhs_alternative, rhs_alternative)) break;
        } else {
            return false;
        }
    }
    return true;
}

fn knownTagEql(program: *const Ast.Program, lhs: KnownTag, rhs: KnownTag) bool {
    if (!sameType(program, lhs.ty, rhs.ty) or
        lhs.name != rhs.name or lhs.payloads.len != rhs.payloads.len)
    {
        return false;
    }
    for (lhs.payloads, rhs.payloads) |lhs_payload, rhs_payload| {
        if (!known_valueEql(program, lhs_payload, rhs_payload)) return false;
    }
    return true;
}

fn finiteKnownTagContainsKnownTag(program: *const Ast.Program, finite: KnownTags, tag: KnownTag) bool {
    for (finite.alternatives) |alternative| {
        if (!sameType(program, alternative.ty, tag.ty) or
            alternative.name != tag.name or
            alternative.payloads.len != tag.payloads.len)
        {
            continue;
        }
        for (alternative.payloads, tag.payloads) |pattern_payload, actual_payload| {
            if (!knownValueMatchesKnownValue(program, pattern_payload, actual_payload)) break;
        } else {
            return true;
        }
    }
    return false;
}

fn knownTagsContainsKnownValue(program: *const Ast.Program, pattern: KnownTags, actual: KnownTags) bool {
    if (!sameType(program, pattern.ty, actual.ty)) return false;
    for (actual.alternatives) |alternative| {
        if (!finiteKnownTagContainsKnownTag(program, pattern, alternative)) return false;
    }
    return true;
}

fn commonKnownCallables(
    program: *const Ast.Program,
    arena: Allocator,
    lhs: KnownValue,
    rhs: KnownValue,
) Allocator.Error!?KnownValue {
    const ty = known_valueType(lhs);
    var alternatives = std.ArrayList(KnownCallable).empty;
    defer alternatives.deinit(arena);

    if (!try appendKnownCallableAlternatives(program, arena, &alternatives, lhs)) return null;
    if (!try appendKnownCallableAlternatives(program, arena, &alternatives, rhs)) return null;
    if (alternatives.items.len == 0) return null;
    if (alternatives.items.len == 1) return KnownValue{ .callable = alternatives.items[0] };

    const stored = try arena.dupe(KnownCallable, alternatives.items);
    return KnownValue{ .finite_callables = .{
        .ty = ty,
        .alternatives = stored,
    } };
}

fn appendKnownCallableAlternatives(
    program: *const Ast.Program,
    arena: Allocator,
    out: *std.ArrayList(KnownCallable),
    known_value: KnownValue,
) Allocator.Error!bool {
    switch (known_value) {
        .callable => |callable| return try appendCallableAlternative(program, arena, out, callable),
        .finite_callables => |finite_callables| {
            for (finite_callables.alternatives) |alternative| {
                if (!try appendCallableAlternative(program, arena, out, alternative)) return false;
            }
            return true;
        },
        else => return false,
    }
}

fn appendCallableAlternative(
    program: *const Ast.Program,
    arena: Allocator,
    out: *std.ArrayList(KnownCallable),
    candidate: KnownCallable,
) Allocator.Error!bool {
    for (out.items, 0..) |existing, index| {
        if (existing.fn_id != candidate.fn_id) continue;
        if (!sameType(program, existing.ty, candidate.ty)) continue;
        if (existing.captures.len != candidate.captures.len) continue;

        const captures = try arena.alloc(KnownValue, existing.captures.len);
        for (existing.captures, candidate.captures, captures) |lhs_capture, rhs_capture, *capture_out| {
            capture_out.* = (try joinKnownValuesInArena(program, arena, lhs_capture, rhs_capture)) orelse
                .{ .any = known_valueType(lhs_capture) };
        }
        out.items[index] = .{
            .ty = existing.ty,
            .fn_id = existing.fn_id,
            .captures = captures,
        };
        return true;
    }

    try out.append(arena, candidate);
    return true;
}

fn finiteCallableAlternativeIndex(
    program: *const Ast.Program,
    alternatives: []const KnownCallable,
    value: CallableValue,
) ?usize {
    for (alternatives, 0..) |alternative, index| {
        if (!sameType(program, alternative.ty, value.ty)) continue;
        if (alternative.fn_id != value.fn_id or alternative.captures.len != value.captures.len) continue;
        for (alternative.captures, value.captures) |capture_known_value, capture_value| {
            if (!knownValueMatchesValue(program, capture_known_value, capture_value)) break;
        } else {
            return index;
        }
    }
    return null;
}

fn knownCallablesMatchesValue(
    program: *const Ast.Program,
    known_value: KnownCallables,
    value: FiniteCallablesValue,
) bool {
    if (!sameType(program, known_value.ty, value.ty)) return false;
    if (known_value.alternatives.len != value.alternatives.len) return false;
    for (known_value.alternatives, value.alternatives) |known_value_alternative, value_alternative| {
        if (!sameType(program, known_value_alternative.ty, value_alternative.ty)) return false;
        if (known_value_alternative.fn_id != value_alternative.fn_id or
            known_value_alternative.captures.len != value_alternative.captures.len)
        {
            return false;
        }
        for (known_value_alternative.captures, value_alternative.captures) |capture_known_value, capture_value| {
            if (!knownValueMatchesValue(program, capture_known_value, capture_value)) return false;
        }
    }
    return true;
}

fn knownCallablesEql(program: *const Ast.Program, lhs: KnownCallables, rhs: KnownCallables) bool {
    if (!sameType(program, lhs.ty, rhs.ty) or lhs.alternatives.len != rhs.alternatives.len) return false;
    for (lhs.alternatives) |lhs_alternative| {
        for (rhs.alternatives) |rhs_alternative| {
            if (knownCallableEql(program, lhs_alternative, rhs_alternative)) break;
        } else {
            return false;
        }
    }
    return true;
}

fn knownCallableEql(program: *const Ast.Program, lhs: KnownCallable, rhs: KnownCallable) bool {
    if (!sameType(program, lhs.ty, rhs.ty) or
        lhs.fn_id != rhs.fn_id or
        lhs.captures.len != rhs.captures.len)
    {
        return false;
    }
    for (lhs.captures, rhs.captures) |lhs_capture, rhs_capture| {
        if (!known_valueEql(program, lhs_capture, rhs_capture)) return false;
    }
    return true;
}

fn finiteKnownCallableContainsKnownCallable(program: *const Ast.Program, finite: KnownCallables, callable: KnownCallable) bool {
    for (finite.alternatives) |alternative| {
        if (!sameType(program, alternative.ty, callable.ty) or
            alternative.fn_id != callable.fn_id or
            alternative.captures.len != callable.captures.len)
        {
            continue;
        }
        for (alternative.captures, callable.captures) |pattern_capture, actual_capture| {
            if (!knownValueMatchesKnownValue(program, pattern_capture, actual_capture)) break;
        } else {
            return true;
        }
    }
    return false;
}

fn knownCallablesContainsKnownValue(program: *const Ast.Program, pattern: KnownCallables, actual: KnownCallables) bool {
    if (!sameType(program, pattern.ty, actual.ty)) return false;
    for (actual.alternatives) |alternative| {
        if (!finiteKnownCallableContainsKnownCallable(program, pattern, alternative)) return false;
    }
    return true;
}

fn callableTargetMatches(program: *const Ast.Program, expected: Ast.FnId, actual: Ast.FnId) bool {
    if (expected == actual) return true;
    const expected_source = program.fns.items[@intFromEnum(expected)].source orelse return false;
    const actual_source = program.fns.items[@intFromEnum(actual)].source orelse return false;
    return Mono.fnTemplateIdentityEql(expected_source, actual_source);
}

fn fieldFromValue(program: *const Ast.Program, value: Value, name: names.RecordFieldNameId) ?Value {
    if (value == .private_state) {
        const field = privateStateField(program, value.private_state, name) orelse return null;
        return .{ .private_state = field };
    }
    if (value == .expr_with_known_value) {
        if (value.expr_with_known_value.value) |structured_value| {
            if (fieldFromValue(program, structured_value.*, name)) |field| return field;
        }
    }
    const record = recordFromValue(value) orelse return null;
    return fieldFromRecord(program, record, name);
}

fn fieldFromRecord(
    program: *const Ast.Program,
    record: RecordValue,
    name: names.RecordFieldNameId,
) ?Value {
    for (record.fields) |field| {
        if (program.names.recordFieldLabelTextEql(field.name, name)) return field.value;
    }
    return null;
}

fn recordPatField(
    program: *const Ast.Program,
    fields: []const Ast.RecordDestruct,
    name: names.RecordFieldNameId,
) ?Ast.PatId {
    for (fields) |field| {
        if (program.names.recordFieldLabelTextEql(field.name, name)) return field.pattern;
    }
    return null;
}

fn itemFromValue(value: Value, index: u32) ?Value {
    if (value == .private_state) {
        const item = privateStateItem(value.private_state, index) orelse return null;
        return .{ .private_state = item };
    }
    if (value == .expr_with_known_value) {
        if (value.expr_with_known_value.value) |structured_value| {
            if (itemFromValue(structured_value.*, index)) |item| return item;
        }
    }
    const tuple = tupleFromValue(value) orelse return null;
    if (index >= tuple.items.len) return null;
    return tuple.items[index];
}

fn tagFromValue(value: Value) ?TagValue {
    return switch (value) {
        .tag => |tag| tag,
        .nominal => |nominal| tagFromValue(nominal.backing.*),
        .expr_with_known_value => |known| if (known.value) |structured_value| tagFromValue(structured_value.*) else null,
        else => null,
    };
}

fn tagNameFromValue(value: Value) ?names.TagNameId {
    if (tagFromValue(value)) |tag| return tag.name;
    return switch (value) {
        .private_state => |private_state| if (privateStateTag(private_state)) |tag| tag.name else null,
        .expr_with_known_value => |known| if (known.value) |structured_value| tagNameFromValue(structured_value.*) else null,
        .nominal => |nominal| tagNameFromValue(nominal.backing.*),
        else => null,
    };
}

fn tagPayloadFromValue(value: Value, index: u32) ?Value {
    if (tagFromValue(value)) |tag| {
        if (index >= tag.payloads.len) return null;
        return tag.payloads[index];
    }

    return switch (value) {
        .private_state => |private_state| blk: {
            const tag = privateStateTag(private_state) orelse break :blk null;
            const payload = privateStateIndexedValueByIndex(tag.payloads, index) orelse break :blk null;
            break :blk Value{ .private_state = payload };
        },
        .expr_with_known_value => |known| if (known.value) |structured_value| tagPayloadFromValue(structured_value.*, index) else null,
        .nominal => |nominal| tagPayloadFromValue(nominal.backing.*, index),
        else => null,
    };
}

fn patternTagChoiceMatchesValue(program: *const Ast.Program, pat_id: Ast.PatId, value: Value) bool {
    const pat = program.pats.items[@intFromEnum(pat_id)];
    return switch (pat.data) {
        .wildcard,
        .bind,
        => true,
        .as => |as| patternTagChoiceMatchesValue(program, as.pattern, value),
        .nominal => |backing| patternTagChoiceMatchesValue(program, backing, value),
        .tag => |tag_pat| blk: {
            const tag_name = tagNameFromValue(value) orelse break :blk false;
            break :blk tag_name == tag_pat.name;
        },
        .record,
        .tuple,
        .list,
        .int_lit,
        .dec_lit,
        .frac_f32_lit,
        .frac_f64_lit,
        .str_lit,
        .str_pattern,
        => false,
    };
}

fn knownIfConditionBoolTag(program: *const Ast.Program, value: Value) ?bool {
    if (value == .private_state) {
        const tag = privateStateTag(value.private_state) orelse return null;
        return boolPrivateStateTag(program, tag) orelse
            Common.invariant("known if condition Bool tag used a non-Bool tag label");
    }

    const tag = tagFromValue(value) orelse return null;
    return boolTagValue(program, tag) orelse
        Common.invariant("known if condition Bool tag used a non-Bool tag label");
}

fn finiteBoolTagsValue(program: *const Ast.Program, value: Value) ?FiniteTagsValue {
    const finite_tags = switch (value) {
        .finite_tags => |finite_tags| finite_tags,
        else => return null,
    };
    for (finite_tags.alternatives) |alternative| {
        if (boolTagValue(program, alternative) == null) return null;
    }
    return finite_tags;
}

fn boolTagValue(program: *const Ast.Program, tag: TagValue) ?bool {
    if (tag.payloads.len != 0) Common.invariant("Bool tag had payloads");
    const tag_text = program.names.tagLabelText(tag.name);
    if (std.mem.eql(u8, tag_text, "True")) return true;
    if (std.mem.eql(u8, tag_text, "False")) return false;
    return null;
}

fn boolPrivateStateTag(program: *const Ast.Program, tag: PrivateStateTag) ?bool {
    if (tag.payloads.len != 0) Common.invariant("Bool tag had payloads");
    const tag_text = program.names.tagLabelText(tag.name);
    if (std.mem.eql(u8, tag_text, "True")) return true;
    if (std.mem.eql(u8, tag_text, "False")) return false;
    return null;
}

fn unsignedIntLiteral(value: anytype) can.CIR.IntValue {
    const widened: u128 = @intCast(value);
    return .{ .bytes = @bitCast(widened), .kind = .u128 };
}

fn recordFromValue(value: Value) ?RecordValue {
    return switch (value) {
        .record => |record| record,
        .nominal => |nominal| recordFromValue(nominal.backing.*),
        .expr_with_known_value => |known| if (known.value) |structured_value| recordFromValue(structured_value.*) else null,
        else => null,
    };
}

fn tupleFromValue(value: Value) ?TupleValue {
    return switch (value) {
        .tuple => |tuple| tuple,
        .nominal => |nominal| tupleFromValue(nominal.backing.*),
        .expr_with_known_value => |known| if (known.value) |structured_value| tupleFromValue(structured_value.*) else null,
        else => null,
    };
}

test "value demand equality ignores capture read order" {
    const materialize: ValueDemand = .materialize;
    const none: ValueDemand = .none;
    const field_a: names.RecordFieldNameId = @enumFromInt(1);
    const field_b: names.RecordFieldNameId = @enumFromInt(2);
    const tag_a: names.TagNameId = @enumFromInt(3);

    const record_lhs_fields = [_]FieldDemand{
        .{ .name = field_a, .demand = &materialize },
        .{ .name = field_b, .demand = &none },
    };
    const record_rhs_fields = [_]FieldDemand{
        .{ .name = field_b, .demand = &none },
        .{ .name = field_a, .demand = &materialize },
    };
    try std.testing.expect(valueDemandEql(
        null,
        .{ .record = &record_lhs_fields },
        .{ .record = &record_rhs_fields },
    ));

    const tuple_lhs_items = [_]ItemDemand{
        .{ .index = 0, .demand = &materialize },
        .{ .index = 3, .demand = &none },
    };
    const tuple_rhs_items = [_]ItemDemand{
        .{ .index = 3, .demand = &none },
        .{ .index = 0, .demand = &materialize },
    };
    try std.testing.expect(valueDemandEql(
        null,
        .{ .tuple = &tuple_lhs_items },
        .{ .tuple = &tuple_rhs_items },
    ));

    const tag_lhs_payloads = [_]ItemDemand{
        .{ .index = 2, .demand = &none },
        .{ .index = 0, .demand = &materialize },
    };
    const tag_rhs_payloads = [_]ItemDemand{
        .{ .index = 0, .demand = &materialize },
        .{ .index = 2, .demand = &none },
    };
    const tag_lhs_alternatives = [_]TagAlternativeDemand{
        .{ .name = tag_a, .payloads = &tag_lhs_payloads },
    };
    const tag_rhs_alternatives = [_]TagAlternativeDemand{
        .{ .name = tag_a, .payloads = &tag_rhs_payloads },
    };
    try std.testing.expect(valueDemandEql(
        null,
        .{ .tag = .{ .alternatives = &tag_lhs_alternatives } },
        .{ .tag = .{ .alternatives = &tag_rhs_alternatives } },
    ));

    const record_missing_field = [_]FieldDemand{
        .{ .name = field_a, .demand = &materialize },
    };
    try std.testing.expect(!valueDemandEql(
        null,
        .{ .record = &record_lhs_fields },
        .{ .record = &record_missing_field },
    ));
}

test "demanded known value materialization preserves indexed tuple children" {
    var arena = std.heap.ArenaAllocator.init(std.testing.allocator);
    defer arena.deinit();

    const tuple_ty: Type.TypeId = @enumFromInt(10);
    const first_ty: Type.TypeId = @enumFromInt(11);
    const second_ty: Type.TypeId = @enumFromInt(12);
    const third_ty: Type.TypeId = @enumFromInt(13);
    const dense_items = [_]KnownValue{
        .{ .leaf = first_ty },
        .{ .any = second_ty },
        .{ .leaf = third_ty },
    };
    const known = KnownValue{ .tuple = .{
        .ty = tuple_ty,
        .items = &dense_items,
    } };

    const demanded = (try demandedKnownValueFromDemand(null, null, arena.allocator(), known, .materialize)) orelse
        return error.TestUnexpectedResult;

    try std.testing.expectEqual(tuple_ty, demanded.tuple.ty);
    try std.testing.expectEqual(@as(usize, 3), demanded.tuple.items.len);
    try std.testing.expectEqual(@as(u32, 0), demanded.tuple.items[0].index);
    try std.testing.expectEqual(@as(u32, 1), demanded.tuple.items[1].index);
    try std.testing.expectEqual(@as(u32, 2), demanded.tuple.items[2].index);
    try std.testing.expectEqual(second_ty, demanded.tuple.items[1].known_value.any);
}

